window.__QUIZ_SUBJECT__=[{"id": "objective>Accounts>1993>1", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The books of accounts are opened by means of a", "images": [], "options": {"A": "Sale Journal", "B": "Principal Journal", "C": "Purchases Journal", "D": "Returns Inwards Journal"}, "answer": "B", "explanation": "The books of accounts are typically opened by means of a 'Principal Journal' which serves as the primary record for all transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>2", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Which of the following is true of trade discounts?", "images": [], "options": {"A": "They are recorded in the ledger only", "B": "They are not different from cash discounts", "C": "They are recorded in the Journals only", "D": "They are recorded in ledgers and Journals"}, "answer": "D", "explanation": "Trade discounts are reductions in the listed price of goods or services and are typically recorded in both the journals and ledgers. This is because they affect the overall sales figures and need to be reflected in the financial records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>3", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Returns inwards was understated. The effect is that", "images": [], "options": {"A": "amount of goods available was understated", "B": "cost of sales was understated", "C": "amount of purchases returns was understated", "D": "amount of sales was understated"}, "answer": "D", "explanation": "If returns inwards (goods returned by customers) are understated, it means that the amount of sales is also understated because the returns reduce the total sales figure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>4", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not contained in the Sales Ledger Control Account?", "images": [], "options": {"A": "Receipts from debtors", "B": "Returns inwards", "C": "Returns outwards", "D": "Dishonoured cheques"}, "answer": "C", "explanation": "The Sales Ledger Control Account typically contains transactions related to sales and receipts from debtors. Returns outwards (goods returned to suppliers) are not part of the sales ledger; they belong to the purchases ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>5", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Payment for future services are", "images": [], "options": {"A": "prepayments", "B": "deposit", "C": "accruals", "D": "investment"}, "answer": "A", "explanation": "Payments for future services are classified as 'prepayments' in accounting. Prepayments are expenses that have been paid in advance and will be recognized as expenses in future periods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>6", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Which of the following is a credit item on an Income and Expenditure account?", "images": [], "options": {"A": "Bar expenses", "B": "Electricity", "C": "Salaries", "D": "Subscriptions"}, "answer": "D", "explanation": "In an Income and Expenditure account, credit items typically include income sources. Subscriptions represent income received by an organization, making it a credit item. The other options (Bar expenses, Electricity, Salaries, Rates) are all expenses, which are debit items.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>7", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO", "question": "An excess of the value of the assets over the purchases consideration for acquisition of business is credited to", "images": [], "options": {"A": "general reserve", "B": "capital reserve", "C": "goodwill", "D": "current asset"}, "answer": "B", "explanation": "An excess of the value of the assets over the purchase consideration for the acquisition of a business is credited to a capital reserve. This reflects the additional value that the business has over what was paid for it, which is not recognized as goodwill but rather as a reserve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>8", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Shares are sold at less than nominal value. They are issued at a", "images": [], "options": {"A": "profit", "B": "loss", "C": "discount", "D": "premium"}, "answer": "C", "explanation": "When shares are sold at less than nominal value, they are issued at a discount. This means that the selling price is lower than the nominal or par value of the shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>9", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A share is under-subscribed when", "images": [], "options": {"A": "it is offered for sale at less than the nominal value", "B": "it is offered for sale at nominal value", "C": "the number of shares applied for is less than the offer", "D": "it is offered for sale at more than nominal value"}, "answer": "C", "explanation": "A share is considered under-subscribed when the number of shares applied for is less than the number of shares offered. This indicates that there is not enough demand for the shares being issued.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>10", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "BRANCH ACCOUNT", "question": "Mark-up on goods sent to branch offices are recorded in the books by crediting", "images": [], "options": {"A": "Stock Adjustment Account debiting Branch Stock Account", "B": "Goods sent to Branch Account and debiting Branch Stock Account", "C": "Branch Stock Account and debiting Stock Adjustment Account", "D": "Cash Account and debiting crediting Branch Stock Account"}, "answer": "A", "explanation": "Mark-up on goods sent to branch offices is recorded by crediting the Stock Adjustment Account and debiting the Branch Stock Account. This reflects the increase in stock value due to the mark-up applied to goods sent to the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>11", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Cash stolen from branch-takings is recorded in the Head Office books by debiting", "images": [], "options": {"A": "defalcations Account and crediting Branch Stock Account", "B": "Mark-up Account and crediting Branch Stock Account", "C": "defalcations Account and crediting Profit and loss Account", "D": "Cash Account and crediting Branch Stock Account"}, "answer": "A", "explanation": "Cash stolen from branch-takings is recorded by debiting the defalcations account, which is used to record losses due to theft or fraud, and crediting the Branch Stock Account to reflect the decrease in assets. This accounting treatment ensures that the loss is recognized in the financial records.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1993>12", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A Trial Balance is a proof of accuracy of", "images": [], "options": {"A": "trasactions", "B": "final accounts", "C": "double entry in the ledgers", "D": "trading account"}, "answer": "C", "explanation": "A Trial Balance is primarily a proof of the accuracy of double entry in the ledgers. It ensures that the total debits equal total credits, which is a fundamental principle of double-entry accounting. However, it does not guarantee that there are no errors in the accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>13", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The term bad debts means debt", "images": [], "options": {"A": "recorded in wrong accounts", "B": "owed by an employee", "C": "paid with fake currency", "D": "that cannot be collected"}, "answer": "D", "explanation": "The term bad debts refers to debts that cannot be collected, meaning that the debtor is unable to pay the amount owed. This is a common occurrence in business and is recognized as an expense in the financial statements.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>14", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "The equivalent of a Club's Receipt and Payment Account is", "images": [], "options": {"A": "Cash Account", "B": "Revenue Account", "C": "Trading Account", "D": "Suspense Account"}, "answer": "A", "explanation": "The equivalent of a Club's Receipt and Payment Account is the Cash Account. This account summarizes all cash inflows and outflows, similar to how a Receipt and Payment Account operates, tracking the cash position of the club.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>15", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "Goodwill is", "images": [], "options": {"A": "a current asset", "B": "a current liability", "C": "a long term liability", "D": "an intangible asset"}, "answer": "D", "explanation": "Goodwill is classified as an intangible asset. It represents the value of a business's brand, customer relationships, and other non-physical assets that contribute to its earning potential. Unlike tangible assets, goodwill cannot be physically touched or measured.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>16", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Purchases in Accounting refer to goods bought for", "images": [], "options": {"A": "repairs", "B": "owner's use", "C": "resale", "D": "decorating offices"}, "answer": "C", "explanation": "Purchases in accounting refer to goods bought for resale. This is a fundamental concept in accounting where purchases are recorded as inventory until sold, at which point they are recognized as an expense (Cost of Goods Sold).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>17", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000    What is the amount of share capital?", "images": [], "options": {"A": "#33,000", "B": "#25,000", "C": "#23,000", "D": "#15,000"}, "answer": "D", "explanation": "The amount of share capital is calculated by adding the value of ordinary shares and preference shares. Here, 10,000 ordinary shares at #1 each contribute #10,000, and 5,000 preference shares at #1 each contribute #5,000, totaling #15,000.     However, the total share capital is the sum of both types of shares, which is #10,000 + #5,000 = #15,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>18", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000  What is the value of shareholder's equity?", "images": [], "options": {"A": "#25,000", "B": "#23,000", "C": "#18,000", "D": "#15,000"}, "answer": "B", "explanation": "Shareholder's equity  = #10,000 (ordinary shares) + #5,000 (preference shares) + #8,000 (Profit and Loss Account)   = #23,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>19", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000  What is the total value of long term liability?", "images": [], "options": {"A": "#33,000", "B": "#25,000", "C": "#23,000", "D": "#10,000"}, "answer": "D", "explanation": "Long-term liabilities include the 8% debenture, which is #10,000. This is the only long-term liability listed in the information provided. Therefore, the total value of long-term liabilities is #10,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>20", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000  What is the total amount of fixed assets?", "images": [], "options": {"A": "#26,000", "B": "#21,000", "C": "#18,000", "D": "#13,000"}, "answer": "D", "explanation": "The total amount of fixed assets includes:  =   plants and machinery (#10,000) +  furniture and fittings (#3,000)  =  #13,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>21", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000  What is the value of current liabilities?", "images": [], "options": {"A": "#13,000", "B": "#10,000", "C": "#5,000", "D": "#3,000"}, "answer": "C", "explanation": "Current liabilities are obligations that a company needs to settle within a year. In this case, the current liabilities include:   =  creditors (#3,000) + bank overdraft (#2,000).     = #5,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>22", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Use the following information to answer the question   #10000 ordinary shares of #1 each 100005000 5% preference shares of #1 each 5000Profit and Loss Account 80008% debenture 10000Creditors 3000Bank overdraft 2000Plants and machinery 10000Furniture and fittings 3000Stock 8000Debtors 5000  What is the total of current assets?", "images": [], "options": {"A": "#15,000", "B": "#13,000", "C": "#11,000", "D": "#8,000"}, "answer": "B", "explanation": "Current assets are assets that are expected to be converted into cash or used up within one year. In this case, the current assets include stock (#8,000), debtors (#5,000), and cash (not explicitly listed but can be inferred from the absence of current liabilities).     Therefore, the total current assets are #8,000 + #5,000   = #13,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>23", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Which of the following is not a Nominal Account?", "images": [], "options": {"A": "Rent", "B": "Wages", "C": "Discount", "D": "Land"}, "answer": "D", "explanation": "Nominal accounts are accounts that represent expenses, losses, incomes, or gains. 'Land' is a real account, as it represents a tangible asset, while the others (Rent, Wages, Discount, Interest) are nominal accounts. Therefore, the correct answer is 'Land'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>24", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The amount of individuals items on a government budget is called", "images": [], "options": {"A": "a vote", "B": "a deposit", "C": "an investment", "D": "a loan"}, "answer": "A", "explanation": "In government budgeting, a 'vote' refers to the amount allocated for a specific purpose or item in the budget. It represents the individual items on a government budget. Therefore, the correct answer is 'a vote'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>25", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT~~THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following does not belong to the group?", "images": [], "options": {"A": "Discount allowed", "B": "Salaries and wages", "C": "Sundry expeneses", "D": "Return inwards"}, "answer": "D", "explanation": "The items listed are all types of expenses except for 'Return inwards', which refers to the return of goods sold to customers. The other options (Discount allowed, Salaries and wages, Sundry expenses, Rates and rent) are all expenses. Therefore, 'Return inwards' does not belong to the group.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>26", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000    The interest on Johnson's capital is", "images": [], "options": {"A": "#3,000", "B": "#2,000", "C": "#500", "D": "#1,000"}, "answer": "C", "explanation": "To calculate the interest on Johnson's capital, we use the formula:     Interest = Capital x Interest Rate.     Johnson's capital is #10,000 and the interest rate is 5%.     Therefore, Interest = #10,000 x 5%   = #10,000 x 0.05   = #500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>27", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  Interest on John's drawings is", "images": [], "options": {"A": "#500", "B": "#300", "C": "#200", "D": "#150"}, "answer": "C", "explanation": "To calculate the interest on John's drawings, we use the formula: Interest = Drawings x Interest Rate. John's drawings are #2,000 and the interest rate is 10%.     Therefore, Interest = #2,000 x 10%   = #2,000 x 0.10   = #200.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>28", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  What is John's share of the profit?", "images": [], "options": {"A": "#5,000", "B": "#3,600", "C": "#3,000", "D": "#2,400"}, "answer": "B", "explanation": "John's share of the profit is calculated based on the profit-sharing ratio.     The total profit is #6,000, and John's share is 3/5 of the total profit (since the ratio is 3:2). Therefore, John's share = #6,000 x (3/5)   = #3,600.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>29", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  What is Johnson's share of profit?", "images": [], "options": {"A": "#6,000", "B": "#3,600", "C": "#3,000", "D": "#2,400"}, "answer": "D", "explanation": "Johnson's share of the profit is calculated based on the profit-sharing ratio. The total profit is #6,000, and Johnson's share is 2/5 of the total profit (since the ratio is 3:2).     Therefore, Johnson's share = #6,000 x (2/5)   = #2,400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>30", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  The balance on John's current account is", "images": [], "options": {"A": "#4,000 DR", "B": "#3,800 CR", "C": "#3,300 DR", "D": "#2,400 CR"}, "answer": "D", "explanation": "Interest on capital = 5%  x 20000  = 1000    Interest on drawings = 10% x 2000  = 200    Profit sharing= 3/5 x 6000  =3600    Current account computation  Credit side = 1000 + 3600  = 4600    Debit side = 2000 + 200  = 2200    Balance = 4600 - 2200  = #2400 CR", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>31", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  The balance on Johnson's current account is", "images": [], "options": {"A": "#3,000 CR", "B": "#2,200 CR", "C": "#1,300 CR", "D": "#400 DR"}, "answer": "D", "explanation": "Interest on capital = 5% x 10000  = 500    Interest on drawings= 10% x 3000  = 300    Share of profit = 2/5 x 6000  = 2400    Computation of current account  Credit side = 500 + 2400  = 2900    Debit side = 3000 + 300  =3300    Balance = 3300 - 2900  = #400 DR", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1993>32", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question    John and Johnson are in partnership, sharing profit and losses in the ratio 3: 2. Other information are as follows:    Capital- John #20000- Johnson- #10000Drawings- John #2000- Johnson#3000Interest on capital 5%Interest on drawings 10%Profit #6000  Interest on Johnson's drawings is", "images": [], "options": {"A": "#500", "B": "#300", "C": "#200", "D": "#150"}, "answer": "B", "explanation": "To calculate the interest on Johnson's drawings, we use the formula: Interest on Drawings = Drawings Amount * Interest Rate.     Johnson's drawings = #3,000 and the interest rate is 10%.     Interest on Drawings = #3,000 x 10%   = #300.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>33", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following is the most liquid?", "images": [], "options": {"A": "Land and Building", "B": "Cash at Bank", "C": "Machinery", "D": "Goodwill"}, "answer": "B", "explanation": "Liquidity refers to how easily an asset can be converted into cash. Among the options provided, 'Cash at Bank' is the most liquid asset because it is already in cash form and can be accessed immediately. Other assets like land, machinery, goodwill, and furniture require time and effort to convert into cash, making them less liquid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>34", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following does not belong to the group?", "images": [], "options": {"A": "Plant and machinery", "B": "Stock", "C": "Goodwill", "D": "Overdraft"}, "answer": "D", "explanation": "The group consists of assets and expenses related to business operations. 'Overdraft' is a liability, not an asset or expense, which makes it the odd one out. The other options (plant and machinery, stock, goodwill, preliminary expenses) are all related to assets or expenses incurred in the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>35", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "A partner's drawing is debited to", "images": [], "options": {"A": "Profit and Loss Appropriation Account", "B": "Interest Account", "C": "Loan Account", "D": "Current Account"}, "answer": "D", "explanation": "A partner's drawing is debited to the Current Account. The Current Account reflects the transactions between the partner and the partnership, including drawings. This account is used to track the amounts withdrawn by partners from the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>36", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ADJUSTMENT IN THE FINAL ACCOUNT", "question": "Trade debts amounting to #300 were written off. Which of the following would be affected?", "images": [], "options": {"A": "Purchases", "B": "Profit and losses", "C": "Creditors", "D": "Sales Ledger"}, "answer": "B", "explanation": "When trade debts amounting to #300 are written off, it affects the Profit and Loss account because it represents a loss to the business. Writing off debts means that the business acknowledges that it will not receive that amount, which directly impacts its profitability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>37", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Debenture is a", "images": [], "options": {"A": "current asset", "B": "fixed asset", "C": "long term liability", "D": "current liability"}, "answer": "C", "explanation": "A debenture is a long-term liability. It is a type of debt instrument that companies use to borrow money, typically with a fixed interest rate. Debentures are not secured by physical assets or collateral but are backed by the creditworthiness and reputation of the issuer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>38", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following is a Revenue Income?", "images": [], "options": {"A": "The sale proceeds of an old table", "B": "The sale proceeds of shares", "C": "Loan refund", "D": "Debt recovered"}, "answer": "A", "explanation": "Revenue income refers to the income generated from the normal business operations. The sale proceeds of an old table is considered revenue income because it is part of the regular activities of the business, even though it is from an asset that is no longer in use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>39", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Which of the following is a fictitious asset?", "images": [], "options": {"A": "Plant and Machinery", "B": "Prepayment", "C": "Preliminary Expenses", "D": "Investment"}, "answer": "C", "explanation": "Preliminary expenses are considered fictitious assets. They are costs incurred before a business starts its operations, such as legal fees and registration costs. These expenses do not have a tangible value and are not expected to generate future economic benefits, hence they are classified as fictitious.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>40", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Income received in advance is shown in the Balance Sheet as", "images": [], "options": {"A": "Current Asset", "B": "Intangible Asset", "C": "Tangible Asset", "D": "Current liability"}, "answer": "D", "explanation": "Income received in advance is shown in the Balance Sheet as a Current liability. This is because it represents money that has been received for services or goods that have not yet been delivered, creating an obligation for the business to provide those services or goods in the future.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>41", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Gavbon Ltd. failed to record #2,000 wages. The error committed is that of", "images": [], "options": {"A": "omission", "B": "commission", "C": "principle", "D": "compensation"}, "answer": "A", "explanation": "The error committed is that of omission. An omission error occurs when a transaction is not recorded in the accounting records. In this case, failing to record wages means that the expense is omitted from the financial statements.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>42", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "The excess of current assets over current liabilities is", "images": [], "options": {"A": "Authorised capital", "B": "Nominal capital", "C": "Issued capital", "D": "Working capital"}, "answer": "D", "explanation": "The excess of current assets over current liabilities is known as working capital. Working capital is a measure of a company's short-term financial health and operational efficiency, calculated as current assets minus current liabilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>43", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Carriage inwards are", "images": [], "options": {"A": "credited to the profit and loss account", "B": "debited to the trading account", "C": "debited to the profit and loss account", "D": "credited to the trading account"}, "answer": "B", "explanation": "Carriage inwards refers to the transportation costs incurred to bring goods into a business. These costs are debited to the trading account as they are part of the cost of goods sold, which affects the gross profit calculation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1993>44", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     #Purchases: raw materials 20000finished goods 15000Stock 1/1/89: raw materials 3000work-in-progress 2500Wages: direct 22800indirect 7200Factory expenses: electricity 12000insurance 2000Stock 31/12/89: raw materials 4000work-in-progress4500    What is the value of raw materials available?", "images": [], "options": {"A": "#23,000", "B": "#22,500", "C": "#20,000", "D": "#19,000"}, "answer": "A", "explanation": "To calculate the value of raw materials available, we add the purchases of raw materials to the opening stock of raw materials     =   20,000 (purchases) + 3,000 (opening stock)  = #23,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>45", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     #Purchases: raw materials 20000finished goods 15000Stock 1/1/89: raw materials 3000work-in-progress 2500Wages: direct 22800indirect 7200Factory expenses: electricity 12000insurance 2000Stock 31/12/89: raw materials 4000work-in-progress4500  The cost of materials used is", "images": [], "options": {"A": "#23,000", "B": "#21,000", "C": "#20,000", "D": "#19,000"}, "answer": "D", "explanation": "To calculate the value of raw materials available, we add the purchases of raw materials to the opening stock of raw materials and subtract the closing stock.     =   20,000 (purchases) + 3,000 (opening stock) - 4,000 (closing stock)   = #19,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>46", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     #Purchases: raw materials 20000finished goods 15000Stock 1/1/89: raw materials 3000work-in-progress 2500Wages: direct 22800indirect 7200Factory expenses: electricity 12000insurance 2000Stock 31/12/89: raw materials 4000work-in-progress4500  The prime cost is", "images": [], "options": {"A": "#49,000", "B": "#45,800", "C": "#43,800", "D": "#41,800"}, "answer": "D", "explanation": "The prime cost is calculated as the sum of direct materials and direct labor costs. Here, direct materials are the purchases of raw materials plus the opening stock of raw materials minus the closing stock of raw materials, and direct labor is the direct wages.     Therefore, Prime Cost = (20000 + 3000 - 4000) + 22800   = #41800.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1993>47", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     #Purchases: raw materials 20000finished goods 15000Stock 1/1/89: raw materials 3000work-in-progress 2500Wages: direct 22800indirect 7200Factory expenses: electricity 12000insurance 2000Stock 31/12/89: raw materials 4000work-in-progress4500  The amount of factory overhead is", "images": [], "options": {"A": "#28,200", "B": "#23,200", "C": "#21,200", "D": "#19,200"}, "answer": "C", "explanation": "Factory overhead includes indirect wages, factory expenses, and any other indirect costs. Here, indirect wages are 7200, electricity is 12000, and insurance is 2000.     Therefore, Factory Overhead = 7200 + 12000 + 2000   =# 21200. .", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1993>48", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     #Purchases: raw materials 20000finished goods 15000Stock 1/1/89: raw materials 3000work-in-progress 2500Wages: direct 22800indirect 7200Factory expenses: electricity 12000insurance 2000Stock 31/12/89: raw materials 4000work-in-progress4500  The cost of manufactured goods is", "images": [], "options": {"A": "#67,500", "B": "#65,500", "C": "#65,000", "D": "#61,000"}, "answer": "D", "explanation": "The cost of manufactured goods is calculated as the prime cost plus factory overhead. From previous calculations, Prime Cost = 41800 and Factory Overhead = 21200.   Add opening work in progress and subtract closing work in progress    Therefore, Cost of manufactured goods = 41800 + 21200 + 2500 - 4500  = #61,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1993>49", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the question  Rent paid 31/12/89 #4000Rent owing 1/1/89 #500Rent owing 31/12/89 #300  Rent for 1989 amounts to", "images": [], "options": {"A": "#4,500", "B": "#4,300", "C": "#4,000", "D": "#3,800"}, "answer": "D", "explanation": "Rent paid (cash paid during the year) = ₦4,000    Rent owing on 1/1/89 (opening) = ₦500 ← for previous year    Rent owing on 31/12/89 (closing) = ₦300 ← for current year    Therefore, rent for 1989 = 4000 - 500 + 300  = #3,800", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1993>50", "subject": "Accounts", "year": "1993", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following account is not kept by a local government?", "images": [], "options": {"A": "Departmental votes Revenue Account", "B": "Departmental votes Expenditure Account", "C": "Deposit Account", "D": "Profit and Loss Account"}, "answer": "D", "explanation": "A Profit and Loss Account is typically not kept by local governments as they do not operate for profit. Instead, they focus on budgets and expenditures. The other accounts listed are relevant to local government accounting practices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>1", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Which of the following statements is not valid?", "images": [], "options": {"A": "Provision for bad debts is deducted from debtors total in the Balance sheet", "B": "An increase in provision for bad debts appears on the debit side of the Profit and Loss Account", "C": "A decrease in the Provision for bad debt appears on the credit side of Profit and Loss Account", "D": "The bad debt account is closed to the debit side of the Profit and Loss Account"}, "answer": "D", "explanation": "The statement 'The bad debt account is closed to the debit side of the Profit and Loss Account' is not valid. In accounting, bad debts are typically written off as an expense, which would be recorded on the debit side of the Profit and Loss Account. However, the bad debt account itself is not closed to the debit side; rather, it is the expense that is recognized. Therefore, this statement is misleading.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>2", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Carriage outwards is charged to the", "images": [], "options": {"A": "debit side of Profit and Loss Account", "B": "credit side of Profit and Loss Account", "C": "credit side of Trading Account", "D": "debit side of Profit and Loss Appropriation Account"}, "answer": "A", "explanation": "Carriage outwards refers to the transportation costs incurred to deliver goods to customers. This expense is charged to the debit side of the Profit and Loss Account, as it is a selling expense that reduces the overall profit of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>3", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Where a proprietor withdraws cash from bank for office use, the entries would be", "images": [], "options": {"A": "credit cash account, debit bank account", "B": "debit cash account, credit bank account", "C": "debit office account, credit bank account", "D": "debit drawings account, credit bank account"}, "answer": "B", "explanation": "When a proprietor withdraws cash from the bank for office use, the cash account is debited to reflect the increase in cash, and the bank account is credited to reflect the decrease in bank balance. Therefore, the correct entry is 'debit cash account, credit bank account'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>4", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A debit cash balance of #26,900 was brought down as #24,300. The entries necessary to correct the error are", "images": [], "options": {"A": "debit cash account #5,200, credit suspense account #5,200", "B": "credit cash account #5,200, debit suspense account #5,200", "C": "debit cash account #2,600, credit suspense account #2,600", "D": "credit cash account #2,600, debit suspense account #2,600"}, "answer": "A", "explanation": "To correct the error of bringing down a debit cash balance of #26,900 as #24,300, we need to increase the cash account by the difference of #2,600. This means we should debit the cash account by #2,600 and credit a suspense account by the same amount to balance the books. Thus, the correct entry is 'debit cash account #2,600, credit suspense account #2,600'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>5", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the question   ##Opening stock 1200 Sales 29000Purchases ? Less sales returns 500Add Carriage inwards  300 Less returns outwards  1570 Less closing stock  2220 Gross profit (25% of sales)2850028500    What is the cost of goods sold?", "images": [], "options": {"A": "#19,805", "B": "#21,075", "C": "#21,375", "D": "#21,250"}, "answer": "D", "explanation": "Net sales = Sales - Sales returns  = 29000 - 500  = 28500    Gross profit is 25% of sales  =25% x 29000  = 7250    Gross profit = net sales - COGS  7250 = 28500 = COGS  COGS = 28500 - 7250  = #21250", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>6", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question   ##Opening stock 1200 Sales 29000Purchases ? Less sales returns 500Add Carriage inwards  300 Less returns outwards  1570 Less closing stock  2220 Gross profit (25% of sales)2850028500  The cost of goods available for sale is", "images": [], "options": {"A": "#23,450", "B": "#22,095", "C": "#22,395", "D": "#23,595"}, "answer": "A", "explanation": "Net sales = Sales - Sales returns  = 29000 - 500  = 28500    Gross profit is 25% of sales  =25% x 29000  = 7250    Gross profit = net sales - COGS  7250 = 28500 = COGS  COGS = 28500 - 7250  = #21250    Cost of goods available for sales = closing stock + cost of goods sold  = 2200 + 21250  = #23450", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>7", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question   ##Opening stock 1200 Sales 29000Purchases ? Less sales returns 500Add Carriage inwards  300 Less returns outwards  1570 Less closing stock  2220 Gross profit (25% of sales)2850028500  What is the cost of goods purchased?", "images": [], "options": {"A": "#22,095", "B": "#23,520", "C": "#22,765", "D": "#23,665"}, "answer": "B", "explanation": "Cost of purchases = cost of goods available for sales  + returns outwards - carriage inwards - opening stock    = 23450 + 1570 - 300 - 1200  = #23,520", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>8", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question   ##Opening stock 1200 Sales 29000Purchases ? Less sales returns 500Add Carriage inwards  300 Less returns outwards  1570 Less closing stock  2220 Gross profit (25% of sales)2850028500  The gross profit is", "images": [], "options": {"A": "#7,125", "B": "#7,250", "C": "#7425", "D": "#7625"}, "answer": "B", "explanation": "Gross profit is 25% of sales    =25% x 29000    = #7250", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>9", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "When a buyer is undercharged, the seller forwards", "images": [], "options": {"A": "undercast note", "B": "consignment invoice", "C": "purchase invoice", "D": "debit note"}, "answer": "D", "explanation": "When a buyer is undercharged, the seller typically forwards a debit note to adjust the amount owed. This is a document that indicates an increase in the amount payable by the buyer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>10", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CASH BOOK : THREE COLUMN CASH BOOK", "question": "Cash discount is given for", "images": [], "options": {"A": "buying in large quantity", "B": "prompt settlement of account", "C": "being regular customer", "D": "introducing other customers"}, "answer": "B", "explanation": "Cash discounts are typically offered for prompt settlement of accounts. This incentivizes customers to pay their bills quickly, which improves cash flow for the seller.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>11", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Where there is no partnership agreement, any contribution in excess of the agreed capital attracts", "images": [], "options": {"A": "no interest at all", "B": "interestattherateof212%perannum", "C": "interest at the rate of 5% per annum", "D": "interestattherateof712%perannum"}, "answer": "C", "explanation": "In the absence of a partnership agreement, any contribution in excess of the agreed capital typically attracts interest at a statutory rate. In many jurisdictions, this rate is set at 5% per annum, which is a common legal standard for such situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>12", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question  Balance Sheet  ##Ordinary share capital 100000 PLant and machinery 600006% Preference share capital 60000 Furniture 50000Reserve  20000  Motor van  68000  180000 Stock 1400010% Debentures 40000 Debtors 36000Creditors 25000 Prepayments 1800Accrued rent  3000  Bank  18200 248,000248,000    What is the current ratio?", "images": [], "options": {"A": "1: 1", "B": "1: 2", "C": "2.5: 1", "D": "5: 2"}, "answer": "C", "explanation": "The current ratio is calculated as current assets divided by current liabilities.     In this case, current assets include stock (14,000), debtors (36,000), prepayment (1800)and bank (18,200)   =   70,000    Current liabilities include creditors (25,000) and accrued rent (3,000)= 28,000.     Therefore, the current ratio is 70000 / 28,000   = 2.5: 1", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>13", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question  Balance Sheet  ##Ordinary share capital 100000 PLant and machinery 600006% Preference share capital 60000 Furniture 50000Reserve  20000  Motor van  68000  180000 Stock 1400010% Debentures 40000 Debtors 36000Creditors 25000 Prepayments 1800Accrued rent  3000  Bank  18200 248,000248,000  What is the ratio of debenture to equity?", "images": [], "options": {"A": "1: 1", "B": "2: 9", "C": "3: 1", "D": "5: 2"}, "answer": "B", "explanation": "The ratio of debentures to equity is calculated by dividing the total debentures by the total equity.     The total debentures are 40,000, and the total equity (ordinary share capital + preference share capital + reserves) is 100,000 + 60,000 + 20,000   = 180,000.     Thus, the ratio is 40,000 / 180,000   = 2: 9", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>14", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question  Balance Sheet  ##Ordinary share capital 100000 PLant and machinery 600006% Preference share capital 60000 Furniture 50000Reserve  20000  Motor van  68000  180000 Stock 1400010% Debentures 40000 Debtors 36000Creditors 25000 Prepayments 1800Accrued rent  3000  Bank  18200 248,000248,000  What is the net total of assets?", "images": [], "options": {"A": "#178,000", "B": "#208,000", "C": "#220,000", "D": "#248,000"}, "answer": "D", "explanation": "The net total of assets is the sum of all assets listed in the balance sheet.     The total assets include plant and machinery (60,000), furniture (50,000), motor van (68,000), stock (14,000), debtors (36,000), and bank (18,200).     60,000 + 50,000 + 68,000 + 14,000 + 36,000 + 18,200   = #248,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>15", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question  Balance Sheet  ##Ordinary share capital 100000 PLant and machinery 600006% Preference share capital 60000 Furniture 50000Reserve  20000  Motor van  68000  180000 Stock 1400010% Debentures 40000 Debtors 36000Creditors 25000 Prepayments 1800Accrued rent  3000  Bank  18200 248,000248,000  What is the equity capital?", "images": [], "options": {"A": "#100,000", "B": "#120,000", "C": "#160,000", "D": "#180,000"}, "answer": "D", "explanation": "Equity capital is calculated as the total of ordinary share capital, preference share capital, and reserves. In this case, ordinary share capital is 100,000, preference share capital is 60,000, and reserves are 20,000.     Therefore, the total equity capital is 100,000 + 60,000 + 20,000   = #180,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>16", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Use the following information to answer the question  Balance Sheet  ##Ordinary share capital 100000 PLant and machinery 600006% Preference share capital 60000 Furniture 50000Reserve  20000  Motor van  68000  180000 Stock 1400010% Debentures 40000 Debtors 36000Creditors 25000 Prepayments 1800Accrued rent  3000  Bank  18200 248,000248,000  The working capital is", "images": [], "options": {"A": "#42,000", "B": "#60,000", "C": "#160,000", "D": "#180,000"}, "answer": "A", "explanation": "Working capital is calculated as current assets minus current liabilities.    In this case, current assets include stock (14,000), debtors (36,000), Prepayment (1800) and bank (18,200)  = 70,000    Current liabilities include creditors (25,000) and accrued rent (3,000)  =  28,000.     Therefore, working capital = 70000 - 28000  = #42,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>17", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Which of the following is a current asset item?", "images": [], "options": {"A": "Goodwill", "B": "Bank overdraft", "C": "Preliminary expenses", "D": "Prepayments"}, "answer": "D", "explanation": "A current asset is an asset that is expected to be converted into cash or used up within one year. Prepayments are considered current assets because they represent payments made in advance for goods or services to be received in the future. The other options do not qualify as current assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>18", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Which of the following is a real account?", "images": [], "options": {"A": "wages and salaries account", "B": "machinery account", "C": "capital account", "D": "drawings account"}, "answer": "B", "explanation": "A real account is an account that represents tangible assets or liabilities. The machinery account is a real account because it represents a physical asset owned by the business. The other options are nominal accounts, which represent income, expenses, or equity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>19", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Use the following information to answer the question  Year to 31st December Debtors after and debts written off Doubtful debts # #1984 12000 1001985 15000 1301986 14000 115    What was the treatment of provision for doubtful debts in the Profit and Loss Account for 1985?", "images": [], "options": {"A": "Debit #30", "B": "Credit #30", "C": "Credit #130", "D": "Debit #130"}, "answer": "B", "explanation": "In 1985, the provision for doubtful debts is calculated based on the doubtful debts figure of 130. This amount is credited to the Profit and Loss Account to account for the estimated uncollectible debts. Therefore, the correct treatment is 'Credit #130'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>20", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Use the following information to answer the question  Year to 31st December Debtors after and debts written off Doubtful debts # #1984 12000 1001985 15000 1301986 14000 115  In 1986, debtors figure will appear in the Balance Sheet as", "images": [], "options": {"A": "#13,655", "B": "#13,755", "C": "#13,885", "D": "#14,000"}, "answer": "C", "explanation": "In 1986, the debtors figure will appear in the Balance Sheet as the total debtors after accounting for doubtful debts.     The debtors figure is 14,000, and the doubtful debts are 115, which means the net debtors will be 14,000 - 115   = #13,885.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>21", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question  A plant which costs #10,000 and has a residual value of #125 is depreciated at 20% per annum.    Using the diminishing balance method, what is the amount of depreciation for the second year?", "images": [], "options": {"A": "#1280", "B": "#1400", "C": "#1600", "D": "#1750"}, "answer": "C", "explanation": "Using the diminishing balance method, the depreciation for the first year is calculated as 20% of the cost price.     Therefore, for the first year, depreciation = 20% of #10,000   = #2,000.     The book value at the end of the first year = #10,000 - #2,000   = #8,000.     For the second year, depreciation = 20% of #8,000   = #1,600.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>22", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question  A plant which costs #10,000 and has a residual value of #125 is depreciated at 20% per annum.  Using the straight line method, what is the depreciation charge for the second year?", "images": [], "options": {"A": "#1280", "B": "#1400", "C": "#1600", "D": "#1975"}, "answer": "D", "explanation": "Using the straight-line method, the annual depreciation is calculated as (Cost - Residual Value) / Useful Life.     Depreciable amount = 10000 - 125  = 9875    Annual depreciation = 20% x 9875  = #1975 since the same amount is charged every year", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>23", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question  A plant which costs #10,000 and has a residual value of #125 is depreciated at 20% per annum.  Using the diminishing balance, what is the net book value at the second year?", "images": [], "options": {"A": "#5120", "B": "#5250", "C": "#6400", "D": "#7000"}, "answer": "C", "explanation": "Using the diminishing balance method, the depreciation for the first year is calculated as 20% of the cost price.     Therefore, for the first year, depreciation = 20% of #10,000   = #2,000.     The book value at the end of the first year = #10,000 - #2,000   = #8,000.     For the second year, depreciation = 20% of #8,000   = #1,600.     Therefore, the net book value at the end of the second year = #8,000 - #1,600   = #6,400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>24", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Which of the following serves the same purpose as the Income and Expenditure Account of a non-trading organisation?", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Balance Sheet", "D": "Income Distribution Account"}, "answer": "B", "explanation": "The Income and Expenditure Account of a non-trading organization serves a similar purpose to the Profit and Loss Account, as both accounts summarize the income and expenses over a period. Therefore, the correct option is the Profit and Loss Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>25", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following is treated under Partnership Appropriation Account?", "images": [], "options": {"A": "Interest on loan", "B": "Salary of workers", "C": "Electricity", "D": "Salary of Partner"}, "answer": "D", "explanation": "In a Partnership Appropriation Account, the Salary of Partner is treated as an appropriation of profit. This is because it is a distribution of the profits earned by the partnership to the partners. Therefore, the correct option is the Salary of Partner.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>26", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Debtors at start was #5,600 and at a close #3,460. Cash and cheque received from customers amounted to #16,330. Credit sales for the year valued", "images": [], "options": {"A": "#3,460", "B": "#5,620", "C": "#14,190", "D": "#16,330"}, "answer": "C", "explanation": "To calculate the credit sales for the year, we can use the formula: Credit Sales = Cash received from customers + Debtors at close- Debtors at start      Credit sales = 16330 + 3460 - 5600  = #14190", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>27", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "The excess of current assets over current liabilities is", "images": [], "options": {"A": "fixed capital", "B": "registered capital", "C": "nominal capital", "D": "working capital"}, "answer": "D", "explanation": "The excess of current assets over current liabilities is known as working capital. Working capital is a measure of a company's short-term financial health and its efficiency in using its current assets and liabilities. It is calculated as Current Assets - Current Liabilities. Therefore, the correct option is 'working capital'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>28", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Rate of stock turnover is defined as", "images": [], "options": {"A": "purchase over stock", "B": "cost of goods available for sale over total of opening and closing stock", "C": "cost of goods sold for sale over total of opening and closing stock", "D": "cost of goods sold over average stock"}, "answer": "D", "explanation": "The rate of stock turnover is defined as the cost of goods sold over average stock. This ratio indicates how many times a company's inventory is sold and replaced over a period. It is a measure of efficiency in managing inventory. Therefore, the correct option is 'cost of goods sold over average stock'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>29", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following is not true of a partnership business without written agreement?", "images": [], "options": {"A": "Profit and Losses will be shared equally", "B": "Interest not to be paid on capital", "C": "Interest on drawings is to be at the rate of 5% per annum", "D": "Salaries are not allowed to partners"}, "answer": "C", "explanation": "In a partnership without a written agreement, it is generally assumed that profits and losses will be shared equally among partners. However, the statement 'Interest on drawings is to be at the rate of 5% per annum' is not true, as there is no standard rate for interest on drawings unless specified in a written agreement. Therefore, the correct option is 'Interest on drawings is to be at the rate of 5% per annum'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>30", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Creditors at start was #940 and purchases for the year was #4,060. During the year, cash paid to creditors was #3,890. #490 was received as discount. What is the creditors amount in the balance sheet?", "images": [], "options": {"A": "#450", "B": "#620", "C": "#660", "D": "#1,110"}, "answer": "B", "explanation": "To find the creditors amount in the balance sheet, we can use the formula:     Creditors at end = Creditors at start + Purchases - Cash paid to creditors - Discounts received.     Here, Creditors at start = #940, Purchases = #4,060, Cash paid = #3,890, and Discounts = #490.     Therefore, Creditors at end = 940 + 4060 - 3890 - 490   = #620.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>31", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A cheque drawn for #1,200 was entered in the cash book as a receipt. The accounting entries are", "images": [], "options": {"A": "credit Cash Account, debit Bank Account with #1,200", "B": "debit Cash Account, credit Bank Account with #1,200", "C": "credit Cash Account, debit Suspense Account with #2,400", "D": "debit Cash Account, debit Suspense Account with #2,400"}, "answer": "B", "explanation": "The cheque drawn for #1,200 was incorrectly entered as a receipt in the cash book. The correct accounting entry should be to debit the Bank Account (as the bank is being reduced by the cheque amount) and credit the Cash Account (as cash is not actually received). Therefore, the correct entry is 'debit Bank Account, credit Cash Account with #1,200'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>32", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the question  Debtors on 1st January was #1,490 and sales for the year was #5,760. Cash received from debtors during the year was #5,410. Bad debt written off was #410. Discount allowed amounted to #320.    What was the debtors' balance at the end of the year?", "images": [], "options": {"A": "#1,110", "B": "#1,430", "C": "#1,520", "D": "#1,750"}, "answer": "A", "explanation": "Ending Debtors = Opening Debtors + Sales - Cash Received - Bad Debts - Discounts     Ending Debtors = #1,490 + #5,760 - #5,410 - #410 - #320     = #1,110.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>33", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the question  Debtors on 1st January was #1,490 and sales for the year was #5,760. Cash received from debtors during the year was #5,410. Bad debt written off was #410. Discount allowed amounted to #320.  What is the the net profit for that year, assuming a gross profit of #3,650 was made?", "images": [], "options": {"A": "#2,920", "B": "#3,240", "C": "#3,330", "D": "#5,340"}, "answer": "A", "explanation": "Net Profit = Gross Profit - (Bad Debts + Discounts)     Net Profit = #3,650 - (#410 + #320)     = #3,650 - #730     = #2,920.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>34", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following errors will not allow a Trial balance to agree?", "images": [], "options": {"A": "Where a transaction is completely omitted from the books", "B": "Where the correct amount is entered but in the wrong account", "C": "Where the figure entered on one side is different from the one entered on the other side", "D": "Where an item is entered in the wrong class of account"}, "answer": "A", "explanation": "A trial balance will not agree if a transaction is completely omitted from the books because this means that the total debits and credits will not match. In contrast, if the correct amount is entered but in the wrong account, the trial balance may still agree, as the total debits and credits remain the same. Therefore, the correct answer is 'Where a transaction is completely omitted from the books'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>35", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Profit expressed as a proportion of cost price is known as", "images": [], "options": {"A": "gross profit", "B": "profit mark-up", "C": "profit margin", "D": "profit percentage"}, "answer": "B", "explanation": "Profit expressed as a proportion of cost price is known as 'profit mark-up'. This term refers to the amount added to the cost price of goods to cover overhead and profit. It is calculated as (Selling Price - Cost Price) / Cost Price. Therefore, the correct answer is 'profit mark-up'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>36", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Bosun bought goods worth #500 and sold it at a margin of 20% on selling price. For how much did he sell the goods?", "images": [], "options": {"A": "#100", "B": "#125", "C": "#500", "D": "#625"}, "answer": "D", "explanation": "Bosun sold the goods at a margin of 20% on the selling price.     Let the selling price be 'SP'.   The margin is calculated as 20% of SP, which means the cost price (CP) is 80% of SP.     Therefore, if CP is #500, we can set up the equation:   0.8 x SP   = 500.     Solving for SP gives:   SP = 500 / 0.8   = #625.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>37", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following does not appear on the debit side of a company's profit and loss appropriation account?", "images": [], "options": {"A": "Company tax", "B": "Unappropriated surplus", "C": "Proposed dividend", "D": "Transfer to reserve"}, "answer": "A", "explanation": "In a company's profit and loss appropriation account, the debit side typically includes expenses and distributions such as proposed dividends, transfers to reserves, and interim dividends paid. Company tax, however, is an expense that appears on the debit side of the profit and loss account, not the appropriation account. Therefore, the correct answer is 'Company tax'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>38", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following is not a Profit and Loss Appropriation Account item?", "images": [], "options": {"A": "Staff salaries", "B": "Interest on capital", "C": "Interest on money advanced by partners", "D": "Share of profit"}, "answer": "A", "explanation": "The Profit and Loss Appropriation Account deals with the distribution of profits among partners and shareholders. Items like staff salaries and interest on capital are expenses that would appear in the profit and loss account, not in the appropriation account. Therefore, 'Staff salaries' is not an item in the Profit and Loss Appropriation Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>39", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Drawing appear on the", "images": [], "options": {"A": "debit side of the Profit and Loss Account", "B": "credit side of the Profit and Loss Account", "C": "debit side of the Appropriation Account", "D": "debit side of the Current Account"}, "answer": "C", "explanation": "Drawings represent the amounts taken out of the business by the owners and are recorded on the debit side of the Current Account, which reflects the personal accounts of the owners. They do not appear on the Profit and Loss Account or the Appropriation Account. Therefore, the correct answer is 'debit side of the Current Account'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>40", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Sales of goods for #500 to Eddy was not posted. This is an error of", "images": [], "options": {"A": "omission", "B": "compensation", "C": "commission", "D": "principle"}, "answer": "A", "explanation": "The error of omission occurs when a transaction is completely left out of the accounting records. In this case, the sale of goods for #500 to Eddy was not posted at all, which is a classic example of an omission error. Therefore, the correct answer is 'omission'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>41", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Purchase of goods for #1,000 from Chukwu had been entered in Chukwura's Account. This is an error of", "images": [], "options": {"A": "omission", "B": "compensation", "C": "commission", "D": "principle"}, "answer": "D", "explanation": "This is an error of principle because the purchase of goods should be recorded in the correct account (Purchases) rather than in Chukwura's Account. An error of principle occurs when a transaction is recorded in a way that violates the fundamental accounting principles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>42", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A typewriter for office use sold for #5,000 was posted to Sales Account. This is an error of", "images": [], "options": {"A": "omission", "B": "compensation", "C": "commission", "D": "principle"}, "answer": "D", "explanation": "This is an error of principle because the sale of a typewriter, which is an asset, should not be recorded in the Sales Account. Instead, it should be recorded in the appropriate asset account. An error of principle occurs when the accounting treatment of a transaction is incorrect based on the nature of the transaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>43", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Goods purchased for #92 was entered in the books as #29. This is an error of", "images": [], "options": {"A": "compensation", "B": "omission", "C": "original entry", "D": "principle"}, "answer": "C", "explanation": "This is an error where a wrong amount is entered on the debit and credit sides.  This type of error is when an amount is incorrectly posted. It will not affect the trial balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>44", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "John brought in an additional plant into his business. What are the accounting entries necessary to reflect the transaction?", "images": [], "options": {"A": "Debit Plant Account, credit Current Account", "B": "Debit Current Account, credit Plant Account", "C": "Credit Plant Account, credit Profit and Loss Account", "D": "Debit Profit and Loss Account, Credit Plant Account"}, "answer": "A", "explanation": "The correct accounting entries for bringing in an additional plant into the business would be to debit the Plant Account (to increase the asset) and credit the Current Account (to reflect the owner's contribution). This reflects the increase in assets due to the owner's investment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>45", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Patent and Trade Mark are classified under", "images": [], "options": {"A": "fixed assets", "B": "current assets", "C": "intangible assets", "D": "wasting assets"}, "answer": "C", "explanation": "Patent and Trade Mark are classified under intangible assets because they represent non-physical assets that provide value to a business. Intangible assets are identifiable non-monetary assets without physical substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>46", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the information below to answer the question  A machine bought for #7,000 was estimated to have a useful life of 4 years and a scrap value of #500.    Using the straight line method, what is the amount of depreciation charged per annum?", "images": [], "options": {"A": "#1,313", "B": "#1,406", "C": "#1,625", "D": "#1,750"}, "answer": "C", "explanation": "To calculate the annual depreciation using the straight-line method, we use the formula: (Cost - Scrap Value) / Useful Life.     Here, the cost is #7,000, the scrap value is #500, and the useful life is 4 years.     Thus, the annual depreciation is (#7,000 - #500) / 4   = #1,625.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>47", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the information below to answer the question  A machine bought for #7,000 was estimated to have a useful life of 4 years and a scrap value of #500.  Using the reducing balance method, what is the amount of depreciation for the second year?", "images": [], "options": {"A": "#1,313", "B": "#1,406", "C": "#1,625", "D": "#1,734"}, "answer": "B", "explanation": "Scrap value = cost x (1 - r)n  500 = 700 x (1 - r)4    500/700 = (1 - r)4    0.07143 = (1- r)4    (1 -r) = 4&radic;0.7143&nbsp;    1 -r = 0.5748    r = 1 - 0.5748   r= 0.4522 or 54.22%    Year 1 : 7000 x 45.22%  = 3165.40  NBV = 7000 - 3165.40  = 3834.60    Year 2: 3834.60 x 45.22  = #1,734.43", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1994>48", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Use the information below to answer the question  A machine bought for #7,000 was estimated to have a useful life of 4 years and a scrap value of #500.  What is the Net Book Value of the machine at the end of the second year?", "images": [], "options": {"A": "#3,250", "B": "#3,562", "C": "#3,656", "D": "#3,750"}, "answer": "A", "explanation": "The Net Book Value (NBV) at the end of the second year is calculated by deducting the total depreciation from the original cost.     The total depreciation after two years using the straight-line method is #1,625 x 2   = #3,250.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1994>49", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Fixed Assets include", "images": [], "options": {"A": "prepayment", "B": "stock", "C": "accrual", "D": "land"}, "answer": "D", "explanation": "Fixed assets are long-term tangible assets that are used in the operations of a business. They include land, buildings, machinery, and equipment. Among the options provided, 'land' is a fixed asset, while the others (prepayment, stock, accrual, debenture) do not fall under this category. Therefore, the correct option is 'land', which corresponds to option 4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1994>50", "subject": "Accounts", "year": "1994", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Deferred charges are also known as", "images": [], "options": {"A": "accrued expenses", "B": "accrued income", "C": "prepaid expenses", "D": "preliminary expenses"}, "answer": "D", "explanation": "Deferred charges refer to expenses that have been paid but not yet incurred. They are also known as preliminary expenses. Among the options provided, 'preliminary expenses' is the correct term for deferred charges.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>1", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Which of the following is the effect of a reduction in the provision for doubtful debts?", "images": [], "options": {"A": "reduction in net profit", "B": "reduction in cash balance", "C": "increase in net profit", "D": "increase in gross profit"}, "answer": "C", "explanation": "A reduction in the provision for doubtful debts means that the company expects fewer debts to be uncollectible. This would increase the net profit as less money is set aside to cover these potential losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>2", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following is the basis of accounting in the Civil Service?", "images": [], "options": {"A": "accrual", "B": "cash", "C": "income", "D": "expenditure"}, "answer": "B", "explanation": "Under the cash basis, financial transactions are recorded in the books when actual payment is made or money is received. This approach does not take into consideration creditors and debtors and it is a major basis of public sector accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>3", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "The reward given to a debenture holder is called", "images": [], "options": {"A": "profit", "B": "reserve", "C": "premium", "D": "interest"}, "answer": "D", "explanation": "The reward given to a debenture holder is called interest. Debentures are a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>4", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not a debit entry on a sales ledger control account?", "images": [], "options": {"A": "goods sold", "B": "cash received", "C": "dishonoured cash", "D": "payment to debtors for claim"}, "answer": "B", "explanation": "Cash received is not a debit entry on a sales ledger control account. It is a credit entry because it increases the company's assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>5", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "If incorrect entries on the debit side equal other incorrect entries on the credit side, the error is that of", "images": [], "options": {"A": "ordinary entry", "B": "omission", "C": "commission", "D": "principle"}, "answer": "D", "explanation": "An error of principle is a technical error, meaning that the value recorded was the correct value but placed wrongly. For example, amount spent on additions to the buildings should be treated as capital expenditure and must be debited to the asset account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>6", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The accounting entries required for increase in provision for doubtful debts are", "images": [], "options": {"A": "debit profit and loss account, credit provision for doubtful debts account", "B": "credit provision for doubtful debts account; debit debtors account", "C": "credit trading account; credit provision and doubtful debts account", "D": "credit trading trading account; debit provision for doubtful debts account"}, "answer": "A", "explanation": "The accounting entries required for increase in provision for doubtful debts are debit profit and loss account, credit provision for doubtful debts account. This is because an increase in provision for doubtful debts reduces the net profit and increases the liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>7", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscription in advance is an example of", "images": [], "options": {"A": "payment", "B": "accrual", "C": "debtors", "D": "provision"}, "answer": "B", "explanation": "Subscription in advance is an example of accrual. Accruals are revenues earned or expenses incurred which impact a company's net income, although cash related to the transaction has not yet changed hands.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>8", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is an example of Personal Accounts?", "images": [], "options": {"A": "stock", "B": "fixture", "C": "equipment", "D": "debtors"}, "answer": "D", "explanation": "Debtors are an example of Personal Accounts. Personal accounts relate to individuals, companies, and their representatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>9", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000    The cost of goods sold is", "images": [], "options": {"A": "N45,000", "B": "N30,000", "C": "N25,000", "D": "N15,000"}, "answer": "D", "explanation": "Cost of goods sold = Opening stock + Purchases - Closing stock   = 20,000 + 25,000 - 30,000  = #15,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>10", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000  Net profit is", "images": [], "options": {"A": "N45,000", "B": "N30,000", "C": "N25,000", "D": "N15,000"}, "answer": "D", "explanation": "First, determine the gross profit.  Gross profit = Sales - Cost of goods sold   = 45,000 - 15,000  = 30,000    Net profit = Gross profit - Expenses  =  30,000 - 15,000  = #15,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>11", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000  Net profit percentage is", "images": [], "options": {"A": "100%", "B": "67%", "C": "50%", "D": "33%"}, "answer": "D", "explanation": "Net profit as a percentage = NP/Sales   x100    15000/45000  x 100    = 33.3  = 33%", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>12", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000  Current ratio is", "images": [], "options": {"A": "16 : 1", "B": "15 : 1", "C": "8 : 1", "D": "2 : 1"}, "answer": "C", "explanation": "Current ratio = Current assets/ Current liabilities     Current asset = debtors and closing stock  Current liabilty = creditors    Therefore, Current ratio = 10,000 + 30,000/5,000    =  40,000 /5,000    = 8 : 1", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>13", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000  Working capital is", "images": [], "options": {"A": "N60,000", "B": "N45,000", "C": "N40,000", "D": "N35,000"}, "answer": "D", "explanation": "Working capital = Current assets - Current liabilities  =  30,000 + 10,000 - 5,000  = #35,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>14", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following to answer the given questions      NSales 45 000Opening stock 20 000closing stock 30 000expenses 15 000fixed assets 40 000debtors 10 000creditors 5 000purchases 25 000  Gross profit percentage is", "images": [], "options": {"A": "100%", "B": "67%", "C": "50%", "D": "33%"}, "answer": "B", "explanation": "Gross profit percentage = GP/Sales x 100     = 30000/45000  x 100    = 66.6  =  67%", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>15", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Working capital is measured by the excess of", "images": [], "options": {"A": "current liabilities over current assets", "B": "fixed assets over current assets", "C": "currents assets over current liabilities", "D": "current assets over fixed assets"}, "answer": "C", "explanation": "Working capital is measured by the excess of current assets over current liabilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>16", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "The undistributed profits of a limited liability company is", "images": [], "options": {"A": "goodwill", "B": "working capital", "C": "net profit", "D": "retained earings"}, "answer": "D", "explanation": "The undistributed profits of a limited liability company is known as retained earnings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>17", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Use the following information to answer the question    Nbalance as per bank statement 240amount paid in but not credited 192unpresented cheques 70  what is the balance as per cashbook?", "images": [], "options": {"A": "N362", "B": "N310", "C": "N262", "D": "N240"}, "answer": "A", "explanation": "Balance as per bank statement  240Add: Uncredited cheque   192  432 Less: Unpresented cheque   70 Balance as per cash book  362", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>18", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Credit sales were debited to A. Akpan instead of B. Akpan. This is an error of", "images": [], "options": {"A": "principle", "B": "original entry", "C": "omission", "D": "commission"}, "answer": "D", "explanation": "Credit sales were debited to A. Akpan instead of B. Akpan. This is an error of commission, which occurs when an incorrect account is debited or credited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>19", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A list of balance extracted from the ledger is known as.", "images": [], "options": {"A": "balance sheet", "B": "statement of affairs", "C": "trading account", "D": "trial balance"}, "answer": "D", "explanation": "A list of balance extracted from the ledger is known as a trial balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>20", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Provision for depreciation on office furniture is charged to", "images": [], "options": {"A": "capital account", "B": "profit and loss appropriation account", "C": "trading account", "D": "profit and loss account"}, "answer": "D", "explanation": "Provision for depreciation on office furniture is charged to the profit and loss account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>21", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following is not a cause of discrepancy between cash book and bank statement balances?", "images": [], "options": {"A": "deposits in transit", "B": "standing order", "C": "paid cheques", "D": "dishonoured cheque"}, "answer": "C", "explanation": "Paid cheques is not one of the reasons for disagreement between the cash book and statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>22", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The financial plan of the government for a year is contained in the", "images": [], "options": {"A": "vote book", "B": "cash analysis book", "C": "budget", "D": "general order"}, "answer": "C", "explanation": "The financial plan of the government for a year is contained in the budget. A budget is an estimate of income and expenditure for a set period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>23", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "When a business is purchased, the double entries required in the purchaser's book are debit", "images": [], "options": {"A": "vendor's account and credit purchase of business account", "B": "asset account and credit purchases of business account", "C": "cash account and credit vendor's account", "D": "vendor's account and credit cash account"}, "answer": "B", "explanation": "When a business is purchased, the double entries required in the purchaser's book are debit asset account and credit purchases of business account. This is because the assets of the business are increasing (hence the debit) and the business is incurring a liability or reducing equity (hence the credit).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>24", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following are on the bank statement before reconciliation?     i. standing order   ii. payment to a creditor   iii. receipt from a debtor   iv. uncredited cheque   v. unpresented cheque", "images": [], "options": {"A": "i and v", "B": "i and ii", "C": "i, ii and iii", "D": "i and iv"}, "answer": "C", "explanation": "Uncredited cheques and unpresented cheques will not appear on the bank statement before the preparrtion of bank reconciliation statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>25", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions   DEBTORS CONTROL ACCOUNT  N NBalance b/d 8000 Bank \"Y\"'X' 12000 Discount 200  Balance c/d 3000    'X' refers to", "images": [], "options": {"A": "stock", "B": "returns", "C": "discount", "D": "sales"}, "answer": "D", "explanation": "'X' refers to sales. In a debtor's control account, sales are recorded on the debit side, while payments from debtors (bank) and discounts allowed are recorded on the credit side.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>26", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions   DEBTORS CONTROL ACCOUNT  N NBalance b/d 8000 Bank \"Y\"'X' 12000 Discount 200  Balance c/d 3000  how much is the figure for bank?", "images": [], "options": {"A": "N20000", "B": "N17 000", "C": "N16 800", "D": "N12 000"}, "answer": "C", "explanation": "The figure for bank is N16 800. This is calculated by subtracting the balance carried down (N3000) and the discount (N200) from the balance brought down (N8000) and the sales (N12000).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>27", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions   DEBTORS CONTROL ACCOUNT  N NBalance b/d 8000 Bank \"Y\"'X' 12000 Discount 200  Balance c/d 3000  The closing balance is a", "images": [], "options": {"A": "current asset", "B": "current liability", "C": "fixed asset", "D": "fictitious asset"}, "answer": "A", "explanation": "The closing balance of a debtor's control account is a current asset. Current assets are assets that are expected to be converted to cash within one year. Debtors are people who owe the business money, and this is expected to be received within one year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>28", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A fund established for the payment of minor expenses is", "images": [], "options": {"A": "cash discount", "B": "cash flow", "C": "petty cash", "D": "accumulated fund"}, "answer": "C", "explanation": "A fund established for the payment of minor expenses is petty cash. Petty cash is a small amount of cash on hand that is used for paying small amounts owed, rather than writing a check.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>29", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "The maximum amount which a company can raise by way of selling share is", "images": [], "options": {"A": "issued capital", "B": "working capital", "C": "paid-up capital", "D": "authorized capital"}, "answer": "D", "explanation": "The maximum amount which a company can raise by way of selling share is authorized capital. Authorized capital is the maximum amount of share capital that the company is authorized by its constitutional documents to issue to shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>30", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The aggregate of amounts owed to a business by is customers is known as", "images": [], "options": {"A": "accounts receivable", "B": "account current", "C": "accounts payable", "D": "accumulated fund"}, "answer": "A", "explanation": "The aggregate of amounts owed to a business by its customers is known as accounts receivable. Accounts receivable is a legally enforceable claim for payment from a business to its customer/clients for goods supplied and/or services rendered in execution of the customer's order.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>31", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "MISCELLANEOUS ACCOUNTS : CONSIGNMENT ACCOUNTS", "question": "Which of the following does a consignee prepare and send to his consignor?", "images": [], "options": {"A": "account receivable", "B": "current account", "C": "account payable", "D": "account sales"}, "answer": "D", "explanation": "A consignee prepares and sends an 'account sales' to his consignor. This document provides a detailed account of the sale of the consignor's goods, including the quantity sold, the price, the total amount received, and the expenses related to the sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>32", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "MISCELLANEOUS ACCOUNTS : CONSIGNMENT ACCOUNTS", "question": "In the consignee's record account, the accounting treatment of expenses paid for on behalf of the consignor is debit", "images": [], "options": {"A": "consignor's account, credit cash account, credit cash account", "B": "cash account, credit consignor's account", "C": "consignee's account, credit cash account", "D": "cash account, credit consignee's account"}, "answer": "A", "explanation": "Accounting entries:  Debit : Consignment account  Credit: Cash/bank account  With the amount paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>33", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following is a fictitious asset?", "images": [], "options": {"A": "preliminary expenses", "B": "fixtures and fittings", "C": "cash in hand", "D": "land and buildings"}, "answer": "A", "explanation": "A fictitious asset is an asset that has no tangible existence and cannot be seen or felt. Preliminary expenses are a type of fictitious asset. They are the expenses incurred during the formation of a company and are written off over a period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>34", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the questions    The department of Administration of Odi Naka Chukwu State Water Corporation has underlisted staff position on 31st December, 1993  Post Grade Number in post rate- - - -Director of Audit 16 1 N200 000 x N20 000-N300 000Assistant Director (Audit) 15 2 N160 000 x N18 000-N268 000Asst. Chief Internal Auditor 13 1 N140 000 x N12 000-N224 000Internal Auditor II 08 2 N60 000 x N6 000-N120 000Higher Executive Officer (Audit) 08 4 N60 000 x N6 000-N120 000  NOTE: (a) All employees are on the first step of their salary  (b) Grade level Housing Allowance Transport Allowance     12 and Above N24 000 p.a N18 000 p.a     07 to 11 N18 000 p.a N12 000 p.a    The total basic salary for the period is", "images": [], "options": {"A": "N1,368", "B": "N1,224,000", "C": "N1, 924,000", "D": "N1,020,000"}, "answer": "D", "explanation": "200000  x 1 = 200000160000  x 2 = 320000140000  x 1 = 14000060000  x 2 = 12000060000  x 4 =  240000 Total basic salary 1020000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>35", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the questions    The department of Administration of Odi Naka Chukwu State Water Corporation has underlisted staff position on 31st December, 1993  Post Grade Number in post rate- - - -Director of Audit 16 1 N200 000 x N20 000-N300 000Assistant Director (Audit) 15 2 N160 000 x N18 000-N268 000Asst. Chief Internal Auditor 13 1 N140 000 x N12 000-N224 000Internal Auditor II 08 2 N60 000 x N6 000-N120 000Higher Executive Officer (Audit) 08 4 N60 000 x N6 000-N120 000  NOTE: (a) All employees are on the first step of their salary  (b) Grade level Housing Allowance Transport Allowance     12 and Above N24 000 p.a N18 000 p.a     07 to 11 N18 000 p.a N12 000 p.a  Total housing allowance for the period is", "images": [], "options": {"A": "N404,000", "B": "N242,000", "C": "N204,000", "D": "144,000"}, "answer": "C", "explanation": "The total housing allowance can be calculated by adding up the housing allowance for each grade level multiplied by the number of people in that grade level. The calculation is as follows: (1*24,000) + (2*24,000) + (1*24,000) + (2*18,000) + (4*18,000) = N204,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>36", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the questions    The department of Administration of Odi Naka Chukwu State Water Corporation has underlisted staff position on 31st December, 1993  Post Grade Number in post rate- - - -Director of Audit 16 1 N200 000 x N20 000-N300 000Assistant Director (Audit) 15 2 N160 000 x N18 000-N268 000Asst. Chief Internal Auditor 13 1 N140 000 x N12 000-N224 000Internal Auditor II 08 2 N60 000 x N6 000-N120 000Higher Executive Officer (Audit) 08 4 N60 000 x N6 000-N120 000  NOTE: (a) All employees are on the first step of their salary  (b) Grade level Housing Allowance Transport Allowance     12 and Above N24 000 p.a N18 000 p.a     07 to 11 N18 000 p.a N12 000 p.a  Total transport allowance for the period is", "images": [], "options": {"A": "N404,000", "B": "N242,000", "C": "N204,000", "D": "N144,000"}, "answer": "D", "explanation": "Number of post from 12 and above = 1 + 2 + 1  = 4  Therefore, 4 x 18000  = 72000    Number of post from 07 to 11 = 2 + 4  = 6  Therefore, 6  x 12000  = 72000    Total transport allowance = 72000 + 72000  = #144,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>37", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the questions    The department of Administration of Odi Naka Chukwu State Water Corporation has underlisted staff position on 31st December, 1993  Post Grade Number in post rate- - - -Director of Audit 16 1 N200 000 x N20 000-N300 000Assistant Director (Audit) 15 2 N160 000 x N18 000-N268 000Asst. Chief Internal Auditor 13 1 N140 000 x N12 000-N224 000Internal Auditor II 08 2 N60 000 x N6 000-N120 000Higher Executive Officer (Audit) 08 4 N60 000 x N6 000-N120 000  NOTE: (a) All employees are on the first step of their salary  (b) Grade level Housing Allowance Transport Allowance     12 and Above N24 000 p.a N18 000 p.a     07 to 11 N18 000 p.a N12 000 p.a  The total emolument for the assistant directors is", "images": [], "options": {"A": "N404,000", "B": "N242,000", "C": "N204,000", "D": "N144,000"}, "answer": "A", "explanation": "Basic salary:  160000  x 2 = 320000  Housing allowance : 24000 x 2 = 48000  Transport allowance: 18000  x 2 = 36000  Total emolument for the assistant directors  = 320000 + 48000 + 36000  = #404,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>38", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the questions    The department of Administration of Odi Naka Chukwu State Water Corporation has underlisted staff position on 31st December, 1993  Post Grade Number in post rate- - - -Director of Audit 16 1 N200 000 x N20 000-N300 000Assistant Director (Audit) 15 2 N160 000 x N18 000-N268 000Asst. Chief Internal Auditor 13 1 N140 000 x N12 000-N224 000Internal Auditor II 08 2 N60 000 x N6 000-N120 000Higher Executive Officer (Audit) 08 4 N60 000 x N6 000-N120 000  NOTE: (a) All employees are on the first step of their salary  (b) Grade level Housing Allowance Transport Allowance     12 and Above N24 000 p.a N18 000 p.a     07 to 11 N18 000 p.a N12 000 p.a  The total emolument for the Internal Audit Department is", "images": [], "options": {"A": "N1,368,000", "B": "N1,224,000", "C": "N1,024,000", "D": "N1,020,000"}, "answer": "A", "explanation": "The total emolument for the Internal Audit Department can be calculated by adding up the total basic salary, total housing allowance, and total transport allowance. The calculation is as follows: N1,224,000 (total basic salary) + N204,000 (total housing allowance) + N242,000 (total transport allowance) = N1,368,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1995>39", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Expenditure incurred to maintain an asset's earning capacity is called", "images": [], "options": {"A": "capacity expenditure", "B": "revenue expenditure", "C": "general expenditure", "D": "tangible expenditure"}, "answer": "B", "explanation": "Expenditure incurred to maintain an asset's earning capacity is called 'revenue expenditure'. This type of expenditure is incurred on an ongoing basis to ensure the continuous operation of a business. It includes costs such as salaries, rent, utilities, and maintenance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>40", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Which of the following does not relate to a manufacturing concern?", "images": [], "options": {"A": "balance sheet", "B": "profit and loss account", "C": "ledger account", "D": "income and expenditure"}, "answer": "D", "explanation": "All the options given except 'income and expenditure' relate to a manufacturing concern. An income and expenditure account is a type of financial statement used by non-profit organizations, not manufacturing concerns. It shows the income earned and expenses incurred during a specific period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>41", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is not true of a trial balance?", "images": [], "options": {"A": "list taken of the account balance in the general ledger", "B": "proof of the arithmetical accuracy of the ledger postings", "C": "summary of data for the preparation of financial statement", "D": "list of account abstracted from a subsidiary ledger to check their agreement with the related control account"}, "answer": "D", "explanation": "A trial balance is a report that is completed for internal use only and that does not leave the accounting department of a company. This accounting tool separates the debits and credits that are listed on a company's ledger for a certain period of time and is used to show that each column is equal to the other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>42", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The chief accounting officer of Nigeria is called the", "images": [], "options": {"A": "auditor general", "B": "chief accountant", "C": "treasurer", "D": "accountant general"}, "answer": "D", "explanation": "The chief accounting officer of Nigeria is called the Accountant General. The Accountant General is responsible for managing and supervising the financial and accounting affairs of the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>43", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Expenses incurred but not yet paid is", "images": [], "options": {"A": "contingent liability", "B": "current liability", "C": "current asset", "D": "fixed asset"}, "answer": "B", "explanation": "Expenses incurred but not yet paid are considered as current liabilities. Current liabilities are a company's debts or obligations that are due within one year, appearing on the company's balance sheet and include short term debt, accounts payable, accrued liabilities and other similar debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>44", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Which of the following does not lead to depreciation of assets?", "images": [], "options": {"A": "wear and tear", "B": "passage of time", "C": "devaluation of Naira", "D": "obsolescence"}, "answer": "C", "explanation": "Depreciation is the gradual decrease in the economic value of an asset. It is caused by wear and tear, passage of time, obsolescence, etc. However, devaluation of a currency (like Naira) does not lead to depreciation of assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>45", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Which of the following is capital expenditure?", "images": [], "options": {"A": "purchase of stock", "B": "a purchase of motor vehicles for sale", "C": "subscriptions paid", "D": "extension of building"}, "answer": "D", "explanation": "Capital expenditure is the money spent by a business or organization on acquiring or maintaining fixed assets, such as land, buildings, and equipment. Extension of a building is considered a capital expenditure because it is likely to benefit the business for more than one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>46", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "What are accounting entries for bad debts recovered?", "images": [], "options": {"A": "debit debtor's account, credit bad debts recovered account", "B": "credit debtor's account, debit bad debts recovered account", "C": "debit debtor's credit sales account", "D": "credit debtor's account, debit sales account"}, "answer": "A", "explanation": "When bad debts are recovered, the accounting entry is to debit the debtor's account and credit the bad debts recovered account. This is because the recovery of bad debts is an income for the business, and incomes are credited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1995>47", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "use the following information to answer the questions    Halima and ibinabo are partners sharing profits and losses equally. extracts from their books showed.    Halima Ibinabo  N NCapital accounts 1st Jan 1992 100 000 50 000Current Accounts 1st Jan 1992 20 000 40 000Drawing during the year 10 000 15 000Annual salaries 14 000 12 000  Interest on capital is 10%. The net profit for the year is N60,000.    The interest on Halima's capital is", "images": [], "options": {"A": "N10,000", "B": "N6,000", "C": "N4,0000", "D": "N2,000"}, "answer": "A", "explanation": "Interest on capital is calculated as a percentage of the capital. In this case, Halima's capital is N100,000 and the interest rate is 10%. Therefore, the interest on Halima's capital is 10% of N100,000 which equals N10,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>48", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "use the following information to answer the questions    Halima and ibinabo are partners sharing profits and losses equally. extracts from their books showed.    Halima Ibinabo  N NCapital accounts 1st Jan 1992 100 000 50 000Current Accounts 1st Jan 1992 20 000 40 000Drawing during the year 10 000 15 000Annual salaries 14 000 12 000  Interest on capital is 10%. The net profit for the year is N60,000.   The shares of profit of each partners is", "images": [], "options": {"A": "N17,000", "B": "N15,000", "C": "N10,750", "D": "N9,500"}, "answer": "D", "explanation": "## Interest on capital Halima 10% x 10000010000 Net profit 60000Ibinabo 10%  x 50000 500015000 Annual salaries :Halima 14000Ibinabo 1200026000 Share of profit :Halima ( 1/2 x 19500) 9500Ibinabo ( 1/2  x 19500)  9500 6000060000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>49", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "use the following information to answer the questions    Halima and ibinabo are partners sharing profits and losses equally. extracts from their books showed.    Halima Ibinabo  N NCapital accounts 1st Jan 1992 100 000 50 000Current Accounts 1st Jan 1992 20 000 40 000Drawing during the year 10 000 15 000Annual salaries 14 000 12 000  Interest on capital is 10%. The net profit for the year is N60,000.   The balance on Halima's current account on 31st December, 1992 is", "images": [], "options": {"A": "N66,500", "B": "N53,300", "C": "N51,500", "D": "N43,500"}, "answer": "D", "explanation": "Halima's current account  balance = Bal b/f + interest on capital + salary + share of profit - drawings  = (20000 + 10000 + 14000 + 9500) - 10000  = 53500 - 10000  = #43,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1995>50", "subject": "Accounts", "year": "1995", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "use the following information to answer the questions    Halima and ibinabo are partners sharing profits and losses equally. extracts from their books showed.    Halima Ibinabo  N NCapital accounts 1st Jan 1992 100 000 50 000Current Accounts 1st Jan 1992 20 000 40 000Drawing during the year 10 000 15 000Annual salaries 14 000 12 000  Interest on capital is 10%. The net profit for the year is N60,000.   The balance on Ibinabo's current account on 32st December, 1992 is", "images": [], "options": {"A": "N66,500", "B": "N53,500", "C": "N51,500", "D": "N43,500"}, "answer": "C", "explanation": "Ibinabo's current account  balance = Bal b/f + interest on capital + salary + share of profit - drawings  = (40000 + 5000 + 12000 + 9500 ) - 15000  = 66500 - 15000  = #51,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>1", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Which of the following is the book of original entry for all payments and receipts whether by cash or cheque?.", "images": [], "options": {"A": "sales day book", "B": "purchases day book", "C": "cash book", "D": "cheque book"}, "answer": "C", "explanation": "The cash book is the book of original entry for all payments and receipts whether by cash or cheque. It is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>2", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following is not a cause for the difference between bank statement balance and cash book balance?", "images": [], "options": {"A": "bank charges", "B": "presented cheque", "C": "direct transfer", "D": "standing order"}, "answer": "B", "explanation": "presented cheque is not the cause of discrepancy or disagreement between the cash book and the bank statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>3", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "A sales journal is used to record", "images": [], "options": {"A": "sales expenses", "B": "cash sales", "C": "credit sales", "D": "sales return"}, "answer": "C", "explanation": "A sales journal is used to record credit sales. It is a specialized accounting journal and it is also known as the sales day book. Cash sales are recorded in the cash book, not the sales journal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>4", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following fixed assets is not depreciable?", "images": [], "options": {"A": "building", "B": "tools", "C": "land", "D": "Motor van"}, "answer": "C", "explanation": "Land is not a depreciable asset. Depreciation is the process of allocating the cost of a tangible asset over its useful life. Buildings, tools, and motor vans are all tangible assets that have a limited useful life and therefore can be depreciated. Land, however, has an unlimited useful life and does not depreciate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>5", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Payment is shown in the Balance Sheet as", "images": [], "options": {"A": "Current asset", "B": "liability", "C": "capital", "D": "fixed asset"}, "answer": "B", "explanation": "Payment is shown in the Balance Sheet as a liability. In accounting, a liability is defined as an obligation of an entity arising from past transactions or events, the settlement of which may result in the transfer or use of assets, provision of services or other yielding of economic benefits in the future.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>6", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the questions  Mr. B sold goods worth N200 on credit to Mr. C.    Mr. B should debit this to", "images": [], "options": {"A": "profit and loss account", "B": "manufacturing account", "C": "sales account", "D": "Mr. C's account"}, "answer": "D", "explanation": "When Mr. B sells goods on credit to Mr. C, Mr. B should debit Mr. C's account. This is because in accounting, a debit to an individual's account signifies that the individual owes money to the business. Therefore, Mr. C's account should be debited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>7", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Use the following information to answer the questions  Mr. B sold goods worth N200 on credit to Mr. C.   The credit sales should be entered into", "images": [], "options": {"A": "sales day book", "B": "trading account", "C": "profit and loss account", "D": "purchases day book"}, "answer": "A", "explanation": "Credit sales are recorded in the sales day book. The sales day book is a book of original entry (also known as a prime entry book) where credit sales are recorded before they are posted to the ledger accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>8", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions   An equipment costing N60,000 was bought on 1st January 1991. Depreciation was provided at 20 percent annually on straight line method. It was straight line method. it was sold on 30th June 1994 for N15,750.    Its accumulated depreciation provision at the time of sale was", "images": [], "options": {"A": "N48,000", "B": "N42,000", "C": "N36,000", "D": "N24,000"}, "answer": "B", "explanation": "Equipment #Cost 60000Year 1 Dep ( 20%  x 60000)  12000  48000Year 2 Dep ( 20%  x 60000)  12000  36000Year 3 Dep ( 20%  x 60000)  12000 NBV 24000    Since the depreciation amount to #12000 for each year, then the accumulated depreciation for the three  and half year (1st Jan 1991 to 30th June 1994   = 3.5 x 12000  = #42000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1996>9", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions   An equipment costing N60,000 was bought on 1st January 1991. Depreciation was provided at 20 percent annually on straight line method. It was straight line method. it was sold on 30th June 1994 for N15,750.  The net book value of the equipment at the time sale was", "images": [], "options": {"A": "N48,000", "B": "N36,000", "C": "N37,000", "D": "N18,000"}, "answer": "D", "explanation": "The net book value of an asset is its original cost minus accumulated depreciation. In this case, the original cost is N60,000 and the accumulated depreciation is N36,000 (calculated in the previous question). Therefore, the net book value at the time of sale is N60,000 - N36,000 = N24,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1996>10", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions   An equipment costing N60,000 was bought on 1st January 1991. Depreciation was provided at 20 percent annually on straight line method. It was straight line method. it was sold on 30th June 1994 for N15,750.  In the year of sale, profit was", "images": [], "options": {"A": "reduced by N15,750", "B": "increased by N15,750", "C": "reduced by N12,000", "D": "increased by N2,250"}, "answer": "C", "explanation": "The profit is reduced by the difference between the net book value and the sale price. In this case, the net book value is N24,000 (calculated in the previous question) and the sale price is N15,750. Therefore, the profit is reduced by N24,000 - N15,750 = N8,250. However, none of the options matches this value. The closest option is 'reduced by N12,000', but it is not correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1996>11", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Debentures issued at a price above the nominal value are said to be issued", "images": [], "options": {"A": "at discount", "B": "at premium", "C": "at subsidy", "D": "on goodwill"}, "answer": "B", "explanation": "Debentures issued at a price above the nominal value are said to be issued at a premium. This is because the term 'premium' in finance refers to a situation where a security is priced higher than its nominal or face value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>12", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A trial balance is", "images": [], "options": {"A": "an attempt to balance the accounts", "B": "the credit balances of the accounts", "C": "list of all balances extracted from the ledger", "D": "the debit balances of the accounts"}, "answer": "C", "explanation": "A trial balance is a list of all balances extracted from the ledger. It is a statement that shows if the total debits equal the total credits in the ledgers. It is used to check the arithmetic accuracy and correctness of the bookkeeping entries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>13", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "The balance sheet is a statement showing", "images": [], "options": {"A": "all assets and liabilities", "B": "all balances", "C": "credit entries of the business", "D": "debit entries of the business"}, "answer": "A", "explanation": "The balance sheet is a statement showing all assets and liabilities of a business. It provides a snapshot of a company's financial condition at a specific moment in time. It does not show all balances, credit entries, or debit entries of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>14", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Which of the following entries would be made for goods bought and paid for immediately? Debit", "images": [], "options": {"A": "cash account, credit sales account", "B": "purchases account; credit cash account", "C": "cash account; credit purchases account", "D": "purchases account; credit sales account"}, "answer": "B", "explanation": "For goods bought and paid for immediately, the correct entry would be to debit the purchases account and credit the cash account. This is because the purchases account is increased by debits and the cash account, being an asset, is decreased by credits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>15", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The purpose of a trading account is to ascertain", "images": [], "options": {"A": "sales", "B": "gross profit or loss", "C": "net profit or loss", "D": "carriage outwards"}, "answer": "B", "explanation": "The purpose of a trading account is to ascertain the gross profit or loss of a business. It is the first stage in the preparation of the final accounts of a trading organization. It shows the result of buying and selling goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>16", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Factory wages are always entered into the", "images": [], "options": {"A": "sales account", "B": "manufacturing account", "C": "profit ans loss account", "D": "purchases account"}, "answer": "B", "explanation": "Factory wages are always entered into the manufacturing account. This is because factory wages are a direct cost of production, and therefore are considered part of the cost of manufacturing goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>17", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions    # Fixed assets 12000Current assets 5000Current liabilities 2300Capital 10000Long term liabilities 4700    What is the total assets?", "images": [], "options": {"A": "N17,300", "B": "N17,000", "C": "N15,000", "D": "N14,700"}, "answer": "B", "explanation": "Total assets are the sum of fixed assets and current assets. In this case, fixed assets are N12,000 and current assets are N5,000.     Therefore, the total assets are N12,000 + N5,000   = N17,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>18", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions    # Fixed assets 12000Current assets 5000Current liabilities 2300Capital 10000Long term liabilities 4700  What is the total net assets?", "images": [], "options": {"A": "N17,300", "B": "N17,000", "C": "N15,000", "D": "N14,700"}, "answer": "B", "explanation": "Total net assets are calculated by subtracting total liabilities from total assets. In this case, total assets are N17,000 (N12,000 fixed assets + N5,000 current assets) and total liabilities are N7,000 (N2,300 current liabilities + N4,700 long term liabilities). Therefore, the total net assets are N17,000 - N7,000 = N10,000. However, none of the options matches this answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>19", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions    # Fixed assets 12000Current assets 5000Current liabilities 2300Capital 10000Long term liabilities 4700  Total liabilities amount to", "images": [], "options": {"A": "N17,000", "B": "N14,700", "C": "N12,300", "D": "N7,000"}, "answer": "D", "explanation": "Total liabilities = current liabilties + long term liabilities  = 2300 + 4700  = #7000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>20", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions    # Fixed assets 12000Current assets 5000Current liabilities 2300Capital 10000Long term liabilities 4700  The working capital is", "images": [], "options": {"A": "N10,000", "B": "N9,700", "C": "N7,300", "D": "N2,700"}, "answer": "D", "explanation": "Working capital is calculated by subtracting current liabilities from current assets. In this case, current assets are N5,000 and current liabilities are N2,300. Therefore, the working capital is N5,000 - N2,300 = N2,700.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>21", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "The payee of a cheque is the", "images": [], "options": {"A": "drawer's banker", "B": "drawee's banker", "C": "person named to receive the amount on the cheque", "D": "bank cashier"}, "answer": "C", "explanation": "The payee of a cheque is the person named to receive the amount on the cheque. The drawer is the person who writes the cheque, the drawee is the bank on which the cheque is drawn, and the bank cashier is the person who cashes the cheque.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>22", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is no part of prime cost of production?", "images": [], "options": {"A": "cost raw materials", "B": "carriage on raw materials", "C": "direct expenses", "D": "depreciation of factory equipment"}, "answer": "D", "explanation": "Prime cost of production includes direct costs such as raw materials, direct labor, and other direct costs. Depreciation of factory equipment is an indirect cost, not a part of the prime cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>23", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The person who has applied for shares in a company is called", "images": [], "options": {"A": "allotee", "B": "subscriber", "C": "promoter", "D": "shareholder"}, "answer": "B", "explanation": "A person who has applied for shares in a company is called a subscriber. An allotee is a person to whom the shares have been allotted. A promoter is a person who initiates the process of company formation. A shareholder is a person who owns shares in the company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>24", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "which of the following is not an appropriation account item for company?", "images": [], "options": {"A": "interest on drawings", "B": "proposed dividends", "C": "interim dividends", "D": "provision for taxation"}, "answer": "A", "explanation": "An appropriation account item is an amount set aside out of profits for a specific purpose. Interest on drawings is not an appropriation account item as it is not an amount set aside out of profits. Proposed dividends, interim dividends, and provision for taxation are all appropriation account items.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>25", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "use the following information to answer the questions  The total debtors account of a trading concern is N13,000. Out of this 2 percent is irrecoverable; 5 percent of the balance is unlikely to be collected.    What is the provision for doubtful debts?", "images": [], "options": {"A": "N910", "B": "N650", "C": "N637", "D": "N377"}, "answer": "B", "explanation": "Provision for doubtful debt is calculated as:     = 5%  x 13000    = #650", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>26", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "use the following information to answer the questions  The total debtors account of a trading concern is N13,000. Out of this 2 percent is irrecoverable; 5 percent of the balance is unlikely to be collected.   Bad debts is", "images": [], "options": {"A": "N910", "B": "N650", "C": "N637", "D": "N260"}, "answer": "D", "explanation": "Bad debt is calculated as :    = 2%  x 13000    = #260", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>27", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following are examples of Nominal account?", "images": [], "options": {"A": "land and insurance", "B": "cash and interest", "C": "building and cash", "D": "rent and discount"}, "answer": "D", "explanation": "Nominal accounts are accounts related to income, expenses, losses, and gains. Rent and discount are examples of expenses and gains respectively, hence they are nominal accounts. The other options contain examples of real accounts (land, building, cash) which are not nominal accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>28", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "A payment of N150 to a creditor is", "images": [], "options": {"A": "an increase in assets only", "B": "a reduction of assets only", "C": "a reduction in assets and liabilities", "D": "an increase in assets and liabilities"}, "answer": "C", "explanation": "A payment to a creditor reduces the amount of money (an asset) you have and also reduces the amount you owe (a liability). Therefore, it is a reduction in both assets and liabilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>29", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not charged to Manufacturing Account?", "images": [], "options": {"A": "raw materials", "B": "factory's wages", "C": "Distribution expenses", "D": "direct expenses"}, "answer": "C", "explanation": "Manufacturing account includes all the direct costs related to the production of goods. This includes raw materials, factory's wages, and direct expenses. Distribution expenses, which are incurred to deliver the product from the production area to the customer, are not included in the manufacturing account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>30", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Discount received is shown in the", "images": [], "options": {"A": "credit side of sales ledger balances", "B": "debit side of bought ledger balances", "C": "credit side of bought ledger balances", "D": "debit side of sales ledger balances"}, "answer": "B", "explanation": "Discount received is shown in the total creditors control account. Others include: bills payable, returns outwards, credit note received etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>31", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following does not appear in a bank statement?", "images": [], "options": {"A": "dividend received on behalf of customers", "B": "bank charges", "C": "insurance premium paid on behalf of customers", "D": "uncredited charges"}, "answer": "D", "explanation": "A bank statement is a summary of financial transactions that have occurred over a given period on a bank account held by a person or business with a financial institution. Uncredited charges do not appear on a bank statement because they are not transactions that have been processed by the bank. The other options like dividend received on behalf of customers, bank charges, and insurance premium paid on behalf of customers are all transactions that would be processed by the bank and therefore would appear on a bank statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>32", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Impersonal Accounts contain", "images": [], "options": {"A": "real and cash accounts", "B": "capital and nominal accounts", "C": "real and nominal accounts", "D": "investment and real accounts"}, "answer": "C", "explanation": "Impersonal accounts are those accounts that are not personal accounts. They are further divided into two categories: Real Accounts and Nominal Accounts. Real accounts are accounts related to properties or assets of a business. Nominal accounts are accounts related to income, expenses, losses, and gains. Therefore, the correct answer is 'real and nominal accounts'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>33", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions     UCHENNA ENTERPRISES  Balance sheet as at 31st December, 1993   ###Capital 84000 Land and building 45000Add net profit 15000 99000 Furniture and fittings 34000Less drawings 9000  Stock 2800090000 debtors 22000Creditors25000Cash 1000Accurals  15000 130000130000    Capital employed is", "images": [], "options": {"A": "N130,000", "B": "N115,000", "C": "N99,000", "D": "N90,000"}, "answer": "D", "explanation": "Capital employed = Total assets = Total liabilties   = 130,000 - 40,000 ( i.e 25000 + 15000)  = #90,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>34", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions     UCHENNA ENTERPRISES  Balance sheet as at 31st December, 1993   ###Capital 84000 Land and building 45000Add net profit 15000 99000 Furniture and fittings 34000Less drawings 9000  Stock 2800090000 debtors 22000Creditors25000Cash 1000Accurals  15000 130000130000  Current assets amount to", "images": [], "options": {"A": "N51,000", "B": "N50,000", "C": "N23,000", "D": "N22,000"}, "answer": "A", "explanation": "Current assets are the assets that a company expects to convert into cash within one fiscal year. In this case, the current assets are Stock, Debtors, and Cash (28000 + 22000 + 1000 = 51000). Therefore, the correct answer is 'N51,000'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>35", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer the questions     UCHENNA ENTERPRISES  Balance sheet as at 31st December, 1993   ###Capital 84000 Land and building 45000Add net profit 15000 99000 Furniture and fittings 34000Less drawings 9000  Stock 2800090000 debtors 22000Creditors25000Cash 1000Accurals  15000 130000130000  Working capital amounts to", "images": [], "options": {"A": "N51,000", "B": "N50,000", "C": "N23,000", "D": "N11,000"}, "answer": "D", "explanation": "Working assets = current assets - current liabilities  = (stock + cash + debtors) - (creditors + accurals)  = (28000 + 22000 + 1000) - ( 25000 + 15000)   = 51000 - 40000  = #11,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>36", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Which of the following accounts does not have a debit balance?", "images": [], "options": {"A": "salaries account", "B": "share premium account", "C": "advertisement account", "D": "returns inwards account"}, "answer": "B", "explanation": "A share premium account is a reserve which a company can build up from the profits it makes from selling its shares at a premium. It is a part of the shareholders' equity and it represents the amount received by a company when it issues shares above their par value. Therefore, it has a credit balance, not a debit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>37", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Which of the following is a charge against profit?", "images": [], "options": {"A": "ordinary dividend", "B": "general reserve", "C": "preference dividend", "D": "debenture interest"}, "answer": "D", "explanation": "A charge against profit refers to an expense that is deducted from a company's profit. Debenture interest is a charge against profit because it is an expense that the company has to pay to its debenture holders. Dividends (both ordinary and preference) and general reserves are not charges against profit, they are appropriations of profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>38", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS", "question": "The cash realized from the sale of asset on dissolution of partnership is", "images": [], "options": {"A": "debited to cash account and credit to asset account", "B": "credited to cash account and debited to asset account", "C": "debited to cash account and credited realisation account and credited to realisation account", "D": "credited to cash account and debited to realisation account"}, "answer": "C", "explanation": "The cash realized from the sale of asset on dissolution of partnership is debited to cash account and credited realisation account and credited to realisation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>39", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following does not belong to the group?", "images": [], "options": {"A": "furniture and fittings", "B": "plant and machinery", "C": "building", "D": "general reserve"}, "answer": "D", "explanation": "Furniture and fittings, plant and machinery, and building are all types of fixed assets. General reserve, on the other hand, is a type of reserve fund and does not belong to the group of fixed assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>40", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The portion of the authorizes capital which has been allotted to members is", "images": [], "options": {"A": "uncalled capital", "B": "paid-up capital", "C": "issued capital", "D": "unissued capital"}, "answer": "C", "explanation": "The portion of the authorized capital which has been allotted to members is known as issued capital. Uncalled capital refers to the part of the subscribed capital which has not yet been called up. Paid-up capital is the part of the subscribed capital which has been called up and paid by the shareholders. Unissued capital is the part of the authorized capital which has not yet been issued to the shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>41", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "use the following information to answer the questions    #Stock 1/1/93 4500Sales 13500Purchases 5000Carriage inwards 500Stock 31/12/93 4200Return inwards 600    Cost of sales is", "images": [], "options": {"A": "N10,000", "B": "N9,500", "C": "N5,800", "D": "N5,300"}, "answer": "C", "explanation": "Cost of sales ( cost of goods sold ) = opening stock + purchases + carriage inward - closing stock  = 4500 + 5000 + 500 - 4200  = #5800", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>42", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "use the following information to answer the questions    #Stock 1/1/93 4500Sales 13500Purchases 5000Carriage inwards 500Stock 31/12/93 4200Return inwards 600  Net sales is", "images": [], "options": {"A": "N14,100", "B": "N14,000", "C": "N13,500", "D": "N12,900"}, "answer": "D", "explanation": "Net sales is calculated as: Sales - Return Inwards. Substituting the given values, we get: 13500 - 600 = 12900. Therefore, the correct answer is N12,900.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>43", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "use the following information to answer the questions    #Stock 1/1/93 4500Sales 13500Purchases 5000Carriage inwards 500Stock 31/12/93 4200Return inwards 600  Gross profit is", "images": [], "options": {"A": "N8,300", "B": "N8,200", "C": "N7,700", "D": "N7,100"}, "answer": "D", "explanation": "Gross profit = Net sales - Cost of sales   = 12900 - 5800  = #7100", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>44", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discount allowed is a charge made against", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "appropriation account", "D": "current account"}, "answer": "B", "explanation": "Discount allowed is a charge made against the profit and loss account. It is an expense to the business and reduces the net profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>45", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Which of the following is used before the appropriation bill is approved?", "images": [], "options": {"A": "supplementary general warrant", "B": "provisional general warrant", "C": "reserved expenditure warrant", "D": "virement warrant"}, "answer": "B", "explanation": "A provisional general warrant is used before the appropriation bill is approved. It authorizes the government to withdraw funds from the consolidated fund for the running of government during the period the appropriation bill is being considered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>46", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Which of the following is used where virement is not possible and where an application for additional provision reveals a degree of urgency?", "images": [], "options": {"A": "reserved expenditure warrant", "B": "provisional general warrant", "C": "contingencies warrant", "D": "supplementary general warrant"}, "answer": "C", "explanation": "A contingencies warrant is used where virement is not possible and where an application for additional provision reveals a degree of urgency. Virement is the process of transferring money from one budget head to another within the same budgetary level. A contingencies warrant is a type of budgetary control mechanism that allows for the allocation of additional funds in urgent situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>47", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "FINANCIAL SYSTEM : METHODS OF RAISING FUNDS", "question": "A document which acknowledges that a company owes a named person a stated sum of money with the promise that a stated interest rate will be paid periodically is called", "images": [], "options": {"A": "share certificate", "B": "preference certificate", "C": "debenture certificate", "D": "allotment certificate"}, "answer": "C", "explanation": "A debenture certificate is a document which acknowledges that a company owes a named person a stated sum of money with the promise that a stated interest rate will be paid periodically. It is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>48", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not a debit entry in the Bought Ledger?", "images": [], "options": {"A": "cash", "B": "discount received", "C": "purchases", "D": "returns outwards"}, "answer": "C", "explanation": "purchases is not posted to the purchases ledger control account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1996>49", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer the questions    #Provision for bad debts 1000CrBad debts 500DrDebtors 50000DrAdditional bad debts to be written off 500    New provision for bad debts to stand at 5% of debtors    In the balance sheet, the net figure for debtors is", "images": [], "options": {"A": "N47,025", "B": "N46,550", "C": "N45,600", "D": "N45,500"}, "answer": "D", "explanation": "5% of debtors = 5%  x 50000  = 2500    debtor's balance = 50000 - (2500 + 1000+ 500 + 500)  = 50000 - 4500  = #45500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1996>50", "subject": "Accounts", "year": "1996", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer the questions    #Provision for bad debts 1000CrBad debts 500DrDebtors 50000DrAdditional bad debts to be written off 500    New provision for bad debts to stand at 5% of debtors  The total amount of bad debts to be charges as expense in the profit and Loss Account is", "images": [], "options": {"A": "N2,500", "B": "N2,000", "C": "N1,500", "D": "N1,200"}, "answer": "C", "explanation": "5%  x 50000  = 2500 New  old = 1000  Amount in the profit and loss = 2500 - 1000  = #1500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>1", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A suspense account is used to", "images": [], "options": {"A": "agree the trial balance", "B": "record sales", "C": "record purchases", "D": "correct errors"}, "answer": "A", "explanation": "A suspense account is a temporary account that is used when there is an imbalance in the trial balance. It is used to 'agree the trial balance' by recording the difference between the debit and credit sides of the trial balance. Once the error causing the imbalance is identified and corrected, the suspense account is cleared.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>2", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "SUSPENSE ACCOUNT : ERRORS THAT WILL AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "To correct an error, the purchases account was debited while Suspense account was credited. Which of the following was the cause of the error?", "images": [], "options": {"A": "undercasting of purchase", "B": "overcasting of purchases", "C": "original entry", "D": "transportation of returns outwards"}, "answer": "A", "explanation": "If the purchases account was debited and the suspense account was credited to correct an error, it means that the purchases were initially undercast. Undercasting refers to the situation where the total of a column in the books of original entry (like purchases journal) is added up to less than the actual total. This means that the total purchases were less than they should have been, hence the need to debit the purchases account (increase its value) and credit the suspense account.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>3", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscription in advance is treated in the Balance sheet of non-profit making organizations as", "images": [], "options": {"A": "current asset", "B": "fixed asset", "C": "current liability", "D": "accumulated fund"}, "answer": "C", "explanation": "Subscription received in advance means the amount of money that has been received during the current year but which relates to the year that is yet to come. In other words, we can say it is the unearned income by the organization. It is recurring in nature and liability for the organization as it does not relate to the current year. It is treated as current liability in the balance sheet of a non-profit making organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>4", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "A sales day book is used to record", "images": [], "options": {"A": "cash sales of stock", "B": "credit sales of stock", "C": "cash and credit sales of stock", "D": "cash sales of fixed assets"}, "answer": "B", "explanation": "A sales day book, also known as a sales journal, is used to record credit sales of stock. It is not used to record cash sales of stock because these are typically recorded in the cash book. It is also not used to record both cash and credit sales of stock because these are recorded in separate books. Finally, it is not used to record cash sales of fixed assets because these are typically recorded in the general journal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>5", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Which of the following is not a capital expenditure to a local government?", "images": [], "options": {"A": "beds", "B": "theatre equipment", "C": "incubators", "D": "drugs"}, "answer": "D", "explanation": "Capital expenditure refers to the funds used by a company to acquire, maintain, and upgrade fixed assets, such as property, plant, equipment, or hardware. In the context of a local government, capital expenditure would include items like beds, theatre equipment, and incubators, which are long-term investments. Drugs, on the other hand, are considered a revenue expenditure because they are consumable and do not have a long-term benefit. Therefore, the correct answer is 'drugs'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>6", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions     Creditors Control Account  #  #Bank \"X'' Balance b/d 1200Discount 30 \"Y\" 1800 balance c/d 450      How much \"X\" ?", "images": [], "options": {"A": "N3,480", "B": "N2,520", "C": "N1,800", "D": "N1,320"}, "answer": "B", "explanation": "The question is asking for the value of 'X' in the Creditors Control Account. From the given information, we can see that 'X' is the bank balance. To find 'X', we need to balance the account. The balance brought down (b/d) is 1200, the discount is 30, and the balance carried down (c/d) is 450. The formula to balance the account is: Balance b/d + 'Y' = 'X' + Balance c/d. If we substitute the given values into the formula, we get: 1200 + 1800 = 'X' + 450. Solving for 'X', we get 'X' = 1200 + 1800 - 450 = 2550. Therefore, the correct answer is 'N2,520'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>7", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions     Creditors Control Account  #  #Bank \"X'' Balance b/d 1200Discount 30 \"Y\" 1800 balance c/d 450    \"Y\" represents", "images": [], "options": {"A": "sales", "B": "purchases", "C": "returns outwards", "D": "return inwards"}, "answer": "B", "explanation": "In the context of a Creditors Control Account, 'Y' represents purchases. This is because a Creditors Control Account is a summary account that reflects the total amount owed to all a company's individual creditors. When a company purchases goods or services on credit, the amount of the purchase is added to the Creditors Control Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>8", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "use the following information to answer the questions     Creditors Control Account  #  #Bank \"X'' Balance b/d 1200Discount 30 \"Y\" 1800 balance c/d 450    The balance of 450 in the above accounts represents", "images": [], "options": {"A": "trading account item", "B": "profit and loss account item", "C": "current asset", "D": "current liability"}, "answer": "D", "explanation": "The balance of 450 in the Creditors Control Account represents a current liability. This is because a Creditors Control Account shows the amount of credit purchases that are yet to be paid by the company. These unpaid amounts are considered as current liabilities as they are obligations that the company needs to pay off within the next accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>9", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "A Receipt and Payments Account reveals", "images": [], "options": {"A": "net profit", "B": "surplus", "C": "cash in hand", "D": "gross profit"}, "answer": "C", "explanation": "A Receipt and Payments Account is a summary of cash and bank transactions, in and out, for a specific period. It does not reveal net profit, surplus, or gross profit. It only shows the cash in hand at the end of the period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>10", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "An example of appropriation of profit in a company is", "images": [], "options": {"A": "salaries", "B": "rent income", "C": "debenture interest", "D": "dividend"}, "answer": "D", "explanation": "Appropriation of profit in a company refers to the distribution of profit among different areas such as retained earnings, dividends, etc. Dividend is an example of appropriation of profit as it is a portion of the company's earnings distributed to its shareholders. Salaries and debenture interest are expenses, not appropriation of profits. Rent income is a source of profit, not an appropriation of it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>11", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "In a partnership goodwill is recognized when", "images": [], "options": {"A": "a new partner is admitted", "B": "a partner is dormant", "C": "the business is making huge profit", "D": "the business has good customer relations"}, "answer": "A", "explanation": "Goodwill in a partnership is recognized when a new partner is admitted. Goodwill is an intangible asset that represents the non-physical assets, such as the value of a brand name, large and loyal customer base, good customer relations, good employee relations, and any patents or proprietary technology. When a new partner is admitted into the partnership, the existing partners often require the new partner to pay for their share of the goodwill that the existing partners have built up.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>12", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is a nominal account?", "images": [], "options": {"A": "Machinery", "B": "Debtors", "C": "Creditors", "D": "Salaries"}, "answer": "D", "explanation": "A nominal account is an account that is closed at the end of each accounting period. Nominal accounts include all income statement accounts (revenues, expenses, gains, losses) and the drawing account. Among the given options, 'Salaries' is a nominal account as it is an expense account which is closed at the end of each accounting period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>13", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions    An asset was bought on 1st January, 1992 for N20,000. Depreciation was provided for annually at 20% on cost. It was sold for N7,000 on 1st July, 1995.    The net book value at the time of sale was", "images": [], "options": {"A": "N16,000", "B": "N14,000", "C": "N12,000", "D": "N8,000"}, "answer": "D", "explanation": "Cost 20000Year 1 20000  x 20%  4000  16000Year 2  20000 x 20%  4000 12000Year  3 20000  x 20%  4000 NBV 8000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>14", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions    An asset was bought on 1st January, 1992 for N20,000. Depreciation was provided for annually at 20% on cost. It was sold for N7,000 on 1st July, 1995.  Accumulated depreciation at the time of sale was", "images": [], "options": {"A": "N16,000", "B": "N14,000", "C": "N12,000", "D": "N8,000"}, "answer": "B", "explanation": "Accumulated depreciation = 20000  x 20%  = 4000 for each year.    From 1992 to 1995, that is 3 years, therefore:   3  x 4000  = #12000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>15", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions    An asset was bought on 1st January, 1992 for N20,000. Depreciation was provided for annually at 20% on cost. It was sold for N7,000 on 1st July, 1995.  The profit on sale was", "images": [], "options": {"A": "N8,000", "B": "N7,000", "C": "N6,000", "D": "N1,000"}, "answer": "D", "explanation": "#Cost 20000Dep 1 ( 20%  x 20000)  4000 16000Dep 2 ( 20%  x 20000)  4000 12000Dep 3 ( 20%  x 20000)  4000 NBV 8000    Profit = 8000 - 7000   = 1000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>16", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "In Manufacturing Account, prime cost plus factory overhead is known as", "images": [], "options": {"A": "conversion cost", "B": "cost of raw materials consumed", "C": "total cost", "D": "production cost"}, "answer": "D", "explanation": "In a Manufacturing Account, the prime cost (direct materials, direct labor, and direct expenses) plus factory overhead (indirect materials, indirect labor, and indirect expenses) is known as the production cost. This is the total cost incurred in the production process before administrative, selling and distribution costs are considered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>17", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PETTY CASH BOOK : ADVANTAGES OF PETTY CASH BOOK", "question": "Which of the following is an advantage of the imprest system?", "images": [], "options": {"A": "making high profits in the business", "B": "Rewarding the imprest holder", "C": "Easy preparation of the final accounts", "D": "Meeting small items of expenditure"}, "answer": "D", "explanation": "The imprest system is a financial accounting system that is primarily used to maintain and control petty cash. The main advantage of the imprest system is that it allows for the efficient management of small items of expenditure. It does not directly contribute to making high profits, rewarding the imprest holder, or easy preparation of the final accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>18", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "Where a business is purchased, the full amount of the purchase consideration is credited to", "images": [], "options": {"A": "Purchase of Business Account", "B": "Creditor's Account", "C": "Vendor's Account", "D": "Purchaser's Account"}, "answer": "A", "explanation": "When a business take over value of asset, the accounting entries is:  Dr Assets account  Cr Business purchase account", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>19", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "A financial plan of action expressed in monetary terms is known as", "images": [], "options": {"A": "imprest", "B": "consolidated fund", "C": "warrant", "D": "budget"}, "answer": "D", "explanation": "A financial plan of action expressed in monetary terms is known as a budget. A budget is a financial plan for a defined period, often one year, that is known in advance. Budgets may also be set in money terms, but can also be expressed in terms of units of product, hours of labor, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>20", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Which of the following is not a source document for recording sales?", "images": [], "options": {"A": "Debit note", "B": "Credit note", "C": "Receipt", "D": "Sales journal"}, "answer": "D", "explanation": "The source documents are: receipts, invoice, credit note,debit note, statement of account, petty cash voucher, cheque etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>21", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the questions     A company charges out goods to a branch at cost plus 25 percent. It invoiced N12,000 worth of goods    The mark-up is", "images": [], "options": {"A": "N15,000", "B": "N9,000", "C": "N4,000", "D": "N3,000"}, "answer": "D", "explanation": "Mark up is calculated as:    = 25%  x 12000    = #3000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>22", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the questions     A company charges out goods to a branch at cost plus 25 percent. It invoiced N12,000 worth of goods  The double entry required for the mark-up is debit Branch", "images": [], "options": {"A": "Sales Account, credit Branch Adjustment Account", "B": "Adjustment Account, credit Branch Stock Account", "C": "Stock Account, credit Branch Adjustment Account", "D": "Adjustment Account, credit Branch Profit and Loss Account"}, "answer": "C", "explanation": "In accounting, the double entry system means that every financial transaction has equal and opposite effects in at least two different accounts. In this case, the mark-up is the extra amount charged over the cost price, which is a gain or profit for the company. Therefore, the double entry required for the mark-up is to debit (increase) the Branch Stock Account (which represents the cost of goods sold to the branch) and credit (increase) the Branch Adjustment Account (which represents the profit or gain from the mark-up).", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>23", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "A ledger is a", "images": [], "options": {"A": "book of accounts", "B": "summary of entries", "C": "book of original entry", "D": "double entry posting"}, "answer": "D", "explanation": "A ledger, also known as the second book of entry, is a record-keeping system that records all of a company's classified financial data. Transactions are recorded in the ledger in different accounts as debits and credits. The ledger is often referred to as a general ledger, and it's intended to provide a record of every financial transaction that takes place during an operating company's life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>24", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A real account is the account of", "images": [], "options": {"A": "expenses or losses", "B": "gains or income", "C": "physical tangible items", "D": "fictitious items"}, "answer": "C", "explanation": "A real account is the account of physical tangible items. In accounting, real accounts, also known as permanent accounts, are balance sheet accounts that track the balances of assets, liabilities, and equity. These accounts do not close at the end of an accounting period, hence the term 'permanent'. They include accounts like cash, accounts receivable, buildings, equipment, accounts payable, and retained earnings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>25", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "An item is fictitious because it", "images": [], "options": {"A": "does not exist", "B": "is too costly", "C": "is worthless", "D": "cannot be sold for cash"}, "answer": "A", "explanation": "In accounting, a fictitious item is one that does not exist. It may be recorded in the books of accounts due to fraud or error, but in reality, it does not have any existence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>26", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not a personal account?", "images": [], "options": {"A": "Bolaji Account", "B": "Drawings Account", "C": "P.Z. Plc Account", "D": "Cash Account"}, "answer": "D", "explanation": "In accounting, accounts are classified into three types: Personal, Real, and Nominal. Personal accounts relate to individuals, companies, and their accounts. Real accounts relate to the properties or assets of a business. Nominal accounts relate to the income, expenses, gains, and losses. Cash Account is a Real account, not a Personal account. It represents a business's asset and not any individual or company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>27", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "A provision is", "images": [], "options": {"A": "an expense of business to be paid for in cash", "B": "an amount of loss from trading activities", "C": "a loss in value of all business assets", "D": "an expense the amount of which is not certain"}, "answer": "D", "explanation": "A provision is an amount set aside to cover a probable future expense, or reduction in the value of an asset. The amount of the provision is not certain because it is an estimate of what the future expense might be. Therefore, option 4 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>28", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "A cash discount is a", "images": [], "options": {"A": "Trading Account item", "B": "Profit and Loss Account item", "C": "Appropriation Account item", "D": "Receipts and Payments Account item"}, "answer": "B", "explanation": "A cash discount is a reduction in the amount that a debtor owes to the creditor in the event of prompt payment. It is recorded in the Profit and Loss Account as it affects the net profit or loss of the business. Therefore, option 2 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>29", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to the answer     Kudi local government council incurred the following expenditure in 1995:    Npayment of salaries 140 000purchase of drugs for dispensaries 80 000purchase of books for library 30 000sinking of wells 70 000extension of council offices 160 000    The amount of capital expenditure for 1995 was", "images": [], "options": {"A": "N260,000", "B": "N230,000", "C": "N220,000", "D": "N160,000"}, "answer": "B", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets. In this case, the capital expenditures are the costs for 'sinking of wells' and 'extension of council offices', which total N230,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>30", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to the answer     Kudi local government council incurred the following expenditure in 1995:    Npayment of salaries 140 000purchase of drugs for dispensaries 80 000purchase of books for library 30 000sinking of wells 70 000extension of council offices 160 000  The amount of revenue expenditure for 1995 was", "images": [], "options": {"A": "N26,000", "B": "N230,000", "C": "N250,000", "D": "N160,000"}, "answer": "C", "explanation": "Revenue expenditure = 140000 + 80000 + 30000  = #250,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>31", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "An expense becomes an accrual because it", "images": [], "options": {"A": "is due for payment", "B": "is a Profit and Loss Account item", "C": "is a Trading Account item", "D": "is to be paid within the next one year"}, "answer": "A", "explanation": "An expense becomes an accrual because it is due for payment. Accruals are amounts that are owed but have not yet been paid. They are recognized in the period they are incurred, not when they are paid. This is in line with the accrual basis of accounting, which records financial events regardless of when the cash transactions occur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>32", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "The amount for which a business is sold is known as", "images": [], "options": {"A": "goodwill", "B": "capital reserve", "C": "purchase consideration", "D": "premium"}, "answer": "C", "explanation": "The amount for which a business is sold is known as purchase consideration. Purchase consideration is the total value that a buyer gives up in order to acquire a business. It can be in the form of cash, shares, or other assets. Goodwill is the value of a company's brand name, solid customer base, good customer relations, good employee relations, and any patents or proprietary technology. Capital reserve is a type of account on a company's balance sheet that is reserved for long-term capital investment projects or any other large and anticipated expenses. Premium is the amount paid periodically to the insurer by the insured for covering his risk.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>33", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "The person who is responsible for the formation of a company is called the", "images": [], "options": {"A": "promoter", "B": "dividend", "C": "shareholder", "D": "director"}, "answer": "A", "explanation": "The promoter is the person who undertakes the formation of a company. They are responsible for all the necessary steps to set up the company including its registration, raising capital, and starting its operations. The other options do not fit the definition. A shareholder is an owner of shares in the company, a director is a member of the board of directors who governs the company, and a dividend is a distribution of a portion of a company's earnings to its shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>34", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "The amount of a company's profit given to a shareholder is known as", "images": [], "options": {"A": "premium", "B": "dividend", "C": "interest", "D": "allotment"}, "answer": "B", "explanation": "A dividend is a distribution of a portion of a company's earnings, decided by the board of directors, to a class of its shareholders. Dividends can be issued as cash payments, as shares of stock, or other property. The other options do not fit the definition. A premium is an amount paid periodically to the insurer by the insured for covering his risk, interest is the charge for the privilege of borrowing money, typically expressed as an annual percentage rate, and allotment is the process of dividing something into portions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>35", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Which of the following best described the path of a transaction?", "images": [], "options": {"A": "Source documents to Journal to Ledger", "B": "Source documents to Ledger to Journal", "C": "Journal to Ledger to source documents", "D": "Journal to source documents to Ledger"}, "answer": "A", "explanation": "The path of a transaction in accounting typically follows this order: Source documents -> Journal -> Ledger. Source documents are the original records that contain the details to substantiate a transaction entered into by a business. The Journal is a book where all transactions are recorded in chronological order. The Ledger is a book that contains accounts in which the classified and summarized information from the journals is posted as debits and credits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>36", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer the questions     Opening stock - Footwears department N800                         - stationery department N600Purchases - footwears department N1600                   - stationery department N2800Wages of shoe packers -  N600 - salaries N1200Sales:  - footwears N4000- stationery N6000  Additional information   i No closing stock  ii. common expenses are to be shared in the ratio of sales.    The net profit of the footwears department is", "images": [], "options": {"A": "N1880", "B": "N1600", "C": "N880", "D": "N520"}, "answer": "C", "explanation": "To calculate the net profit of the footwears department, we need to subtract the cost of goods sold and the expenses from the sales. The cost of goods sold is the opening stock plus purchases, which is N800 + N1600 = N2400. The expenses are the wages of shoe packers and the share of common expenses (salaries), which is N600 + (N1200 * (N4000 / (N4000 + N6000))) = N600 + N480 = N1080. Therefore, the net profit is Sales - Cost of goods sold - Expenses = N4000 - N2400 - N1080 = N520.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>37", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer the questions     Opening stock - Footwears department N800                         - stationery department N600Purchases - footwears department N1600                   - stationery department N2800Wages of shoe packers -  N600 - salaries N1200Sales:  - footwears N4000- stationery N6000  Additional information   i No closing stock  ii. common expenses are to be shared in the ratio of sales.  The profit of the Stationery Department is", "images": [], "options": {"A": "N1,880", "B": "N1,600", "C": "N880", "D": "N1520"}, "answer": "D", "explanation": "Common expenses ratio:  Footwear = 4000/10000  = 0.4    Stationery = 6000/10000  = 0.6    Cost of goods sold:  Footwear = 800 + 1600  = 2400    Stationery = 600 + 2800  = 3400    Gross profit:  Footwear = 4000 - 2400  = 1600    Stationery = 6000 - 3400  = 2600    Common expenses allocation:  Footwear = 1800 x 0.4  = 720    Stationery = 1800 x 0.6  = 1080    Net profit:  Footwear = 1600 - 720  = 880    Stationery = 2600 - 1080  = 1520", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>38", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer the questions     Opening stock - Footwears department N800                         - stationery department N600Purchases - footwears department N1600                   - stationery department N2800Wages of shoe packers -  N600 - salaries N1200Sales:  - footwears N4000- stationery N6000  Additional information   i No closing stock  ii. common expenses are to be shared in the ratio of sales.  The cost goods for the stationery is", "images": [], "options": {"A": "N4,120", "B": "N3,400", "C": "N3,000", "D": "N2,800"}, "answer": "B", "explanation": "The cost of goods for the Stationery Department is calculated as the sum of the opening stock and purchases, which is N600 + N2800 = N3400. This matches option 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>39", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer the questions     Opening stock - Footwears department N800                         - stationery department N600Purchases - footwears department N1600                   - stationery department N2800Wages of shoe packers -  N600 - salaries N1200Sales:  - footwears N4000- stationery N6000  Additional information   i No closing stock  ii. common expenses are to be shared in the ratio of sales.  the cost of goods for the footwears department is", "images": [], "options": {"A": "N4120", "B": "N3400", "C": "N3000", "D": "N2400"}, "answer": "D", "explanation": "Cost of goods sold is calculated as:    = 800 + 1600    = #2400", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1997>40", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "Where there are no proper books of account , the capital at the commencement of a period is ascertained by preparing", "images": [], "options": {"A": "total debtors and creditors accounts", "B": "Bank Reconciliation Statement", "C": "Statement of Affairs", "D": "trading, profit and loss accounts"}, "answer": "C", "explanation": "When there are no proper books of account, the capital at the commencement of a period can be ascertained by preparing a Statement of Affairs. A Statement of Affairs is a financial statement that shows the assets, liabilities, and capital of a business at a particular point in time. It is used when there are no proper books of account because it can be prepared using incomplete records and it provides an estimate of the capital at the commencement of a period. Hence, the correct option is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>41", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Rent receivable is a", "images": [], "options": {"A": "current asset", "B": "current liability", "C": "contingent liability", "D": "fictitious asset"}, "answer": "A", "explanation": "Rent receivable is a current asset. In accounting, a current asset is any asset reasonably expected to be sold, consumed, or exhausted through the normal operations of a business within the current fiscal year or operating cycle (whichever period is longer). Rent receivable is an amount that has been earned by a company for providing goods or services to its customers, but which has not yet been received by the company. Therefore, it is considered a current asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>42", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is a factory overhead?", "images": [], "options": {"A": "carriage on raw materials", "B": "purchase of raw materials", "C": "production wages", "D": "depreciation of factory equipment"}, "answer": "D", "explanation": "Factory overhead, also known as manufacturing overhead, refers to the indirect factory-related costs that are incurred when a product is manufactured. This includes costs that are not directly tied to a specific product, such as the cost of utilities, property taxes, and depreciation of factory equipment. Therefore, the depreciation of factory equipment is considered a factory overhead.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>43", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Use the following information to answer the questions  A business whose assets consisted of stock N15,000 and debtors N8,000 was bought by issuing 20,000 ordinary shares of N1 each at a premium of 20 percent.    The purchase consideration was", "images": [], "options": {"A": "N24,000", "B": "N23,000", "C": "N20,000", "D": "N15,000"}, "answer": "A", "explanation": "The purchase consideration is calculated as the number of shares issued multiplied by the price per share. In this case, 20,000 shares were issued at a price of N1.20 per share (N1 + 20% of N1), giving a total purchase consideration of N24,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>44", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION", "question": "Use the following information to answer the questions  A business whose assets consisted of stock N15,000 and debtors N8,000 was bought by issuing 20,000 ordinary shares of N1 each at a premium of 20 percent.  The amount of goodwill was", "images": [], "options": {"A": "N4,000", "B": "N3,000", "C": "N2,000", "D": "N1,000"}, "answer": "D", "explanation": "Goodwill is calculated as the purchase consideration minus the fair market value of the net assets. In this case, the fair market value of the net assets is N23,000 (N15,000 + N8,000) and the purchase consideration is N24,000, giving a goodwill of N1,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>45", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "When a share is sold for less than its nominal value, the difference is called", "images": [], "options": {"A": "discount", "B": "reserve", "C": "premium", "D": "loss"}, "answer": "A", "explanation": "When a share is sold for less than its nominal value, the difference is called a discount. This is because the company is essentially 'discounting' the price of the share from its nominal or face value. The nominal value is the value of a share as stated in the company's articles of association, it's the minimum amount that must be paid for a share when it's issued.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1997>46", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "Which of the following serves the same purpose as a Trading Account?", "images": [], "options": {"A": "Branch Adjustment Account", "B": "Goods sent to Branch Account", "C": "Branch Stock Account", "D": "Branch Debtors Account"}, "answer": "C", "explanation": "A Branch Stock Account serves the same purpose as a Trading Account. Both accounts are used to record the opening stock, purchases, sales and closing stock of goods. A Trading Account is used in the head office while a Branch Stock Account is used in the branch. The purpose of these accounts is to determine the gross profit or loss of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>47", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the questions    The receipts and payments account of Acada club for the year ended 31st december, 1995 is as follows    N NBalance b/f 800 printing and stationery 320subscriptions 3600 postages and telephone 160donations 650 rent 1200dance tickets 1200 library books 2500  anniversary dance expenses 945  balance c/d  1125 6250 6250    The amount of income credited to income and expenditure account for the year was", "images": [], "options": {"A": "N6250", "B": "N5450", "C": "N3600", "D": "N1850"}, "answer": "B", "explanation": "The income credited to the income and expenditure account is the sum of subscriptions, donations, and dance tickets. These are the incomes for the club. Adding these up gives 3600 + 650 + 1200 = 5450.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>48", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the questions    The receipts and payments account of Acada club for the year ended 31st december, 1995 is as follows    N NBalance b/f 800 printing and stationery 320subscriptions 3600 postages and telephone 160donations 650 rent 1200dance tickets 1200 library books 2500  anniversary dance expenses 945  balance c/d  1125 6250 6250  The total expenses debited to income and expenditure account for the year was", "images": [], "options": {"A": "N6250", "B": "N5125", "C": "N2625", "D": "N2500"}, "answer": "C", "explanation": "Total exenses = 320 + 160 + 1200 + 2500 + 945   = #5125", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>49", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the questions    The receipts and payments account of Acada club for the year ended 31st december, 1995 is as follows    N NBalance b/f 800 printing and stationery 320subscriptions 3600 postages and telephone 160donations 650 rent 1200dance tickets 1200 library books 2500  anniversary dance expenses 945  balance c/d  1125 6250 6250  The capital expenditure of the club for the year was", "images": [], "options": {"A": "N6250", "B": "N5450", "C": "N5125", "D": "N2500"}, "answer": "D", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets. In the given account, the only capital expenditure is the purchase of library books which costs N2500. Therefore, the capital expenditure of the club for the year was N2500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1997>50", "subject": "Accounts", "year": "1997", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "Which of the following is not a revenue receipt?", "images": [], "options": {"A": "Receipt from sales of goods", "B": "Rent from premises sublet", "C": "Interest on savings account", "D": "cash on sale of fixed asset"}, "answer": "D", "explanation": "Revenue receipts are the income received by a business in the regular course of business activities. These receipts are recurring in nature and they are used in meeting the day-to-day expenditure of the business. Cash on sale of fixed asset is not a revenue receipt because it is a one-time transaction and not a regular income. It is considered a capital receipt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>1", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following is the least liquid?", "images": [], "options": {"A": "stock", "B": "debtors", "C": "bills receivable", "D": "machinery"}, "answer": "D", "explanation": "Liquidity refers to how quickly an asset can be converted into cash. Among the options, machinery is the least liquid because it cannot be easily sold or converted into cash without a significant loss of investment. Stocks, debtors, and bills receivable are more liquid in comparison.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>2", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Opening stock + Purchases + carriage inwards is equal to", "images": [], "options": {"A": "total sales", "B": "cost of goods sold", "C": "cost of goods available for sale", "D": "gross profit"}, "answer": "C", "explanation": "The formula for calculating the cost of goods available for sale is: Opening stock + Purchases + Carriage Inwards. This gives the total cost of all goods that were available for sale during the period. It does not represent total sales, cost of goods sold, or gross profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>3", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is a source of the local government Revenue?", "images": [], "options": {"A": "personal income tax", "B": "sales of armed forces property", "C": "repayment (state)", "D": "market rates"}, "answer": "D", "explanation": "The local government revenue is mainly generated from local taxes, fees, and charges. Market rates are one of the sources of local government revenue. They are fees charged by local governments for the use of public markets. Personal income tax is a source of revenue for the federal government, not the local government. Sales of armed forces property and repayment (state) are not typical sources of local government revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>4", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The accountant general disburses government fund by the use of", "images": [], "options": {"A": "a voucher", "B": "a warrant", "C": "an estimate", "D": "a vote"}, "answer": "B", "explanation": "The Accountant General disburses government funds by the use of a warrant. A warrant is a legal document that authorizes the payment of government funds. It is issued by the Accountant General or another authorized officer. A voucher is a document that serves as proof of a transaction, not a means of disbursement. An estimate is a rough calculation or judgment of the value, number, quantity, or extent of something, not a means of disbursement. A vote refers to a formal expression of opinion or choice, either positive or negative, made by an individual or body of individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>5", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Carriage inwards are included on goods", "images": [], "options": {"A": "on display", "B": "sold", "C": "in process", "D": "purchases"}, "answer": "D", "explanation": "Carriage inwards refers to the cost of transportation of goods or materials from suppliers to the business. This cost is directly related to the purchase of goods, hence it is included in the cost of purchases. Therefore, the correct answer is 'purchases'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>6", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions       NDebtors 30 000Creditors 20 000Opening Stock 15 000Closing stock 18 000Wages 3 000Salaries 10 000Purchases 30 000Sales 60 000    The gross profit percentage is", "images": [], "options": {"A": "67%", "B": "55%", "C": "50%", "D": "45%"}, "answer": "B", "explanation": "First, determine the cost of goods sold;  Cost of goods sold = opening stock + purchases - closing stock   COGS = 15000 + 30000 - 18000  = 27000    Gross profit = Sales - cost of goods sold   = 60000 - 27000  = 33000    Gross profit percentage = Gross profit/Sales  x 100     = 33000/60000  x 100    = 55%", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>7", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions       NDebtors 30 000Creditors 20 000Opening Stock 15 000Closing stock 18 000Wages 3 000Salaries 10 000Purchases 30 000Sales 60 000  The net profit percentage is", "images": [], "options": {"A": "100%", "B": "67%", "C": "50%", "D": "33%"}, "answer": "D", "explanation": "First, determine the net profit  Net profit = Gross profit - Expenses  = (33000) - ( 3000 +10000)  = 33000 - 13000  = 20000    Net profit percentage = Net profit/Sales  x 100    = 20000/60000  x 100    = 33.3%  ≃ 33%", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>8", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions       NDebtors 30 000Creditors 20 000Opening Stock 15 000Closing stock 18 000Wages 3 000Salaries 10 000Purchases 30 000Sales 60 000  The working capital is", "images": [], "options": {"A": "48,000", "B": "N33,000", "C": "N28,000", "D": "N25,000"}, "answer": "C", "explanation": "The working capital is calculated as Current Assets - Creditors. The current assets are Debtors + Closing Stock = 30,000 + 18,000 = 48,000. The working capital is 48,000 - 20,000 = 28,000. The correct answer is N28,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>9", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions       NDebtors 30 000Creditors 20 000Opening Stock 15 000Closing stock 18 000Wages 3 000Salaries 10 000Purchases 30 000Sales 60 000  The stock turnover is", "images": [], "options": {"A": "4.0 times", "B": "3.6 times", "C": "3.3 times", "D": "1.6 times"}, "answer": "D", "explanation": "Stock turnover=Cost of goods soldAverage stock    Note that cost of goods sold = #27,000    Average stock=Opening stock +Closing stock2  Average stock = 15000 +18000/2    = 16500    Therefore, stock turnover = 27000/16500    = 1.6 tmes", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>10", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following is an asset?", "images": [], "options": {"A": "bad debt provision", "B": "rent in arrears", "C": "sales", "D": "insurance prepaid"}, "answer": "D", "explanation": "An asset is a resource with economic value that an individual, corporation, or country owns or controls with the expectation that it will provide a future benefit. In this case, 'insurance prepaid' is an asset because it is a payment made in advance for insurance services that will be received in the future.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>11", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A balance sheet is prepared", "images": [], "options": {"A": "for the year ended...........19 x 1", "B": "for............19 x 1", "C": "as at.............19 x 1", "D": "in the year..............19 x 1"}, "answer": "C", "explanation": "A balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time. Therefore, it is prepared 'as at' a specific date, not 'for' a specific year. The correct phrase is 'as at.............19 x 1'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>12", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Partners salary is shown in the", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "income and expenditure", "D": "profit and loss appropriation account"}, "answer": "D", "explanation": "Partners' salary is an appropriation of profit, not an expense. Therefore, it is shown in the profit and loss appropriation account, not in the trading account, profit and loss account, or income and expenditure account. The profit and loss appropriation account is a financial statement that shows how the profit of a partnership is divided among the partners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>13", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not a Nominal Account?", "images": [], "options": {"A": "electricity account", "B": "furnitures and fittings account", "C": "postages and telephone account", "D": "insurance account"}, "answer": "B", "explanation": "A nominal account is an account that is closed at the end of each accounting period. Temporary or nominal accounts include revenue, expense, and gain and loss accounts. However, the 'furnitures and fittings account' is not a nominal account but a real account. Real accounts are asset accounts, and they do not get closed at the end of the accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>14", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "Which of the following is an intangible asset?", "images": [], "options": {"A": "Goodwill", "B": "Furniture & fittings", "C": "cash in hand", "D": "proprietor's capital"}, "answer": "A", "explanation": "An intangible asset is a type of asset that is not physical in nature. Goodwill, brand recognition and intellectual property, such as patents, trademarks, and copyrights, are all intangible assets. Hence, 'Goodwill' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>15", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is found in the personal ledger?", "images": [], "options": {"A": "assets account", "B": "discount allowed account", "C": "sales account", "D": "debtors account"}, "answer": "D", "explanation": "The personal ledger contains accounts of debtors and creditors. Therefore, the 'debtors account' is found in the personal ledger. The other options, 'assets account', 'discount allowed account', and 'sales account' are not typically found in the personal ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>16", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Which of the following has a debit balance?     i. calls-in-arrears   ii. cash-in-advance   iii. share discount", "images": [], "options": {"A": "i only", "B": "ii only", "C": "iii only", "D": "i and iii only"}, "answer": "D", "explanation": "In accounting, a debit balance is the ending balance that remains after all debits and credits have been accounted for. It's the amount that a company or individual owes. 'Calls-in-arrears' and 'share discount' have a debit balance. 'Calls-in-arrears' is a liability account that records the amount due from shareholders who have not paid the amount due on their shares. 'Share discount' is a contra equity account, which means it reduces the balance of the related equity account, in this case, the share capital. 'Cash-in-advance' has a credit balance because it's a liability account that records the amount received from customers before the goods are delivered or services are rendered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>17", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the information to answer the questions     #Furniture and fittings 15000land and buildings 40000Motor vehicles 25000Stock 10000Debtors 27500Cash in hand 2000Bank overdraft 17500Profit and loss b/d 28000Rent owing 800Sundry creditors 22000    The value of current assets is", "images": [], "options": {"A": "N68,300", "B": "N57,000", "C": "N40,300", "D": "N39,500"}, "answer": "D", "explanation": "The value of current assets is calculated by adding up the values of Stock, Debtors, and Cash in hand. From the given data, the value of current assets is N10,000 + N27,500 + N2,000 = N39,500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>18", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the information to answer the questions     #Furniture and fittings 15000land and buildings 40000Motor vehicles 25000Stock 10000Debtors 27500Cash in hand 2000Bank overdraft 17500Profit and loss b/d 28000Rent owing 800Sundry creditors 22000  The value of current liabilities is", "images": [], "options": {"A": "N56,5000", "B": "N40,300", "C": "N39,500", "D": "N28,000"}, "answer": "B", "explanation": "The value of current liabilities is calculated by adding up the values of Bank overdraft, Rent owing, and Sundry creditors. From the given data, the value of current liabilities is N17,500 + N800 + N22,000 = N40,300.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>19", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the information to answer the questions     #Furniture and fittings 15000land and buildings 40000Motor vehicles 25000Stock 10000Debtors 27500Cash in hand 2000Bank overdraft 17500Profit and loss b/d 28000Rent owing 800Sundry creditors 22000  The opening capital is", "images": [], "options": {"A": "N52,200", "B": "N51,200", "C": "N48,300", "D": "N39,500"}, "answer": "B", "explanation": "Opening capital = Total assets( fixed +current) - Total liabilties - profit   ( 15000 + 40000 + 25000 + 10000 + 27500 + 2000) - 17500 + 800 + 22000  = 119,500 - 40,300 - 28000  = #51,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>20", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the information to answer the questions     #Furniture and fittings 15000land and buildings 40000Motor vehicles 25000Stock 10000Debtors 27500Cash in hand 2000Bank overdraft 17500Profit and loss b/d 28000Rent owing 800Sundry creditors 22000  The value of total fixed assets is", "images": [], "options": {"A": "N119,500", "B": "N90,000", "C": "N80,000", "D": "N79,200"}, "answer": "C", "explanation": "Total fixed assets = furniture + land + motor  = 15000 + 40000 + 25000  = #80,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>21", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Accounts payable is", "images": [], "options": {"A": "an accrual", "B": "a provision", "C": "a current liability", "D": "a long-term liability"}, "answer": "C", "explanation": "Accounts payable is a current liability. It represents the amount a company owes to its suppliers or vendors for goods or services received that have not yet been paid for.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>22", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following is/are true?    i. depreciation charges increase profits   ii. reduction in provision for bad debt increases profit   iii. undervalued stock increases profits", "images": [], "options": {"A": "ii and iii only", "B": "i and iii only", "C": "iii only", "D": "ii only"}, "answer": "A", "explanation": "Depreciation charges do not increase profits, they decrease them because they represent the wear and tear of a company's assets over time. Reduction in provision for bad debt increases profit because it means the company expects fewer customers to default on their payments. Undervalued stock does not necessarily increase profits. It may indicate that the company's assets are undervalued, but it does not directly affect the company's profitability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>23", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Uche returned goods worth N1,500 to Udo. Uche should receive", "images": [], "options": {"A": "an invoice", "B": "a statement of account", "C": "a debit note", "D": "a credit note"}, "answer": "D", "explanation": "When goods are returned, the buyer (Uche in this case) should receive a credit note from the seller (Udo). A credit note is a document issued by a seller to a buyer. The seller issues a credit note for the same or lower amount than the invoice, and then repays the money to the buyer or sets it off against a balance due from other transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>24", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "To realize an asset means to", "images": [], "options": {"A": "close its account in the ledger", "B": "give it out as a collateral", "C": "turn it to cash", "D": "open its account in the ledger"}, "answer": "C", "explanation": "To realize an asset means to convert it into cash or cash equivalents. This is usually done through a sale. The cash can then be used for various purposes such as paying off debts, reinvesting in the business, or distributing dividends to shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>25", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "When a fixed asset is fully depreciated, its net book value is", "images": [], "options": {"A": "equal to its original cost", "B": "twice its original cost", "C": "equal to its current market value", "D": "equal to zero"}, "answer": "D", "explanation": "When a fixed asset is fully depreciated, its net book value is equal to zero. The net book value of an asset is calculated by subtracting the accumulated depreciation from the original cost of the asset. When an asset is fully depreciated, the accumulated depreciation is equal to the original cost, hence the net book value is zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>26", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Goods worth N800 was stolen. The double entries are, debit", "images": [], "options": {"A": "purchases account, credit trading account", "B": "trading account, credit purchases account", "C": "profit and loss account, credit purchases account", "D": "profit and loss account, credit trading account"}, "answer": "C", "explanation": "When goods are stolen, the loss is recorded by debiting the profit and loss account and crediting the purchases account. The profit and loss account is debited because the loss reduces the company's profit. The purchases account is credited because the stolen goods reduce the amount of goods the company has purchased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>27", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Payment for shares in excess of amount demanded gives rise to", "images": [], "options": {"A": "dividend warrant", "B": "revenue reserve", "C": "capital reserve", "D": "call-in-advance"}, "answer": "D", "explanation": "Call in advance is the amount paid up in excess of the instalment ( call) requested. This is transfered to a separate call in advance account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>28", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Provision for discount on debtors is to be", "images": [], "options": {"A": "debited to profit and loss account", "B": "credit to profit and loss discount", "C": "debited to debtors account", "D": "credited to debtors account"}, "answer": "A", "explanation": "Provision for discount on debtors is to be debited to profit and loss account. This is because the provision for discount on debtors is an expense for the business and all expenses are debited in the profit and loss account. The provision for discount on debtors is made to account for the discounts that the business expects to give to its debtors to encourage early payment of debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>29", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION", "question": "Which of the following cannot be realized?", "images": [], "options": {"A": "debtors", "B": "creditors", "C": "fixtures", "D": "goodwill"}, "answer": "D", "explanation": "Goodwill cannot be realized. Goodwill is an intangible asset that is associated with the purchase of one company by another. Specifically, goodwill is the portion of the purchase price that is higher than the sum of the net fair value of all of the assets purchased in the acquisition and the liabilities assumed in the process. The nature of goodwill makes it a non-realizable asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>30", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following to answer the questions      The education department of Arimoro Local Government incurred the following expenses in 1995:      NConstruction of classrooms 500 000Purchase of tables and chairs 50 000Purchase of textbooks for library 40 000Annual inter-house sports competition 20 000payment of teachers salary 80 000    Capital expenditure for the year was", "images": [], "options": {"A": "N690 000", "B": "N590 000", "C": "N500 000", "D": "N140 000"}, "answer": "B", "explanation": "Capital expenditure = 500000 + 50000 + 40000  = #590,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>31", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following to answer the questions      The education department of Arimoro Local Government incurred the following expenses in 1995:      NConstruction of classrooms 500 000Purchase of tables and chairs 50 000Purchase of textbooks for library 40 000Annual inter-house sports competition 20 000payment of teachers salary 80 000  Recurrent expenditure of the year was", "images": [], "options": {"A": "N170 000", "B": "N130 000", "C": "N120 000", "D": "N100 000"}, "answer": "D", "explanation": "Recurrent expenditure is calculated as:     = 20000 + 80000    = #100,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>32", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Which of the following is a recurrent expenditure to a Local Government Council?", "images": [], "options": {"A": "building classroom", "B": "sinking of wells", "C": "purchase of drugs", "D": "construction of markets"}, "answer": "C", "explanation": "Recurrent expenditure refers to the regular and ongoing costs that are necessary to run a business, organization, or system. These are usually short-term expenses that are consumed within the year and are necessary for the daily functioning of the organization. In the context of a Local Government Council, the purchase of drugs would be considered a recurrent expenditure as it is a regular and ongoing cost necessary for the functioning of the health services of the council. The other options such as building classrooms, sinking of wells, and construction of markets are capital expenditures as they are long-term investments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>33", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is an example of production overhead?", "images": [], "options": {"A": "discount allowed", "B": "carried inwards", "C": "factory rent", "D": "carriage outwards"}, "answer": "C", "explanation": "Production overhead refers to the indirect factory-related costs that are incurred when a product is manufactured. This includes costs related to the operation of the factory such as rent, utilities, and maintenance. Therefore, 'factory rent' is an example of production overhead.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>34", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "The double entries for refund of unsuccessful application monies are, debit", "images": [], "options": {"A": "application for shares account, credit bank account", "B": "bank account, credit application for shares account", "C": "allotment account, credit application for shares account", "D": "allotment account, credit bank account"}, "answer": "A", "explanation": "When a company refunds unsuccessful application monies, it reduces (debits) the 'Application for Shares Account' and decreases (credits) its 'Bank Account'. This is because the company is giving back the money it had previously received for share applications that were not successful, hence reducing its cash at bank and the corresponding share application account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>35", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Rent paid during 1995 was #2,000 while rent paid at 31st December, 1995 was #200", "images": [], "options": {"A": "N2,400", "B": "N2,200", "C": "N2,000", "D": "N1,800"}, "answer": "D", "explanation": "Rent debited is calculated as:    = 2000 - 200    = #1800", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1998>36", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When a share is sold for less than its nominal value, the difference is debited to", "images": [], "options": {"A": "share premium account", "B": "share discount account", "C": "profit and loss account", "D": "capital reserve account"}, "answer": "B", "explanation": "When a share is sold for less than its nominal value, the difference is known as a discount on issue of shares. This discount is debited to the 'Share Discount Account'. The 'Share Discount Account' is a loss for the company and is shown on the debit side of the Profit and Loss Account. It is not debited to the 'Share Premium Account' because this account is used when shares are issued at a premium, not a discount. It is also not debited to the 'Profit and Loss Account' directly or the 'Capital Reserve Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>37", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions     The accounting year of Fehintola Ltd. ends on 31st December every year.  Plant and Machinery purchased on 1st January, Year 1 N600,000  Depreciation rate per annum, 10%  Scrap value, N60,000.    Using reducing balance method, what is the depreciation for Yr. 2?", "images": [], "options": {"A": "N160,000", "B": "N114,000", "C": "N60,000", "D": "N54,000"}, "answer": "B", "explanation": "Cost 600000Yr 1 Dep ( 10%  x 600000)  60000 540000Yr 2 Dep ( 10%  x 540000)  54000 486000    Therefore , the depreciation totalled for year 1 and 2 is 60000 + 54000  = #114,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>38", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions     The accounting year of Fehintola Ltd. ends on 31st December every year.  Plant and Machinery purchased on 1st January, Year 1 N600,000  Depreciation rate per annum, 10%  Scrap value, N60,000.  Using reducing balance method, what is the net book value on 31st December of Yr. 2?", "images": [], "options": {"A": "N551,400", "B": "N546,000", "C": "N540,000", "D": "N486,000"}, "answer": "D", "explanation": "The net book value on 31st December of Year 2 is the net book value at the end of Year 1 minus the depreciation for Year 2. The net book value at the end of Year 1 is N540,000 and the depreciation for Year 2 is N54,000. Therefore, the net book value on 31st December of Year 2 is N540,000 - N54,000 = N486,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>39", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions     The accounting year of Fehintola Ltd. ends on 31st December every year.  Plant and Machinery purchased on 1st January, Year 1 N600,000  Depreciation rate per annum, 10%  Scrap value, N60,000.  Using the straight line method, what is the cumulative depreciation at the end of yr.3?", "images": [], "options": {"A": "N216,000", "B": "N206,340", "C": "N180,000", "D": "N162,600"}, "answer": "C", "explanation": "Depreciation = 10%  x 600,000  = #60,000    For 3 years, cummulative depreciation = 3 x 60000  = #180,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>40", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the questions     The accounting year of Fehintola Ltd. ends on 31st December every year.  Plant and Machinery purchased on 1st January, Year 1 N600,000  Depreciation rate per annum, 10%  Scrap value, N60,000.  Using the straight line method, what is the net book value at the beginning of the year 3?", "images": [], "options": {"A": "N540,000", "B": "N420,000", "C": "N486,000", "D": "N438,000"}, "answer": "B", "explanation": "NBV = Cost - dep  = 600,000 - 180,000 ( accumulated depreciation)  = 420,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>41", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the questions       NOpening stock of Raw materials 5800Closing stock of Raw materials 4500Raw materials purchased 19000Carriage outwards 1300Direct labour 4000Electricity(Factory) 2500Supervisor's salary 5500Depreciation of Plant 1500Sales 58000Closing stock (finished Goods) 4500Administrative expenses 5500selling and Distributive expenses 3000    The cost of raw materials used is", "images": [], "options": {"A": "N28,100", "B": "N24,300", "C": "N25,300", "D": "N20,300"}, "answer": "D", "explanation": "Cost of raw materials consumed = 5800 + 19000 - 4500  = #20,300", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>42", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the questions       NOpening stock of Raw materials 5800Closing stock of Raw materials 4500Raw materials purchased 19000Carriage outwards 1300Direct labour 4000Electricity(Factory) 2500Supervisor's salary 5500Depreciation of Plant 1500Sales 58000Closing stock (finished Goods) 4500Administrative expenses 5500selling and Distributive expenses 3000  The prime cost is", "images": [], "options": {"A": "N26,800", "B": "N25,600", "C": "N24,300", "D": "N21,300"}, "answer": "C", "explanation": "Prime cost = cost of raw materials consumed + direct labour  = 20300 + 4000  = #24,300", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>43", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the questions       NOpening stock of Raw materials 5800Closing stock of Raw materials 4500Raw materials purchased 19000Carriage outwards 1300Direct labour 4000Electricity(Factory) 2500Supervisor's salary 5500Depreciation of Plant 1500Sales 58000Closing stock (finished Goods) 4500Administrative expenses 5500selling and Distributive expenses 3000  What is the factory overhead?", "images": [], "options": {"A": "N10,800", "B": "N9,800", "C": "N9,500", "D": "N8,500"}, "answer": "C", "explanation": "Factory overhead is the sum of Electricity(Factory), Supervisor's salary, and Depreciation of Plant. Therefore, Factory overhead = 2500 + 5500 + 1500 = N9500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>44", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the questions       NOpening stock of Raw materials 5800Closing stock of Raw materials 4500Raw materials purchased 19000Carriage outwards 1300Direct labour 4000Electricity(Factory) 2500Supervisor's salary 5500Depreciation of Plant 1500Sales 58000Closing stock (finished Goods) 4500Administrative expenses 5500selling and Distributive expenses 3000  What is the production cost?", "images": [], "options": {"A": "N33,800", "B": "N33,200", "C": "N28,700", "D": "N28,300"}, "answer": "A", "explanation": "Production cost is the sum of the cost of raw materials, Direct labour, and Factory overhead. The cost of raw materials is calculated as: Opening stock of Raw materials + Raw materials purchased - Closing stock of Raw materials = 5800 + 19000 - 4500 = N20300. Therefore, Production cost = 20300 + 4000 + 9500 = N33800.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>45", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the questions       NOpening stock of Raw materials 5800Closing stock of Raw materials 4500Raw materials purchased 19000Carriage outwards 1300Direct labour 4000Electricity(Factory) 2500Supervisor's salary 5500Depreciation of Plant 1500Sales 58000Closing stock (finished Goods) 4500Administrative expenses 5500selling and Distributive expenses 3000  The gross profit", "images": [], "options": {"A": "N33,800", "B": "N28,700", "C": "N25,600", "D": "N19,000"}, "answer": "B", "explanation": "Gross profit = Sales - (Cost of production - closing stock of finished goods)  = 58000 - ( 33800 - 4500)  = #28700", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1998>46", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Interest on Partner's drawing is credited to", "images": [], "options": {"A": "capital account", "B": "drawings account", "C": "current account", "D": "appropriate account"}, "answer": "D", "explanation": "The drawing account is not an expense – rather, it represents a reduction of owners' equity in the business. It is used primarily for businesses that are taxed as sole proprietorships or partnerships. Interest in the drawing is an income of the partnership firm and is credited to profit and loss appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>47", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Carriage outwards is the amount spent on transporting", "images": [], "options": {"A": "goods sold", "B": "goods purchased", "C": "goods returned to stock", "D": "excess stock"}, "answer": "A", "explanation": "Carriage outwards refers to the costs of transportation that a company incurs when it sells and delivers its products to customers. Therefore, it is the amount spent on transporting goods sold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>48", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "The loss made by a non-trading organization is called", "images": [], "options": {"A": "surplus", "B": "drawing", "C": "deficit", "D": "shortage"}, "answer": "C", "explanation": "In the context of a non-trading organization, the term 'deficit' is used to refer to a situation where the organization's expenses exceed its income, resulting in a loss. Therefore, the loss made by a non-trading organization is called a deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>49", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discount allowed is charged to", "images": [], "options": {"A": "profit and loss appropriation account", "B": "manufacturing account", "C": "trading account", "D": "profit and loss account"}, "answer": "D", "explanation": "Discount allowed is an expense for the business and it is charged to the Profit and Loss Account. It is not charged to the Profit and Loss Appropriation Account, Manufacturing Account or Trading Account. The Profit and Loss Account is used to record all expenses and revenues of a business, including discount allowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1998>50", "subject": "Accounts", "year": "1998", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following is true in public sector accounting? Cost of assets is", "images": [], "options": {"A": "A depreciated on straight line method", "B": "depreciated on reducing balance method", "C": "expensed in the year of purchase", "D": "charged to federation account"}, "answer": "C", "explanation": "The costs of long-lived assets are usually capitalized, i.e., included in the asset shown on the balance sheet, and then allocated as expenses in the income statement over the period during which they are expected to provide economic benefits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>1", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Errors in the ledger can be corrected through", "images": [], "options": {"A": "journal proper", "B": "sales day book", "C": "purchases day book", "D": "control account"}, "answer": "A", "explanation": "Errors in the ledger can be corrected through the journal proper. The journal proper, also known as the general journal, is a book of original entry in which non-routine transactions such as corrections of errors, closing of accounts, etc., are recorded. The other options like sales day book, purchases day book, and control account are not used for correcting errors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>2", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Items in the bank statement of a business but not in the Cash Book before preparation of bank reconciliation statement do not include", "images": [], "options": {"A": "bank charges", "B": "standing order", "C": "presented cheque", "D": "interest overdraft"}, "answer": "C", "explanation": "Items in the bank statement of a business but not in the Cash Book before preparation of bank reconciliation statement do not include presented cheques. A presented cheque is a cheque that has been presented to the bank by the payee and is already recorded in the cash book. On the other hand, bank charges, standing orders, and interest on overdraft are items that may appear on the bank statement but not in the cash book before the preparation of the bank reconciliation statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>3", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discounts received is", "images": [], "options": {"A": "credited to the trading account", "B": "debited to the Profit and Loss Account", "C": "credited to the Profit and Loss Account", "D": "credited to the Appropriation Account"}, "answer": "C", "explanation": "Discounts received is a gain for the business, hence it is credited to the Profit and Loss Account. In accounting, the rule is to debit the receiver and credit the giver. In this case, the business is the receiver of the discount, so the discount received account is debited and since it is an income, the profit and loss account is credited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>4", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Carriage outwards is charged to", "images": [], "options": {"A": "trading account", "B": "appropriation account", "C": "purchase account", "D": "profit and loss account"}, "answer": "D", "explanation": "Carriage outwards refers to the cost of transportation of goods sold to customers, and it is considered as a selling expense. Therefore, it is charged to the Profit and Loss Account, specifically under the expenses section. It is not charged to the trading account because it is not directly related to the purchase or production of goods. It is also not charged to the appropriation account because this account is used for distribution of profits among the partners or shareholders, not for recording expenses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>5", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     #Debtors (1/1/98) 2000Debtors (31/12/98) 1250Cash received from debtors 6000Bad debts written off 750Discount allowed 500Discount received 125    What was the amount of sales for the year?", "images": [], "options": {"A": "N8,500", "B": "N6,625", "C": "N6,500", "D": "N6,000"}, "answer": "C", "explanation": "Sales is calculated as:    = (6000 + 750 + 500 + 1250) - 2000    = #6500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1999>6", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     #Debtors (1/1/98) 2000Debtors (31/12/98) 1250Cash received from debtors 6000Bad debts written off 750Discount allowed 500Discount received 125  Assuming a gross profit of N3,000, what was the net profit?", "images": [], "options": {"A": "N3,375", "B": "N2,625", "C": "N2,000", "D": "N1,875"}, "answer": "D", "explanation": "The net profit can be calculated by subtracting the sum of bad debts written off and discount allowed from the gross profit. Given a gross profit of N3,000, bad debts of N750, and discount allowed of N500, the net profit is: 3000 - 750 - 500 = N1,875. Therefore, option 4 is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1999>7", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     #Debtors (1/1/98) 2000Debtors (31/12/98) 1250Cash received from debtors 6000Bad debts written off 750Discount allowed 500Discount received 125  The debtors balance to be shown in the Balance Sheet at 31st December, 1998 is", "images": [], "options": {"A": "N6,000", "B": "N3,250", "C": "N2,000", "D": "N1,250"}, "answer": "D", "explanation": "The debtors balance at the beginning of the year was N2000. During the year, cash received from debtors was N6000, bad debts written off was N750 and discount allowed was N500. Therefore, the total amount of money that should have been received from the debtors is N2000 (initial debtors) + N6000 (cash received) + N750 (bad debts) + N500 (discount allowed) = N9250. However, the debtors balance at the end of the year is N1250. This means that N9250 - N1250 = N8000 was received from the debtors during the year. Therefore, the debtors balance to be shown in the Balance Sheet at 31st December, 1998 is N1250.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>8", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CONTROL ACCOUNTS : TREATMENT OF CONTRA ENTRIES", "question": "Which of the following is a contra entry?", "images": [], "options": {"A": "lodgement of cheques into bank account", "B": "Lodgement of cash in hand into bank account", "C": "withdrawal of cash for private use", "D": "treatment of discount received in the cash book"}, "answer": "B", "explanation": "A contra entry is an entry which is recorded in the debit side and credit side of the same account but in different columns. It is an entry that offsets or counteracts another entry. Lodgement of cash in hand into bank account is a contra entry because it involves two different aspects of the same transaction i.e., decrease in cash in hand (debit) and increase in bank balance (credit).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>9", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Profit expressed as a proportion of cost price is", "images": [], "options": {"A": "gross profit", "B": "mark-up", "C": "margin", "D": "profit percentage"}, "answer": "B", "explanation": "Mark-up is the term used to describe profit expressed as a proportion of cost price. It is the amount added to the cost price of goods to cover overheads and profit. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. Margin is the difference between the selling price and the producer's cost. Profit percentage is the ratio of profit to the selling price.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>10", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following will not make a trial balance total to agree?", "images": [], "options": {"A": "incomplete posting in the ledger accounts", "B": "double entry for each transaction", "C": "omission of a transaction from the ledger", "D": "wrong entry of correct amount into different groups of accounts"}, "answer": "A", "explanation": "Errors that will affect the agreement of the trial balance are:  - one sided omission  - misposting of figures to the account  - errors in transfers of totals of subsidairy book  - two entries on the same side  - trial balancing errors  - undercasting or overcasting of balances", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>11", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Deferred charges are also known as", "images": [], "options": {"A": "prepayment", "B": "accrued expenses", "C": "accruals", "D": "deferred income"}, "answer": "A", "explanation": "Deferred charges, also known as prepayments, are costs that have been paid for in advance and are recorded as assets on a company's balance sheet. These costs will be expensed out or consumed over time or through the normal operations of the business. The term 'prepayment' is used because these are costs that have been paid ahead of being consumed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>12", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "The vote book in governmental accounting is used to", "images": [], "options": {"A": "register the name of voters", "B": "control expenditure", "C": "record government revenue", "D": "record taxes paid"}, "answer": "B", "explanation": "In governmental accounting, the vote book is used to control expenditure. It is a record of all financial transactions related to a particular budget or fund. It helps to ensure that expenditures do not exceed the approved budget. It is not used to register voters, record government revenue, or record taxes paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>13", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the questions    July 1 cash in hand #420 ,Cash at bank #65002 paid Asaolu T. by cheque #15005 paid transport by cash #429 received cheque from olawoyin #360015 cash sales to date #180017 paid haruna by cheque #120019 paid Umana by cash #10031 paid wages by cash #1500    The cash in hand on 31st July is", "images": [], "options": {"A": "N2,220", "B": "N2,078", "C": "N1,642", "D": "N578"}, "answer": "D", "explanation": "The cash in hand on 31st July is calculated by adding the initial cash in hand and the cash sales to date, then subtracting the cash payments made. The calculation is as follows: #420 (initial cash in hand) + #1800 (cash sales to date) - #42 (transport) - #100 (Umana) - #1500 (wages) = #578.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>14", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the questions    July 1 cash in hand #420 ,Cash at bank #65002 paid Asaolu T. by cheque #15005 paid transport by cash #429 received cheque from olawoyin #360015 cash sales to date #180017 paid haruna by cheque #120019 paid Umana by cash #10031 paid wages by cash #1500  The cash at bank on 31st July is", "images": [], "options": {"A": "N10,100", "B": "N8,900", "C": "N7,400", "D": "N5,900"}, "answer": "C", "explanation": "The cash at bank on 31st July is calculated by adding the initial cash at bank and the cheque received, then subtracting the cheque payments made. The calculation is as follows: #6500 (initial cash at bank) + #3600 (cheque received) - #1500 (Asaolu T.) - #1200 (Haruna) = #7400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>15", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the questions    July 1 cash in hand #420 ,Cash at bank #65002 paid Asaolu T. by cheque #15005 paid transport by cash #429 received cheque from olawoyin #360015 cash sales to date #180017 paid haruna by cheque #120019 paid Umana by cash #10031 paid wages by cash #1500  The total cash payments during the month is", "images": [], "options": {"A": "N2,220", "B": "N2,078", "C": "N1,642", "D": "N578"}, "answer": "C", "explanation": "Total cash payment is calculated as:    = 42 + 100 + 1500    = #1642", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>16", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "How many bits make a byte?", "images": [], "options": {"A": "8 bits", "B": "9 bits", "C": "16 bits", "D": "64 bits"}, "answer": "A", "explanation": "A byte is a unit of digital information that most commonly consists of eight bits. Therefore, the correct answer is 8 bits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>17", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "Which of the following does not relate to a non-for-profit-making organization?", "images": [], "options": {"A": "Balance sheet", "B": "receipt and payment account", "C": "Ledger Accounts", "D": "Profit and Loss Account"}, "answer": "D", "explanation": "Non-for-profit organizations do not have a Profit and Loss Account because they are not engaged in commercial activities for profit. Instead, they use a Statement of Financial Activities (SOFA) to show all incoming resources and all resources expended, regardless of whether they are capital or revenue in nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>18", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is the memory part that is available for use by the computer user?", "images": [], "options": {"A": "bits", "B": "Ram", "C": "Data", "D": "ROM"}, "answer": "B", "explanation": "RAM (Random Access Memory) is the part of a computer's memory that is directly accessible to the CPU, and can be read from and written to by the processor or other hardware devices. It is used to store data and instructions that are actively being used by the computer. This makes it available for use by the computer user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>19", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "In-not-profit-making organizations, accumulated fund is the name for", "images": [], "options": {"A": "profit", "B": "loss", "C": "capital", "D": "current assets"}, "answer": "C", "explanation": "In not-for-profit organizations, the term 'accumulated fund' is used to refer to the capital of the organization. This is because these organizations do not have shareholders or owners, so the funds they accumulate over time through surplus (income over expenditure) is considered their capital. This is different from profit-making organizations where capital refers to the funds invested by the owners or shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>20", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the questions     J. Chike B. Balla Current Accounts balance (1/4/98) 4000 6000Current Accounts balance (1/4/99) 7000 ?Drawings 1500 1500Share of net profit ? 2500    What is chike's share of profit from the partnership for the year ended 31/3/99 ?", "images": [], "options": {"A": "N8,500", "B": "N7,000", "C": "N5,500", "D": "N4,500"}, "answer": "D", "explanation": "Chike's share of profit = 7000 + 1500 - 4000  = #4,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1999>21", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the questions     J. Chike B. Balla Current Accounts balance (1/4/98) 4000 6000Current Accounts balance (1/4/99) 7000 ?Drawings 1500 1500Share of net profit ? 2500   What is Balla's Current Account balance as at 31/3/99?", "images": [], "options": {"A": "N11,000", "B": "N7,000", "C": "N5,500", "D": "N4,500"}, "answer": "B", "explanation": "Balla's Current Account balance as at 31/3/99 is calculated by adding the share of net profit to the initial balance and subtracting the drawings. So, the balance would be the initial balance (6000) plus the share of net profit (2500) minus the drawings (1500), which equals 7000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>1999>22", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the questions     J. Chike B. Balla Current Accounts balance (1/4/98) 4000 6000Current Accounts balance (1/4/99) 7000 ?Drawings 1500 1500Share of net profit ? 2500   Their profit sharing ratio is", "images": [], "options": {"A": "1 . 8 : 1", "B": "1 . 5 : 1", "C": "1 . 25 : 1", "D": "1 : 1"}, "answer": "A", "explanation": "Increase in J.Chike's Current account balance:  Balance on 1/14/99 = 7000  Balance on 1/4/98 = 3000  Increase in balance = 7000 - 3000  = 4000    Chike's drawing = 1500  Increase in balance = 3000    Total share of net profit = 3000 + 1500  = 4500    Share of profit ratio= 4500/2500  = 1.8 : 1", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>23", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Company tax paid is debited to", "images": [], "options": {"A": "profit and loss appropriation", "B": "manufacturing account", "C": "profit and loss account", "D": "trading account"}, "answer": "A", "explanation": "Company tax paid is debited to the debit side of the profit and loss appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>24", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following is not a revenue expenditure ?", "images": [], "options": {"A": "repair of generating set", "B": "purchase of inventory", "C": "extension of building", "D": "payment of subscription"}, "answer": "C", "explanation": "Extension of building is not a revenue expenditure. Revenue expenditure is an amount that is expensed immediately—thereby being matched with revenues of the current period. Examples include rent, salaries, and maintenance. On the other hand, extension of building is a capital expenditure, which is not expensed immediately but is instead capitalized and depreciated or amortized over the life of the asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>25", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Dividend proposed by a company is shown in its Balance Sheet as", "images": [], "options": {"A": "current asset", "B": "current liability", "C": "long-term liability", "D": "fixed asset"}, "answer": "B", "explanation": "A proposed dividend is not an asset to the company, rather it is a liability because it is an amount that the company is expected to pay to its shareholders. Therefore, it is shown as a current liability in the balance sheet. A current liability is a debt that a company expects to pay within one fiscal year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>26", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The main classes of shares are", "images": [], "options": {"A": "preference shares and rights issue", "B": "fixed shares and current share", "C": "ordinary shares and preference shares", "D": "redeemable shares and Irredeemable shares"}, "answer": "C", "explanation": "The main classes of shares are ordinary shares and preference shares. Ordinary shares, also known as common shares, give the holder the right to vote at shareholders' meetings and to receive any dividends paid by the company. Preference shares, on the other hand, give the holder the right to a fixed dividend, but generally do not provide voting rights. However, preference shareholders have a higher claim on the assets and earnings of the company than ordinary shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>27", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     HOPEWELL LIMITED   Balance sheet as at 31st December, 1998.    N  NOrdinary share capital 140 000 Plant and Machinery 100 0008% Preference share 63 000 Furniture 62 000Retained earnings 40 000 Motor van 75 00010% Debentures 60 000 Stock 22 000Creditors 10 000 Debtors 26 000Accrued wages  12 000  Bank  40 000    325 000   325 000     What is the current ratio?", "images": [], "options": {"A": "4 : 1", "B": "3 : 1", "C": "2 : 1", "D": "1 : 1"}, "answer": "A", "explanation": "The current ratio is calculated as Current Assets / Current Liabilities. From the balance sheet, the current assets are Stock (22,000), Debtors (26,000), and Bank (40,000) which sum up to 88,000. The current liabilities are Creditors (10,000) and Accrued wages (12,000) which sum up to 22,000. Therefore, the current ratio is 88,000 / 22,000 = 4 : 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>28", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     HOPEWELL LIMITED   Balance sheet as at 31st December, 1998.    N  NOrdinary share capital 140 000 Plant and Machinery 100 0008% Preference share 63 000 Furniture 62 000Retained earnings 40 000 Motor van 75 00010% Debentures 60 000 Stock 22 000Creditors 10 000 Debtors 26 000Accrued wages  12 000  Bank  40 000    325 000   325 000   The debt to equity ratio is", "images": [], "options": {"A": "1 : 4.05", "B": "1 : 4", "C": "1 : 3", "D": "1 : 2.3"}, "answer": "C", "explanation": "Equity ratio = Total liabilties/shareholder's equity    = 82000/ 140000 + 63000 + 40000    = 1: 0.3", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>29", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     HOPEWELL LIMITED   Balance sheet as at 31st December, 1998.    N  NOrdinary share capital 140 000 Plant and Machinery 100 0008% Preference share 63 000 Furniture 62 000Retained earnings 40 000 Motor van 75 00010% Debentures 60 000 Stock 22 000Creditors 10 000 Debtors 26 000Accrued wages  12 000  Bank  40 000    325 000   325 000   What is the working capital?", "images": [], "options": {"A": "N180,000", "B": "N140,000", "C": "N88,000", "D": "N66,000"}, "answer": "D", "explanation": "The working capital is calculated as Current Assets - Current Liabilities. From the balance sheet, the Current Assets are Stock (22,000), Debtors (26,000), and Bank (40,000) which sum up to 88,000. The Current Liabilities are Creditors (10,000) and Accrued wages (12,000) which sum up to 22,000. Therefore, the working capital is 88,000 - 22,000 = 66,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>30", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     HOPEWELL LIMITED   Balance sheet as at 31st December, 1998.    N  NOrdinary share capital 140 000 Plant and Machinery 100 0008% Preference share 63 000 Furniture 62 000Retained earnings 40 000 Motor van 75 00010% Debentures 60 000 Stock 22 000Creditors 10 000 Debtors 26 000Accrued wages  12 000  Bank  40 000    325 000   325 000   The equity capital is", "images": [], "options": {"A": "N203,000", "B": "N180,000", "C": "N140,000", "D": "N88,000"}, "answer": "B", "explanation": "The equity capital is the sum of Ordinary share capital and Retained earnings. From the balance sheet, the Ordinary share capital is 140,000 and the Retained earnings is 40,000. Therefore, the equity capital is 140,000 + 40,000 = 180,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>31", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the questions     HOPEWELL LIMITED   Balance sheet as at 31st December, 1998.    N  NOrdinary share capital 140 000 Plant and Machinery 100 0008% Preference share 63 000 Furniture 62 000Retained earnings 40 000 Motor van 75 00010% Debentures 60 000 Stock 22 000Creditors 10 000 Debtors 26 000Accrued wages  12 000  Bank  40 000    325 000   325 000   What is the quick ratio?", "images": [], "options": {"A": "4 : 1", "B": "3 : 1", "C": "2 : 1", "D": "1 : 1"}, "answer": "B", "explanation": "Quick ratio = Current assets - Closing stock / Current liabilities    = 88000 - 22000/22000    = 66000/22000    = 3 : 1", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>32", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A suspense Account is used to", "images": [], "options": {"A": "record difference in the books until errors are located", "B": "accumulate debit and credit balances", "C": "accomodate debit balances of profit statements", "D": "record accounts of the general ledger"}, "answer": "A", "explanation": "A suspense account is a temporary account that is used when an accounting transaction error has occurred and the error is not immediately identifiable. It is used to record differences in the books until the errors are located and corrected. Once the error is identified, the suspense account is debited or credited accordingly to balance the books.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>33", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The purpose of the trading account is to ascertain", "images": [], "options": {"A": "carriage outwards", "B": "gross profit or loss", "C": "distribution expenses", "D": "net profit or loss"}, "answer": "B", "explanation": "The purpose of the trading account is to ascertain the gross profit or loss of a business. Gross profit is calculated by subtracting the cost of goods sold from the net sales. It does not take into account any other expenses or income. Therefore, the correct answer is 'gross profit'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>34", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A trial Balance is the", "images": [], "options": {"A": "narration of all transactions and accounts", "B": "debit balances of the accounts", "C": "list of all balances extracted from the ledger", "D": "list of all credit balances in the ledger"}, "answer": "C", "explanation": "A trial balance is a list of all balances extracted from the ledger. It is a statement that shows the balances of all ledger accounts on a specific date. It is prepared to check the arithmetical accuracy of the ledger accounts. Therefore, the correct answer is 'list of all balances extracted from the ledger'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>35", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Which of the following entries is made when damaged goods are returned to the supplier?", "images": [], "options": {"A": "supplier's account is debited and the purchasers account credited", "B": "returns outwards account is debited and the supplier's account credited", "C": "purchaser's Account is debited and the supplier's account credited", "D": "supplier's account is debited and the returns Outwards Account credited"}, "answer": "D", "explanation": "We can make the journal entry for the return of damaged goods to the supplier by debiting the accounts payable or cash account and crediting the purchase returns and allowances account if we use the periodic inventory system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>36", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A balance sheet is a", "images": [], "options": {"A": "form of trading account", "B": "proof of arithmetical accuracy of postings", "C": "statement showing profits at a certain date", "D": "statement showing assets and liabilities at a certain date"}, "answer": "D", "explanation": "A balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time. It provides a basis for computing rates of return and evaluating the capital structure of the company. It is not a form of trading account, it does not prove the arithmetical accuracy of postings, and it does not show profits at a certain date.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>37", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Yinka bought goods worth N800.00 and sold at a margin of 20% on selling price. How much did she sell the goods?", "images": [], "options": {"A": "N1,000", "B": "N960", "C": "N933", "D": "N820"}, "answer": "B", "explanation": "The selling price is calculated by dividing the cost price by (1 - margin/100). Here, the cost price is N800 and the margin is 20%. So, the selling price is 800 / (1 - 20/100) = N1000. However, the question states that the margin is on the selling price, not the cost price. This means that the selling price is such that 20% of it is equal to the profit. So, we let the selling price be x. Therefore, 20% of x = profit = selling price - cost price. Solving for x gives x = 800 / 0.8 = N1000. But since the margin is on the selling price, the actual selling price will be less than N1000. The closest option to this is N960.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>38", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Recurrent expenditure of government is paid from", "images": [], "options": {"A": "contingencies fund", "B": "reserve fund", "C": "development fund", "D": "consolidated fund"}, "answer": "D", "explanation": "Recurrent expenditure refers to the regular and ongoing costs that are necessary to run a government, such as salaries, maintenance, etc. These are paid from the consolidated fund, which is the government's main bank account into which all receipts are paid and from which all disbursements are made.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>39", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "A bond acknowledging a loan to a company under the company's seal, bearing a fixed rate of interest is known as", "images": [], "options": {"A": "certificate", "B": "agreement", "C": "bank loan", "D": "debenture"}, "answer": "D", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. Both corporations and governments frequently issue this type of bond to secure capital. Like other types of bonds, debentures are documented in an indenture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>40", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "One mega byte is equal to", "images": [], "options": {"A": "8 bytes", "B": "1 million bytes", "C": "10 million bytes", "D": "1 billion bytes"}, "answer": "B", "explanation": "A megabyte is a unit of information or computer storage equal to 1 million bytes. This is based on the standard decimal system of measurement, where 'mega' refers to a multiplier of 1 million. However, in the binary system used by computers, a megabyte is actually 1,048,576 (2^20) bytes, but it is commonly rounded down to the nearest million bytes for simplicity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>41", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Purchases of goods from Obi had been entered in Obike's Account. This is an error of", "images": [], "options": {"A": "omission", "B": "compensation", "C": "commission", "D": "original entry"}, "answer": "C", "explanation": "Errors of commission are those errors which may be committed when transactions are recorded with wrong amounts, wrong balancing is done, wrong posting and/or wrong carrying forwarded is done.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>42", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The authority of the Accountant General to disburse from government fund is called", "images": [], "options": {"A": "estimate", "B": "warrant", "C": "provision", "D": "vote"}, "answer": "B", "explanation": "The authority of the Accountant General to disburse from government fund is called a warrant. A warrant is a legal document that authorizes a person to perform a specific act, in this case, the disbursement of funds from the government treasury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>43", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Use the following information to answer the questions     Umana Ltd. issued 200,000 shares at N1 each out of its Authorized Share capital of N300,000 at N1 each. At the end of the first call, all shareholders paid in full, except for one shareholder who owes N10,000.    The company's paid-up capital is", "images": [], "options": {"A": "N310,000", "B": "N290,000", "C": "N210,000", "D": "N190,000"}, "answer": "D", "explanation": "Paid up capital = issued capital - Unpaid capital  = 200,000 - 10,000  = #190,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>44", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Use the following information to answer the questions     Umana Ltd. issued 200,000 shares at N1 each out of its Authorized Share capital of N300,000 at N1 each. At the end of the first call, all shareholders paid in full, except for one shareholder who owes N10,000.   The unissued capital of the company is", "images": [], "options": {"A": "N310,000", "B": "N300,000", "C": "N210,000", "D": "N100,000"}, "answer": "D", "explanation": "Unissued capital is the portion of a company's equity that has been authorized for sale but has not yet been sold (issued). Umana Ltd. has an authorized share capital of N300,000 at N1 each, and it has issued 200,000 shares at N1 each. So, the unissued capital is N300,000 - N200,000 = N100,000. The correct option is N100,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>45", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The total share capital which a company would be allowed to issue is known as", "images": [], "options": {"A": "issued share capital", "B": "authorised share capital", "C": "working capital", "D": "fixed capital"}, "answer": "B", "explanation": "Authorised share capital is the maximum amount of share capital that a company is allowed to issue according to its constitution or articles of association.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>46", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Creditors at start was N4,650 and at close N2,480, cash paid to suppliers during the year amounted to N12,000. Credit purchases for the year is valued at?", "images": [], "options": {"A": "N14,480", "B": "N12,000", "C": "N9,830", "D": "N7,130"}, "answer": "C", "explanation": "Credit Purchases = Cash paid to suppliers + Creditors at close - Creditors at start. Substituting the given values gives: Credit Purchases = N12,000 + N2,480 - N4,650 = N9,830.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>1999>47", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A sale of goods to audu was not posted. This is an error of", "images": [], "options": {"A": "omission", "B": "compensation", "C": "commission", "D": "principle"}, "answer": "A", "explanation": "An error of omission in accounting refers to a situation where a transaction is completely left out and not recorded. In this case, the sale of goods to Audu was not posted, meaning it was completely left out of the books, hence it's an error of omission.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>48", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Into how many major types can general purpose computers be classified?", "images": [], "options": {"A": "six", "B": "five", "C": "four", "D": "three"}, "answer": "C", "explanation": "General purpose computers can be classified into four types: Microcomputers, Minicomputers, Mainframe computers, and Supercomputers. Microcomputers are personal computers that are small and inexpensive. Minicomputers are larger than microcomputers and have higher processing speed. Mainframe computers are large computers capable of handling and processing very large amounts of data quickly. Supercomputers are the fastest and most expensive computers, used for specialized applications that require immense amounts of mathematical calculations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>49", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Which of the following is not a petty cash book item? purchase of", "images": [], "options": {"A": "machinery", "B": "stamps", "C": "office pins", "D": "milk"}, "answer": "A", "explanation": "A petty cash book is a record of small-value purchases before they are later transferred to the ledger. It is maintained by a petty or junior cashier. This cashier includes all the transaction like expenses incurred on tea, Xerox copy etc. The purchase of machinery is not a petty cash book item because it is a significant expense and not a small-value purchase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>1999>50", "subject": "Accounts", "year": "1999", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "When a shareholder fails to pay the calls requested from him, this situation leads to", "images": [], "options": {"A": "forfeiture of shares", "B": "bonus shares", "C": "over-subscription", "D": "right issues"}, "answer": "A", "explanation": "When a shareholder fails to pay the calls requested from him, this situation leads to forfeiture of shares. Forfeiture of shares is the cancellation of shares due to non-payment of call money. It is a penalty imposed on the shareholder who fails to pay the amount due on shares allotted to him. Bonus shares, over-subscription, and right issues are not related to the non-payment of call money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>1", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following is not an intangible asset?", "images": [], "options": {"A": "Licences", "B": "Patents", "C": "Trade marks", "D": "Fixtures"}, "answer": "D", "explanation": "An intangible asset is a type of asset that is not physical in nature. Examples include patents, copyrights, franchises, goodwill, trademarks, and trade names. The term 'fixtures' refers to items that are attached (or fixed) to real property. If an item is not removable without damage to the real property, it is considered a fixture and part of the real property. Therefore, 'fixtures' is not an intangible asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>2", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : CAPITAL EXPENDITURE", "question": "Which of the following is a capital expenditure?", "images": [], "options": {"A": "salaries and wages", "B": "Stationery", "C": "Repairs of motors vehicle", "D": "Purchase of furniture"}, "answer": "D", "explanation": "Capital expenditure, or CapEx, are funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, an industrial plant, technology, or equipment. Salaries and wages, stationery, and repairs of motor vehicles are all examples of revenue expenditure, which are short-term costs used in the day-to-day running of a business. Therefore, 'Purchase of furniture' is a capital expenditure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>3", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Sales of goods for #600 to Ade was not posted. This is an error of", "images": [], "options": {"A": "omission", "B": "Commission", "C": "Principle", "D": "compensation"}, "answer": "A", "explanation": "The error described in the question is an error of omission. In accounting, an error of omission occurs when a financial transaction is completely omitted from the accounting records. In this case, the sale of goods to Ade was not posted, hence it was omitted from the records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>4", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Shares sold at the nominal value are issued at", "images": [], "options": {"A": "a discount", "B": "a premium", "C": "a loss", "D": "par"}, "answer": "D", "explanation": "Shares sold at the nominal value are issued at par. In finance, 'at par' means at face value. When shares are issued at their face value, they are said to be issued at par. Therefore, if the shares are sold at their nominal value, they are issued at par.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>5", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "The excess of current assets over current liabilities is", "images": [], "options": {"A": "authorised share capital", "B": "working capital", "C": "loan capital", "D": "called- up capital"}, "answer": "B", "explanation": "The excess of current assets over current liabilities is known as working capital. Current assets are the assets that a company expects to convert into cash within one year. Current liabilities are the company's debts or obligations that are due within one year. The difference between these two is the working capital, which is a measure of a company's short-term liquidity - the ability to cover its short-term obligations. This is important for the day-to-day operations of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>6", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the  following information to answer questions 6 to 9williams and  jacob are in partnership but there is no partnership agreement. The capital contributed are #60,000 and #40,000 respectively. Profit for the year is #20,000. Interest on capital is 10%.    what is Williams' share of profit?", "images": [], "options": {"A": "#12,000", "B": "#10,000", "C": "#8,000", "D": "#5,000"}, "answer": "D", "explanation": "share of profit = profit - interest on captial                           = 20,000 - (6000+4000)                            =10,000  When there is no partnership agreement, the profit and loss will be shared equally   therefore, williams' share of profit is                  1/2 x 10,000                    = 5,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>7", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "williams and  jacob are in partnership but there is no partnership agreement. The capital contributed are #60,000 and #40,000 respectively. Profit for the year is #20,000. Interest on capital is 10%.  What is Jacob's share of profit?", "images": [], "options": {"A": "#10,000", "B": "#8,000", "C": "#5,000", "D": "#4,000"}, "answer": "C", "explanation": "jacob's share of profit will be:             1/2 x 10,000                  = 5,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>8", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "williams and  jacob are in partnership but there is no partnership agreement. The capital contributed are #60,000 and #40,000 respectively. Profit for the year is #20,000. Interest on capital is 10%.  If Williams introduces cash of #10,000 by way of loan to the partnership, how muh interest will he earn per annum on the loan?", "images": [], "options": {"A": "#2,000", "B": "#1,500", "C": "#1,000", "D": "#500"}, "answer": "D", "explanation": "According to the partnership deed, if a partner introduces cash in inform of loan, there will be a  5% interest a year on loans.   therefore,           5% x 10,000             = 500", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>9", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "williams and  jacob are in partnership but there is no partnership agreement. The capital contributed are #60,000 and #40,000 respectively. Profit for the year is #20,000. Interest on capital is 10%.  What is Williams ' interest on capital?", "images": [], "options": {"A": "#10,000", "B": "#7,000", "C": "#6,000", "D": "#4,000"}, "answer": "C", "explanation": "Interest on capital is calculated by multiplying the capital by the interest rate. In this case, Williams' capital is #60,000 and the interest rate is 10%. Therefore, the interest on capital is #60,000 * 10/100 = #6,000. Hence, the correct answer is #6,000.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>10", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "In a bonus issue of one new share for every four held, a holder of 100,000 shares will get an additional shares of", "images": [], "options": {"A": "50,000", "B": "25,000", "C": "20,000", "D": "10,000"}, "answer": "B", "explanation": "In a bonus issue of one new share for every four held, a holder of 100,000 shares will get an additional 1/4 of his total shares as bonus shares. Therefore, the holder will get 100,000 * 1/4 = 25,000 additional shares. Hence, the correct answer is 25,000.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>11", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A partner who has full powers of participating in the conduct of a partnership business is a", "images": [], "options": {"A": "general partner", "B": "limited partner", "C": "sleeping partner", "D": "nominal partner"}, "answer": "A", "explanation": "A general partner is a partner who has full powers of participating in the conduct of a partnership business. They are fully involved in the company's operations and share in its profits and losses. They also have unlimited liability, meaning they are personally responsible for the partnership's debts. This contrasts with a limited partner, who only has limited liability and does not participate in the day-to-day operations of the business. A sleeping partner is a partner who invests capital into the business but does not participate in its operations, while a nominal partner is a partner in name only and has no real involvement or liability in the partnership.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>12", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "The ratio which measures the solvency of a firm is the", "images": [], "options": {"A": "quick ratio", "B": "gross profit over sales ratio", "C": "stock turnover ratio", "D": "debtors turnover ratio"}, "answer": "A", "explanation": "The quick ratio, also known as the acid-test ratio, measures the solvency of a firm. It does this by comparing a company's most liquid assets (cash, marketable securities, and accounts receivable) to its current liabilities. This ratio shows how well a company can pay off its current liabilities without relying on the sale of inventory. This is different from the gross profit over sales ratio, which measures a company's profitability, and the stock turnover ratio and debtors turnover ratio, which measure how quickly a company sells its inventory and collects its accounts receivable, respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>13", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "When goods are purchased on account, the accounting entries are", "images": [], "options": {"A": "debit purchase account, credit suppplier's account", "B": "credit purchase account, debit supplier's account", "C": "credit bank account, debit purchase account", "D": "debit bank account, credit purchase account"}, "answer": "A", "explanation": "When goods are purchased on account, the accounting entries are to debit the purchase account and credit the supplier's account. Debiting the purchase account increases the expense account, reflecting the cost of the goods purchased. Crediting the supplier's account increases the liability account, reflecting the amount owed to the supplier.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>14", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Closing stock was overstated. the effect is that", "images": [], "options": {"A": "amount of goods available was understated", "B": "cost of goods sold was overstated", "C": "amount of sales returns was understated", "D": "gross profit was overstated"}, "answer": "D", "explanation": "If closing stock is overstated, it means that the value of goods on hand at the end of the accounting period is recorded as more than the actual amount. This results in a lower cost of goods sold (COGS) because COGS is calculated as opening stock plus purchases minus closing stock. A lower COGS increases the gross profit because gross profit is calculated as sales minus COGS. Therefore, if closing stock is overstated, gross profit is also overstated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>15", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "Use the following information to answer questions 15 and 16XYZ Enterprises bought ABC Enterprises by issuing 30,000 ordinary shares of #1 at a discount of 5%. The assets of ABC Enterprises are stock #18,000, Debtors #11,000.    The purchase consideration was", "images": [], "options": {"A": "#31,500", "B": "#30,000", "C": "#28,500", "D": "#28,000"}, "answer": "C", "explanation": "The purchase consideration is calculated by multiplying the number of shares issued by the discounted share price. In this case, the share price is #1 and there is a 5% discount. Therefore, the discounted share price is #1 - 5% of #1 = #0.95. The purchase consideration is therefore 30,000 shares * #0.95 = #28,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2000>16", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "XYZ Enterprises bought ABC Enterprises by issuing 30,000 ordinary shares of #1 at a discount of 5%. The assets of ABC Enterprises are stock #18,000, Debtors #11,000.  Capital reserve was", "images": [], "options": {"A": "#1,500", "B": "#1,000", "C": "#500", "D": "#150"}, "answer": "C", "explanation": "The capital reserve is calculated by subtracting the purchase consideration from the total assets of the acquired company. In this case, the total assets of ABC Enterprises are #18,000 (stock) + #11,000 (debtors) = #29,000. The purchase consideration is #28,500 (from the first question). Therefore, the capital reserve is #29,000 - #28,500 = #500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2000>17", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "The entries necessary for recording profit loading on the goods sent to branch are", "images": [], "options": {"A": "debit Branch stock Account, credit Branch stock Adjustment Account", "B": "credit Branch stock Adjustment Account, debit Goods sent to Branch Account", "C": "debit Goods sent to Branch Account, credit Branch stock Account", "D": "debit Branch stock Adjustment Account, credit Branch stock Account"}, "answer": "A", "explanation": "Profit loading on goods sent to a branch is an accounting practice where the head office charges the branch more than the cost price for goods sent. This is done to account for profits that the head office would have made if it sold the goods directly. The correct entry for this is to debit the Branch Stock Account (increasing the value of stock at the branch) and credit the Branch Stock Adjustment Account (reducing the adjustment needed for the branch's stock).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>18", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "Expenses incurred when incorporating a company are", "images": [], "options": {"A": "preliminary expenses", "B": "selling expenses", "C": "administrative expenses", "D": "finanncial expenses"}, "answer": "A", "explanation": "Expenses incurred when incorporating a company are known as preliminary expenses. These are costs that are incurred before a company starts business operations. They include legal fees, registration fees, and other expenses related to the formation of the company. These costs are considered as capital expenses and are written off over a period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>19", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Gross profit of a business is the", "images": [], "options": {"A": "excess of sales over all the trading expenses", "B": "difference between sales and purchases", "C": "excess of sales over the cost of goods sold", "D": "difference between discounts received and  discounts allowed"}, "answer": "C", "explanation": "Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. Gross profit will appear on a company's income statement and can be calculated by subtracting the cost of goods sold (COGS) from revenue (sales).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>20", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Prepaid rent of #650 had been recorded as #560. This is an error of", "images": [], "options": {"A": "Commission", "B": "Principle", "C": "Compensation", "D": "Original entry"}, "answer": "D", "explanation": "This is an error of original entry. An error of original entry occurs when an incorrect amount is input into the accounting records. In this case, the prepaid rent was recorded as #560 instead of the correct amount of #650.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>21", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "When a buyer is under- charged, the seller forwards", "images": [], "options": {"A": "a debit note", "B": "a credit note", "C": "an undercast note", "D": "a payment receipt"}, "answer": "A", "explanation": "Debit note is a document sent by the seller to the buyer to correct an undercharged.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>22", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer questions 22 and 23.Rent owing as at 31st December 1998 #800. Rent paid up to 31st December 1998 #1,700. Rent owing as at 1st january 1998 #500.    Rent charged to the profit and loss account for the year 1998 is", "images": [], "options": {"A": "#2,000", "B": "#1,700", "C": "#1,400", "D": "#1,300"}, "answer": "A", "explanation": "Rent charged to the profit and loss account for the year 1998 is calculated as follows: Rent paid up to 31st December 1998 (#1,700) + Rent owing as at 31st December 1998 (#800) - Rent owing as at 1st January 1998 (#500) = #2,000. Therefore, the correct answer is #2,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>23", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Rent owing as at 31st December 1998 #800. Rent paid up to 31st December 1998 #1,700. Rent owing as at 1st january 1998 #500.  The closing balance for 1998 is an item under", "images": [], "options": {"A": "current liabilty", "B": "current asset", "C": "long term liability", "D": "fixed asset"}, "answer": "A", "explanation": "The closing balance for 1998 is an item under current liability. This is because rent owing is a debt that the company has to pay within a short period of time (typically within a year), which makes it a current liability. Current liabilities are a company's debts or obligations that are due within one year, appearing on the company's balance sheet and include short term debt, accounts payable, accrued liabilities and other similar debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>24", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "In computing, external storage is called", "images": [], "options": {"A": "backing storage", "B": "logging storage", "C": "primary storage", "D": "extra storage"}, "answer": "A", "explanation": "In computing, external storage is called backing storage. Backing storage refers to any computer storage media besides the internal memory. These can be devices like CD-ROMs, DVDs, USB drives, or hard drives. They are used to safely store data and information for long periods, even when the computer is switched off or disconnected from power.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>25", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Profit expressed as a fraction of the selling price is known as", "images": [], "options": {"A": "mark -up", "B": "margin", "C": "gross profit", "D": "net profit"}, "answer": "B", "explanation": "Profit expressed as a fraction of the selling price is known as margin. Margin is a profitability ratios calculated as net income divided by revenues, or net profits divided by sales. It measures how much out of every dollar of sales a company actually keeps in earnings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>26", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "In computing ALU stands for", "images": [], "options": {"A": "Accounting Logical Unit", "B": "Arithmetic Logic Unit", "C": "Acess logical Unit", "D": "Additional Liability Unit"}, "answer": "B", "explanation": "In computing, ALU stands for Arithmetic Logic Unit. It is a digital circuit used to perform arithmetic and logic operations. It represents the fundamental building block of the central processing unit (CPU) of a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>27", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Which of the following is not a petty Cash Book item? purchase of", "images": [], "options": {"A": "stationery", "B": "postage stamps", "C": "cutlass for gardeners", "D": "machinery"}, "answer": "D", "explanation": "A petty cash book is a record of small-value purchases before they are later transferred to the ledger. It is maintained by a petty or junior cashier. This type of cash book usually uses the imprest system: a certain amount of money is provided to start with and the petty cashier expenses from this amount. Items like stationery, postage stamps, and gardening tools are small-value purchases that can be recorded in a petty cash book. However, machinery is a high-value item and would not be recorded in a petty cash book.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>28", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer questions 28 and 30                   #                                      Opening stock :                                       raw materials                                                               6500                                      work -in-progress                                                         2500                                       Closing stock :                                       raw materials                                                                4000                                        work-in-progress                                                          1000                                        purchase of raw materials                                            12500                                        manufacturing wages                                                    2000                                        factory rent                                                                     500    What is the cost of raw materials consumed?", "images": [], "options": {"A": "#18,500", "B": "#16,000", "C": "#15,000", "D": "#12,500"}, "answer": "C", "explanation": "cost of raw materials consumed= opening stock of raw materials+ purchases of raw materials- closing stock of raw materials                                                                               =6,500+12,500-4000                                                                                         =15,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>29", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#                                      Opening stock :                                       raw materials                                                               6500                                      work -in-progress                                                         2500                                       Closing stock :                                       raw materials                                                                4000                                        work-in-progress                                                          1000                                        purchase of raw materials                                            12500                                        manufacturing wages                                                    2000                                        factory rent                                                                     500            What is the cost of production?", "images": [], "options": {"A": "#19,000", "B": "#18,500", "C": "#15,000", "D": "#12,500"}, "answer": "A", "explanation": "cost of production = prime cost+ opening work in progress- closing work in progress                                      = 17,500+ 2,500+ 1000                                            = 19,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>30", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#                                      Opening stock :                                       raw materials                                                               6500                                      work -in-progress                                                         2500                                       Closing stock :                                       raw materials                                                                4000                                        work-in-progress                                                          1000                                        purchase of raw materials                                            12500                                        manufacturing wages                                                    2000                                        factory rent                                                                     500            What is the prime cost?", "images": [], "options": {"A": "#19,000", "B": "#18,000", "C": "#17,500", "D": "#17,000"}, "answer": "D", "explanation": "prime cost= cost of raw materials consumed + manufacturing wages                                 15,000+ 2,000+ 500                                      = 17,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>31", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "The vote book in public sector accounting is used to", "images": [], "options": {"A": "register the names of voters", "B": "control expenditure", "C": "control government policies", "D": "record revenue accruing to he government"}, "answer": "B", "explanation": "The vote book in public sector accounting is used to control expenditure. It is a record of all financial transactions made by a government department or agency, and is used to ensure that the department does not exceed its allocated budget.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>32", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The accounting entry for depreciation at the end of each year is to debit", "images": [], "options": {"A": "provision for depreciation account and credit machinery account", "B": "provision for depreciation account and credit profit and loss account", "C": "trading account and credit provision for depreciation account", "D": "manufacturing account and credit provision for depreciation account"}, "answer": "A", "explanation": "The accounting entry for depreciation at the end of each year is to debit provision for depreciation account and credit machinery account. This is because depreciation is an expense that reduces the value of an asset (in this case, machinery). The provision for depreciation account is debited to increase the accumulated depreciation (the total depreciation that has been recorded for an asset so far), and the machinery account is credited to decrease its book value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>33", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER", "question": "An account is said to have a debit balance because", "images": [], "options": {"A": "the first entry made in its is on its debit side", "B": "there are more entries on the debit side than on the credit side", "C": "total value of debit entries is more than total value of credit entries", "D": "there is no entry at all on the debit side"}, "answer": "C", "explanation": "An account is said to have a debit balance when the total value of debit entries is more than the total value of credit entries. This is because in double-entry bookkeeping, debits and credits in accounts are used to track the changes of value due to business transactions. If the total of debit entries in an account exceeds the total of credit entries, that account is said to have a debit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>34", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "use the information below to answer questions 34 to 36A motor vehicle bought for #16,000 was estimated to have a useful life span of 4 years and a scrap value of #2,000.    What is the net book value of the motor vehicle at the end of the third year, using the straight line method?", "images": [], "options": {"A": "#9,000", "B": "#5,500", "C": "#3,500", "D": "#2,000"}, "answer": "B", "explanation": "Cost - scrap value /estimated useful life                             16,000 - 2000 / 4                                        = 3,500( depreciation)         The net book value at the end of the third year will be:                                                                                                   #                                 year 1       cost                                    16,000                                                 less  dep                                  (3500)                                                                                                     12,500                                  year 2       cost                                         12,500                                                  less dep                                     3,500                                                                                                       9,000                                  year 3      cost                                                9,000                                                 less dep                                          3,500                                                                                                            5,500   The NBV is #5,500 at the end of the third year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>35", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "A motor vehicle bought for #16,000 was estimated to have a useful life span of 4 years and a scrap value of #2,000.  Using the straight line method, What is the amount of depreciation charged per annum?", "images": [], "options": {"A": "#9,000", "B": "#5,500", "C": "#4,000", "D": "#3,500"}, "answer": "D", "explanation": "Cost - scrap value /estimated useful life                             16,000 - 2000 / 4                                                                                  = 3,500( depreciation)", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>36", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "A motor vehicle bought for #16,000 was estimated to have a useful life span of 4 years and a scrap value of #2,000.  If the vehicle is sold for #6,000 at the end of thrid year, what is the profit or loss on sales?", "images": [], "options": {"A": "#1,000 profit", "B": "#500 profit", "C": "#500 loss", "D": "#1,000 loss"}, "answer": "B", "explanation": "since the NBV at the end of the third year is #5,000 and the vehilce is sold for #6,000   Therefore, 6,000 - 5,500                 = 500 gain/ profit", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>37", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not an example of input devices?", "images": [], "options": {"A": "card reader", "B": "keyboard", "C": "Visual Display Unit", "D": "Central Processing Unit"}, "answer": "D", "explanation": "An input device is a piece of hardware used to provide data and control signals to an information processing system such as a computer or information appliance. Examples of input devices include keyboards, mouse, scanners, digital cameras, joysticks, and microphones. In the given options, card reader, keyboard and Visual Display Unit are input devices. The Central Processing Unit (CPU) is not an input device, it is the primary component of a computer that performs most of the processing inside the computer. It interprets and carries out the basic instructions that operate a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>38", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The double entry for increasing provision for bad debt is debit", "images": [], "options": {"A": "Debtors's Account, Credit provision for Bad Debt Account", "B": "Profit and loss Account, Credit debtor's Account", "C": "Debtor's Account, Credit profit and loss Account", "D": "Profit and loss Account, credit Provision for Bad Debt Account"}, "answer": "D", "explanation": "In accounting, a provision is an account which records a present liability of an entity. The recording of the liability in the entity's balance sheet is matched to an appropriate expense account on the entity's income statement. Therefore, when increasing provision for bad debt, the double entry would be to debit (increase) the expense account (Profit and Loss Account) and credit (increase) the liability account (Provision for Bad Debt Account).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>39", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Bills receivables is a", "images": [], "options": {"A": "current liability", "B": "current asset", "C": "long -term liability", "D": "fictitious asset"}, "answer": "B", "explanation": "Bills receivables are considered a current asset because they represent a legal claim for payment from a business's customers or debtors. They are expected to be converted into cash within a short period, typically one year, hence they are classified as current assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>40", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "How much did Olu sell goods bought at #1,000 if he sells at a margin of 20% on the selling price?", "images": [], "options": {"A": "#1,250", "B": "#1,200", "C": "#1,000", "D": "#250"}, "answer": "B", "explanation": "cost price = #1,000  margin = 20%   selling price = ?  profit = 20% x 1000                   =200  Therefore, selling price= profit + cost price                                                  =200 + 1000                                                      =1,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>41", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Which of the following accounts has a debit balance?", "images": [], "options": {"A": "capital reserve", "B": "revenue reserve", "C": "share premium", "D": "share discount"}, "answer": "D", "explanation": "In accounting, a debit balance is the ending balance in an account that has more debits than credits. This is typically the case for asset accounts, expense accounts, and dividend accounts. A share discount account is an example of an account with a debit balance. It represents the amount by which the par value of the shares issued is more than their issue price. The other options, capital reserve, revenue reserve, and share premium, are all accounts with credit balances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>42", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A list of all credit and debit balances from the ledger acounts is", "images": [], "options": {"A": "trial balance", "B": "profit and loss statement", "C": "statement of affairs", "D": "balance sheet"}, "answer": "A", "explanation": "A trial balance is a list of all the General ledger accounts (both revenue and capital) contained in the ledger of a business. This list will contain the name of each nominal ledger account and the value of that nominal ledger balance. Each nominal ledger account will hold either a debit balance or a credit balance. The debit balance values will be listed in the debit column of the trial balance and the credit value balance will be listed in the credit column. The other options, profit and loss statement, statement of affairs, and balance sheet, are financial statements, not lists of account balances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2000>43", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer the question                                                                       #sales                                                 14600purchases                                           5500Returns inward                                      150Salaries                                               1000Rent                                                    2000Discount received                                 400Closing stock                                       250Opening stock                                      100     The cost of goods sold is", "images": [], "options": {"A": "#5,350", "B": "#5,150", "C": "#4,500", "D": "#4,250"}, "answer": "A", "explanation": "The cost of goods sold is calculated by adding the opening stock to purchases and then subtracting the closing stock. In this case, the opening stock is 100, purchases are 5500, and the closing stock is 250. Therefore, the cost of goods sold is 100 + 5500 - 250 = 5350.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>44", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question                                                                       #sales                                                 14600purchases                                           5500Returns inward                                      150Salaries                                               1000Rent                                                    2000Discount received                                 400Closing stock                                       250Opening stock                                      100     Gross profit is", "images": [], "options": {"A": "#10,350", "B": "#10,200", "C": "#9,500", "D": "#9,100"}, "answer": "D", "explanation": "Gross profit is calculated by subtracting the cost of goods sold from sales. In this case, sales are 14600 and the cost of goods sold is 5350 (calculated in the previous question). Therefore, the gross profit is 14600 - 5350 = 9250.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>45", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer the question                                                                       #sales                                                 14600purchases                                           5500Returns inward                                      150Salaries                                               1000Rent                                                    2000Discount received                                 400Closing stock                                       250Opening stock                                      100     Net sales is", "images": [], "options": {"A": "#15,000", "B": "#14,750", "C": "#14,600", "D": "#14,450"}, "answer": "D", "explanation": "Net sale = sales - returns inwards                  =  14,600 - 150                             14,450", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>46", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question                                                                       #sales                                                 14600purchases                                           5500Returns inward                                      150Salaries                                               1000Rent                                                    2000Discount received                                 400Closing stock                                       250Opening stock                                      100     Net profit is", "images": [], "options": {"A": "#9,100", "B": "#7,850", "C": "#7,750", "D": "#6,500"}, "answer": "D", "explanation": "Net profit = gross profit + discount received  - expenses (salaries + Rent)                    = (9,100+ 400)- (1,000+2000)                        = 9500 - 3000                         = 6500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2000>47", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The capital of a not- profit making organization is", "images": [], "options": {"A": "capital reservea", "B": "accumulated fund", "C": "endownment fund", "D": "development fund"}, "answer": "B", "explanation": "The capital of a not-for-profit organization is known as the accumulated fund. This is the fund that is accumulated from the surplus of income over expenditure. It is similar to the capital of a profit-making organization, which is accumulated from the profits of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>48", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is used in locating errors in the ledger?", "images": [], "options": {"A": "Trading Account", "B": "Trial Balance", "C": "Control Account", "D": "Journal proper"}, "answer": "C", "explanation": "Control account is a memorandum account into which are transfered in totals, the various amounts of transactions which have been debited or credited in details to individual ledger accounts. Control accounts aids the location of errors, prevention of fraud, easy detection of missing figure etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>49", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "A reserve is an amount", "images": [], "options": {"A": "to be paid to creditors", "B": "set out of profit for the future use", "C": "for paying dividends", "D": "recovered from debts earlier written off"}, "answer": "B", "explanation": "A reserve is an amount set aside from the profit of a business for future use. This could be for any specific purpose like replacing fixed assets, paying off future liabilities, or for general business expansion. It is not necessarily to be paid to creditors or for paying dividends, and it is not recovered from debts earlier written off.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2000>50", "subject": "Accounts", "year": "2000", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The document which authorises the Minister of Finance to release fund for government expenditure is", "images": [], "options": {"A": "a warrant", "B": "a bank cheque", "C": "an order", "D": "a vote book"}, "answer": "A", "explanation": "A warrant is a document that authorises the Minister of Finance to release funds for government expenditure. It is an official order that allows or compels the release of funds. A bank cheque, an order, or a vote book do not have this function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>1", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "The income accruing to debenture holders is called", "images": [], "options": {"A": "dividend", "B": "net profit", "C": "shares", "D": "interest"}, "answer": "D", "explanation": "The income accruing to debenture holders is called interest. Debentures are a type of debt instrument that is not secured by physical assets or collateral. They are backed only by the general creditworthiness and reputation of the issuer. The holders of debentures are paid a fixed interest income periodically.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>2", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "The amount by which assets exceed specific liabilities is called", "images": [], "options": {"A": "reserve", "B": "provision", "C": "premium", "D": "bonus"}, "answer": "A", "explanation": "Reserves are amount set aside out of profit and other surpluses, which are not designed to meet any liability or losses but are reatined in the business in order to strengthen the financial position of a business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>3", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Which of the following has a debit balance at the end of the year?", "images": [], "options": {"A": "Rates prepaid account", "B": "Bank loan account", "C": "Income received in advance account", "D": "Ordinary share capital account"}, "answer": "A", "explanation": "A debit balance at the end of the year is typically found in asset accounts. Rates prepaid account is an asset account that represents payments made in advance for services that the company will receive in the future. Therefore, it has a debit balance at the end of the year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>4", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Which of the following is not an example of a fictitious asset?", "images": [], "options": {"A": "Raw materials stock", "B": "Debit balance fo profit and loss account", "C": "preliminary expenses of a limited company", "D": "Expenditure on incorporation carried forward"}, "answer": "A", "explanation": "Fictitious assets are not real assets but are shown as assets in the financial statements. They are written off against the firm's earnings in more than one accounting period. Examples include preliminary expenses of a limited company, debit balance of profit and loss account, and expenditure on incorporation carried forward. Raw materials stock, however, is a current asset and not a fictitious asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>5", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Prime cost coinsists of", "images": [], "options": {"A": "direct material and direct labour cost", "B": "direct material, direct labour and direct expenses", "C": "direct material, dierct labour, direct expenses and overhead", "D": "dierct material and direct expenses"}, "answer": "B", "explanation": "Prime cost is the total cost of direct materials, direct labor, and direct expenses. It does not include overhead costs. Therefore, the correct answer is 'direct material, direct labour and direct expenses'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>6", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Use the following information to answer questions 6 to 8Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month:    Dec. 1      petty cash in hand                                    517           1      petty cash to imprest                               3,483           6      Bought notebooks                                    328           7      Paid wages                                                914           14    Bought postages stamps                          375           16    Paid to J. Thomas, a creditor                   536            21   Paid wages                                                928            23   Bought envelopes                                     437            27   Bought postages stamps                          210    Amount to be posted to the personal ledger is", "images": [], "options": {"A": "#765", "B": "#585", "C": "#536", "D": "#517"}, "answer": "C", "explanation": "In the imprest system, the amount to be posted to the personal ledger is the amount paid to a creditor. In this case, the amount paid to J. Thomas, a creditor, is #536. Therefore, the correct answer is '#536'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>7", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month:    Dec. 1      petty cash in hand                                    517           1      petty cash to imprest                               3,483           6      Bought notebooks                                    328           7      Paid wages                                                914           14    Bought postages stamps                          375           16    Paid to J. Thomas, a creditor                   536            21   Paid wages                                                928            23   Bought envelopes                                     437            27   Bought postages stamps                          210     Amount spent on stationery is", "images": [], "options": {"A": "#765", "B": "#585", "C": "#538", "D": "#437"}, "answer": "A", "explanation": "The amount spent on stationery is the sum of the amounts spent on notebooks and envelopes, which is #328 + #437 = #765.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>8", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Taiwo is a sole trader who keeps his petty cash on the imprest system, the imprest amount being #4,000. The following transactions took place for a particular month:    Dec. 1      petty cash in hand                                    517           1      petty cash to imprest                               3,483           6      Bought notebooks                                    328           7      Paid wages                                                914           14    Bought postages stamps                          375           16    Paid to J. Thomas, a creditor                   536            21   Paid wages                                                928            23   Bought envelopes                                     437            27   Bought postages stamps                          210     Amount to be reimbursed at the end of the month is", "images": [], "options": {"A": "#4,000", "B": "#3,728", "C": "#3,483", "D": "#1,842"}, "answer": "B", "explanation": "The amount to be reimbursed at the end of the month is the total amount spent during the month, which is #328 (notebooks) + #914 (wages) + #375 (postage stamps) + #536 (J. Thomas, a creditor) + #928 (wages) + #437 (envelopes) + #210 (postage stamps) = #3,728.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>9", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Which of the following explains the short term insolvency of a company?", "images": [], "options": {"A": "Acid test ratio", "B": "Debtor to equity ratio", "C": "Net profit margin ratio", "D": "Gross profit margin ratio"}, "answer": "A", "explanation": "The short term insolvency of a company is best explained by the Acid test ratio. This ratio, also known as the quick ratio, measures a company's ability to meet its short-term obligations with its most liquid assets. It is calculated by subtracting inventories from current assets and then dividing by current liabilities. A higher acid test ratio indicates a higher likelihood of a company being able to cover its current liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>10", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "which of the following is a fictitious assets?", "images": [], "options": {"A": "Overdraft", "B": "Csah in hand", "C": "Reserves", "D": "Preliminary expenses"}, "answer": "D", "explanation": "Fictitious assets are not real assets but are expenses & losses which for some reason could not be written off during the accounting period of their incidence. Preliminary expenses are a common example of fictitious assets. They are incurred at the time of formation of a company or for extension of a project or setting up a new project, and are written off over a period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>11", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "A subsidiary record is a book", "images": [], "options": {"A": "of origianl entry", "B": "containing the ledgers", "C": "found in the journal", "D": "containing the balance sheet"}, "answer": "A", "explanation": "The subsidairy books are the books of original entry or prime entry in which events and transactions are initially recorded before being posted or transferred to the legders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>12", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "In which ledger is the control account prepared?", "images": [], "options": {"A": "Nominal ledger", "B": "General ledger", "C": "Sales ledger", "D": "Purchases ledger"}, "answer": "B", "explanation": "The control account is prepared in the General Ledger. A control account is a summary-level account in the general ledger. This account contains aggregated total of transactions that are individually stored in subsidiary-level ledger accounts. The purpose of control account is to keep the general ledger free of details, but still have the correct balance for the financial statements.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>13", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Suppliers personal accounts are found in the", "images": [], "options": {"A": "Purchases ledger", "B": "Sales account", "C": "Purchase account", "D": "Sales ledger"}, "answer": "A", "explanation": "Suppliers personal accounts are found in the Purchases ledger. A purchase ledger is a record of purchase transactions for a business, including raw materials and other supplies. It serves as a subsidiary ledger to the general ledger, providing detailed information about purchases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>14", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "Commission of #5,000 to a sales representative is debited to salaries account. This  is an error of", "images": [], "options": {"A": "reversal of entries", "B": "principle", "C": "commission", "D": "compensation"}, "answer": "B", "explanation": "Commission of #5,000 to a sales representative is debited to salaries account. This is an error of principle. An error of principle in accounting occurs when the fundamental principles of accounting are not adhered to while recording business transactions. In this case, the commission should have been debited to the commission account, not the salaries account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>15", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "Purchase of goods of #2,000 was treated as sales and entered in the sales day book and had been carried through the accounts as such. This is an error of", "images": [], "options": {"A": "principle", "B": "omission", "C": "reversal of entries", "D": "origainal entry"}, "answer": "A", "explanation": "Error of principle is an error whereby a transaction is entered in the wrong class of account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>16", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following is not correct?", "images": [], "options": {"A": "increases in asset accounts are entered on the debit side", "B": "Decreases in assets accounts are entered on the credit side", "C": "Increases in liability accounts are entered on the credit side", "D": "Decreases in liabilty accounts are entered on the credit side"}, "answer": "D", "explanation": "The statement 'Decreases in liability accounts are entered on the credit side' is not correct. In accounting, decreases in liability accounts are actually entered on the debit side. This is because liabilities are increased by credits and decreased by debits, following the rules of double-entry bookkeeping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>17", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "A business firm incurs labour cost in installing machinery. This should be treated as", "images": [], "options": {"A": "salaries", "B": "installation cost", "C": "machinery cost", "D": "wages"}, "answer": "B", "explanation": "the defination of an asset's cost is all costs that are necessary to get an asset in place and ready for use. Therefore, the cost of installation labour is part of the cost of the asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>18", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is an impersonal nominal account?", "images": [], "options": {"A": "Salaries account", "B": "Machinery account", "C": "Debtors account", "D": "Creditors account"}, "answer": "A", "explanation": "An impersonal nominal account is an account that records expenses, losses, incomes, and gains of a business. The Salaries account is an example of an impersonal nominal account as it records the expense incurred by the business in the form of salaries paid to employees. The other options, Machinery account, Debtors account, and Creditors account, are real and personal accounts respectively, not nominal accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>19", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "John Udoh started business on 1st january, 1998 with the following assets:                                                                                                                       #Motor van        120000Buildings     300000Stock of goods         40000  In addition, he had cash of #60,000 out of which #20,000 was borrowed from a friend.    The  capital of the business is", "images": [], "options": {"A": "#520,000", "B": "#500,000", "C": "#480,000", "D": "#460,000"}, "answer": "B", "explanation": "Capital = Assets - Liability                  (120,000+300,000+40,000+60,000) - 20,000                     = 500,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>20", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "John Udoh started business on 1st january, 1998 with the following assets:                                                                                                                       #Motor van        120000Buildings     300000Stock of goods         40000  In addition, he had cash of #60,000 out of which #20,000 was borrowed from a friend.    The liabilities of the business amount to", "images": [], "options": {"A": "#80,000", "B": "#60,000", "C": "#40,000", "D": "#20,000"}, "answer": "D", "explanation": "The liabilities of the business are the amount borrowed from a friend, which is #20,000. This matches option D.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>21", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "What is the effect on a firm for making a payment of #10,000 to a creditor?Its liabilities", "images": [], "options": {"A": "decrease and its assets decrease", "B": "increase and its assets decrease", "C": "decrease and its assets increase", "D": "increase and its assets increase"}, "answer": "A", "explanation": "When a firm makes a payment to a creditor, it reduces its liabilities because it owes less money. At the same time, its assets decrease because it has used cash (an asset) to make the payment. Therefore, the correct answer is 'decrease and its assets decrease'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>22", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "The depreciation method that allocates higher value to the use of an asset in its earlier years is", "images": [], "options": {"A": "diminishing balance method", "B": "revaluation method", "C": "fixed instalment method", "D": "straight line method"}, "answer": "A", "explanation": "The diminishing balance method of depreciation allocates higher value to the use of an asset in its earlier years. This is because it calculates depreciation based on the asset's book value at the beginning of each period, which decreases over time. Therefore, the depreciation expense is higher in the earlier years and decreases over the life of the asset. The other methods listed do not allocate higher value to the use of an asset in its earlier years.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>23", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Given a purchases invioce showing 5 items at #40,000 each less trade discount of 25% and cash discount of 10% the amount to be paid within the credit period is", "images": [], "options": {"A": "#200,000", "B": "#180,000", "C": "#135,000", "D": "#75,000"}, "answer": "C", "explanation": "Gross amount = 5 x 40,000                           = 200,000   Trade discount = 25% x 200,000                              = 50,000   Cash discount = (200,000 - 50,000) x 10%                                  = 15,000  Total discounts = 50,000 + 15,000                                           65,000        Amount to be paid wuthin the credit period is 200,000 - 65,000                                                                                    = 135,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>24", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "The purchases ledger control account is also referred to as", "images": [], "options": {"A": "Total Creditors Account", "B": "Total Debtors Account", "C": "Cash Account", "D": "Personal account"}, "answer": "A", "explanation": "The purchases ledger control account is also referred to as the Total Creditors Account. This is because it is an account that records the total amount owed by a business to its suppliers (creditors) for the goods or services purchased on credit. It is part of the double-entry bookkeeping system, where each transaction is recorded in two accounts: a debit in one account and a credit in another. In this case, the purchases ledger control account is credited when a purchase is made on credit, indicating an increase in the business's liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>25", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is a primary source of entry into the debtors ledger?", "images": [], "options": {"A": "Suppliers invoices", "B": "Returns outward notes", "C": "Sales invoices", "D": "Payment vouchers"}, "answer": "C", "explanation": "The primary source of entry into the debtors ledger is the sales invoices. This is because when a company sells goods or services on credit, the customer becomes a debtor to the company. The sales invoice serves as a record of the transaction and is therefore the primary source of entry into the debtors ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>26", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following to answer questions 26 to 29                                                                            #Opening stock  of Raw Materials                             8000Purchases                                                               45000Closing stock of Raw materials                               9500Direct wages                                                             6450Indirect wages                                                           2800Depreciation - Plant and machinery                         3200Factory rents and rates                                               350Opening work- in- progress                                     3250          Closing work-in- progress                                       3750      Cost of raw materials consumed is", "images": [], "options": {"A": "#53,000", "B": "#45,500", "C": "#45,000", "D": "#43,500"}, "answer": "D", "explanation": "The cost of raw materials consumed is calculated by adding the opening stock of raw materials to the purchases and then subtracting the closing stock of raw materials. In this case, the calculation would be 8000 (opening stock) + 45000 (purchases) - 9500 (closing stock) = 43500. Therefore, the correct answer is #43,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>27", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Opening stock  of Raw Materials                             8000Purchases                                                               45000Closing stock of Raw materials                               9500Direct wages                                                             6450Indirect wages                                                           2800Depreciation - Plant and machinery                         3200Factory rents and rates                                               350Opening work- in- progress                                     3250          Closing work-in- progress                                       3750  Prime cost is", "images": [], "options": {"A": "#53,000", "B": "#52,750", "C": "#49,950", "D": "#46,300"}, "answer": "C", "explanation": "Prime cost = cost of raw materials consumed + direct expenses                         = 43,500 + 6450                             =49,950", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>28", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Opening stock  of Raw Materials                             8000Purchases                                                               45000Closing stock of Raw materials                               9500Direct wages                                                             6450Indirect wages                                                           2800Depreciation - Plant and machinery                         3200Factory rents and rates                                               350Opening work- in- progress                                     3250          Closing work-in- progress                                       3750  Factory cost of production is", "images": [], "options": {"A": "#56,300", "B": "#53,300", "C": "#52,750", "D": "#45,500"}, "answer": "A", "explanation": "Factory cost of production is calculated as the prime cost plus factory overheads. Factory overheads include indirect wages, depreciation, and factory rents and rates. Therefore, the factory cost of production is 52950 + (2800 + 3200 + 350) = 56300.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>29", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Opening stock  of Raw Materials                             8000Purchases                                                               45000Closing stock of Raw materials                               9500Direct wages                                                             6450Indirect wages                                                           2800Depreciation - Plant and machinery                         3200Factory rents and rates                                               350Opening work- in- progress                                     3250          Closing work-in- progress                                       3750  Production cost is", "images": [], "options": {"A": "#57,300", "B": "#56,300", "C": "#55,800", "D": "#53,000"}, "answer": "C", "explanation": "production cost = factory cost of production + opening W.I.P - Closing W.I.P                                   =56,300 + 3,250 - 3,750                                      =   55,800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>30", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The accounting entries for recording cash withdrawn by the propietor for personal use are, debit", "images": [], "options": {"A": "Cash and credit purchases", "B": "Purchases and Credit Drawings", "C": "Purchases and credit Cash", "D": "Drawings and credit Cash"}, "answer": "D", "explanation": "When cash is withdrawn by the proprietor for personal use, it is recorded as a debit to Drawings and a credit to Cash. The Drawings account represents the amount of money or value of goods drawn by the owner from the business for personal use, and it decreases the owner's equity in the business. The Cash account represents the amount of cash available in the business, and it decreases when cash is withdrawn.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>31", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The head office usually issues goods to branches at", "images": [], "options": {"A": "prime cost", "B": "production cost", "C": "net realisable value", "D": "cost price"}, "answer": "D", "explanation": "The head office usually issues goods to branches at cost price. This is because the cost price is the actual cost incurred to produce the goods. It does not include any profit margin. The cost price is the most accurate reflection of the value of the goods at the time they are transferred from the head office to the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>32", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following does not relate to government accounting sysytem?", "images": [], "options": {"A": "Vote", "B": "Trial balance", "C": "Consolidated fund", "D": "Profit and loss account"}, "answer": "D", "explanation": "The option that does not relate to government accounting system is 'Profit and loss account'. Government accounting system is based on budgetary control and it does not aim at earning profits. Therefore, it does not prepare Profit and Loss Account. Instead, it prepares a statement of comparison of budget and actual figures to ascertain the efficiency of operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>33", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer question 33 to 35.Jeng Limited disposes a fixed asset in 1999 for #2,000. The asset was purchased in 1996 at a cost of #10,000 ans has been depreciated at the rate of 20% per annum using the straight line method.    What was the book value when the asset was sold?", "images": [], "options": {"A": "#8,000", "B": "#6,000", "C": "#4,000", "D": "#2,000"}, "answer": "C", "explanation": "The book value of an asset is calculated by subtracting the accumulated depreciation from the original cost of the asset. In this case, the accumulated depreciation is #10,000 * 20% * 3 = #6,000. The book value when the asset was sold is therefore #10,000 - #6,000 = #4,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>34", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Jeng Limited disposes a fixed asset in 1999 for #2,000. The asset was purchased in 1996 at a cost of #10,000 ans has been depreciated at the rate of 20% per annum using the straight line method.  What is the profit or loss on the disposal of the asset?", "images": [], "options": {"A": "#4,000 profit", "B": "#2,000 profit", "C": "#2,000 loss", "D": "#4,000 loss"}, "answer": "C", "explanation": "The profit or loss on the disposal of an asset is calculated by subtracting the book value of the asset from the disposal price. In this case, the profit or loss on the disposal of the asset is #2,000 - #4,000 = -#2,000, which is a loss of #2,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>35", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "What is the correct entry for the sale of the asset in the Asset Account and Disposal of Asset Account? Debit", "images": [], "options": {"A": "Fixed Asset Account #4,000, Credit Disposal of Assets Account #4,000", "B": "Disposal of Asset Account #4,000, Credit Fixed Asset Account #4,000", "C": "Disposal of Asset Account #2,000, Credit Fixed Asset Account #2,000", "D": "Fixed Asset Account #2,000, Credit Disposal of Assets Account #2,000"}, "answer": "B", "explanation": "When an asset is sold, the asset account is credited to reduce its balance. The disposal of asset account is debited to record the disposal. Therefore, the correct entry is 'Debit Disposal of Asset Account #4,000, Credit Fixed Asset Account #4,000'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>36", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "\"The Accountant thinks the investment in the book are worthless\". This is", "images": [], "options": {"A": "consistency concept", "B": "objectivity concept", "C": "conservatism concept", "D": "money measurement concept"}, "answer": "D", "explanation": "Money measurement states that only monetary transactions which can be expressed in monetary terms are recorded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>37", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Profits are recognised when goods are sold. What concept is this?", "images": [], "options": {"A": "Realization", "B": "Matching", "C": "Periodicity", "D": "Going concern"}, "answer": "A", "explanation": "The concept that profits are recognised when goods are sold is known as the Realization concept. This concept states that revenue and profits are recognized only when the transaction is completed, i.e., when the goods are sold or the services are rendered. Therefore, the correct answer is option 1, 'Realization'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>38", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions 38 to 40 Ali and Baba are in partnership sharing profits and losses in the ratio of 3:2 respectively. Net profit for the year was #4,000,000.00. The extract from the provisions of the partnership agreement and other information relating to 1999 are as follows:                                                                                                           Ali                                                                         BabaInterest on capital                                                                          5%                                                                          5%Partner's salary                                                                          #500000                                                              #300000Capital Account b/d                                                                    #5000000                                                           #4000000Current Account b/d                                                                   #400000                                                              #500000Partner's Drawing                                                                      #2300000                                                           #500000     What is Baba's share of profit?", "images": [], "options": {"A": "#1,650,000", "B": "#1,600,000", "C": "#1,280,000", "D": "#1,100,000"}, "answer": "D", "explanation": "interest on capital: Ali  (5% x 5000000) = 250000Baba (5% x 400000) =  200000                                            450000 Partners salary:Ali =          500000Baba =  300000                        800000   Share of profit = Net profit - interest on capital + partners salary                              =  4,000,000 - 450,000 + 800,000                                =4,000,000- 1,250,000                                              =  2,750,000    Ali's share  3/5 x 2,750,000   =1,650,000    Baba's share 2/5 x 2,750,000   = 1,110,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>39", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Ali and Baba are in partnership sharing profits and losses in the ratio of 3:2 respectively. Net profit for the year was #4,000,000.00. The extract from the provisions of the partnership agreement and other information relating to 1999 are as follows:                                                                                                           Ali                                                                         BabaInterest on capital                                                                          5%                                                                          5%Partner's salary                                                                          #500000                                                              #300000Capital Account b/d                                                                    #5000000                                                           #4000000Current Account b/d                                                                   #400000                                                              #500000Partner's Drawing                                                                      #2300000                                                           #500000     What is Ali's share of profit?", "images": [], "options": {"A": "#1,650,000", "B": "#1,600,000", "C": "#1,280,000", "D": "#1,100,000"}, "answer": "A", "explanation": "Ali's share of profit is calculated by first determining the total profit to be shared which is the net profit minus interest on capital and partners' salaries. Interest on capital for Ali is 5% of #5,000,000 which equals #250,000. Ali's salary is #500,000. Therefore, the total profit to be shared is #4,000,000 - #250,000 - #500,000 = #3,250,000. Ali's share of this profit is 3/5 of #3,250,000 which equals #1,950,000. However, Ali's drawings of #2,300,000 must be subtracted from this amount, resulting in a final share of profit for Ali of #1,950,000 - #2,300,000 = -#350,000. This means Ali has overdrawn his share of the profits by #350,000. However, none of the options match this answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>40", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Ali and Baba are in partnership sharing profits and losses in the ratio of 3:2 respectively. Net profit for the year was #4,000,000.00. The extract from the provisions of the partnership agreement and other information relating to 1999 are as follows:                                                                                                           Ali                                                                         BabaInterest on capital                                                                          5%                                                                          5%Partner's salary                                                                          #500000                                                              #300000Capital Account b/d                                                                    #5000000                                                           #4000000Current Account b/d                                                                   #400000                                                              #500000Partner's Drawing                                                                      #2300000                                                           #500000     What is the closing balance in Ali's current account?", "images": [], "options": {"A": "#1,600,000 Cr", "B": "#500,000 Cr", "C": "#500,000 Dr", "D": "#1,600,00 Dr"}, "answer": "B", "explanation": "Ali current account is calculated as:   ( salary+ interest on capital+ share of profit+ current account b/d) - Drawings        =500,000 +250,000 + 1,650,000 + 400,000 - 2,300,000                            =   2,800,000 - 2,300,000                                       =500,000 Cr", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2001>41", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS(PARTNERSHIP)", "question": "An agreement made by partners to regulate and govern their business activities is known as", "images": [], "options": {"A": "Partnership Act", "B": "Partnership Deed", "C": "Partnership Code", "D": "Memorandum"}, "answer": "B", "explanation": "A Partnership Deed is an agreement made by partners to regulate and govern their business activities. It outlines the terms and conditions of the partnership, including the roles and responsibilities of each partner, the division of profits and losses, and the procedures for resolving disputes and dissolving the partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>42", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "Which of the following are correct about limited liability company? i. Members have power to bind the company ii. Perpetual succession iii. Certificate of incorporation iv. Wound- up on death of a shareholder.", "images": [], "options": {"A": "II and III only", "B": "I and IV only", "C": "II and IV only", "D": "I and III only"}, "answer": "A", "explanation": "A limited liability company has the characteristic of perpetual succession, meaning the company continues to exist even if the shareholders change. It also requires a certificate of incorporation to be legally recognized. Members do not have the power to bind the company and the company does not wind up on the death of a shareholder. Therefore, statements II and III are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>43", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Issue of prospectus is an invitation to members of the public to", "images": [], "options": {"A": "Subcribe for shares", "B": "register a company", "C": "redeem shares", "D": "liquidate a company"}, "answer": "A", "explanation": "A prospectus is a formal document that is required by and filed with the Securities and Exchange Commission that provides details about an investment offering for sale to the public. In the context of an initial public offering (IPO), a prospectus is distributed by underwriters or brokerages to potential investors. Therefore, the issue of a prospectus is an invitation to members of the public to subscribe for shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>44", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer questions 44 to 46       #Sales                                                   200000Opening Stock                                      20000Purchases                                           140000Closing Stock                                       10000Expenses                                              10000  Bank                                                      10000Capital                                                    85000Creditors                                                35000Debtors                                                  50000Fixtures and fittings: cost                      10000Freehold land and building                     70000Drawings                                                10000    Percentage of net profit to sales is", "images": [], "options": {"A": "40%", "B": "30%", "C": "20%", "D": "10%"}, "answer": "C", "explanation": "To calculate the percentage of net profit to sales, we first need to calculate the net profit. From the given information, we can calculate the cost of goods sold (COGS) as Opening Stock + Purchases - Closing Stock = 20000 + 140000 - 10000 = 150000. Then, we subtract the COGS and Expenses from Sales to get the net profit: 200000 - 150000 - 10000 = 40000. The percentage of net profit to sales is then (Net Profit / Sales) * 100 = (40000 / 200000) * 100 = 20%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>45", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "#Sales                                                   200000Opening Stock                                      20000Purchases                                           140000Closing Stock                                       10000Expenses                                              10000  Bank                                                      10000Capital                                                    85000Creditors                                                35000Debtors                                                  50000Fixtures and fittings: cost                      10000Freehold land and building                     70000Drawings                                                10000  Acid test ratio is", "images": [], "options": {"A": "1.8 : 1", "B": "1.7 : 1", "C": "1.4 : 1", "D": "1.2 : 1"}, "answer": "B", "explanation": "The Acid Test Ratio is calculated by dividing Current Assets (excluding Inventory) by Current Liabilities. From the given data, Current Assets (excluding Inventory) are Debtors (50000) and Bank (10000), which sum up to 60000. Current Liabilities are Creditors (35000). So, the Acid Test Ratio is 60000/35000 = 1.71, which is approximately 1.7 : 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>46", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "#Sales                                                   200000Opening Stock                                      20000Purchases                                           140000Closing Stock                                       10000Expenses                                              10000  Bank                                                      10000Capital                                                    85000Creditors                                                35000Debtors                                                  50000Fixtures and fittings: cost                      10000Freehold land and building                     70000Drawings                                                10000  Gross profit is", "images": [], "options": {"A": "#70,000", "B": "#60,000", "C": "#50,000", "D": "#40,000"}, "answer": "C", "explanation": "Gross Profit is calculated by subtracting the cost of goods sold from the total sales. The cost of goods sold is calculated by adding the opening stock and purchases, and then subtracting the closing stock. From the given data, the cost of goods sold is Opening Stock (20000) + Purchases (140000) - Closing Stock (10000) = 150000. The total sales are 200000. So, the Gross Profit is 200000 - 150000 = 50000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2001>47", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The chief Accounting Officer of the federation is", "images": [], "options": {"A": "Minister of Finance", "B": "Auditor General", "C": "Accountant General", "D": "Chief Accountant"}, "answer": "C", "explanation": "The Chief Accounting Officer of the federation is the Accountant General. The Accountant General is responsible for the supervision over the receipt, custody and issue or payment of public moneys. The Minister of Finance is responsible for the overall financial management of the country, the Auditor General is responsible for auditing public accounts and the Chief Accountant is not a recognized position in the federation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>48", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "The expenditure on a good or services which is consumed either immediately or within a current accounting period is", "images": [], "options": {"A": "annual expenditure", "B": "budgetary expenditure", "C": "capital expenditure", "D": "recurrent expenditure"}, "answer": "D", "explanation": "The expenditure on a good or services which is consumed either immediately or within a current accounting period is a recurrent expenditure. Recurrent expenditures are often contrasted with capital expenditures, which are longer term investments. Annual expenditure refers to the total expenditure in a year, budgetary expenditure refers to the expenditure as planned in the budget, and capital expenditure refers to the expenditure on assets that have a useful life of more than one year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>49", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following serves as the main Government Fund used to service all operations of the government?", "images": [], "options": {"A": "General Fund", "B": "Consolidated Revenue Fund", "C": "Consolidated Reserve Fund", "D": "Special Fund"}, "answer": "B", "explanation": "The Consolidated Revenue Fund is the main government fund used to service all operations of the government. It is a fund into which all revenues collected by the government, except for those revenues that are legally directed into some other fund, are deposited. This fund is used to finance the day-to-day operations of the government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2001>50", "subject": "Accounts", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following serves as an input, storage and output device of a computer?", "images": [], "options": {"A": "Diskette", "B": "Keyboard", "C": "Monitor", "D": "Printer"}, "answer": "A", "explanation": "Diskette is an example of storage, input and output devices. A diskette is a random access, removable data storage medium that can used with personal computers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>1", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The accounting equation is", "images": [], "options": {"A": "Capital less Current Assets amounted to Liabilities", "B": "Assets less Liabilities amount to Capital", "C": "Fixed Assets and Current Liabilities amount to Capital", "D": "Capital and Assets amount to Liabilities"}, "answer": "B", "explanation": "The accounting equation is a fundamental principle in double-entry bookkeeping. It states that at any given time, a company's assets are financed by its liabilities and its owner's equity. In other words, the assets of a company (what it owns) are financed by the money it owes to others (liabilities) and the money its owners have invested in it (capital). Therefore, the correct equation is 'Assets less Liabilities amount to Capital'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>2", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A fixed amount of money set aside for petty expenses is", "images": [], "options": {"A": "imprest", "B": "float", "C": "receipt", "D": "fund"}, "answer": "B", "explanation": "Cash float is a money set aside or set up by giving a specified sum to the cashier in order to cover petty expenses during the period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>3", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Rent payable Account is an example of a", "images": [], "options": {"A": "nomimal account", "B": "real account", "C": "personal account", "D": "private account"}, "answer": "A", "explanation": "A nominal account is a general ledger account pertaining to all income, expenses, losses and gains. Rent payable is an expense for the business, hence it is a nominal account. A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year-end and are carried forward. A personal account is a general ledger account pertaining to individuals or organizations. A private account doesn't exist in accounting terminology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>4", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "The source document sent by the seller to the buyer when goods are returned is", "images": [], "options": {"A": "cedit note", "B": "purchase invoice", "C": "sales invoice", "D": "debit note"}, "answer": "A", "explanation": "A credit note or credit memo is a commercial document issued by a seller to a buyer. Credit notes act as a source document for the sales return journal. In other words, the credit note is evidence of the reduction in sales. A purchase invoice is sent by the seller to the buyer, detailing the items purchased and the amount owed. A sales invoice is a document sent by a provider of a product or service to the purchaser, requiring payment. A debit note is a document used by a vendor to inform the buyer of a unit or dollar amount being added to the buyer's ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>5", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Which of the following is not a liability?", "images": [], "options": {"A": "Accrued wages", "B": "Rent arrears", "C": "Prepayment", "D": "Insurance due but unpaid"}, "answer": "C", "explanation": "A liability is something a person or company owes, usually a sum of money. Accrued wages, rent arrears, and insurance due but unpaid are all liabilities because they are amounts that are owed. However, a prepayment is not a liability. A prepayment occurs when a buyer pays a seller for goods or services before they are received. It is considered an asset because it is a payment for a good or service that will be received in the future.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>6", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discount allowed is charged to", "images": [], "options": {"A": "Trading account", "B": "Balance sheet", "C": "Current Account", "D": "Profit and Loss account"}, "answer": "D", "explanation": "Discount allowed is an expense for the seller, as it reduces the amount of cash received from sales. Therefore, it is charged to the Profit and Loss account, which records all income and expenses for a business over a period of time. The Trading account is used to determine the gross profit or loss of a business, the Balance sheet provides a snapshot of a company's financial condition at a specific moment in time, and the Current Account records the net balance of a country's exports and imports of goods and services. None of these accounts would be appropriate for recording a discount allowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>7", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER", "question": "Which of the following belongs to the nominal ledger?", "images": [], "options": {"A": "Salaries account", "B": "Fixtures account", "C": "Stock account", "D": "Debtor's account"}, "answer": "A", "explanation": "The nominal ledger, also known as the general ledger, contains all the accounts for recording transactions relating to a company's assets, liabilities, owners' equity, revenue, and expenses. In this case, the 'Salaries account' is part of the nominal ledger as it records the expenses related to employee compensation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>8", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer questions 8 to 11                                                                            #Raw materials :   Stock 1/1/2000                              4500                             Purchases                                   30000                             Stock 31/12/2000                          6000Wages: direct                                                           34200              indirect                                                        10800Factory expenses: rent                                             18000                               insurance                                     3000Work-in-progress: 1/1/2000                                       3750                                31/12/2000                                  6750    What is the cost of raw materials consumed?", "images": [], "options": {"A": "#34,000", "B": "#31,500", "C": "#30,000", "D": "#28,500"}, "answer": "D", "explanation": "Cost of raw materials consumed = opening stock of raw materials + purchases of raw materials - closing stock of raw materials                                                             = 4,500 + 30,000 + 6,000                                                                = 28,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>9", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Raw materials :   Stock 1/1/2000                              4500                             Purchases                                   30000                             Stock 31/12/2000                          6000Wages: direct                                                           34200              indirect                                                        10800Factory expenses: rent                                             18000                               insurance                                     3000Work-in-progress: 1/1/2000                                       3750                                31/12/2000                                  6750The prime cost is", "images": [], "options": {"A": "#68,700", "B": "#65,700", "C": "#62,700", "D": "#58,200"}, "answer": "C", "explanation": "The prime cost is calculated as the sum of direct materials and direct labor. Direct materials is calculated as opening stock of raw materials plus purchases minus closing stock of raw materials (4500 + 30000 - 6000 = 28500). Direct labor is given as 34200. Therefore, the prime cost is 28500 + 34200 = 62700.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>10", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Raw materials :   Stock 1/1/2000                              4500                             Purchases                                   30000                             Stock 31/12/2000                          6000Wages: direct                                                           34200              indirect                                                        10800Factory expenses: rent                                             18000                               insurance                                     3000Work-in-progress: 1/1/2000                                       3750                                31/12/2000                                  6750The amount of factory overhead is", "images": [], "options": {"A": "#42,300", "B": "#31,800", "C": "#28,800", "D": "#21,000"}, "answer": "B", "explanation": "The amount of factory overhead is calculated as the sum of indirect labor and factory expenses. Indirect labor is given as 10800 and factory expenses (rent and insurance) sum up to 21000. Therefore, the factory overhead is 10800 + 21000 = 31800.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>11", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "#Raw materials :   Stock 1/1/2000                              4500                             Purchases                                   30000                             Stock 31/12/2000                          6000Wages: direct                                                           34200              indirect                                                        10800Factory expenses: rent                                             18000                               insurance                                     3000Work-in-progress: 1/1/2000                                       3750                                31/12/2000                                  6750The cost of goods manufactured is", "images": [], "options": {"A": "#101,250", "B": "#98,250", "C": "#94,500", "D": "#91,500"}, "answer": "D", "explanation": "Cost of goods manufactured/ cost of production = prime cost + factory overhead + opening W.I.P - closing W.I.P                                                                                    = 62,700 + 31,800 + 3,750 - 6750                                                                                          = 91,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>12", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following errors affects the Trial Balance?", "images": [], "options": {"A": "Commssion", "B": "Omission", "C": "Principle", "D": "Single entry"}, "answer": "D", "explanation": "The error that affects the Trial Balance is the 'Single entry' error. A Trial Balance is a statement of all debits and credits in a double-entry accounting system with the totals of debit and credit side equal. If a transaction is recorded only on one side (debit or credit), it is a 'Single entry' error and it will cause the totals of the Trial Balance to be unequal, hence affecting the Trial Balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>13", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Carriage inward expenses of a business is treated in", "images": [], "options": {"A": "trading account", "B": "balance sheet", "C": "appropriation account", "D": "profit and loss account"}, "answer": "A", "explanation": "Carriage inwards refers to the cost of transporting goods or raw materials into a business. It is treated as part of the cost of goods sold and therefore, it is recorded in the trading account. The trading account is a part of the final accounts prepared by a business to determine the gross profit or gross loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>14", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "A provision is", "images": [], "options": {"A": "an amount set out of profit for other uses", "B": "an amount of loss from trading activities", "C": "an expenses of business to be paid for in cash", "D": "a loss in value of all business assets"}, "answer": "A", "explanation": "A provision is an amount set aside from the profits of a business to cover a known or expected liability or loss. It is not an expense, but rather a deduction from the profit. Provisions are made in anticipation of potential future losses. For example, a business might make a provision for bad debts, which are debts that it does not expect to recover.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>15", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The term bad debts is used to describe", "images": [], "options": {"A": "a debt that cannot be recovered", "B": "a debt that is long over due", "C": "an over charge on a debtor's account", "D": "a debt owned by a former employee"}, "answer": "A", "explanation": "Bad debts refer to the amount that was receivable by a business but has not been paid and is now deemed to be irrecoverable. This usually happens when the debtor is unable to fulfill their obligation due to bankruptcy or other financial problems. Therefore, the term 'bad debts' is used to describe 'a debt that cannot be recovered'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>16", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES PAYABLE IN FULL ON APPLICATIONS", "question": "The double entry for refund of unsuccessful application money is debit", "images": [], "options": {"A": "Application for Shares Account, credit Bank Account", "B": "Bank Account, credit Application for Shares Account", "C": "Allotment Account, credit Bank Account", "D": "Cash Account, credit Bank Account"}, "answer": "A", "explanation": "An issue is said to be over subcribed if the number of shares applied for is greater than the number offered for sale. In such a situation, allotment would be made to the applicants on pro- rata basis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>17", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not an accounting concept?", "images": [], "options": {"A": "Entity", "B": "Going- concern", "C": "Accuracy", "D": "Historical cost"}, "answer": "C", "explanation": "Accuracy is not an accounting concept. The accounting concepts include: Periodicity, which refers to the idea that financial reports are prepared at regular intervals (usually annually); Consistency, which means that the same accounting methods should be used from one financial period to the next; and Objectivity, which means that financial information is based on evidence and can be verified by a third party. Accuracy, while important in accounting, is not a concept but rather a quality or characteristic of good accounting information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>18", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "An asset was bought on 1st January,1995 for #60,000?. Depreciation was provided for annually at 20% on cost. It was sold for #21,000 on 30th October 1998. Depreciation is charged fully in the year of disposal.    The net book value at the time of sale was", "images": [], "options": {"A": "#39,000", "B": "#16,000", "C": "#14,000", "D": "#12,000"}, "answer": "D", "explanation": "The net book value is calculated by subtracting the accumulated depreciation from the cost of the asset. In this case, the asset was bought for #60,000 and depreciation was provided annually at 20% on cost for 4 years (1995 to 1998). Therefore, the accumulated depreciation is #60,000 * 20% * 4 = #48,000. The net book value at the time of sale is #60,000 - #48,000 = #12,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>19", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "An asset was bought on 1st January,1995 for #60,000?. Depreciation was provided for annually at 20% on cost. It was sold for #21,000 on 30th October 1998. Depreciation is charged fully in the year of disposal.  Accumulated depreciation is", "images": [], "options": {"A": "#48,000", "B": "#39,000", "C": "#36,000", "D": "#21,000"}, "answer": "A", "explanation": "The asset was bought in 1995 and sold in 1998. This means it was used for 4 years. The depreciation rate is 20% on cost annually. Therefore, the accumulated depreciation is 20% of 60,000 for 4 years which equals to 48,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>20", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "An asset was bought on 1st January,1995 for #60,000?. Depreciation was provided for annually at 20% on cost. It was sold for #21,000 on 30th October 1998. Depreciation is charged fully in the year of disposal.  Profit on sale is", "images": [], "options": {"A": "#24,000", "B": "#21,000", "C": "#18,000", "D": "#9,000"}, "answer": "D", "explanation": "The profit on sale is calculated by subtracting the book value of the asset at the time of sale from the sale price. The book value is the cost of the asset minus the accumulated depreciation. Therefore, the book value is 60,000 - 48,000 = 12,000. The sale price is 21,000. Therefore, the profit on sale is 21,000 - 12,000 = 9,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>21", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The capital sum which represents the difference between the assets and liabilities of a society or club is", "images": [], "options": {"A": "working capital", "B": "accumulated fund", "C": "consolidated fund", "D": "reserve capital"}, "answer": "B", "explanation": "The capital sum which represents the difference between the assets and liabilities of a society or club is known as the accumulated fund. This is the fund that accumulates over time from the surplus of income over expenditure. It is not a working capital as this refers to the funds used in the day-to-day operations of a business. It is also not a consolidated fund as this is a term used in public finance to refer to the total of all revenues received by a government. Lastly, it is not a reserve capital as this is a part of the authorized capital of a company that has not been called up and is available for drawing in case of need.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>22", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "The total of the purchases day book is posted to the purchases account in the", "images": [], "options": {"A": "Purchase ledger", "B": "general ledger", "C": "private ledger", "D": "nominal ledger"}, "answer": "A", "explanation": "Total of purchase is posted on the debit side of purchase account. Purchase book is a subsidiary book or a sub-division or journal. Thus all the entries related to credit purchases of goods are first recorded in purchase book then the posting is made to the respective ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>23", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The document authorising an officer to incur expenditure is known as", "images": [], "options": {"A": "Virement", "B": "budget", "C": "warrant", "D": "vote"}, "answer": "C", "explanation": "A warrant is a document that authorizes an officer to incur expenditure. It is a financial instrument that gives the holder the right to buy the underlying security at a specific price, on or before a certain date. Virement is a process of transferring money from one budgetary account to another. A budget is a financial plan for a defined period, often one year. A vote is a formal expression of an individual's choice for or against some motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>24", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When shares are oversubscribed, the promoter may decide to scale down. When this is done, the shares are issued proportionately", "images": [], "options": {"A": "on pro- rata", "B": "at discount", "C": "at par", "D": "at premium"}, "answer": "A", "explanation": "When shares are oversubscribed, the promoter may decide to scale down. When this is done, the shares are issued proportionately on pro-rata. Pro-rata is a Latin term used to describe a proportionate allocation. It essentially translates to 'in proportion,' which means a process where whatever is being allocated will be distributed in equal portions. If something is given out to people on a pro-rata basis, it means dividing an amount according to the proportion that those people have in the whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>25", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PURCHASES OF BUSINESS : INTRODUCTION AND ADVANTAGES", "question": "The amount for which a business is sold is", "images": [], "options": {"A": "purchase consideration", "B": "premium", "C": "capital reserve", "D": "goodwill"}, "answer": "A", "explanation": "The amount for which a business is sold is known as the purchase consideration. This is the total value that is agreed upon by both the buyer and the seller for the sale or transfer of ownership of the business. It can be in the form of cash, shares, assets, or a combination of these.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>26", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Into how many types can general purpose computers be classified?", "images": [], "options": {"A": "Three", "B": "Four", "C": "Five", "D": "Six"}, "answer": "B", "explanation": "General purpose computers can be classified into four types: Microcomputers, Minicomputers, Mainframe computers, and Supercomputers. Microcomputers are personal computers that are small and inexpensive. Minicomputers are larger than microcomputers and have higher processing speed. Mainframe computers are large computers capable of handling and processing very large amounts of data quickly. Supercomputers are the fastest and most expensive computers, used for specialized applications that require immense amounts of mathematical calculations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>27", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer questions 27 to 30#Land and buildings                                                           20000Stock                                                                                 5000Cash in hand                                                                     1000Profit and loss b/f                                                            14000Rent owing                                                                           400Creditors                                                                          11000Furniture and Fittings                                                         7500Motor vehicle                                                                   12500Debtors                                                                            13750Bank overdraft                                                                   8750    The value of current liabilities is", "images": [], "options": {"A": "#32,750", "B": "#20,150", "C": "#19,750", "D": "#11,000"}, "answer": "B", "explanation": "Current liabilities = 400 + 11,000 + 8,750                               = 20,150", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>28", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "#Land and buildings                                                           20000Stock                                                                                 5000Cash in hand                                                                     1000Profit and loss b/f                                                            14000Rent owing                                                                           400Creditors                                                                          11000Furniture and Fittings                                                         7500Motor vehicle                                                                   12500Debtors                                                                            13750Bank overdraft                                                                   8750The value of current assets is", "images": [], "options": {"A": "#28,500", "B": "#20,150", "C": "#19,750", "D": "#17,000"}, "answer": "C", "explanation": "The value of current assets is calculated by adding 'Stock', 'Cash in hand' and 'Debtors' which gives 19750. This matches with option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>29", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "#Land and buildings                                                           20000Stock                                                                                 5000Cash in hand                                                                     1000Profit and loss b/f                                                            14000Rent owing                                                                           400Creditors                                                                          11000Furniture and Fittings                                                         7500Motor vehicle                                                                   12500Debtors                                                                            13750Bank overdraft                                                                   8750The opening capital is", "images": [], "options": {"A": "#32,000", "B": "#26,000", "C": "#39,600", "D": "#14,000"}, "answer": "C", "explanation": "Capital =Asset( fixed asset + current asset) - Liabilities                       = 40,000 + 19,750 - 20150                             = 39,600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>30", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "#Land and buildings                                                           20000Stock                                                                                 5000Cash in hand                                                                     1000Profit and loss b/f                                                            14000Rent owing                                                                           400Creditors                                                                          11000Furniture and Fittings                                                         7500Motor vehicle                                                                   12500Debtors                                                                            13750Bank overdraft                                                                   8750The value of fixed assets is", "images": [], "options": {"A": "#57,300", "B": "#47,500", "C": "#40,000", "D": "#37,500"}, "answer": "C", "explanation": "The value of fixed assets is calculated by adding the value of all the fixed assets. From the given data, the fixed assets are Land and buildings (20000), Furniture and Fittings (7500), Motor vehicle (12500). So, the value of fixed assets is 20000+7500+12500 = 40000. The correct option that matches this answer is option C.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>31", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The financial plan of the govenment for the year is contained in the", "images": [], "options": {"A": "analysis book", "B": "gazatte", "C": "budget", "D": "vote"}, "answer": "C", "explanation": "The financial plan of the government for the year is contained in the budget. A budget is a financial plan for a defined period, often one year. It may also include planned sales volumes and revenues, resource quantities, costs and expenses, assets, liabilities and cash flows.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>32", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "The price paid for the purchase of a business is", "images": [], "options": {"A": "Credited to Cash Account and debited to Vendor's Account", "B": "debited to cash Account and credited to vendor's account", "C": "debited to Business Purchase Account and credited to Asset Account", "D": "credited to Cash Account and debited to Asset Account"}, "answer": "B", "explanation": "The price paid for the purchase of a business is debited to Cash Account and credited to Vendor's Account. This is because when a business is purchased, cash is paid out (hence a debit to the cash account) and the vendor (the person or entity selling the business) is owed money (hence a credit to the vendor's account).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>33", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "A deduction from the sales price of goods that is allowed if payment is made within a specified period of time is", "images": [], "options": {"A": "trade discount", "B": "cash discount", "C": "quantity discount", "D": "rebate"}, "answer": "B", "explanation": "A cash discount is a deduction from the sales price of goods that is allowed if payment is made within a specified period of time. It is a strategy used by sellers to encourage buyers to pay earlier, thereby improving the seller's cash flow. Trade discount is a reduction in the listed price of an item when it's sold for resale. Quantity discount is a reduction in price given to a buyer based on the quantity purchased. Rebate is a partial refund to someone who has paid too much money for tax, rent, or a utility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>34", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A trader paid #15,000 on rent for 15 months but charged #12,000 to the profit and loss account for the year. This is the concept of", "images": [], "options": {"A": "accrual", "B": "materiality", "C": "prudence", "D": "going- concern"}, "answer": "A", "explanation": "The concept described in the question is the accrual concept. According to the accrual concept of accounting, transactions are recorded in the books of accounts at the time when they occur, not when the cash is received or paid. In this case, the trader paid for 15 months of rent but only charged 12 months to the profit and loss account for the year, indicating that the remaining 3 months of rent will be accounted for in the next accounting period. Materiality concept states that all significant items must be reported in the financial statements. Prudence concept suggests that the income should not be anticipated, but all losses should be provided for. Going-concern concept assumes that a business entity will continue to operate indefinitely.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>35", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Partner's interest on capital is shown in the", "images": [], "options": {"A": "Profit and loss Account", "B": "Partners Fixed Account", "C": "Profit and loss Appropriation Account", "D": "Trading Account"}, "answer": "C", "explanation": "The partner's interest on capital is shown in the Profit and Loss Appropriation Account. This account is used to distribute the net profit among the partners in their agreed profit sharing ratio. It includes all adjustments related to partners like interest on capital, interest on drawings, salary, commission etc. Therefore, the interest on capital is shown in this account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>36", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions 36 to 39Baba and Tunde are partners sharing profits and losses equally. Extracts from their books showed                                                                                                        Baba                                              Tunde                                                                                                        #                                                     #Capital Accounts 1 January 2,000                                           40000                                         50000Current Accounts 1 January 2,000                                        20000Cr                                     15000CrDrawings during the year                                                                4000                                          5000Salaries                                                                                           5000                                         5000    Interest on capital is 10%. The net profit for the year is #40,000.    The interest on Tunde's capital is", "images": [], "options": {"A": "#10,000", "B": "#5,000", "C": "#4,000", "D": "#1,500"}, "answer": "B", "explanation": "Interest on capital is calculated as a percentage of the capital invested by the partner. In this case, Tunde's capital is #50,000 and the interest rate is 10%. Therefore, the interest on Tunde's capital is 10% of #50,000 which equals #5,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2002>37", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Baba and Tunde are partners sharing profits and losses equally. Extracts from their books showed                                                                                                        Baba                                              Tunde                                                                                                        #                                                     #Capital Accounts 1 January 2,000                                           40000                                         50000Current Accounts 1 January 2,000                                        20000Cr                                     15000CrDrawings during the year                                                                4000                                          5000Salaries                                                                                           5000                                         5000    Interest on capital is 10%. The net profit for the year is #40,000.  The share of profit of each partner is", "images": [], "options": {"A": "#20,000", "B": "#10,500", "C": "#5,000", "D": "#4,000"}, "answer": "B", "explanation": "# #                                       Salaries: Baba                            5000           Net profit  40000                                                                           Tunde                          5000  Interest on capital : 10%Baba  (10% x 40000)               4000Tunde (10% x 50000 )              5000                                Share of profit :Baba (1/2 x 21000)                      10500Tunde (1/2 x 21000)                      10500                                                         40000                                           40000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>38", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Baba and Tunde are partners sharing profits and losses equally. Extracts from their books showed                                                                                                        Baba                                              Tunde                                                                                                        #                                                     #Capital Accounts 1 January 2,000                                           40000                                         50000Current Accounts 1 January 2,000                                        20000Cr                                     15000CrDrawings during the year                                                                4000                                          5000Salaries                                                                                           5000                                         5000    Interest on capital is 10%. The net profit for the year is #40,000.  Tunde's Current Account balance on 31st December, 2000 is", "images": [], "options": {"A": "#30,500", "B": "#25,500", "C": "#25,000", "D": "#10,000"}, "answer": "A", "explanation": "Tunde's current account = Current account balance + interest on capital+salary+share of profit - Drawings                                            =  15,000 + 5,000 + 5,000 + 10,500 - (5,000)                                              = 30,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>39", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Baba and Tunde are partners sharing profits and losses equally. Extracts from their books showed                                                                                                        Baba                                              Tunde                                                                                                        #                                                     #Capital Accounts 1 January 2,000                                           40000                                         50000Current Accounts 1 January 2,000                                        20000Cr                                     15000CrDrawings during the year                                                                4000                                          5000Salaries                                                                                           5000                                         5000    Interest on capital is 10%. The net profit for the year is #40,000.  Baba's Current Account balance on 31st December, 2000 is", "images": [], "options": {"A": "#35,500", "B": "#25,000", "C": "#21,000", "D": "#20,000"}, "answer": "A", "explanation": "Baba's current account = Current account balance + interest on capital+salary+share of profit - Drawings                                          = 20,000 + 4,000 + 5,000 + 10,500 - 4,000                                             =  39,500 - 4000                                               = 35,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>40", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Depreciation is", "images": [], "options": {"A": "cost of repairs incurred on a fixed  asset", "B": "a charge for the wear and tear of fixed assets", "C": "the cost incurred on replacing a fixed asset", "D": "provision for loss of fixed asset"}, "answer": "B", "explanation": "Depreciation is a method of allocating the cost of a tangible asset over its useful life. It is a charge for the wear and tear of fixed assets. Businesses depreciate long-term assets for both tax and accounting purposes. It is not a provision for loss, cost of repairs or cost of replacing the asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>41", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Cash discount received is shown in the i. cash book ii. Discount Received Account ii. Suppliers' Account", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I , II and III"}, "answer": "D", "explanation": "cash discount received can be shown in Cash book ,Discount Received Account and Suppliers' Account", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>42", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not an input device?", "images": [], "options": {"A": "Diskette", "B": "Card", "C": "Keyboard", "D": "Printer"}, "answer": "D", "explanation": "An input device is a piece of hardware used to provide data and control signals to an information processing system such as a computer or information appliance. Examples of input devices include keyboards, mouse, scanners, digital cameras, joysticks, and microphones. A printer is not an input device, it is an output device because it outputs data from the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>43", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer questions 43 to 45A trader paid insurance premium of #45,000 for 15 months ended 31st March,2000. He prepares account to 31 December.    How much is charged to profit and loss account for the year 2000?", "images": [], "options": {"A": "#45,000", "B": "#42,000", "C": "#36,000", "D": "#33,000"}, "answer": "C", "explanation": "The insurance premium of #45,000 covers 15 months, so the monthly cost is #45,000 / 15 = #3,000. The year 2000 includes 12 months, so the cost charged to the profit and loss account for the year 2000 is 12 * #3,000 = #36,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>44", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A trader paid insurance premium of #45,000 for 15 months ended 31st March,2000. He prepares account to 31 December.  How much is carried in the Balance sheet at 31st December, 2000?", "images": [], "options": {"A": "#45,000", "B": "#12,000", "C": "#9,000", "D": "#4,500"}, "answer": "C", "explanation": "The insurance premium of #45,000 covers 15 months, so the monthly cost is #45,000 / 15 = #3,000. The insurance premium has been paid up to the end of March 2000, so there are 3 months (January, February, March) of the premium that will be carried in the balance sheet at 31st December, 2000. This is 3 * #3,000 = #9,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>45", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A trader paid insurance premium of #45,000 for 15 months ended 31st March,2000. He prepares account to 31 December.  The amount carried in the Balance sheet is classified as", "images": [], "options": {"A": "current asset", "B": "current liability", "C": "capital", "D": "long- term liability"}, "answer": "A", "explanation": "The insurance premium paid for 15 months ended 31st March, 2000 is a prepayment, which is an amount paid for a service or benefit that the business will receive in the future. Since the trader prepares account to 31 December, the insurance premium for the period from 1st January to 31st March, 2000 has not been utilized yet and is therefore a prepayment. Prepayments are classified as current assets in the balance sheet because they represent future economic benefits that are expected to be realized within the next accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>46", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The total amount of money set aside for a particular purpose by government is", "images": [], "options": {"A": "fund", "B": "vote", "C": "virement", "D": "budget"}, "answer": "B", "explanation": "This term refers specifically to the amount of money that is approved and allocated by the legislature for a particular purpose within the budget. It signifies the authorization given by the legislative body to spend a certain amount of money.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2002>47", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "\"Accountants do not count chickens before they are hatched\". This is the concept of", "images": [], "options": {"A": "accrual", "B": "materiality", "C": "realisation", "D": "going-concern"}, "answer": "C", "explanation": "The phrase 'Accountants do not count chickens before they are hatched' refers to the concept of realisation. In accounting, the realisation concept states that revenue and profits are recognised when they are realised or earned, and not when they are received. This means that accountants do not record income until the goods are delivered or the services are provided, i.e., until the income is 'realised'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>48", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscriptions in arrears is treated in the balance sheet of a club as", "images": [], "options": {"A": "current liability", "B": "intangible asset", "C": "fictitious asset", "D": "current asset"}, "answer": "D", "explanation": "Subscription in arrears is the sum of money due form members for a particular year but which has been paid for the year. It is treated as a current asset in the balance sheet of a non profit making organisation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>49", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A suspense account is used to", "images": [], "options": {"A": "record sales", "B": "agree the trial balance", "C": "record purchase", "D": "prepare the balance sheet"}, "answer": "B", "explanation": "A suspense account is a temporary account used when an aspect of a transaction is unclear. It is used to agree the trial balance when there are discrepancies. The suspense account holds the difference until the error is discovered and corrected. Therefore, the correct answer is 'agree the trial balance'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2002>50", "subject": "Accounts", "year": "2002", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following belongs to the sales ledger?", "images": [], "options": {"A": "Motor Van Disposal Account", "B": "Bank Account", "C": "Debtors Account", "D": "Rent and Rates Account"}, "answer": "C", "explanation": "The sales ledger is a record of a company's sales, it includes individual accounts for each customer. A Debtors Account is part of the sales ledger as it records the money owed to the company by its customers. Therefore, the correct answer is 'Debtors Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>1", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES", "question": "The transformation of pieces of information into a more useful format is", "images": [], "options": {"A": "data processing", "B": "information processing", "C": "computerization", "D": "system analysis"}, "answer": "A", "explanation": "Data processing refers to the transformation of raw data into a meaningful output. It involves the collection, manipulation, and processing of data to generate information that can be used for decision making. Information processing, on the other hand, is a broader term that includes data processing as a subset. Computerization and system analysis are related to data processing but they are not the process of transforming pieces of information into a more useful format.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>2", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The document which advertises the sale of shares of a company is a/an", "images": [], "options": {"A": "prospectus", "B": "debenture", "C": "statement", "D": "invoice"}, "answer": "A", "explanation": "A prospectus is a legal document issued by companies that are offering securities for sale. It contains details about the company, its operations, and financial statements. It is used to provide potential investors with detailed information about a company's business operations and financial condition. A debenture is a type of debt instrument, a statement is a general term that could refer to various types of documents, and an invoice is a document issued by a seller to a buyer, indicating the products, quantities, and agreed prices for products or services the seller has provided the buyer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>3", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not an externally visible part of a computer?", "images": [], "options": {"A": "Central Processing Unit", "B": "Microchip", "C": "Monitor", "D": "Keyboard"}, "answer": "A", "explanation": "The Central Processing Unit (CPU) is not an externally visible part of a computer. It is the primary component of a computer that performs most of the processing inside the computer. It's often referred to as the 'brain' of the computer. It is located inside the computer case and is not visible from outside.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>4", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Which of the following is the responsibility of a local government?", "images": [], "options": {"A": "Constructing market stalls", "B": "Raising income tax", "C": "Developing highways and tolling them", "D": "Developing major ports for tax purposes"}, "answer": "A", "explanation": "Local governments are responsible for the administration of their local area. This includes the construction of local infrastructure such as market stalls. Raising income tax is a responsibility of the central government, not local government. Developing highways and tolling them, and developing major ports for tax purposes are also typically responsibilities of higher levels of government, not local government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>5", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "The procedure for utilising the savings from one sub-head of expenditure to pay for another under the same head is", "images": [], "options": {"A": "apportionment", "B": "virement", "C": "appropriation", "D": "allocation"}, "answer": "B", "explanation": "The procedure for utilising the savings from one sub-head of expenditure to pay for another under the same head is known as virement. Virement is a process that allows for the transfer of amounts from one account to another within the same budget category. This is often used in budget management to ensure that funds are used where they are most needed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>6", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "Patent and trade marks are classified under", "images": [], "options": {"A": "intangible assets", "B": "current assets", "C": "fixed assets", "D": "wasting assets"}, "answer": "A", "explanation": "Patents and trademarks are classified under intangible assets. Intangible assets are non-physical assets that have a monetary value since they represent potential revenue. Patents and trademarks are examples of intangible assets because they can provide a competitive advantage for a company and potentially generate revenue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>7", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer this question  Net profit for the year  Ordinary share capital of 50 kobo each  10% Preference shares of 50 kobo eachN75,000  N65,000  N100,000    The amount available as dividend to ordinary shareholders is", "images": [], "options": {"A": "N75,000", "B": "N65,000", "C": "N55,000", "D": "N52,500"}, "answer": "B", "explanation": "The amount available as dividend to ordinary shareholders is calculated by subtracting the preference dividend from the net profit. The preference dividend is calculated as 10% of the preference share capital, which is N100,000. Therefore, the preference dividend is N10,000. Subtracting this from the net profit of N75,000 gives N65,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>8", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer this question  Net profit for the year  Ordinary share capital of 50 kobo each  10% Preference shares of 50 kobo eachN75,000  N65,000  N100,000  Preference dividend for the year is", "images": [], "options": {"A": "N20,000", "B": "N10,500", "C": "N10,000", "D": "N7,500"}, "answer": "C", "explanation": "The preference dividend for the year is calculated as 10% of the preference share capital, which is N100,000. Therefore, the preference dividend is N10,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>9", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer this question  Net profit for the year  Ordinary share capital of 50 kobo each  10% Preference shares of 50 kobo eachN75,000  N65,000  N100,000  Dividend per ordinary share is", "images": [], "options": {"A": "N1.00", "B": "N0.50", "C": "N0.45", "D": "N0.40"}, "answer": "B", "explanation": "Dividend per ordinary shareholder is the price of ordinary share which is 80k to N0.50.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>10", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "The transfer of goods between departments is recorded by debiting", "images": [], "options": {"A": "the receiving department and crediting the giving department", "B": "the giving department and crediting the receiving department", "C": "stock account and crediting trading account", "D": "trading account and crediting purchases account"}, "answer": "A", "explanation": "When goods are transferred between departments, the receiving department is debited because it is receiving an asset (the goods), and the giving department is credited because it is giving up an asset. This is in line with the double-entry bookkeeping principle, which states that for every debit entry, there must be a corresponding credit entry. Therefore, the correct option is 'the receiving department and crediting the giving department'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>11", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Which of the following is the basis for apportioning rent among departments?", "images": [], "options": {"A": "Sales", "B": "Floor area", "C": "Number of employees", "D": "Direct labour cost"}, "answer": "B", "explanation": "Rent is usually apportioned among departments based on the floor area each department occupies. This is because the cost of rent is directly related to the amount of space used. Therefore, departments that occupy more space should bear a larger portion of the rent cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>12", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "Which of the following brings a company into legal existence?", "images": [], "options": {"A": "Certificate of Incorporation", "B": "Memorandum of Association", "C": "Articles of Association", "D": "Company Law"}, "answer": "A", "explanation": "A company comes into legal existence when it is incorporated. The Certificate of Incorporation is a legal document that is issued by the government upon the registration of a company. It confirms the company's existence and shows the company has complied with the necessary legal requirements to start a business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>13", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following documents sets out the internal regulations of a partnership?", "images": [], "options": {"A": "Law", "B": "Deed", "C": "Regulation", "D": "Code"}, "answer": "B", "explanation": "The internal regulations of a partnership are set out in a document known as the partnership deed. This document outlines the rights, responsibilities, and obligations of each partner. It includes information such as the name of the partnership, the purpose of the partnership, the duration of the partnership, and how profits and losses will be shared among the partners.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>14", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  ₦Capital Accounts: Ojo  Aina  Drawings: Ojo  Aina40,000  20,000  10,000  6,000  Interest on capital - 5%  Interest on drawings - 10%  Net profit for the year - ₦30,000    Profit sharing ratio - Ojo 2/3 , Aina 1/3    The divisible profit for the year is", "images": [], "options": {"A": "₦31,600", "B": "₦31,400", "C": "₦904,000", "D": "₦28,600"}, "answer": "D", "explanation": "Dr &nbsp &nbsp &nbsp &nbsp Profit or loss appropriation account &nbsp &nbsp &nbsp Cr  ₦₦Interest on Capital:  Ojo (5/100 × 40,000)  Aina (5/100 × 20,000)  2,000  1,000Net profit b/f  Interest on drawings:  Ojo (5/100 × 10,000)  Aina (5/100 × 6,000)30,000    1,000  600Share of profit  Ojo (2/3 × 28,600)   Aina (1/3 × 28,600)  19067  9533            31,60031,600    The divisible profit = (30,000 + 1,000 + 600) - (2000 + 1000)  ⇒ 31,600 - 3,000 = ₦28,600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>15", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  ₦Capital Accounts: Ojo  Aina  Drawings: Ojo  Aina40,000  20,000  10,000  6,000  Interest on capital - 5%  Interest on drawings - 10%  Net profit for the year - ₦30,000    Profit sharing ratio - Ojo 2/3 , Aina 1/3   Ojo's share of profit is", "images": [], "options": {"A": "₦21,067", "B": "₦20,933", "C": "₦20,000", "D": "₦19,067"}, "answer": "D", "explanation": "Ojo's share of profit = 2/3 × 28,600  ⇒ 19,067", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>16", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  ₦Capital Accounts: Ojo  Aina  Drawings: Ojo  Aina40,000  20,000  10,000  6,000  Interest on capital - 5%  Interest on drawings - 10%  Net profit for the year - ₦30,000    Profit sharing ratio - Ojo 2/3 , Aina 1/3   Aina's Current Account balance is", "images": [], "options": {"A": "₦9,933", "B": "₦9,533", "C": "₦6,600", "D": "₦3,933"}, "answer": "D", "explanation": "Current Account  RetailsOjoAinaDetailsOjoAina  Drawings   Interest on drawings  balance c/d₦  10,000  1,000  10,067₦  6,000  600  3,933Interest on Capital  Share of profit  ₦  2,000  19,067    ₦  1,000  9,533    21,06710,53321,06710,533balance b/d10,0673933", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>17", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept that supports the application of double entry book-keeping is the", "images": [], "options": {"A": "going concern concept", "B": "dual aspect concept", "C": "historical cost concept", "D": "consistency concept"}, "answer": "B", "explanation": "The dual aspect concept is the foundation of the double-entry bookkeeping system. The concept states that every financial transaction has two sides - a debit and a credit, and both sides must be recorded. This is what makes it possible to keep the accounting equation (Assets = Liabilities + Equity) in balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>18", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is a limitation of the money measurement concept?", "images": [], "options": {"A": "Efficient management is not disclosed", "B": "There is no basis for comparison", "C": "Inter-period comparison is impossible", "D": "It does not allow choice of methods"}, "answer": "A", "explanation": "The money measurement concept in accounting means that only transactions and events that are capable of being measured in monetary terms are recognized in the financial statements. One of its limitations is that it does not disclose the efficiency of management. This is because many aspects of management's performance, such as leadership ability, employee morale, and customer satisfaction, cannot be easily quantified in monetary terms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>19", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "The account that shows both the cash and bank transactions of an enterprise is", "images": [], "options": {"A": "Appropriation Account", "B": "Trading Account", "C": "Profit and Loss Account", "D": "Cash Book"}, "answer": "D", "explanation": "The Cash Book is a type of ledger that records all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger. Therefore, it shows both the cash and bank transactions of an enterprise.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>20", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "A control account is", "images": [], "options": {"A": "an imprest system", "B": "a statement of affairs", "C": "a bank reconciliation statement", "D": "a self balancing ledger system"}, "answer": "D", "explanation": "A control account, also known as a summary account, is an account in the general ledger for which a corresponding subsidiary ledger has been created. The purpose of the control account is to keep the general ledger free of details, but still provide the balance for the financial statements. In other words, it's a part of a self-balancing ledger system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>21", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "In a not-for-profit making organization, the cash book is summarised in the form of", "images": [], "options": {"A": "Balance Sheet", "B": "Income and Expenditure Account", "C": "Receipts and Expenditure Account", "D": "Receipts and Payments Account"}, "answer": "D", "explanation": "In a not-for-profit making organization, the cash book is summarised in the form of a Receipts and Payments Account. This account is a summary of all cash transactions, including receipts and payments, that have occurred over a certain period. It is similar to a cash flow statement in a for-profit organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>22", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Which of the following is found in a Receipts and Payments Account?", "images": [], "options": {"A": "Accruals", "B": "Prepayments", "C": "Depreciation of fixed assets", "D": "Purchase of fixed assets"}, "answer": "D", "explanation": "A Receipts and Payments Account includes the purchase of fixed assets. This account records all cash receipts and payments, including those related to fixed assets. Accruals, prepayments, and depreciation of fixed assets are not included because these are non-cash items.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>23", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question  ₦Club house   Furniture  Sports kit  Subscriptions prepaid  Bar creditors   Subscriptions owing375,000  250,000  400,000  10,000  156,000  45,000    What is the club's Accumulated Fund?", "images": [], "options": {"A": "₦824,000", "B": "₦914,000", "C": "₦904,000", "D": "₦834,000"}, "answer": "C", "explanation": "Statements of Affairs  ₦Assets₦Accumulated fund  Liabilities  Bar creditors   Subscription prepaid904,000    156,000  10,000  Club house   Furniture  Sport kits   Subscription owing375,000  250,000  400,000  45,0001,070,0001,070,000    NOTE: Accumulated fund = Total Assets - Total liabilities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>24", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following items is found on the credit side of a Sales Ledger Control Account?", "images": [], "options": {"A": "Credit sales", "B": "Debtors cheques dishonoured", "C": "Interest on overdue account", "D": "Bad debts written off"}, "answer": "D", "explanation": "Bad debts written off is found at the credit side of sales ledger control account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>25", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not a credit item in the Sales Ledger Control Account?", "images": [], "options": {"A": "Cash received", "B": "Discount allowed", "C": "Dishonoured cheque", "D": "Returns inward"}, "answer": "C", "explanation": "Dishonoured cheque is not found at the credit side of sales ledger control account.    Dr &nbsp &nbsp &nbsp Format of Sales Ledger Control A/c &nbsp &nbsp &nbsp Cr  bal. b/f  credit sales  dishonoured cheque  cash/bank refund  Int. charges in overdue accounts  bal. c/d        xx  xx  xx  xx  xx  xx         bal. b/f  cash/bank from customers  Discount allowed  Sales returns   Bad debts  Set off  Bill of exchange  Bill receivable  bal. c/dxx  xx  xx  xx  xx  xx  xx  xx  xxxxxxbal. b/dxxbal. b/dxx", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>26", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this question  1st Jan31st Dec₦₦Creditors  Stocks4,200  3,6005,200  3,200  Cash paid to creditors during the year was ₦18,000    Purchases for the year was", "images": [], "options": {"A": "₦19,400", "B": "₦19,000", "C": "₦18,000", "D": "₦17,000"}, "answer": "B", "explanation": "Dr &nbsp &nbsp &nbsp Creditors Control A/c &nbsp &nbsp Cr  ₦₦Cash paid  bal. c/d18,000  5,200bal. b/f  purchases4,200  19,00023,20023,200bal. b/d5,200", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>27", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this question  1st Jan31st Dec₦₦Creditors  Stocks4,200  3,6005,200  3,200  Cash paid to creditors during the year was ₦18,000  Cost of sales for the year was", "images": [], "options": {"A": "₦19,800", "B": "₦19,400", "C": "₦18,400", "D": "₦17,400"}, "answer": "B", "explanation": "Cost of sales = Opening stock + Purchases - Closing stock  ⇒ (3,600 + 19,000) - 3,200  ⇒ 22,600 - 3,200  ⇒ ₦19,400", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2003>28", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The cost of raw materials consumed is determined in the Manufacturing Account as", "images": [], "options": {"A": "opening stock plus purchases less closing stock", "B": "purchases plus closing stock less opening stock", "C": "cost of materials available plus closing stock", "D": "cost of materials available less opening stock"}, "answer": "A", "explanation": "The cost of raw materials consumed is determined in the Manufacturing Account as opening stock plus purchases less closing stock. This is because the opening stock and purchases represent the total materials available for use during the period, and the closing stock represents the materials not used, which should be subtracted from the total materials available to get the cost of materials consumed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>29", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is an item of prime cost?", "images": [], "options": {"A": "Royalties payable", "B": "Factory salaries", "C": "Depreciation of plant", "D": "Rent of factory building"}, "answer": "A", "explanation": "Prime cost include: Royalty payable, Direct wages and direct expenses, direct materials, excise duty etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>30", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Opening creditors was ₦65,000 closing creditors was ₦41,000. Credit purchases was ₦200,000 and discount received ₦3,000. How much was paid to creditors?", "images": [], "options": {"A": "₦262,000", "B": "₦224,000", "C": "₦221,000", "D": "₦176,000"}, "answer": "C", "explanation": "The amount paid to creditors is calculated by starting with the opening creditors, adding the credit purchases, subtracting the closing creditors and the discount received. Therefore, the calculation is as follows: 65000 + 200000 - 41000 - 3000 = 221000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>31", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The opening balance of debtors is ₦100,000 and that of provision for doubtful debts is ₦1,000. If provision is to be at 2 1/2 of debtors, how much would be charged in the Profit and Loss Account?", "images": [], "options": {"A": "₦3,500", "B": "₦2,500", "C": "₦1,500", "D": "₦1,000"}, "answer": "C", "explanation": "The provision for doubtful debts is calculated as 2% of the debtors' balance. In this case, it would be 2% of ₦100,000, which equals ₦2,000. The opening balance of the provision for doubtful debts is ₦1,000. Therefore, the amount to be charged in the Profit and Loss Account is the difference between the calculated provision and the opening balance, which is ₦2,000 - ₦1,000 = ₦1,000. However, none of the options matches this answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>32", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Rent owing by a business is shown in the", "images": [], "options": {"A": "Trading Account", "B": "Trial balance", "C": "Balance Sheet", "D": "Cash Book"}, "answer": "C", "explanation": "Rent owing by a business is a liability and therefore it is shown in the Balance Sheet. The Balance Sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time. It provides a basis for computing rates of return and evaluating its capital structure. It is a financial statement that provides a snapshot of what a company owns and owes, as well as the amount invested by shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>33", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer this question  ₦Opening Stock 40,000Purchases  130,000Closing stocks 32,000Sales180,000    What was the cost of goods sold?", "images": [], "options": {"A": "₦170,000", "B": "₦138,000", "C": "₦130,000", "D": "₦122,000"}, "answer": "B", "explanation": "The cost of goods sold (COGS) is calculated by adding the opening stock and purchases, then subtracting the closing stock. So, COGS = Opening Stock + Purchases - Closing Stock = ₦40,000 + ₦130,000 - ₦32,000 = ₦138,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>34", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question  ₦Opening Stock 40,000Purchases  130,000Closing stocks 32,000Sales180,000  What was the gross profit?", "images": [], "options": {"A": "₦58,000", "B": "₦50,000", "C": "₦42,000", "D": "₦10,000"}, "answer": "C", "explanation": "The gross profit is calculated by subtracting the cost of goods sold from the sales. So, Gross Profit = Sales - COGS = ₦180,000 - ₦138,000 = ₦42,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>35", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Which of the following source documents is used for recording goods returned to suppliers?", "images": [], "options": {"A": "Invoice", "B": "Waybill", "C": "Debit note", "D": "Credit note"}, "answer": "D", "explanation": "A Credit Note is a document sent by a seller to its buyer, or, in other words, a vendor to the customer, notifying that a credit has been provided to their account. The credit note is used in case of goods returned to suppliers, indicating that the buyer is not required to pay the full original amount of the invoice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>36", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "In which of the following is purchase of fixed assets on credit first recorded?", "images": [], "options": {"A": "Purchases Journal", "B": "Journal Proper", "C": "Cash Book", "D": "General Ledger"}, "answer": "B", "explanation": "The Journal Proper is a book of original entry (like a diary) where transactions that do not fit into any other specific journal are recorded. The purchase of fixed assets on credit is first recorded in the Journal Proper before being posted to the ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>37", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "In which ledger is the account of Yao, a debtor found?", "images": [], "options": {"A": "Nominal ledger", "B": "Purchases ledger", "C": "General ledger", "D": "Sales ledger"}, "answer": "D", "explanation": "The account of Yao, a debtor, would be found in the Sales Ledger. This is because the Sales Ledger is where a business keeps a record of its customers (debtors) and their transactions. The Nominal Ledger is used for company's own accounts, the Purchases Ledger is for suppliers (creditors), and the General Ledger is a collection of all the individual financial transactions that a company makes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>38", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Use the following information to answer this question  A fixed asset was bought for ₦60,000 on 1st January, 1997. Depreciation was provided at 10% on cost. It was sold for ₦16,000 on 30th June, 2001.    The profit or loss on sale was", "images": [], "options": {"A": "₦17,000 profit", "B": "₦17,000 loss", "C": "₦16,000 profit", "D": "₦16,000 loss"}, "answer": "B", "explanation": "Calculationofdepreciation=10100×60,000 = ₦6,000        depreciationattheyearofdisposal=612×10100×60,000=3000  Asset disposal A/c  ₦₦Cost     60,000     provision for depreciation  cash realised from sales of assets  loss on sales27,000  16,000  17,00060,000 60,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>39", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Use the following information to answer this question  A fixed asset was bought for ₦60,000 on 1st January, 1997. Depreciation was provided at 10% on cost. It was sold for ₦16,000 on 30th June, 2001.  The net book value at the time of sale was", "images": [], "options": {"A": "₦33,000", "B": "₦30,000", "C": "₦17,000", "D": "₦16,000"}, "answer": "A", "explanation": "Netbook value at the time of sales = cost - Accumulated depreciation at the time of sales   ⇒ 60,000 - 27,000  Netbook value = ₦33,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>40", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following errors would affect the agreement of the trial balance totals?", "images": [], "options": {"A": "Commission", "B": "Omission", "C": "Single entry", "D": "Original entry"}, "answer": "C", "explanation": "Single entry errors will affect the agreement of the trial balance totals, others include errors of additions , error of posting etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>41", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer this question  Debtors value as at 1st January 2000 was ₦40,000. Bad debts written off during the year was ₦5,000.  Provision for bad debt was 5%.    The amount debited to Profit and Loss Account as provision for the year was", "images": [], "options": {"A": "₦5,000", "B": "₦2,250", "C": "₦2,000", "D": "₦1,750"}, "answer": "D", "explanation": "Debtors balance b/f  less: Bad debt written off40,000  5,000  less: Provision for the year (5/100 × 35,000)35,000  1,75033,250", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>42", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following items is found in the credit column of the trial balance?", "images": [], "options": {"A": "Provision for doubtful debts", "B": "Bad debts written off", "C": "Carriage inwards", "D": "Carriage outwards"}, "answer": "A", "explanation": "The provision for doubtful debts is found in the credit column of the trial balance. This is because it is a liability or negative asset for the company, representing the amount that the company does not expect to collect from its debtors. Therefore, it is credited in the trial balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>43", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Which of the following is not a source document?", "images": [], "options": {"A": "Cheque stub", "B": "Cash receipt", "C": "Cash book", "D": "Sales invoice"}, "answer": "C", "explanation": "A cash book is not a source document. Source documents are original documents that contain the details that substantiate the transactions entered in an accounting system. Examples of source documents include invoices, receipts, cheques etc. A cash book, on the other hand, is a book of primary entry and it is from the source documents that entries are made in it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2003>44", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer this question  ₦Balance as per Cash book  Dishonoured cheques  Bank charges   Unpresented cheques18,000  1,200  300  2,400    The Adjusted Cash Book balance is", "images": [], "options": {"A": "₦18,900", "B": "₦18,000", "C": "₦17,700", "D": "₦16,500"}, "answer": "D", "explanation": "Dr &nbsp &nbsp &nbsp Adjusted Cash Book &nbsp &nbsp &nbsp Cr  ₦₦bal. b/f18,000dishonoured cheques  Bank charges  balance c/d1200  300  16,50018,00018,000balance b/d16,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>45", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer this question  ₦Balance as per Cash book  Dishonoured cheques  Bank charges   Unpresented cheques18,000  1,200  300  2,400  The balance as per the bank statement is", "images": [], "options": {"A": "₦21,300", "B": "₦18,900", "C": "₦16,500", "D": "₦14,100"}, "answer": "B", "explanation": "Bank Reconciliation statement     Balance as per adjusted cashbook  Add: Unpresented cheques₦  16,500  2,40018,900", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>46", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Which of the following transactions is posted to the nominal ledger?", "images": [], "options": {"A": "Discounts allowed to customers", "B": "Cash paid by a customer", "C": "Purchase of fixed asset for cash", "D": "Cash paid to suppliers"}, "answer": "A", "explanation": "Nominal ledger are accounts in which income and expenses are recorded e.g sales account, rent account, discounts account etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>47", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "The purchase of a typewriter for office was debited to Purchases Account. This is an error of", "images": [], "options": {"A": "original entry", "B": "commission", "C": "principle", "D": "omission"}, "answer": "C", "explanation": "The error made here is an error of principle. An error of principle in accounting occurs when the fundamental principles of accounting are not adhered to while recording transactions. In this case, the purchase of a typewriter, which is a fixed asset, was incorrectly debited to the Purchases Account, which is typically used for recording the purchase of goods for resale. The correct entry should have been to debit the Office Equipment account (or a similar fixed asset account), not the Purchases Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>48", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is a real account item?", "images": [], "options": {"A": "Goodwill", "B": "Fixtures", "C": "Debtors", "D": "Interest"}, "answer": "B", "explanation": "A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year end and are carried forward. An example of a real account is a Fixed Asset Account, such as 'Fixtures'. Goodwill is an intangible asset, Debtors is a personal account and Interest is a nominal account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>49", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Which of the following has multiple uses?", "images": [], "options": {"A": "Sales Journal", "B": "Purchases Journal", "C": "General Journal", "D": "Returns Outward Journal"}, "answer": "C", "explanation": "The General Journal has multiple uses because it is the accounting journal where all the financial transactions of a business are initially recorded. The General Journal is often referred to as the book of original entry. Sales Journal, Purchases Journal, and Returns Outward Journal are all specialized journals and are used to record specific types of transactions only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2003>50", "subject": "Accounts", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The art of recording transactions in books of account is known as", "images": [], "options": {"A": "debiting", "B": "book-keeping", "C": "auditing", "D": "crediting"}, "answer": "B", "explanation": "The art of recording transactions in books of account is known as book-keeping. Book-keeping is the process of recording financial transactions and information pertaining to a business in the books of accounts. It serves as a basis for accounting and it's done on a regular basis. It involves the systematic recording and organising of financial transactions in a company. Debiting and crediting are part of the book-keeping process, but they are not the process itself. Auditing is the process of examining the financial statements of a company to ensure they are accurate and in accordance with any applicable laws, regulations, and policies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>1", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "The Sales Day Book is used to record", "images": [], "options": {"A": "cash and credit sales", "B": "credit sales", "C": "cash sales", "D": "sales to middlemen"}, "answer": "B", "explanation": "The Sales Day Book is a book of original entry in which, under different heads, all credit sales made during a particular period are recorded. The Sales Day Book records only credit sales, not cash sales. Cash sales are recorded in the Cash Book.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>2", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The principle of double entry book-keeping states that every", "images": [], "options": {"A": "debit entry must have a corresponding credit entry", "B": "debtor must have a creditor", "C": "double debit entry must have a double credit entry", "D": "account debited should also be credited"}, "answer": "A", "explanation": "The principle of double entry book-keeping states that for every debit entry, there must be a corresponding credit entry. This is based on the accounting equation that states that assets = liabilities + equity. Therefore, every transaction has an effect on at least two accounts, one account is debited and another account is credited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>3", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is used to record the purchase of fixed asset on credit?", "images": [], "options": {"A": "Sales journal", "B": "Journal proper", "C": "Purchases journal", "D": "Cash book"}, "answer": "B", "explanation": "The Journal Proper is used to record the purchase of fixed assets on credit. The Journal Proper is a book of original entry (like a diary) where transactions that do not belong to any other journal are recorded. These transactions include opening entries, closing entries, adjustment entries, rectification entries, and entries related to non-cash transactions such as the purchase of fixed assets on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>4", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Which of the following is both a subsidiary book and a ledger?", "images": [], "options": {"A": "Sales journal", "B": "Purchases journal", "C": "Returns inward book", "D": "Cash book"}, "answer": "D", "explanation": "The Cash Book is both a subsidiary book and a ledger. A subsidiary book is a book of original entry where transactions are recorded for the first time from the source document. A ledger, on the other hand, is a book of final entry where transactions are classified into different accounts. The Cash Book serves both purposes as it records cash transactions when they occur (like a subsidiary book) and also classifies them into debit and credit (like a ledger).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>5", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Rent receivable account is an example of", "images": [], "options": {"A": "nominal account", "B": "real account", "C": "personal account", "D": "private account"}, "answer": "A", "explanation": "Nominal account record income and expenses of a firm or organisation. e.g Rental income, discount received, discount allowed, wages & salaries etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>6", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Which of the following is not a source document?", "images": [], "options": {"A": "Credit note", "B": "Invoice", "C": "Debit note", "D": "Bank note"}, "answer": "D", "explanation": "A bank note is not a source document. In accounting, source documents are the physical or electronic documents that provide evidence of a financial transaction. These include invoices, receipts, credit notes, and debit notes. A bank note, on the other hand, is a type of negotiable instrument issued by a bank, and it is not a document that records a specific business transaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>7", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "Pending the location of an error, the difference disclosed in a trial balance is temporarily treated in", "images": [], "options": {"A": "Suspense Account", "B": "Trading Account", "C": "Control Account", "D": "Profit and Loss Account"}, "answer": "A", "explanation": "A Suspense Account is used in accounting to record discrepancies found in a trial balance. When the trial balance does not balance, the difference is temporarily held in a suspense account until the error is located and corrected. Therefore, the correct answer is 'Suspense Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>8", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following items is not shown in the Trial Balance", "images": [], "options": {"A": "Closing stock value", "B": "Opening stock balance", "C": "Opening debtors balance", "D": "Closing asset value"}, "answer": "A", "explanation": "A Trial Balance is a statement of ledger account balances within a ledger, at a particular instance. It is a part of the closing process of the accounting cycle. The closing stock value is not shown in the trial balance because it is not a ledger account. It is calculated at the end of the accounting period and is used in the preparation of the Trading Account and Balance Sheet. Therefore, the correct answer is 'Closing stock value'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>9", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "The total of the purchases day book is posted to the purchases account in the", "images": [], "options": {"A": "general ledger", "B": "purchases journal", "C": "private ledger", "D": "purchase ledger"}, "answer": "D", "explanation": "Total of the purchases daybook is posted to the purchases account in the purchases ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>10", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question  NRent prepaid  Rent paid  Rent prepaid1/01/2003  31/12/2003600.00  3,000.00  400.00    Rent for 2003 amounted to", "images": [], "options": {"A": "N4,000", "B": "N3,200", "C": "N3,000", "D": "N2,800"}, "answer": "B", "explanation": "Rent for 2003 is calculated by adding the rent paid and the rent prepaid at the beginning of the year, then subtracting the rent prepaid at the end of the year. So, N3,000 (Rent paid) + N600 (Rent prepaid at the beginning of the year) - N400 (Rent prepaid at the end of the year) = N3,200.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>11", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Use the following information to answer this question  NUnpresented cheques  Balance as per bank statement  Balance as per cash book85,305  206,865  144,495  Uncredited cheques amount to", "images": [], "options": {"A": "N229,800", "B": "N121,560", "C": "N85,305", "D": "N22,935"}, "answer": "D", "explanation": "Bal. as per Cashbook  Add: Unpresented cheques₦  144,495  85,305  less: uncredited cheques229,800  xBal. as per bank statement206,865  uncredited cheque = x  229,800 - x = 206,865  229,800 - 206,865 = x  x = 22,935 (uncredited cheques)", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>12", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "The amount set aside out of profit for a specific purpose is", "images": [], "options": {"A": "provision", "B": "reserve", "C": "depreciation", "D": "depletion"}, "answer": "B", "explanation": "The amount set aside out of profit for a specific purpose is known as a reserve. This is because a reserve is a part of profits that a company keeps aside to meet future uncertainties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>13", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following terms describes the provision made for the loss in the value of an asset that has a legal life span?", "images": [], "options": {"A": "Capitalization", "B": "Depreciation", "C": "Depletion", "D": "Amortization"}, "answer": "B", "explanation": "Provision for depreciation is the provision made for the loss on the value of an asset that has a legal life span.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>14", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following is correct about cost of goods sold?", "images": [], "options": {"A": "Opening stock + purchases - closing stock", "B": "Opening stock + sales - closing stock", "C": "Opening stock - purchases - closing stock", "D": "Opening stock + sales + closing stock"}, "answer": "A", "explanation": "The correct formula for calculating the cost of goods sold is: Opening stock + purchases - closing stock. This formula is used to calculate the direct costs attributable to the production of the goods sold in a company. This includes the cost of the materials used in creating the goods along with the direct labor costs used to produce the good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>15", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Net debtors is", "images": [], "options": {"A": "debtors less provision for bad debts", "B": "debtors plus provision for bad debts", "C": "debtors less prepayments", "D": "debtors plus prepayments"}, "answer": "A", "explanation": "Net debtors is calculated by subtracting the provision for bad debts from the total debtors. This is done to account for the debts that are expected to be uncollectible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>16", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The balance on the Sales Ledger Control Account at the end of the accounting year represents total", "images": [], "options": {"A": "trade debtors at the end of the year", "B": "cash sales for the year", "C": "credit sales for the year", "D": "amount transferred from the Sales Day Book"}, "answer": "A", "explanation": "The balance on the Sales Ledger Control Account at the end of the accounting year represents the total trade debtors at the end of the year. This account is used to keep track of the money owed to a business by its customers (debtors).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>17", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which allows the use of a particular method for treating a transaction for a reasonable number of years is", "images": [], "options": {"A": "consistency", "B": "cost", "C": "accrual", "D": "conservatism"}, "answer": "A", "explanation": "The accounting concept that allows the use of a particular method for treating a transaction for a reasonable number of years is 'consistency'. The consistency concept, also known as the uniformity principle, states that businesses should use the same accounting methods and procedures from period to period. This allows the financial statements of a company to be comparable across periods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>18", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "A decrease in the provision fo doubtful debts results in", "images": [], "options": {"A": "an increase in net profit", "B": "a decrease in gross profit", "C": "an increase in gross profit", "D": "a decrease in net profit"}, "answer": "A", "explanation": "A decrease in the provision for doubtful debts results in an increase in net profit. The provision for doubtful debts is an estimated amount of bad debts that we expect to arise from the accounts receivable that have been issued but not yet collected. When this provision decreases, it means that less money is being set aside for debts that are not expected to be paid, which increases the net profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>19", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer this question  NPurchases   Opening stock  Closing stock  Sales2,000  900  300  3,850    Gross profit is", "images": [], "options": {"A": "N1,850", "B": "N1,250", "C": "N950", "D": "N650"}, "answer": "B", "explanation": "Gross profit is calculated by subtracting the cost of goods sold (COGS) from the total sales. The COGS is calculated by adding the opening stock and purchases, then subtracting the closing stock. So, COGS = (Opening Stock + Purchases) - Closing Stock = (900 + 2000) - 300 = 2600. Therefore, Gross Profit = Sales - COGS = 3850 - 2600 = 1250.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>20", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer this question  NPurchases   Opening stock  Closing stock  Sales2,000  900  300  3,850  The cost of goods available is", "images": [], "options": {"A": "N3,850", "B": "N2,900", "C": "N2,300", "D": "N2,000"}, "answer": "B", "explanation": "The cost of goods available for sale is calculated by adding the opening stock and purchases. So, Cost of Goods Available = Opening Stock + Purchases = 900 + 2000 = 2900.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>21", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is not a debit item in the partnership profit and loss appropriation account?", "images": [], "options": {"A": "Interest on partners drawings", "B": "Partners salaries", "C": "Interest on partners capital", "D": "Share of profit"}, "answer": "A", "explanation": "Interest on partners drawings is a credit item in the partnership profit and loss appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>22", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Which of the following is not correct?", "images": [], "options": {"A": "Credit sales are entered on the debit side of the customers personal account", "B": "Credit purchases are entered on the debit side of the supplier's personal account", "C": "Returns inwards are entered on the credit side of the customer's personal account", "D": "Returns outwards are entered on the debit side of the supplier's account"}, "answer": "B", "explanation": "The statement 'Credit purchases are entered on the debit side of the supplier's personal account' is not correct. In accounting, when a business makes credit purchases, it is recorded on the credit side of the supplier's personal account, not the debit side. This is because the supplier is a creditor to the business, and creditors are liabilities which are credited when they increase. The other options correctly describe how transactions are recorded in the personal accounts of customers and suppliers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>23", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "When discount is allowed, the accounting entry is debit Discount Allowed Account and credit", "images": [], "options": {"A": "Suspense Account", "B": "Expenses Account", "C": "Debtors Account", "D": "Creditors Account"}, "answer": "C", "explanation": "When a discount is allowed, it means that the debtor is given a reduction in the amount they owe. This reduction is a loss to the business and is therefore debited to the Discount Allowed Account. The corresponding credit entry is made to the Debtors Account to reduce the amount owed by the debtor. Therefore, the correct accounting entry is 'Debit Discount Allowed Account and Credit Debtors Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>24", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "When partners maintain fixed capital accounts, the correct entries for a partner's share of profit is", "images": [], "options": {"A": "Debit Profit and Loss Appropriation Account, credit Current Account", "B": "Debit Profit and Loss Appropriation Account, credit Capital Account", "C": "Debit Current Account, credit Capital Account", "D": "Debit Profit and Loss Account, credit Current Account"}, "answer": "A", "explanation": "When partners maintain fixed capital accounts, their share of profit is not credited to their capital accounts but to their current accounts. The Profit and Loss Appropriation Account, which is an account used to distribute the profit among partners, is debited because the profit is an expense for the business. Therefore, the correct entries for a partner's share of profit is 'Debit Profit and Loss Appropriation Account, credit Current Account'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>25", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO", "question": "Goodwill is taken into account in partnership when", "images": [], "options": {"A": "the business has good customer relations", "B": "the business is making huge profit", "C": "a new partner is admitted", "D": "a partner becomes dormant"}, "answer": "C", "explanation": "Goodwill is taken into account in a partnership when a new partner is admitted. Goodwill is an intangible asset that represents the non-physical assets, such as brand name, customer relationships, and reputation, that a business has built up over time. When a new partner is admitted into the partnership, the existing partners often want to be compensated for the goodwill that they have built up. This is usually done by having the new partner contribute an amount to the partnership that represents their share of the goodwill.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>26", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "The excess of current assets over current liabilities is", "images": [], "options": {"A": "working capital", "B": "preference capital", "C": "loan capital", "D": "founder's capital"}, "answer": "A", "explanation": "The excess of current assets over current liabilities is known as working capital. Working capital is a measure of a company's operational liquidity and short-term financial health. It is calculated as current assets minus current liabilities. Current assets are assets that a company expects to convert to cash within one year, while current liabilities are the company's debts or obligations that are due within one year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>27", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A class of shareholders who are paid last in the event of winding-up are", "images": [], "options": {"A": "Ordinary", "B": "Preference", "C": "Founder", "D": "Treasury"}, "answer": "A", "explanation": "Ordinary shareholders are the last to be paid in the event of a company's liquidation. This is because they are the owners of the company and bear the highest risk. The order of payment in the event of winding up is usually: secured creditors, unsecured creditors, preference shareholders, and finally ordinary shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>28", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The class of shareholders who are paid last in the event of winding-up are", "images": [], "options": {"A": "Ordinary", "B": "Preference", "C": "Founder", "D": "Treasury"}, "answer": "C", "explanation": "Ordinary shareholders are paid last in the event of winding up of a company but where founder shareholder exist in a company, it will be founder shareholder exist in a company, it will be founder share but not ordinary shareholder.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>29", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "CONTROL ACCOUNTS : TREATMENT OF CONTRA ENTRIES", "question": "When both debit and credit entries in respect of a transaction are made in the same ledger account, this is", "images": [], "options": {"A": "a ledger entry", "B": "an accounting entry", "C": "a folio entry", "D": "a contra entry"}, "answer": "D", "explanation": "When both debit and credit entries in respect of a transaction are made in the same ledger account, it is known as a contra entry. A contra entry is recorded when the debit and credit affect the same parent account and resulting in a net zero effect to the account. These are transactions that are recorded between cash and bank accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>30", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question  NStock of raw materials - 1st January, 2002  Purchases of raw materials  Carriage inwards   Stock of raw materials - 31st December, 2002  Royalty paid   Manufacturing wages   Supervisor's salary 460,000  1,000,000  100,000  500,000  35,000  80,000  15,000    Total overhead cost is", "images": [], "options": {"A": "N105,000", "B": "N95,000", "C": "N50,000", "D": "N15,000"}, "answer": "D", "explanation": "Total overhead cost = 15,000  i.e supervisory salary", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>31", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question  NStock of raw materials - 1st January, 2002  Purchases of raw materials  Carriage inwards   Stock of raw materials - 31st December, 2002  Royalty paid   Manufacturing wages   Supervisor's salary 460,000  1,000,000  100,000  500,000  35,000  80,000  15,000  The prime cost is", "images": [], "options": {"A": "N1,175,000", "B": "N1,140,000", "C": "N1,075,000", "D": "N1,060,000"}, "answer": "A", "explanation": "The prime cost is calculated by adding the cost of raw materials used, direct labor, and direct expenses. In this case, the cost of raw materials used is calculated by adding the opening stock of raw materials, purchases of raw materials, and carriage inwards, then subtracting the closing stock of raw materials. The direct labor is the manufacturing wages and the direct expenses is the royalty paid. Therefore, the prime cost is (460,000 + 1,000,000 + 100,000 - 500,000) + 80,000 + 35,000 = N1,175,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>32", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question  NStock of raw materials - 1st January, 2002  Purchases of raw materials  Carriage inwards   Stock of raw materials - 31st December, 2002  Royalty paid   Manufacturing wages   Supervisor's salary 460,000  1,000,000  100,000  500,000  35,000  80,000  15,000  Cost of raw materials used is", "images": [], "options": {"A": "N1,175,000", "B": "N1,140,000", "C": "N1,075,000", "D": "N1,060,000"}, "answer": "D", "explanation": "The cost of raw materials used is calculated by adding the opening stock of raw materials, purchases of raw materials, and carriage inwards, then subtracting the closing stock of raw materials. Therefore, the cost of raw materials used is 460,000 + 1,000,000 + 100,000 - 500,000 = N1,060,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>33", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PURCHASES OF BUSINESS : INTRODUCTION AND ADVANTAGES", "question": "The price paid by an acquiring company is", "images": [], "options": {"A": "conversion fee", "B": "premium", "C": "sales consideration", "D": "purchases consideration"}, "answer": "D", "explanation": "Purchases consideration is the price paid for purchases of a company or acquiring a company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>34", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A unit of a company's capital which can be bought is", "images": [], "options": {"A": "share", "B": "interest", "C": "asset", "D": "property"}, "answer": "A", "explanation": "A unit of a company's capital which can be bought is referred to as a 'share'. A share represents a unit of ownership in a company and constitutes a claim on part of the company's assets and earnings. There are two main types of stock: common and preferred. The term 'share' is used in the context of stock market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>35", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and Payments Account  NNBalance - 1st January, 2002  Subscriptions received:  2002  2003  Receipts from Bar  Receipts from dance  Sundry receipts200    3,600  250  4,500  500  400Bar supplies   Wages   General expenses   Printing expenses  Equipment  Repairs  Balance - 31st December2,850  350  400  120  650  200  4,8809,4509,450    Additional information  1/01/02  N31/12/02  NEquipment  Stock-bar  Bar supplies4,500  1,200  2,4005,150  3,200  5,600    Accumulated fund as at 1st January 2002 is", "images": [], "options": {"A": "N6,900", "B": "N5,900", "C": "N4,500", "D": "N3,500"}, "answer": "D", "explanation": "Opening  Statement of affairs  ₦Assets₦Accumulated fund  Liabilities  Bar Suppliers 3500    2400Equipment   Stock-bar  Cash balance4500  1200  20059005900    Accumulated fund = Total Assets - Total Liabilities", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>36", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and Payments Account  NNBalance - 1st January, 2002  Subscriptions received:  2002  2003  Receipts from Bar  Receipts from dance  Sundry receipts200    3,600  250  4,500  500  400Bar supplies   Wages   General expenses   Printing expenses  Equipment  Repairs  Balance - 31st December2,850  350  400  120  650  200  4,8809,4509,450    Additional information  1/01/02  N31/12/02  NEquipment  Stock-bar  Bar supplies4,500  1,200  2,4005,150  3,200  5,600  Gross profit from Bar trading is", "images": [], "options": {"A": "N4,500", "B": "N1,350", "C": "N550", "D": "N400"}, "answer": "C", "explanation": "The gross profit from Bar trading is calculated by subtracting the cost of bar supplies from the receipts from the bar. In this case, the receipts from the bar are 4,500 and the cost of bar supplies is 2,850. Therefore, the gross profit is 4,500 - 2,850 = 1,650. However, none of the options match this answer. The closest option is N1,350, but it is not correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>37", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and Payments Account  NNBalance - 1st January, 2002  Subscriptions received:  2002  2003  Receipts from Bar  Receipts from dance  Sundry receipts200    3,600  250  4,500  500  400Bar supplies   Wages   General expenses   Printing expenses  Equipment  Repairs  Balance - 31st December2,850  350  400  120  650  200  4,8809,4509,450    Additional information  1/01/02  N31/12/02  NEquipment  Stock-bar  Bar supplies4,500  1,200  2,4005,150  3,200  5,600  Amount owing to Bar creditors is", "images": [], "options": {"A": "N8,450", "B": "N6,050", "C": "N5,600", "D": "N2,850"}, "answer": "C", "explanation": "Dr &nbsp &nbsp Bar Supplies A/c &nbsp &nbsp Cr    Cash paid  bal. c/d₦  2850  5600  bal. b.f  purchases₦  2400  59508,4508,450bal b/d (owing)5,600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>38", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following is the basis of accounting in public service?", "images": [], "options": {"A": "Profit", "B": "Accrual", "C": "Expenditure", "D": "Cash"}, "answer": "D", "explanation": "The basis of accounting in public service is cash basis. This means that revenues are recognized when cash is received, and expenses are recognized when they are actually paid. This contrasts with the accrual basis of accounting, where revenues and expenses are recognized when they are earned and incurred, respectively, not when cash changes hands.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>39", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "An expense is said to be revenue in nature if it", "images": [], "options": {"A": "adds or contributes to the operating income of the business", "B": "reduces the capital of the business", "C": "necessitates the introduction of additional capital", "D": "adds to or improves the value of fixed assets"}, "answer": "A", "explanation": "An expense is said to be revenue in nature if it adds or contributes to the operating income of the business. This is because revenue expenses are those expenses that are incurred in the day-to-day conduct and administration of a business and which are written off against profits of that period. They are necessary for the maintenance of the earning capacity of the business and are usually recurring in nature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>40", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The amount of money granted by government to public institutions to meet recurrent expenditure during a fiscal year is", "images": [], "options": {"A": "subvention", "B": "budget", "C": "deposit", "D": "estimates"}, "answer": "A", "explanation": "The amount of money granted by government to public institutions to meet recurrent expenditure during a fiscal year is known as subvention. Subvention is a grant of money from a government or central bank to cover a deficit in its budget or to stimulate a sector of the economy. It is a form of financial aid or support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>41", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "A business operates on a mark-up of 25%. If cost of goods sold is N800,000. What is the profit?", "images": [], "options": {"A": "N360,000", "B": "N200,000", "C": "N160,000", "D": "N40,000"}, "answer": "B", "explanation": "The profit is calculated by multiplying the cost of goods sold by the mark-up percentage. In this case, the profit is 25% of N800,000, which equals N200,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>42", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Rent prepaid as at 1st January, 2002 was N10,000. Annual rent payable is N80,000 and rent accrued as at 31st December, 2002 was N15,000. How much was paid for rent in 2002?", "images": [], "options": {"A": "N80,000", "B": "N75,000", "C": "N55,000", "D": "N35,000"}, "answer": "B", "explanation": "The total amount paid for rent in 2002 is calculated by adding the rent prepaid at the beginning of the year to the annual rent payable, and then subtracting the rent accrued at the end of the year. In this case, the total amount paid for rent is N10,000 + N80,000 - N15,000, which equals N75,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>43", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following is not correct?", "images": [], "options": {"A": "Assets  NLiabilities  NCapital  N95,55011,50082,000", "B": "Assets  NLiabilities  NCapital  N82,00028,00054,000", "C": "Assets  NLiabilities  NCapital  N78,50012,50066,000", "D": "Assets  NLiabilities  NCapital  N65,40011,20054,200"}, "answer": "A", "explanation": "Capital = Assets - Liabilities   95,550 - 11,500  ⇒ ₦84,050", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>44", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Use the following information to answer this question  NPurchase price of equipment  Freight and installation cost  Annual maintenance cost  Estimated useful life - 5 years  Estimated scrap value60,000  10,000  1,000    2,000    What is the total acquisition cost of the equipment?", "images": [], "options": {"A": "N76,000", "B": "N72,000", "C": "N70,000", "D": "N60,000"}, "answer": "C", "explanation": "Total acquisition cost of equipment = purchase price of equipment + freight and installation cost  ⇒ 60,000 + 10,000  ⇒ 70,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>45", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question  NPurchase price of equipment  Freight and installation cost  Annual maintenance cost  Estimated useful life - 5 years  Estimated scrap value60,000  10,000  1,000    2,000  What is the annual depreciation charge if straight line method is used?", "images": [], "options": {"A": "N14,000", "B": "N13,600", "C": "N12,000", "D": "N10,000"}, "answer": "B", "explanation": "The annual depreciation charge using the straight-line method is calculated by subtracting the scrap value from the cost of the asset and then dividing by the useful life of the asset. In this case, the cost of the asset includes the purchase price and the freight and installation cost. Therefore, the annual depreciation charge is (60,000 + 10,000 - 2,000) / 5 = 13,600.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>46", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question  NPurchase price of equipment  Freight and installation cost  Annual maintenance cost  Estimated useful life - 5 years  Estimated scrap value60,000  10,000  1,000    2,000  Using reducing balance method at the rate of 20%. What is the depreciation charge for the second year?", "images": [], "options": {"A": "N13,600", "B": "N11,200", "C": "N10,880", "D": "N9,600"}, "answer": "B", "explanation": "The depreciation charge for the second year using the reducing balance method is calculated by applying the depreciation rate to the net book value of the asset at the end of the first year. The net book value at the end of the first year is the cost of the asset minus the depreciation charge for the first year. The depreciation charge for the first year is 20% of the cost of the asset. Therefore, the depreciation charge for the second year is 20% * (60,000 + 10,000 - 20% * (60,000 + 10,000)) = 11,200.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2004>47", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "Capital at start was N280,000, while capital at the end of the year was N485,000 and drawings during the year was N15,000. What is profit for the year?", "images": [], "options": {"A": "N265,000", "B": "N220,000", "C": "N205,000", "D": "N190,000"}, "answer": "B", "explanation": "The profit for the year can be calculated by subtracting the capital at the start from the capital at the end and adding the drawings during the year. This gives us a profit of N220,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2004>48", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "A statement that measures the performance of a business over a period of time is the", "images": [], "options": {"A": "Balance sheet", "B": "Bank statement", "C": "Funds flow statement", "D": "Profit and loss account"}, "answer": "A", "explanation": "Balance sheet is a comprehensive financial statement that shows assets and liabilities of a company which measures the performance of a business over a period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>49", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Computer programmes are", "images": [], "options": {"A": "micro processors", "B": "software", "C": "hardware", "D": "memory"}, "answer": "B", "explanation": "Computer programs are software. A computer program is a collection of instructions that can be executed by a computer to perform a specific task. A computer program is usually written by a computer programmer in a programming language. This broad definition includes both system software such as operating systems, which provide services to other software, and application software such as word processors, which provide a service directly to end users.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2004>50", "subject": "Accounts", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not a unit of the computer?", "images": [], "options": {"A": "Console", "B": "Output", "C": "Control", "D": "Input"}, "answer": "A", "explanation": "Console is not a unit of computer. console is a terminal, which is being used for communication between the operator and the programs, which are controlling the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>1", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The systematic recording of business transactions in monetary term is", "images": [], "options": {"A": "auditing", "B": "book-keeping", "C": "debiting", "D": "crediting"}, "answer": "B", "explanation": "The systematic recording of business transactions in monetary terms is known as book-keeping. Book-keeping is the process of recording daily transactions in a consistent way, and is a key component to building a financially successful business. It ensures that records of the individual financial transactions are correct, up-to-date and comprehensive. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>2", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "An allowance given to a customer by a supplier for prompt payment is", "images": [], "options": {"A": "trade discount", "B": "discount received", "C": "cash discount", "D": "cash rebate"}, "answer": "C", "explanation": "An allowance given to a customer by a supplier for prompt payment is known as a cash discount. A cash discount is a deduction allowed by the seller of goods or by the provider of services in order to motivate the customer to pay within a specified time. The seller or provider often refers to this discount as a sales discount, and the buyer sees it as a purchase discount. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>3", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Which of the following is not contained in a journal?", "images": [], "options": {"A": "Folio number of transaction", "B": "Date of transaction", "C": "Address of the customer", "D": "Description of the transaction"}, "answer": "C", "explanation": "A journal in accounting is a book where transactions are recorded in the order they occur. It contains the date of the transaction, a brief description of the transaction, and the folio number of the transaction. The address of the customer is not typically included in a journal entry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>4", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is found in the private ledger?", "images": [], "options": {"A": "Rent account", "B": "Sales account", "C": "Drawings account", "D": "Bank account"}, "answer": "C", "explanation": "A private ledger in accounting is a ledger that contains accounts that are only accessible to certain individuals within a company. This typically includes accounts related to the owners of the company, such as the drawings account. The rent account, sales account, and bank account are usually found in the general ledger, not the private ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>5", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Which of the following is not one of the uses of a journal proper? To record", "images": [], "options": {"A": "small and repetitive cash disbursements", "B": "purchase and sale of fixed assets on credit", "C": "writing off bad debts", "D": "correction of errors"}, "answer": "A", "explanation": "A journal proper is used to record non-repetitive, infrequent and miscellaneous transactions. Small and repetitive cash disbursements are usually recorded in a cash disbursements journal, not a journal proper.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>6", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A trial balance is a list of", "images": [], "options": {"A": "current assets", "B": "current liabilities", "C": "debit and credit balances", "D": "debtors and creditors"}, "answer": "C", "explanation": "A trial balance is a list of all the General ledger accounts (both revenue and capital) contained in the ledger of a business. This list will contain the name of the nominal ledger account and the value of that nominal ledger balance. Each nominal ledger account will hold either a debit balance or a credit balance. The debit balance values will be listed in the debit column of the trial balance and the credit value balance will be listed in the credit column.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>7", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following is an example of direct expense?", "images": [], "options": {"A": "Royalties", "B": "Carriage inwards", "C": "Carriage outwards", "D": "Manufacturing wages"}, "answer": "D", "explanation": "Direct expenses are costs that can be directly tied to a cost object, which can be a product, department or project. This can include items such as direct materials, direct labor, machine repairs, and machine depreciation. In the given options, 'Manufacturing wages' is an example of direct expense as it can be directly attributed to the production of goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>8", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer this question  CASH BOOK  Dr &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Cr    Jan 5 Hassan  Jan 24 Malik  Jan 29 Rasaq  Jan 31 Lukman  Jan 31 Balance c/dN  3,080  1,200  1,240  1,060  2,540  Jan 1 Balance b/d  Jan 9  Dauda  Jan 31  HusseinN  7,090  1,400  6309,1209,120Feb 1 Balance b/d2,540    BANK STATEMENT  Dr.  NCr.  NBalance  NJan. 1 Balance b/d  Jan 5 Hassan   Jan 9 Dauda  Jan 24 Malik  Jan 29 Rasaq  Jan 30 Standing order   Jan 31 Bank charges    1,400      770  490  3,080    1,200  1,240    7,090 O/D  4,010 O/D  5,410 O/D  4,210 O/D  2,970 O/D  3,740 O/D  4,230 O/D    Uncredited cheques totalled", "images": [], "options": {"A": "N3,600", "B": "N2,540", "C": "N1,060", "D": "N630"}, "answer": "C", "explanation": "Uncredited cheque is item at debit side of the cashbook but not at the credit side of bank statement which is ₦1,060", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>9", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer this question  CASH BOOK  Dr &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Cr    Jan 5 Hassan  Jan 24 Malik  Jan 29 Rasaq  Jan 31 Lukman  Jan 31 Balance c/dN  3,080  1,200  1,240  1,060  2,540  Jan 1 Balance b/d  Jan 9  Dauda  Jan 31  HusseinN  7,090  1,400  6309,1209,120Feb 1 Balance b/d2,540    BANK STATEMENT  Dr.  NCr.  NBalance  NJan. 1 Balance b/d  Jan 5 Hassan   Jan 9 Dauda  Jan 24 Malik  Jan 29 Rasaq  Jan 30 Standing order   Jan 31 Bank charges    1,400      770  490  3,080    1,200  1,240    7,090 O/D  4,010 O/D  5,410 O/D  4,210 O/D  2,970 O/D  3,740 O/D  4,230 O/D  Adjusted Cash Book balance is", "images": [], "options": {"A": "N3,800 O/D", "B": "N3,310 O/D", "C": "N3,030 O/D", "D": "N2,540 O/D"}, "answer": "A", "explanation": "Dr &nbsp &nbsp &nbsp Adjusted Cashbook &nbsp &nbsp Cr    bal. c/d₦  3,800  balance b/f  standing order  Bank charges₦  2540  770  49038003800bal. b/d3800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>10", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer this question  CASH BOOK  Dr &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Cr    Jan 5 Hassan  Jan 24 Malik  Jan 29 Rasaq  Jan 31 Lukman  Jan 31 Balance c/dN  3,080  1,200  1,240  1,060  2,540  Jan 1 Balance b/d  Jan 9  Dauda  Jan 31  HusseinN  7,090  1,400  6309,1209,120Feb 1 Balance b/d2,540    BANK STATEMENT  Dr.  NCr.  NBalance  NJan. 1 Balance b/d  Jan 5 Hassan   Jan 9 Dauda  Jan 24 Malik  Jan 29 Rasaq  Jan 30 Standing order   Jan 31 Bank charges    1,400      770  490  3,080    1,200  1,240    7,090 O/D  4,010 O/D  5,410 O/D  4,210 O/D  2,970 O/D  3,740 O/D  4,230 O/D  Unpresented cheque(s) totalled", "images": [], "options": {"A": "N9,120", "B": "N7,090", "C": "N1,400", "D": "N630"}, "answer": "D", "explanation": "Unpresented cheque is item at the credit side of the cash book but not at the debit side of the bank statement which is ₦630.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>11", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "A debit balance of N1,000 in a cash account means that", "images": [], "options": {"A": "cash in hand is N1,000", "B": "cash has been overspent by N1,000", "C": "total cash paid out is N1,000", "D": "total cash received was less by N1,000"}, "answer": "A", "explanation": "In accounting, a debit balance in a cash account means that there is cash on hand. Therefore, a debit balance of N1,000 in a cash account means that there is N1,000 cash in hand. This is because in the double-entry bookkeeping system, debits and credits are used to track the changes of values resulting from business transactions. Debits are used to increase the balances of assets and expenses, and decrease the balances of liabilities, equity, and revenues. In this case, cash is an asset, so a debit increases its balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>12", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "The maximum level of cash held by a cashier under an imprest system is a/an", "images": [], "options": {"A": "vote", "B": "float", "C": "reimbursement", "D": "advance"}, "answer": "B", "explanation": "In an imprest system, the maximum level of cash held by a cashier is referred to as a 'float'. The float is the maximum amount of money that a cashier is allowed to have in their cash drawer at any given time. This system is used to control the amount of cash that is available, reducing the risk of theft or mismanagement. When the cash in the drawer drops below a certain level, it is replenished from a central fund (the imprest). Therefore, the correct answer is 'float'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>13", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "The total of the sales journal is entered on the", "images": [], "options": {"A": "debit side of Sales Account", "B": "debit side of Cash Account", "C": "credit side of Sales Account", "D": "credit side of Cash Account"}, "answer": "C", "explanation": "The total of the sales journal is entered on the credit side of the Sales Account. This is because when a sale is made, the sales account is credited. This is in accordance with the double-entry bookkeeping system where every debit has a corresponding credit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>14", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Gross profit is calculated in the", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Appropriation Account", "D": "Partners Current Account"}, "answer": "A", "explanation": "Gross profit is calculated in the Trading Account. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. The Trading Account is where these calculations are made.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>15", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "An example of fixed asset is", "images": [], "options": {"A": "creditors", "B": "goodwill", "C": "accruals", "D": "furniture"}, "answer": "D", "explanation": "A fixed asset is a long-term tangible piece of property or equipment that a firm owns and uses in its operations to generate income. Fixed assets are not expected to be consumed or converted into cash within a year. Furniture is a good example of a fixed asset because it is a tangible item that is expected to be used for several years. Creditors and accruals are examples of liabilities, not assets. Goodwill, on the other hand, is an intangible asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>16", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this questions      Capital Accounts  Current Accounts   DrawingsAde  N  60,000  10,000 Cr.  8,000Bola   N  40,000  6,000 Dr  2,000  Interest on drawings is 5%, interest on capital is 10%. Profits and losses are shared equally. Net profit for the year is ₦30,000.    The amount of distributable profit is", "images": [], "options": {"A": "N39,500", "B": "N30,500", "C": "N30,000", "D": "N20,500"}, "answer": "D", "explanation": "Dr &nbsp &nbsp Profit & loss appropriation account &nbsp &nbsp Cr    Interest on capital  Ade ( 10/100 × 60,000 )  Bola ( 10/100 × 40,000 )  Share of profit:  Ade  Bola₦    6000  4000    10,250  10,250  Profit b/f  Interest on drawings  Ade ( 5/100 × 8000 )  Bola ( 5/100 × 2000 )₦  30,000    400  100    30,50030,500  The amount of distributable profit = (30,000 + 400 + 100) - (6000 + 4000)  ⇒ 30,500 - 10,000  ⇒ 20,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>17", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this questions      Capital Accounts  Current Accounts   DrawingsAde  N  60,000  10,000 Cr.  8,000Bola   N  40,000  6,000 Dr  2,000  Interest on drawings is 5%, interest on capital is 10%. Profits and losses are shared equally. Net profit for the year is ₦30,000.  Ade's share of profit is", "images": [], "options": {"A": "N19,750", "B": "N15,250", "C": "N15,000", "D": "N10,250"}, "answer": "D", "explanation": "Ade share of profit will be 10,250 since the distributable profit are shared equally between Ade and Bola  20,500 ÷ 2 = ₦10,250", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>18", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this questions      Capital Accounts  Current Accounts   DrawingsAde  N  60,000  10,000 Cr.  8,000Bola   N  40,000  6,000 Dr  2,000  Interest on drawings is 5%, interest on capital is 10%. Profits and losses are shared equally. Net profit for the year is ₦30,000.  Bola's current account balance is", "images": [], "options": {"A": "N8,150 Cr", "B": "N16,150 Cr", "C": "N10,150 Cr", "D": "N6,150 Cr"}, "answer": "A", "explanation": "Dr &nbsp &nbsp Partner' Current Account &nbsp &nbsp &nbsp Cr  DetailsAdeBolaRetailsAdeBola  Bal. b/f  Interest on drawings  Bal c/d₦  -  400  25,850₦  6,000  100  8,150  balance b/f  Interest on capital  Share of profit₦  10,000  6,000  10,250₦  -  4,000  10,25026,25014,25026,25014,250bal b/d25,8508,150", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>19", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this questions      Capital Accounts  Current Accounts   DrawingsAde  N  60,000  10,000 Cr.  8,000Bola   N  40,000  6,000 Dr  2,000  Interest on drawings is 5%, interest on capital is 10%. Profits and losses are shared equally. Net profit for the year is ₦30,000.  The total amount credited to the Profit and Loss Appropriation Account is", "images": [], "options": {"A": "N40,500", "B": "N30,500", "C": "N30,000", "D": "N25,000"}, "answer": "C", "explanation": "That is the net profit for the year, it is given as ₦30,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>20", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "FINANCIAL SYSTEM : METHODS OF RAISING FUNDS", "question": "Capital expenditure is the", "images": [], "options": {"A": "cost of running a business", "B": "money spend on buying goods for resale", "C": "money spend on acquiring fixed assets", "D": "extra capital paid in by the proprietor"}, "answer": "C", "explanation": "Capital expenditure refers to the money spent on acquiring or maintaining fixed assets, such as land, buildings, and equipment. It is considered a capital expenditure when the asset is newly purchased or when money is used towards extending the useful life of an existing asset, such as repairing the roof on a company building. Therefore, the correct option is 'money spend on acquiring fixed assets'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>21", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Depreciation of assets is provided for in consideration of", "images": [], "options": {"A": "disposal", "B": "loss by fire", "C": "loss in transit", "D": "wear and tear"}, "answer": "D", "explanation": "Depreciation of assets is provided for in consideration of 'wear and tear'. Depreciation is the reduction in the value of an asset due to usage, passage of time, wear and tear, technological outdating or obsolescence, etc. It is a method of allocating the cost of a tangible asset over its useful life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>22", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is a factory overhead?", "images": [], "options": {"A": "Depreciation of plant and machinery", "B": "Royalties", "C": "Raw materials consumed", "D": "Carriage outwards"}, "answer": "A", "explanation": "A factory overhead refers to the indirect factory-related costs that are incurred when a product is manufactured. This includes costs such as depreciation of plant and machinery, utilities, factory leases, and factory equipment maintenance. Therefore, 'Depreciation of plant and machinery' is a factory overhead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>23", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is used to derive missing figures in a system of incomplete records?", "images": [], "options": {"A": "Control acccount", "B": "Bank account", "C": "Profit and loss account", "D": "Bank statement"}, "answer": "A", "explanation": "Returns ouwtards is not included when preparing sales ledger control account but rather shown in purchases ledger control account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>24", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not contained in sales ledger control account?", "images": [], "options": {"A": "Returns inwards", "B": "Returns outwards", "C": "Receipts from debtors", "D": "Dishonoured cheques"}, "answer": "B", "explanation": "Returns outwards are not contained in the sales ledger control account because they are transactions that involve the business returning goods to its suppliers, which are related to creditors, not debtors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>25", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not credited to debtors control account?", "images": [], "options": {"A": "Provision for bad debt", "B": "Bad debts", "C": "Discounts allowed", "D": "Bills receivable"}, "answer": "A", "explanation": "Provision for bad debts is not credited to debtors control account. It is not an item of debtors control account. It is always ignored when it is given.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>26", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "Where a firm has not kept proper books of account, an increase in closing capital over opening capital represents", "images": [], "options": {"A": "profit", "B": "loss", "C": "prepayments", "D": "cash balance"}, "answer": "A", "explanation": "In accounting, capital represents the owner's investment in the business. An increase in closing capital over opening capital indicates that the business has made a profit during the period. This is because the profit increases the owner's equity in the business, which is reflected in the capital account. Therefore, where a firm has not kept proper books of account, an increase in closing capital over opening capital represents profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>27", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question  Dr &nbspRECEIPTS AND PAYMENTS ACCOUNT &nbsp Cr    Balance b/f  Subscriptions        D  1,000  15,000          Salaries   Rent   Rates  Expenses  Balance c/fD  2,000  1,000  1,500  500  11,00016,00016,000Balance b/f11,000  1st January, 200431st December, 2004  Fixed Assets   Rent (accrued)  Rates (prepaid)  Subscriptions in arrears  Subscriptions in advanceD  50,000  200  300  1,500  1,300D  50,000  250  400  1,000  800    Accumulated fund as at 1st January 2004 is", "images": [], "options": {"A": "D54,100", "B": "D52,800", "C": "D52,600", "D": "D51,300"}, "answer": "D", "explanation": "Statement of affairs as at 1/1/2004  ₦₦Accumulated Fixed  Liabilities  Rent accured  Subscription in adv.   ₦  51,300    200  1300     Assets  Fixed asset  Cash balance (opening)  Rate prepaid  Subscription in arrears₦    50,000  1,000  300  150052,80052,800  Accumulated fund = total assets - total liabilities  ⇒ 52,800 - 1,500  ⇒ D51,300", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>28", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question  Dr &nbspRECEIPTS AND PAYMENTS ACCOUNT &nbsp Cr    Balance b/f  Subscriptions        D  1,000  15,000          Salaries   Rent   Rates  Expenses  Balance c/fD  2,000  1,000  1,500  500  11,00016,00016,000Balance b/f11,000  1st January, 200431st December, 2004  Fixed Assets   Rent (accrued)  Rates (prepaid)  Subscriptions in arrears  Subscriptions in advanceD  50,000  200  300  1,500  1,300D  50,000  250  400  1,000  800  Subscriptions relating to the year 2004 is", "images": [], "options": {"A": "D19,600", "B": "D17,300", "C": "D16,500", "D": "D15,000"}, "answer": "D", "explanation": "This is the subscription in the receipt and payments account which is D15,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>29", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question  Dr &nbspRECEIPTS AND PAYMENTS ACCOUNT &nbsp Cr    Balance b/f  Subscriptions        D  1,000  15,000          Salaries   Rent   Rates  Expenses  Balance c/fD  2,000  1,000  1,500  500  11,00016,00016,000Balance b/f11,000  1st January, 200431st December, 2004  Fixed Assets   Rent (accrued)  Rates (prepaid)  Subscriptions in arrears  Subscriptions in advanceD  50,000  200  300  1,500  1,300D  50,000  250  400  1,000  800  Rates charged to the Income and Expenditure Account for the year 2004 is", "images": [], "options": {"A": "D2,200", "B": "D1,600", "C": "D1,500", "D": "D1,400"}, "answer": "D", "explanation": "The rates charged to the Income and Expenditure Account for the year 2004 is calculated by adding the rates paid during the year to the opening accrued rates and then subtracting the closing prepaid rates. From the data, rates paid during the year is D1,500, opening accrued rates is D200 and closing prepaid rates is D400. Therefore, the rates charged to the Income and Expenditure Account for the year 2004 is D1,500 + D200 - D400 = D1,300.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>30", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not an accounting concept?", "images": [], "options": {"A": "Periodicity", "B": "Accuracy", "C": "Consistency", "D": "Objectively"}, "answer": "B", "explanation": "Accuracy is not an accounting concept. The accounting concepts include: Periodicity, which refers to the idea that financial reports are prepared at regular intervals (usually annually); Consistency, which means that the same accounting methods should be used from one financial period to the next; and Objectivity, which means that financial information is based on evidence and can be verified by a third party. Accuracy, while important in accounting, is not a concept but rather a quality or characteristic of good accounting information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>31", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "'Transactions are governed by legal principles, but are nevertheless accounted for and presented in accordance with the substance and financial reality'. This is in compliance with the principles of", "images": [], "options": {"A": "substance over form", "B": "prudence", "C": "objectively", "D": "materiality"}, "answer": "A", "explanation": "The principle of 'substance over form' means that transactions should be accounted for and presented in accordance with their substance and economic reality, not merely their legal form. This principle ensures that the financial statements provide a complete, relevant and accurate picture of transactions and events. If an entity sells an asset to another entity, but the terms of the agreement retain significant risks and rewards of the asset to the first entity, the substance of the transaction is that the first entity continues to recognise the asset in its statement of financial position and to recognise a liability for the consideration received.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>32", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following statements is not correct?", "images": [], "options": {"A": "Profits increase capital", "B": "Losses reduce capital", "C": "Drawings reduce capital", "D": "Drawings increase capital"}, "answer": "D", "explanation": "Drawings refer to the money withdrawn from a business by its owner(s) for personal use. It reduces the capital in the business, not increase it. Therefore, the statement 'Drawings increase capital' is not correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>33", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Direct material + direct expenses is", "images": [], "options": {"A": "overhead", "B": "prime cost", "C": "total cost", "D": "conversion cost"}, "answer": "B", "explanation": "Prime cost is the total cost of direct materials and direct labor (also known as direct costs), that a company incurs when producing goods. It excludes indirect expenses such as distribution costs and sales force costs. Therefore, the sum of direct material and direct expenses is the prime cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>34", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Books of account are opened by means of a", "images": [], "options": {"A": "purchases journal", "B": "principal journal", "C": "sales journal", "D": "returns inward journal"}, "answer": "B", "explanation": "The principal journal, also known as the general journal, is the book of account where all the company's financial transactions are initially recorded. The other options like purchases journal, sales journal, and returns inward journal are all subsidiary books, which are used to record specific types of transactions. Therefore, books of account are opened by means of a principal journal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>35", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "When both debit and credit entries of a transaction are shown in the cash book, it is described as", "images": [], "options": {"A": "contra entry", "B": "reversal entry", "C": "double entry", "D": "single entry"}, "answer": "A", "explanation": "A contra entry is an entry that is recorded in the cash book when both the debit and credit aspects of a transaction relate to cash or bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>36", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "The correct order of liquidity is", "images": [], "options": {"A": "stock, debtors, prepayments and cash", "B": "cash, prepayments, debtors and stock", "C": "stock, cash, debtors and prepayments", "D": "debtors, stock, cash and prepayments"}, "answer": "A", "explanation": "Order of liquidity is the presentation of assets in the balance sheet in the order of the amount of time it would usually take to convert them into cash. Thus , cash is always presented first, followed by marketable securities, then accounts receivable, then inventory and then fixed assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>37", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following ratios measure the ability of a firm to meet short-term obligations?", "images": [], "options": {"A": "Net profit margin", "B": "Quick asset ratio", "C": "Turnover ratio", "D": "Creditors ratio"}, "answer": "B", "explanation": "The Quick Asset Ratio, also known as the Acid-Test Ratio, measures a company's ability to pay off its short-term obligations with its most liquid assets. It excludes inventory and prepayments which cannot be easily converted into cash. Therefore, it is a more stringent measure of liquidity than the current ratio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>38", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Which of the following is not an appropriation of profit?", "images": [], "options": {"A": "Dividends", "B": "Reserves", "C": "Provisions", "D": "Bonus issue"}, "answer": "C", "explanation": "Provisions are not an appropriation of profit. They are amounts set aside to cover a probable future liability or loss in the business. They are charged against profits in the income statement before the calculation of net profit. On the other hand, dividends, reserves, and bonus issues are appropriations of profit, which are distributions of profit after it has been calculated.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>39", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "RESERVES AND PROVISIONS : DIFFERENCES BETWEEN RESERVES AND PROVISIONS", "question": "Which of the following is a capital reserve?", "images": [], "options": {"A": "Profit and Loss Account balance", "B": "Share premium", "C": "Gross profit", "D": "Share discount"}, "answer": "B", "explanation": "A capital reserve is a type of account on a company's balance sheet that is reserved for long-term capital investment projects or any other large and anticipated expenses that will be incurred in the future. This type of reserve fund is set aside to ensure that the company has adequate funding to at least partially finance long-term projects or unexpected expenses. The Share premium account is a type of capital reserve. It is an account which forms part of a company's reserves, which are retained earnings and are therefore a component of the company's shareholders' equity. The share premium account represents the difference between the par value of the shares issued and the subscription or issue price. It's money that a company raises in an initial public offering (IPO) above the nominal value of the shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>40", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When shares are sold at less than the nominal value, it means they are issued at", "images": [], "options": {"A": "a premium", "B": "a loss", "C": "a discount", "D": "par"}, "answer": "C", "explanation": "When shares are sold at less than the nominal value, it means they are issued at a discount. The nominal value of a share, also known as the par value, is its face value as stated in the company's constitution. When shares are issued at a price less than the nominal value, they are said to be issued at a discount. This is typically done when a company is in urgent need of cash flow, or when it initially has difficulty finding buyers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>41", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Where goods are invoiced by a firm its branch at cost-plus, the branch stock adjustment account is used to determine", "images": [], "options": {"A": "cost price", "B": "branch profit", "C": "selling price", "D": "branch expenses"}, "answer": "B", "explanation": "When goods are invoiced by a firm to its branch at cost-plus, the branch stock adjustment account is used to determine the branch profit. This is because the cost-plus pricing method involves setting the price of a product by adding a profit margin to the cost of production. Therefore, any adjustment in the branch stock would affect the profit of the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>42", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Which of the following is apportioned in proportion of the purchases of each department?", "images": [], "options": {"A": "Discounts received", "B": "Selling commission", "C": "Bad debts", "D": "Carriage outwards"}, "answer": "A", "explanation": "Discount received is application in the proportion of purchases of each departments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>43", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer this question  The Accounts Department of a ministry had the following staff position on 31st December, 2004.  PostGradeNumber in PostRateChief Accountant  Asst. Chief Accountant  Principal Accountant  Accountant I  Clerk15  14  12  7  31  2  4  6  10N371,748  N301,452  N243,732  N113,632  N54,166  Additional Information:  (a) All employees are on the first step of their salary  (b) Allowances     Grade LevelTransport AllowanceHousing AllowanceResponsibility Allowance12 and above  1 to 7N24,000 per annum  N13,200 per annumN120,000 per annum  N48,000 per annumN30,000 per annum  -    The total basic salary for the year was", "images": [], "options": {"A": "N3,173,032", "B": "N3,048,000", "C": "N1,084,730", "D": "N855,600"}, "answer": "C", "explanation": "Basic salary = 371,748 + 301,452 + 243,732 + 113,632 + 54,166  ⇒ 1,084,730", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>44", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer this question  The Accounts Department of a ministry had the following staff position on 31st December, 2004.  PostGradeNumber in PostRateChief Accountant  Asst. Chief Accountant  Principal Accountant  Accountant I  Clerk15  14  12  7  31  2  4  6  10N371,748  N301,452  N243,732  N113,632  N54,166  Additional Information:  (a) All employees are on the first step of their salary  (b) Allowances     Grade LevelTransport AllowanceHousing AllowanceResponsibility Allowance12 and above  1 to 7N24,000 per annum  N13,200 per annumN120,000 per annum  N48,000 per annumN30,000 per annum  -  The total transport allowance was", "images": [], "options": {"A": "N552,000", "B": "N379,200", "C": "N211,200", "D": "N168,000"}, "answer": "B", "explanation": "The total transport allowance is calculated by multiplying the number of employees in each grade level by the transport allowance for that grade level, and then summing these values. The correct total is N379,200.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>45", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer this question  The Accounts Department of a ministry had the following staff position on 31st December, 2004.  PostGradeNumber in PostRateChief Accountant  Asst. Chief Accountant  Principal Accountant  Accountant I  Clerk15  14  12  7  31  2  4  6  10N371,748  N301,452  N243,732  N113,632  N54,166  Additional Information:  (a) All employees are on the first step of their salary  (b) Allowances     Grade LevelTransport AllowanceHousing AllowanceResponsibility Allowance12 and above  1 to 7N24,000 per annum  N13,200 per annumN120,000 per annum  N48,000 per annumN30,000 per annum  -  The total housing allowance was", "images": [], "options": {"A": "N1,608,000", "B": "N840,000", "C": "N2,760,000", "D": "N168,000"}, "answer": "A", "explanation": "The total housing allowance is calculated by multiplying the number of employees in each grade by the housing allowance for that grade. For grades 12 and above, the housing allowance is N120,000 per annum, and for grades 1 to 7, it is N48,000 per annum. Therefore, the total housing allowance is (1*120,000) + (2*120,000) + (4*120,000) + (6*48,000) + (10*48,000) = N1,608,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>46", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer this question  The Accounts Department of a ministry had the following staff position on 31st December, 2004.  PostGradeNumber in PostRateChief Accountant  Asst. Chief Accountant  Principal Accountant  Accountant I  Clerk15  14  12  7  31  2  4  6  10N371,748  N301,452  N243,732  N113,632  N54,166  Additional Information:  (a) All employees are on the first step of their salary  (b) Allowances     Grade LevelTransport AllowanceHousing AllowanceResponsibility Allowance12 and above  1 to 7N24,000 per annum  N13,200 per annumN120,000 per annum  N48,000 per annumN30,000 per annum  -  The responsibility allowance of grade levels 14 and 15 was", "images": [], "options": {"A": "N210,000", "B": "N90,000", "C": "N60,000", "D": "N30,000"}, "answer": "B", "explanation": "The responsibility allowance for grade levels 14 and 15 is N30,000 per annum. Therefore, the total responsibility allowance for these grades is (1*30,000) + (2*30,000) = N90,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2005>47", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "The part of the C.P.U used for the processing of data is", "images": [], "options": {"A": "Monory unit", "B": "Arithmetic and logic unit", "C": "Output unit", "D": "Input unit"}, "answer": "B", "explanation": "The Central Processing Unit (CPU) is the primary component of a computer that performs most of the processing inside the computer. It's often referred to as the 'brain' of the computer. The CPU has two components: the Control Unit and the Arithmetic Logic Unit (ALU). The ALU performs arithmetic and logical operations, which are the actual 'processing' of data. Therefore, the part of the CPU used for the processing of data is the Arithmetic and Logic Unit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2005>48", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Resources consumed but to be paid for within the next accounting period are classified in the balance sheet as", "images": [], "options": {"A": "current liabilities", "B": "current assets", "C": "long-term liabilities", "D": "capital"}, "answer": "A", "explanation": "In accounting, resources consumed but to be paid for within the next accounting period are classified as current liabilities. Current liabilities are obligations that a company expects to pay off within one year or within one operating cycle, whichever is longer. These may include accounts payable, short-term loans, or other similar obligations that are due within a short period of time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>49", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Where a proprietor withdraws stock for personal consumption, the accounting entries to record the transaction are", "images": [], "options": {"A": "debit Drawings Account, credit Purchases Account", "B": "debit Purchases Account, credit Drawings Account", "C": "debit Sales Account, credit Drawings Account", "D": "debit Drawings Account, credit Sales Account"}, "answer": "A", "explanation": "When a proprietor withdraws stock for personal use, it is considered as a drawing from the business. Therefore, the Drawings Account is debited (increased) to reflect the withdrawal. The Purchases Account is credited (decreased) because the stock (an asset) has reduced. Hence, the correct accounting entry is 'debit Drawings Account, credit Purchases Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2005>50", "subject": "Accounts", "year": "2005", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Where there is a loss on disposal of a fixed asset, it means", "images": [], "options": {"A": "depreciation has been underestimated", "B": "depreciation has been overestimated", "C": "scrap value has not been estimated", "D": "depreciation method used is inappropriate"}, "answer": "A", "explanation": "A loss on disposal of a fixed asset occurs when the selling price of the asset is less than its book value (cost - accumulated depreciation). This could be due to the fact that depreciation has been underestimated, meaning the asset's value has not been written down sufficiently over its useful life. Therefore, the correct answer is 'depreciation has been underestimated'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>1", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The art of collecting, recording, presenting and interpreting account data is", "images": [], "options": {"A": "cost accounting", "B": "management accounting", "C": "financial accounting", "D": "data accounting"}, "answer": "C", "explanation": "Financial accounting is the field of accounting concerned with the summary, analysis and reporting of financial transactions related to a business. This involves the preparation of financial statements available for public use. It includes the process of recording, summarizing, analyzing, and reporting financial transactions of a business to oversight agencies, regulators, and tax collection entities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>2", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "The depreciation method in which the number of years of the useful life of an asset is allocated in a reverse order is", "images": [], "options": {"A": "straight line", "B": "reducing balance", "C": "sum of years' digits", "D": "revaluation"}, "answer": "C", "explanation": "The sum of years' digits method is a type of accelerated depreciation method that front-loads the depreciation expense. It does this by applying a higher depreciation expense earlier in the life of an asset and lower expenses as the asset ages. This is done by creating a fraction where the numerator is the remaining useful life of the asset and the denominator is the sum of the years' digits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>3", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A system where a separate cash book is maintained for small payments is", "images": [], "options": {"A": "single entry", "B": "imprest", "C": "float", "D": "reimbursement"}, "answer": "B", "explanation": "A system where a separate cash book is maintained for small payments is known as an imprest system. The imprest system is a financial accounting system that is commonly used to manage petty cash. The term 'imprest' refers to money that is allocated for a specific purpose. In this case, the purpose is to cover small expenses. At the start of a period, the petty cash box is topped up to a set amount (the imprest). As money is spent, the box is gradually depleted, until it is replenished at the start of the next period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>4", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Public sector accounting is practiced in", "images": [], "options": {"A": "public limited companies", "B": "government organizations", "C": "profit making organizations", "D": "public trading companies"}, "answer": "B", "explanation": "Public sector accounting is practiced in government organizations. Public sector accounting refers to the process of recording, communicating, summarizing, analyzing and interpreting the financial statements and statistics of government in aggregate and details. It is concerned with the receipts, custody, disposal and rendering of stewardship on public funds entrusted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>5", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "A book that contains the account for the financial transactions of an organization is the", "images": [], "options": {"A": "journal", "B": "ledger", "C": "folio", "D": "register"}, "answer": "B", "explanation": "A ledger is a book that contains the account for the financial transactions of an organization. It is where all the transactions are posted by debiting and crediting the accounts. A journal, on the other hand, is a book of original entry where transactions are recorded for the first time. A folio is a page number in a ledger or a journal. A register is a record of a specific type of transaction, like a sales register or a purchase register.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>6", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "A sales ledger contains", "images": [], "options": {"A": "creditor's accounts", "B": "nominal accounts", "C": "real accounts", "D": "debtor's accounts"}, "answer": "D", "explanation": "A sales ledger contains debtor's accounts. It is a subsidiary ledger that records all the details of sales on credit to customers or debtors. Creditor's accounts are contained in the purchase ledger. Nominal accounts are income and expense accounts that are reported in the income statement. Real accounts are asset, liability, and equity accounts that are reported in the balance sheet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>7", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Books of account consists of", "images": [], "options": {"A": "ledger and subsidiary books", "B": "ledger and principal books", "C": "folio and subsidiary books", "D": "ledgers and cash books"}, "answer": "A", "explanation": "Books of account consist of the ledger and subsidiary books. The ledger is the principal book to which all business transactions are posted from the journal. Subsidiary books are books of original entry and include the sales book, purchases book, returns inwards book, returns outwards book, cash book, and journal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>8", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "The amount set aside out of profits earned by a company which are not meant for liability or contingency are", "images": [], "options": {"A": "dividends", "B": "provisions", "C": "retained profits", "D": "reserves"}, "answer": "D", "explanation": "The amount set aside out of profits earned by a company which are not meant for liability or contingency are reserves. Reserves are part of a company's profits, which have been set aside to strengthen the business financial position. They are retained earnings that have been kept for future use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>9", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The basis of accounting which eliminates debtors and creditors is", "images": [], "options": {"A": "cash basis", "B": "accrual basis", "C": "fund basis", "D": "commitment basis"}, "answer": "A", "explanation": "The cash basis of accounting recognizes transactions only when there is an exchange of cash. This means that it does not recognize debtors (people who owe money) and creditors (people who are owed money). This is because these transactions do not involve an immediate exchange of cash. On the other hand, the accrual basis of accounting recognizes transactions when they occur, regardless of when the cash is exchanged. Therefore, it recognizes both debtors and creditors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>10", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Which of the following is not a revenue account?", "images": [], "options": {"A": "Sales", "B": "Purchase", "C": "Discount received", "D": "Interest received"}, "answer": "B", "explanation": "A revenue account is an account that tracks the income of a business. This includes sales, discounts received, and interest received. These are all forms of income for the business. However, purchases are not a form of income. Instead, they are an expense. Therefore, the purchase account is not a revenue account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>11", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Use the following information to answer this question.      ₦Ordinary shares of ₦ 1 each 500 0008% preference shares of ₦ 1 each 200 000Interim dividends paid: - Ordinary shares 40 000- Preference shares 12 000Profit for the year 100 000     If the profits is to be retained, proposed preference shares dividend is", "images": [], "options": {"A": "₦28,000", "B": "₦16,000", "C": "₦12,000", "D": "₦4,000"}, "answer": "B", "explanation": "Preference shares are those that have a fixed dividend rate. In this case, the preference shares have an 8% dividend rate. The total value of preference shares is ₦200,000. Therefore, the total dividend for preference shares is 8% of ₦200,000 which equals ₦16,000. Since ₦12,000 interim dividends have already been paid, the proposed preference shares dividend to be retained is ₦16,000 - ₦12,000 = ₦4,000. However, the question asks for the total proposed dividend, not the remaining amount, so the answer is ₦16,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>12", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Use the following information to answer this question.      ₦Ordinary shares of ₦ 1 each 500 0008% preference shares of ₦ 1 each 200 000Interim dividends paid: - Ordinary shares 40 000- Preference shares 12 000Profit for the year 100 000   If no profit is to be retained, proposed ordinary shares dividend is", "images": [], "options": {"A": "₦48,000", "B": "₦44,000", "C": "₦40,000", "D": "₦28,000"}, "answer": "C", "explanation": "Proposed ordinary shares dividends   = 8% x ₦500,000  = ₦40,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>13", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Use the following information to answer this question.      ₦Ordinary shares of ₦ 1 each 500 0008% preference shares of ₦ 1 each 200 000Interim dividends paid: - Ordinary shares 40 000- Preference shares 12 000Profit for the year 100 000   The dividend per ordinary share for the year is", "images": [], "options": {"A": "₦0.88 kobo", "B": "₦0.40 kobo", "C": "₦0.20 kobo", "D": "₦0.17 kobo"}, "answer": "C", "explanation": "The dividend per ordinary share is calculated by dividing the total dividends paid to ordinary shareholders by the total number of ordinary shares. In this case, the total dividends paid to ordinary shareholders is ₦40,000 and the total number of ordinary shares is 500,000. Therefore, the dividend per ordinary share is ₦40,000 / 500,000 = ₦0.08 or 0.08 kobo. However, none of the options match this answer. The closest option is ₦0.20 kobo, but this is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>14", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "A customer who returns goods to the supplier because they are defective is issued a", "images": [], "options": {"A": "debit note", "B": "credit note", "C": "delivery note", "D": "bank note"}, "answer": "B", "explanation": "When a customer returns defective goods to the supplier, the supplier issues a credit note to the customer. This document serves as a proof that the supplier owes the customer the value of the returned goods. This reduces the amount the customer owes the supplier in their accounts payable. Therefore, the correct answer is a credit note.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>15", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Cross referencing among difference books of accounts is achieved with the use of", "images": [], "options": {"A": "columns", "B": "reference numbers", "C": "folio", "D": "margin"}, "answer": "B", "explanation": "Cross referencing among different books of accounts is achieved with the use of reference numbers. Reference numbers are used to track transactions across different books of accounts. They provide a way to quickly locate and verify transactions, making it easier to maintain accuracy and consistency in accounting records.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>16", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "In company accounts, profit after tax is shared in the", "images": [], "options": {"A": "appropriation account", "B": "revaluation account", "C": "current account", "D": "realization account"}, "answer": "A", "explanation": "In company accounts, profit after tax is shared in the appropriation account. The appropriation account is a part of the company's financial statements that details how the company's net income is distributed, including dividends and retained earnings. It is used to show how the profits of the company are 'appropriated' or divided up and used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>17", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is not a source of revenue to a government?", "images": [], "options": {"A": "Taxation", "B": "Sales of goods", "C": "Imposition of fines", "D": "Grants"}, "answer": "B", "explanation": "Sales of goods is not a source of revenue to a government. A government's revenue is primarily derived from taxes, fines, and grants. Sales of goods is a source of revenue for businesses, not governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>18", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question.     Ebrima Jaiteh  D D Capital 2 000 10 000Drawings 4 0003 000Salary - 900Profit sharing ratio 3/5 2/5   Profit for the year before 5% interest on capital was D18, 000    Ebrima's share of profit was", "images": [], "options": {"A": "D10,440", "B": "D9,900", "C": "D7,560", "D": "D6,600"}, "answer": "B", "explanation": "Dr. Partnership Appropriation A/c Cr.  D   D Interest on capital  Net profit 18 000Ebrima 5%x2000 100  Jaiteh 5%x10 000 500  Salary : Jaiteh900    share of profit   Ebrima 9 900  Jaitel 6 600    18 000  18 000    Profit = 100 + 500 + 900 = 1500  = 18,000 - 1,500  = 16,500    Share of profit Ebrima = 3/5 x 16, 500 = D9, 900  Share of profit Jaiteh = 2/5 x 16, 500 = D6, 600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>19", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question.     Ebrima Jaiteh  D D Capital 2 000 10 000Drawings 4 0003 000Salary - 900Profit sharing ratio 3/5 2/5   Profit for the year before 5% interest on capital was D18, 000   Jaiteh's share of profit was", "images": [], "options": {"A": "D10,440", "B": "D9,900", "C": "D7,560", "D": "D6,600"}, "answer": "D", "explanation": "Share of profit for Jaiteh     = 2/5 x 16, 500     = D6, 600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>20", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Whatever is fed into the computer is exactly what would be processed and produced as output. This is the concept of", "images": [], "options": {"A": "sorting out", "B": "last in, first out", "C": "first in, first out", "D": "garbage in, garbage out"}, "answer": "D", "explanation": "The concept that whatever is fed into the computer is exactly what would be processed and produced as output is known as 'Garbage In, Garbage Out'. This concept is based on the fact that computers will unquestioningly process the most nonsensical of input data ('garbage in') and produce nonsensical output ('garbage out').", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>21", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Bank reconciliation statement reconciles", "images": [], "options": {"A": "bank and cash balances in the cash book", "B": "bank balance in the cash book and bank statement balance", "C": "cash balance in the cash book and bank statement balance", "D": "bank balance brought down and bank balance carried down in the cash book"}, "answer": "B", "explanation": "A bank reconciliation statement is a statement prepared by the entity as part of its internal control mechanism to check the accuracy of the bank balances shown in the bank column of the cash book. It reconciles the bank balance as per company's accounting records with the bank balance as per the bank statement. Therefore, it reconciles the bank balance in the cash book and bank statement balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>22", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The unit which keeps government's books accounts is the", "images": [], "options": {"A": "central bank", "B": "Internal Audit Department", "C": "Treasure Department", "D": "Accountant General's Department"}, "answer": "C", "explanation": "Treasury department is the unit which keeps government's books of account involving the management of money.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>23", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is not a debit in a partnership appropriation account?", "images": [], "options": {"A": "Interest on drawings", "B": "partners salary", "C": "Interest on partner's capital", "D": "Share of profit"}, "answer": "A", "explanation": "Interest on drawing is always found on the credit side of the partnership appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>24", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question.       LeCash in hand 15 000Balance as at 1st January 2005: Subscription in arrears 6 000Subscriptions in advance 2 500Subscription received 18 000Expenses for the year 6 500Balance as at 31st December 2005: Subscriptions in arrears 3 000Subscriptions in advance 1 500    Accumulated fund at the beginning of the year was", "images": [], "options": {"A": "Le 23, 500", "B": "Le 18,500", "C": "Le 11,500", "D": "Le 8,500"}, "answer": "B", "explanation": "Statement of affairs as at 1st January, 2005     Le  LeAccumulated fund 18 500 Current Asset:    Cash 15 000Current liabilities  Subscription in arrears 6 000Subscription in advance 2 500    21 000  21 000    Accumulate fund = Total assets - Total Liabilities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>25", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question.       LeCash in hand 15 000Balance as at 1st January 2005: Subscription in arrears 6 000Subscriptions in advance 2 500Subscription received 18 000Expenses for the year 6 500Balance as at 31st December 2005: Subscriptions in arrears 3 000Subscriptions in advance 1 500  Subscriptions credited to the Income and Expenditure Account was", "images": [], "options": {"A": "Le 23,500", "B": "Le 18,000", "C": "Le 16,000", "D": "Le 13,000"}, "answer": "C", "explanation": "The subscriptions credited to the Income and Expenditure Account is calculated as follows: Subscriptions received during the year (Le 18,000) plus Subscriptions in arrears at the beginning of the year (Le 6,000) minus Subscriptions in arrears at the end of the year (Le 3,000) minus Subscriptions in advance at the beginning of the year (Le 2,500) plus Subscriptions in advance at the end of the year (Le 1,500). This gives a total of Le 16,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>26", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question.       LeCash in hand 15 000Balance as at 1st January 2005: Subscription in arrears 6 000Subscriptions in advance 2 500Subscription received 18 000Expenses for the year 6 500Balance as at 31st December 2005: Subscriptions in arrears 3 000Subscriptions in advance 1 500  The excess of income over expenditure for the year was", "images": [], "options": {"A": "Le 16,500", "B": "Le 11,500", "C": "Le 9,500", "D": "Le 6,500"}, "answer": "C", "explanation": "Income: 16 000Expenses 6 500Surplus 9 500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>27", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Revenue is recognised in the profit and loss account as soon as a", "images": [], "options": {"A": "debtor pays what is due from him", "B": "sale of goods takes place and money is received", "C": "sale of goods takes place whether or not money is received", "D": "sale of fixed asset takes place"}, "answer": "C", "explanation": "Revenue is recognized when it is earned, not necessarily when it is received. This is known as the accrual basis of accounting. Therefore, revenue is recognized when a sale of goods takes place, whether or not money is received. This is in line with the revenue recognition principle which states that revenue should be recognized and recorded when it is realized or realizable and when it is earned, not when cash is received.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>28", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A business unit is assumed to operate into forseable future and earn reasonable net income. This statement is emphasized by the concept of", "images": [], "options": {"A": "business entity", "B": "going concern", "C": "realization", "D": "accrual"}, "answer": "B", "explanation": "The statement refers to the 'going concern' concept in accounting. This concept assumes that a business will continue to operate indefinitely, or at least for the foreseeable future. It is on this basis that the company can defer some of its prepaid expenses to future accounting periods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>29", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "Which of the following is not used in solving problems of incomplete records?", "images": [], "options": {"A": "Control Accounts", "B": "Statement of affairs", "C": "Cash book", "D": "Balance sheet"}, "answer": "D", "explanation": "In the context of incomplete records, a balance sheet is not used to solve problems. Incomplete records, also known as single-entry bookkeeping, is a system of bookkeeping where only one side of each transaction is recorded. The tools used to solve problems in this system are Control Accounts, Statement of Affairs, and Cash Book. A balance sheet, on the other hand, is a financial statement that reports a company's assets, liabilities, and shareholders' equity at a specific point in time, and provides a basis for computing rates of return and evaluating its capital structure. It is not used in the context of incomplete records because it requires complete double-entry bookkeeping to prepare.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>30", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "In a system of incomplete records, the opening capital is determined by preparing", "images": [], "options": {"A": "statement of affairs", "B": "balance sheet", "C": "cash book", "D": "trial balance"}, "answer": "A", "explanation": "In a system of incomplete records, the opening capital is determined by preparing a Statement of Affairs. A Statement of Affairs is a financial statement that shows the assets, liabilities, and capital of a business at a particular point in time. It is used in single-entry bookkeeping or in cases where a full set of financial statements is not prepared. It is similar to a balance sheet, but it is prepared when the records are incomplete. The other options, Balance Sheet, Cash Book, and Trial Balance, are not used to determine the opening capital in a system of incomplete records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>31", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.   DOpening stock: raw materials 10 000Work-in-progress 16 000Purchase of raw materials 95 500Direct labour wages paid 13 500Royalties paid 6 200Accrued wages 2 800Closing stock: raw materials 7 500Work-in-progress 8 500Manufacturing overhead 10 000    Cost of raw materials consumed is", "images": [], "options": {"A": "D113,000", "B": "D 105,500", "C": "D98,000", "D": "D95,500"}, "answer": "C", "explanation": "The cost of raw materials consumed is calculated by adding the opening stock of raw materials to the purchase of raw materials and then subtracting the closing stock of raw materials. So, the calculation would be: 10,000 + 95,500 - 7,500 = 98,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>32", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.   DOpening stock: raw materials 10 000Work-in-progress 16 000Purchase of raw materials 95 500Direct labour wages paid 13 500Royalties paid 6 200Accrued wages 2 800Closing stock: raw materials 7 500Work-in-progress 8 500Manufacturing overhead 10 000  Prime cost is", "images": [], "options": {"A": "D120,500", "B": "D117,700", "C": "D114,900", "D": "D 114,300"}, "answer": "B", "explanation": "manufacturing account   DOpening stock of raw materials 10 000Add: purchase of raw materials 95 500Less: closing stock of raw materials 7 500Cost of raw materials consumed 98 000Add : royalties6 200Direct labour13 500Prime cost117 700", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>33", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.   DOpening stock: raw materials 10 000Work-in-progress 16 000Purchase of raw materials 95 500Direct labour wages paid 13 500Royalties paid 6 200Accrued wages 2 800Closing stock: raw materials 7 500Work-in-progress 8 500Manufacturing overhead 10 000  Cost of goods manufactured is", "images": [], "options": {"A": "D 138,000", "B": "D 131,800", "C": "D130,500", "D": "D123,000"}, "answer": "A", "explanation": "manufacturing account   DOpening stock of raw materials 10 000Add: purchase of raw materials 95 500Less: closing stock of raw materials 7 500Cost of raw materials consumed 98 000[Add : royalties|6 200][Direct labour|13 500][Prime cost|117 700][Add:factory overhead|][Manufacturing overhead|10 000][Accrued wages| 2 800 ][                         |130 500][Add: opening stock of WIP|16 000][Less: closing stock of WIP| 8 500 ][Cost of goods manufactured| 138 000]}}", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>34", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES", "question": "A set of instructions fed into a computer for accomplishing a given task is a/an", "images": [], "options": {"A": "input", "B": "programme", "C": "output", "D": "data"}, "answer": "B", "explanation": "A set of instructions fed into a computer for accomplishing a given task is known as a program. A program is a sequence of instructions that a computer can interpret and execute. The instructions tell the computer what to do and how to do it. Therefore, the correct answer is 'programme'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>35", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "Control accounts are also known as", "images": [], "options": {"A": "contra accounts", "B": "total account", "C": "ledger accounts", "D": "integral accounts"}, "answer": "B", "explanation": "Control accounts are also known as total accounts. A control account, often called a controlling account, is a general ledger account that summarizes and combines all of the subsidiary accounts for a specific type. In other words, it's a summary account that equals the sum of the subsidiary account and is used to simplify and organize the general ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>36", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following is charged to trading account?", "images": [], "options": {"A": "Discounts allowed", "B": "Carriage outwards", "C": "Salaries", "D": "Carriage inwards"}, "answer": "D", "explanation": "Carriage inwards is charged to trading account. Carriage inwards refers to the transportation costs incurred by a business in receiving goods it has purchased. These costs are added to the cost of goods purchased when calculating the cost of goods sold. The cost of goods sold is deducted from sales in the trading account to calculate gross profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>37", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not a debit item in a creditor's control account?", "images": [], "options": {"A": "Cash paid", "B": "Return outwards", "C": "Purchases", "D": "Discount received"}, "answer": "C", "explanation": "In a creditor's control account, purchases are not a debit item. A creditor's control account is a summary account in the general ledger. This account contains only summary entries and is supported by detailed information that is maintained in the subsidiary ledger. The debit side of the creditor's control account includes returns outwards, cash paid, and discounts received. Purchases are credited to the account because they increase the amount owed to creditors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>38", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions.  Motor vehicle (at cost) 1/1/2002 -----  ₦1 000 000   Addition to motor vehicles 1/7/2003  ------- ₦600 000  Depreciation rate 10%    Use the straight line method, the depreciation charged for year 2002 was", "images": [], "options": {"A": "₦160,000", "B": "₦130, 000", "C": "₦100,000", "D": "₦60,000"}, "answer": "A", "explanation": "Using straight line method.   Depreciation=Cost - Scrap valueNo. of years    But rate is given, so we use the rate   Depreciation for the second year = 10% X 1,000,000  = ₦100,000    Depreciation for the second year = 10% x 60,000  = ₦60,000    The accumulated depreciation is = ₦(100,000 + 60,000)   = ₦160,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>39", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions.  Motor vehicle (at cost) 1/1/2002 -----  ₦1 000 000   Addition to motor vehicles 1/7/2003  ------- ₦600 000  Depreciation rate 10%   using the reducing balance method, the depreciation charged for the year 2003 was", "images": [], "options": {"A": "₦160,000", "B": "₦90,000", "C": "₦80,000", "D": "₦60,000"}, "answer": "A", "explanation": "Depreciation charged = 10% x ₦1,000,000  = ₦100,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>40", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this questions.  Motor vehicle (at cost) 1/1/2002 -----  ₦1 000 000   Addition to motor vehicles 1/7/2003  ------- ₦600 000  Depreciation rate 10%   Using the reducing balance method, the depreciation charged for the year 2003 was", "images": [], "options": {"A": "₦160,000", "B": "₦150,000", "C": "₦130,000", "D": "₦120,000"}, "answer": "B", "explanation": "For 2003, depreciation charged is calculated thus, for year 1, Depreciation = ₦100,000   the net book value = ₦100,000 - ₦100,000  = ₦900,000    There is addition to major vehicles in 2003 i.e.   = ₦900,000 + ₦600,000  = ₦1,500,000    Depreciation charged = 10% x 1,500,000  = ₦150,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>41", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following is not a revenue expenditure?", "images": [], "options": {"A": "Payment of salaries", "B": "payment for advertisement", "C": "Purchases of motor vehicle", "D": "Purchases of goods"}, "answer": "C", "explanation": "Revenue expenditure is an amount that is expensed immediately. It includes payments for salaries, advertisement, and purchases of goods. However, the purchase of a motor vehicle is a capital expenditure, not a revenue expenditure. Capital expenditures are investments in a company's future; they create benefits over a long period, unlike revenue expenditures, which are fully consumed within a short period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>42", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The amount allowed off the cost price of an article to stimulate patronage is", "images": [], "options": {"A": "cash discount", "B": "trade discount", "C": "discount on debts", "D": "discount on bills"}, "answer": "B", "explanation": "A trade discount is a reduction in the listed price of an item that is allowed by the seller to the buyer, usually to encourage bulk buying or repeat business. It is different from a cash discount, which is an incentive offered by the seller to the buyer for paying off the debt owed before the due date. Discount on debts and discount on bills are not directly related to stimulating patronage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>43", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Which of the following is a Journal as well as an account?", "images": [], "options": {"A": "Sales day book", "B": "Cash book", "C": "General journal", "D": "Purchases journal"}, "answer": "B", "explanation": "A cash book is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger. Therefore, it serves as both a journal (for recording transactions) and an account (for showing the balance of cash on hand).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2006>44", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "CASH BOOK : THREE COLUMN CASH BOOK", "question": "Which of the following columns of a three column cash book are memoranda?     I. Discount received   II. Discount allowed   III. cash   IV. Bank", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "III and IV only"}, "answer": "A", "explanation": "In a three column cash book, the columns for 'Discount received' and 'Discount allowed' are considered memoranda columns. These columns are used to record discounts on transactions, but they do not affect the cash or bank balance. Therefore, they are not part of the double entry system, but are recorded for informational purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>45", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "use the following information to answer this question      DBalance as per cash book 8 400Bank charges 300Standing order paid 2 500Unpresented cheque 2 800    The adjusted cash book balance is", "images": [], "options": {"A": "D 11,200", "B": "D 8,400", "C": "D 6,200", "D": "D 5,600"}, "answer": "D", "explanation": "The adjusted cash book balance is calculated by subtracting the bank charges and standing order paid from the balance as per cash book. So, 8400 - 300 - 2500 = 5600.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2006>46", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "use the following information to answer this question      DBalance as per cash book 8 400Bank charges 300Standing order paid 2 500Unpresented cheque 2 800  The balance as per bank statement is", "images": [], "options": {"A": "D 10,900", "B": "D 8,400", "C": "D 5,600", "D": "D2,800"}, "answer": "B", "explanation": "Bank Reconciliation Statement     ₦Balance as per adjusted cash book 5 600Add: Unpresented cheque 2 800 Balance as per banks statement 8 400", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>47", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "Where the head office maintains all books of account, goods sent to branch is credited to", "images": [], "options": {"A": "Goods sent to Branch Account", "B": "Branch Stock Account", "C": "Branch Stock Adjustment Account", "D": "head Office Current Account"}, "answer": "A", "explanation": "When the head office sends goods to its branch, it is credited to the 'Goods sent to Branch Account'. This is because in accounting, a credit to an account signifies an increase in liabilities, income or equity or a decrease in assets or expenses. In this case, the head office is decreasing its assets (goods) by sending them to the branch, hence the credit to the 'Goods sent to Branch Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>48", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "Which of the following is not a purpose for preparing departmental accounts? To", "images": [], "options": {"A": "compare the results to different departments", "B": "employ staff into different departments", "C": "reward departmental managers", "D": "obtain information for formulating policies"}, "answer": "B", "explanation": "Departmental accounts are prepared for a number of reasons, including to compare the results of different departments, to reward departmental managers based on performance, and to obtain information for formulating policies. However, employing staff into different departments is not a purpose for preparing departmental accounts. This is a human resources function, not an accounting function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>49", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question.    DRent accrued 1st January , 2005 600Rent paid in 2005 11 300Rent prepaid 31st December, 2005 500    Rent expenses for the year 2005 is", "images": [], "options": {"A": "₦ 11,400", "B": "₦ 11,300", "C": "₦ 11,200", "D": "₦ 10,200"}, "answer": "D", "explanation": "Rent paid in 2005 - Rent accrued in January. 2005 - Rent prepaid in 31st December  ₦(11, 300- 600 - 500)   = ₦10,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2006>50", "subject": "Accounts", "year": "2006", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not classified as an overhead?", "images": [], "options": {"A": "Factory rates", "B": "Factory power", "C": "Factory building extension", "D": "Factory depreciation"}, "answer": "C", "explanation": "Overhead costs are all costs on the income statement except for direct labor, direct materials, and direct expenses. Overhead costs include rent, utilities, office supplies, and other miscellaneous expenses that are necessary to keep a business running. Factory building extension is a capital expenditure, not an overhead cost. It is a one-time expense for the long-term asset of a company, not a recurring expense like the other options.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>1", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The manufacturing account is prepared to determine the cost of", "images": [], "options": {"A": "trading", "B": "production", "C": "factory overhead", "D": "raw materials used"}, "answer": "B", "explanation": "The manufacturing account is prepared to determine the cost of production. It is a statement that shows the detailed components of total cost of production. It is prepared to ascertain the production cost of goods completed during a specific period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>2", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Factory costs excluding prime cost is", "images": [], "options": {"A": "overhead", "B": "material cost", "C": "fixed cost", "D": "administration cost"}, "answer": "A", "explanation": "Factory costs excluding prime cost is overhead. Prime cost is the direct costs of a product i.e., direct materials and direct labor. Overhead costs are the indirect costs that cannot be directly attributed to the production. These include costs such as rent, utilities, and maintenance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>3", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "An example of direct expense is", "images": [], "options": {"A": "insurance", "B": "carriage inwards", "C": "purchase of raw materials", "D": "royalty"}, "answer": "D", "explanation": "Royalty and direct wages are costs that  relate to a production unit specifically on a particular product and every unit produced", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>4", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is not shown in the trial balance?", "images": [], "options": {"A": "Opening Stock", "B": "Closing Stock", "C": "Discount allowed", "D": "Discount received"}, "answer": "B", "explanation": "A trial balance is a bookkeeping worksheet in which the balances of all ledgers are compiled into debit and credit account column totals that are equal. The closing stock is not shown in the trial balance because it is not a ledger account. It is a part of the trading account and is shown on the credit side of the trading account and assets side of the balance sheet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>5", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Financial accounting information is for", "images": [], "options": {"A": "internal use only", "B": "external use only", "C": "business use only", "D": "internal and external use"}, "answer": "D", "explanation": "Financial accounting information is used both internally by management and externally by other interested parties including investors, creditors, and regulators. Therefore, it is for both internal and external use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>6", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following statement is not true?", "images": [], "options": {"A": "A trial balance is an account having debit and credit sides", "B": "Expenses, loses and assets have debit balances", "C": "Revenue, gains and liabilities have credit balances", "D": "None of the above"}, "answer": "D", "explanation": "- Trial balance have both debit and credit side  - Expenses and asset have a debit balance  - Revenue, income, gain and liabilties have credit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>7", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "Adobawale extracted a trial balance on 31st December 2005 and realized that the total debit balance exceeded the total of credit balance. Pending investigation the difference should be", "images": [], "options": {"A": "debited to suspense account", "B": "credited to suspense account", "C": "debited to asset account", "D": "credited to asset account"}, "answer": "B", "explanation": "The difference is credited to suspense account  till  the error is detected and corrected when the debit side of trial balances is greater than the credit side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>8", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "A debit entry in the Cash Account and a corresponding credit entry in Alieu's Account indicate a", "images": [], "options": {"A": "receipt of cash to Alieu", "B": "payment of cash to Alieu", "C": "Sale of goods Alieu for cash", "D": "purchase of goods from Alieu for cash"}, "answer": "A", "explanation": "There was a receipt of cash from Alieu.It followed the principle of double entry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>9", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : PREPARATION OF FINAL ACCOUNTS FROM INCOMPLETE RECORDS", "question": "Use the following information to answer this question.    ₦Opening stock 1 800Closing stock 1 350Creditors - 1/01/2004 1 275Creditors - 31/1/12/2004 1 140Cash paid to creditors 6 900Debtors 1/01/2004 465 Cash received from debtors 11 130Debtors 31/12/2004 300    Sales for the year was", "images": [], "options": {"A": "₦11,430", "B": "₦11,295", "C": "₦11,130", "D": "₦10,965"}, "answer": "D", "explanation": "Debtor's Account     ₦   ₦Bal b/f 465 cash rec. 11 130Credit sales 10 965 Bal.c/d 300  11 430  11 430       Creditors A/c   Cash paid 6 900 Bal.b/f 1 275Bal.c/d 1 140 Credit Purchased 6 765   8 040  8 040", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>10", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : PREPARATION OF FINAL ACCOUNTS FROM INCOMPLETE RECORDS", "question": "Use the following information to answer this question.    ₦Opening stock 1 800Closing stock 1 350Creditors - 1/01/2004 1 275Creditors - 31/1/12/2004 1 140Cash paid to creditors 6 900Debtors 1/01/2004 465 Cash received from debtors 11 130Debtors 31/12/2004 300  Cost of sales for the year was", "images": [], "options": {"A": "₦10,965", "B": "₦8,565", "C": "₦7,215", "D": "₦6,765"}, "answer": "C", "explanation": "Cost of Sales = Opening + Purchases - Closing stock    = ₦(1,800 + 6,765 -1350)   = ₦7,215", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>11", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer this question.    ₦Opening stock 1 800Closing stock 1 350Creditors - 1/01/2004 1 275Creditors - 31/1/12/2004 1 140Cash paid to creditors 6 900Debtors 1/01/2004 465 Cash received from debtors 11 130Debtors 31/12/2004 300  Gross profit for the year was", "images": [], "options": {"A": "₦4,650", "B": "₦4,200", "C": "₦3,750", "D": "₦2,400"}, "answer": "C", "explanation": "Gross profit = Sale - cost of sales = 10,965 - 7 215 = ₦3,750", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2007>12", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "The total of the Sales  Journal is posted to the", "images": [], "options": {"A": "credit side of sales ledger", "B": "credit side of sales account", "C": "debit sides ledger", "D": "debit side of sales account"}, "answer": "B", "explanation": "The total of the journal is posted on the credit side of the sales account. This is because when a sale is made, the sales account is credited. This is in accordance with the double-entry bookkeeping system where every transaction is recorded in two accounts: a debit in one account and a credit in another. The sales account is a revenue account and increases on the credit side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>13", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "A rent of 12,000 was paid by Taiwo to his landlord by cheque. The double entry in Taiwo's books is", "images": [], "options": {"A": "debit Rent Account, credit Bank Account", "B": "debit Rent Account, credit Taiwo's Account", "C": "debit Bank Account, credit Rent Account", "D": "debit Taiwo's Account, credit Rent Account"}, "answer": "A", "explanation": "When Taiwo pays rent, he is reducing his bank balance and increasing his expenses. In double entry bookkeeping, an expense is debited and the bank account is credited. Therefore, the correct entry is 'Debit Rent Account, Credit Bank Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>14", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "The sum of money given to a petty cashier out of which small payments are made is a/an", "images": [], "options": {"A": "bonus", "B": "loan", "C": "advance", "D": "float"}, "answer": "D", "explanation": "The sum of money given to a petty cashier for making small payments is known as a petty cash float. This is a small amount of cash kept on hand to pay for minor expenses, such as postage due, reimbursement of small amounts, etc. Therefore, the correct answer is 'float'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>15", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "The total of the discount from creditor is transferred to", "images": [], "options": {"A": "credit side of Discounts Received Account", "B": "debit side of Discounts Received Account", "C": "credit side of Discounts Allowed Account", "D": "debit side of Discounts Allowed"}, "answer": "A", "explanation": "The total of the discount from creditors is transferred to the credit side of the Discounts Received Account. This is because when a business receives a discount from its creditors, it is considered as an income or gain for the business. In accounting, incomes or gains are credited. Therefore, the Discounts Received Account is credited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>16", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "The profit of a sole trader increases his", "images": [], "options": {"A": "stock", "B": "asset", "C": "liability", "D": "capital"}, "answer": "D", "explanation": "The profit of a sole trader increases his capital. In the context of a sole proprietorship, the owner's capital account is increased by the profits earned by the business. This is because the profits are essentially the owner's earnings, and thus increase the amount of capital they have invested in the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>17", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the information to answer this question    ₦Balance as per cash book 8 000CrUnpresented cheques 14 400Uncredited cheques 2 600    A cheque for ₦2,000 paid to a creditor had been entered in error in the cash column. bank commission of ₦800 had not been entered in the cash book. The credit side of the cash book (bank column) had been undercast by ₦5,000    The adjusted balance as per cash book is", "images": [], "options": {"A": "₦10,800 Cr", "B": "₦5,800 Cr", "C": "₦5,800 Dr", "D": "₦10,800 Dr"}, "answer": "B", "explanation": "Dr. Adjusted Cash Book Cr.     ₦  ₦Under cast 5 000 Bal. b/f 8 000Bal. c/d 5 800 Creditors 2 000   Bank commission 800  10 800  10 800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2007>18", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the information to answer this question    ₦Balance as per cash book 8 000CrUnpresented cheques 14 400Uncredited cheques 2 600    A cheque for ₦2,000 paid to a creditor had been entered in error in the cash column. bank commission of ₦800 had not been entered in the cash book. The credit side of the cash book (bank column) had been undercast by ₦5,000  The balance as per bank statement is", "images": [], "options": {"A": "₦8,000 Cr", "B": "₦6,000 Cr", "C": "₦6,000 Dr", "D": "₦8,000 Dr"}, "answer": "B", "explanation": "Dr. Bank Reconciliation Statement Cr.   Bal. as per cash book (5800)Unpresented cheques 14 000  8 600Less: Uncredited cheques 2 600Bal. as per bank statement 6 000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>19", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question.    Rent receivable accrued 1/01/2005 D3,000  Rent received during the year 2005 D5,000  Rent receivable accrued 31/12/2005 D2,500    The entry for rent received in the profit and loss account for the year ended 31st December 2005 is", "images": [], "options": {"A": "credit profit and loss account with D4,500", "B": "credit profit and loss account with D2,500", "C": "debit profit and loss account with D2,500", "D": "debit profit and loss account D4,500"}, "answer": "D", "explanation": "Dr. Rent received account Cr.     D  DBal b/f 3 000 Cash 5 000Profit and loss 4 500 Bal b/d 2 500      7 500  7 500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>20", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this question.    Rent receivable accrued 1/01/2005 D3,000  Rent received during the year 2005 D5,000  Rent receivable accrued 31/12/2005 D2,500  The rent receivable accrued as at 31st December 2005 is shown in the balance sheet as", "images": [], "options": {"A": "current asset", "B": "current liability", "C": "long-term liability", "D": "fixed asset"}, "answer": "A", "explanation": "Rent receivable accrued is an amount that is owed to the business but has not yet been received. It is therefore an asset to the business. As it is expected to be received within the next accounting period, it is classified as a current asset. Therefore, the rent receivable accrued as at 31st December 2005 is shown in the balance sheet as a current asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>21", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "Which of the following is not a cause of depreciation?", "images": [], "options": {"A": "Inflation", "B": "Erosion and decay", "C": "Wear and tear", "D": "Obsolescence"}, "answer": "A", "explanation": "Depreciation is the decrease in the value of an asset over time due to factors such as wear and tear, obsolescence, and decay. However, inflation is not a cause of depreciation. Inflation is a general increase in prices and fall in the purchasing value of money, which affects the economy as a whole, not the value of individual assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>22", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Items on the left hand side of a total debtors account are debit in the", "images": [], "options": {"A": "purchases ledger", "B": "sales ledger", "C": "general ledger", "D": "journal"}, "answer": "B", "explanation": "The left-hand side of a total debtors account represents the debit side. In accounting, the debit side is used to record all the incoming money. In the context of a total debtors account, this would be the sales ledger, where all the sales on credit are recorded.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>23", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this questions.      ₦Opening balance 1 894 Dr Cheque received from customers 7 284 Cash received from customers 1 236 Returns from customers 296 Closing balance 3 368 Dr    Credit Sales for the period is", "images": [], "options": {"A": "₦14,078", "B": "₦10,290", "C": "₦8520", "D": "₦3,554"}, "answer": "B", "explanation": "The credit sales for the period can be calculated by adding the opening balance to the cheque received from customers, cash received from customers and returns from customers, then subtracting the closing balance. This gives: 1894 + 7284 + 1236 + 296 - 3368 = 10290. Therefore, the correct answer is ₦10,290.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>24", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this questions.      ₦Opening balance 1 894 Dr Cheque received from customers 7 284 Cash received from customers 1 236 Returns from customers 296 Closing balance 3 368 Dr   The closing balance of ₦3,368 Dr is classified in the balance sheet as a", "images": [], "options": {"A": "fixed asset", "B": "current asset", "C": "current liability", "D": "capital"}, "answer": "B", "explanation": "The balance (i.e ₦3,368) represent the balance of debtor which is usually treated as current asset in the balance sheet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>25", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "The cost price of a book is 9,000 and the selling price is Le 12,000. The mark up is", "images": [], "options": {"A": "66 2/3%", "B": "50%", "C": "33 1/3%", "D": "25%"}, "answer": "C", "explanation": "The mark up is calculated as the difference between the selling price and the cost price, divided by the cost price, and then multiplied by 100 to get the percentage. In this case, the mark up is (12,000 - 9,000) / 9,000 * 100 = 33.33%. The closest option to this is 33 1/3%, which is option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>26", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "In single entry and incomplete records, the net assets method used to ascertain profit is", "images": [], "options": {"A": "net asset at the end of a period - net asset at the beginning of a period = profit + additional capital drawings", "B": "net asset at the end of a period - net asset at the beginning of a period = profit - additional capital drawings", "C": "net asset at the end of a period - net asset at the beginning of a period - drawings", "D": "net asset at the end of a period + additional capital drawings"}, "answer": "A", "explanation": "In single entry and incomplete records, the net assets method used to ascertain profit as Net asset at the end of a period - net asset at the beginning of a period = profit + additional capital - drawing.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2007>27", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The assumption that a business has perpetually existed is recognized by", "images": [], "options": {"A": "entity concept", "B": "periodic concept", "C": "going concern concept", "D": "realization concept"}, "answer": "C", "explanation": "The assumption that a business will continue to exist indefinitely is recognized by the going concern concept. This concept is a fundamental principle of accounting that influences how financial statements are prepared. It assumes that an entity will continue its operations for the foreseeable future. Hence, it is not expected to liquidate or significantly curtail its scale of operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>28", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this questions.     Youngsters Club has a membership of 115 persons. Each member pays an annual subscription of ₦50. During the year ended 31st December 2005, 8 members had not paid their subscriptions.    The subscriptions recorded in the Income and Expenditure Account for the year ended 31st December 2005 is", "images": [], "options": {"A": "₦5,750", "B": "₦5,350", "C": "₦400", "D": "₦115"}, "answer": "A", "explanation": "To get the subscriptions recorded in the income and expenditure account, multiply the total number of persons by the annual subscription. i.e. 115 x 50 = ₦5 750 i.e ₦5 750 will be recorded in the income and expenditure account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>29", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer this questions.     Youngsters Club has a membership of 115 persons. Each member pays an annual subscription of ₦50. During the year ended 31st December 2005, 8 members had not paid their subscriptions.   The subscriptions shown in the Balance sheet as at 31st December 2005 is", "images": [], "options": {"A": "₦400 (asset)", "B": "₦150 (asset)", "C": "₦150 (liability)", "D": "₦400 (liability)"}, "answer": "A", "explanation": "The total number of members is 115, and each member pays an annual subscription of ₦50. Therefore, the total subscription should be 115 * 50 = ₦5750. However, 8 members have not paid their subscriptions, so the subscriptions shown in the balance sheet would be (115 - 8) * 50 = ₦5350. But none of the options matches this answer. Therefore, none of the options is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>30", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The accounting principle that states that for every debit entry, there is a corresponding credit entry is recognized by", "images": [], "options": {"A": "realization concept", "B": "entity concept", "C": "going concern concept", "D": "dual aspect concept"}, "answer": "D", "explanation": "The accounting principle that states that for every debit entry, there is a corresponding credit entry is recognized by the dual aspect concept. This concept is the foundation of the double-entry bookkeeping system, where each transaction affects at least two accounts and ensures that the accounting equation (Assets = Liabilities + Equity) is always balanced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>31", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not an accounting convention?", "images": [], "options": {"A": "Materiality", "B": "Consistency", "C": "Business entity", "D": "Periodicity"}, "answer": "C", "explanation": "The business entity concept is not an accounting convention but an accounting principle. Accounting principles are the rules and guidelines that companies must follow when reporting financial data. The common set of US accounting principles is the generally accepted accounting principles (GAAP). The business entity concept states that the transactions associated with a business must be separately recorded from those of its owners or other businesses. This separation makes it possible for the business to be accounted for separately, which is necessary for the business to be taxed, regulated, and to show its financial status.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>32", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "In the absence of partnership agreement, profits and losses are shared", "images": [], "options": {"A": "in the ratio of capitals", "B": "equality", "C": "in the ratio of drawings", "D": "according to service rendered"}, "answer": "B", "explanation": "In the absence of a partnership agreement, profits and losses are shared equally among the partners. This is based on the Uniform Partnership Act (UPA), which most states have adopted, and it provides that profits and losses from the partnership business are to be divided equally among the partners, unless there is a written agreement that states otherwise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>33", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is credited to a partnership approriation account?", "images": [], "options": {"A": "Interest on capital", "B": "Interest on drawings", "C": "Partner's salaries", "D": "partner's drawings"}, "answer": "B", "explanation": "Interest on drawings is always found on the credit side of the partnership appropriation account while others are always found on the debit side of the appropriation account", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>34", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following formulae is used to calculate stock turnover rate?", "images": [], "options": {"A": "Sales/Average stock", "B": "Cost of Sales/Average stock", "C": "Cost of sales/Closing stock", "D": "Cost of sales/Opening stock"}, "answer": "B", "explanation": "The formula used to calculate stock turnover rate is Cost of Sales/Average stock. Stock turnover rate is a measure of the number of times inventory is sold or used in a time period such as a year. The equation for inventory turnover equals the cost of goods sold divided by the average inventory. Average inventory is used instead of ending inventory because many businesses' inventory levels fluctuate greatly throughout the year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>35", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following bases of accounting does not make allowance for depreciation", "images": [], "options": {"A": "Cash basis", "B": "Accrual basis", "C": "Matching basis", "D": "Commitment basis"}, "answer": "A", "explanation": "The cash basis of accounting recognizes revenues and expenses only when money changes hands. This means it does not account for expenses that have been incurred but not yet paid, including depreciation. Depreciation is an expense that is recorded over time as the value of an asset decreases, and it is not directly tied to cash transactions. Therefore, it is not recognized in cash basis accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>36", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES", "question": "Use the following information to answer this question.      ₦Premises 100 000Plant 50 000Fixtures 30 000Stock 20 000Debtors 10 000Cash 10 000Creditors 20 000    Total assets is", "images": [], "options": {"A": "₦240,000", "B": "₦220,000", "C": "₦200,000", "D": "₦180,000"}, "answer": "B", "explanation": "Total Asset = Fixed Asset + Current Asset   ₦(100,000 + 50,000 + 30,000 + 20,000 + 100,000 + 10,000)  = ₦220, 000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>37", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question.      ₦Premises 100 000Plant 50 000Fixtures 30 000Stock 20 000Debtors 10 000Cash 10 000Creditors 20 000  Current ratio is", "images": [], "options": {"A": "4:1", "B": "3:1", "C": "2:1", "D": "1:1"}, "answer": "C", "explanation": "The current ratio is calculated by dividing current assets (Stock, Debtors, and Cash) by current liabilities (Creditors). In this case, the current assets total to ₦40,000 and the current liabilities total to ₦20,000. So, the current ratio is 2:1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>38", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question.      ₦Premises 100 000Plant 50 000Fixtures 30 000Stock 20 000Debtors 10 000Cash 10 000Creditors 20 000  Quick ratio is", "images": [], "options": {"A": "4:1", "B": "3:1", "C": "2:1", "D": "1:1"}, "answer": "D", "explanation": "The quick ratio is calculated by dividing quick assets (current assets excluding Stock) by current liabilities (Creditors). In this case, the quick assets total to ₦20,000 and the current liabilities total to ₦20,000. So, the quick ratio is 1:1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>39", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES", "question": "Which of the following is not used for determining working capital?", "images": [], "options": {"A": "Cash", "B": "Debtors", "C": "Motor vehicles", "D": "Overdraft"}, "answer": "C", "explanation": "Working capital is calculated as current assets minus current liabilities. Current assets include cash, debtors, and other short-term assets that can be converted into cash within a year. Current liabilities include overdraft and other short-term liabilities that need to be paid within a year. Motor vehicles are considered as fixed assets, not current assets, hence they are not used in determining working capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>40", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "In the absence of partnership agreement, a loan by a partner attracts interest at", "images": [], "options": {"A": "20%", "B": "15%", "C": "10%", "D": "5%"}, "answer": "D", "explanation": "In the absence of a partnership agreement, a loan by a partner attracts interest at 5%. This is stipulated in the Indian Partnership Act of 1932, Section 24, which states that a partner's loan to the partnership firm will attract interest at 6% per annum. However, this rate can be adjusted if the partners agree to a different rate in their partnership agreement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>41", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Which of the following is not a data processing method?", "images": [], "options": {"A": "Manual", "B": "Mechanical", "C": "Electronic", "D": "Formatting"}, "answer": "D", "explanation": "Data processing methods include manual, mechanical, and electronic methods. These methods refer to how data is processed. Manual involves human intervention, mechanical involves the use of machines, and electronic involves the use of computers. Formatting, on the other hand, is not a method of processing data but rather a way of arranging or presenting the data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>42", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The correct sequence in data processing is", "images": [], "options": {"A": "input ⊸ process  ⊸ output", "B": "input   ⊸ output  ⊸ process", "C": "process  ⊸ input  ⊸ output", "D": "process  ⊸ output  ⊸ input"}, "answer": "A", "explanation": "The correct sequence in data processing is input, process, and output. This is often referred to as the IPO model. Input is where data is collected and entered into the system. Process is where the data is manipulated or processed. Output is where the results of the processing are presented or outputted.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>43", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION", "question": "Use the following information to answer this question.    Year Profit 2003 Le 40 0002004 Le 48 0002005 Le 62 000    The value of goodwill calculated at 3 years purchase of annual profit is", "images": [], "options": {"A": "Le 450,000", "B": "Le 150,000", "C": "Le 50,000", "D": "Le 48,000"}, "answer": "C", "explanation": "Purchase of average profit method = Total AmountTotal no of years  40,000 + 48,000 + 62,0003  Le150,0003  Le50,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>44", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "The maximum amount that a company is allowed to raise through the share is", "images": [], "options": {"A": "authorized capital", "B": "paid-up capital", "C": "issued capital", "D": "working capital"}, "answer": "A", "explanation": "The maximum amount that a company is allowed to raise through the share is known as authorized capital. Authorized capital is the maximum amount of share capital that the company is authorized by its constitutional documents to issue (allocate) to shareholders. Parts of authorized capital can (and often does) remain unissued. The other options: paid-up capital, issued capital, and working capital do not represent the maximum amount a company is allowed to raise through shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>45", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO", "question": "The double entry in the books to write off goodwill is", "images": [], "options": {"A": "debit Goodwill Account, credit Capital Account", "B": "debit Goodwill Account, credit Revaluation Account", "C": "debit Profit and Loss Appropriation Account, credit Goodwill Account", "D": "debit trading Account, credit Goodwill Account"}, "answer": "C", "explanation": "Goodwill is an intangible asset that represents the non-physical assets, such as the value of a brand name, large and loyal customer base, good customer relations, good employee relations, and any patents or proprietary technology. Writing off goodwill involves reducing the value of this asset in the company's books, which is done by debiting the Profit and Loss Appropriation Account and crediting the Goodwill Account. This is because the write-off is an expense for the company, and expenses are debited in accounting, while the reduction in the asset (goodwill) is credited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>46", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Holder of ordinary shares do not have the right to", "images": [], "options": {"A": "participate in additional issue of shares", "B": "vote at annual general meetings", "C": "elect the board of directors", "D": "receive dividend at a predetermined rate"}, "answer": "D", "explanation": "Ordinary shareholders, also known as common shareholders, have the right to vote at annual general meetings, elect the board of directors, and participate in additional issue of shares. However, they do not have the right to receive dividends at a predetermined rate. This is because dividends for ordinary shareholders are not fixed and are declared by the board of directors depending on the company's profitability. In contrast, preferred shareholders receive dividends at a predetermined rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>47", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is not a real account?", "images": [], "options": {"A": "Building account", "B": "Motor Vehicle account", "C": "Patent account", "D": "Furniture account"}, "answer": "C", "explanation": "A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year-end and are carried forward. An example of a real account is an asset account, like 'Building account' or 'Motor Vehicle account'. On the other hand, 'Patent account' is an example of a nominal account, which relates to income, expenses, losses or gains.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>48", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "An example of capital gain is", "images": [], "options": {"A": "premium", "B": "bonus", "C": "shares", "D": "debentures"}, "answer": "A", "explanation": "Capital gain refers to the increase in the value of an investment or real estate that gives it a higher worth than the purchase price. The gain is not realized until the asset is sold. A 'premium' on shares or bonds is an example of capital gain. It is the amount by which the price paid for a security exceeds its face value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2007>49", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Which of the following attracts a fixed rate of dividend?", "images": [], "options": {"A": "Ordinary shares", "B": "Founders' shares", "C": "Preference shares", "D": "Deferred shares"}, "answer": "C", "explanation": "Preference shares attract a fixed rate of dividend. This is because preference shareholders have a preferential right to receive a fixed rate of dividend before any dividend is paid to the ordinary shareholders. The rate of dividend is usually stated at the time of issue of such shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2007>50", "subject": "Accounts", "year": "2007", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is a source of revenue to a local government authority?", "images": [], "options": {"A": "Poll tax", "B": "Excise duty", "C": "PAYE tax", "D": "Income tax"}, "answer": "A", "explanation": "Poll tax is a source of revenue to a local government authority. It is a tax levied on every adult in the community without reference to income or resources. Other taxes like Excise duty, PAYE tax, and Income tax are usually collected by the central government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>1", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following is the basic accounting equation?", "images": [], "options": {"A": "Assets = Capital + Liabilities", "B": "Capital = Assets + Liabilities", "C": "Liability = Assets + Capital", "D": "Assets = Liability - Equity"}, "answer": "A", "explanation": "The basic accounting equation is Assets = Capital + Liabilities. This equation is the foundation of double-entry bookkeeping. It shows that all of a company's resources (assets) are provided by either creditors (liabilities) or owners (capital).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>2", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "A sales Day Book is used for recording", "images": [], "options": {"A": "credit sales", "B": "sales returns", "C": "hire purchase", "D": "cash sales"}, "answer": "A", "explanation": "A Sales Day Book is a book of original entry in which are recorded the details of credit sales made by a business. It is also known as a Sales Journal. Cash sales are not recorded in the Sales Day Book because they do not involve credit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>3", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "An analytical cash book is used to", "images": [], "options": {"A": "indicate sources of cash received", "B": "categorise pretty cash  payment", "C": "separate cash and bank balance", "D": "analyse amounts due from debtors"}, "answer": "A", "explanation": "An analytical cash book is a type of cash book that not only records the transactions of cash but also classifies them into various heads. It is used to indicate sources of cash received. It helps in understanding from where the cash is coming into the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>4", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following concept is expected to hold when a proprietor makes a drawing of goods or cash from the business?", "images": [], "options": {"A": "Business entity", "B": "Realization", "C": "Going concern", "D": "Dual - aspect"}, "answer": "A", "explanation": "The business entity concept states that the business and the owner are two separate entities. In other words, the business is separate from its owners. So, when a proprietor makes a drawing of goods or cash from the business, it is treated as the business's expense or loss. This is because the business entity concept holds that the business's transactions are separate from the personal transactions of its owner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>5", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "In a partnership business, the net profit serve as opening figure for", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "current account", "D": "appropriation account"}, "answer": "D", "explanation": "The net profit serves as opening figure for appropriation account.the netprofit is taken to the profit and loss appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>6", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Which of the following is the effect of an increase in the provision for discount allowed?", "images": [], "options": {"A": "Increase in net profit", "B": "Decrease in gross profit", "C": "Decrease in net profit", "D": "Increase in gross profit"}, "answer": "C", "explanation": "An increase in the provision for discount allowed will decrease the net profit. The provision for discount allowed is an expense for the business. When it increases, it reduces the amount of profit that the business makes. This is because the provision for discount allowed is deducted from the gross profit to arrive at the net profit. Therefore, an increase in this provision will result in a decrease in net profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>7", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "In the preparation of manufacturing accounts, prime cost plus factory overheads equal to cost of", "images": [], "options": {"A": "materials available", "B": "production", "C": "sales", "D": "materials used"}, "answer": "B", "explanation": "In the preparation of manufacturing accounts, prime cost plus factory overheads equals to cost of production. Prime cost is the total cost of direct materials and direct labor used in production, while factory overheads are the indirect costs of production. When these two are added together, they give the total cost of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>8", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Returns inwards is also called", "images": [], "options": {"A": "purchases returns", "B": "sales returns", "C": "goods on sale or return", "D": "goods in transit"}, "answer": "B", "explanation": "Returns inwards is also known as sales returns. This refers to the goods that are returned to the seller by the buyer. It is recorded as a contra entry to sales in the seller's books of accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>9", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer this question.    Tale Ltd. has 100,000 ordinary shares of 1₦ each and 60,000   5% preference shares of ₦ 1 each. Both were fully paid     ₦Profit and Loss appropriation b/f 10 000Net profit for the year 6 000Proposed dividend on ordinary shares 4 000Interim dividend 6 000Goodwill written off 600    The balance of the profit and loss appropriation account as at the end of the year was", "images": [], "options": {"A": "₦16 000", "B": "₦10 000", "C": "₦5 400", "D": "₦1 400"}, "answer": "C", "explanation": "Cr. Appropriation A/C Dr.     ₦  ₦Proposed dividend 4 000 Bal. b/f 10 000Interim dividend 6 000 Net profit 6 000Good will written off 600    Retained profit  5 400     16 000  16 000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>10", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer this question.    Tale Ltd. has 100,000 ordinary shares of 1₦ each and 60,000   5% preference shares of ₦ 1 each. Both were fully paid     ₦Profit and Loss appropriation b/f 10 000Net profit for the year 6 000Proposed dividend on ordinary shares 4 000Interim dividend 6 000Goodwill written off 600  The authorised capital of Tale Ltd is", "images": [], "options": {"A": "₦176,000", "B": "₦166,000", "C": "₦160,000", "D": "₦16,000"}, "answer": "C", "explanation": "The authorised capital of a company is the maximum amount of share capital that the company is authorised by its constitutional documents to issue to shareholders. In this case, Tale Ltd. has 100,000 ordinary shares of ₦1 each and 60,000 5% preference shares of ₦1 each. Therefore, the authorised capital is (100,000 * ₦1) + (60,000 * ₦1) = ₦160,000. So, the correct answer is ₦160,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>11", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Use the following information to answer this question.    Tale Ltd. has 100,000 ordinary shares of 1₦ each and 60,000   5% preference shares of ₦ 1 each. Both were fully paid     ₦Profit and Loss appropriation b/f 10 000Net profit for the year 6 000Proposed dividend on ordinary shares 4 000Interim dividend 6 000Goodwill written off 600  The dividend payable to preference shareholders is", "images": [], "options": {"A": "₦9,000", "B": "₦6,000", "C": "₦3,000", "D": "₦2,400"}, "answer": "C", "explanation": "Preference dividend payable - 5% x 60,000   5100x60,000 = ₦3,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>12", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not a characteristic of a computer?", "images": [], "options": {"A": "Large storage capacity", "B": "very fast", "C": "High accuracy", "D": "High diligence"}, "answer": "D", "explanation": "A computer has a large storage capacity which allows it to store large amounts of data. It is very fast in processing data and can perform complex calculations in a fraction of a second. It is highly accurate and can perform tasks with a high level of precision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>13", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Final accounts of a not-for-profit making organization is made up of", "images": [], "options": {"A": "subscriptions account and income and expenditure accounts", "B": "subscriptions accounts and balance sheet", "C": "income and expenditure account and balance sheet", "D": "receipts and payments account and income and expenditure account"}, "answer": "C", "explanation": "The final accounts of a not-for-profit making organization is made up of the income and expenditure account and the balance sheet. The income and expenditure account shows the income earned and the expenses incurred during a particular period. The balance sheet shows the financial position of the organization at a particular point in time, including its assets, liabilities, and capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>14", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is a debit entry in debtors control account?", "images": [], "options": {"A": "Credit sales", "B": "Bad debts", "C": "Return inwards", "D": "Discount allowed"}, "answer": "A", "explanation": "Debtor control is an account prepared to know the sales as well as the total debtors for the period. The debit side consist of sales(Credit sales), interest charges, carriage ouwtards, debit note issued, dishonoured bill etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>15", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following imformation to answer the questions#Opening capital 60000Drawings 4000Cost of sales 50000General expenses 7000Mark up 50%    Net profit is", "images": [], "options": {"A": "₦43,000", "B": "₦25,000", "C": "₦23,000", "D": "₦18,000"}, "answer": "D", "explanation": "The net profit is calculated by subtracting the cost of sales and general expenses from the total revenue. The total revenue is calculated by adding the markup to the cost of sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>16", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "#Opening capital 60000Drawings 4000Cost of sales 50000General expenses 7000Mark up 50%  Closing capital is", "images": [], "options": {"A": "₦81,000", "B": "₦78,000", "C": "₦74,000", "D": "₦64,000"}, "answer": "C", "explanation": "The closing capital is calculated by adding the net profit to the opening capital and subtracting the drawings.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>17", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following is not found in a partnership balance sheet?", "images": [], "options": {"A": "Capital", "B": "Drawings", "C": "Creditors", "D": "Bank balance"}, "answer": "B", "explanation": "Drawings are not found in a partnership balance sheet. Drawings refer to the money withdrawn by the partners from the business for personal use. It is not a liability or an asset of the business, hence it does not appear on the balance sheet. It is deducted from the capital account of the partners in the balance sheet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>18", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is not a debit item in partners appropriation account?", "images": [], "options": {"A": "Interest on capital", "B": "Salary", "C": "Share of profit", "D": "Share of loss"}, "answer": "D", "explanation": "Share of loss is not a debit item in partners appropriation account. The partners' appropriation account is an account that shows how the profit of a partnership is divided among the partners. It includes items like interest on capital, salaries, and share of profit which are debited to this account as they are expenses for the business. However, share of loss is not debited to this account. Instead, it is credited to the partners' capital accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>19", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The difference between factory cost of goods produced and its market value is", "images": [], "options": {"A": "interest", "B": "premium", "C": "manufacturing profit", "D": "manufacturing overhead"}, "answer": "C", "explanation": "The difference between the factory cost of goods produced and its market value is referred to as manufacturing profit. This is because the factory cost of goods produced is the cost incurred by the company to produce the goods, while the market value is the price at which the goods are sold in the market. The difference between these two values is the profit made by the company from manufacturing the goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>20", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Which of the following is not an item in the appropriation account of a company?", "images": [], "options": {"A": "General reserve", "B": "Company tax", "C": "Debenture interest", "D": "Goodwill written off"}, "answer": "C", "explanation": "Debenture is a loan capital given to an individual or company the internet charged on debenture is always treated as expenses in the company's profit and loss account. Others are charged to appropriation account of a company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>21", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "The purchase of furniture, an asset to the company was debited to purchase account. This is an error of", "images": [], "options": {"A": "omission", "B": "original entry", "C": "principle", "D": "commission"}, "answer": "C", "explanation": "The error is an error of principle. An error of principle in accounting occurs when the fundamental principles of accounting are not observed or violated while recording business transactions. In this case, the purchase of furniture, an asset, was incorrectly debited to the purchase account, which is typically used for recording the purchase of inventory items. This is a violation of the accounting principle that states that assets should be recorded in their respective asset accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>22", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "Which of the following terms is not used to describe the total amount stated in the memorandum of association approved by the registrar of companies?", "images": [], "options": {"A": "Authorised capital", "B": "Registered capital", "C": "Issued capital", "D": "Nominal capital"}, "answer": "C", "explanation": "The term 'Issued capital' is not used to describe the total amount stated in the memorandum of association approved by the registrar of companies. The memorandum of association includes the company's authorized or nominal capital, which is the maximum amount of share capital that the company is authorized to issue to shareholders. Registered capital is also a term used to describe this. However, issued capital refers to the part of the authorized capital which has been issued to shareholders and is fully paid up. Therefore, it is not a term used to describe the total amount stated in the memorandum of association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>23", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "A cash payment of ₦85 to Regina was entered in the books as ₦58. The entries to correct the error are: debit", "images": [], "options": {"A": "Regina's Account ₦27: Credit Cash Account ₦27", "B": "Cash Account ₦27: Credit Regina's Account ₦27", "C": "Regina's Account ₦143: Credit Cash Account *N143", "D": "Cash Account ₦143: Credit Regina's Account ₦143"}, "answer": "A", "explanation": "The error committed is an error of original entry because it involved wrong amount (i.e. ₦58 was recorded instead of ₦85) To correct this error      Dr Regina's A/C with ₦27       Cr. Cash A/C with ₦27", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>24", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question.      Le Sales 183 400Purchases 168 000Opening stock 20 100Closing stock 48 900Carriage outwards 2 400Carriage inwards 5 000Return inward 10 000Expenses 15 000Return outwards 8 000    The gross profit is", "images": [], "options": {"A": "Le 47,200", "B": "Le 42,200", "C": "Le 37,200", "D": "Le 19,800"}, "answer": "C", "explanation": "₦ ₦Sales  183 400Less: returns inwards  10 000Net sales  173 400Less: cost of goods sold  Opening stock 20 100 Add: purchases 168 000 Carriage inwards 5 000 Net purchases 193 100 Return outwards 8 000 COGAS 185 100 Less: closing stock 48 900 Cost of goods sold  136 200   136 200 Gross profit  37 200Less: Expenses  15 000Carriage outwards  2 400Net profit  19 800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>25", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question.      Le Sales 183 400Purchases 168 000Opening stock 20 100Closing stock 48 900Carriage outwards 2 400Carriage inwards 5 000Return inward 10 000Expenses 15 000Return outwards 8 000  The net profit is", "images": [], "options": {"A": "Le 42,200", "B": "Le 37,200", "C": "Le 32,700", "D": "Le 19,800"}, "answer": "D", "explanation": "₦ ₦Sales  183 400Less: returns inwards  10 000Net sales  173 400Less: cost of goods sold  Opening stock 20 100 Add: purchases 168 000 Carriage inwards 5 000 Net purchases 193 100 Return outwards 8 000 COGAS 185 100 Less: closing stock 48 900 Cost of goods sold 136 200 136 200Gross profit  37 200Less: Expenses  15 000Carriage outwards  2 400Net profit  19 800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>26", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer this question.      Le Sales 183 400Purchases 168 000Opening stock 20 100Closing stock 48 900Carriage outwards 2 400Carriage inwards 5 000Return inward 10 000Expenses 15 000Return outwards 8 000  The cost of goods sold is", "images": [], "options": {"A": "Le 185,100", "B": "Le 139,200", "C": "Le 136,200", "D": "Le 131,200"}, "answer": "C", "explanation": "₦ ₦Sales  183 400Less: returns inwards  10 000Net sales  173 400Less: cost of goods sold  Opening stock 20 100 Add: purchases 168 000 Carriage inwards 5 000 Net purchases 193 100 Return outwards 8 000 COGAS 185 100 Less: closing stock 48 900 Cost of goods sold 136 200 136 200Gross profit  37 200Less: Expenses  15 000Carriage outwards  2 400Net profit  19 800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>27", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The class of share to which payment of dividend depends on profit is", "images": [], "options": {"A": "forfeited shares", "B": "ordinary shares", "C": "bonus shares", "D": "preference shares"}, "answer": "B", "explanation": "Ordinary shares are the shares to which payment of dividend depends on the profit of the company. Dividends on ordinary shares are not fixed and are decided by the board of directors depending on the company's profitability. Forfeited shares are those that have been taken back by the company due to non-payment of calls. Bonus shares are additional shares given to the current shareholders without any additional cost, based upon the number of shares that a shareholder owns. Preference shares are those that have a fixed dividend, which is paid before any dividends are paid to ordinary shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>28", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Payment for shares in installments is done by means of", "images": [], "options": {"A": "call", "B": "circulars", "C": "subscription", "D": "invitation"}, "answer": "A", "explanation": "Payment for shares in installments is done by means of 'call'. A 'call' in corporate finance is a notice to a shareholder explaining that the company needs more money. The company can make a call on unpaid share capital either all at once or at intervals. The other options like circulars, subscription, and invitation are not related to the payment for shares in installments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>29", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Mark-up on goods sent to branch are recorded in the books by crediting", "images": [], "options": {"A": "Stock Adjustment Account; debiting Branch Stock Account", "B": "Goods sent to branch Account; debiting Branch Stock Account", "C": "bank Stock Account; debiting Stock Adjustment Account", "D": "Branch stock Account; credit Cash Account"}, "answer": "A", "explanation": "Mark-up on goods sent to branch are recorded in the books by crediting Stock Adjustment Account and debiting Branch Stock Account. This is because the mark-up represents an increase in the value of the stock sent to the branch, hence the increase (credit) in the Stock Adjustment Account and the corresponding decrease (debit) in the Branch Stock Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>30", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not part of cost of production?", "images": [], "options": {"A": "Direct material cost", "B": "Direct wages", "C": "Factory overheads", "D": "Administrative overheads"}, "answer": "D", "explanation": "Administrative overheads are not part of the cost of production. The cost of production includes all costs associated with the production of goods or services, such as direct material cost, direct wages, and factory overheads. Administrative overheads, on the other hand, are costs associated with the general administration of the business and are not directly tied to the production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>31", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Use the following information to answer this question.     Sulay Local Government DConstruction of classrooms 500 000Sinking of boreholes 100 000Staff salaries 150 000Electricity 14 000Transport and levels 7 000Office expenses 9 000    Recurrent expenditure is", "images": [], "options": {"A": "D180,000", "B": "D164,000", "C": "D150,000", "D": "D30,000"}, "answer": "A", "explanation": "Recurrent expenditure refers to the regular and routine expenditure that the government incurs to maintain its existing services. In the given question, the recurrent expenditures are Staff salaries, Electricity, Transport and levels, and Office expenses. Adding these up gives us 150,000 + 14,000 + 7,000 + 9,000 = 180,000. Therefore, the correct answer is D180,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>32", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Use the following information to answer this question.     Sulay Local Government DConstruction of classrooms 500 000Sinking of boreholes 100 000Staff salaries 150 000Electricity 14 000Transport and levels 7 000Office expenses 9 000  Capital expenditure is", "images": [], "options": {"A": "D780,000", "B": "D750,000", "C": "D600,000", "D": "D500,000"}, "answer": "C", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, technology, or equipment. In the given question, the capital expenditures are Construction of classrooms and Sinking of boreholes. Adding these up gives us 500,000 + 100,000 = 600,000. Therefore, the correct answer is D600,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>33", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is not a subsidiary book?", "images": [], "options": {"A": "Sales journal", "B": "Cash book", "C": "Purchase ledger", "D": "General journal"}, "answer": "C", "explanation": "A subsidiary book is a book of original entry. The options provided are all books of original entry except for the Purchase Ledger. The Purchase Ledger is a ledger account, not a book of original entry, hence it is not a subsidiary book.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>34", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "In bank reconciliation, when a cash book shows a credit balance, uncredited cheque are:  I. deducted from the cash book balance   II. added to the bank statement balance   III. added to the cash book balance", "images": [], "options": {"A": "I and II only", "B": "I, II and III", "C": "II and III only", "D": "III only"}, "answer": "A", "explanation": "In bank reconciliation, when the cash book shows a credit balance, it means the bank owes the business. Therefore, uncredited cheques, which are cheques that have been issued by the business but not yet presented to the bank for payment, are deducted from the cash book balance because they represent future payments that the bank will make on behalf of the business. They are not added to the bank statement balance because the bank is not yet aware of them. Therefore, the correct answer is 'I and II only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>35", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "When provision is made for doubting debt, the accounting entries are", "images": [], "options": {"A": "debit Profit and loss account; credit trading provision for doubting debt account", "B": "debit debtors account; credit trading account", "C": "debit profit and loss account; credit sales account", "D": "debit trading account; credit debtors account"}, "answer": "A", "explanation": "When provision is made for doubtful debts, the accounting entries are debit Profit and Loss account and credit Provision for Doubtful Debts account. This is because the provision for doubtful debts is an expense for the business and thus reduces the profit. Therefore, the Profit and Loss account is debited (as expenses are debited) and the Provision for Doubtful Debts account is credited (as it is a liability for the business and liabilities are credited).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>36", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "An approach for discovering missing figures in incomplete records is the use of", "images": [], "options": {"A": "cash book", "B": "control account", "C": "trading accounts", "D": "balance sheet"}, "answer": "B", "explanation": "Control accounts are used in accounting to check the accuracy of transactions and to discover any errors or discrepancies. They provide a summary of transactions and allow for the identification of any missing figures. Therefore, an approach for discovering missing figures in incomplete records is the use of control accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>37", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A merchant paid ₦180,00 on rent for 18 months but charged ₦120,000 to profit and loss account for the year. The concept applied is", "images": [], "options": {"A": "business entity", "B": "going concern", "C": "accrual", "D": "materiality"}, "answer": "C", "explanation": "The accrual concept in accounting means that expenses or revenues are recorded when a transaction occurs rather than when payment is received or made. In this case, the merchant paid for 18 months rent but only charged 12 months to the profit and loss account. This is because the merchant is applying the accrual concept, recognizing the expense for the period it relates to, not when the payment was made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>38", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PETTY CASH BOOK : ADVANTAGES OF PETTY CASH BOOK", "question": "Which of the following is an advantage of the imprest system?", "images": [], "options": {"A": "rewarding the imprest holder", "B": "Reducing the burden of petty cashier", "C": "Reimbursing the petty cashier.", "D": "Reducing the postings for small expenses into the main ledger"}, "answer": "D", "explanation": "The imprest system is a form of financial accounting system. The most common example is the petty cash system. The main advantage of using the imprest system is that it helps to maintain a constant balance of petty cash, which makes it easier to control and monitor small, miscellaneous expenses. Therefore, it reduces the postings for small expenses into the main ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>39", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Use the following information to answer this question.    Henik Plc has departments A and B and has made the following information available concerning its operations:       Department A Department BTurnover   ₦100 000 ₦80 000Commission ₦3 600  Rent ₦6 000  Floor space  200m2 100m2    How much commission was apportioned to Department A?", "images": [], "options": {"A": "₦9,600", "B": "₦3,600", "C": "₦2,000", "D": "₦1,600"}, "answer": "C", "explanation": "The commission is apportioned based on the turnover of each department. The proportion of Department A's turnover to the total turnover is 100,000/180,000 = 0.5556. Therefore, the commission apportioned to Department A is 0.5556 * ₦3,600 = ₦2,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>40", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Use the following information to answer this question.    Henik Plc has departments A and B and has made the following information available concerning its operations:       Department A Department BTurnover   ₦100 000 ₦80 000Commission ₦3 600  Rent ₦6 000  Floor space  200m2 100m2  Rent apportioned to department B is", "images": [], "options": {"A": "₦4,000", "B": "₦3,600", "C": "₦2,000", "D": "₦1,600"}, "answer": "B", "explanation": "Rent for dept B is apportioned on basis of floor space i.e     Dept. B =   100200+100x6,000    = ₦2,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>41", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "The entries to record goods bought for cash are: debit", "images": [], "options": {"A": "Cash Account; Credit Purchases Account", "B": "Purchases Account; Credit cash Account", "C": "Purchases Account; Credit Stock Account", "D": "Purchases Account; Credit Goods Account"}, "answer": "B", "explanation": "When goods are bought for cash, the Purchases Account is debited because the company is acquiring assets (goods) which is an increase in assets. The Cash Account is credited because cash is going out of the business which is a decrease in assets. Therefore, the correct entry is: Debit Purchases Account; Credit Cash Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>42", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Carriage inwards is posted to", "images": [], "options": {"A": "Trading Account", "B": "profit and Loss Account", "C": "Appropriation Account", "D": "Balance sheet"}, "answer": "A", "explanation": "Carriage inwards refers to the cost of transporting goods into a business. This cost is directly related to the purchase of goods and is therefore considered a direct expense. In accounting, direct expenses are posted to the Trading Account. Therefore, Carriage inwards is posted to the Trading Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>43", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Repairs to air conditioners was debited to office equipment account. This is an error of", "images": [], "options": {"A": "principle", "B": "commission", "C": "original entry", "D": "compensation"}, "answer": "A", "explanation": "The error described in the question is an error of principle. An error of principle in accounting occurs when the fundamental principles of accounting are not adhered to during the recording of financial transactions. In this case, the cost of repairs to air conditioners, which should have been recorded as an expense, was incorrectly debited to the office equipment account, which is an asset account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>44", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The practice of identifying with one constant approach where number of approaches exists for solving an accounting problem is the convention of", "images": [], "options": {"A": "conservatism", "B": "consistency", "C": "prudence", "D": "materiality"}, "answer": "B", "explanation": "The convention described in the question is the convention of consistency. The convention of consistency in accounting requires that once an accounting method or procedure is adopted, it should be followed consistently from one period to another. This allows for comparability of financial statements over different accounting periods. It means that the same accounting principles should be applied in the same way in each accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>45", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Use the following information to answer this question.      ₦Opening debtors 40 000Opening creditors 30 000Credit sales 100 000Credit purchases 80 000Bad debts 5 500Set offs 65 500    Closing debtors figure is", "images": [], "options": {"A": "₦140,000", "B": "₦14,500", "C": "₦80,000", "D": "₦69,000"}, "answer": "D", "explanation": "Opening debtors + Credit sales  - Bad debts - Set offs  = 40000 + 100000 - 5500 - 65500  = #69,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>46", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Use the following information to answer this question.      ₦Opening debtors 40 000Opening creditors 30 000Credit sales 100 000Credit purchases 80 000Bad debts 5 500Set offs 65 500  Closing creditors figure is", "images": [], "options": {"A": "₦115,500", "B": "₦110,000", "C": "₦95,500", "D": "₦44,500"}, "answer": "D", "explanation": "Dr. Creditors control Account Cr.     ₦  ₦Sell off 65 500 Bal.b/f 30 000Bal.c/d 44 500 Purchases 80 000  110 000  110 000   Bal. b/d 44 500    Using closing balance, ₦44,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2008>47", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is a nominal account?", "images": [], "options": {"A": "Bank Account", "B": "Cash Account", "C": "Sales Account", "D": "Stock Account"}, "answer": "C", "explanation": "A nominal account is an account that is used for reporting the current period's income and expenses. In this case, the 'Sales Account' is a nominal account because it records the income from sales during a particular period. The other options, 'Bank Account', 'Cash Account', and 'Stock Account', are real and personal accounts, not nominal accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>48", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is a storage device?", "images": [], "options": {"A": "Diskette", "B": "Key board", "C": "Printer", "D": "Monitor"}, "answer": "A", "explanation": "A storage device is a piece of computer equipment on which information can be stored. A 'Diskette' is a storage device as it can store digital information. The other options, 'Key board', 'Printer', and 'Monitor', are input and output devices, not storage devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2008>49", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Trade creditors personal accounts are found in the", "images": [], "options": {"A": "purchases ledger", "B": "sales ledger", "C": "general ledger", "D": "sales day book"}, "answer": "A", "explanation": "Trade creditors are entities from which a business has purchased goods but has not yet paid for them. These are accounts payable and are found in the purchases ledger. The purchases ledger is a subsidiary ledger in which individual accounts with suppliers (trade creditors) are maintained.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2008>50", "subject": "Accounts", "year": "2008", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Which of the following is not an instrument for controlling public expenditure?", "images": [], "options": {"A": "Constitution", "B": "Financial regulation", "C": "Budget", "D": "Memorandum of association"}, "answer": "D", "explanation": "A Memorandum of Association is not an instrument for controlling public expenditure. It is a legal document prepared in the formation and registration process of a limited liability company to define its relationship with shareholders. The Constitution, Financial regulation, and Budget are all instruments for controlling public expenditure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>1", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Which of the following books of original entry is used to record payment and receipt by cash or cheque?", "images": [], "options": {"A": "Sales day book", "B": "Cash book", "C": "Purchase day book", "D": "General journal"}, "answer": "B", "explanation": "The Cash Book is a book of original entry in which transactions relating only to cash receipts and payments are recorded in detail. When cash is received, it is entered on the debit or left hand side. Similarly, when cash is paid out the same is recorded on the credit or right hand side of the cash book.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>2", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "As a basis for assessing future usage, fixed assets are showing at", "images": [], "options": {"A": "selling price", "B": "cost price", "C": "cost plus residual value", "D": "net book value"}, "answer": "D", "explanation": "Fixed assets are shown at net book value on the balance sheet. Net book value is the cost of the asset minus accumulated depreciation. Depreciation is the allocation of the cost of the asset over its useful life. This provides a more accurate estimate of the asset's value and the amount that could be recovered through its use or sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>3", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "In the absence of an agreement, partners share profit", "images": [], "options": {"A": "based on activeness of a partner", "B": "based on capital contribution", "C": "on patronage basis", "D": "on equal basis"}, "answer": "D", "explanation": "In the absence of a specific agreement, partners share profits and losses equally, regardless of their capital contribution or the level of their activity in the partnership. This is a standard rule in partnership accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>4", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscriptions prepaid by members is recorded in the Balance Sheet at a club as a", "images": [], "options": {"A": "current liability", "B": "current asset", "C": "fixed asset", "D": "long term liability"}, "answer": "A", "explanation": "Subscriptions prepared is an income prepayment which is always treated as current liability in an account for non profit making organisation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>5", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The reduction in value of an intangible asset is", "images": [], "options": {"A": "depletion", "B": "depreciation", "C": "amortization", "D": "appreciation"}, "answer": "C", "explanation": "The reduction in value of an intangible asset is referred to as amortization. Amortization is the process of gradually writing off the initial cost of an asset. Depletion refers to the use of up of natural resources by mining, quarrying, drilling, or felling. Depreciation refers to the decrease in value of physical assets due to usage, wear and tear. Appreciation is an increase in the value of an asset over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>6", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not part of cost of  production?", "images": [], "options": {"A": "Wage of operators", "B": "factory power", "C": "Advertising", "D": "Cost of raw materials"}, "answer": "C", "explanation": "Advertising is not part of the cost of production. The cost of production includes all the costs incurred in producing a product or providing a service. This includes the cost of raw materials, wages of operators, and factory power. Advertising is a selling expense, not a production cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>7", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Rent is apportioned to each department on the basis of", "images": [], "options": {"A": "area of space occupied", "B": "equality", "C": "turnover", "D": "purchase"}, "answer": "A", "explanation": "Rent is typically apportioned to each department based on the area of space occupied. This is because the amount of space a department occupies in a building often correlates with the amount of rent that department should pay. This method is fair and equitable, as departments that occupy more space pay more rent, and departments that occupy less space pay less rent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>8", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "A document which acknowledge that a company owes a person a stated sum of money with an agreement to pay a fixed rate of interest periodically is", "images": [], "options": {"A": "share certificate", "B": "allotment certificate", "C": "preference certificate", "D": "debenture certificate"}, "answer": "D", "explanation": "A debenture certificate is a document that acknowledges a company owes a person a stated sum of money with an agreement to pay a fixed rate of interest periodically. It is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. Both corporations and governments frequently issue this type of bond to secure capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>9", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      D Purchase of raw materials 236 500Returns of raw materials 4 750Carriage on raw materials 34 000Stock of raw materials at close 39 500Factory fuel 150 000Direct wages 205 000Indirect wages 31 250Factory power 105 000Work-in-progress at start 32 500    What is the value of raw materials used?", "images": [], "options": {"A": "D270,500", "B": "265,750", "C": "236,500", "D": "226,250"}, "answer": "D", "explanation": "The value of raw materials used is calculated by adding the purchase of raw materials and the carriage on raw materials, then subtracting the returns of raw materials and the stock of raw materials at close. This gives us 236,500 + 34,000 - 4,750 - 39,500 = 226,250.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>10", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      D Purchase of raw materials 236 500Returns of raw materials 4 750Carriage on raw materials 34 000Stock of raw materials at close 39 500Factory fuel 150 000Direct wages 205 000Indirect wages 31 250Factory power 105 000Work-in-progress at start 32 500  What is the prime cost?", "images": [], "options": {"A": "D 717,500", "B": "D431,250", "C": "255,000", "D": "236,250"}, "answer": "B", "explanation": "Add: purchase of raw material 236 500carriage on raw materials 34 000Less: return of raw materials  4 750 Cost of raw material available for use 265 750Less: closing stock of raw material  39 500 Cost of raw material consumed 226 250Add: Direct wages  205 000 Prime cost 431 250", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>11", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      D Purchase of raw materials 236 500Returns of raw materials 4 750Carriage on raw materials 34 000Stock of raw materials at close 39 500Factory fuel 150 000Direct wages 205 000Indirect wages 31 250Factory power 105 000Work-in-progress at start 32 500  The total factory overhead is", "images": [], "options": {"A": "D318,750", "B": "D286,250", "C": "D255,000", "D": "D236,250"}, "answer": "B", "explanation": "Factory fuel150 000 Indirect wages 31 250 Factory power  105 000 286 250", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>12", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "\"Financial statement do not disclose all information users need to known about a firm\". This is the concept of", "images": [], "options": {"A": "consistency", "B": "money measurement", "C": "dual aspect", "D": "materiality"}, "answer": "D", "explanation": "Material concept only disclose and record items that only affect the organization.   Money measurement concept states that only item that can be capable of being measured in monetary value should be recorded.   Dual aspect concepts states that every transaction has two parts; the part of receiving and the part of giving.   Consistency convention states the treatment of like item should be consistent from one period to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>13", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is not a source of revenue for local government?", "images": [], "options": {"A": "Mining royalties", "B": "Radio and T.V licenses", "C": "Tenement/property rates", "D": "Business permit fee"}, "answer": "A", "explanation": "Mining royalties are not a source of revenue for local government. Mining royalties are typically paid to the national government or state in some countries, not to local government. The other options like Radio and T.V licenses, Tenement/property rates, Business permit fee are typical sources of revenue for local governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>14", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A difference between the debit and credit totals in a trial Balance is placed in", "images": [], "options": {"A": "bank reconciliation statement", "B": "profit and loss account", "C": "suspense account", "D": "appropriation account"}, "answer": "C", "explanation": "A difference between the debit and credit totals in a trial balance is placed in a suspense account. A suspense account is a temporary account that is used when an account cannot be properly identified during a transaction. The suspense account is used until such time that the correct account can be determined. The other options like bank reconciliation statement, profit and loss account, appropriation account are not used for this purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>15", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CASH BOOK : THREE COLUMN CASH BOOK", "question": "A three column Cash Book contains columns for", "images": [], "options": {"A": "Cash, Assets and liabilities", "B": "bank, Cash and Assets", "C": "Cash, Bank and Returns", "D": "Discount, Cash and Bank"}, "answer": "D", "explanation": "A three-column cash book typically contains columns for Discount, Cash, and Bank. The Discount column is used to record cash discounts allowed and received. The Cash column is used to record all cash transactions. The Bank column is used to record all bank transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>16", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "The total debtors account of a trading concern is ₦13,000. Out of this 2% is irrecoverable. 5% of the balance is nit likely to be collected. What is the provision for doubtful debts?", "images": [], "options": {"A": "₦910", "B": "₦650", "C": "₦637", "D": "₦260"}, "answer": "C", "explanation": "First, calculate the irrecoverable amount which is 2% of ₦13,000 = ₦260. Subtract this from the total debtors account: ₦13,000 - ₦260 = ₦12,740. Then, calculate 5% of this balance as the provision for doubtful debts: 5% of ₦12,740 = ₦637.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>17", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not part of factory overhead?", "images": [], "options": {"A": "Factory salaries", "B": "Factory lighting and heating", "C": "Depreciation of plant and machinery", "D": "Depreciation of fixtures and fittings"}, "answer": "D", "explanation": "Factory overhead refers to the indirect factory-related costs that are incurred when a product is manufactured. This includes costs related to indirect materials, indirect labor, factory rent, factory insurance, factory lighting, heating and cooling, and depreciation on factory assets. However, depreciation of fixtures and fittings is not considered part of factory overhead as they are not directly related to the manufacturing process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>18", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Cost of extension to a factory building is classified as", "images": [], "options": {"A": "capital receipt", "B": "revenue receipt", "C": "revenue expenditure", "D": "capital expenditure"}, "answer": "D", "explanation": "The cost of extension to a factory building is classified as capital expenditure. Capital expenditure, or CapEx, are funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, an industrial plant, technology, or equipment. This is done to increase the capacity or efficiency of the company for the long term. In this case, extending a factory building is a form of improvement to increase its capacity, hence it is considered a capital expenditure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>19", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following does not appear in a bank statement?", "images": [], "options": {"A": "Dividend received", "B": "Bank charges", "C": "uncredited cheques", "D": "Dishonoured cheques"}, "answer": "C", "explanation": "Uncredited cheque are cheque recorded in cash book but yet to be recorded by the bank. It is not an item in the bank statement.     Items in the bank statements are: credit transfer, standing order, bank charges, dividend, dishonoured cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>20", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "The purchase of a typewriter for office use for c2,000 is debited to", "images": [], "options": {"A": "creditors", "B": "bank account", "C": "purchase account", "D": "equipment account"}, "answer": "D", "explanation": "When a business purchases an asset like a typewriter for office use, the cost of the asset is debited to the equipment account. This is because the typewriter is a tangible asset that will provide future economic benefits to the business, and therefore it is classified as equipment. The equipment account is a type of fixed asset account, which is used to record the cost of assets that are not expected to be converted into cash within one year. Creditors account, bank account, and purchase account are not the correct accounts to debit when a business purchases an asset for office use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>21", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The document making a public offer for the sale of a company's share is", "images": [], "options": {"A": "Memorandum of Association", "B": "Articles of Association", "C": "Prospectus", "D": "Certificate of Registration"}, "answer": "C", "explanation": "The document making a public offer for the sale of a company's share is a Prospectus. A prospectus is a legal document issued by companies that are offering securities for sale. It contains details about the company, its operations, and the securities being offered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>22", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Programs installed in computers to facilitate processing of data are", "images": [], "options": {"A": "hardware", "B": "software", "C": "magnetic tapes", "D": "diskettes"}, "answer": "B", "explanation": "Programs installed in computers to facilitate processing of data are software. Software is a collection of data or computer instructions that tell the computer how to work. This is in contrast to physical hardware, from which the system is built and actually performs the work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>23", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "In a not for profit making organization, the excess of income over expenditure is", "images": [], "options": {"A": "added to capital", "B": "added to accumulated fund", "C": "deducted from capital", "D": "deducted from accumulated fund"}, "answer": "B", "explanation": "In a not for profit making organization, the excess of income over expenditure is added to the accumulated fund. This is because the accumulated fund is a reserve which is built up by retaining the surplus income over expenditure. It is not a capital because the organization is not a profit-making entity and does not have shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>24", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the information to answer this question.    The authorized capital of City Entertainment Company is made up of 200,000       2 1/2 %preference shares of Le 60 each and 300,000 ordinary shares of Le 20,      80% of the ordinary shares have been insured at Le 30 each and fully paid. The directors decided to pay preference dividend and recommended ordinary dividend of Le 0.10 per share    What is the amount of preference dividend payable for the year?", "images": [], "options": {"A": "Le 600,000", "B": "Le 500,000", "C": "Le 300,000", "D": "Le 5,000"}, "answer": "C", "explanation": "The amount of preference dividend payable is calculated thus:  preference share dividend = 212% of authorized capital x 60    212%x200,000x60    2.5100x200,000x60    = Le( 5000 x 60)  = Le 300,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>25", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the information to answer this question.    The authorized capital of City Entertainment Company is made up of 200,000       2 1/2 %preference shares of Le 60 each and 300,000 ordinary shares of Le 20,      80% of the ordinary shares have been insured at Le 30 each and fully paid. The directors decided to pay preference dividend and recommended ordinary dividend of Le 0.10 per share   What is the amount of the share premium?", "images": [], "options": {"A": "Le 9,000,000", "B": "Le 5,000,000", "C": "Le 3,000,000", "D": "Le 2, 400,000"}, "answer": "D", "explanation": "The share premium is calculated as the difference between the issue price and the nominal value of the shares. In this case, 80% of the ordinary shares have been issued at Le 30 each, while their nominal value is Le 20. Therefore, the share premium per share is Le 30 - Le 20 = Le 10. Since 80% of 300,000 shares have been issued, the total share premium is Le 10 * 0.8 * 300,000 = Le 2,400,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>26", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the information to answer this question.    The authorized capital of City Entertainment Company is made up of 200,000       2 1/2 %preference shares of Le 60 each and 300,000 ordinary shares of Le 20,      80% of the ordinary shares have been insured at Le 30 each and fully paid. The directors decided to pay preference dividend and recommended ordinary dividend of Le 0.10 per share   The value of the ordinary share capital to be stated in the balance sheet is", "images": [], "options": {"A": "Le 9,000,000", "B": "Le 7,200,000", "C": "Le 4,800,000", "D": "Le 5,000,000"}, "answer": "C", "explanation": "The value of the ordinary share capital to be stated in the balance sheet is the nominal value of the shares multiplied by the number of shares issued.     In this case, the nominal value is Le 20 and 80% of 300,000 shares have been issued.     Therefore, the value of the ordinary share capital is Le 20 x 0.8 x 300,000   = Le 4,800,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>27", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "The petty cash book has", "images": [], "options": {"A": "a debit balance only", "B": "a credit balance only", "C": "a nil balance only", "D": "both debit and credit balance"}, "answer": "D", "explanation": "Petty cash book is a type of cash book having both debit and credit side for recording transaction involving small cash.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>28", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Credit sales was debited to A. Akpan instead of B. Akpan. This is an error of", "images": [], "options": {"A": "principle", "B": "original entry", "C": "omission", "D": "commission"}, "answer": "D", "explanation": "The error described is an error of commission. This type of error occurs when an incorrect entry is made, or an entry is made in the wrong account, but the correct type of account. In this case, the credit sales were debited to A. Akpan instead of B. Akpan, which is a wrong account but the correct type of account (i.e., debtor's account).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>29", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question.     A motor car costing D100,000 was depreciated at 20% per annum by the diminishing balance method. Two years later, it was sold for D60,000    The net profit or loss on the sales was", "images": [], "options": {"A": "D 40,000 profit", "B": "D 4,000 profit", "C": "D 4,000 loss", "D": "D 40,000 loss"}, "answer": "C", "explanation": "Asset Cost Depreciation N.B.V 1. Moto van 100 000 20 000 80 0002. -  100 000 16 000 64 0003. -    Asset was sold for 60 000    4000 loss    Calculations   Depreciation for year1 = 20% x 100,000  = D20,000  Depreciation for year2 = 20% x 80,000   = 16,000  The netbook value is = 64,000    Two years later,  it was sold for 60,000   i.e 64,000 - 60,000   = 4,000 Loss on sale of the asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>30", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question.     A motor car costing D100,000 was depreciated at 20% per annum by the diminishing balance method. Two years later, it was sold for D60,000   The net book value at the time of sale is", "images": [], "options": {"A": "D 64,000", "B": "D 60,000", "C": "D 40,000", "D": "D 36,000"}, "answer": "A", "explanation": "The net book value is D64,000 from the account prepared.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>31", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A service which a firm has enjoyed, but which has not yet been paid for is", "images": [], "options": {"A": "accrued expense", "B": "preliminary expense", "C": "prepaid expense", "D": "overhead expense"}, "answer": "A", "explanation": "An accrued expense is an accounting term that refers to an expense that is recognized on the books before it has been paid. The expense is recognized in the accounting period in which it is incurred. Therefore, if a service has been enjoyed but not yet paid for, it is an accrued expense.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>32", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "Which of the following is not part of the double entry system?", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Appropriation Account", "D": "Balance sheet"}, "answer": "D", "explanation": "Balance sheet also known as statement of financial position. It shows the business asset and liabilities as well as the capital used in financing the business. It does not form part of double entry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>33", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "In the balance sheet, the balance on the Provision for Depreciation Account is shown as", "images": [], "options": {"A": "additional to fixed assets", "B": "deduction from fixed assets", "C": "addition to capital", "D": "deduction from current liabilities"}, "answer": "B", "explanation": "In the balance sheet, the balance on the Provision for Depreciation Account is shown as a deduction from fixed assets. This is because the provision for depreciation is an accumulated depreciation which is subtracted from the cost of the fixed assets to give the net book value of the assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>34", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "S. Sule sets aside from his private fund ₦20,000 for business purposes. The ₦20,000 is referred to as", "images": [], "options": {"A": "drawings", "B": "capital", "C": "loan", "D": "profit"}, "answer": "B", "explanation": "When S. Sule sets aside from his private fund ₦20,000 for business purposes, the ₦20,000 is referred to as capital. Capital refers to the amount of money that the owner of the business has invested in the business. It is not a loan because it does not need to be repaid, and it is not profit because it is not earnings from the business operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>35", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "An article cost ₦1,800 and is sold at a gross profit of 20% on selling price. What is the selling price?", "images": [], "options": {"A": "₦2,250", "B": "₦2,160", "C": "₦1,800", "D": "₦1,440"}, "answer": "B", "explanation": "Cost = ₦1,800  120% of cost = selling price   Selling price = 120100x1800     = ₦2,160", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>36", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following are Personal Account   I. Wages II. Debtors   III. Creditors IV. Building", "images": [], "options": {"A": "I, II and III only", "B": "II and III only", "C": "II and IV only", "D": "III and IV only"}, "answer": "B", "explanation": "Personal accounts are accounts related to individuals, firms, companies, etc. They include debtors and creditors. Wages and buildings are not personal accounts. Wages are an expense account and buildings are an asset account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>37", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Prepayment is treated in the balance sheet of a firm as a", "images": [], "options": {"A": "fixed asset", "B": "long-term liability", "C": "current asset", "D": "current liability"}, "answer": "C", "explanation": "Prepayment is an amount paid for a service or product that will be received in the future. According to accounting principles, prepayments are considered current assets because they provide a future economic benefit. A current asset is any asset that can reasonably be expected to be sold, consumed, or exhausted through the normal operations of a business within the current fiscal year or operating cycle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>38", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is found in a Sales Ledger Account?", "images": [], "options": {"A": "Credit purchases", "B": "Bill payable", "C": "Discount received", "D": "Discount allowed"}, "answer": "D", "explanation": "A Sales Ledger Account is a record of a company's sales, whether paid or unpaid. It includes all the transactions related to sales such as discounts allowed. Discount allowed is a reduction in price given by the supplier of goods or services on the list price. This is done to encourage the buyer to make payment within a specified time. Therefore, 'Discount allowed' is found in a Sales Ledger Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>39", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The authority of the Account-General to disburse from government fund is", "images": [], "options": {"A": "provision", "B": "warrant", "C": "vote", "D": "estimate"}, "answer": "B", "explanation": "The authority of the Account-General to disburse from government fund is given by a warrant. A warrant is a legal document that gives the authority to an officer to pay out money from the treasury for the item specified in the warrant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>40", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Use the following information to answer question 40.       Bank Statement  Dr Cr Balance    e   e   e 2/1/06 Balance b/d   2 0003/1/06 '23456' 500 1 5004/1/06 Deposit 1 000 2 5005/1/06 Deposit  1 500 4 0006/1/06 '23457' 3 000 1 000     Total withdrawal is", "images": [], "options": {"A": "e 3,500", "B": "e 2,500", "C": "e 2,000", "D": "e 1,000"}, "answer": "A", "explanation": "The total withdrawal from the bank account can be calculated by adding up all the debit entries in the bank statement. In this case, the debit entries are 500 and 3,000, which add up to 3,500. Therefore, the total withdrawal is 3,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2009>41", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The depreciation on plant acquired by a manufacturing company is treated as", "images": [], "options": {"A": "prime cost", "B": "administrative expenses", "C": "Factory overhead", "D": "selling and distribution expenses"}, "answer": "C", "explanation": "Depreciation on plant acquired by a manufacturing company is treated as Factory overhead. This is because the plant is used in the production process, and its depreciation is considered part of the cost of manufacturing. Factory overheads are all the costs incurred in the production process that are not directly linked to the production of goods, such as indirect materials, indirect labor, and other indirect costs like depreciation on plant and machinery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>42", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "As evidence of payment to a government treasury, revenue collectors issue", "images": [], "options": {"A": "treasury card", "B": "receipt voucher card", "C": "treasury receipt", "D": "payment voucher"}, "answer": "C", "explanation": "As evidence of payment to a government treasury, revenue collectors issue a treasury receipt. This is a document that serves as proof that a payment or deposit has been made into a government treasury. It is issued by the revenue collector after the payment has been made.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>43", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Hardware in data processing refers to", "images": [], "options": {"A": "programs run on the computer", "B": "entry and storage of information on computer", "C": "microsoft disc operating system", "D": "mechanical components of the computer"}, "answer": "D", "explanation": "In computing, hardware refers to the physical components of a computer system. These include the central processing unit, monitors, keyboards, mouse, printers, and other mechanical components that make up a computer. Therefore, the correct answer is 'mechanical components of the computer'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>44", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "Which of the following is a self-balance account?", "images": [], "options": {"A": "Trading Account", "B": "Appropriation Account", "C": "Assets Account", "D": "Control Account"}, "answer": "D", "explanation": "A self-balancing account is an account that is maintained in the general ledger to check the arithmetical accuracy of the ledger. The Control Account is a summary account in the General Ledger. This is also known as a total or control account. Therefore, the correct answer is 'Control Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>45", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "A medium of inputting data into the computer is through the use of the", "images": [], "options": {"A": "keyboard", "B": "monitor", "C": "software", "D": "hardware"}, "answer": "A", "explanation": "A keyboard is a primary input device used to enter data into a computer. It allows a user to input letters, numbers, and other symbols into a computer that can serve as commands or be used to type text. The monitor, software, and hardware are not mediums for inputting data into the computer. The monitor is an output device, software is a set of instructions that tell the computer what to do, and hardware refers to the physical components of a computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>46", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is debited to partner's current account?", "images": [], "options": {"A": "Capital", "B": "Interest on capital", "C": "Drawings", "D": "Share of profit"}, "answer": "C", "explanation": "Drawings is a debit item in the partner's current account.  Other item is interest on drawings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>47", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use this information to answer this questions.  Abu, a debtor to Dania, owned  e  10,500 at the start of the month. He paid cash of  e  40,005 during the month and received additional credit sales of  e 20,000    Abu's balance at the end of the month is", "images": [], "options": {"A": "e  30,505 cr.", "B": "e  9,505 cr.", "C": "e  8,505 cr.", "D": "e  30,500 cr."}, "answer": "B", "explanation": "Abu started with a debt of 10,500. During the month, he paid 40,005 in cash, which reduced his debt. However, he also received additional credit sales of 20,000, which increased his debt. So, at the end of the month, his balance would be the initial debt, minus the cash payment, plus the additional credit sales. That is, 10,500 - 40,005 + 20,000 = -9,505. Since this is a negative number, it means Abu is now a creditor to Dania, not a debtor. Therefore, the balance is 9,505 cr.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>48", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use this information to answer this questions.  Abu, a debtor to Dania, owned  e  10,500 at the start of the month. He paid cash of  e  40,005 during the month and received additional credit sales of  e 20,000   In Dania's book, to record the payment of  e  40,005 by Abu", "images": [], "options": {"A": "debit Cash Account, credit Abu's Account", "B": "debit Abu's Account, credit Cash Account", "C": "debit Cash Account, credit Sales Account", "D": "debit Sales Account, credit Cash Account"}, "answer": "A", "explanation": "When Abu pays Dania, Dania's cash account increases, so it should be debited (as per the rule 'Debit what comes in'). Also, Abu's account (a debtor's account) decreases, so it should be credited (as per the rule 'Credit what goes out'). Therefore, the correct entry is 'Debit Cash Account, Credit Abu's Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2009>49", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "A debenture holder is a", "images": [], "options": {"A": "creditor", "B": "promoter", "C": "debtor", "D": "shareholder"}, "answer": "A", "explanation": "A debenture holder is a creditor of the company. A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. Therefore, the debenture holders are considered as creditors of the company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2009>50", "subject": "Accounts", "year": "2009", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A stock as a form of capital of a company compromises", "images": [], "options": {"A": "tons of merchandise", "B": "units of goods", "C": "units of shares", "D": "bundles of wares"}, "answer": "C", "explanation": "A stock as a form of capital of a company comprises units of shares. In the context of a company, a stock represents ownership in the company and constitutes a claim on part of the company's assets and earnings. Therefore, the stock of a company is divided into units of shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>1", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Which of the following is not an external user of accounting information?", "images": [], "options": {"A": "Management", "B": "Creditors", "C": "Shareholders", "D": "Government"}, "answer": "A", "explanation": "Management is considered an internal user of accounting information. They use this information to make strategic decisions for the company. External users, such as creditors, shareholders, and government, do not participate in the day-to-day operations of the business but use the accounting information to make decisions related to the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>2", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "A trial balance is prepared to", "images": [], "options": {"A": "detect fraud", "B": "ascertain losses in a trading period", "C": "determine opening capital", "D": "test arithmetical accuracy of ledger entries"}, "answer": "D", "explanation": "A trial balance is prepared to test the arithmetical accuracy of ledger entries. It is a statement that lists the balances of all ledger accounts to check the equality of debits and credits. It does not detect fraud, ascertain losses in a trading period, or determine opening capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>3", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Which of the following is the reason why a seller allows a customer cash discount?", "images": [], "options": {"A": "Agreement to become a regular customer", "B": "Introducing a new customer to the seller", "C": "Settlement of account within a stated period", "D": "Placing a large order"}, "answer": "C", "explanation": "A cash discount is a deduction allowed by the seller of goods or by the provider of services in order to motivate the customer to pay within a specified time. The seller or provider often refers to this discount as a sales discount, and the buyer refers to the same discount as a purchase discount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>4", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "A ledger is a", "images": [], "options": {"A": "principal book of accounts", "B": "book of original entry", "C": "record of credit transaction", "D": "summary of entries"}, "answer": "A", "explanation": "A ledger is the principal book or computer file for recording and totaling economic transactions measured in terms of a monetary unit of account by account type, with debits and credits in separate columns and a beginning monetary balance and ending monetary balance for each account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>5", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is not found in a trial balance?", "images": [], "options": {"A": "Opening stock", "B": "Closing stock", "C": "Capital", "D": "Rent paid"}, "answer": "B", "explanation": "A trial balance is a bookkeeping worksheet in which the balances of all ledgers are compiled into debit and credit account column totals that are equal. It includes all the ledger accounts including assets, liabilities, income, expenses and capital. Among the options, 'Closing stock' is not included in the trial balance. It is because closing stock is not a ledger account, it is an adjustment entry which is shown on the credit side of trading account and assets side of balance sheet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>6", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer this question.   Jan. 1  ₦1/1/08 Capital introduced by cash 50 000 2/1/08 Bought goods for retail by cash 10 0003/1/08 Bought fixtures by cash 5 0004/1/08 Sold goods to Lagbaja on credit 3 0005/1/08 Bought goods on credit from Tamedu 8 000    Cash balance at 5/1/08 is", "images": [], "options": {"A": "₦ 50,000", "B": "₦ 40,000", "C": "₦ 35,000", "D": "₦ 30,000"}, "answer": "C", "explanation": "The cash balance can be calculated by adding and subtracting the cash transactions. On Jan 1, the cash introduced is ₦50,000. On Jan 2, goods were bought for ₦10,000, reducing the cash balance to ₦40,000. On Jan 3, fixtures were bought for ₦5,000, further reducing the cash balance to ₦35,000. The transactions on Jan 4 and Jan 5 do not affect the cash balance as they were on credit. Therefore, the cash balance at 5/1/08 is ₦35,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>7", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer this question.   Jan. 1  ₦1/1/08 Capital introduced by cash 50 000 2/1/08 Bought goods for retail by cash 10 0003/1/08 Bought fixtures by cash 5 0004/1/08 Sold goods to Lagbaja on credit 3 0005/1/08 Bought goods on credit from Tamedu 8 000  Balance in Purchases Account at 5/1/08 is", "images": [], "options": {"A": "₦23,000", "B": "₦ 18,000", "C": "₦ 10,000", "D": "₦ 8,000"}, "answer": "B", "explanation": "The balance in the Purchases Account at 5/1/08 is calculated by adding the amount of goods bought for retail by cash on 2/1/08 and the amount of goods bought on credit from Tamedu on 5/1/08. This gives a total of ₦10,000 + ₦8,000 = ₦18,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>8", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer this question.   Jan. 1  ₦1/1/08 Capital introduced by cash 50 000 2/1/08 Bought goods for retail by cash 10 0003/1/08 Bought fixtures by cash 5 0004/1/08 Sold goods to Lagbaja on credit 3 0005/1/08 Bought goods on credit from Tamedu 8 000  Balance in the Capital Account 5/1/08 is", "images": [], "options": {"A": "₦ 60,000", "B": "₦ 50,000", "C": "₦ 35,000", "D": "₦ 5,000"}, "answer": "B", "explanation": "The balance in the Capital Account on 5/1/08 is the initial capital introduced by cash on 1/1/08, which is ₦50,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>9", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A suspense account is used to", "images": [], "options": {"A": "correct errors", "B": "record errors detected until corrected", "C": "prepare the balance sheet", "D": "extract the trial balance"}, "answer": "B", "explanation": "A suspense account is a temporary account used in the general ledger to record errors detected until they are corrected. It is used when the nature of the error is not known and further investigation is required. Once the error is identified and corrected, the suspense account is cleared.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>10", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following is added to the proprietor's capital?", "images": [], "options": {"A": "Net profit", "B": "Gross profit", "C": "Net Sales", "D": "Gross sales"}, "answer": "A", "explanation": "Net profit is added to the proprietor's capital. The proprietor's capital is the amount of money that the owner has invested in the business. When a business makes a net profit, this increases the amount of capital that the owner has in the business. Gross profit, net sales, and gross sales are not added to the proprietor's capital as they are income and not capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>11", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Where a wrong figure occurs in only one account with the second figure correctly stated, this is an error of", "images": [], "options": {"A": "transposition", "B": "compensation", "C": "omission", "D": "commission"}, "answer": "A", "explanation": "Error of transposition is data entry error that occurs when two digits are accidentally reversed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>12", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A temporary difference in the Trial Balance totals is kept in the", "images": [], "options": {"A": "Adjustment Account", "B": "Suspense Account", "C": "Imprest Account", "D": "Appreciation Account"}, "answer": "B", "explanation": "A Suspense Account is a temporary account that is used when there is a difference in the Trial Balance totals. The difference is kept in the Suspense Account until the error causing the difference is found and corrected. Therefore, a temporary difference in the Trial Balance totals is kept in the Suspense Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>13", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "In the preparation of bank reconciliation statement uncredited cheques are", "images": [], "options": {"A": "added to the balance as per bank statement", "B": "deducted from the balance as per bank statement", "C": "added to the balance as per cash book", "D": "ignored totally"}, "answer": "A", "explanation": "In the preparation of a bank reconciliation statement, uncredited cheques are added to the balance as per bank statement. This is because uncredited cheques are those cheques which have been issued by the business but have not yet been presented to the bank for payment. Therefore, the bank is not aware of these cheques and hence, the bank balance is higher than the cash book balance. To reconcile the two balances, the amount of uncredited cheques is added to the balance as per bank statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>14", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is found in the general ledger?", "images": [], "options": {"A": "Capital Accounts", "B": "Sales Account", "C": "Loan Accounts", "D": "Drawing Accounts"}, "answer": "B", "explanation": "General ledger contains the nominal and real accounts. It also contains the sales account, purchases account, returns inwards and returns outwards account as well as account for assets, expenses, income etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>15", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer this question.     1/1/06 ----- Debtor -------- D2,600  1/1/06 ----- Provision for bad debts --------- D60  31/12/06 ---- Bad debts --------- D60   31/12/06 New provision for bad debts 5% on debtors    What is the amount for the new provision and for bad debts?", "images": [], "options": {"A": "D130", "B": "D127", "C": "D124", "D": "D120"}, "answer": "B", "explanation": "The new provision for bad debts is calculated as 5% of the remaining debtors after deducting the bad debts. The remaining debtors are D2,600 - D60 = D2,540. Therefore, the new provision for bad debts is 5% of D2,540 = D127. The amount for bad debts is D60. Therefore, the correct answer is D127 for the new provision and D60 for bad debts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2010>16", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer this question.     1/1/06 ----- Debtor -------- D2,600  1/1/06 ----- Provision for bad debts --------- D60  31/12/06 ---- Bad debts --------- D60   31/12/06 New provision for bad debts 5% on debtors  The provision for bad debts in the profit and loss account is", "images": [], "options": {"A": "D187", "B": "D127", "C": "D67", "D": "D60"}, "answer": "C", "explanation": "New provision for bad debt D127  - Old provision for bad debt D60  There is an increase of D67. The amount of increase is treated as expenses in the profit & loss A/C", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2010>17", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The balance in a Sales Ledger Control Account indicates the", "images": [], "options": {"A": "difference between debtors and creditors", "B": "total sales", "C": "total purchases", "D": "total debtors"}, "answer": "D", "explanation": "The balance in a Sales Ledger Control Account indicates the total debtors. The Sales Ledger Control Account is a summary account that reflects the total of individual debtor accounts. It is used to ensure that the sum of all individual debtor balances matches the total balance of the Sales Ledger Control Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>18", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Sales was D12,500, total expenses was D2,500 and net profit is 10% of sales. What is the gross profit?", "images": [], "options": {"A": "D11,250", "B": "D8,750", "C": "D3,750", "D": "D1,250"}, "answer": "C", "explanation": "Net profit = 10% of sales    = 10% x D12,500   = D1,250     Net profit = Gross profit - Expenses   Gross Profit = Net profit + Expenses.   Gross profit = D1,250 + D 2500   = D3,750", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>19", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Which of the following is the equivalent of the Receipts and Payment Account?", "images": [], "options": {"A": "Income and Expenditure Accounts", "B": "Cash Book", "C": "Subscription Account", "D": "Profit and Loss Account"}, "answer": "B", "explanation": "The Receipts and Payments Account is equivalent to the Cash Book. This is because both accounts record all cash transactions of an organization. Cash Book is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the Cash Book are then posted into the general ledger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>20", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscriptions received in advance are", "images": [], "options": {"A": "included in the Income and Expenditure Account", "B": "not included in the Receipt and Payments Account", "C": "shown as current asset in Balance Sheet", "D": "shown in the Balance Sheet as a current liability"}, "answer": "D", "explanation": "Subscriptions received in advance are shown in the Balance Sheet as a current liability. This is because they represent amounts that the organization has received, but has not yet earned. In accounting, such amounts are considered liabilities because there is an obligation to provide services in the future.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>21", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "Where records maintained are inadequate to facilitate the preparation of a trading and profit and loss account, this is described as", "images": [], "options": {"A": "cost accounting", "B": "book-keeping", "C": "incomplete records", "D": "double entry"}, "answer": "C", "explanation": "The term 'incomplete records' refers to a situation where the double-entry accounting system is not fully implemented, or where records are not sufficiently maintained to allow for the preparation of financial statements, such as a trading and profit and loss account. The other options do not accurately describe this situation. 'Cost accounting' is a form of managerial accounting that aims to capture a company's total cost of production by assessing the variable costs of each step of production as well as fixed costs. 'Book-keeping' is the process of recording daily transactions in a consistent way, and it is a key component to building a financially successful business. 'Double entry' is a method of book-keeping where every entry to an account requires a corresponding and opposite entry to a different account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>22", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      ₦Opening stock of raw materials 24 750 Purchase of raw materials 123 640Carriage on raw materials 10 000Closing stock of raw materials 45 000Factory supervisor's salary 30 000Wages of factory hands 50 000Royalties paid 18 000Insurance of factory 62 000Work-in-progress (opening) 23 000Raw material returned 12 200    The value of raw material consumed is", "images": [], "options": {"A": "₦ 121,440", "B": "₦113,390", "C": "₦111,190", "D": "₦101,190"}, "answer": "D", "explanation": "Opening stock of raw material 24 750 Add: purchase of raw material 123 640Carriage on raw materials 10 000Less: Return outward on raw materials 12 200Cost of raw material available for use 146 190Less: closing stock of raw material 45 000Cost of raw material consumed 101 190", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>23", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      ₦Opening stock of raw materials 24 750 Purchase of raw materials 123 640Carriage on raw materials 10 000Closing stock of raw materials 45 000Factory supervisor's salary 30 000Wages of factory hands 50 000Royalties paid 18 000Insurance of factory 62 000Work-in-progress (opening) 23 000Raw material returned 12 200  The prime cost is", "images": [], "options": {"A": "₦199,190", "B": "₦169,190", "C": "₦151,190", "D": "₦146,190"}, "answer": "B", "explanation": "The prime cost is calculated as the sum of the cost of raw materials and direct labor. The cost of raw materials is calculated as the :  opening stock of raw materials + purchases + carriage on raw materials - closing stock of raw materials + raw materials returned.     Direct labor is the wages of factory hands.     Therefore, the prime cost is:   (24,750 + 123,640 + 10,000 + 18000 - 45,000 - 12,200) + 50,000   = ₦169,190.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>24", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question.      ₦Opening stock of raw materials 24 750 Purchase of raw materials 123 640Carriage on raw materials 10 000Closing stock of raw materials 45 000Factory supervisor's salary 30 000Wages of factory hands 50 000Royalties paid 18 000Insurance of factory 62 000Work-in-progress (opening) 23 000Raw material returned 12 200  The total overhead expenses is", "images": [], "options": {"A": "₦142,000", "B": "₦115,000", "C": "₦110,000", "D": "₦92,000"}, "answer": "D", "explanation": "The total overhead expenses is the sum of the factory supervisor's salary, and insurance of the factory.     Therefore, the total overhead expenses is 30,000 + 62,000   = ₦92000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>25", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Bad debts written off is shown as", "images": [], "options": {"A": "debt in the sales ledger", "B": "debt in the purchases ledger", "C": "credit in the sales ledger", "D": "credit in the purchase ledger"}, "answer": "C", "explanation": "Bad debts written off is shown as a credit in the sales ledger. When a debt is written off, it means that the business has decided that the debt is uncollectible and has removed it from their books. This is done by crediting the sales ledger, which decreases the amount of accounts receivable that the business has.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>26", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The balance of sales ledger control account represents", "images": [], "options": {"A": "total sales", "B": "total credit sales", "C": "total creditors", "D": "total debtors"}, "answer": "D", "explanation": "The balance of sales ledger control account represents total debtors. The sales ledger control account is a summary account that reflects the total of all individual debtor accounts. Therefore, the balance of this account represents the total amount owed to the business by its customers, or in other words, its total debtors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>27", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting principle that states that insignificant expenditure are not to be taken unto account is the", "images": [], "options": {"A": "realization concept", "B": "materiality convention", "C": "marching concept", "D": "consistency convention"}, "answer": "B", "explanation": "The materiality convention in accounting states that all significant items must be reported but insignificant items can be disregarded. This principle allows accountants to ignore rules of accounting if an item is too insignificant to affect users' business decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>28", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "Which of the following transactions will increase the working capacity of a business?", "images": [], "options": {"A": "Payment in cash to a creditor", "B": "Payment by cheque to a creditor", "C": "Sale of fixed asset in cash", "D": "Cash received from debtors"}, "answer": "C", "explanation": "Working capital is the excess of the business current assets over the current liabilities when there is sale of fixed asset in cash, the amount of current asset will increase by the amount received from the sales and this will cause the working capital to increase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>29", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The realization concept states that", "images": [], "options": {"A": "revenue is recognized as being earned when ownership of goods passes to the customer.", "B": "revenue and profit should not be anticipated", "C": "similar items should be accounted for in a similar way from one accounting period to another", "D": "transactions must be expressed in monetary terms"}, "answer": "A", "explanation": "The realization concept in accounting states that revenue is recognized when it is earned, which is typically when goods or services are transferred or provided to the customer. This is when the ownership of goods passes to the customer. This concept is important as it helps to match revenues with the expenses incurred in earning those revenues, providing a more accurate picture of a company's financial performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>30", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Where fixed capitals are maintained, partners' drawing are transferred to the", "images": [], "options": {"A": "credit of Capital Accounts", "B": "debit of Capital Accounts", "C": "credit of Partner's Current Accounts", "D": "debit of Partners' Current Accounts"}, "answer": "D", "explanation": "In a partnership where fixed capitals are maintained, partners' drawings are transferred to the debit of Partners' Current Accounts. This is because when a partner withdraws from the business for personal use, it reduces the amount of capital available in the business. Therefore, it is debited (increased) in the partner's current account, not the capital account. The capital account remains unchanged or 'fixed' unless additional capital is introduced or a part of profit is transferred to it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>31", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The method that provides a reliable check upon cash and stock at the branch and discloses the gross profit in the accounts is", "images": [], "options": {"A": "cost plus percentage", "B": "cost price", "C": "average cost", "D": "selling price"}, "answer": "A", "explanation": "Cost plus percentage is one of the methods for stock branches. It is the most reliable method as it provide check upon cash and stock.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>32", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS(PARTNERSHIP)", "question": "A partner whose liability goes beyond his capital is known as", "images": [], "options": {"A": "dormant partner", "B": "limited partner", "C": "general partner", "D": "nominal partner"}, "answer": "C", "explanation": "A general partner is a partner whose liability goes beyond his capital. This means that in the event of the partnership's debts exceeding its assets, the general partner's personal assets can be used to settle the debts. This is different from a limited partner whose liability is limited to the amount of capital they have invested in the partnership.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>33", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question.  Aba and Baba are partners who agree to share profits and losses in the ratio 4:3 respectively. Extracts from their books for the year ended 31/12/08 are:       ABA BABA TOTAL    e   e   e Capital 20 000 15 000 35 000Drawings 2 520 -  2 520Interest on drawings 504 -  504Interest on capital 2 000 1 500 3 500Net profit 31/12/08 -  -  34 636    Aba's share of profit is", "images": [], "options": {"A": "e 21,504", "B": "e 19,792", "C": "e  18,352", "D": "e  18,080"}, "answer": "D", "explanation": "Dr. Partners appropriation A/C Cr.   Interest on capital  Net profit 34 636ABA 2 000 Interest on drawing BABA 1 500 ABA 504   BABA - Share of profit   ABA 4/7x31 640 18 080  BABA 3/7x31 640 13 560    35 140  35 140      Aba's share of profit is  c 18,080 from the account prepared", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2010>34", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question.  Aba and Baba are partners who agree to share profits and losses in the ratio 4:3 respectively. Extracts from their books for the year ended 31/12/08 are:       ABA BABA TOTAL    e   e   e Capital 20 000 15 000 35 000Drawings 2 520 -  2 520Interest on drawings 504 -  504Interest on capital 2 000 1 500 3 500Net profit 31/12/08 -  -  34 636  Baba's share of profit is", "images": [], "options": {"A": "e  16,128", "B": "e  14,844", "C": "e  13,764", "D": "e  13,560"}, "answer": "D", "explanation": "Baba's share of profit is  e  13,560 from the account prepared", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2010>35", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question.  Aba and Baba are partners who agree to share profits and losses in the ratio 4:3 respectively. Extracts from their books for the year ended 31/12/08 are:       ABA BABA TOTAL    e   e   e Capital 20 000 15 000 35 000Drawings 2 520 -  2 520Interest on drawings 504 -  504Interest on capital 2 000 1 500 3 500Net profit 31/12/08 -  -  34 636  The rate of interest on capital is", "images": [], "options": {"A": "15%", "B": "10%", "C": "8%", "D": "5%"}, "answer": "B", "explanation": "The rate of interest on capital is calculated thus,  To get the rate for ABA  R% of 20,000 = 2,000  R% = 12,00020,000=0.1    R = 0.1 x 100  R = 10%", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2010>36", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Carriage inwards is shown on the", "images": [], "options": {"A": "debit side of the trading account", "B": "credit side of the trading account", "C": "credit side of the profit and loss account", "D": "debit side of the profit and loss account"}, "answer": "A", "explanation": "Carriage inwards refers to the cost of transporting goods into a business. It is considered part of the cost of sales and therefore is recorded on the debit side of the trading account. The trading account is used to calculate the gross profit or loss of a business by comparing the costs of goods sold with the sales revenue. Costs of goods sold include the cost of purchasing the goods and any additional costs incurred to get the goods into a saleable condition, such as carriage inwards.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>37", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "An expense is termed an 'accrual' because it", "images": [], "options": {"A": "is yet to be paid for", "B": "is a profit and loss account item", "C": "must appear in the balance sheet", "D": "is a trading account"}, "answer": "A", "explanation": "An expense is termed an 'accrual' because it is yet to be paid for. Accruals are expenses that have been incurred but not yet paid. This concept is part of the accrual basis of accounting, where revenues and expenses are recorded when they are earned, regardless of when the money is actually received or paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>38", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The accounting treatment when goods are sent to branch at cost is, debit Branch Stock Account and credit", "images": [], "options": {"A": "Branch Stock Adjustment Account", "B": "Goods send to Branch Account", "C": "Branch Debtor's Account", "D": "Branch Profit and Loss Account"}, "answer": "B", "explanation": "The accounting treatment when goods are sent to branch at cost is, debit Branch Stock Account and credit Goods send to Branch Account. This is because when goods are sent to a branch, the branch stock account (an asset account) is increased (debited), and the goods sent to branch account (also an asset account) is decreased (credited). This reflects the movement of goods from the main business to the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>39", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The document for the disbursement of government fund is", "images": [], "options": {"A": "an invoice", "B": "a receipt", "C": "a payment voucher", "D": "a bill"}, "answer": "C", "explanation": "The document for the disbursement of government fund is a payment voucher. A payment voucher is a document that includes the details about a financial transaction. For a disbursement of funds, the payment voucher serves as proof of the money paid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>40", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "A financial plan of action expressed in monetary terms is a/an", "images": [], "options": {"A": "warrant", "B": "budget", "C": "imprest", "D": "consolidated fund"}, "answer": "B", "explanation": "A financial plan of action expressed in monetary terms is a budget. A budget is an estimation of revenue and expenses over a specified future period of time and is usually compiled and re-evaluated on a periodic basis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>41", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Which of the following reserves is not used for bonus shares?", "images": [], "options": {"A": "Revaluation reserve", "B": "Share premium", "C": "Capital redemption reserves fund", "D": "General reserve"}, "answer": "A", "explanation": "Revaluation reserve is not used for issuing bonus shares. Bonus shares are issued to the shareholders when the company has not enough cash to pay dividends. These shares are issued from the company's accumulated earnings. The revaluation reserve is created when the company revalues its assets and they have a higher market value. This reserve is not a realized profit and hence cannot be used for issuing bonus shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>42", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which assumes that the business will continue to be in existence into the foreseeable future is", "images": [], "options": {"A": "dual aspect", "B": "business entity", "C": "accrual", "D": "going - concern"}, "answer": "D", "explanation": "The 'going concern' concept in accounting assumes that the business will continue to operate in the foreseeable future. This assumption allows the business to defer some of its prepaid expenses until future accounting periods. This concept is fundamental to accrual accounting as it allows businesses to record revenues and expenses in the periods they are earned or incurred, rather than when the cash transactions occur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>43", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When shares are sold \"at par\" it means they are issued at", "images": [], "options": {"A": "the market value", "B": "the nominal value", "C": "a discount", "D": "a premium"}, "answer": "B", "explanation": "When shares are sold 'at par', it means they are issued at their nominal value. The nominal value is the face value of the share as stated in the company's articles of association. It is the value at which the share was originally issued and does not change with market fluctuations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>44", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Which of the following does not form part of share-holders fund?", "images": [], "options": {"A": "Ordinary shares", "B": "Shares premium", "C": "Profit", "D": "Debenture"}, "answer": "D", "explanation": "Shareholders' fund is made up of the money that belongs to the shareholders of a company. It includes ordinary shares, share premium, and profit. However, debentures do not form part of the shareholders' fund. Debentures are a type of debt instrument, not equity, and are therefore a liability to the company, not an asset or part of the shareholders' fund.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>45", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question.   On 1/7/07, a trader owed wages of Le 2 000. During the year ended 30/6/08, wages of Le 2,400 were owed and Le 8,000 were paid.    The wages of the year ended 30/6/08 is", "images": [], "options": {"A": "Le 12 400", "B": "Le 8 400", "C": "Le 8 000", "D": "Le 7 600"}, "answer": "B", "explanation": "From the account    Dr. Wages A/C Cr.     Le  LeCash 8 000 Bal. b/f 2 000Bal.c/d 2 400 P&L(missing figure) 8 400  10 400  10 400   Bal. b/d 2 400", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>46", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question.   On 1/7/07, a trader owed wages of Le 2 000. During the year ended 30/6/08, wages of Le 2,400 were owed and Le 8,000 were paid.   Wages recorded in the balance sheet as at 30/6/08 is", "images": [], "options": {"A": "Le 8,000", "B": "Le 6,000", "C": "Le 2,400", "D": "Le 2,000"}, "answer": "C", "explanation": "The wages recorded in the balance sheet as at 30/6/08 is the amount of wages owed at the end of the period. This is calculated by adding the wages owed at the start of the period (Le 2,000) to the wages owed during the year (Le 2,400) and then subtracting the wages paid during the year (Le 8,000). This gives a total of Le 2,400, which matches option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>47", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The collection and organization of data is", "images": [], "options": {"A": "accounting process", "B": "central processing", "C": "data processing", "D": "data manipulation"}, "answer": "C", "explanation": "The collection and organization of data is referred to as data processing. Data processing involves the collection, manipulation, and processing of data to achieve a specific outcome. It's a series of operations that use information to produce a result. Common methods of data processing include checking, validation, sorting, classification, calculation, interpretation, organization and transformation of data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>48", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "Money received from a customer is recorded in the customer's account and bank account; The accounting concept applied is", "images": [], "options": {"A": "business entity", "B": "dual aspect", "C": "going-concern", "D": "money measurement"}, "answer": "B", "explanation": "The scenario described in the question is an application of the dual aspect concept in accounting. The dual aspect concept, also known as the duality principle, is a fundamental concept in accounting. It states that every financial transaction has two effects on a company's finances - a debit and a credit. In this case, receiving money from a customer increases (credits) the bank account and decreases (debits) the customer's account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2010>49", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "The amount for which a business is sold is the", "images": [], "options": {"A": "goodwill", "B": "consolidated fund", "C": "purchase consideration", "D": "capital reserve"}, "answer": "C", "explanation": "The amount for which a business is sold is known as the purchase consideration. This is the total value that is agreed upon between the buyer and the seller for the sale of the business. It can include cash, shares, or other assets. Goodwill is an intangible asset that represents the value of a company's brand name, solid customer base, good customer relations, good employee relations, and any patents or proprietary technology. The consolidated fund and capital reserve are not related to the sale price of a business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2010>50", "subject": "Accounts", "year": "2010", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is a prime cost?", "images": [], "options": {"A": "Royalty", "B": "Salary", "C": "Commission", "D": "Discount allowed"}, "answer": "A", "explanation": "A prime cost is a direct cost. Royalty is a direct cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>1", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL~~THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "The two fundamental books of accounts are", "images": [], "options": {"A": "returns inwards and outwards", "B": "journal and ledger", "C": "discounts allowed and received", "D": "credit note and debit note"}, "answer": "B", "explanation": "The two fundamental books of accounts are the journal and the ledger. The journal is the first place where all transactions are recorded using the double-entry system. The ledger is a book that contains all the accounts whether real, personal, or nominal, where changes due to transactions are recorded.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>2", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Which of the following is a capital expenditure?", "images": [], "options": {"A": "Extension of building", "B": "Repair of generator", "C": "Purchase of stock", "D": "Purchase of stationery"}, "answer": "A", "explanation": "A capital expenditure is an amount spent to acquire or significantly improve the capacity or capabilities of a long-term asset such as equipment or buildings. In this case, the extension of a building is a capital expenditure because it increases the value of the building, which is a long-term asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>3", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Expenses accrued at the end of the accounting year is treated in the balance sheet as", "images": [], "options": {"A": "current assets", "B": "current liability", "C": "fixed assets", "D": "long-term liability"}, "answer": "B", "explanation": "Expenses accrued at the end of the accounting year are treated as current liabilities in the balance sheet. Accrued expenses are costs that a company has incurred, but has not yet paid. Since these are amounts owed by the company, they are considered liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>4", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Another name for owner's equity is", "images": [], "options": {"A": "loan", "B": "debtors", "C": "capital", "D": "overdraft"}, "answer": "C", "explanation": "Owner's equity is also known as capital. It represents the owner's investment in the business minus the owner's draws or withdrawals from the business plus the net income (or minus the net loss) since the business began. It essentially represents the amount of assets that the owner has a claim on.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>5", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The reduction in value of goodwill is", "images": [], "options": {"A": "amortization", "B": "appreciation", "C": "depletion", "D": "depreciation"}, "answer": "A", "explanation": "The reduction in value of goodwill is referred to as amortization. Goodwill is an intangible asset that is associated with the purchase of one company by another. Specifically, goodwill is the portion of the purchase price that is higher than the sum of the net fair value of all of the assets purchased in the acquisition and the liabilities assumed in the process. The value of a company's goodwill asset can decrease if the value of the assets associated with the goodwill decreases. Amortization is the process of gradually writing off the initial cost of an asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>6", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "GH⊄Opening Stock    Purchase    Carriage inwards    Returns outwards    Sales    Closing Stock4,000  12,000  300  322  20,000  6,000    The cost of goods sold is", "images": [], "options": {"A": "GHc 16,300", "B": "GHc 15,978", "C": "GHc 10,022", "D": "GHc 9,978"}, "answer": "D", "explanation": "Dr. Trading Account Cr.     GHC  GHCOpening stock 12 000  Carriage inwards 300  Net purchase 16 300  less return outward 322  Cost of goods available for sale 15 978  Less: closing stock 6 000  Cost of goods sold 9 978  Gross profit 10 022    20 000  20 000      Cost of goods sold from the account prepared above is GHE 9,978", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>7", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "GH⊄Opening Stock    Purchase    Carriage inwards    Returns outwards    Sales    Closing Stock4,000  12,000  300  322  20,000  6,000  The cost of goods available for sale is", "images": [], "options": {"A": "GHc 16,300", "B": "GHc 15,978", "C": "GHc 10,022", "D": "GHc 9,978"}, "answer": "B", "explanation": "The cost of goods available for sale is calculated by adding the opening stock, purchases, and carriage inwards, then subtracting returns outwards. Therefore, the correct answer is GHc 15,978.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>8", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "GH⊄Opening Stock    Purchase    Carriage inwards    Returns outwards    Sales    Closing Stock4,000  12,000  300  322  20,000  6,000  The gross profit is", "images": [], "options": {"A": "GHc 12,300", "B": "GHc 11,978", "C": "GHc 10,022", "D": "GHc 9,978"}, "answer": "C", "explanation": "The gross profit is calculated by subtracting the cost of goods sold from the sales. The cost of goods sold is calculated by subtracting the closing stock from the cost of goods available for sale. Therefore, the correct answer is GHc 10,022.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>9", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is not recorded in a Partnership Appropriation Account?", "images": [], "options": {"A": "Interest on capital", "B": "Partners drawings", "C": "Share of profit", "D": "Interest on drawings"}, "answer": "B", "explanation": "A Partnership Appropriation Account is an account that shows how the profit of a partnership is divided among the partners. It includes items like interest on capital, share of profit, and interest on drawings. However, it does not include partners' drawings. Partners' drawings are recorded in the partners' capital or current accounts, not in the appropriation account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>10", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "When a transaction is completely left out from the books, it is error of", "images": [], "options": {"A": "Commission", "B": "Omission", "C": "Principle", "D": "Compensation"}, "answer": "B", "explanation": "In accounting, when a transaction is completely left out from the books, it is referred to as an error of omission. This means that a financial transaction was not recorded in the accounting system. This could be due to forgetfulness, oversight or possibly from intentional fraudulent action. Therefore, the correct answer is 'Omission'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>11", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is not a subsidiary book?", "images": [], "options": {"A": "Sales Day Book", "B": "Purchase Day Book", "C": "General Journal", "D": "Trial Balance"}, "answer": "D", "explanation": "A subsidiary book is a book of original entry where a record of business transactions is made before posting to the ledger. The Sales Day Book, Purchase Day Book, and General Journal are all examples of subsidiary books. However, the Trial Balance is not a subsidiary book. It is a statement that summarizes all the balances of the ledger accounts irrespective of whether they carry debit balance or credit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>12", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "In departmental accounts, rent is apportioned on the basis of", "images": [], "options": {"A": "purchases", "B": "floor area occupied", "C": "number of personnel in each department", "D": "volume of sales"}, "answer": "B", "explanation": "In departmental accounting, expenses are apportioned to each department based on certain basis. Rent is usually apportioned based on the floor area occupied by each department. This is because the amount of space a department occupies in a building is a fair measure of the benefit it gains from the rent paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>13", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "The document used in government accounting to show evidence of cash receipts and payments is the", "images": [], "options": {"A": "budget", "B": "warrant", "C": "vote", "D": "voucher"}, "answer": "D", "explanation": "The document used in government accounting to show evidence of cash receipts and payments is the voucher. A voucher is a document that contains details of a financial transaction. For cash receipts and payments, a voucher would detail the amount of cash received or paid, the date of the transaction, the account it was posted to, and any other relevant information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>14", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following errors will affect the totals of a trial balance?", "images": [], "options": {"A": "Compensating error", "B": "Complete reversal of entry", "C": "Error in addition", "D": "Error of original entry"}, "answer": "C", "explanation": "The error that will affect the totals of a trial balance is the Error in addition. A trial balance is a list of all the General ledger accounts (both revenue and capital) contained in the ledger of a business. If there is an error in the addition of these accounts, it will affect the total of the trial balance. The other options listed are types of errors but they do not affect the total of the trial balance. For example, a compensating error is an error that is offset by another error. A complete reversal of entry is an error where a correct amount is posted in the correct accounts but on the wrong side of each account. An error of original entry is when an incorrect amount is entered in the books.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>15", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Okoro and Osula are in partnership sharing profits and losses in the ratio 3:2 respectively. Their respective capital were ₦40,000 and ₦15,000 and their drawings were ₦7,000 and ₦5,000. Interest on capital was 5% and interest on drawings was 10%. The net profit was ₦30,000.    Okoro's share of profit is", "images": [], "options": {"A": "₦17,070", "B": "₦16,070", "C": "₦11,380", "D": "₦10,000"}, "answer": "A", "explanation": "Dr. Partners appropriation A/C Cr.    ₦  ₦Interest on capital  Net profit 30 000Okoro 5% x 40 000 2 000 interest on drawing Osula 5% x 15 000 750 okoro 10%x7 000 700Share of profit  Osula10% x 5 000 500Okoro 3 /5 x28450 17 070  Osula2/5 x 28 450 11 380    31 200  31 200      Okoro's share of profit from the table is ₦17,070", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>16", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Okoro and Osula are in partnership sharing profits and losses in the ratio 3:2 respectively. Their respective capital were ₦40,000 and ₦15,000 and their drawings were ₦7,000 and ₦5,000. Interest on capital was 5% and interest on drawings was 10%. The net profit was ₦30,000.   Osula's interest on drawings is", "images": [], "options": {"A": "₦2,000", "B": "₦750", "C": "₦700", "D": "₦500"}, "answer": "D", "explanation": "The interest on drawings for Osula is 10% of ₦5,000, which equals ₦500. This matches option D.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>17", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Okoro and Osula are in partnership sharing profits and losses in the ratio 3:2 respectively. Their respective capital were ₦40,000 and ₦15,000 and their drawings were ₦7,000 and ₦5,000. Interest on capital was 5% and interest on drawings was 10%. The net profit was ₦30,000.   The total interest on capital is", "images": [], "options": {"A": "₦4,000", "B": "₦2,750", "C": "₦2,000", "D": "₦750"}, "answer": "B", "explanation": "The total interest on capital is calculated by multiplying the capital by the interest rate. For Okoro, the interest on capital is ₦40,000 * 5% = ₦2,000. For Osula, the interest on capital is ₦15,000 * 5% = ₦750. Therefore, the total interest on capital is ₦2,000 + ₦750 = ₦2,750.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>18", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is an example of a subsidiary book?", "images": [], "options": {"A": "Cash book", "B": "Bank statement", "C": "Control accounts", "D": "Trial balance"}, "answer": "A", "explanation": "A subsidiary book is a book of original entry. The cash book is a subsidiary book where all cash transactions (i.e., receipts and payments) are recorded. Bank statements, control accounts, and trial balances are not subsidiary books. They are part of the double entry system and are prepared from the information in the subsidiary books.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>19", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Goods returned by the buyer is recorded in the seller's books as", "images": [], "options": {"A": "carriage inwards", "B": "carriage outwards", "C": "returns outwards", "D": "returns inwards"}, "answer": "D", "explanation": "Returns inwards book is used to record goods previously sold but later returned by the customers to the business. Goods may be returned as a result of inferior quality or are damaged in transit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>20", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "The method of ascertaining capital from incomplete records is by preparing the", "images": [], "options": {"A": "cash book", "B": "statement of affairs", "C": "suspense account", "D": "control account"}, "answer": "B", "explanation": "The method of ascertaining capital from incomplete records is by preparing the 'statement of affairs'. A statement of affairs is a financial statement that shows the assets, liabilities, and capital of a business at a particular point in time. It is often used when the records are incomplete to ascertain the capital of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>21", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A petty cashier operates with an imprest of D1,000 per week. At the end of the week, he had disbursed D920. How much is needed to restore the imprest.", "images": [], "options": {"A": "D1,920", "B": "D1,000", "C": "D920", "D": "D80"}, "answer": "C", "explanation": "The petty cashier will be re-imbursed at intervals to bring the amount back to the formal amount. Since D920 is disbursed, then 920 wil be re-imbursed for the amount spent thus bringing it to the original amount.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>22", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "Accumulated fund is also referred to as", "images": [], "options": {"A": "surplus", "B": "profit", "C": "deficit", "D": "capital"}, "answer": "D", "explanation": "Accumulated fund is a term used in not-for-profit accounting to refer to the net assets of the organization. It is equivalent to the equity of a for-profit company, which is often referred to as 'capital'. Therefore, the correct answer is 'capital'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>23", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscriptions owed by members of a club is a/an", "images": [], "options": {"A": "asset", "B": "liability", "C": "profit", "D": "surplus"}, "answer": "A", "explanation": "Subscriptions owed by members of a club is considered an asset. In accounting, an asset is a resource with economic value that an individual, corporation, or country owns or controls with the expectation that it will provide a future benefit. In this case, the subscriptions owed by members are expected to provide future financial benefit to the club.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>24", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Prime cost is derived by adding     I. cost of raw materials consumed.   II. Indirect expenses   III.  direct labour    IV.   factory expenses    V.   work in progress  VI.   direct expenses", "images": [], "options": {"A": "I, II and IV only", "B": "I, III and VI only", "C": "IV, V and VI only", "D": "II, III and V only"}, "answer": "B", "explanation": "Prime cost is the total cost of direct materials and direct labor that a company pays for the production of a product. It includes the cost of raw materials consumed (I), direct labour (III), and direct expenses (VI). Indirect expenses (II), factory expenses (IV), and work in progress (V) are not included in the prime cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>25", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "The document from which entries are transferred to the purchases day book is the", "images": [], "options": {"A": "waybill", "B": "credit note", "C": "receipt", "D": "invoice"}, "answer": "D", "explanation": "The purchases day book is a special journal used to record all purchases on account (credit purchases). The source document for these entries is the invoice received from the supplier. An invoice is a commercial document issued by a seller to a buyer, relating to a sale transaction and indicating the products, quantities, and agreed prices for products or services the seller has provided the buyer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>26", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A book-keeper debited Motor Vehicle Account in Motor Expenses Account. This is an error of", "images": [], "options": {"A": "commission", "B": "original entry", "C": "complete reversal of entry", "D": "principle"}, "answer": "D", "explanation": "The error described is an error of principle. An error of principle in accounting occurs when the bookkeeper or accountant records a financial transaction that does not comply with the fundamental principles of double entry system. In this case, the Motor Vehicle Account (an asset account) was debited instead of the Motor Expenses Account (an expense account). This is a violation of the accounting principle that requires expenses to be recorded in the expense accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>27", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "John received a cheque from Dawda, a debtor, in payment for goods purchased by Dawda on credit. The transaction will be recorded in John's", "images": [], "options": {"A": "cash book and sales ledger", "B": "nominal ledger and sales ledger", "C": "cash book and purchases ledger", "D": "nominal ledger and purchases ledger"}, "answer": "C", "explanation": "The transaction will be recorded in John's cash book since he received cheque from Dawda and purchase ledger since there is a purchase credit i.e payment for goods purchased by Dawda on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>28", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Prime cost    Factory overheads    Stock on 1/1/09 work-in-progress  Stock on 31/12/09 work-in-progress    Returns inwards   Sales4,000  6,000  1,000  2,000  800  20,000    Cost of production is", "images": [], "options": {"A": "₦10,000", "B": "₦9,000", "C": "₦8,000", "D": "₦6,000"}, "answer": "B", "explanation": "The cost of production is calculated by adding the prime cost and factory overheads, and adjusting for the change in work-in-progress. In this case, the prime cost is ₦4,000, the factory overheads are ₦6,000, the work-in-progress at the start of the period is ₦1,000 and at the end of the period is ₦2,000. Therefore, the cost of production is (₦4,000 + ₦6,000 + ₦1,000) - ₦2,000 = ₦9,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>29", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Prime cost    Factory overheads    Stock on 1/1/09 work-in-progress  Stock on 31/12/09 work-in-progress    Returns inwards   Sales4,000  6,000  1,000  2,000  800  20,000   Net sales for the period of", "images": [], "options": {"A": "₦20,000", "B": "₦20,800", "C": "₦19,200", "D": "₦10,000"}, "answer": "C", "explanation": "Net sales is calculated by subtracting returns inwards from the total sales. In this case, the total sales is ₦20,000 and the returns inwards is ₦800. Therefore, the net sales for the period is ₦20,000 - ₦800 = ₦19,200.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>30", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "The total value received by a company as consideration for shares issued constitutes", "images": [], "options": {"A": "paid-up capital", "B": "authorized capital", "C": "working capital", "D": "capital employed"}, "answer": "A", "explanation": "The total value received by a company as consideration for shares issued constitutes the paid-up capital. Paid-up capital is the amount of money a company has received from shareholders in exchange for shares of stock. It is the money that a company has received from the sale of its shares and is a component of a company's equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>31", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The first calculating machine in data processing was", "images": [], "options": {"A": "Abacus", "B": "Pascal", "C": "Punched cards", "D": "Digital"}, "answer": "A", "explanation": "The first calculating machine in data processing was the Abacus. The Abacus is an ancient tool used for arithmetic calculations. It was invented in China around 500 BC. It is considered the first mechanical calculating device. The other options, Pascal is a mechanical calculator invented by Blaise Pascal in the 17th century, Punched cards were used in early computers to represent data and instructions, and Digital refers to modern computing and does not represent a specific machine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>32", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The going concern concept assumes that", "images": [], "options": {"A": "every transaction is represented by a debit and credit entry", "B": "the currency must not change", "C": "the firm is a legal entity", "D": "the business will continue to operate indefinitely"}, "answer": "D", "explanation": "The going concern concept in accounting assumes that a business will continue to operate indefinitely. This concept implies that the financial statements of the business are prepared with the expectation that the business will continue its operations in the foreseeable future and has no intention to liquidate or to significantly curtail its operations. The other options do not accurately represent the going concern concept. The double-entry bookkeeping (every transaction is represented by a debit and credit entry) is a separate accounting concept, the currency stability (the currency must not change) is an economic concept, and the legal entity status (the firm is a legal entity) is a legal concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>33", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Which of the following is not a purpose for which share premium may be utilized?", "images": [], "options": {"A": "Issuing fully paid bonus shares", "B": "Writing off preliminary expenses", "C": "Settling salesman commission", "D": "Providing for a redeemable preference shares."}, "answer": "C", "explanation": "Share premium can be used for issuing fully paid bonus shares, writing off preliminary expenses, and providing for redeemable preference shares. However, it cannot be used for settling salesman commission. This is because share premium is an amount received by a company in excess of the face value of its shares, and it is typically used for purposes that are beneficial to the company as a whole, not for operational expenses like salesman commission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>34", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "A debenture is", "images": [], "options": {"A": "a loan capital raised by a company", "B": "money given to a company as a gift", "C": "accrued expenses", "D": "share capital"}, "answer": "A", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. Therefore, it is a loan capital raised by a company. It is not money given as a gift, accrued expenses, or share capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>35", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which deals with the exclusion of trivial items in the accounting records is", "images": [], "options": {"A": "consistency", "B": "going concern", "C": "materiality", "D": "money measurement"}, "answer": "C", "explanation": "The concept which deals with the exclusion of trivial items in the accounting records is 'materiality'. The materiality concept, in accounting, refers to the relative significance of an amount, transaction, or discrepancy. The concept suggests that all relatively relevant items should be reported but trivial ones can be disregarded. This is because including such trivial items in the accounting records would not significantly alter the decision-making process of the users of those records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>36", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Which of the following is not an example of capital reserve?", "images": [], "options": {"A": "Share premium", "B": "Retained profits", "C": "Surplus on revaluation of assets", "D": "Pre-incorporation profits"}, "answer": "D", "explanation": "Capital reserves are reserves which are not available for distribution as dividends. Examples are Share premium,  Capital redemption reserve fund ,Surplus on revaluation of asset , general reserve, revenue reserve, dividend reserve, retained profit etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>37", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Goods sent to branch are recorded in the head office's books at  I.  selling price  II.  cost price plus mark-up percentage  III.   cost price", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "Goods sent to branch are recorded in the head office's book at   -Selling price   -cost price plus Mark-up price   -Cost price", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>38", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Computer memory sizes are measured in", "images": [], "options": {"A": "kilometers", "B": "kilowatts", "C": "kilobytes", "D": "centimetres"}, "answer": "C", "explanation": "Computer memory sizes are measured in kilobytes. A kilobyte is a unit of digital information storage used to quantify the size of data. It is made up of 1024 bytes. The other options such as kilometers and kilowatts are units of measurement for distance and power respectively, and centimetres is a unit of length. Therefore, they are not used to measure computer memory sizes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2011>39", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Rent owed by a department is treated in the Balance Sheet as", "images": [], "options": {"A": "asset of the business", "B": "asset of the department", "C": "liability of the business", "D": "liability of the department"}, "answer": "C", "explanation": "Rent owed by a department is treated in the Balance Sheet as a liability of the business. This is because the business, as a whole, is responsible for paying the rent. The department is just a part of the business and does not have separate legal existence. Therefore, the rent owed is a liability of the business, not the department.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>40", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When shares are issued to the public and the issuing company has not requested for payment, it is referred to as", "images": [], "options": {"A": "authorized capital", "B": "paid-up capital", "C": "uncalled capital", "D": "unissued capital"}, "answer": "C", "explanation": "When shares are issued to the public and the issuing company has not requested for payment, it is referred to as uncalled capital. Uncalled capital refers to that portion of the share capital of a company that has been issued to shareholders but not called up. It represents the difference between the nominal value of a company's issued share capital and the amount of capital that has been called up.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>41", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Ogogo's Sales Ledger Control Account    DDBalance b/d 25180 Discount allowed 1936Sales 43220 Sales returns 1884Dishonoured cheque 542 Cash received from customers xxxBalance c/d 5122 6894268942    Net sales is", "images": [], "options": {"A": "D41,878", "B": "D41,336", "C": "D41,284", "D": "D39,400"}, "answer": "B", "explanation": "Net sales is calculated by subtracting the sales returns and discounts allowed from the total sales. In this case, the total sales is 43,220. The sales returns is 1,884 and the discounts allowed is 1,936. Therefore, the net sales is 43,220 - 1,884 - 1,936 = 39,400. However, there is no option that matches this answer. The closest option is 41,336 which is obtained by subtracting only the sales returns from the total sales. This is incorrect because the discounts allowed have not been taken into account.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>42", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Ogogo's Sales Ledger Control Account    DDBalance b/d 25180 Discount allowed 1936Sales 43220 Sales returns 1884Dishonoured cheque 542 Cash received from customers xxxBalance c/d 5122 6894268942  The total cash received from customers is", "images": [], "options": {"A": "D68,942", "B": "D60,000", "C": "D43,220", "D": "D41,336"}, "answer": "B", "explanation": "The total balance less the cr side of the sales ledger control account will give us the value of the cash received from customer i.e.   Total = 68 942 68 942Less: credit side of sales ledger Discount allowed 1 936Sales return 1 884 Bal.c/d 5 122Cash received from customer 60 000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2011>43", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "The diagrammatic representation of the working of the computer program is", "images": [], "options": {"A": "flow chart", "B": "desktop", "C": "keyboard", "D": "byte"}, "answer": "A", "explanation": "A flow chart is a type of diagram that represents an algorithm, workflow or process, showing the steps as boxes of various kinds, and their order by connecting them with arrows. This diagrammatic representation can be used to design or document a process or program in various fields, including computer programming. Therefore, the diagrammatic representation of the working of a computer program is a flow chart.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>44", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The process of recording financial transactions of government is", "images": [], "options": {"A": "management accounting", "B": "financial accounting", "C": "cost accounting", "D": "public sector accounting"}, "answer": "D", "explanation": "Public sector accounting is the process of recording, communicating, summarizing, analyzing and interpreting the financial statements and statistics of government in aggregate and details. It deals with the receipts, custody, disposal, and rendering of stewardship on public funds entrusted. Therefore, the process of recording financial transactions of government is public sector accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>45", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A bank statement shows a debit balance of Le 475. After the entry of an uncredited cheque of Lee 800, the new balance is", "images": [], "options": {"A": "Le 325 overdraft", "B": "Le 325", "C": "Le 1,275", "D": "Le 1,275 overdraft"}, "answer": "D", "explanation": "A debit balance in a bank statement means the account holder owes the bank, which is an overdraft. If an uncredited cheque of Le 800 is added to the existing debit balance of Le 475, the new balance becomes Le 1,275. Since this is still a debit balance, it is an overdraft. Therefore, the correct answer is 'Le 1,275 overdraft'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>46", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The business entity concept", "images": [], "options": {"A": "separates the owners transactions from the business", "B": "records transactions outside the business", "C": "does not separate the owner's transactions from the business transactions", "D": "involves other business transactions"}, "answer": "A", "explanation": "The business entity concept is an accounting principle that states a business is its own entity separate from its owners and should be treated as such. Therefore, it separates the owner's transactions from the business transactions. The other options are incorrect as they do not accurately describe the business entity concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>47", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "Which of the following is not used in Public Sector Accounting?", "images": [], "options": {"A": "Cash book", "B": "Trial Balance", "C": "Profit and loss Account", "D": "Bank Reconciliation Statement"}, "answer": "C", "explanation": "Public Sector Accounting is the process of recording, communicating, summarizing, analyzing and interpreting the financial statements and statistics of Government in aggregate and details. It is different from private sector accounting in many ways. One of the main differences is that public sector organizations do not aim to make a profit, hence they do not use Profit and Loss Account. Instead, they use a Statement of Financial Performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>48", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which states that assets are not to be recorded at their current market value is", "images": [], "options": {"A": "money measurement", "B": "materiality", "C": "cost", "D": "entity"}, "answer": "C", "explanation": "The concept which states that assets are not to be recorded at their current market value is the cost concept. According to the cost concept, an asset is ordinarily recorded in the accounting records at the price paid to acquire it at the time of its acquisition and this cost is the basis for all subsequent accounting for the asset. If the asset is purchased on credit, the initial cost is the cash equivalent price. A cash equivalent price is the amount that would have been paid if the purchase had been made in cash at the time of acquisition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>49", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Provision for depreciation on delivery van is charged to", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "appropriation account", "D": "manufacturing account"}, "answer": "B", "explanation": "Provision for depreciation on delivery van is charged to the profit and loss account. Depreciation is the decrease in the value of an asset over time due to wear and tear, obsolescence etc. It is considered an expense and is charged to the profit and loss account to calculate the net profit or loss of a business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2011>50", "subject": "Accounts", "year": "2011", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following date lines is correct for a profit and loss account?", "images": [], "options": {"A": "For the year ended 31st December 2009", "B": "As at 31st December 2009", "C": "For the period 31st December 2009", "D": "As at the year 2009"}, "answer": "A", "explanation": "The correct date line for a profit and loss account is 'For the year ended 31st December 2009'. A profit and loss account is prepared for a specific period of time, usually a year, to show the revenues and expenses during that period. Therefore, the date line should reflect the period for which the account is prepared.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>1", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The objective of accounting information is to enable users to", "images": [], "options": {"A": "prepare the financial statements", "B": "value stock", "C": "make decisions", "D": "prepare budgets"}, "answer": "C", "explanation": "The primary objective of accounting information is to provide useful information for decision-making purposes. It is not specifically for preparing financial statements, valuing stock, or preparing budgets, although these activities may be part of the decision-making process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>2", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Trade discounts are given for", "images": [], "options": {"A": "bulk purchases", "B": "prompt payment", "C": "quick delivery", "D": "cash payment"}, "answer": "A", "explanation": "Trade discounts are typically given to incentivize bulk purchases. They are not typically given for prompt payment, quick delivery, or cash payment, although these may be reasons for other types of discounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>3", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : RELATIONSHIP BETWEEN MARK UP AND MARGIN", "question": "When closing stock is overstated, it would reduce", "images": [], "options": {"A": "cost of sales and increase gross profit", "B": "gross profit and increase cost of sales", "C": "purchase and increase cost of sales", "D": "purchases and increase sales"}, "answer": "A", "explanation": "Closing stock is the amount of inventory that a business still has on hand at the end of a financial period. If closing stock is overstated, it means that the business has reported more inventory than it actually has. This would reduce the cost of sales because the cost of sales is calculated by adding the opening stock and purchases, then subtracting the closing stock. If the closing stock is overstated, the cost of sales will be lower than it should be. This in turn increases the gross profit because gross profit is calculated by subtracting the cost of sales from sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>4", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Which of the following is not a source document?", "images": [], "options": {"A": "Journal proper", "B": "Sales invoice", "C": "Debit note", "D": "Credit note"}, "answer": "A", "explanation": "A source document is the original record of a transaction. It provides the evidence that a financial transaction occurred and includes details about the transaction. Examples of source documents include sales invoices, debit notes, and credit notes. A journal proper, on the other hand, is not a source document. It is a book of original entry where miscellaneous credit transactions that do not fit into other specific books of original entry are recorded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>5", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "A fixed asset fully written-down by a trader is now considered to be worth ₦5,000. The double entry required to effect this is: debit", "images": [], "options": {"A": "Asset Account, Credit Purchase Account", "B": "Asset Account, Credit Capital Account", "C": "Capital Account, Credit Asset Account", "D": "Capital Account, Credit Profit and Loss Account"}, "answer": "B", "explanation": "When a fixed asset is fully written down but is now considered to be worth a certain amount, the double entry required to effect this is to debit the Asset Account and credit the Capital Account. This is because the asset's value has increased, so the Asset Account (which records the value of the company's assets) is debited (increased). The Capital Account (which records the company's equity) is credited (increased) because the increase in the asset's value increases the company's equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>6", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is a book of original entry?", "images": [], "options": {"A": "Ledger", "B": "Balance Sheet", "C": "Bank Statement", "D": "Sales Journal"}, "answer": "D", "explanation": "A book of original entry is a record where transactions are initially recorded. The Sales Journal is a book of original entry because it is where sales of goods on credit are initially recorded. The Ledger, Balance Sheet, and Bank Statement are not books of original entry. The Ledger is a book of final entry where transactions from the books of original entry are posted. The Balance Sheet is a financial statement that shows a company's financial position at a specific point in time. The Bank Statement is a statement issued by a bank detailing the transactions in a bank account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>7", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A Balance Sheet shows only", "images": [], "options": {"A": "fixed assets and current assets", "B": "assets and long term liabilities", "C": "assets and liabilities", "D": "assets and capital"}, "answer": "C", "explanation": "A balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time. It provides a basis for computing rates of return and evaluating its capital structure. It is a financial statement that provides a snapshot of what a company owns and owes, as well as the amount invested by shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>8", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The process of entering transaction from one book to another is", "images": [], "options": {"A": "reading", "B": "posting", "C": "numbering", "D": "listing"}, "answer": "B", "explanation": "Posting in accounting is the process of recording amounts as credits (right side), and amounts as debits (left side), in the pages of the general ledger. More specifically, you can think of it as transferring information from the journal to the ledger. After an event is identified to have an economic impact on the accounting equation, the business event must be quantified in monetary terms and reflected in the accounts through this process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>9", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "1/1/1031/12/10GH⊄GH⊄Stocks   Creditors   1,400  2,000  1,900  2,700    Cash paid to trade creditors GH⊄8,000  Mark-up on cost of sales 20%    The total purchase is", "images": [], "options": {"A": "GHc8,700", "B": "GHc7,300", "C": "GHc6,000", "D": "GHc4,800"}, "answer": "A", "explanation": "Dr. Creditor Control A/C Cr.     GHE  GHECash paid to creditor 8 000 Bal.b/f 2 000Bal. c/d  2 700  purchases( missing figure)  8 700    10 700    10 700    Bal. b/d 2 700", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>10", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "1/1/1031/12/10GH⊄GH⊄Stocks   Creditors   1,400  2,000  1,900  2,700    Cash paid to trade creditors GH⊄8,000  Mark-up on cost of sales 20%     The cost of sales is", "images": [], "options": {"A": "GHc8,200", "B": "GHc6,800", "C": "GHc5,500", "D": "GHc4,800"}, "answer": "A", "explanation": "GHEOpening Stock 1 400Add: purchase 8 700Less: closing stock 1 900COGS 8 200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>11", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following is a Trading Account item?", "images": [], "options": {"A": "Discounts allowed", "B": "Discounts received", "C": "Carriage outwards", "D": "Carriage inwards"}, "answer": "D", "explanation": "A Trading Account item refers to the items that are directly related to the purchase, production, and sale of goods. Carriage inwards is a direct cost associated with the transportation of goods purchased from suppliers to the business premises. Therefore, it is considered a Trading Account item.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>12", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The addition of prime cost and factory overheads is", "images": [], "options": {"A": "total factory overheads", "B": "market value of goods produced", "C": "cost of goods produced", "D": "work-in-progress"}, "answer": "C", "explanation": "The prime cost is the total cost of direct materials and direct labor used in production. Factory overheads are the indirect costs of production. The addition of prime cost and factory overheads gives the total cost of goods produced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>13", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "FINANCIAL SYSTEM : METHODS OF RAISING FUNDS", "question": "Capital receipt is collected", "images": [], "options": {"A": "on sales of motor vehicle", "B": "on sales of stock in trade", "C": "from trade debtors", "D": "from trading activities"}, "answer": "A", "explanation": "Capital receipt is a non-recurring income which either creates a liability or reduces an asset. It is collected on the sale of a fixed asset like a motor vehicle. It is not collected on sales of stock in trade, from trade debtors, or from trading activities as these are all part of regular business operations and would be considered revenue receipts, not capital receipts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>14", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is an example of factory overheads?", "images": [], "options": {"A": "Salary of marketing officer", "B": "Salary of production officer", "C": "Salary of accounting officer", "D": "Wages of machine operator"}, "answer": "B", "explanation": "Overhead costs are the operating costs incurred in a manufacturing business to support production process. The overhead expenses exclude all the direct cost related to the production of a good or services. Overhead can be fixed, variable or mix of both.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>15", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Osa started business with Le40,000 cash. The accounting entry is debit", "images": [], "options": {"A": "Cash Account; Credit Capital Account", "B": "Capital Account; Credit Cash Account", "C": "Purchases Account; Credit Cash Account", "D": "Expenses Account; Credit Capital Account"}, "answer": "A", "explanation": "When a business is started with cash, the cash account is debited because it is an asset that is increasing. The capital account is credited because it represents the owner's equity in the business, which increases when the owner invests cash in the business. This follows the fundamental principle of accounting that assets = liabilities + owner's equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>16", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Branch Stock Account is used to determine the", "images": [], "options": {"A": "net value of goods sent to branch", "B": "gross profit of the branch", "C": "branch credit sales", "D": "branch net profit or loss"}, "answer": "A", "explanation": "The Branch Stock Account is used to track the value of goods sent to a branch. It helps in determining the net value of goods sent to the branch. It is not used to determine the gross profit, credit sales, or net profit or loss of the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>17", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The name given to a budget in public service accounting is", "images": [], "options": {"A": "vote", "B": "subvention", "C": "general order", "D": "estimate"}, "answer": "D", "explanation": "Budget estimate is the financial plan of the government for a year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>18", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Balance Sheet as at 31st December, 2010    ₦₦Capital  Less: Net loss   .  Less: drawings   .  Long term loan   .    Creditors    Accrued expenses  .40,000    5,000    35,000    2,000  33,000   20,000   53,000    8,000  4,000   65,000Freehold premises   Stock    Debtors    Cash at bank    Cash in hand  50,000  3,000   4,000    6,500    1,500   65,000    The amount of working capital is", "images": [], "options": {"A": "₦11,000", "B": "₦7,000", "C": "₦4,000", "D": "₦3,000"}, "answer": "D", "explanation": "Working capital is the excess of current assets over the current liabilities. I.e Working capital CA - CL      Current Asset   Stock 3 000Debtors 4 000Cash at bank 6 500Cash in hand 1 500  15 000      Current liability  Creditor 8 000Accrued expenses 4 00012 000    Working capital = 15,000 - 12,000  = #3,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>19", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Balance Sheet as at 31st December, 2010    ₦₦Capital  Less: Net loss   .  Less: drawings   .  Long term loan   .    Creditors    Accrued expenses  .40,000    5,000    35,000    2,000  33,000   20,000   53,000    8,000  4,000   65,000Freehold premises   Stock    Debtors    Cash at bank    Cash in hand  50,000  3,000   4,000    6,500    1,500   65,000   Working capital ratio is", "images": [], "options": {"A": "5 : 4", "B": "5 : 3", "C": "4 : 5", "D": "1 : 1"}, "answer": "A", "explanation": "Working capital ratio is the ratio of current assets to the current liabilities i.e. working capital Ratio  i.e CA:CL     = 15000:12000    =15,0000/ 12,000    = 5:4", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>20", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Balance Sheet as at 31st December, 2010    ₦₦Capital  Less: Net loss   .  Less: drawings   .  Long term loan   .    Creditors    Accrued expenses  .40,000    5,000    35,000    2,000  33,000   20,000   53,000    8,000  4,000   65,000Freehold premises   Stock    Debtors    Cash at bank    Cash in hand  50,000  3,000   4,000    6,500    1,500   65,000   Acid test ratio is", "images": [], "options": {"A": "5 : 4", "B": "5 : 3", "C": "4 : 5", "D": "1 : 1"}, "answer": "D", "explanation": "The acid test ratio (or quick ratio) is calculated as (Current Assets - Inventory) / Current Liabilities. In this case, there is no inventory. Therefore, the acid test ratio is the same as the working capital ratio, which is 1 : 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>21", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following not prepared by a partnership?", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Income and Expenditure Account", "D": "Profit and Loss Appropriation Account."}, "answer": "C", "explanation": "An Income and Expenditure Account is not prepared by a partnership. This type of account is typically prepared by non-profit organizations to show their income (receipts) and expenditure (payments) for a particular period. It is similar to a Profit and Loss Account, but it does not include capital expenditure or income. Trading Account, Profit and Loss Account, and Profit and Loss Appropriation Account are all prepared by a partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>22", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A partner who only makes capital contribution but does not take part in the management of  the partnership business is a/an", "images": [], "options": {"A": "ordinary partner", "B": "limited partner", "C": "dormant partner", "D": "nominal partner"}, "answer": "C", "explanation": "A partner who only makes capital contribution but does not take part in the management of the partnership business is a dormant partner. A dormant partner, also known as a silent partner, is one who contributes capital into a business but does not participate in its day-to-day operations or management. The other types of partners listed in the options are involved in the management of the business in one way or another.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>23", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is a component of prime cost?", "images": [], "options": {"A": "Depreciation", "B": "Royalty", "C": "Factory rent", "D": "Factory electricity"}, "answer": "B", "explanation": "Royalty is a direct expense which is included to the prime cost. All other options are factory overheads.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>24", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which establishes the rule for the periodic recognition of revenue as soon as it is capable of objective measurement is", "images": [], "options": {"A": "going concern", "B": "entity", "C": "consistency", "D": "realization"}, "answer": "D", "explanation": "The realization concept in accounting establishes the rule for the periodic recognition of revenue as soon as it is capable of objective measurement. This means that revenue is recognized when it is earned and not necessarily when it is received. This concept is fundamental to the accrual basis of accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>25", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Rent accrued in 2009 was D140. In 2010, D900 was paid while D160 was outstanding. Rent for 2010 was", "images": [], "options": {"A": "D1,200", "B": "D1,060", "C": "D920", "D": "D880"}, "answer": "C", "explanation": "Dr. Rent A/C Cr.     D  DBal. b/f 140 Amount paid 900Owings 920 Bal.c/d 160  1 060  1 060Bal.b/d 160", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>26", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "Which of the following is not an input device?", "images": [], "options": {"A": "Card reader", "B": "Paper to reader", "C": "Alpha-numeric keyboard", "D": "Line printer"}, "answer": "D", "explanation": "An input device is a piece of computer hardware used to provide data and control signals to an information processing system such as a computer or information appliance. Examples of input devices include keyboards, mouse, scanners, digital cameras, joysticks, and microphones. A line printer is an output device, not an input device. It prints one entire line of text before advancing to another line and is mostly found in an industrial setting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>27", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "The equivalent of Income and Expenditure Account in a trading concern is", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Appropriation Account", "D": "Balance sheet"}, "answer": "B", "explanation": "The equivalent of Income and Expenditure Account in a trading concern is the Profit and Loss Account. Both accounts are used to determine the net profit or loss of a business. The Income and Expenditure Account is used by non-profit organizations, while the Profit and Loss Account is used by trading concerns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>28", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The term used to denote the capital of a not-for-profit making organization is", "images": [], "options": {"A": "annuity fund", "B": "nominal capital", "C": "circulating capital", "D": "accumulated fund"}, "answer": "D", "explanation": "The term used to denote the capital of a not-for-profit making organization is the accumulated fund. This represents the net assets of the organization, i.e., the excess of assets over liabilities. It is similar to the capital of a profit-making business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>29", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "The portion of authorized capital that has been allotted to subscribers is", "images": [], "options": {"A": "called-up capital", "B": "paid up capital", "C": "issued capital", "D": "nominal capital"}, "answer": "C", "explanation": "The portion of authorized capital that has been allotted to subscribers is known as issued capital. Authorized capital is the maximum amount of capital that a company can issue to shareholders. Issued capital refers to the portion of a company's equity that has been bought and held by shareholders. It does not include shares that have been authorized but not yet issued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>30", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Partner whose liabilities are restricted to their financial contribution to the partnership in the event of winding up are", "images": [], "options": {"A": "ordinary partner", "B": "limited partner", "C": "dormant partners", "D": "sleeping partners"}, "answer": "B", "explanation": "A limited partner is a partner whose liability is limited to the extent of the amount of capital contributed by them. They cannot participate in the management of the firm and are only liable to the extent of their capital contribution in the event of winding up. This is different from an ordinary partner who has unlimited liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>31", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "If creditors at 1/1/10 were Le 3,000, creditors at 31/12/10 Le 5,500 and payments to creditors Le 29,000. The purchases figure for 2010 is", "images": [], "options": {"A": "Le 34,500", "B": "Le 32,000", "C": "Le 31,500", "D": "Le 26,500"}, "answer": "C", "explanation": "The purchases figure for 2010 is calculated using the formula: Opening creditors + Purchases - Payments to creditors = Closing creditors. Rearranging the formula to find Purchases gives: Purchases = Payments to creditors + Closing creditors - Opening creditors. Substituting the given values gives: Purchases = Le 29,000 + Le 5,500 - Le 3,000 = Le 31,500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>32", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not found in the personal ledger?", "images": [], "options": {"A": "Debtor Account", "B": "Creditors Account", "C": "Capital Account", "D": "Nominal Account"}, "answer": "D", "explanation": "The personal ledger contains accounts of individual persons or firms with whom the business has dealings. It includes Debtor Account, Creditors Account, and Capital Account. However, the Nominal Account, which records expenses, losses, incomes, and gains, is not found in the personal ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>33", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The Sales Ledger Control Account is also referred to as", "images": [], "options": {"A": "Bought ledger Control Account", "B": "Purchases Account", "C": "Total Debtors Account", "D": "Total Creditors Account"}, "answer": "C", "explanation": "The Sales Ledger Control Account is also referred to as the Total Debtors Account. This is because the Sales Ledger Control Account is a summary account which checks the arithmetical accuracy of the Sales Ledger. It contains the total balance of all the individual customer accounts (debtors) in the sales ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>34", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The Health Department of Zango Local Government incurred the following expenditure in 2010.    leConstruction of Hospital ward    Purchase of Hospital Beds    Salaries and Wages    Purchase of drugs    Purchase of X-ray machine300,000    40,000    80,000    55,000    150,000    Capital expenditure for the year was", "images": [], "options": {"A": "Le 545,000", "B": "Le 490,000", "C": "Le 450,000", "D": "Le 300,000"}, "answer": "B", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, an industrial plant, technology, or equipment. In this case, the capital expenditures are the Construction of Hospital ward (Le 300,000), Purchase of Hospital Beds (Le 40,000), and Purchase of X-ray machine (Le 150,000). Adding these up gives Le 490,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2012>35", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The Health Department of Zango Local Government incurred the following expenditure in 2010.    leConstruction of Hospital ward    Purchase of Hospital Beds    Salaries and Wages    Purchase of drugs    Purchase of X-ray machine300,000    40,000    80,000    55,000    150,000   The amount of recurrent expenditure was", "images": [], "options": {"A": "Le 245,000", "B": "Le 175,000", "C": "Le 135,000", "D": "Le 80,000"}, "answer": "C", "explanation": "Recurrent expenditures    leSalaries & wages 80 000  Purchases of drugs  55000   135 000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2012>36", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "An increase in the provision for doubtful debts results in a/an", "images": [], "options": {"A": "increase in the gross profit", "B": "decrease in the gross profit", "C": "decrease in the net profit", "D": "increase in the net profit"}, "answer": "C", "explanation": "The provision for doubtful debts is an estimated amount of bad debts that are likely to arise from the accounts receivable that have been given out by the company. It is treated as an expense and is included in the profit and loss account. Therefore, an increase in the provision for doubtful debts would decrease the net profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>37", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following errors affects the agreement of a Trial Balance?", "images": [], "options": {"A": "Wrong addition in the sales account", "B": "Crediting a purchase to A. Tambi's account instead of F. Tambi's account", "C": "Failure to enter sales in the books", "D": "Posting the Purchase of a van to the debit side of the purchases account"}, "answer": "A", "explanation": "The agreement of a Trial Balance is affected by errors that involve a single entry. Wrong addition in the sales account is an example of such an error. This is because the trial balance is a statement of all debits and credits in a double-entry account system. If there is a wrong addition in the sales account, it means that the total debits will not equal the total credits, hence the trial balance will not agree. The other options involve errors that affect two accounts, hence they will not affect the agreement of the trial balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>38", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION", "question": "The excess of the value of assets over the purchase consideration on acquisition of a business is credited to", "images": [], "options": {"A": "share capital account", "B": "goodwill account", "C": "capital reserve account", "D": "general reserve account"}, "answer": "C", "explanation": "The excess of the value of assets over the purchase consideration on acquisition of a business is credited to the capital reserve account. This is because the capital reserve account is used to record gains that are not realized through normal business operations, such as the purchase of a business for less than the value of its assets. The other options are not correct because they involve accounts that are used for different purposes. The share capital account is used to record the value of shares issued by the company, the goodwill account is used to record the value of intangible assets such as brand name and customer relationships, and the general reserve account is used to record funds set aside for general business purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>39", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Share of ₦3 nominal value were issued at a price of ₦4. The difference of ₦1 is a", "images": [], "options": {"A": "commission", "B": "discount", "C": "premium", "D": "bonus"}, "answer": "C", "explanation": "When shares are issued at a price higher than their nominal value, the difference is known as a premium. In this case, the shares have a nominal value of ₦3 but were issued at ₦4, so the difference of ₦1 is a premium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>40", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "Which of the following is not the purpose of control account?", "images": [], "options": {"A": "Check on errors of addition", "B": "Locate errors", "C": "Locate missing figures", "D": "Monitor the cash book"}, "answer": "D", "explanation": "A control account is a summary account in the general ledger. The purpose of a control account is to keep the general ledger free of details, but still provide enough information to be useful. It is used to check the accuracy of transactions, locate errors and locate missing figures. However, monitoring the cash book is not a purpose of a control account. The cash book is monitored separately.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>41", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES", "question": "Which of the following is not part of the Central Processing Unit of a computer?", "images": [], "options": {"A": "Arithmetic and Logical unit", "B": "Memory unit", "C": "Input unit", "D": "Control unit"}, "answer": "C", "explanation": "The Central Processing Unit (CPU) of a computer is the primary component of a computer that performs most of the processing inside the computer. It is often referred to as the 'brain' of the computer. The CPU is made up of three main parts: the Arithmetic Logic Unit (ALU) that performs arithmetic and logical operations, the Control Unit (CU) that manages the various components of the computer, and the Memory Unit (MU) that stores data. The Input Unit is not part of the CPU; it is a separate component that allows data to be input into the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>42", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "The double entry to record the proceeds on disposal of assets is debit", "images": [], "options": {"A": "Bank Account, Credit Asset Disposal Account", "B": "Asset, Disposal Account; Credit Bank Account", "C": "Provision or Depreciation Account; Credit Asset Disposal Account", "D": "Asset Disposal Account, Credit Provision for Depreciation Account"}, "answer": "A", "explanation": "When an asset is disposed of, the proceeds from the disposal are recorded as a debit to the Bank Account and a credit to the Asset Disposal Account. This is because the Bank Account (an asset account) increases with the inflow of cash from the disposal, and this increase is recorded as a debit. The Asset Disposal Account (a gain account) increases with the gain on disposal, and this increase is recorded as a credit. The other options do not correctly represent the double entry for recording the proceeds on disposal of assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>43", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "An underwriter for a company's share is paid", "images": [], "options": {"A": "interest", "B": "commission", "C": "dividend", "D": "salary"}, "answer": "B", "explanation": "An underwriter for a company's share is paid a commission. Underwriting is the process by which investment bankers raise investment capital from investors on behalf of corporations and governments that are issuing securities (both equity and debt capital). The services of underwriters are typically used during a company's Initial Public Offering (IPO), or when it seeks to issue debt securities. The underwriter gets paid on a commission basis, which is a percentage of the amount of money raised in the IPO or other issuance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>44", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "Which of the following is found in a Memorandum of Association?", "images": [], "options": {"A": "Names of directors", "B": "Appointment of directors", "C": "Object of business", "D": "Payment of dividend"}, "answer": "C", "explanation": "The Memorandum of Association is a document that sets out the constitution of a company and is therefore fundamental to its incorporation and operation. It includes the company's name, the location of its registered office, and its object of business. The object of business refers to the purpose for which the company is formed. It defines the boundaries beyond which the actions of the company cannot go. The names and appointment of directors are not typically included in the Memorandum of Association, these are usually found in the Articles of Association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>45", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Administrative, selling and distribution expenses in a manufacturing firm are recorded in", "images": [], "options": {"A": "Trading Account", "B": "Manufacturing Account", "C": "Profit and Loss Account", "D": "Balance sheet"}, "answer": "C", "explanation": "Administrative, selling and distribution expenses in a manufacturing firm are recorded in the Profit and Loss Account. The Profit and Loss Account is a financial statement that summarizes the revenues, costs, and expenses incurred during a specific period of time. These records provide information about a company's ability or inability to generate profit by increasing revenue, reducing costs, or both. The administrative, selling and distribution expenses are part of the operating expenses which are deducted from the gross profit to arrive at the net profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>46", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is not a revenue to a local government?", "images": [], "options": {"A": "Fines", "B": "Licenses", "C": "Personal income tax", "D": "Craftsmen fees"}, "answer": "C", "explanation": "Personal income tax is not a revenue to a local government. Personal income tax is a type of tax that governments impose on income generated by businesses and individuals within their jurisdiction. In most jurisdictions, including Nigeria, personal income tax is collected by the state government, not the local government. The local government collects revenues through sources like fines, licenses, and fees from local craftsmen and other local levies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>47", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "DCash in    Cash at Bank    Stock    Furniture and fittings    Creditors1,440    2,440    2,500    2,200    1,000    The capital is", "images": [], "options": {"A": "D7,580", "B": "D6,580", "C": "D5,380", "D": "D1,000"}, "answer": "A", "explanation": "DCash in hand 1 440cash at bank 2 440 Stock 2 500Furniture & fittings  2 200   8 580less Liability: creditors  1 000 Capital 7 580", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>48", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "DCash in    Cash at Bank    Stock    Furniture and fittings    Creditors1,440    2,440    2,500    2,200    1,000    The liability is", "images": [], "options": {"A": "D7,580", "B": "D6,580", "C": "D5,380", "D": "D1,000"}, "answer": "D", "explanation": "The liability is the Creditors which is 1,000. This matches option D.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2012>49", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following is not an item in the profit and loss account?", "images": [], "options": {"A": "Drawings", "B": "Interest", "C": "Salaries", "D": "Bad debts"}, "answer": "A", "explanation": "Drawings are not an item in the profit and loss account. Drawings refer to the money withdrawn from the business by the owner(s) for personal use. It is not an expense of the business and therefore does not appear in the profit and loss account. Interest, Salaries, and Bad debts are all expenses and would appear in the profit and loss account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2012>50", "subject": "Accounts", "year": "2012", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "A loss made on the disposal of a fixed asset is debited to", "images": [], "options": {"A": "Sales Account", "B": "Purchase Account", "C": "Profit and Loss Account", "D": "Capital Account"}, "answer": "C", "explanation": "A loss made on the disposal of a fixed asset is debited to the Profit and Loss Account. This is because the loss represents an expense to the business, and all expenses are debited in the Profit and Loss Account. The Sales Account and Purchase Account are used for recording the sale and purchase of goods respectively, not fixed assets. The Capital Account is used for recording the owner's investment in the business, not losses or expenses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>1", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CASH BOOK : TWO COLUMN CASH BOOK~~CASH BOOK : THREE COLUMN CASH BOOK", "question": "The distinguishing features between a two-column and three-column cash book is", "images": [], "options": {"A": "discount column", "B": "cash column", "C": "Bank column", "D": "Ledger folio"}, "answer": "A", "explanation": "A two-column cash book has two columns on each side to record cash and bank transactions. On the other hand, a three-column cash book has an additional column on each side to record discount received and discount allowed. Therefore, the distinguishing feature between a two-column and three-column cash book is the discount column.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>2", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "The lodgement of business cash into the business bank account is an example of", "images": [], "options": {"A": "contra entry", "B": "bank reconciliation", "C": "self balancing ledger", "D": "reversal entry"}, "answer": "A", "explanation": "A contra entry is a transaction that is recorded in two different accounts where one account is debited and the other account is credited. The lodgement of business cash into the business bank account is an example of a contra entry because the cash account is debited (decrease in cash) and the bank account is credited (increase in bank balance).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>3", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A credit balance is", "images": [], "options": {"A": "a liability or an expense", "B": "a liability or an income", "C": "an expenditure or an income", "D": "an asset or an expense"}, "answer": "B", "explanation": "All asset and expenses have a debit side and balance while all incomes and liabilities have a credit side balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>4", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is not a characteristic of a Trial Balance?", "images": [], "options": {"A": "It has columns for debit and credit balances", "B": "Total of debit balance equals total of credit balance", "C": "It is a statement", "D": "It is an account"}, "answer": "D", "explanation": "A Trial Balance is not an account, it is a statement that lists the balances of all ledger accounts of a business at a specific point in time. It has columns for debit and credit balances and the total of debit balance equals the total of credit balance. These characteristics are used to check the mathematical accuracy of the double-entry accounting system. Therefore, option 4 is correct as a Trial Balance is not an account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>5", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "The capital of a sole trader changes as a result of", "images": [], "options": {"A": "paying wages by cash", "B": "equipment purchased by cheque", "C": "drawings by cheque", "D": "goods purchase by cheque"}, "answer": "C", "explanation": "The capital of a sole trader changes as a result of drawings by cheque. Drawings refer to the money withdrawn from the business by the owner for personal use. This reduces the capital invested in the business, hence changing the capital of the sole trader.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>6", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The order of financial accounting process involves    (I) recording    (II) presenting   (III) collecting   (IV)   analyzing", "images": [], "options": {"A": "I, II, III and IV", "B": "II, III I and IV", "C": "III, I, II and IV", "D": "IV, III, II and I"}, "answer": "C", "explanation": "The order of financial accounting process involves collecting (III), recording (I), presenting (II) and analyzing (IV). This is the standard process in financial accounting. First, data is collected from various sources. Then, this data is recorded in the books of accounts. After recording, the data is presented in the form of financial statements. Finally, these financial statements are analyzed to make business decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>7", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A dishonoured cheque is", "images": [], "options": {"A": "debited in the cash book", "B": "credited in the cash book", "C": "double entry in the cash book", "D": "credited in the bank book"}, "answer": "B", "explanation": "A dishonoured cheque is a cheque that the bank has refused to cash or pay out, because there are no funds to cover it in the account of the person who wrote the cheque, or the person who wrote the cheque has instructed the bank not to cash it. When a cheque is dishonoured, it is credited in the cash book because it reduces the balance of the cash account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>8", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A petty cashier receied a float of GHc 120 and spent GHc 84. The imprest is", "images": [], "options": {"A": "GHc 204", "B": "GHc 120", "C": "GHc 84", "D": "GHc 36"}, "answer": "C", "explanation": "Imprest system involves recording of transaction involving small cash. The imprest is re-imbursed at frequent interval for the amount spent thus bringing it to the original amount since 84 is spent, it will also be re-imbursed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>9", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is not a book of original entry?", "images": [], "options": {"A": "Cash Book", "B": "Purchases Ledger", "C": "Returns Outwards Journal", "D": "General Journal"}, "answer": "B", "explanation": "A book of original entry is the first place where a transaction is recorded. The Cash Book, Returns Outwards Journal, and General Journal are all books of original entry. However, the Purchases Ledger is not a book of original entry. It is a subsidiary ledger where purchases are recorded.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>10", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "₦Net profit    Total Assets    Current liabilities    Current assets  60,000    520,000    150,000    280,000    The current ratio is", "images": [], "options": {"A": "1.87 : 1", "B": "1 : 1.87", "C": "1 : 2", "D": "2 : 1"}, "answer": "A", "explanation": "The current ratio is calculated by dividing current assets by current liabilities. In this case, the current assets are ₦280,000 and the current liabilities are ₦150,000. Therefore, the current ratio is 280,000/150,000 = 1.87 : 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>11", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "₦Net profit    Total Assets    Current liabilities    Current assets  60,000    520,000    150,000    280,000  The capital employed is", "images": [], "options": {"A": "₦740,000", "B": "₦580,000", "C": "₦370,000", "D": "₦280,000"}, "answer": "C", "explanation": "Capital Employed is calculated as Total Assets - Current Liabilities. Therefore, Capital Employed = ₦520,000 - ₦150,000 = ₦370,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>12", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "₦Net profit    Total Assets    Current liabilities    Current assets  60,000    520,000    150,000    280,000  The returns on capital employed is", "images": [], "options": {"A": "17.2%", "B": "16.2%", "C": "15.2%", "D": "11.2%"}, "answer": "B", "explanation": "Returns on Capital Employed is calculated as (Net Profit / Capital Employed) * 100. Therefore, Returns on Capital Employed = (₦60,000 / ₦370,000) * 100 = 16.2%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>13", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The double entry principle states that", "images": [], "options": {"A": "every debit entry must have a corresponding credit entry", "B": "every credit entry must have a corresponding double entry", "C": "every debit entry must have a corresponding double entry", "D": "every asset must have a corresponding liability"}, "answer": "A", "explanation": "The double entry principle in accounting states that for every financial transaction, equal and opposite effects are recorded in at least two different accounts. This means that every debit entry must have a corresponding credit entry. This principle is used to keep the accounting equation (Assets = Liabilities + Equity) in balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>14", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following is a nominal account?", "images": [], "options": {"A": "Machinery Account", "B": "Drawings Account", "C": "Debtors Account", "D": "Wages Account"}, "answer": "D", "explanation": "A nominal account is an account that is closed at the end of each accounting period. Nominal accounts include all income statement accounts (revenues, expenses, gains, losses), dividend accounts, income summary accounts, and any other account that is not an asset, liability, or equity account. In this case, Wages Account is a nominal account as it records the expenses related to employee compensation which is closed at the end of each accounting period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>15", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Reserves account is kept in the", "images": [], "options": {"A": "private ledger", "B": "creditors ledger", "C": "nominal ledger", "D": "debtors ledger"}, "answer": "C", "explanation": "A reserves account is kept in the nominal ledger. The nominal ledger, also known as the general ledger, contains all the balance sheet (assets, liabilities, equity) and income statement (revenues, expenses) accounts. The reserves account falls under the equity section of the balance sheet in the nominal ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>16", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "An advantage of control account is", "images": [], "options": {"A": "locating figures", "B": "adding figures", "C": "changing figures", "D": "locating errors"}, "answer": "D", "explanation": "An advantage of control account is locating errors. A control account is a summary account in the general ledger. The details that support the summary amounts in the control account will be found in a subsidiary ledger. This allows for errors to be located and corrected more easily, as the control account should always balance with the sum of its corresponding subsidiary accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>17", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The accumulated fund of a not-for-profit making organization is", "images": [], "options": {"A": "a fixed asset", "B": "a current asset", "C": "a liability", "D": "capital"}, "answer": "D", "explanation": "The accumulated fund of a not-for-profit organization is equivalent to the capital of a profit-making organization. It represents the net assets of the organization, i.e., the excess of assets over liabilities. It is not an asset or a liability but a representation of the organization's equity or capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>18", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A business is treated as being separate from the owners. This statement is emphasized by", "images": [], "options": {"A": "consistency concept", "B": "realization concept", "C": "going concern concept", "D": "business entity concept"}, "answer": "D", "explanation": "The statement that a business is treated as being separate from the owners is emphasized by the business entity concept. This concept states that for accounting purposes, the business and its owners are to be treated as two separate entities. This means that the personal transactions of the owner should not be mixed with the transactions of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>19", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following is recorded on the debit side of the Trial Balance?", "images": [], "options": {"A": "Bank Overdraft", "B": "Returns Outwards", "C": "Purchases", "D": "Capital"}, "answer": "C", "explanation": "In a trial balance, purchases are recorded on the debit side. This is because purchases increase the total assets of a business, and according to the rules of double-entry bookkeeping, an increase in assets is recorded as a debit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>20", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "1/6/201130/5/2012DDCreditors    Debtors    Cash paid to Creditors    Cash received from customers   Goods returned to supplier2,495    1,215   ________    _________    _________ 2,285    2,145   32,170    40,650    500    Purchases for the year is", "images": [], "options": {"A": "D32,880", "B": "D32,780", "C": "D32,460", "D": "D31,960"}, "answer": "C", "explanation": "Dr. Creditor's A/C Cr.     D  DCash paid to creditor 32 170 Bal. b/f 2 495Return outward 500 Purchases 32 460Bal. c/d 2 285    34 955  34 955    The purchase for the year is ₦32,460", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2013>21", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "1/6/201130/5/2012DDCreditors    Debtors    Cash paid to Creditors    Cash received from customers   Goods returned to supplier2,495    1,215   ________    _________    _________ 2,285    2,145   32,170    40,650    500  Sales for the year is", "images": [], "options": {"A": "D42,795", "B": "D42,080", "C": "D41,580", "D": "D39,720"}, "answer": "C", "explanation": "Dr. Debtor's A/C Cr.   Bal.b/f 1 215 Cash received 40 650Sales 41 580 Bal.c/d 2 145   42 795  42 795", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2013>22", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following is determined in the Trading Account?", "images": [], "options": {"A": "Factory overheads", "B": "Cost of goods sold", "C": "Prime cost", "D": "Net profit"}, "answer": "B", "explanation": "The Trading Account is a part of the final accounts prepared by a business to determine the gross profit or gross loss of a business. It includes details of direct expenses and revenues. The cost of goods sold is determined in the Trading Account. It is calculated as the sum of the opening stock, purchases and direct expenses minus the closing stock. The cost of goods sold is an important figure as it is subtracted from sales to find the gross profit or loss. The correct option is 'Cost of goods sold'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>23", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CASH BOOK : THREE COLUMN CASH BOOK", "question": "Cash receipts and payments involving discounts are entered in", "images": [], "options": {"A": "three-column cash book", "B": "two-column cash book", "C": "analytical cash book", "D": "petty cash book"}, "answer": "A", "explanation": "Cash receipts and payments involving discounts are entered in a three-column cash book. A three-column cash book has columns for discount, cash and bank. This allows for the recording of discounts received or given along with the cash or bank transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>24", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "The minimum number of persons required to form a partnership business is", "images": [], "options": {"A": "2", "B": "3", "C": "5", "D": "10"}, "answer": "A", "explanation": "The minimum number of persons required to form a partnership business is 2. This is according to the Partnership Act which states that a partnership can be formed between two or more persons who agree to share the profits of a business carried on by all or any of them acting for all.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>25", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following accounts has a credit balance?", "images": [], "options": {"A": "Returns Inward Account", "B": "Machinery Account", "C": "Sales Account", "D": "Cash Account"}, "answer": "C", "explanation": "In accounting, the Sales Account is typically credited when a sale is made. This is because the sales account records the revenue generated by the sale of goods or services. When a sale is made, the sales account is credited (increased) and the corresponding account (like accounts receivable or cash) is debited (increased). Therefore, the Sales Account has a credit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>26", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting principle that states that, in the preparation of accounting statement, revenue are recognized as soon as goods are passed on to the customer is the", "images": [], "options": {"A": "materiality concept", "B": "matching concept", "C": "consistency concept", "D": "realization concept"}, "answer": "D", "explanation": "The realization concept in accounting states that revenue should be recognized and recorded when it is realized or realizable, and when it is earned, not when cash is received. This means that revenue is recognized when the goods are delivered or the service is provided, regardless of when payment is received. Therefore, the principle that states that revenue is recognized as soon as goods are passed on to the customer is the realization concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>27", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Agreement between partners is contained in the Partnership", "images": [], "options": {"A": "Act", "B": "Deed", "C": "Accord", "D": "Deal"}, "answer": "B", "explanation": "The agreement between partners in a business is contained in the Partnership Deed. A partnership deed, also known as a partnership agreement, is a document that outlines in detail the rights and responsibilities of all parties to a business operation. It has the force of law and is designed to guide the partners in the conduct of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>28", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "A low current ratio in a business indicates that the business is", "images": [], "options": {"A": "faced with long term loan repayment problem", "B": "efficient in the utilization of its resources", "C": "unable to pay its bills on time", "D": "growing its net asset effectively"}, "answer": "C", "explanation": "A low current ratio in a business indicates that the business may be unable to pay its bills on time. The current ratio is a liquidity ratio that measures a company's ability to pay short-term obligations or those due within one year. It compares a firm's current assets to its current liabilities. A low current ratio indicates that the company might struggle to cover its short-term liabilities, hence may be unable to pay its bills on time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>29", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Which of the following is a recurrent expenditure in public sector accounting?", "images": [], "options": {"A": "Purchase of vehicles", "B": "Purchase of drugs", "C": "Construction of boreholes", "D": "Construction of buildings"}, "answer": "B", "explanation": "Recurrent expenditure refers to payments made by governments or organizations for all sorts of running (operational) costs. These are expenses that are required to fulfill the everyday operations of such entities. In the context of public sector accounting, purchase of drugs is a recurrent expenditure because it is an operational cost that recurs within a short period of time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>30", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "In departmental accounts, administrative expenses are recorded in the", "images": [], "options": {"A": "Trading Account", "B": "Balance sheet", "C": "Profit and Loss Account", "D": "Profit and Loss Appropriation Account"}, "answer": "C", "explanation": "In departmental accounts, administrative expenses are recorded in the Profit and Loss Account. Departmental accounts are a way to keep track of the performance of different departments within a business. The Profit and Loss Account is used to record revenues, costs, and expenses, which includes administrative expenses. Administrative expenses are the costs of running the business, which are not directly tied to a specific business activity, but instead related to the organization as a whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>31", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The Public Accounts Committee is an organ of", "images": [], "options": {"A": "military regime", "B": "parliament regime", "C": "presidency", "D": "Councillors"}, "answer": "B", "explanation": "The Public Accounts Committee is a parliamentary committee that examines the accounts showing the appropriation of the sums granted by Parliament to meet the public expenditure. It is an organ of the parliament regime, not the military regime, presidency, or councillors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>32", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Aminn Local Government prepared its receipts and payments accounts from the following:   LeFines    Market rates    Salaries    Maintenance of Vehicles    Park collections  20,000   120,000    60,000    49,000   100,000     The balance at the end of the period is", "images": [], "options": {"A": "Le270,000", "B": "Le139,000", "C": "Le131,000", "D": "Le120,000"}, "answer": "C", "explanation": "The balance at the end of the period is calculated by subtracting the total payments from the total receipts. The total receipts are Le20,000 (Fines) + Le120,000 (Market rates) + Le100,000 (Park collections) = Le240,000. The total payments are Le60,000 (Salaries) + Le49,000 (Maintenance of Vehicles) = Le109,000. Therefore, the balance at the end of the period is Le240,000 - Le109,000 = Le131,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>33", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Aminn Local Government prepared its receipts and payments accounts from the following:   LeFines    Market rates    Salaries    Maintenance of Vehicles    Park collections  20,000   120,000    60,000    49,000   100,000    The total expenditure for the period is", "images": [], "options": {"A": "Le319,000", "B": "Le270,000", "C": "Le139,000", "D": "Le109,000"}, "answer": "D", "explanation": "The total expenditure for the period is calculated by adding up the Salaries and Maintenance of Vehicles. This is because in accounting, expenditures are the costs incurred in the effort to generate revenue. In this case, Salaries and Maintenance of Vehicles are the costs incurred. Adding these two gives us Le109,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>34", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Which of the following is not an item in the purchases ledger control account?", "images": [], "options": {"A": "Cash received", "B": "Cash payment", "C": "Contra settlement", "D": "Cheque payment"}, "answer": "A", "explanation": "The credit side of the purchases ledger control account records the payments made to suppliers. Therefore, 'Cash received' is not an item on the credit side of the purchases ledger control account because it is an inflow, not an outflow.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>35", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION", "question": "When a business is purchased from a sole trader, the excess of the purchase price over the net assets is", "images": [], "options": {"A": "reserve", "B": "goodwill", "C": "freehold", "D": "valuation price"}, "answer": "B", "explanation": "When a business is purchased from a sole trader, the excess of the purchase price over the net assets is referred to as 'goodwill'. Goodwill is an intangible asset that represents the non-physical assets, such as brand reputation, customer relationships, and intellectual property, that a company has built up over time and that can help contribute to future profits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>36", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "A set of instructions or programs which controls the operation of a computer is", "images": [], "options": {"A": "software", "B": "hardware", "C": "monitor", "D": "keyboard"}, "answer": "A", "explanation": "A set of instructions or programs which controls the operation of a computer is referred to as 'software'. Software is a general term for the various kinds of programs used to operate computers and related devices. It is the non-tangible component of computers, which is used to manage and control the hardware components and to perform specific tasks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>37", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "The process of detecting, tracing and eliminating errors in a computer program is", "images": [], "options": {"A": "reproduction", "B": "debugging", "C": "sorting", "D": "retrieving"}, "answer": "B", "explanation": "Debugging is the process of detecting, tracing, and eliminating errors in a computer program. It involves identifying the problem, isolating the source of the problem, and then either correcting the problem or determining a way to work around it. The final step of debugging is to test the correction or workaround for correctness.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>38", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "In a not-for-profit making organization, the cash book is referred to as", "images": [], "options": {"A": "income and expenditure account", "B": "receipts and payments account", "C": "two column cash book", "D": "petty cash book"}, "answer": "B", "explanation": "In a not-for-profit making organization, the cash book is referred to as 'receipts and payments account'. This account records all cash receipts and payments, including bank deposits and withdrawals. Entries in the receipts and payments account are not typically broken down into as much detail as those in a for-profit organization's cash account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>39", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "When the going concern concept is no longer applicable, the fixed assets are recorded at their", "images": [], "options": {"A": "net book value", "B": "realizable value", "C": "gross value", "D": "revalued amount"}, "answer": "B", "explanation": "The going concern concept in accounting assumes that a business will continue to operate indefinitely. If this concept is no longer applicable, it means the business is facing liquidation or closure. In such a case, the fixed assets are recorded at their realizable value, which is the amount that can be recovered from their sale, not their original cost or book value. Hence, the correct answer is 'realizable value'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>40", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "GH⊄Stock of raw materials 1/1/09    Stock of raw materials 31/12/09    Purchase of raw materials    Carriage inwards    Direct labour    Factory overhead5,000    5,500    50,000    3,000    12,000    17,000    The cost of raw materials consumed is", "images": [], "options": {"A": "GH⊄58,000", "B": "GH⊄52,500", "C": "GH⊄52,000", "D": "GH⊄50,000"}, "answer": "B", "explanation": "GH⊄ Opening stock of raw material 5 000Add: purchase of raw material 50 000carriage inward 3 000Cost of raw material available for use 58 000Less: closing stock of raw material  5 500  Cost of raw material consumed 52 500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2013>41", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "GH⊄Stock of raw materials 1/1/09    Stock of raw materials 31/12/09    Purchase of raw materials    Carriage inwards    Direct labour    Factory overhead5,000    5,500    50,000    3,000    12,000    17,000   The prime cost is", "images": [], "options": {"A": "GH⊄64,500", "B": "GH⊄64,000", "C": "GH⊄58,500", "D": "GH⊄52,500"}, "answer": "A", "explanation": "The prime cost is calculated by adding the cost of raw materials and direct labor. The cost of raw materials is calculated by adding the opening stock of raw materials, purchases of raw materials, and carriage inwards, then subtracting the closing stock of raw materials. Therefore, the prime cost is (5,000 + 50,000 + 3,000 - 5,500) + 12,000 = 64,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2013>42", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following relates to the essence of partnership? To", "images": [], "options": {"A": "run a charity organization", "B": "pursue a social objective", "C": "form a business for profit", "D": "run a religious objective"}, "answer": "C", "explanation": "The essence of a partnership is to form a business for profit. This is the primary objective of forming a partnership.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>43", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The basic assumption which underlines the preparation of periodic financial statement is known as accounting", "images": [], "options": {"A": "bases", "B": "techniques", "C": "concepts", "D": "method"}, "answer": "C", "explanation": "The basic assumption which underlines the preparation of periodic financial statement is known as accounting concepts. Accounting concepts are the basic assumptions, rules of operation, and essential characteristics that make up the framework for the construction of accounting financial statements. They include concepts like the money measurement concept, business entity concept, going concern concept, accounting period concept, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>44", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS", "question": "Upon the dissolution of a partnership business, the party to be settled first out of the proceeds realized is", "images": [], "options": {"A": "unsecured creditors", "B": "partners' loan and advances", "C": "secured creditors", "D": "partners' capital"}, "answer": "C", "explanation": "Upon the dissolution of a partnership business, the party to be settled first out of the proceeds realized is the secured creditors. This is because secured creditors have a legal right to get their payments before others due to the collateral that secures their loan. After secured creditors, the order of payment is usually unsecured creditors, partners' loan and advances, and finally partners' capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>45", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Stock account is a type of", "images": [], "options": {"A": "nominal account", "B": "personal account", "C": "real account", "D": "fixed assets account"}, "answer": "C", "explanation": "A stock account is a type of real account. Real accounts are those that relate to the properties or legal rights of a company. They include assets accounts, liability accounts, and capital accounts. Stock account is an asset account because it represents the stock of goods a company has for its business operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2013>46", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "At the end of a trading period, cost of goods sold is debited to the trading account while cost of services is debited to the", "images": [], "options": {"A": "balance sheet", "B": "manufacturing account", "C": "trading account", "D": "profit and loss account"}, "answer": "D", "explanation": "At the end of a trading period, cost of goods sold is debited to the trading account while cost of services is debited to the profit and loss account. This is because the cost of services rendered is an expense, and all expenses are recorded in the profit and loss account. The trading account, on the other hand, is used to determine the gross profit or loss of a business by comparing the costs of goods sold with the sales revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>47", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not part of prime cost of production?", "images": [], "options": {"A": "Depreciation of factory equipment", "B": "Direct expenses", "C": "Direct wages", "D": "Carriage on raw materials"}, "answer": "A", "explanation": "Prime cost is the cost of all direct expenses. This include Royalties, direct wages, direct expenses, manufacturing wages. All except depreciation of factory equipment are prime cost. Depreciation of factory equipment is an indirect expense.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>48", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Excess of current assets over current liabilities is", "images": [], "options": {"A": "deferred capital", "B": "nominal capital", "C": "working capital", "D": "authorized capital"}, "answer": "C", "explanation": "The excess of current assets over current liabilities is known as working capital. It represents a company's operational liquidity or the amount of money that a company has to meet its short-term obligations. Therefore, the correct answer is 'working capital'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>49", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A statement showing a trader's financial position as at a particular date is a/an", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "balance sheet", "D": "appropriation account"}, "answer": "C", "explanation": "A balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time, and provides a basis for computing rates of return and evaluating its capital structure. It is a financial snapshot of the firm at a given point in time. The other options do not accurately describe a statement showing a trader's financial position.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2013>50", "subject": "Accounts", "year": "2013", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "A trading account is prepare to disclose the", "images": [], "options": {"A": "net profit or loss for the year", "B": "gross profit or loss for the year", "C": "accumulated fund for the year", "D": "gross profit on manufacturing"}, "answer": "B", "explanation": "A trading account is a separate account managed by a broker or financial institution on behalf of an investor. The trading account is where all the buying and selling of securities, commodities, and other financial instruments occur. The purpose of a trading account is to determine the gross profit or loss. The gross profit or loss is calculated as the difference between the total sales and the cost of goods sold. The other options do not accurately describe the purpose of a trading account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>1", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "The source document used to make entries in the purchases day book is", "images": [], "options": {"A": "debit note", "B": "credit note", "C": "invoice", "D": "receipt"}, "answer": "C", "explanation": "The source document used to make entries in the purchases day book is the invoice. An invoice is a document issued by a seller to the buyer that indicates quantities, descriptions, and prices of the products or services the seller has provided the buyer. It indicates the amount that the buyer owes for the goods or services they have purchased.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>2", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "A book that contains individual accounts of suppliers is the", "images": [], "options": {"A": "purchases ledger", "B": "general ledger", "C": "nominal ledger", "D": "sales ledger"}, "answer": "A", "explanation": "A book that contains individual accounts of suppliers is the purchases ledger. The purchases ledger is a subsidiary ledger where a business records its purchases on credit. Each supplier (creditor) has an individual account in the purchases ledger. The total balance of the purchases ledger is then transferred to the general ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>3", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "In the operation of an imprest system of petty cash,the", "images": [], "options": {"A": "petty cashier pays all expenses", "B": "petty cashier pays money to the accountant", "C": "petty cashier regularly begins each period with the same amount of money", "D": "main cashier accounts to the petty cashier for some expenses made by him"}, "answer": "C", "explanation": "In an imprest system of petty cash, the petty cashier starts each period with a fixed amount of money. This system is used to control the amount of petty cash expenditures by replenishing the fund at the end of each period to the fixed amount. Therefore, the petty cashier regularly begins each period with the same amount of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>4", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "An example of a credit entry in a profit and loss account is", "images": [], "options": {"A": "carriage inwards", "B": "carriage outwards", "C": "discounts allowed", "D": "discounts received"}, "answer": "D", "explanation": "A credit entry in a profit and loss account represents an income or gain. Discounts received is an example of a gain or income, hence it is credited in the profit and loss account. On the other hand, carriage inwards, carriage outwards and discounts allowed are expenses and are debited in the profit and loss account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>5", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Which of the following subsidiary books involves cash movement?", "images": [], "options": {"A": "Sales day book", "B": "Purchases day book", "C": "Returns inwards book", "D": "Petty cash book"}, "answer": "D", "explanation": "The Petty Cash Book is a type of subsidiary book where small day-to-day expenses of the business which are of small value and are not recorded in the main cash book as it is impractical to do so. These expenses involve cash movement, hence the correct answer is 'Petty cash book'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>6", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "The accounting treatment for a dishonoured cheque is, debit", "images": [], "options": {"A": "Customer's Account, Credit Bank Account", "B": "Bank Account, Credit Customer's Account", "C": "Customer's Account, Credit Sales Account", "D": "Sales Account, Credit Customer's Account"}, "answer": "A", "explanation": "When a cheque is dishonoured, the customer's account is debited because the customer owes the business the amount of the cheque. The bank account is credited because the business's bank balance decreases due to the dishonoured cheque. Hence, the correct accounting treatment for a dishonoured cheque is to debit the Customer's Account and credit the Bank Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>7", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Net turnover is referred to as", "images": [], "options": {"A": "purchases", "B": "assets", "C": "sales", "D": "profits"}, "answer": "C", "explanation": "Net turnover is a term that is often used to describe the total sales of a company in a given period after accounting for returns, allowances for damaged or missing goods, and any discounts allowed. Therefore, the correct answer is 'sales'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>8", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Which of the following transactions will result in disagreement between the cash book and the bank statement?", "images": [], "options": {"A": "Selling of goods on credit to a customer", "B": "Withdrawal of goods by the proprietor for his personal use", "C": "Cheque paid directly into the bank account by a customer", "D": "Omission of purchases received from a supplier on credit."}, "answer": "C", "explanation": "The transactions that can cause a disagreement between the cash book and the bank statement are those that are recorded by the bank but not yet recorded by the business or vice versa. When a cheque is paid directly into the bank account by a customer, the bank will record this transaction immediately, but the business may not record it until it receives notification from the bank. Therefore, there may be a temporary disagreement between the cash book and the bank statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>9", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Purchases Account is overcast by ₦200, while Wages Account is undercast by ₦200. This is", "images": [], "options": {"A": "an error of omission", "B": "a compensating error", "C": "an error of commission", "D": "an error of principle"}, "answer": "B", "explanation": "A compensating error occurs when two or more errors are committed in such a way that the net effect on the accounts is nil. In this case, the overcast of the Purchases Account by ₦200 is compensated by the undercast of the Wages Account by ₦200. Therefore, the net effect on the accounts is zero, making it a compensating error.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>10", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Which of the following is used to record the disposal of a fixed asset?", "images": [], "options": {"A": "Journal Proper", "B": "Petty Cash Book", "C": "Sales Day Book", "D": "Purchases Day Book"}, "answer": "A", "explanation": "The Journal Proper is used to record transactions that do not fit into any other specific journal such as the sales journal, purchases journal, cash receipts journal, or cash disbursements journal. Disposal of a fixed asset is a unique transaction that does not fit into the other specific journals, hence it is recorded in the Journal Proper.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>11", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "₦Cost of motor vehicle - 1/1/12    Residual value    Estimated useful lifespan 10 years  85,000    5,000   .      The business makes use of the straight line method for providing depreciation.    The annual depreciation is", "images": [], "options": {"A": "₦9,000", "B": "₦8,500", "C": "₦8,000", "D": "₦6,500"}, "answer": "C", "explanation": "The annual depreciation is calculated using the straight-line method formula: (Cost of Asset - Residual Value) / Useful Life of Asset = (₦85,000 - ₦5,000) / 10 = ₦8,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>12", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "₦Cost of motor vehicle - 1/1/12    Residual value    Estimated useful lifespan 10 years  85,000    5,000   .      The business makes use of the straight line method for providing depreciation.   The accumulated depreciation as at 31/12/2013 is", "images": [], "options": {"A": "₦18,500", "B": "₦17,000", "C": "₦16,000", "D": "₦8,000"}, "answer": "C", "explanation": "The accumulated depreciation is the total depreciation that has been recorded up to a specific point in time. In this case, two years of depreciation have occurred by 31/12/2013, so the accumulated depreciation is ₦8,000 * 2 = ₦16,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>13", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "An error of principle is made, if", "images": [], "options": {"A": "an entry has been made in the wrong class of account", "B": "a transaction has been completely omitted", "C": "an entry has been made on the wrong side of the two accounts concerned", "D": "a transaction is entered in both accounts for the wrong amount"}, "answer": "A", "explanation": "An error of principle in accounting occurs when the correct amount is posted in the wrong type of account. This means that the entry has been made in the wrong class of account. This error is a fundamental breach of the basic or fundamental principles of accounting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>14", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Which of the following is entered in the general journal?", "images": [], "options": {"A": "Purchase of goods", "B": "Sale of goods on credit", "C": "Returns inwards", "D": "Acquisition of fixed assets"}, "answer": "D", "explanation": "The general journal, also known as the book of original entry, records transactions in chronological order. It includes all types of entries, including the acquisition of fixed assets. The other options like purchase of goods, sale of goods on credit, and returns inwards are typically recorded in specific journals like the purchases journal, sales journal, and returns inwards journal respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>15", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The cost of carriage outward is classified as", "images": [], "options": {"A": "a selling and distribution expense", "B": "an administrative expense", "C": "a trading expense", "D": "a finance expense"}, "answer": "A", "explanation": "The cost of carriage outward refers to the expenses incurred by a business to transport goods to a customer after a sale has been made. This cost is typically classified as a selling and distribution expense because it is directly related to the sale of goods. Therefore, option 1 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>16", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "MISCELLANEOUS ACCOUNTS : CONSIGNMENT ACCOUNTS", "question": "The purchase of ten ceiling fans by Akpan Electronic Enterprises will be recorded as", "images": [], "options": {"A": "an acquisition of fixed asset", "B": "an expense in its general office expense account", "C": "part of capital in the capital account", "D": "an acquisition of stock"}, "answer": "D", "explanation": "The purchase of ten ceiling fans by Akpan Electronic Enterprises will be recorded as an acquisition of stock. This is because the fans are likely to be sold to customers, making them part of the company's inventory or stock. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>17", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following accounts would appear in the nominal ledger?   I.  Sanison's account (a debtor)   II. Motor vehicle account    III. Sales account      IV.  Rent and rates account", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "III and IV only"}, "answer": "D", "explanation": "Nominal account is the account for all expenses and incomes. Sales account and rent & rate account are nominal account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>18", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The sum of direct cost in a manufacturing account is", "images": [], "options": {"A": "production cost", "B": "prime cost", "C": "total cost", "D": "finance cost"}, "answer": "B", "explanation": "In a manufacturing account, the sum of direct costs (direct materials, direct labor, and other direct costs) is referred to as the prime cost. Direct costs are those that can be conveniently and directly allocated to a particular product. They are also known as the cost of goods directly attributable to the production process. Therefore, the correct answer is 'prime cost'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>19", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Net profit in a business is", "images": [], "options": {"A": "the amount of money taken out of the business by the owner", "B": "the cash in the business sales and cost of sales", "C": "the difference between sales and cost of sales", "D": "sale revenue less cost of sales and expenses"}, "answer": "D", "explanation": "Net profit in a business is the amount of revenue that remains after all costs, expenses, and taxes are deducted from the business's total revenue. This is represented by the formula: Net Profit = Total Revenue - Total Expenses. Therefore, the correct answer is 'sale revenue less cost of sales and expenses'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>20", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "An example of a self balancing account is the", "images": [], "options": {"A": "suspense account", "B": "creditors account", "C": "control account", "D": "debtors account"}, "answer": "C", "explanation": "A self-balancing account is an account in a double entry bookkeeping system, the total of which always equals the combined total of the corresponding subsidiary accounts. It is used to check the arithmetical accuracy of the books of accounts. Examples of self-balancing accounts include control accounts like Purchases Ledger Control Account, Sales Ledger Control Account etc. Therefore, the correct answer is 'control account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>21", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "The total sales of business was GH⊄ 2,160,000. The average mark-up for the year was 50%.    The gross profit", "images": [], "options": {"A": "GHc2,160,000", "B": "GHc1,440,000", "C": "GHc1,080,000", "D": "GHc720,000"}, "answer": "D", "explanation": "Markup = 50%   markup = 50100=12    To margin = 12+1=13    Margin = ProfitSalesx1001     13=profit2,160,000    Profit=2,160,0003    = 720,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>22", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "The total sales of business was GH⊄ 2,160,000. The average mark-up for the year was 50%.  The cost of sales is", "images": [], "options": {"A": "GHc2,160,000", "B": "GHc1,440,000", "C": "GHc1,080,000", "D": "GHc720,000"}, "answer": "B", "explanation": "Markup=Profitcost of sales      50100x720,000Cost of sales    Cost of sales = 720,000 x 2       Cost of sales = ₦1,440,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>23", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not an administrative expenses in a manufacturing organization?", "images": [], "options": {"A": "Discounts allowed", "B": "Office electricity", "C": "Stationery", "D": "Insurance"}, "answer": "A", "explanation": "Administrative expenses are the costs that an organization incurs not directly tied to a specific function such as manufacturing, production or sales. These expenses are related to the organization as a whole as opposed to an individual department or business unit. Major examples include salaries for employees not involved in manufacturing, such as the sales and administrative personnel. 'Discounts allowed' is not an administrative expense, it is a financial expense that arises from the business offering a reduction in the selling price to its customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>24", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "When an asset is sold, the entries for the accumulated depreciation are: debit", "images": [], "options": {"A": "Asset Disposal Account, credit Provision for Depreciation Account", "B": "Provision for Depreciation Account, Credit Asset Disposal Account", "C": "Fixed Asset Account, Credit Asset Disposal Account", "D": "Asset Disposal Account, Credit Fixed Asset Account"}, "answer": "A", "explanation": "When an asset is sold, the accumulated depreciation is removed from the books. The journal entry to remove the asset and its contra account is to debit the Accumulated Depreciation account and credit the respective asset account. Then, the gain or loss on the sale is calculated and recorded. If the asset is sold for cash, the cash account is debited. If the asset is sold on credit, the accounts receivable account is debited. The Asset Disposal Account is debited to remove the asset from the books and the Provision for Depreciation Account is credited to remove the accumulated depreciation related to that asset from the books.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>25", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A petty cash account has an imprest of D28,000. The account has a debit balance of D5,000. How much cash is needed to restore the imprest?", "images": [], "options": {"A": "D33,000", "B": "D28,000", "C": "D23,000", "D": "D5,000"}, "answer": "C", "explanation": "The imprest system is a way of managing petty cash. To restore the imprest, we subtract the debit balance from the imprest. That is, D28,000 - D5,000 = D23,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>26", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "In a not-for-profit making organization, when the total income is less than the total expenditure, the difference is a", "images": [], "options": {"A": "surplus", "B": "shortfall", "C": "loss", "D": "deficit"}, "answer": "D", "explanation": "In a not-for-profit organization, when the total income is less than the total expenditure, the difference is a deficit. A deficit occurs when expenses exceed revenues, imports exceed exports, or liabilities exceed assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>27", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept underlying the treatment of personal expenses of the business owner as drawing is", "images": [], "options": {"A": "periodicity", "B": "accrual", "C": "entity", "D": "materiality"}, "answer": "C", "explanation": "The accounting concept underlying the treatment of personal expenses of the business owner as drawing is the 'entity' concept. The entity concept is a principle that separates the business and the owner as two different entities. Therefore, any personal expenses of the owner are not considered as business expenses but as drawings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>28", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Which of the following items is not contained in the Receipts and Payments Account?", "images": [], "options": {"A": "Subscription paid in the advance", "B": "Stock paid for in advance", "C": "Outstanding wages and salaries", "D": "Donations"}, "answer": "C", "explanation": "The 'Receipts and Payments Account' is a summary of all cash transactions of a non-profit organization. It does not include non-cash items like outstanding wages and salaries. Therefore, 'Outstanding wages and salaries' is not contained in the Receipts and Payments Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>29", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that states that a business should not lay claim to any profits before it is earned with reasonable certainty  is", "images": [], "options": {"A": "consistency concept", "B": "prudence concept", "C": "accrual concept", "D": "going concern concept"}, "answer": "B", "explanation": "The prudence concept in accounting states that a business should not recognize any profit until it has been realized or earned with reasonable certainty. This concept is also known as the conservatism principle, which requires that expenses and liabilities be recognized as soon as possible, but revenues only when they are assured or realized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>30", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When shares are issued above their nominal value, the excess above the nominal value is", "images": [], "options": {"A": "credited to Profit and Loss Account", "B": "debited to Share Premium Account", "C": "credited to Share Capital Account", "D": "credited to share Premium Account"}, "answer": "D", "explanation": "When shares are issued above their nominal value, the excess above the nominal value is credited to the Share Premium Account. This is in accordance with the Companies Act, which states that the amount received over and above the face value of shares should be transferred to the 'Securities Premium Account' or 'Share Premium Account'. This account can be used for purposes specified in the Act, such as issuing bonus shares to shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>31", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Shares issued below nominal value are referred to as shares at", "images": [], "options": {"A": "premium", "B": "discount", "C": "face value", "D": "cumulative value"}, "answer": "B", "explanation": "Shares issued below nominal value are referred to as shares at a discount. The nominal value of a share, also known as the par value, is its face value. When shares are issued at a price lower than this, they are said to be issued at a discount.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>32", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "leCapital:    Aye   Bee    Drawings:    Aye    Bee    Profit for the year    Interest on capital - 60%    Interest on drawings - 10%    Profit sharing is in the ratio of capital.  20,000   30,000    .   8,000    2,000    10,000             The divisible profit is", "images": [], "options": {"A": "Le 14,000", "B": "Le 12,000", "C": "Le 10,000", "D": "Le 8,000"}, "answer": "D", "explanation": "Dr. partners Appropriation A/C Cr.     Le  LeInterest on capital  Net profit b/f 10 000Aye 6% x 20 000 1 200 Interest on drawing Bee 6% x 30 000 18 000 Aye 10% x 8 000 800Share of profit: Aye 3 200 Bee 10% x 2 000 200Bee 4 800   11 000  11 000    Sharing ratio using their capital   Aye=20,00020,0000+30,000x8,000(Divisible profit)    25x8,0001    = ₦3,200    Bee=30,00050,000x8,000     = Le4,800    Divisible profit = Le3,2000 + Le4,800 = ₦8,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>33", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "leCapital:    Aye   Bee    Drawings:    Aye    Bee    Profit for the year    Interest on capital - 60%    Interest on drawings - 10%    Profit sharing is in the ratio of capital.  20,000   30,000    .   8,000    2,000    10,000            Aye's share of profit is", "images": [], "options": {"A": "Le6,000", "B": "Le4,800", "C": "Le4,000", "D": "Le3,200"}, "answer": "D", "explanation": "Aye=20,00020,0000+30,000x8,000(Divisible profit)    25x8,0001    = ₦3,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>34", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "leCapital:    Aye   Bee    Drawings:    Aye    Bee    Profit for the year    Interest on capital - 60%    Interest on drawings - 10%    Profit sharing is in the ratio of capital.  20,000   30,000    .   8,000    2,000    10,000            Bee's share of profit is", "images": [], "options": {"A": "Le8,000", "B": "Le6,000", "C": "Le4,800", "D": "Le3,200"}, "answer": "C", "explanation": "Bee's share of profit =30,00050,000x8,000     = Le4,800", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>35", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "The accounting ratio used to measure the average number of days for which suppliers remain unpaid is", "images": [], "options": {"A": "stock turnover", "B": "creditor's payment period", "C": "debtors collection period", "D": "return on capital employed"}, "answer": "B", "explanation": "The creditor's payment period is an accounting ratio that measures the average number of days that a company takes to pay its suppliers. It is calculated by dividing the accounts payable by the cost of sales, then multiplying by the number of days in the period. This ratio is useful for understanding the company's management of its relationships with its suppliers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>36", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PURCHASES OF BUSINESS : INTRODUCTION AND ADVANTAGES", "question": "When the purchase consideration exceeds the value of business, the difference is", "images": [], "options": {"A": "profit", "B": "discount", "C": "goodwill", "D": "reserve"}, "answer": "C", "explanation": "When the purchase consideration exceeds the value of the business, the difference is known as goodwill. Goodwill is an intangible asset that represents the non-physical assets, such as brand reputation, customer relationships, and intellectual property, that a company has. It is often created in an acquisition when the purchase price paid for a company exceeds the fair value of its identifiable tangible and intangible assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>37", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "The primary classification of government expenditure is based on", "images": [], "options": {"A": "programs", "B": "funds", "C": "activity", "D": "project"}, "answer": "A", "explanation": "The primary classification of government expenditure is based on programs. This is because government expenditure is usually allocated to different sectors or departments (programs) such as health, education, defense, etc. This classification helps in tracking and controlling the expenditure in each sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>38", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "An example of input device of a computer is", "images": [], "options": {"A": "an optical character reader", "B": "a graph plotter", "C": "a visual display unit", "D": "a printer"}, "answer": "A", "explanation": "An optical character reader (OCR) is an input device of a computer. It is used to read printed text and convert it into a form that the computer can manipulate (such as a text file). A graph plotter, a visual display unit, and a printer are all output devices, not input devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>39", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which states that expenditure involving insignificant amounts should be regarded as expenses and not assets is ?", "images": [], "options": {"A": "business entity", "B": "materiality", "C": "dual aspect", "D": "realization"}, "answer": "B", "explanation": "The accounting concept which states that expenditure involving insignificant amounts should be regarded as expenses and not assets is the Materiality concept. The Materiality concept in accounting states that all significant items must be reported but trivial ones can be disregarded. Items are considered material if they could influence economic decisions of financial statement users.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>40", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "A company made a net profit of ₦2,000,000 for the year and its net profit percentage is 25% of total sales. What is the total sales for the year?", "images": [], "options": {"A": "₦8,000,000", "B": "₦6,000,000", "C": "₦800,000", "D": "₦500,000"}, "answer": "A", "explanation": "The net profit percentage is given as 25% of total sales. This means that the net profit (₦2,000,000) is 25% of the total sales. To find the total sales, we can set up the equation: 0.25 * Total Sales = ₦2,000,000. Solving for Total Sales gives us ₦8,000,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>41", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following information is recorded in the returns outwards book?", "images": [], "options": {"A": "Goods purchased on credit and subsequently returned to supplier", "B": "Fixed asset bought on credit and subsequently returned to supplier", "C": "Cash payment received from a customer and subsequently returned to supplier", "D": "Goods sold to a customer and subsequently returned to the business"}, "answer": "A", "explanation": "The returns outwards book, also known as the purchase returns journal, is used to record goods that were purchased on credit and then returned to the supplier. This could be due to various reasons such as receiving damaged goods, incorrect quantity, etc. Therefore, the correct answer is 'Goods purchased on credit and subsequently returned to supplier'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>42", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "DBranch stock account (at selling price)    Branch mark-up account346,000 - Debit    62,000 - Credit    Calculate the stock figure to be included in the balance sheet at the year end.", "images": [], "options": {"A": "D408,000", "B": "D346,000", "C": "D284,000", "D": "D62,000"}, "answer": "C", "explanation": "The stock figure to be included in the balance sheet at the year end is calculated by subtracting the branch mark-up account (credit) from the branch stock account (debit). In this case, it would be 346,000 - 62,000 = 284,000. Therefore, the correct answer is 'D284,000'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>43", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "DBranch stock account (at selling price)    Branch mark-up account346,000 - Debit    62,000 - Credit  The concept applied in answering the former question is", "images": [], "options": {"A": "matching", "B": "consistency", "C": "prudence", "D": "entity"}, "answer": "A", "explanation": "Matching concept states all expenses and incomes will be matched together to ascertain the value of net profit - Like the illustration given above, the debit and the credit side are matched together to ascertain the balance of stock at the year end.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>44", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscriptions in advance is classified in the balance sheet as", "images": [], "options": {"A": "an asset", "B": "a liability", "C": "a deficit", "D": "a surplus"}, "answer": "B", "explanation": "Subscriptions in advance are classified in the balance sheet as a liability. This is because it represents an amount that has been received by the company, but for which the company has not yet provided goods or services. It is an obligation that the company needs to fulfill in the future, hence it is a liability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>45", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Which of the following items is not treated in the Profit and Loss Account?", "images": [], "options": {"A": "Office expenses", "B": "Salaries and allowances", "C": "Carriage inwards", "D": "Discounts allowed"}, "answer": "C", "explanation": "The Profit and Loss Account is a financial statement that summarizes the revenues, costs, and expenses incurred during a specific period of time. Office expenses, salaries and allowances, and discounts allowed are all expenses that are treated in the Profit and Loss Account. However, Carriage inwards refers to the cost of transporting goods into a business and is typically included in the cost of goods sold, not in the Profit and Loss Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>46", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The document prepared by a local/district government to present is annual estimates for a planning period is", "images": [], "options": {"A": "a balance sheet", "B": "budget", "C": "an income and expenditure account", "D": "a cash book"}, "answer": "B", "explanation": "A budget is a financial plan for a defined period, often one year, that is prepared by any entity, including a local/district government. It includes estimates of income or revenue and planning of how to meet the expenses of the entity. Therefore, the document prepared by a local/district government to present its annual estimates for a planning period is a budget. A balance sheet, an income and expenditure account, and a cash book are all financial statements or records, but they do not serve the same purpose as a budget.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>47", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "A manufacturing account is drawn up by", "images": [], "options": {"A": "firms providing personal services", "B": "firms engaged solely in buying and selling of goods", "C": "firms which make and sell articles", "D": "non-trading organization"}, "answer": "C", "explanation": "A manufacturing account is drawn up by firms which make and sell articles. This is because a manufacturing account is a type of account that is used to calculate the cost of goods produced in a manufacturing business. It includes all the direct and indirect costs associated with the production of goods. Firms providing personal services, firms engaged solely in buying and selling of goods, and non-trading organizations do not produce goods, hence they do not draw up manufacturing accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>48", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following is not a factory overhead cost?", "images": [], "options": {"A": "Manufacturing wages", "B": "Factory rent", "C": "Depreciation of machinery", "D": "Salary of factory guard"}, "answer": "A", "explanation": "Manufacturing wages are not a factory overhead cost. Factory overhead costs, also known as manufacturing overhead or factory burden, includes all the costs that a factory incurs, other than direct costs. Direct costs are costs that can be directly attributed to a product, such as direct materials and direct labor. Manufacturing wages are considered a direct cost because they can be directly attributed to the production of specific goods. Therefore, they are not included in factory overhead costs. The other options, factory rent, depreciation of machinery, and salary of factory guard, are all examples of factory overhead costs because they cannot be directly attributed to a specific product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2014>49", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO COMPUTER", "question": "A collection of fields relating to one logically definable unit of business information is known as", "images": [], "options": {"A": "data", "B": "character", "C": "byte", "D": "record"}, "answer": "D", "explanation": "A collection of fields relating to one logically definable unit of business information is known as a record. In database management, a record is a collection of related data items treated as a unit, such as all the information about a particular employee in a company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2014>50", "subject": "Accounts", "year": "2014", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The principle of double entry book-keeping states that", "images": [], "options": {"A": "every debtor must have a creditor", "B": "every account debited must be immediately credited", "C": "for every debit entry, there must be a corresponding credit entry", "D": "for every double debit, there must be a double credit"}, "answer": "C", "explanation": "The principle of double entry book-keeping states that for every debit entry, there must be a corresponding credit entry. This is a fundamental concept in accounting that ensures the accounting equation (Assets = Liabilities + Equity) is always balanced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>1", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following describes a trial balance?", "images": [], "options": {"A": "It is a special account", "B": "It is a list of balances in the books", "C": "It reveals the financial position of a business", "D": "It shows all the entries in the books of a business"}, "answer": "B", "explanation": "A trial balance is a bookkeeping worksheet in which the balances of all ledgers are compiled into debit and credit account column totals that are equal. Therefore, it is a list of balances in the books.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>2", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Which of the following is not a feature of accounting information?", "images": [], "options": {"A": "Affordability", "B": "Timeliness", "C": "Accuracy", "D": "Completeness"}, "answer": "A", "explanation": "Accounting information should be relevant, reliable, comparable and consistent. Affordability is not a feature of accounting information. The other options, timeliness, accuracy, and completeness, are all features of good accounting information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>3", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following is the equation for determining net profit or loss from the records of a firm?", "images": [], "options": {"A": "Closing Capital - Drawings - Capital Introduced", "B": "Opening Capital + Drawings - Closing Capital", "C": "Closing Capital + Opening Capital - Drawings", "D": "Closing Capital + Drawings - Opening Capital"}, "answer": "D", "explanation": "Net profit or loss = Closing capital + opening capital - drawing", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>4", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Purchase invoice is first entered in the", "images": [], "options": {"A": "Purchase account", "B": "cash book", "C": "Sales journal", "D": "Purchases journal"}, "answer": "D", "explanation": "A purchase invoice is first entered in the Purchases journal. The Purchases journal is a special journal used to record all purchases of merchandise for resale or supplies for use in the business on account. It is part of the double-entry bookkeeping system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>5", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Assets acquired is recorded by debiting", "images": [], "options": {"A": "Asset Account, crediting Cash Accounting", "B": "Cash Account, crediting Asset Account", "C": "Purchase of Business Account, crediting Sale of Business Account", "D": "Cash Account"}, "answer": "A", "explanation": "When an asset is acquired, the Asset Account is debited because in accounting, a debit to an asset account signifies an increase in its value. The Cash Account is credited because cash is going out of the business to pay for the asset, and a credit to an asset account signifies a decrease in its value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>6", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Goods returned to a supplier is", "images": [], "options": {"A": "debited to Returns outwards account", "B": "credited to Return outwards account", "C": "debited to Return inwards account", "D": "credited to Returns inward account"}, "answer": "B", "explanation": "Good return to supplier is always credited to returns outward account. Return outward is a term used when goods are returned back to the supplier or creditor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>7", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following is a real account?", "images": [], "options": {"A": "Plant account", "B": "Salaries account", "C": "Creditors account", "D": "Trading account"}, "answer": "A", "explanation": "A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year-end and are carried forward. An example of a Real Account is a Plant Account. Salaries account, Creditors account, and Trading account are not real accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>8", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER", "question": "The accounting ledger for goods sold on credit are debit", "images": [], "options": {"A": "Debtors Account, credit Sales Account", "B": "Creditors Account, credit Sales Account", "C": "Sales Account, credit Debtors Account", "D": "Sales Account, credit Creditors Account"}, "answer": "A", "explanation": "When goods are sold on credit, the Debtors Account is debited because it increases the accounts receivable. The Sales Account is credited because it increases the total sales. Therefore, the correct entry is 'Debit Debtors Account, Credit Sales Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>9", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Which of the following is not a  book of original entry ?", "images": [], "options": {"A": "Sales journey", "B": "Purchases account", "C": "Cash account", "D": "Return inwards journal"}, "answer": "C", "explanation": "Book of original entry is used to record all credit transaction. It is the subsidiary book which all first entries are made. Examples include sales, Journal, purchase Journal , cash book, petty cash book etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>10", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER", "question": "What is the ledger entry for the sale of plant and machinery on credit on Wilson?", "images": [], "options": {"A": "Credit Sales Account and debit Cash Account", "B": "Credit Plant and Machinery Account and debit Wilson's Account", "C": "Credit Sales Account and debit Cash Wilson's Account", "D": "Credit Plant and Machinery Account and debit Cash Account"}, "answer": "B", "explanation": "When a sale of plant and machinery on credit is made, the entry is made in the debtor's account (in this case, Wilson's account) and the asset account (Plant and Machinery account). The Plant and Machinery account is credited because the asset is reduced, and Wilson's account is debited because Wilson owes the company money for the asset. Therefore, the correct answer is 'Credit Plant and Machinery Account and debit Wilson's Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>11", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Discount Received Account is a", "images": [], "options": {"A": "real account", "B": "personal account", "C": "nominal account", "D": "profit and loss account"}, "answer": "C", "explanation": "Discount Received Account is a nominal account. Nominal accounts are income, expense, loss, and gain accounts. They are used to record transactions related to expenses, losses, incomes, and gains. In this case, a discount received is an income for the business, hence it is a nominal account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>12", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Which of the following accounts has a credit balance?", "images": [], "options": {"A": "Capital", "B": "Cash", "C": "Drawings", "D": "Premises"}, "answer": "A", "explanation": "A Capital account has a credit balance. In accounting, a capital account is a general ledger account that is used to record the owners' contributed capital and retained earnings—the cumulative amount of a company's earnings since it was formed, minus the cumulative dividends paid to the shareholders. Therefore, it has a credit balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>13", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SUSPENSE ACCOUNT : ERRORS THAT WILL AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "The accounting entry to correct sales day book overcast is", "images": [], "options": {"A": "debit Sales Account and credit Debtors Account", "B": "debit Suspense Account and credit Sales Account", "C": "debit Debtors Account and credit Suspense Account", "D": "debit Sales Account and credit Suspense Account"}, "answer": "D", "explanation": "Sales day book overcast is corrected by debiting sales and crediting suspense A/C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>14", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Which of the following expresses the accounting equation?", "images": [], "options": {"A": "Capital + Assets = Liabilities", "B": "Assets - Liabilities = Capital", "C": "Liabilities + Current Assets = Fixed Asset", "D": "Liabilities - Capital = Current Assets"}, "answer": "B", "explanation": "The accounting equation is a fundamental principle in double-entry bookkeeping. It states that at any given time, a company's assets are financed by its liabilities and its owner's equity (capital). This relationship is expressed as Assets = Liabilities + Capital. Rearranging this equation gives us Assets - Liabilities = Capital, which is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>15", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "When the invoice of a customer is overcast, the supplier will send to him a", "images": [], "options": {"A": "cheque", "B": "payment voucher", "C": "debit note", "D": "credit note"}, "answer": "D", "explanation": "When an invoice is overcast, it means that the total amount of the invoice is more than it should be. In such a case, the supplier will send a credit note to the customer. A credit note is a document sent by a seller to a buyer to correct a mistake, such as an overcharge, in an invoice that has already been sent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>16", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Unpresented cheques are cheques", "images": [], "options": {"A": "the have been recorded in the cash book, but not by the bank.", "B": "that have been received by the bank, but not recorded in the cash book", "C": "returned by the bank", "D": "written, but not handed over to customers"}, "answer": "A", "explanation": "Unpresented cheques are cheques that have been recorded in the cash book, but not yet presented to the bank for payment. This means that the bank is not aware of these cheques and hence, they are not recorded in the bank statement. This often leads to a difference between the balance as per bank statement and the balance as per cash book.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>17", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Extracts from the books of a firm as at June 30, 2012 showed the following balances:    DrCrGHcGHcAdvertising    Electricity36,000  60,000-  -  Advertising was paid by cheque covering 12 month instalments ending March 31, 2012. Electricity was paid by cash covering 15 monthly instalments from March 1, 2011.    Advertising owing in respect of the year ended June 30, 2012 is", "images": [], "options": {"A": "GHc12,000", "B": "GHc9,000", "C": "GHc6,000", "D": "GHc3,000"}, "answer": "B", "explanation": "Advertising per month =   36,00012=3000   Month between March and June = 3 months   3 months advertising expenses is owed in respect of the year ended June 30th, 2012.       Advertising owing = 3 x 3,000  = 9,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>18", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Extracts from the books of a firm as at June 30, 2012 showed the following balances:    DrCrGHcGHcAdvertising    Electricity36,000  60,000-  -  Advertising was paid by cheque covering 12 month instalments ending March 31, 2012. Electricity was paid by cash covering 15 monthly instalments from March 1, 2011.     What was the amount charged to the profit and loss account in respect of advertising for the year ended June 30, 2012?", "images": [], "options": {"A": "GHc 36,000", "B": "GHc 30,000", "C": "GHc 27,000", "D": "GHc 24,000"}, "answer": "A", "explanation": "The amount charged to the profit and loss account in respect of advertising for the year ended June 30, 2012 would be the total amount spent on advertising during that year. According to the information given, this amount is GHc 36,000. Therefore, the correct answer is GHc 36,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>19", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Extracts from the books of a firm as at June 30, 2012 showed the following balances:    DrCrGHcGHcAdvertising    Electricity36,000  60,000-  -  Advertising was paid by cheque covering 12 month instalments ending March 31, 2012. Electricity was paid by cash covering 15 monthly instalments from March 1, 2011.     Electricity in arrears as at June 30, 2012 amounted to", "images": [], "options": {"A": "GHc 12,000", "B": "GHc 10,000", "C": "GHc 8,000", "D": "GHc 4,000"}, "answer": "D", "explanation": "To determine the amount of electricity in arrears as of June 30, 2012, we first need to calculate the total electricity expense incurred from March 1, 2011, to June 30, 2012. The electricity was paid in 15 monthly installments starting from March 1, 2011. By June 30, 2012, 16 months would have passed (from March 2011 to June 2012). Therefore, the total electricity expense for 16 months is 16 installments. If we assume the monthly installment is GHc 4,000 (since the total of GHc 60,000 divided by 15 months equals GHc 4,000), the total expense for 16 months would be GHc 64,000. However, only GHc 60,000 was paid, which means GHc 4,000 is in arrears.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>20", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The cost of putting goods into a saleable condition is charged to", "images": [], "options": {"A": "balance sheet", "B": "trial balance", "C": "profit and loss account", "D": "trading account"}, "answer": "D", "explanation": "The cost of putting goods into a saleable condition is charged to the trading account. This is because the trading account is used to determine the gross profit or loss of a business by comparing the costs of goods sold (which includes the cost of making goods ready for sale) with the sales revenue. The other options (balance sheet, trial balance, and profit and loss account) are not where these costs are recorded.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>21", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Which of the following is not a method of depreciating fixed assets?", "images": [], "options": {"A": "Revaluation", "B": "Straight line", "C": "Diminishing balance", "D": "Obsolescence"}, "answer": "D", "explanation": "Depreciation is the process of allocating the cost of a tangible asset over its useful life. Method of depreciation includes: Straight line method, diminishing balance, revelation, sum of the year digit etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>22", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "In preparing a profit and loss account, a decrease in provision for doubtful debts accounts is treated as", "images": [], "options": {"A": "current liability", "B": "expenses", "C": "income", "D": "current assets"}, "answer": "C", "explanation": "In preparing a profit and loss account, a decrease in provision for doubtful debts is treated as income. This is because the provision for doubtful debts is an estimate of the amount of bad debt that will arise from accounts receivable that have been issued but not yet collected. If the provision decreases, it means that the expected bad debt is less than initially estimated, hence the difference is treated as income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>23", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Which of the following items is found in the sales ledger control account?", "images": [], "options": {"A": "Discount received", "B": "Total credit purchases", "C": "Discount allowed", "D": "Returns outwards"}, "answer": "C", "explanation": "The sales ledger control account is a summary account that checks the accuracy of the sales ledger. It includes all the transactions that involve credit sales, returns, and discounts allowed. Discount allowed is an expense for the business and is found in the sales ledger control account because it is related to credit sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>24", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "CONTROL ACCOUNTS : TREATMENT OF CONTRA ENTRIES", "question": "The process of using sales ledger balance to cancel off purchases ledger balance is", "images": [], "options": {"A": "balancing", "B": "set off", "C": "reconciliation", "D": "cancelling"}, "answer": "B", "explanation": "The process of using sales ledger balance to cancel off purchases ledger balance is known as 'set off'. This is a method used in accounting to eliminate or reduce the balance of one account with the balance of another account. It is often used when a company has both a receivable and a payable with the same party.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>25", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "The total of the returns outwards journal is posted to the", "images": [], "options": {"A": "credit side of the returns outwards book", "B": "debit side of the returns outwards account", "C": "debit side of the purchases returns book", "D": "credit side of the returns outwards account."}, "answer": "D", "explanation": "A return outward account is an account with a credit side balance which its source document as return outward Journal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>26", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Which of the following is not revealed by a firm's accounting records?", "images": [], "options": {"A": "Profit of a period", "B": "Quality of labour force", "C": "Credit worthiness", "D": "Value of assets"}, "answer": "B", "explanation": "A firm's accounting records reveal financial information such as the profit of a period, credit worthiness, and value of assets. However, they do not reveal the quality of the labour force. The quality of the labour force is a qualitative factor that cannot be measured in monetary terms and therefore is not recorded in the accounting records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>27", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "1/7/1030/6/11DDStock    Motor van    Creditors 1,460  3,600  6004,200  3,200  700   Drawings during the year amounted to D1,500    Opening capital is", "images": [], "options": {"A": "D5,660", "B": "D5,060", "C": "D4,460", "D": "D2,960"}, "answer": "C", "explanation": "Opening statement of capital     D  DOpening capital 4 460 Asset    Motor van 3 600Creditors 600 Stock 1 460  5 060  5060     Opening capital is ascertained when the liability is subtracted from the assets", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>28", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "1/7/1030/6/11DDStock    Motor van    Creditors 1,460  3,600  6004,200  3,200  700   Drawings during the year amounted to D1,500  Closing capital is", "images": [], "options": {"A": "D8,100", "B": "D7,400", "C": "D6,700", "D": "D5,200"}, "answer": "C", "explanation": "Closing statement of capital     D  DClosing capital 6 700 Asset    Motor van 3 200Creditors 700 Stock 4 200  7 400  7 400    Closing capital is ascertained when the liability is subtracted from the assets", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>29", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "1/7/1030/6/11DDStock    Motor van    Creditors 1,460  3,600  6004,200  3,200  700   Drawings during the year amounted to D1,500  Net profit for the year is", "images": [], "options": {"A": "D12,260", "B": "D3,740", "C": "D2,440", "D": "D2,040"}, "answer": "B", "explanation": "Statement of profit     DClosing capital 6 700Add: Drawing 1 500Less: opening capital 4 460Net profit 3 740", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2015>30", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "In the balance sheet of a social club, subscription owing is treated as a", "images": [], "options": {"A": "current liability", "B": "current asset", "C": "tangible asset", "D": "long-term liability"}, "answer": "B", "explanation": "In the balance sheet of a social club, subscription owing is treated as a current asset. This is because it represents the amount of money that is owed to the club by its members for the services provided. It is expected to be received within a short period of time, typically within one year, hence it is classified as a current asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>31", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept that allows the cost of kitchen cutlery to be expensed, though it will be used for more than one year is", "images": [], "options": {"A": "materiality", "B": "accrual", "C": "going concern", "D": "business entity"}, "answer": "A", "explanation": "The accounting concept that allows the cost of kitchen cutlery to be expensed, though it will be used for more than one year is 'materiality'. The materiality concept in accounting states that all significant items must be reported but insignificant items can be disregarded. In this case, the cost of kitchen cutlery is considered insignificant compared to the total expenses of the business, hence it can be expensed in the year it was purchased even though it will be used for more than one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>32", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept that assumes that a business will continue operating for an indefinite period is", "images": [], "options": {"A": "business entity", "B": "going concern", "C": "consistency", "D": "duality"}, "answer": "B", "explanation": "The accounting concept that assumes that a business will continue operating for an indefinite period is 'going concern'. The going concern concept in accounting assumes that a business will continue to operate indefinitely, or at least for another twelve months. This assumption allows the business to defer some of its prepaid expenses until future accounting periods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>33", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept states that a firm's financial affairs must be separated from that of the owner's private transaction is", "images": [], "options": {"A": "business entity", "B": "going concern", "C": "consistency", "D": "duality"}, "answer": "A", "explanation": "The 'business entity' concept in accounting states that the business and the owner are two separate entities. In other words, the business's financial transactions are separate from the owner's personal transactions. This concept helps in keeping the business's financial information independent and accurate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>34", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "Goodwill is recognized in partnership accounts when", "images": [], "options": {"A": "the business makes a huge profit", "B": "the business has good customer relationship", "C": "a partner is dormant", "D": "a new partner is admitted"}, "answer": "D", "explanation": "Goodwill is recognized in partnership accounts when a new partner is admitted. This is because the new partner usually pays an amount for the goodwill of the firm, which is the firm's reputation that has been built over time. This amount is then divided among the existing partners in the agreed ratio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>35", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "In which of the following accounts is interest  on partners capital found?", "images": [], "options": {"A": "Profit and Loss", "B": "Trading", "C": "Income surplus", "D": "Profit and loss appropriation"}, "answer": "D", "explanation": "Interest on partners' capital is found in the Profit and Loss Appropriation Account. This account is used to distribute the net profit among the partners in their agreed profit sharing ratio. It also includes any interest on capital, salaries, or commissions to the partners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>36", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Which of the following is not stated in the partnership agreement?", "images": [], "options": {"A": "Profit sharing ratio", "B": "Interest on capital", "C": "Interest on fixed asset", "D": "Purpose of partnership"}, "answer": "C", "explanation": "Interest on fixed asset is not stated in the partnership agreement. A partnership agreement typically includes terms such as profit sharing ratio, interest on capital, and purpose of partnership. However, interest on fixed asset is not a term that is typically included in a partnership agreement as fixed assets are not usually subject to interest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>37", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "Mr. White acquired Mr. Black's business for GHc 410,000. The total assets were GHc 670,000 and liabilities amounted to GHc 320,000.    How much was paid for goodwill?", "images": [], "options": {"A": "GHc350,000", "B": "GHc260,000", "C": "GHc90,000", "D": "GHc60,000"}, "answer": "D", "explanation": "Business value = Asset - Liability  =   670,000 - 320,000  = 350,000    Goodwill = Purchase consideration - business value  = 410,000 - 350,000  = 60,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>38", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "Mr. White acquired Mr. Black's business for GHc 410,000. The total assets were GHc 670,000 and liabilities amounted to GHc 320,000.    The double entry to record the goodwill in the books is debit.", "images": [], "options": {"A": "Cash Account and credit Goodwill Account", "B": "Goodwill Account and credit Purchases of Business Account", "C": "Goodwill Account and credit Cash Account", "D": "Purchase of Business Account and credit Cash Account."}, "answer": "B", "explanation": "When recording goodwill in the books, the Goodwill Account is debited to increase its value, and the Purchases of Business Account is credited to decrease its value. This is because the purchase of a business is an expense, and expenses are increased by debits and decreased by credits. On the other hand, goodwill is an asset, and assets are increased by debits and decreased by credits. Therefore, the correct double entry to record the goodwill is to debit the Goodwill Account and credit the Purchases of Business Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>39", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "The document which sets out the internal arrangement for the proper management of a company is the", "images": [], "options": {"A": "prospectus", "B": "article of association", "C": "memorandum of association", "D": "certificate of incorporation"}, "answer": "B", "explanation": "The 'articles of association' is the document that sets out the internal arrangement for the proper management of a company. It contains the rules and regulations or by-laws of the company and covers areas such as the rights of shareholders, the appointment and powers of directors, the conduct of meetings, etc. The 'memorandum of association' is a document that governs the company's relations with the outside world. 'Prospectus' is a document inviting the public to subscribe to shares, while 'certificate of incorporation' is a document that signifies the legal existence of a company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>40", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A person who has applied to purchase shares in a company is referred to as", "images": [], "options": {"A": "a promoter", "B": "a subscriber", "C": "an allotee", "D": "an underwriter"}, "answer": "B", "explanation": "Underwriter is a entity who is in the business of evaluating and taking over other people's risk. A subscriber or applicant is a person who buys a company's share. A promoter is an individual or organization that helps to raise money for some type of investment activities. An allottee is a person to whom shares are allotted to.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>41", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Which of the following expenses is allocated according to the floor area?", "images": [], "options": {"A": "Wages and salaries", "B": "Rent and rates", "C": "Canteen expenses", "D": "Discount allowed"}, "answer": "B", "explanation": "Rent and rates are typically allocated according to the floor area. This is because the cost of rent and rates is often directly proportional to the size of the space being used. Therefore, in a situation where multiple departments or entities are sharing a space, the rent and rates would be divided according to the amount of floor area each one is occupying.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>42", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "MISCELLANEOUS ACCOUNTS : CONSIGNMENT ACCOUNTS", "question": "Goods stolen at the branch is debited to", "images": [], "options": {"A": "Defalcations Account", "B": "Branch Stock Account", "C": "Branch Adjustment Account", "D": "Branch Debtors' Account"}, "answer": "C", "explanation": "Good stolen at branch   Dr. profit and loss A/C  cost price   Dr. Branch adjustment A/C  profit loading   Cr. Branch stock account  invoice price", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>43", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is a source of revenue for a local government?", "images": [], "options": {"A": "Personal income tax", "B": "company registration fees", "C": "Royalties", "D": "Market tolls"}, "answer": "D", "explanation": "A source of revenue for a local government includes market tolls. Market tolls are fees that are charged by local governments for the use of certain facilities or services in the market. This is a common source of revenue for local governments. Personal income tax is typically a source of revenue for the federal government, not local governments. Company registration fees are usually collected by the corporate affairs commission, not local governments. Royalties are typically paid to individuals or companies that own rights to a particular asset, not to local governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>44", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The instrument used to release fund which the minister of finance had earlier withheld is", "images": [], "options": {"A": "reserve expenditure warrant", "B": "supplementary general warrant", "C": "provisional general warrant", "D": "supplementary statutory warrant"}, "answer": "B", "explanation": "Supplementary general warrant is an instrument that is used to authorize the officer in charge to release funds as contained in the supplementary budget", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>45", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "Which of the following relates to cash basis of accounting?", "images": [], "options": {"A": "Accruals and prepayments are considered", "B": "Debtors and creditors are recorded", "C": "Fixed assets are written off in the year of purchase", "D": "Profits are maximized."}, "answer": "D", "explanation": "Under cash basis, financial transactions are recorded in the books when actual payment is made or money received. This approach does not take into consideration creditors and debtors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>46", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "AdeBola₦₦Capital   Drawings 40,000  10,00030,000  15,000  Interest on Drawings is 5%    Profit is shared equally:    Net profit for the period is ₦ 4,250    Ade's share of profit is", "images": [], "options": {"A": "₦5,500", "B": "₦4,250", "C": "₦2,750", "D": "₦1,250"}, "answer": "C", "explanation": "Dr. Profit & Loss Appropriation Account     ₦  ₦In  Net profit b/f 4 250   Interest on drawing Share of profit: Ade 2 750 Ade 5% x 10 000 500 Bola 2 750 Bola 5% x 1500 750  5 500  5 500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>47", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "AdeBola₦₦Capital   Drawings 40,000  10,00030,000  15,000  Interest on Drawings is 5%    Profit is shared equally:    Net profit for the period is ₦ 4,250   Bola's share of profit is", "images": [], "options": {"A": "₦4,500", "B": "₦4,250", "C": "₦3,000", "D": "₦2,750"}, "answer": "D", "explanation": "Dr. Profit & Loss Appropriation Account     ₦  ₦In  Net profit b/f 4 250   Interest on drawing Share of profit: Ade 2 750 Ade 5% x 10 000 500 Bola 2 750 Bola 5% x 1500 750  5 500  5 500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2015>48", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following is found on the credit side of a partnership's appropriation of profit account?", "images": [], "options": {"A": "Interest on capital", "B": "Interest on drawings", "C": "Share of profit", "D": "Drawings"}, "answer": "B", "explanation": "Credit side of partnership appropriation contains   -  Net profit brought forward   -   Interest on drawings     Debit side of partnership appropriation contains   -   Interest on capital A/C   -   Share of profit etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>49", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Which of the following is a spreadsheet application?", "images": [], "options": {"A": "Excel", "B": "Word", "C": "Internet", "D": "Windows"}, "answer": "A", "explanation": "Excel is a spreadsheet application. A spreadsheet is a file made of rows and columns that help sort, organize, and arrange data efficiently. It also provides the flexibility to use a variety of arithmetic operations on the data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2015>50", "subject": "Accounts", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "The quality of output information depends on the", "images": [], "options": {"A": "Quality of input", "B": "Time of processing", "C": "Speed of processing", "D": "Quantity of output device"}, "answer": "A", "explanation": "The quality of output information depends on the quality of input. This is based on the principle of 'Garbage In, Garbage Out' (GIGO) in the field of information and computer science. It implies that incorrect or poor quality input will always produce faulty output.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>1", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "External users of accounting information include", "images": [], "options": {"A": "employees", "B": "management", "C": "bankers", "D": "directors"}, "answer": "C", "explanation": "External users of accounting information are individuals or other enterprises that are not involved in the day-to-day operations of the business but have an interest in the business. These include investors, creditors, government agencies, analysts, and indeed, bankers. They use the information to make a variety of decisions such as whether to invest in the business, lend money, extend credit, etc. Employees, management, and directors are considered internal users as they are part of the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>2", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Every asset should have", "images": [], "options": {"A": "a non-monetary value", "B": "tangible and intangible qualities", "C": "monetary cost and future benefits", "D": "an inadequate monetary value"}, "answer": "B", "explanation": "Tangible asset are asset we can see with our eyes like cash, furniture, land and building etc. Intangible asset are asset that we can not see nor touch but it shows the patronage of a business such goodwill. This best describe the quality of an assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>3", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER", "question": "Which of the following are impersonal accounts?  I. Investment   II. Creditors  III. Premises  IV. Debtors  V. Salaries", "images": [], "options": {"A": "I, III and IV", "B": "I, III and V", "C": "II and IV", "D": "III and V"}, "answer": "B", "explanation": "Impersonal accounts are those accounts that are not related to individuals, firms, or companies. They are further divided into two categories: Real Accounts and Nominal Accounts. Real accounts are related to properties or assets of a business, while Nominal accounts are related to income, expenses, losses, and gains. In the given options, Investment (I), Premises (III), and Salaries (V) are impersonal accounts. Creditors (II) and Debtors (IV) are personal accounts as they are related to individuals or firms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>4", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Nwoye buys stock and pays by cheque. The entries in the books of Nwoye is Debit", "images": [], "options": {"A": "Purchases, Credit cheque", "B": "Purchase, Credit bank", "C": "Bank, Credit Purchases", "D": "Cheque, Credit Purchases"}, "answer": "B", "explanation": "In accounting, when a purchase is made, the Purchases account is debited because it increases the expense (or asset in case of capital expenditure) of the business, and the mode of payment is credited. In this case, since the payment is made by cheque, the Bank account is credited (as the bank balance decreases).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>5", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A bank statement shows an overdraft of GH⊄190,000. Kofi, a debtor, paid GH⊄400,000 into the account. The new bank balance is", "images": [], "options": {"A": "GH⊄590,000", "B": "GH⊄590,000 overdrawn", "C": "GH⊄210,000", "D": "GH⊄210,000 overdrawn"}, "answer": "C", "explanation": "An overdraft means that the account is in deficit, i.e., the account holder owes the bank money. In this case, the account is GH⊄190,000 in deficit. When Kofi, a debtor, pays GH⊄400,000 into the account, this amount is subtracted from the overdraft, resulting in a new balance of GH⊄210,000. Therefore, the correct answer is GH⊄210,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>6", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Which of the following errors are errors of commission?  I. A cheque paid to Adom debited to Adam's account   II. Credit sales to Eva credited to sales account but debited to Eve's account  III. Furniture repairs debited to furniture account  IV. Credit purchases from Manu credited to Manu's account", "images": [], "options": {"A": "I and II", "B": "I and IV", "C": "II and IV", "D": "III and IV"}, "answer": "A", "explanation": "Errors of commission occur when an entry is made at the right amount, and the appropriate side (debit or credit), but to the wrong person's account. In this case, options I and II are errors of commission. In option I, a cheque paid to Adom is debited to Adam's account, which is a mistake of the person's account. In option II, credit sales to Eva are debited to Eve's account, which is also a mistake of the person's account. Therefore, the correct answer is I and II.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>7", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "A petty cash account has an imprest of GH⊄6,000. If GH⊄2,000 were left, how much will be re-imbursed at the end of the period?", "images": [], "options": {"A": "GH⊄8,000", "B": "GH⊄6,000", "C": "GH⊄4,000", "D": "GH⊄2,000"}, "answer": "C", "explanation": "The petty cash system operates on an imprest system, which means that the amount in the petty cash fund is constant. When the fund gets low, the petty cash custodian requests a check to refill the fund back to the original amount. In this case, the original amount is GH⊄6,000. If GH⊄2,000 were left, then GH⊄4,000 would be needed to bring the fund back to the original amount.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>8", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Cash paid to Jake, ₦2,500, was entered on the credit side of his account and debited to cash account. This is an error of", "images": [], "options": {"A": "Principle", "B": "Commission", "C": "Complete reversal of entries", "D": "Original entry"}, "answer": "C", "explanation": "This is an error of complete reversal of entries. In double-entry bookkeeping, each transaction is recorded as both a debit and a credit. In this case, the cash paid to Jake should have been debited from Jake's account and credited to the cash account. However, the transaction was recorded in reverse, with a credit to Jake's account and a debit to the cash account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>9", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "One of the Purchases invoices of Mr. Dauda showed D96,240 less 12 1/2 % trade discount and cash discount of 20%. Since Mr. Dauda paid the amount due within the credit period, the amount paid is", "images": [], "options": {"A": "D77,368", "B": "D73,157", "C": "D67,368", "D": "D63,157"}, "answer": "C", "explanation": "First, we calculate the trade discount which is 12.5% of D96,240. This gives D12,030. Subtracting this from the original amount gives D84,210. Then, we calculate the cash discount which is 20% of D84,210. This gives D16,842. Subtracting this from D84,210 gives D67,368. Therefore, the amount paid by Mr. Dauda is D67,368.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>10", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Bank reconciliation statement is prepared to reconcile the differences between", "images": [], "options": {"A": "bank statement and credit transfers", "B": "cash book and bank transfer", "C": "bank statement and cash transfers", "D": "cash book and bank statement"}, "answer": "D", "explanation": "A bank reconciliation statement is a statement prepared by a company to reconcile the difference between the balance of cash according to the company's cash book and the balance of cash according to the bank statement. This difference may arise due to checks issued but not yet presented for payment, checks deposited but not yet cleared, bank charges, bank interest, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>11", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Which of the following items of expense involves actual cash payment?", "images": [], "options": {"A": "Discount allowed", "B": "Provision for depreciation", "C": "Carriage outwards", "D": "Allowance for doubtful debts"}, "answer": "C", "explanation": "Carriage outwards is an item of expense that involves actual cash payment. Carriage outwards is the cost of transportation of goods to the point of sales.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>12", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "In the preparation of the Trading Account of Omuya Limited, the company included credit sales of ₦18,000 made during the year. The concept guiding this treatment is the", "images": [], "options": {"A": "materiality concept", "B": "dual aspect concept", "C": "matching concept", "D": "money measurement concept"}, "answer": "D", "explanation": "The money measurement concept in accounting means that only transactions and events that are capable of being measured in monetary terms are recognized in the financial statements. In this case, the credit sales of ₦18,000 made during the year can be measured in monetary terms and hence, are included in the Trading Account of Omuya Limited. The other concepts do not apply in this context. The materiality concept states that all significant items must be reported in the financial statements. The dual aspect concept states that every financial transaction has two sides - a debit and a credit. The matching concept states that the expenses incurred in an accounting period should be matched with the revenues earned in that same period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>13", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "In accounting context, purchases refer to", "images": [], "options": {"A": "goods bought and paid for only", "B": "goods bought for resale only", "C": "goods bought on credit only", "D": "goods bought to be used in the firm only"}, "answer": "B", "explanation": "In the context of accounting, purchases refer to goods bought for resale only. This is because in accounting, especially in businesses that deal with selling of goods, purchases are considered as the goods that are bought with the intention of reselling them to customers. The other options are incorrect because purchases do not only refer to goods bought and paid for only, goods bought on credit only, or goods bought to be used in the firm only.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>14", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Which of the following items is a  Current Liability ?", "images": [], "options": {"A": "Stock of raw materials", "B": "Cash in hand", "C": "Bills payable", "D": "Cash at bank"}, "answer": "C", "explanation": "A current liability is a debt that a company must pay within one year from the date of the financial statement. Bills payable is a current liability because it represents the amount that a company owes to its creditors and is expected to pay within a short-term period. The other options such as stock of raw materials, cash in hand, and cash at bank are not current liabilities. They are considered as assets because they provide future economic benefits to the company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>15", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "The balance sheet is prepared to reveal", "images": [], "options": {"A": "the result of the operations for the period under review", "B": "the financial position of the business", "C": "the arithmetical accuracy of the ledger accounts", "D": "the accruals and payments"}, "answer": "B", "explanation": "The balance sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time, and provides a basis for computing rates of return and evaluating its capital structure. It is a financial snapshot of the firm's financial position at an instance in time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>16", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "The excess of cost of goods sold over net sales is", "images": [], "options": {"A": "gross profit", "B": "gross loss", "C": "net profit", "D": "net loss"}, "answer": "B", "explanation": "The excess of cost of goods sold over net sales is referred to as gross loss. Gross profit is when net sales exceed the cost of goods sold. Net profit or net loss is determined after all expenses, including those related to the cost of goods sold, are subtracted from revenue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>17", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question    ₦Rent prepaid 1/01/2014600Rent paid 31/12/20143,200Rent prepaid 31/12/2014400    Rent for 2014 chargeable to the profit and loss account is", "images": [], "options": {"A": "₦4,000", "B": "₦3,400", "C": "₦3,000", "D": "₦2,800"}, "answer": "B", "explanation": "The rent for 2014 chargeable to the profit and loss account is calculated by adding the rent paid during the year to the rent prepaid at the beginning of the year and then subtracting the rent prepaid at the end of the year. This gives us ₦3,200 + ₦600 - ₦400 = ₦3,400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>18", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer this question    ₦Rent prepaid 1/01/2014600Rent paid 31/12/20143,200Rent prepaid 31/12/2014400  The balance sheet as at 31st December, 2014 will show", "images": [], "options": {"A": "current asset of ₦600", "B": "current asset of ₦400", "C": "current liability of ₦400", "D": "current liability of ₦600"}, "answer": "B", "explanation": "The balance sheet as at 31st December, 2014 will show the amount of rent that has been prepaid and is yet to be used. This is the rent prepaid at the end of the year, which is ₦400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>19", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Which of the following would result from an increase in the provision for doubtful debts?", "images": [], "options": {"A": "A decrease in gross profit", "B": "A decrease in net profit", "C": "An increase in gross profit", "D": "An increase in net profit"}, "answer": "B", "explanation": "An increase in the provision for doubtful debts would result in a decrease in net profit. This is because the provision for doubtful debts is an expense that is deducted from the gross profit to arrive at the net profit. Therefore, an increase in this provision would reduce the net profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>20", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Use the following information to answer this question  LeAcquisition cost of computer80,000Installation cost20,000Estimated residual value4,000  5 years    The depreciable value of computers is", "images": [], "options": {"A": "Le 80,000", "B": "Le 96,000", "C": "Le 100,000", "D": "Le 104,000"}, "answer": "B", "explanation": "The depreciable value of an asset is calculated by subtracting the estimated residual value from the total acquisition cost (including installation cost). In this case, the acquisition cost of the computer is Le 80,000 and the installation cost is Le 20,000, giving a total cost of Le 100,000. Subtracting the estimated residual value of Le 4,000 gives a depreciable value of Le 96,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>21", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Use the following information to answer this question  LeAcquisition cost of computer80,000Installation cost20,000Estimated residual value4,000  5 years  The total costs of the computers is", "images": [], "options": {"A": "Le 80,000", "B": "Le 96,000", "C": "Le 100,000", "D": "Le 104,000"}, "answer": "C", "explanation": "The total cost of the computers is the sum of the acquisition cost and the installation cost. The residual value is not part of the total cost but rather the value of the asset at the end of its useful life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>22", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following expenses constitutes prime cost?  I. Direct labour cost  II. Factory overheads  III. Hiring of machine for production  IV. Warehouse rent", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I, II and III only", "D": "I, II and IV only"}, "answer": "B", "explanation": "Prime cost is the total cost of direct materials and direct labor used in production. It does not include indirect costs such as factory overheads and warehouse rent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>23", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Partly manufactured goods are treated in the balance sheet of a manufacturing company as", "images": [], "options": {"A": "current assets", "B": "fixed assets", "C": "current liabilities", "D": "long term liabilities"}, "answer": "A", "explanation": "Partly manufactured goods, also known as work-in-progress, are considered as current assets in the balance sheet of a manufacturing company. This is because they represent goods that are in the process of being manufactured and will be sold in the near future, thus they are part of the company's short-term resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>24", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this question  DCash purchase29,641Creditors 1/1/142,473Creditors 31/12/143,117Cash paid to creditors127,345Discount received4,211    The credit purchases is", "images": [], "options": {"A": "D161,841", "B": "D156,986", "C": "D134,673", "D": "D132,200"}, "answer": "D", "explanation": "Cash paid to creditors 127345 balance b/f 2473Discount received ( missing figure)  4211  Purchases  132200 Balance c/d  3117  134723  134723", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>25", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer this question  DCash purchase29,641Creditors 1/1/142,473Creditors 31/12/143,117Cash paid to creditors127,345Discount received4,211  The total purchases is", "images": [], "options": {"A": "D161,841", "B": "D156,986", "C": "D134,673", "D": "D132,200"}, "answer": "A", "explanation": "Total purchases = cash purchases + credit purchases                        = 29641 + 132,200  = D161,841", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>26", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Offei, a petty trader, sold goods for GH⊄36,240. The gross profit being 33 1/3 % on cost. What was the cost price?", "images": [], "options": {"A": "GH⊄45,300", "B": "GH⊄28,992", "C": "GH⊄27,180", "D": "GH⊄24,160"}, "answer": "C", "explanation": "The cost price can be calculated using the formula: Selling price / (1 + Gross profit percentage/100). Substituting the given values, we get: 36,240 / (1 + 33.33/100) = 27,180. The correct option is GH⊄27,180.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>27", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Which of the following is a credit item in an Income and Expenditure account?", "images": [], "options": {"A": "Electricity", "B": "Donations", "C": "Stationery", "D": "Bar suppliers"}, "answer": "B", "explanation": "In an Income and Expenditure account, a credit item is an income or gain for the organization. Donations are considered as income because they increase the financial resources of the organization. Therefore, 'Donations' is a credit item in an Income and Expenditure account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>28", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Purchases of fixtures and fittings by a club is recorded in the", "images": [], "options": {"A": "Receipts and Payments Accounts only", "B": "Income and Expenditure only", "C": "Receipts and Payments Account and Balance sheet", "D": "Income and Expenditure Account and Balance sheet"}, "answer": "C", "explanation": "Purchases of fixtures and fittings by a club are capital expenditure and are not recorded in the Income and Expenditure account. They are recorded in the Receipts and Payments Account, which is a summary of all cash transactions, and also shown in the Balance Sheet as an asset. Therefore, 'Receipts and Payments Account and Balance sheet' is the correct option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>29", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which states that the affairs of a business is to be treated as being separate from the private", "images": [], "options": {"A": "realisation concept", "B": "business entity concept", "C": "cost concept", "D": "dual aspect concept"}, "answer": "B", "explanation": "The business entity concept is the concept that states that the affairs of a business are to be treated as being separate from the private affairs of the business owner. This concept is fundamental in accounting as it allows for the separation of personal and business transactions. This is important for accurate and reliable financial reporting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>30", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Where fixed capitals are maintained in a partnership, share of profits are", "images": [], "options": {"A": "credited to partners capital accounts", "B": "credited to partners current accounts", "C": "debited to partners capital accounts", "D": "debited to partners currents accounts"}, "answer": "B", "explanation": "In a partnership where fixed capitals are maintained, the share of profits are credited to the partners' current accounts. This is because the capital accounts remain unchanged unless additional capital is introduced or part of the capital is withdrawn. Profits or losses are therefore recorded in the partners' current accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>31", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "In the absence of a partnership agreement, additional capital contributions by partners attract interest of", "images": [], "options": {"A": "5%", "B": "10%", "C": "12%", "D": "15%"}, "answer": "A", "explanation": "In the absence of a partnership agreement, the Partnership Act 1890 applies. According to this Act, no interest is allowed on capital. Therefore, additional capital contributions by partners do not attract any interest. However, if the partners agree to pay interest, it is usually at a rate of 5% per annum. This is not a legal requirement but a common practice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>32", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "In preparing partnership accounts, interest on drawings is debited to current accounts and credited to", "images": [], "options": {"A": "capital account", "B": "appropriation account", "C": "drawings account", "D": "profit and loss account"}, "answer": "B", "explanation": "In preparing partnership accounts, interest on drawings is debited to the current accounts of the partners and credited to the appropriation account. The appropriation account is used to record the distribution of profits among the partners. Interest on drawings is considered as an expense for the business and income for the partners, hence it is debited to the partners' current accounts and credited to the appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>33", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When allotments have been fully paid, subscribers are referred to as", "images": [], "options": {"A": "allotters", "B": "applicants", "C": "non-members", "D": "shareholders"}, "answer": "D", "explanation": "When allotments have been fully paid, subscribers are referred to as shareholders. This is because, in the context of a company, a shareholder is an individual or institution that legally owns one or more shares of the share capital of a public or private corporation. Shareholders may be referred to as members of a corporation. Legally, a person is not a shareholder in a corporation until their name and other details are entered in the corporation's register of shareholders or members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>34", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Use the following information to answer this question  Oruma Limited issued 300,000 ordinary shares at ₦1.00 each. Applications were received for 200,000 shares and all those who applied, paid in full.    The subscribed share capital is", "images": [], "options": {"A": "₦300,000", "B": "₦250,000", "C": "₦200,000", "D": "₦150,000"}, "answer": "C", "explanation": "The subscribed share capital is the total value of shares that shareholders have agreed to buy and pay for. In this case, applications were received for 200,000 shares and all those who applied, paid in full. Therefore, the subscribed share capital is 200,000 shares * ₦1.00 each = ₦200,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>35", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Use the following information to answer this question  Oruma Limited issued 300,000 ordinary shares at ₦1.00 each. Applications were received for 200,000 shares and all those who applied, paid in full.  The unsubscribed share capital is", "images": [], "options": {"A": "₦300,000", "B": "₦200,000", "C": "₦150,000", "D": "₦100,000"}, "answer": "D", "explanation": "The unsubscribed share capital is the difference between the total shares issued and the shares for which applications were received. In this case, Oruma Limited issued 300,000 shares but received applications for only 200,000 shares. Therefore, the unsubscribed share capital is 300,000 - 200,000 = 100,000. Hence, the correct option is ₦100,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>36", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Use the following information to answer this question  Oruma Limited issued 300,000 ordinary shares at ₦1.00 each. Applications were received for 200,000 shares and all those who applied, paid in full.  The Authorised share capital is", "images": [], "options": {"A": "₦300,000", "B": "₦250,000", "C": "₦200,000", "D": "₦150,000"}, "answer": "A", "explanation": "The Authorised share capital is the maximum amount of share capital that the company is authorized by its constitution to issue to shareholders. In this case, Oruma Limited is authorized to issue 300,000 shares at ₦1.00 each. Therefore, the Authorised share capital is 300,000 * ₦1.00 = ₦300,000. Hence, the correct option is ₦300,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>37", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The Branch Current Account records", "images": [], "options": {"A": "head office transactions with the branch", "B": "branch transactions with the head office", "C": "goods sent to branch at selling price", "D": "cash received from branch as sale"}, "answer": "A", "explanation": "The Branch Current Account records head office transactions with the branch. This account is used to record all transactions between the head office and its branch. It includes all goods sent from the head office to the branch, cash remittances from the branch to the head office, and any expenses incurred by the head office on behalf of the branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>38", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The entries for credit sales at branch where the Head Office keeps all records are: Debit", "images": [], "options": {"A": "Branch Stock Account; Credit Branch Debtors Account", "B": "Branch Debtors Account, Credit Branch stock Account", "C": "Branch Debtors Account, Credit Branch Adjustment Account", "D": "Branch Adjustment Account, Credit Branch Debtors Account"}, "answer": "B", "explanation": "The entries for credit sales at branch where the Head Office keeps all records are: Debit Branch Debtors Account, Credit Branch stock Account. This is because when a credit sale is made at the branch, the branch debtors account (representing the amount owed by customers) is debited, indicating an increase in assets. Simultaneously, the branch stock account (representing the inventory at the branch) is credited, indicating a decrease in assets. This reflects the fact that goods have left the branch's stock and have been sold on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>39", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The cost of goods returned by branch to head office is debited to", "images": [], "options": {"A": "Branch stock Adjustment Account", "B": "Goods sent to Branch Account", "C": "Branch stock Account", "D": "Branch Profit and Loss Account"}, "answer": "B", "explanation": "The cost of good returned by branch to the head office is debited to goods sent to branch account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>40", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "Which of the following is a source of local government  revenue?", "images": [], "options": {"A": "Excise duties", "B": "Market dues", "C": "Import duties", "D": "Loans and grants"}, "answer": "B", "explanation": "Market dues are a source of local government revenue. Local governments often charge fees or dues for the use of markets and other public facilities within their jurisdiction. These fees are used to fund local government operations and provide services to the community. Excise duties and import duties are typically collected by the federal or national government, not local governments. Loans and grants can be a source of revenue, but they are not a primary source and are typically used for specific projects or initiatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>41", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The transfers of money from one sub-head to another in the public sector is", "images": [], "options": {"A": "budgeting", "B": "allocation", "C": "virement", "D": "vote"}, "answer": "C", "explanation": "The transfer of money from one sub-head to another in the public sector is referred to as virement. Virement is a process that allows for the transfer of funds from one budgetary account to another. It is often used in public finance management to ensure flexibility and efficiency in the use of budgeted funds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>42", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "CASH BOOK : THREE COLUMN CASH BOOK", "question": "The total of the discounts received column in the three column cash book is", "images": [], "options": {"A": "debited to Discounts Received Account", "B": "credited to Discounts Received Account", "C": "debited to Discounts Allowed Account", "D": "credited to Discounts Allowed Account"}, "answer": "B", "explanation": "The total of the discounts received column in the three column cash book is credited to the Discounts Received Account. In accounting, when a discount is received, it reduces the amount of cash that is paid to a supplier, hence it is a gain or income to the business. Therefore, it is credited in the Discounts Received Account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>43", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Which of the following expenses is apportioned between departments based on sales?", "images": [], "options": {"A": "Discount received", "B": "Electricity", "C": "Carriage inwards", "D": "Carriage outwards"}, "answer": "D", "explanation": "Carriage outward is the cost of transporting goods from the firm to the point of sales therefore, carriage outward is apportioned between the departments based on sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>44", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "In the purchase of a business, a buyer has paid more than the value of the net assets of the business. The excess payment is referred to as", "images": [], "options": {"A": "bonus", "B": "goodwill", "C": "net profit", "D": "premium"}, "answer": "B", "explanation": "In the purchase of a business, if a buyer has paid more than the value of the net assets of the business, the excess payment is referred to as 'goodwill'. Goodwill is an intangible asset that represents the value of a company's brand name, solid customer base, good customer relations, good employee relations, and any patents or proprietary technology. The other options such as 'bonus', 'net profit' and 'premium' are not correct in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>45", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "Assets which are readily convertible into cash are termed as", "images": [], "options": {"A": "liquid assets", "B": "fixed assets", "C": "intangible assets", "D": "tangible assets"}, "answer": "A", "explanation": "Assets which can be readily converted into cash are termed as liquid assets. This is because they can be easily and quickly converted into cash without losing their value. Examples of liquid assets include cash, checking accounts, savings accounts, money market accounts, and government bonds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>46", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "A loan to a company under the company's seal is", "images": [], "options": {"A": "fixed deposit", "B": "mortgage", "C": "bond", "D": "debenture"}, "answer": "D", "explanation": "A loan to a company under the company's seal is a debenture. A debenture is a type of debt instrument that is not secured by physical assets or collateral. Instead, it is backed only by the general creditworthiness and reputation of the issuer. The 'company's seal' refers to the official seal of the company, which when affixed to a document, signifies that the document is being executed by the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>47", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Debts that a firm is unable to recover are debited to Bad Debts Account and credited to", "images": [], "options": {"A": "Suppliers Account", "B": "Sales Account", "C": "Customers Account", "D": "Cash Account"}, "answer": "C", "explanation": "When a firm is unable to recover a debt, it is considered a bad debt. This bad debt is debited to the Bad Debts Account and credited to the Customers Account. This is because the customer is the one who owes the debt to the firm, and when it is determined that the debt cannot be recovered, the amount is removed from the customer's account (credited) and added to the bad debts account (debited).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>48", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "When a fixed asset is disposed off, the accounting entries to write off the asset are Debit", "images": [], "options": {"A": "Profit and Loss Account, Credit Asset Disposal Account", "B": "Asset Disposal Account, Credit Profit and Loss Account", "C": "Asset Disposal Account, Credit Asset Account", "D": "Profit and Loss Account, Credit Provision for Depreciation Account"}, "answer": "C", "explanation": "When a fixed asset is disposed off, the accounting entries to write off the asset are Debit Asset Disposal Account, Credit Asset Account. This is because the asset is being removed from the company's books, so its value is credited from the Asset Account. The Asset Disposal Account is debited to record the disposal of the asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2016>49", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The financial statement which is an expression of the accounting equation is the", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Balance Sheet", "D": "Statement of Cash Flow"}, "answer": "C", "explanation": "The Balance Sheet is an expression of the accounting equation. The accounting equation is Assets = Liabilities + Equity. This equation is the foundation of double-entry bookkeeping and it shows the relationship between what a company owns (assets), what it owes (liabilities), and the interest of the owners (equity). The Balance Sheet is a financial statement that reports a company's assets, liabilities and shareholders' equity at a specific point in time, and provides a basis for computing rates of return and evaluating its capital structure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2016>50", "subject": "Accounts", "year": "2016", "type": "Objective", "topic": "SUSPENSE ACCOUNT : ERRORS THAT WILL AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Which of the following errors will affect the agreement of the trial balance?", "images": [], "options": {"A": "Error of original entry", "B": "Error of commission", "C": "Error of transposition", "D": "Error of omission"}, "answer": "C", "explanation": "Transposition error occurs when a correct figure is entered in one account and the transpose is entered in the other account e.g sales of goods to dayo ₦15 was entered correctly in sales account but entered in dayo's account as ₦51. Other errors that affect trial balance includes: One sided omission, partial reversal of entry, sliding errors. e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>1", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Customers use the financial statement of a company to", "images": [], "options": {"A": "assess the financial position of the business", "B": "regulate their activities", "C": "ascertain the taxable profit of the business", "D": "be sure of the extent of job security"}, "answer": "A", "explanation": "Customers use the financial statement of a company to assess the financial position of the business. Financial statements provide an overview of a business's profitability and financial condition in both short and long term. They are a tool for the customers to evaluate the company's financial strength, performance and changes in financial position that can affect its future performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>2", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The claim on the assets of a business by outsiders is", "images": [], "options": {"A": "capital", "B": "liabilities", "C": "reserves", "D": "provisions"}, "answer": "B", "explanation": "The claim on the assets of a business by outsiders is referred to as liabilities. Liabilities are obligations of the business that it is required to pay in the future. This includes loans, accounts payable, mortgages, deferred revenues, and accrued expenses. Outsiders in this context refer to entities other than the business owners, such as lenders, suppliers etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>3", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A document sent by a bank to its current customers detailing their transactions over a given period is", "images": [], "options": {"A": "bank reconciliation statement", "B": "bank statement", "C": "credit transfer", "D": "banker's advise"}, "answer": "B", "explanation": "A bank statement is a document that is sent by a bank to its customers detailing all the transactions that have taken place over a given period. It includes all deposits, withdrawals, and transactions made through the account. A bank reconciliation statement, on the other hand, is a statement prepared by the account holder to reconcile the balance of cash according to the bank statement with the balance of cash according to their own records. Credit transfer and banker's advise are types of transactions, not documents sent by the bank to its customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>4", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Which of the following items will not be centred in the adjustment cash book?", "images": [], "options": {"A": "Dishonoured cheques", "B": "Direct payment to bank", "C": "Uncredited cheques", "D": "Standing order payment"}, "answer": "C", "explanation": "Uncredited cheques is an item which is not entered in the adjusted cashbook . The cash book will be adjusted before the bank reconciliation statement is prepared.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>5", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "If a petty cashier has a cash float of Le 39,000 and Le 37,500 is spend, he will be reimbursed with", "images": [], "options": {"A": "Le 40,500", "B": "Le 39,000", "C": "Le 37, 500", "D": "Le 1,500"}, "answer": "C", "explanation": "The petty cashier starts with a cash float of Le 39,000. After spending Le 37,500, the remaining cash is Le 39,000 - Le 37,500 = Le 1,500. To maintain the cash float at Le 37,500, the cashier needs to be reimbursed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>6", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A suspense account is used in the", "images": [], "options": {"A": "prevention of errors", "B": "correction of errors", "C": "detection of errors", "D": "creation of errors"}, "answer": "C", "explanation": "A suspense account is a temporary resting place for an entry that will end up somewhere else once its final destination is determined. It is used to record differences in te trial balance temporarily until errors are detected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>7", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A credit purchase of GH⊄200 from P. Osae was posted to the account of P. Osei. This is an error of", "images": [], "options": {"A": "principle", "B": "commission", "C": "omission", "D": "original entry"}, "answer": "B", "explanation": "This is an error of commission. An error of commission occurs when an entry is made at the right amount, and in the correct side of the ledger, but to the wrong person's account. In this case, the purchase was correctly recorded as a credit, but it was posted to the account of P. Osei instead of P. Osae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>8", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discount allowed on goods invoiced at GH⊄100,000 was calculated at the rate of 20% instead of 10%. The error is corrected by debiting", "images": [], "options": {"A": "customer account with GH⊄20,000; crediting discount allowed with GH⊄20,000", "B": "discount allowed with with GH⊄10,000; crediting customer's account with GH⊄10,000", "C": "customer's account with GH⊄10,000; crediting discount allowed with GH⊄10,000", "D": "discount allowed with GH⊄20,000; crediting cash with GH⊄10,000"}, "answer": "C", "explanation": "The error is corrected by debiting the customer's account with GH⊄10,000 and crediting discount allowed with GH⊄10,000. This is because the discount allowed was overstated by GH⊄10,000 (20% of GH⊄100,000 instead of 10%). Therefore, to correct the error, the overstated amount should be removed from the customer's account (debited) and the discount allowed account should be reduced (credited) by the same amount.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2017>9", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The balance sheet equation shows", "images": [], "options": {"A": "current assets minus current liabilities", "B": "the difference between fixed assets and current liabilities", "C": "asset and sources of financing them", "D": "sources of funding owner's equity"}, "answer": "C", "explanation": "The balance sheet equation, also known as the accounting equation, shows the relationship between a company's assets, liabilities, and equity. It is expressed as Assets = Liabilities + Equity. This equation shows that a company's assets are financed by its liabilities (what it owes) and its equity (the owner's investment in the business). Therefore, option 3 is correct as it states 'asset and sources of financing them'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>10", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The effect on profit when the closing stock is understated is", "images": [], "options": {"A": "increase in profit", "B": "decrease in profit", "C": "no change in profit", "D": "appropriation of profit"}, "answer": "B", "explanation": "Closing stock is the amount of inventory that a business still has on hand at the end of a financial period. If the closing stock is understated, it means that the cost of goods sold (COGS) is overstated. Since profit is calculated as Sales - COGS, an overstated COGS will result in a lower profit. Therefore, option 2 'decrease in profit' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>11", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "Which of the following describe trial balance?", "images": [], "options": {"A": "It shows all the entries in the books", "B": "It reveals the financial position of a business", "C": "It is a list of accounting balances on the books", "D": "It is a special account"}, "answer": "C", "explanation": "A trial balance is a list of all the General ledger accounts (both revenue and capital) contained in the ledger of a business. This list will contain the name of the nominal ledger account and the value of that nominal ledger account. The value of the nominal ledger will hold either a debit balance value or a credit balance value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>12", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The accounts of Jute Enterprise in the books of a supplier, will be a", "images": [], "options": {"A": "nominal account in the general ledger", "B": "personal account in the sale ledger", "C": "personal account in the purchases ledger", "D": "real account in the general ledger"}, "answer": "B", "explanation": "The accounts of Jute Enterprise in the books of a supplier will be a personal account in the sales ledger. This is because the sales ledger is the subsidiary ledger that records all the details of sales on credit to customers or debtors. The personal account refers to the account of the individual or firm to whom the goods have been sold on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>13", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "Which of the following accounts are found in the nominal ledger?     I. Advertising   II. Motor repairs   III. Additions to motor vehicle", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III only"}, "answer": "A", "explanation": "The nominal ledger, also known as the general ledger, contains all the accounts for recording transactions relating to a company's assets, liabilities, owners' equity, revenue, and expenses. In this case, Advertising and Motor repairs are expenses, hence they are found in the nominal ledger. Additions to motor vehicle is a capital expenditure, not an expense, hence it is not found in the nominal ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>14", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Accounts payable is classified as a", "images": [], "options": {"A": "prepayment", "B": "provision", "C": "current liability", "D": "long-term liability"}, "answer": "C", "explanation": "Accounts payable is money owed by a business to its suppliers shown as a liability on a company's balance sheet. It is distinct from notes payable liabilities, which are debts created by formal legal instrument documents. Therefore, it is classified as a current liability, not a prepayment, provision, or long-term liability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>15", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept that provides that accounting statements should not be influenced personal opinion is", "images": [], "options": {"A": "materiality", "B": "periodicity", "C": "objectivity", "D": "conservatism"}, "answer": "C", "explanation": "The objectivity principle in accounting states that the financial statements a company produces must be based on solid evidence. This means that the accounting data that is reported is not influenced by personal feelings or biases of those preparing the statements. It ensures that the accounting information is verifiable and free from personal bias.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>16", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The prudence concept demands that", "images": [], "options": {"A": "care is excercised in recognition of profit", "B": "loss should not be anticipated", "C": "profit should be reported", "D": "income should be recognized and disclosed"}, "answer": "A", "explanation": "The prudence concept in accounting, also known as the conservatism principle, requires that expenses and liabilities be recognized as soon as possible, but revenues only when they are assured or realized. This means that care should be exercised in the recognition of profit to avoid overstatement of financial position and performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>17", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Carriage outward expenses of a business are treated in the", "images": [], "options": {"A": "Balance sheet", "B": "Income Surplus Account", "C": "Profit and Loss Account", "D": "Trading Account"}, "answer": "C", "explanation": "Carriage outward refers to the costs of transportation of goods sold to the customer's place. These costs are not included in the cost of goods sold, but are treated as an expense and are recorded in the Profit and Loss Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>18", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The cost of transportating purchased goods to the warehouse is charged to the", "images": [], "options": {"A": "Profit and Loss Account", "B": "Appropriation Account", "C": "Tradng Account", "D": "Income Surplus"}, "answer": "C", "explanation": "The cost of transporting purchased goods to the warehouse is considered as part of the cost of goods sold and is charged to the Trading Account. This is because it is directly related to the purchase of goods for resale, and is therefore considered a direct expense.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>19", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "An organization purchased an equipment for GH⊄112,000. It is expected to be used for 6 years then sold for GH⊄16,000. What is the annual amount of depreciation, if the straight-line method is used?", "images": [], "options": {"A": "GH⊄16,000", "B": "GH⊄15,000", "C": "GH⊄12,800", "D": "GH⊄12,000"}, "answer": "A", "explanation": "Using straight line method:  RecallDepreciation=Asset cost - Residual valueYears of useful life    ∴AnnualDepreciation=GH⊄112,000 - GH⊄16,0006years    =966=GH⊄16,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>20", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer the question.   DSales ledger balance 01/06/12 9 000   30/06/12 30 000 Total for the month: Cash sales  10 000 Returns inwards  3 000 Cheque dishonoured  4 000    The credit sale of the month is", "images": [], "options": {"A": "D36,000", "B": "D31,000", "C": "D20,000", "D": "D10,000"}, "answer": "C", "explanation": "Sales ledger control account  #\t\t#\tBal b/f\t9000\tReturns inwards\t3000\tDishonoured cheque\t4000\tBal c/d\t30000\tCredit sales ( missing figure)\t20000\t\t\t\t33000\t\t33000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2017>21", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "DSales ledger balance 01/06/12 9 000   30/06/12 30 000 Total for the month: Cash sales  10 000 Returns inwards  3 000 Cheque dishonoured  4 000  The total sale for the month is", "images": [], "options": {"A": "D36,000", "B": "D31,000", "C": "D30,000", "D": "D20,000"}, "answer": "C", "explanation": "Total sales for the month = Credit sales + Cash sales  = 20,000 + 10,000  =D 30,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>22", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The excess of the market value of goods produced over the cost of producing is", "images": [], "options": {"A": "profit on manufacturing", "B": "net profit", "C": "goodwill", "D": "gross profit"}, "answer": "A", "explanation": "Profit on main of production manufacturing is referred to as the excess of the market value of goods over the cost", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>23", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Factory wages form part of", "images": [], "options": {"A": "administration cost", "B": "selling and distribution cost", "C": "overhead cost", "D": "prime cost"}, "answer": "D", "explanation": "Factory wages form part of the prime cost. Prime cost is the total cost of direct materials and direct labor (also known as factory wages) used in producing goods. It does not include indirect costs such as administration cost, selling and distribution cost, or overhead cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>24", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Production cost of a manufacturing firm is made up of", "images": [], "options": {"A": "indirect materials and prime cost", "B": "faactory overheads and prime cost", "C": "direct materials and wages", "D": "factory overheads and direct materials"}, "answer": "B", "explanation": "The production cost of a manufacturing firm is made up of factory overheads and prime cost. Prime cost includes direct materials and direct labor, while factory overheads include indirect costs such as indirect materials, indirect labor, and other indirect expenses related to the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>25", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "In a manufacturing enterprise depreciation of plant is treated in the", "images": [], "options": {"A": "Trading Account", "B": "Profit and Loss Account", "C": "Manufacturing Account", "D": "Appropriation Account"}, "answer": "C", "explanation": "In a manufacturing enterprise, depreciation of plant is treated in the Manufacturing Account. The Manufacturing Account is a part of the final accounts prepared by a manufacturing company. This account is prepared to find out the cost of goods manufactured. It includes direct expenses (like direct material, direct labor, and direct expenses) and indirect expenses (like factory overheads which include depreciation of plant and machinery).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>26", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "The purpose of keeping Sales and Purchases Ledger Control Account is to", "images": [], "options": {"A": "match credit sales and credit purchases", "B": "equate debtors balance to creditors balance", "C": "verify total debtors and total creditors balances", "D": "determine cash sales and cash purchases"}, "answer": "C", "explanation": "The purpose of keeping Sales and Purchases Ledger Control Account is to verify total debtors and total creditors balances. A control account, also known as a total or summary account, is an account in the general ledger for which a corresponding subsidiary ledger has been created. The purpose of the control account is to keep the general ledger free of details, but still have the correct balance for the financial statements. For example, an accounts receivable control account would show the total amount of all outstanding customer invoices, while the accounts receivable subsidiary ledger would contain information about each individual invoice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>27", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Which of the following items will appear in the Total Creditors Account?", "images": [], "options": {"A": "Discount allowed", "B": "Credit sales", "C": "Discount received", "D": "Cash purchases"}, "answer": "C", "explanation": "Discount received is an item that appears on the debit side of the Total Creditors Account ( purchases control account).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>28", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "A disadvantage of single entry system of book-keeping is that", "images": [], "options": {"A": "the profit for the period is reduced", "B": "it is difficult to determine profit for the period", "C": "total sales for the period is reduced", "D": "the owner of the firm withdraws money from the enterprise"}, "answer": "B", "explanation": "A disadvantage of the single entry system of book-keeping is that 'it is difficult to determine profit for the period'. The single entry system records only one aspect of a transaction, either the debit or the credit. This incomplete recording makes it difficult to accurately determine the profit or loss for a given period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>29", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "Which of the following accounts or statement is used to determine credit purchases figure in an Incomplete Records?", "images": [], "options": {"A": "bank Account", "B": "Control Account", "C": "Profit and Loss Account", "D": "Statement of Affairs"}, "answer": "B", "explanation": "The Control Account is used to determine credit purchases figure in an Incomplete Records. In accounting, a control account is a summary-level account in the general ledger. This account contains aggregated total of transactions that are individually stored in subsidiary-level ledger accounts. Control accounts are most commonly used to gather all transactions for similar items, such as all accounts receivable transactions in one account, separate from all accounts payable transactions, which are stored in another account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>30", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "A trader sells goods at an average margin of 20%. His cost of sales for the month amounted to ₦720,000. What is his profit figure?", "images": [], "options": {"A": "₦900,000", "B": "₦864,000", "C": "₦840,000", "D": "₦180,000"}, "answer": "B", "explanation": "Profit = margin x cost of sales  = 20% x 720,000  = 144,000    Therefore, Profit = 720000 + 144,000  = #864,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>31", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Donation to a club are", "images": [], "options": {"A": "credited to the Income and Expenditure Account", "B": "credited to the Receipts and Payments Account", "C": "debited to the Income and Expenditure Account", "D": "debited to Donations Account"}, "answer": "A", "explanation": "Donations to a club are credited to the Income and Expenditure Account. This is because donations are considered as income for the club. The Income and Expenditure Account is a type of Profit and Loss account that reflects the income (credits) and the expenses (debits) during a particular period. Therefore, when a club receives a donation, it increases the club's income, hence it is credited to the Income and Expenditure Account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>32", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "A statement of affairs shows", "images": [], "options": {"A": "receipts and payments", "B": "revenue and expenditure", "C": "financial position", "D": "profit and loss"}, "answer": "C", "explanation": "A statement of affairs shows the financial position of a business. It is a type of balance sheet used in insolvency procedures. It provides a snapshot of the assets, liabilities, and equity of a business at a specific point in time. It does not show receipts and payments, revenue and expenditure, or profit and loss. Therefore, the correct answer is 'financial position'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>33", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "In a not-for-profit making organization, the Receipts and Payments Account is the equivalent of", "images": [], "options": {"A": "Profit and Loss Accounts", "B": "Income and expenditure Accounts", "C": "Cash Book", "D": "Balance Sheet"}, "answer": "C", "explanation": "In a not-for-profit making organization, the Receipts and Payments Account is equivalent to a Cash Book. A Cash Book is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>34", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Where there is no agreement between the partners, the Partnership Act states that", "images": [], "options": {"A": "5% interest is to be paid on capital", "B": "profit and losses are to be shared in proportion to their capital", "C": "50% interest is to be charged on drawings", "D": "no salary is to be paid to parners"}, "answer": "D", "explanation": "According to the Partnership Act, in the absence of an agreement between the partners, no salary is to be paid to partners. This is because, in a partnership, partners are considered as owners and not employees of the firm. They share the profits and losses of the business, and do not receive a salary for their work in the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>35", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Interest on partners drawings are debited in the", "images": [], "options": {"A": "partners current accounts and credited to the appropriation account", "B": "drawings account and credited to the profit and loss account", "C": "profit and loss account and credited to the partners current account", "D": "profit and loss account and credited to the partners drawing account"}, "answer": "A", "explanation": "Interest on partners' drawings is debited in the partners' current accounts and credited to the appropriation account. This is because the interest on drawings is an expense for the partners and hence, it is debited in their current accounts. The appropriation account is credited because it is the account that is used to distribute the profits among the partners and the interest on drawings reduces the amount of profit to be distributed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>36", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO", "question": "Goodwill may be brought into the books when", "images": [], "options": {"A": "no partner retires", "B": "assets are more than liabilities", "C": "profit for the period is high", "D": "a new partner is admitted"}, "answer": "D", "explanation": "Goodwill may be brought into the books when a new partner is admitted. This is because when a new partner is admitted, he/she brings in some amount as capital and also for his/her share of goodwill. The goodwill is then distributed among the old partners in the agreed ratio. This increases the value of the firm's assets and hence, goodwill is recorded in the books.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>37", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Working capital is the excess of", "images": [], "options": {"A": "current assets over fixed assets", "B": "current liabilities over current assets", "C": "fixed assets over current liabilities", "D": "current assets over current liabilities"}, "answer": "D", "explanation": "Working capital is the difference between a company's current assets and current liabilities. It is a measure of a company's operational efficiency and short-term financial health. If a company has positive working capital, it has enough assets to cover its short-term debts. Therefore, the correct answer is 'current assets over current liabilities'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>38", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Share premium is classified in the balance sheet as", "images": [], "options": {"A": "fixed capital", "B": "Capital reserve", "C": "revenue reserve", "D": "short-term capital"}, "answer": "B", "explanation": "Share premium can be classified as a type of capital reserve in a company's balance sheet. It represents the additional amount over the face value that the shareholders were willing to pay for the shares of the company. It is a part of the shareholders' equity and is a non-distributable reserve. Therefore, the correct answer is 'Capital reserve'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>39", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question  ₦Opening stock 2 300Purchases 11 874 Sales 18 600 Closing stock 3 000 Cost of goods sold 11 500    The percentage of gross profit to sales is", "images": [], "options": {"A": "61.82%", "B": "38.17%", "C": "28.49%", "D": "14.25%"}, "answer": "B", "explanation": "Gross profit is calculated as Sales - Cost of Goods Sold.     From the given data, Sales = ₦18,600 and Cost of Goods Sold = ₦11,500.     Therefore, Gross Profit = ₦18,600 - ₦11,500   = ₦7,100.     The percentage of gross profit to sales is calculated as:   (Gross Profit / Sales) x 100   = (₦7,100 / ₦18,600) x 100   = 38.17%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>40", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "₦Opening stock 2 300Purchases 11 874 Sales 18 600 Closing stock 3 000 Cost of goods sold 11 500  What is the rate of stock turnover?", "images": [], "options": {"A": "7 times", "B": "6 times", "C": "5 times", "D": "4 times"}, "answer": "D", "explanation": "Rate of stock turnover:  =Cost of goods soldAverage Stock  Recall:   Cost of goods sold = 11,174     AverageStock=Opening Stock + Closing stock2    AverageStock=2300 + 30002    AverageStock=53002=2650    ∴ Rate of stock Turnover:  =11,1742650=4.21", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>41", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "When allotment of shares is made applicants for shares of company become", "images": [], "options": {"A": "promoters", "B": "creditors", "C": "debtors", "D": "shareholders"}, "answer": "D", "explanation": "When allotment of shares is made, applicants for shares of a company become shareholders. This is because the allotment of shares is the process by which a company allocates new shares to existing shareholders or new investors. Once the shares are allotted, the applicants become shareholders of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>42", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The objective of a departmental accounts is to ascertain the", "images": [], "options": {"A": "number of staff in the department", "B": "departmental performance", "C": "stock held by the departmental", "D": "departmental labour turnover"}, "answer": "B", "explanation": "The objective of departmental accounts is to ascertain the departmental performance. Departmental accounting is a system of accounting where separate accounts are maintained for each department. It allows the business to identify the profitability and performance of each department, which can be useful for decision-making purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>43", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "In departmental accounting, when goods are sent from one department to another for sale, the transaction is treated as", "images": [], "options": {"A": "inter departmental transfer", "B": "inter departmental sales", "C": "intra departmental purchases", "D": "intra departmental sales"}, "answer": "A", "explanation": "In departmental accounting, when goods are sent from one department to another for sale, the transaction is treated as an inter-departmental transfer. This is because the goods are not being sold to an external entity but are being transferred within the same organization from one department to another. The term 'inter-departmental' refers to something occurring between departments, while 'transfer' refers to the movement of goods or resources from one place to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>44", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "A branch that keeps its own records prepares the records of transactions with the head office in the", "images": [], "options": {"A": "Branch Current Account", "B": "Branch Stock Account", "C": "Head Office Current Account", "D": "Profit and Loss Account"}, "answer": "A", "explanation": "A branch that keeps its own records prepares the records of transactions with the head office in the Branch Current Account. This account is used to record all transactions between the branch and the head office. It is a form of inter-branch account that helps in keeping track of the financial transactions between the head office and its branches.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>45", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "The accounting entries when goods are sold on credit at the branch are debit;", "images": [], "options": {"A": "Branch Debtors Account; credit Sales Accounts", "B": "Branch Current Account; credit Sales Accounts", "C": "Branch Debtors Account; credit Head Office Current Account", "D": "Head Office Current Account; credit Sales Account"}, "answer": "A", "explanation": "When goods are sold on credit at the branch, the branch's debtors account is debited because the branch is owed money by the customers who bought the goods on credit. The sales account is credited because the sale increases the company's revenue. This is in line with the double-entry bookkeeping system where every debit has a corresponding credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>46", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : TRANSFER PRICING METHOD", "question": "Which of the following is not a method of charging goods to branch by its head office?", "images": [], "options": {"A": "net realizable value", "B": "Cost price", "C": "Cost plus profit", "D": "Selling price"}, "answer": "A", "explanation": "Net Realizable value is not a method of charging goods to Branch by its Head Office", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>47", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer questions 47 and 48Nzemaman Local Government incurred the following expenditure in the year 2015.     DConstruction of market stalls 120 000 Staff salaries 40 000Purchase of stationery 9 000Sinking of boleholes 200 000Building of classrooms 90 000Maintenance of vehicles 35 000 Purchase of equipment 28 000    Recurrent expenditure for the year is", "images": [], "options": {"A": "D112,000", "B": "D84,000", "C": "D77,000", "D": "D49,000"}, "answer": "B", "explanation": "Recurrent expenditure is the spending on goods and services that are consumed within the current period and which will need to be renewed in subsequent budgets. In this case, the recurrent expenditure includes staff salaries, purchase of stationery, and maintenance of vehicles. Adding these up gives 40,000 + 9,000 + 35,000 = 84,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>48", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Nzemaman Local Government incurred the following expenditure in the year 2015.     DConstruction of market stalls 120 000 Staff salaries 40 000Purchase of stationery 9 000Sinking of boleholes 200 000Building of classrooms 90 000Maintenance of vehicles 35 000 Purchase of equipment 28 000  Capital expenditure for the local government is", "images": [], "options": {"A": "D473,000", "B": "D438,000", "C": "D422,000", "D": "D410,000"}, "answer": "B", "explanation": "Capital expenditure is the spending on goods and services that benefit both the current and future periods. In this case, the capital expenditure includes construction of market stalls, sinking of boreholes, building of classrooms, and purchase of equipment. Adding these up gives 120,000 + 200,000 + 90,000 + 28,000 = 438,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2017>49", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "A reserve is an amount", "images": [], "options": {"A": "set aside from profit for an unknown liability", "B": "of loss from trading activities", "C": "of profit from trading activities", "D": "set aside from profit for specific purpose"}, "answer": "D", "explanation": "A reserve is an amount set aside from profit for a specific purpose. It is a part of profits that a company keeps aside to meet future uncertainties. It is created by debiting the profit and loss account and crediting the reserve account.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2017>50", "subject": "Accounts", "year": "2017", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "An amount set aside to meet expenses whose value is not certain is a", "images": [], "options": {"A": "reverse", "B": "liability", "C": "provision", "D": "prepayment"}, "answer": "C", "explanation": "A provision is an amount set aside to meet expenses whose value is not certain. It is a liability of uncertain timing or amount according to the International Accounting Standards (IAS). It is created to meet a particular loss or liability whose amount cannot be determined with certainty.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>1", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "FINANCIAL SYSTEM : BENEFITS", "question": "Investors in a business are mainly interested in the firm's", "images": [], "options": {"A": "liquidity", "B": "debt", "C": "management", "D": "profitability"}, "answer": "D", "explanation": "Investors are primarily interested in a firm's profitability. This is because profitability indicates the firm's ability to generate earnings relative to its expenses and other relevant costs incurred during a specific period of time. A profitable company can grow and potentially provide a return on investment, which is what investors are looking for.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>2", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "One of the characteristics of useful accounting information is", "images": [], "options": {"A": "profitability", "B": "comparability", "C": "efficiency", "D": "liquidity"}, "answer": "B", "explanation": "One of the characteristics of useful accounting information is comparability. Comparability in accounting refers to the ability to compare the financial statements of a company over different periods. This is important because it allows investors and other stakeholders to track performance, identify trends, and make informed decisions. Profitability, efficiency, and liquidity are outcomes or states of the business that can be evaluated using accounting information, but they are not characteristics of the information itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>3", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "Which of the following items is found on the debit side of a trial balance?", "images": [], "options": {"A": "Provision for doubtful debts", "B": "Discount allowed", "C": "Discount received", "D": "Returns outwards"}, "answer": "B", "explanation": "In accounting, the debit side of a trial balance includes all the business's assets and expenses. Discount allowed is an expense to the business because it represents a reduction in the amount of money received from a customer. Therefore, it is recorded on the debit side of a trial balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>4", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Which of the following transactions is a revenue expenditure?", "images": [], "options": {"A": "Purchase of a plant", "B": "Purchase of a new engine", "C": "Construction of office wall", "D": "Purchase of fuel for vehicle"}, "answer": "D", "explanation": "Revenue expenditure refers to the expenditure which is incurred on day to day conduct of business operations, but which has benefits lasting for a period of less than one year. These are recurring or operational expenses that are necessary for the daily business operations and are written off in the same accounting year in which they are incurred. Purchase of fuel for vehicle is a good example of revenue expenditure as it is a recurring expense and its benefit lasts for a period of less than one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>5", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "Credit notes received are source of documents for", "images": [], "options": {"A": "Returns Inwards Journals", "B": "Return Outwards Journal", "C": "Purchase Journal", "D": "Sales Journal"}, "answer": "B", "explanation": "A credit note is a document sent by a seller to its buyer, or in other words, a vendor to the customer, notifying that a credit has been provided to their account against the goods returned by the buyer. The 'Returns Outwards Journal' is the book of prime entry in which returns outwards (i.e., returns to suppliers) are recorded. The source document for this is the credit note received.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>6", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "A document forwarded to a supplier showing amount due for unsatisfactory goods is", "images": [], "options": {"A": "Debit Note", "B": "Credit Note", "C": "Invoice", "D": "Waybill"}, "answer": "A", "explanation": "A debit note is a document used by a buyer to inform their supplier that they are debiting their account due to an error or discrepancy in the goods or services received. This could be due to unsatisfactory goods or an error in the invoice. The debit note informs the supplier of the amount and the reason for the debit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>7", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The claim of a proprietor of a business entity on its assets is", "images": [], "options": {"A": "liabilities", "B": "capital", "C": "drawings", "D": "funds"}, "answer": "B", "explanation": "The claim of a proprietor of a business entity on its assets is referred to as 'capital'. This is because the capital represents the owner's investment in the business, which is a claim against the assets of the business. Liabilities are what the business owes to others, drawings are the owner's withdrawals for personal use, and funds do not specifically refer to the owner's claim on business assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>8", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The apportionment of cost of a fixed asset to the profit and loss account is termed as", "images": [], "options": {"A": "expense", "B": "depreciation", "C": "loss", "D": "appreciation"}, "answer": "B", "explanation": "The apportionment of cost of a fixed asset to the profit and loss account is termed as 'depreciation'. Depreciation is the systematic allocation of the depreciable amount of an asset over its useful life. It represents the wear and tear of the asset over time. An expense is a cost incurred in the course of business operations, loss is a decrease in economic benefits, and appreciation is an increase in the value of an asset.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>9", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Entries in the purchases journal are transferred to the", "images": [], "options": {"A": "receivable ledger", "B": "payable ledger", "C": "general ledger", "D": "private ledger"}, "answer": "B", "explanation": "Entries in the purchases journal are transferred to the payable ledger. A purchases journal is a special journal used to record all purchases of merchandise on account (credit). These transactions are then posted to the accounts payable ledger which is a subsidiary ledger that records amounts owed to suppliers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>10", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "A reduction in price to encourage prompt payment is", "images": [], "options": {"A": "trade discount", "B": "quantity discount", "C": "cash discount", "D": "seasonal discount"}, "answer": "C", "explanation": "A reduction in price to encourage prompt payment is a cash discount. A cash discount is a deduction allowed by the seller of goods or by the provider of services in order to motivate the customer to pay within a specified time. The seller or provider often refers to this discount as a sales discount, and the buyer sees it as a purchase discount.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>11", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Use the following information to answer the question.     Tei Ltd offered 1,560 units of a magazine at ₦60.00 each. Trade discount is 10% and cash discount is 10% within 30 days and 5% within 60 days.    The amount payable if payment is made on the 40th day is", "images": [], "options": {"A": "₦88,920.", "B": "₦84,240", "C": "₦80,028", "D": "₦72,025"}, "answer": "C", "explanation": "Total invoice = 1560  x 60  = 93600    Trade discount = 10%  = 93600 - (10%  x 93600)  = 84240    Cash discount = 5% ( Since its within 60 days but after 30 days)  = 5%  x 84240  = 4212    Amount payable = 84240 - 4212  = #80028", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>12", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS", "question": "Use the following information to answer the question.     Tei Ltd offered 1,560 units of a magazine at ₦60.00 each. Trade discount is 10% and cash discount is 10% within 30 days and 5% within 60 days.   The cash discount allowed on the 50th days is", "images": [], "options": {"A": "₦9,360", "B": "₦8,424", "C": "₦4680", "D": "₦4,212"}, "answer": "D", "explanation": "Total invoice = 1560  x 60  = 93600    Trade discount = 10%  = 93600 - (10%  x 93600)  = 84240    Cash discount = 5% ( Since its within 60 days but after 30 days)  = 5%  x 84240  = #4212", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>13", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "An amount of Le 2000 received from a customer. Kofi has been credited to another customer, Kofigo's account. This is an error of", "images": [], "options": {"A": "principle", "B": "commission", "C": "original entry", "D": "complete"}, "answer": "B", "explanation": "Error of commission occurs when a correct figure is posted to wrong person account and the accounts involve are the same classes of account e.g sales of goods to tolu was posted to tola's account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>14", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Current assets less current liabilities is", "images": [], "options": {"A": "working capital", "B": "capital employed", "C": "fluctuating capital", "D": "fixed capital"}, "answer": "A", "explanation": "The difference between current assets and current liabilities is known as working capital. It is a measure of a company's operational liquidity and short-term financial health. Current assets are the assets that a company expects to convert into cash within one fiscal year, while current liabilities are the company's debts or obligations that are due within one fiscal year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>15", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "A debit balance of GH⊄ 420 on the purchases Ledger Control Account means that as at that date", "images": [], "options": {"A": "trade creditors have been overpaid by GH⊄ 420", "B": "trade creditors are owed GH⊄ 420", "C": "good returned to trade creditors amounted to GH⊄ 420", "D": "total supplies from trade creditors amounted to GH⊄ 420"}, "answer": "B", "explanation": "A debit balance on the Purchases Ledger Control Account indicates the amount that the business owes to its trade creditors. This is because, in accounting, a debit entry in a liability account like the Purchases Ledger Control Account signifies an increase in the liability. Therefore, a debit balance of GH⊄ 420 means that the business owes its trade creditors GH⊄ 420.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>16", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Sales and Purchases ledgers are used in a business to keep records of", "images": [], "options": {"A": "the owner's capital and cash transactions", "B": "accounts of individual customers and suppliers", "C": "current assets and fixed assets", "D": "current liabilities and long-term liabilities"}, "answer": "B", "explanation": "Sales and Purchases ledgers are used in a business to keep records of accounts of individual customers and suppliers. The Sales Ledger is used to record all the company's sales on credit, and it contains individual accounts for each customer. The Purchases Ledger, on the other hand, is used to record all the company's purchases on credit, and it contains individual accounts for each supplier. Therefore, these ledgers are not used to record the owner's capital, cash transactions, assets, or liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>17", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Which of the following activities will increase profit?", "images": [], "options": {"A": "Depreciation charges", "B": "Reduction in provision for doubtful debts", "C": "Undervalued closing stock", "D": "Returns inwards"}, "answer": "B", "explanation": "Profit increases when expenses decrease or when revenues increase. A reduction in provision for doubtful debts means that the business expects fewer debts to be uncollectible, which reduces expenses and therefore increases profit. Depreciation charges and returns inwards are expenses, so they decrease profit. An undervalued closing stock reduces the value of assets and therefore reduces profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>18", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that implies that a business will operate for an indefinitely long period of time is", "images": [], "options": {"A": "accrual concept", "B": "going concern concept", "C": "business entity concept", "D": "periodicity concept"}, "answer": "B", "explanation": "The going concern concept is the accounting principle that assumes a company will continue its operations indefinitely. It implies that the business will not be forced to halt operations and liquidate its assets in the short term at what may be very low fire-sale prices. The accrual concept is about recording revenues when they are earned and expenses when they are incurred, not when cash is received or paid. The business entity concept states that the transactions of a business are to be kept separate from those of its owners. The periodicity concept states that businesses should report their financial results over a standard time period, which is typically one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>19", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The consistency concept aims at", "images": [], "options": {"A": "ensuring that all expenses are matched against revenue", "B": "reducing cost", "C": "comparability of accounting records", "D": "suppressing profits to be declared"}, "answer": "C", "explanation": "The consistency concept in accounting means that a company should use the same accounting methods and procedures from period to period. This allows for comparability of accounting records over time, making it easier to evaluate the company's financial performance and condition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>20", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which states that revenue is recognized when goods are sold is", "images": [], "options": {"A": "Realisation concept", "B": "Matching concept", "C": "Periodicity concept", "D": "Going concept"}, "answer": "A", "explanation": "The realisation concept in accounting states that revenue should be recognized when goods are sold or services are rendered, regardless of when payment is received. This is because the sale or service has 'realised' income for the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>21", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Cost of goods sold is calculated as", "images": [], "options": {"A": "opening stock + purchases - closing stock", "B": "opening stock + sales - closing stock", "C": "opening stock + purchases + closing stock", "D": "opening stock + sales + closing stock"}, "answer": "A", "explanation": "The cost of goods sold (COGS) is calculated as the cost of the inventory you have at the beginning of the period (opening stock) plus the cost of inventory purchased during that period and then subtracting the cost of the inventory you have at the end of the period (closing stock). Therefore, the correct formula is opening stock + purchases - closing stock.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>22", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The wages of an office cleaner is classified as", "images": [], "options": {"A": "direct labour cost", "B": "direct expenses", "C": "factory overheads", "D": "administrative overhead"}, "answer": "B", "explanation": "Direct expenses are those expenses that have been incurred in full as a direct consequence of making a product or providing a service, or running  a department.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>23", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer questions 23 and 24.     LeSales 120 000 Purchases 100 000 Opening stock 10 000 Closing stock 20 000    The cost of goods sold is", "images": [], "options": {"A": "Le 120,000", "B": "Le 110,000", "C": "Le 90,000", "D": "Le 30,000"}, "answer": "C", "explanation": "The cost of goods sold is calculated as the sum of the opening stock and purchases minus the closing stock. In this case, COGS = Opening stock + Purchases - Closing stock = 10,000 + 100,000 - 20,000 = 90,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>24", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer questions 23 and 24.     LeSales 120 000 Purchases 100 000 Opening stock 10 000 Closing stock 20 000  The gross profit or loss is", "images": [], "options": {"A": "Le 30,000 gross profit", "B": "Le 20,000 gross profit", "C": "Le 10,000 gross loss", "D": "Le 30,000 gross loss"}, "answer": "A", "explanation": "The gross profit is calculated as the difference between the sales and the cost of goods sold. In this case, Gross Profit = Sales - COGS = 120,000 - 90,000 = 30,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>25", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "The amount set aside out of profits to strengthen the financial position of the business is", "images": [], "options": {"A": "provision", "B": "reserve", "C": "depreciation", "D": "surplus"}, "answer": "B", "explanation": "A reserve is an amount that a business sets aside from its profits to strengthen its financial position. This could be used for various purposes such as to cover future liabilities, losses or expenses. The concept of reserve is different from provision, which is an amount that you put aside in your accounts to cover a future liability. Depreciation is the decrease in the value of an asset over time due to factors such as wear and tear, while surplus refers to the amount by which the income of a business exceeds its costs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>26", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION", "question": "A fall in value of a fixed asset due to technological changes is described as", "images": [], "options": {"A": "superfluity", "B": "wear and tear", "C": "obsolescence", "D": "depletion"}, "answer": "C", "explanation": "Obsolescence is the loss in value of a fixed asset due to technological changes. This happens when a newer technology makes the existing one outdated, reducing its value. Superfluity refers to an unnecessary amount or thing that is more than enough. Wear and tear is the ordinary loss of value due to use and passage of time, while depletion refers to the reduction in quantity, content, or availability of a resource as a result of its use or consumption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>27", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "A credit entry is made in the Plant and Machinery Account for the", "images": [], "options": {"A": "purchase of an additional plant and machinery", "B": "sale of plant and machinery", "C": "maintenance of plant and machinery", "D": "appreciation of the plant and machinery"}, "answer": "B", "explanation": "In accounting, a credit entry is made in the Plant and Machinery Account when there is a decrease in the asset. This decrease can be due to the sale of the plant and machinery. Therefore, the correct answer is 'sale of plant and machinery'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>28", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "In a manufacturing account, royalties paid is", "images": [], "options": {"A": "debited to the trading account", "B": "credited to the profit and loss account", "C": "credited to the manufacturing account", "D": "debited to the manufacturing account"}, "answer": "D", "explanation": "In a manufacturing account, royalties paid is an expense incurred in the production process. Therefore, it is debited to the manufacturing account. In accounting, expenses are always debited. Therefore, the correct answer is 'debited to the manufacturing account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>29", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "One of the component of factory overheads is", "images": [], "options": {"A": "raw materials consumed", "B": "manufacturing wages", "C": "carriage inwards", "D": "depreciation of plant and machinery"}, "answer": "D", "explanation": "Factory overheads are the indirect costs incurred during the manufacturing process. These include depreciation of plant and machinery, utilities, rent, and indirect labor. Therefore, the correct answer is 'depreciation of plant and machinery'. Raw materials consumed and manufacturing wages are direct costs, not overheads. Carriage inwards is a cost related to the transportation of raw materials from a supplier, which is also not an overhead cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>30", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "GHcDirect materials used 64000Direct labour 30000Production overheads 22000Work-in-progress at begining 9000Work-in-progress at close 14000    Total cost of production is", "images": [], "options": {"A": "GH⊄ 94,000", "B": "GH⊄ 106,000", "C": "GH⊄ 111,000", "D": "GH⊄ 116,000"}, "answer": "C", "explanation": "The total cost of production is calculated by adding direct materials used, direct labor, and production overheads, and then adjusting for the change in work-in-progress. In this case, the calculation is as follows: 64000 (Direct materials used) + 30000 (Direct labour) + 22000 (Production overheads) + 9000 (Work-in-progress at beginning) - 14000 (Work-in-progress at close) = GH⊄ 111,000. Therefore, the correct answer is 'GH⊄ 111,000'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>31", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "GHcDirect materials used 64000Direct labour 30000Production overheads 22000Work-in-progress at begining 9000Work-in-progress at close 14000  Prime cost of production is", "images": [], "options": {"A": "GH⊄ 64,000", "B": "GH⊄ 94,000", "C": "GH⊄ 111,000", "D": "GH⊄ 116,000"}, "answer": "B", "explanation": "The prime cost of production is the sum of direct materials and direct labor. In this case, it is GHc 64,000 (direct materials) + GHc 30,000 (direct labor) = GHc 94,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>32", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The balance on the sales ledger control account at the end of the accounting yer represents total", "images": [], "options": {"A": "trade debtors at the end of the year", "B": "cash sales for the year", "C": "credit sales for the year", "D": "amount transferred from the sales journal"}, "answer": "A", "explanation": "The balance on the sales ledger control account at the end of the accounting year represents the total trade debtors at the end of the year. This is because the sales ledger control account is a summary of the individual trade debtor accounts, showing the total amount owed by all customers at a particular point in time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>33", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer questions 33 and 34.    01/01/2016 31/12/2016Trade debtors 80 000 100 000Trade creditors 30 000 40 000 Stock 70 000 90 000   Cheques received from tradedebtors in 2016  : D 350 000 Payments made to trade creditors in 2016 : D 220 000    Credit sales for 2016 is", "images": [], "options": {"A": "D 530,000", "B": "D 370,000", "C": "D 350,000", "D": "D 330,000"}, "answer": "B", "explanation": "The credit sales for 2016 can be calculated using the formula: Opening Debtors + Credit Sales - Closing Debtors = Cash received from Debtors. Substituting the given values into the formula, we get Credit Sales = D 350,000 + D 100,000 - D 80,000 = D 370,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>34", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer questions 33 and 34.    01/01/2016 31/12/2016Trade debtors 80 000 100 000Trade creditors 30 000 40 000 Stock 70 000 90 000   Cheques received from tradedebtors in 2016  : D 350 000 Payments made to trade creditors in 2016 : D 220 000   Credit purchases for 2016 is", "images": [], "options": {"A": "D 290,000", "B": "D 230,000", "C": "D 220,000", "D": "D 210,000"}, "answer": "B", "explanation": "The credit purchases for 2016 can be calculated using the formula: Opening Creditors + Credit Purchases - Closing Creditors = Cash paid to Creditors. Substituting the given values into the formula, we get Credit Purchases = D 220,000 + D 40,000 - D 30,000 = D 230,000.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>35", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The excess of assets over liabilities of a not-for-profit making organization is", "images": [], "options": {"A": "surplus", "B": "deficit", "C": "working capital", "D": "accumulated fund"}, "answer": "D", "explanation": "In a not-for-profit organization, the excess of assets over liabilities is referred to as the accumulated fund. This is similar to the concept of equity in a for-profit organization. It represents the net assets of the organization, i.e., the assets that remain after all liabilities have been paid off.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>36", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer questions 36 and 37.   Receipt and Payments: 31st December, 2016     ₦   ₦Cash at bank 460 New equipment 200 Subscriptions 520 Cleaners' wages 540 Donations 500 Stationery 140 Sales of tickets 490 Repairs 110 Entrance fees 670      The surplus for the year is", "images": [], "options": {"A": "₦1,970", "B": "₦1,890", "C": "₦1,650", "D": "₦1,390"}, "answer": "C", "explanation": "Total income = 460 + 520 + 500 + 490 + 670  = 2,640    Total payment = 200 + 540 ++140 + 110  = 990    Surplus = total income - total payment   = 2640 - 990   = ₦1,650", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>37", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer questions 36 and 37.   Receipt and Payments: 31st December, 2016     ₦   ₦Cash at bank 460 New equipment 200 Subscriptions 520 Cleaners' wages 540 Donations 500 Stationery 140 Sales of tickets 490 Repairs 110 Entrance fees 670    The total income received for the yer is", "images": [], "options": {"A": "₦2,640", "B": "₦2,180", "C": "₦1,890", "D": "₦1,690"}, "answer": "A", "explanation": "The total income received for the year is calculated by adding all the income sources. In this case, the income sources are Cash at bank (₦460), Subscriptions (₦520), Donations (₦500), Sales of tickets (₦490), and Entrance fees (₦670). Adding these together gives ₦2,640. Therefore, the correct answer is option 1 (₦2,640).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>38", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "The parties who are paid last in the event of winding-up are", "images": [], "options": {"A": "preference shareholders", "B": "debenture holders", "C": "ordinary shareholders", "D": "trade creditors"}, "answer": "C", "explanation": "In the event of a company's winding-up, the parties who are paid last are the ordinary shareholders. This is because they are the owners of the company and bear the highest risk. The order of payment in the event of winding-up is usually: 1) secured creditors, 2) unsecured creditors (including debenture holders and trade creditors), 3) preference shareholders, and finally 4) ordinary shareholders. Therefore, the correct answer is option 3 (ordinary shareholders).", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>39", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "An event that will not require a change in the profit-sharing ratio of partners in a firm is when", "images": [], "options": {"A": "a partner dies", "B": "a partner retires", "C": "a new partner is admitted", "D": "partners assets value appreciates"}, "answer": "D", "explanation": "The profit-sharing ratio of partners in a firm is not affected by the appreciation of the firm's assets. The profit-sharing ratio is a pre-agreed term between the partners that determines how the firm's profits will be divided among them. It is typically based on their capital contributions, efforts, and other agreed factors, not on the value of the firm's assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>40", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question      ₦Net profit 17 460Capital Account: Taiwo 50 000   - Obi 40 000 Drawings Account: Taiwo12000Obi10000Salary - Obi 1 500 Interest on capital 5% Interest on drawings 4%   Profit sharing ratio is 3 : 2 for Taiwo and Obi respectively.    Taiwo's share of profit is", "images": [], "options": {"A": "₦8,960", "B": "₦7 404", "C": "₦4,936", "D": "₦3,296"}, "answer": "B", "explanation": "Partnership Appropriation Account   ## Interest on capital  2500Net profit 17460Taiwo ( 5/10  x 50000) 2500  Interest on drawings: Obi ( 5/10  x 40000) 2000 Taiwo: (4/10  x 12000) 480Salary: Obi 1500 Obi ( 4/10  x 10000) 400 Share of profit:( 12340)Taiwo (3/5  x 12340)7404Obi  (2/4  x 12340)  4936  18340 18340    Share of profit = ( 17, 460 + 480 + 400) - ( 2,500 + 2,000 + 1,500)  = 12,340  Therefore, Taiwo's share of profit  = #7,404", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>41", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question      ₦Net profit 17 460Capital Account: Taiwo 50 000   - Obi 40 000 Drawings Account: Taiwo12000Obi10000Salary - Obi 1 500 Interest on capital 5% Interest on drawings 4%   Profit sharing ratio is 3 : 2 for Taiwo and Obi respectively.   Obi's share of profit is", "images": [], "options": {"A": "₦8,960", "B": "₦7,404", "C": "₦4,936", "D": "₦3,296"}, "answer": "C", "explanation": "Partnership Appropriation Account   ## Interest on capital  2500Net profit 17460Taiwo ( 5/10  x 50000) 2500  Interest on drawings: Obi ( 5/10  x 40000) 2000 Taiwo: (4/10  x 12000) 480Salary: Obi 1500 Obi ( 4/10  x 10000) 400 Share of profit:( 12340)Taiwo (3/5  x 12340)7404Obi  (2/4  x 12340)  4936  18340 18340    Obi's share of profit = #4,936", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>42", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS", "question": "The accounting entries for cash realized from the sale of assets on dissolution of partnership is debit", "images": [], "options": {"A": "Cash Account; credit Partners Capital Account", "B": "Asset Account; credit Cash Account", "C": "Cash Account; Realisation Account", "D": "Realisation Account; credit Cash"}, "answer": "C", "explanation": "When assets are sold for cash during the dissolution of a partnership, the cash account is debited (increased) because the business is receiving cash. The Realisation Account is credited (decreased) because the asset (which was an element of the Realisation Account) has been converted into cash and is no longer part of the business's assets. Therefore, the correct accounting entry is 'Debit Cash Account; Credit Realisation Account'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>43", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The process of distributing shares to successful applicants is", "images": [], "options": {"A": "allocation", "B": "apportionment", "C": "allotment", "D": "application"}, "answer": "C", "explanation": "The process of distributing shares to successful applicants is known as allotment. Allotment is the process by which a company allocates its securities to the successful applicants. The term 'allocation' refers to the process of assigning resources for specific tasks or purposes, while 'apportionment' refers to the process of dividing and distributing something in proportion or according to a plan. 'Application' refers to the process of making a formal request, in this case, for shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>44", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Interim dividend paid in the year is", "images": [], "options": {"A": "debited to the Profit and Loss Account", "B": "debited to the Income Surplus Account", "C": "credited to the profit and Loss Account", "D": "credited to the Income Surplus Account"}, "answer": "A", "explanation": "Interim dividend paid in the year is debited to the Profit and Loss Account. An interim dividend is a dividend payment made before a company's Annual General Meeting (AGM) and final financial statements. This dividend is usually debited from the company's profit and loss account because it is an expense to the company. The term 'debit' in accounting means an entry on the left side of the account which either increases assets or expenses or decreases income, liabilities, or owner's equity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2018>45", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "The basis of apportionment of insurance on building in departmental account is", "images": [], "options": {"A": "floor space occupied by the department", "B": "purchase cost of the building", "C": "value of the building", "D": "number of office in the building"}, "answer": "A", "explanation": "The basis of apportionment of insurance on building in departmental account is usually the floor space occupied by the department. This is because the amount of space a department occupies in a building is often directly proportional to the amount of insurance coverage it requires. Therefore, departments that occupy more space would typically require more insurance coverage and thus would be apportioned a larger share of the insurance cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>46", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Under the cost method in Branch Account, branch gross profit is disclosed in the", "images": [], "options": {"A": "Goods sent to Branch Account", "B": "Branch Debtors Account", "C": "Branch Stock Account", "D": "Branch Stock Adjustment Account"}, "answer": "D", "explanation": "Under the cost method in Branch Account, branch gross profit is disclosed in the Branch Stock Adjustment Account. The Branch Stock Adjustment Account is used to adjust the value of stock in the branch to reflect the cost price, and any difference between the opening and closing stock (adjusted for any goods sent to the branch and returns) represents the gross profit or loss for the branch.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>47", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Use the following information to answer questions 47 and 48.  LeOrdinary share capital 70 000Retained earnings 31 142Motor vehicle at cost 21 136 Accumulated depreciation motor vehicle 7 109 Furniture and fittings at cost 1 334Accumulated depreciation- Furniture and fittings 1 007 Stock 32 200 Debtors 49 380 Bank 15 953 Creditors 11 329    Equity holders fund is", "images": [], "options": {"A": "Le 22,480", "B": "Le 111,832", "C": "Le 101 142", "D": "Le 70,000"}, "answer": "C", "explanation": "The equity holders fund is calculated by adding the ordinary share capital and the retained earnings. Therefore, the equity holders fund is Le 70,000 + Le 31,142 = Le 101,142.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>48", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "LeOrdinary share capital 70 000Retained earnings 31 142Motor vehicle at cost 21 136 Accumulated depreciation motor vehicle 7 109 Furniture and fittings at cost 1 334Accumulated depreciation- Furniture and fittings 1 007 Stock 32 200 Debtors 49 380 Bank 15 953 Creditors 11 329  Net book value of fixed assets is", "images": [], "options": {"A": "Le 22,480", "B": "Le 21,136", "C": "Le 14,354", "D": "Le 14,027"}, "answer": "C", "explanation": "To determine the net book value of fixed assets   Cost Accu. Dep Net book valueMotor vehicle at cost 21136 ( 7109) 14027Furniture and fitting at cost 1334 ( 1007)  327 Le 14354    The total net book value of fixed asset is Le 14,354", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2018>49", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The authority to incur expenditure in the public sector is", "images": [], "options": {"A": "warrant", "B": "vote", "C": "budget", "D": "voucher"}, "answer": "A", "explanation": "A warrant is the only authority through which money is expended in government. Government officials cannot withdraw money without authority.All warrants must be issued and signed by the minister of finance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2018>50", "subject": "Accounts", "year": "2018", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Below-the-line item in public sector accounting means such an item is", "images": [], "options": {"A": "not budgeted for in the current fiscal year", "B": "budgeted for in the current fiscal year", "C": "to be carried forward to the next fiscal year", "D": "less than what is budgeted for"}, "answer": "A", "explanation": "A below-the-line item in public sector accounting means such an item is 'not budgeted for in the current fiscal year'. Below-the-line items are those that are not included in the main budget and are usually unexpected or unplanned expenses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>1", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A quality of accounting information is that it should be", "images": [], "options": {"A": "profitable", "B": "verifiable", "C": "appreciable", "D": "depreciable"}, "answer": "B", "explanation": "A quality of accounting information is that it should be verifiable. Verifiability means that different knowledgeable and independent observers could reach consensus, although not necessarily complete agreement, that a particular depiction is a faithful representation. This means that the information should be able to be checked and confirmed by others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>2", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "When the letter \"C\" is written in front of an entry in the folio column of a cash book, it shows a", "images": [], "options": {"A": "double entry.", "B": "cash entry.", "C": "contra entry.", "D": "journal entry."}, "answer": "C", "explanation": "When the letter \"C\" is written in front of an entry in the folio column of a cash book, it shows a contra entry. A contra entry is recorded when the debit and credit affect the same parent account and resulting in a net zero effect to the account. These are transactions that are recorded between cash and bank accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>3", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "To show the evidence of payment to a government ministry, the revenue collector issues a", "images": [], "options": {"A": "receipt voucher.", "B": "payment voucher.", "C": "treasury receipt.", "D": "treasury card."}, "answer": "C", "explanation": "A treasury receipt is issued by a government revenue collector as evidence of payment to a government ministry. A receipt voucher and payment voucher are typically used in businesses, not government ministries. A treasury card is not a recognized term in this context.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>4", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "The primary concern of shareholder in a business is the", "images": [], "options": {"A": "ascertainment of taxable profit.", "B": "dividend payable.", "C": "ability to pay interest.", "D": "welfare of employees"}, "answer": "B", "explanation": "The primary concern of a shareholder in a business is the dividend payable. This is because dividends are the return on the investment made by the shareholder in the business. The ascertainment of taxable profit, ability to pay interest, and welfare of employees, while important, are not the primary concern of shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>5", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "In a not-for-profit organization, accumulated fund is", "images": [], "options": {"A": "current assets plus fixed assets less total liabilities.", "B": "long-term liabilities plus current liabilities.", "C": "fixed assets plus current assets plus long-term liabilities.", "D": "fixed assets less long-term liabilities less current liabilities."}, "answer": "A", "explanation": "In a not-for-profit organization, the accumulated fund is the fund that is built up from the surplus of income over expenditure. It is calculated as the total of current assets and fixed assets less total liabilities. This is because the accumulated fund represents the net assets of the organization, which is the total assets (current and fixed) less the total liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>6", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question      Trade creditors  Stock01/01/17  ₦  630,000  540,00031/12/17  ₦  780,000  480,000  Cash paid to trade creditors in 2017 was ₦2,700,000.    Purchases for 2017 was", "images": [], "options": {"A": "₦3,480,000", "B": "₦2,850,000", "C": "₦2,700,000", "D": "₦2,550,000"}, "answer": "B", "explanation": "To determine purchase, we need to prepare creditors control account.  DrCreditors controlA/cCr₦₦Cash paid  bal.c/d  2,700,000  780,000  bal.b/f  purchases  630,000  2,850,000  3,480,0003,480,000bal. b/d780,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>7", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer this question      Trade creditors  Stock01/01/17  ₦  630,000  540,00031/12/17  ₦  780,000  480,000  Cash paid to trade creditors in 2017 was ₦2,700,000.  The cost of goods sold was", "images": [], "options": {"A": "₦3,330,000", "B": "₦2,910,000", "C": "₦2,760,000", "D": "₦2,610,000"}, "answer": "B", "explanation": "Cost of goods sold = Opening stock + Purchases - Closing stock  ⇒ 540,000 + 2,850,000 - 480,000   = ₦2,910,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>8", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "In public sector accounting, salaries of employees is classified as", "images": [], "options": {"A": "capital expenditure", "B": "capital receipt", "C": "recurrent expenditure", "D": "recurrent receipt"}, "answer": "C", "explanation": "In public sector accounting, salaries of employees are classified as recurrent expenditure. Recurrent expenditure refers to the spending on ongoing costs for running services, such as salaries of public servants, maintenance, and operating expenses. It is the expenditure that does not result in the creation of assets. Capital expenditure, on the other hand, refers to the spending on acquisition of assets or improving the capacity of existing assets. Capital receipt refers to the money received from the sale of fixed assets or borrowings. Recurrent receipt refers to the regular or recurring income of the government, such as taxes, fines, and fees.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>9", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Kadiri paid his debt to Suleman by cheque. The accounting entries in Kadiri's books are: debit", "images": [], "options": {"A": "Bank Account; credit Suleman's Account.", "B": "Bank Account; credit Debtor's Account.", "C": "Suleman's Account; credit Bank Account.", "D": "Suleman's Account; credit Cash Account."}, "answer": "C", "explanation": "Since suleman is the receiver and bank is the giver.  Double entry rule state that dr - receiver and cr - giver therefore, Dr - suleman and Cr - bank A/c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>10", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which seeks to prevent profits from being overstated is", "images": [], "options": {"A": "materiality.", "B": "consistency.", "C": "prudence.", "D": "periodicity."}, "answer": "C", "explanation": "The prudence concept in accounting states that businesses should not overstate their profits. Instead, they should be conservative in their accounting estimates, ensuring that income and asset values are not overstated and liabilities and expenses are not understated. This is to ensure that the financial statements provide a 'true and fair' view of the company's financial position.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>11", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer this question  April 11: Sold goods for cash ₦50,000  April 20: Bought goods for cash ₦30,000  April 26: Bought postage stamp ₦5,000  April 28: Cash sales ₦49,000  April 29: Cash purchases ₦11,000  April 30: Paid salaries ₦18,000    Total cash receipts for the period is", "images": [], "options": {"A": "₦99,000", "B": "₦64,000", "C": "₦50,000", "D": "₦35,000"}, "answer": "A", "explanation": "Cash receipts refer to the money received during a particular period. In this case, the cash receipts are the sum of the cash sales made on April 11 and April 28, which are ₦50,000 and ₦49,000 respectively. Adding these two amounts gives a total cash receipt of ₦99,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>12", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer this question  April 11: Sold goods for cash ₦50,000  April 20: Bought goods for cash ₦30,000  April 26: Bought postage stamp ₦5,000  April 28: Cash sales ₦49,000  April 29: Cash purchases ₦11,000  April 30: Paid salaries ₦18,000  The cash balance at the end of the period is", "images": [], "options": {"A": "₦99,000", "B": "₦64,000", "C": "₦35,000", "D": "₦34,000"}, "answer": "C", "explanation": "The cash balance is the difference between Receipts and payments from above (ii)  Cash balance = Receipts - Payments  ⇒ 99,000 - 64,000  ⇒ ₦35,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>13", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "The directors of Olu Ltd. recommended a dividend of 10% on 1,000,000 ordinary share capital of GH⊄ 2.00 each. The amount of dividend declared is", "images": [], "options": {"A": "GH⊄ 200,000", "B": "GH⊄ 100,000", "C": "GH⊄ 20,000", "D": "GH⊄ 10,000"}, "answer": "A", "explanation": "The dividend is calculated as a percentage of the share capital. In this case, the share capital is GH⊄ 2.00 * 1,000,000 = GH⊄ 2,000,000. A 10% dividend on this amount is GH⊄ 200,000. Therefore, the correct answer is GH⊄ 200,000.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>14", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL", "question": "Goodwill is recognized in partnership when", "images": [], "options": {"A": "the business makes a huge profit.", "B": "the business has adequate bank balance.", "C": "a partner is dormant.", "D": "a new partner is admitted."}, "answer": "D", "explanation": "Goodwill is recognized in a partnership when a new partner is admitted and brings in capital that is more than his/her share of the current capital. This excess is considered as goodwill. Therefore, the correct answer is 'a new partner is admitted.'", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>15", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTING RATIO : RELATIONSHIP BETWEEN MARK UP AND MARGIN", "question": "The mark-up on a product is 2/3. The margin is", "images": [], "options": {"A": "3/5", "B": "2/5", "C": "1/3", "D": "2/9"}, "answer": "B", "explanation": "The margin is calculated as the ratio of the markup to the selling price. If the markup is 2/3, then the selling price is 1 + 2/3 = 5/3. Therefore, the margin is (2/3) / (5/3) = 2/5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>16", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Quick ratio is calculated as x - y : z, where", "images": [], "options": {"A": "x = stock; y = current assets and z = long term liabilities.", "B": "x = current assets; y = debtors and z = current liabilities.", "C": "x = current assets; y = stock and z = current liabilities.", "D": "x = debtors; y = stock and z = current assets."}, "answer": "C", "explanation": "The quick ratio (also known as the acid-test ratio) is a measure of a company's ability to meet its short-term obligations using its most liquid assets. It is calculated as (Current Assets - Inventory) / Current Liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>17", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer this question    Opening capital  Drawings  Trade creditors  Trade debtors  Cash in hand  Net profitD  10,800  2,500  2,560  2,880  1,000  6,000    The closing capital is", "images": [], "options": {"A": "D 16,800", "B": "D 14,300", "C": "D 8,300", "D": "D 7,300"}, "answer": "B", "explanation": "The closing capital is calculated by adding the opening capital and the net profit, then subtracting the drawings. So, 10,800 + 6,000 - 2,500 = 14,300.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>18", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use the following information to answer this question    Opening capital  Drawings  Trade creditors  Trade debtors  Cash in hand  Net profitD  10,800  2,500  2,560  2,880  1,000  6,000  The working capital is", "images": [], "options": {"A": "D 6,440", "B": "D 3,880", "C": "D 3,500", "D": "D 1,320"}, "answer": "D", "explanation": "The working capital is calculated by subtracting the trade creditors from the sum of trade debtors and cash in hand. So, (2,880 + 1,000) - 2,560 = 1,320.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>19", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "In a single-entry accounting, purchases are ascertained using a", "images": [], "options": {"A": "trading account.", "B": "debtor's control account.", "C": "statement of affairs.", "D": "creditors' control account."}, "answer": "D", "explanation": "Creditor's Control Account is used to determine the value of purchase in a single entry accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>20", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Goods boght from Samah for Le 1,600 was entered into Shamail's Account. This is an error of", "images": [], "options": {"A": "compensation.", "B": "commission.", "C": "original entry.", "D": "principle."}, "answer": "B", "explanation": "Error of commission occurs when a correct figure is entered into a wrong person's account but the accounts that involve are the same class of account. e.g purchase of goods from tolu was entered into tola's accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>21", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "When closing stock is undervalued, the cost of goods sold would be", "images": [], "options": {"A": "overstated and the gross profit understated.", "B": "understated and the gross profit overstated.", "C": "overstated and the gross profit overstated.", "D": "understated and the gross profit understated."}, "answer": "A", "explanation": "When closing stock is undervalued, it means that the cost of goods sold (COGS) is overstated. This is because the cost of goods sold is calculated as opening stock plus purchases minus closing stock. If the closing stock is undervalued, it means that the subtraction is less, leading to a higher COGS. A higher COGS would lead to a lower gross profit, as gross profit is calculated as sales minus COGS. Therefore, the gross profit would be understated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>22", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Where fixed capital account is maintained, partner's share of profit is transferred to the", "images": [], "options": {"A": "debit side of capital account.", "B": "credit side of capital account.", "C": "credit side of partner's current account.", "D": "debit side of partner's current account."}, "answer": "C", "explanation": "In a partnership where fixed capital accounts are maintained, the partner's share of profit is transferred to the credit side of the partner's current account. The fixed capital account is used to record the initial investment of the partners and any additional capital introduced. It remains unchanged unless additional capital is introduced or part of the capital is withdrawn. The current account, on the other hand, is used to record the day-to-day transactions between the partners and the firm, including the distribution of profits. Therefore, when profits are distributed, they are credited to the partner's current account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>23", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "When bank charges are deducted from a customer's account, the balance on the bank statement would be", "images": [], "options": {"A": "more than the cash book balance.", "B": "less than the cash book balance.", "C": "equal to the cash book balance.", "D": "added to the cash book balance."}, "answer": "B", "explanation": "When bank charges are deducted from a customer's account, the balance on the bank statement would be less than the cash book balance. This is because the bank charges are an expense and when they are deducted, they reduce the balance of the account. The cash book balance is the balance of the account according to the company's records, which may not have been updated to reflect the bank charges yet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>24", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Companies issue shares to the public in order to", "images": [], "options": {"A": "reduce the number of directors.", "B": "reduce the number of shareholders.", "C": "raise capital.", "D": "generate profit."}, "answer": "C", "explanation": "Companies issue shares to the public in order to raise capital. When a company issues shares, it is selling a part of its ownership in exchange for money. This money can then be used to fund business operations or expansion. This process is known as equity financing. It is not done to reduce the number of directors or shareholders, nor is it done to generate profit directly. Profit may be a result of the effective use of the raised capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>25", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Sulah took two textile materials worth GH⊄ 500 from his business for his children's use. This would be treated as", "images": [], "options": {"A": "loan.", "B": "stock.", "C": "drawings.", "D": "sales."}, "answer": "C", "explanation": "When a business owner takes goods from the business for personal use, it is treated as drawings. Drawings refer to the withdrawal of business assets by the owner for personal use. In this case, Sulah took two textile materials worth GH⊄ 500 from his business for his children's use. Therefore, this would be treated as drawings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>26", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  Ajem and Ogah were in partnership sharing profits and losses in the ratio 2 : 3. Interest on capital and drawings were 5% and 3% respectively. The following details relate to the partnership for the year 2017.      Capital Account  Current Account  Drawings   SalaryAjem  GH⊄  60,000  40,000  20,000  10,000Ogah  GH⊄  65,000  50,000  30,000  -  Net profit was GH⊄ 100,000.    Ogah's share of profit was", "images": [], "options": {"A": "GH⊄ 51,150", "B": "GH⊄ 50,250", "C": "GH⊄ 34,100", "D": "GH⊄ 33,500"}, "answer": "A", "explanation": "To calculate Ogah's share of profit, we first need to calculate the total profit after interest on capital and drawings. Interest on capital for Ajem is 5% of 60,000 = GH⊄ 3,000 and for Ogah is 5% of 65,000 = GH⊄ 3,250. Interest on drawings for Ajem is 3% of 20,000 = GH⊄ 600 and for Ogah is 3% of 30,000 = GH⊄ 900. The total profit after interest is 100,000 - (3,000 + 3,250 + 600 + 900) = GH⊄ 92,250. Ogah's share of profit is 3/5 of 92,250 = GH⊄ 55,350. However, we need to subtract the interest on his capital and drawings, so his final share of profit is 55,350 - (3,250 + 900) = GH⊄ 51,200. The closest option to this is GH⊄ 51,150.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>27", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  Ajem and Ogah were in partnership sharing profits and losses in the ratio 2 : 3. Interest on capital and drawings were 5% and 3% respectively. The following details relate to the partnership for the year 2017.      Capital Account  Current Account  Drawings   SalaryAjem  GH⊄  60,000  40,000  20,000  10,000Ogah  GH⊄  65,000  50,000  30,000  -  Net profit was GH⊄ 100,000.  Ajem's current account balance was", "images": [], "options": {"A": "GH⊄ 66,500", "B": "GH⊄ 60,000", "C": "GH⊄ 32,000", "D": "GH⊄ 40,000"}, "answer": "A", "explanation": "Partners' current account  GH⊄GH⊄GH⊄GH⊄drawings   Interest on drawing  balance c/d  20,000  600  66,500  30,000  900  73,500  balance b/f  salary  Interest on capital  share of profit40,000  10,000  3,000  34,10050,000    3,250  51,15087,100104,40087,100104,400balance b/d66,50073,500  Ajem's current account balance is GH⊄66,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>28", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer this question  Ajem and Ogah were in partnership sharing profits and losses in the ratio 2 : 3. Interest on capital and drawings were 5% and 3% respectively. The following details relate to the partnership for the year 2017.      Capital Account  Current Account  Drawings   SalaryAjem  GH⊄  60,000  40,000  20,000  10,000Ogah  GH⊄  65,000  50,000  30,000  -  Net profit was GH⊄ 100,000.  Interest on drawings amounted to", "images": [], "options": {"A": "GH⊄ 6,000", "B": "GH⊄ 1,500", "C": "GH⊄ 900", "D": "GH⊄ 600"}, "answer": "B", "explanation": "The total interest on drawings is calculated as the sum of the interest on Ajem's drawings and the interest on Ogah's drawings, which is 600 + 900 = 1,500 GH⊄. The correct option is B.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>29", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Debtors Control Account is kept in the", "images": [], "options": {"A": "sales ledger", "B": "nominal ledger", "C": "personal ledger", "D": "general ledger"}, "answer": "A", "explanation": "Debtors control account is kept in the sales ledger. Another name for debtors control account is sales ledger control A/c.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>30", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Where there is provision for depreciation, fixed asset is shown in the balance sheet at   I. cost less depreciation for the period only.  II. cost less total depreciation to date.  III. written down values.", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "I and III only"}, "answer": "C", "explanation": "Where there is provision for depreciation, a fixed asset is showb in the balance sheet at cost less total depreciation for the period and at written down value, that is Net book value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>31", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "The partner whose liability goes beyond his capital is a", "images": [], "options": {"A": "nominal partner.", "B": "general partner.", "C": "limited partner.", "D": "dormant partner."}, "answer": "B", "explanation": "A general partner is a partner whose liability goes beyond his capital in a partnership. This means that in the event of any financial trouble, the general partner can be held personally liable for all the debts of the business. This is different from a limited partner whose liability is limited to the amount of capital they have invested in the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>32", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "An effect of increase in the provision for depreciation is", "images": [], "options": {"A": "decrease in gross profit.", "B": "increase in net profit.", "C": "increase in gross profit.", "D": "decrease in net profit."}, "answer": "D", "explanation": "An increase in the provision for depreciation will result in a decrease in net profit. Depreciation is an expense that reduces the value of an asset over time due to wear and tear, decay, or obsolescence. When the provision for depreciation increases, it means that the business is setting aside more money to account for the decrease in value of its assets. This increase in expense will reduce the net profit of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>33", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Uncredited cheques refer to cheques not yet credited", "images": [], "options": {"A": "in the cash book.", "B": "by the bank.", "C": "by the drawer.", "D": "in the ledger."}, "answer": "B", "explanation": "Uncredited cheques refer to cheques that have been issued by a company or individual but have not yet been processed or credited by the bank. This means the bank has not yet recognized the cheque in its records, hence the correct answer is 'by the bank.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>34", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Interim dividend paid in a year is", "images": [], "options": {"A": "debited to the Income Surplus Account/Profit and Loss Appropriation Account.", "B": "credited to the Income Surplus Account/Profit and Loss Appropriation Account.", "C": "debited to the Profit and Loss Account.", "D": "credited to the Profit and Loss Account."}, "answer": "A", "explanation": "Interim dividends are dividends that are declared and distributed by a company before its Annual General Meeting and final financial statements. These dividends are recorded as a debit (expense) to the Income Surplus Account or Profit and Loss Appropriation Account. This is because when a company pays dividends, it reduces the company's retained earnings (Income Surplus Account) or the profits available for distribution (Profit and Loss Appropriation Account).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>35", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "A feature of government accounting is that the", "images": [], "options": {"A": "fixed assets are depreciated.", "B": "objective is to report profit made by the government.", "C": "accounts are prepared on accrual basis.", "D": "accounts are prepared on cash basis."}, "answer": "D", "explanation": "Government accounting is primarily based on the cash basis of accounting. This means that transactions are recorded when cash is either received or paid. Unlike accrual accounting, where transactions are recorded when they are incurred, cash basis accounting does not recognize receivables or payables. This is a key feature of government accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>36", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question    Cost of raw materials available  Manufacturing wages  Factory expenses   Royalty  Factory rent  Depreciation of plant and machinery  Closing stock of raw materials$  32,000  10,000  5,000  3,000  2,000  5,000  3,000    The prime cost is", "images": [], "options": {"A": "$57,000", "B": "$45,000", "C": "$42,000", "D": "$39,000"}, "answer": "C", "explanation": "Prime cost is the total cost of direct materials and direct labor that goes into the production of a product. In this case, the cost of raw materials available ($32,000) and the manufacturing wages ($10,000) are considered as direct costs. Therefore, the prime cost is $32,000 + $10,000 = $42,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>37", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer this question    Cost of raw materials available  Manufacturing wages  Factory expenses   Royalty  Factory rent  Depreciation of plant and machinery  Closing stock of raw materials$  32,000  10,000  5,000  3,000  2,000  5,000  3,000  Factory overhead cost is", "images": [], "options": {"A": "$25,000", "B": "$15,000", "C": "$12,000", "D": "$7,000"}, "answer": "C", "explanation": "Factor overhead cost = 5000 + 2000 + 5000  =   $12,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>38", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "Capital and drawings accounts are kept in the", "images": [], "options": {"A": "general ledger.", "B": "purchases ledger.", "C": "sales ledger.", "D": "private ledger."}, "answer": "D", "explanation": "Capital and drawings accounts are kept in the private ledger. A private ledger is a ledger that includes accounts that are related to capital, such as the capital account, drawings account, and proprietor's personal accounts. These accounts are not included in the general ledger because they contain sensitive information that is not meant for public viewing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>39", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS", "question": "Set-off is carried out in the control account when", "images": [], "options": {"A": "a business organization is both a customer and a supplier.", "B": "customers refuse to pay their debts.", "C": "the debtors settle their accounts.", "D": "customers' cheques are dishonoured."}, "answer": "A", "explanation": "Set-off in accounting is a legal right that a debtor has to balance mutual debts with a creditor. In the context of a control account, set-off is carried out when a business organization is both a customer and a supplier. This means that the business owes money to a supplier (accounts payable) and the same supplier owes money to the business (accounts receivable). The two amounts are offset against each other to reduce the total amount of money that changes hands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>40", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Debtors balance (01/01/16) - Le 2,518; Cash received - Le 10,000; Discount allowed - Le 280; Interest charged to debtors - Le 63; Debtors balance (30/06/16) - Le 1,450.  The credit sales is", "images": [], "options": {"A": "Le 11,730.", "B": "Le 9,149.", "C": "Le 2,581.", "D": "Le 2,518"}, "answer": "B", "explanation": "The credit sales can be calculated by adding the opening balance of debtors to the cash received, the discount allowed and the interest charged to debtors, then subtracting the closing balance of debtors. This gives: Le 2,518 (opening balance) + Le 10,000 (cash received) + Le 280 (discount allowed) + Le 63 (interest charged) - Le 1,450 (closing balance) = Le 11,411. However, none of the options matches this answer. Therefore, none of the options is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>41", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "An example of nominal account is", "images": [], "options": {"A": "Kofi and Ali Account.", "B": "Plant and Machinery Account.", "C": "Profit and Loss Account.", "D": "Cash and Bank Account."}, "answer": "C", "explanation": "A nominal account is an account that is closed at the end of each accounting period. Temporary or nominal accounts include revenue, expense, and gain and loss accounts. In this case, the Profit and Loss Account is a nominal account because it is closed at the end of each accounting period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>42", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that recognizes revenue at the time of sale and not only when cash is received is", "images": [], "options": {"A": "cost concept.", "B": "realization concept.", "C": "accrual concept.", "D": "duality concept."}, "answer": "B", "explanation": "The realization concept, also known as the revenue recognition principle, is an accounting principle that requires revenue to be recorded at the time it is earned, regardless of when the payment is received. This means that revenue is recognized when the sale is made, not when the cash is received.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>43", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which stipulates that income and expenses should be matched to determine profit or loss is", "images": [], "options": {"A": "cost concept.", "B": "accrual concept.", "C": "objectivity concept.", "D": "realization concept."}, "answer": "B", "explanation": "The accrual concept in accounting means that expenses and revenues should be recorded in the period they occur, regardless of when the cash transactions occur. This concept is used to match income and expenses in the correct accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>44", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "The document used to correct an undercharge on an invoice is", "images": [], "options": {"A": "credit note.", "B": "debit note.", "C": "receipt.", "D": "voucher."}, "answer": "B", "explanation": "A debit note is a document used by a buyer to inform the seller of a debit made to the seller's account on the buyer's books. It is used to correct an undercharge on an invoice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2019>45", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer this question      Sales   Purchases  Opening stock  Closing stock  Discount allowedDept. A  D  16,000  9,000  600  900  800Dept. B  D  24,000  6,000  500  600  1,200  Carriage inwards (proportion to sales) 1,600    Carriage inwards for Dept. B is", "images": [], "options": {"A": "D 1,600", "B": "D 960", "C": "D 800", "D": "D 640"}, "answer": "B", "explanation": "The carriage inwards for Dept. B is calculated by finding the proportion of Dept. B's sales to the total sales and then multiplying this proportion by the total carriage inwards. The total sales is the sum of Dept. A's sales and Dept. B's sales, which is 16,000 + 24,000 = 40,000. The proportion of Dept. B's sales to the total sales is 24,000 / 40,000 = 0.6. Therefore, the carriage inwards for Dept. B is 0.6 * 1,600 = 960.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>46", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer this question      Sales   Purchases  Opening stock  Closing stock  Discount allowedDept. A  D  16,000  9,000  600  900  800Dept. B  D  24,000  6,000  500  600  1,200  Carriage inwards (proportion to sales) 1,600  Net profit for Dept. A is", "images": [], "options": {"A": "D 6,340", "B": "D 5,860", "C": "D 4,960", "D": "D 4,900"}, "answer": "B", "explanation": "Net profit of departmental A is shown below   DrDepartmental Trading,Profit & loss A/cCrABABDDDDOpening stock  Add: purchases   Carriage Inwards600  9,000  640500  6,000  960Sales      16,000       24,000      CO GAS  Closing Stock10,240  (900)7,460  (600)      COGS  Gross profit c/d9,340  66606860  17,140         16,00024,00016,00024,000Expenses  Discount allowed  Net profit800  58601200  15,940         666017,140666017,140    Therefore, the netprofit of department A = 5,860", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>47", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer this question      Sales   Purchases  Opening stock  Closing stock  Discount allowedDept. A  D  16,000  9,000  600  900  800Dept. B  D  24,000  6,000  500  600  1,200  Carriage inwards (proportion to sales) 1,600  Net profit for Dept. B is", "images": [], "options": {"A": "D 17,460", "B": "D 16,660", "C": "D 16,260", "D": "D 15,940"}, "answer": "D", "explanation": "Therefore, the netprofit of department B = 15,940.    DrDepartmental Trading,Profit & loss A/cCrABABDDDDOpening stock  Add: purchases   Carriage Inwards600  9,000  640500  6,000  960Sales      16,000       24,000      CO GAS  Closing Stock10,240  (900)7,460  (600)      COGS  Gross profit c/d9,340  66606860  17,140         16,00024,00016,00024,000Expenses  Discount allowed  Net profit800  58601200  15,940         666017,140666017,140", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2019>48", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question  A firm bought lathe machine for Le 45,600 on 1st January, 2015. The life span was estimated to be 20 years while scrap at the end of the period was valued at Le 1,600. It was to be depreciated by fixed instalment method.    The depreciation per annum is", "images": [], "options": {"A": "Le 2,360", "B": "Le 2,280", "C": "Le 2,200", "D": "Le 1,600"}, "answer": "C", "explanation": "Depreciation per annum using the fixed installment method is calculated as (Cost of Asset - Scrap Value) / Useful Life. Substituting the given values, we get (45600 - 1600) / 20 = 2200.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>49", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer this question  A firm bought lathe machine for Le 45,600 on 1st January, 2015. The life span was estimated to be 20 years while scrap at the end of the period was valued at Le 1,600. It was to be depreciated by fixed instalment method.  The net book value of the machine as at 31st December, 2017 was", "images": [], "options": {"A": "Le 44,000", "B": "Le 41,200", "C": "Le 39,000", "D": "Le 38,760"}, "answer": "C", "explanation": "The netbook value of the machine as at 31st Dec. 2017 = Cost - Accumulated depreciation from 1st Jan 2015 to 31st Dec 2017 (3 years)  Accumulated depreciation = 2220 × 3 years = 6600  Netbook value of the machine = 45,600 - 6600  Le 39,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2019>50", "subject": "Accounts", "year": "2019", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscription owing $6,000 (31/12/2014);  Subscription in advance $4,000 (31/12/2014);  Cash received as subscription during the year was $80,000.  The subscription for the year 2014 was", "images": [], "options": {"A": "$90,000", "B": "$82,000", "C": "$78,000", "D": "$70,000"}, "answer": "B", "explanation": "The subscription for the year 2014 is calculated below;  DrSubscription A/cSubscription A/cCr  balance c/d  profit & loss$  4,000  82,000  cash received  balance c/d$  80,000  6,00086,00086,000balance b/d6000balance b/d4000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>1", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "A debit entry in a fixed asset account represents", "images": [], "options": {"A": "an increase in the fixed asset account", "B": "a decrease in the fixed asset account", "C": "a profit on disposal of the fixed asset", "D": "a loss on disposal of the fixed asset"}, "answer": "A", "explanation": "In accounting, a debit entry in a fixed asset account represents an increase in the value of the asset. This is because fixed assets are considered as assets or resources owned by a business, and a debit entry increases the value of an asset account according to the rules of debit and credit in accounting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>2", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "When bank charges are discovered in a bank statement, the adjustment is effected in the", "images": [], "options": {"A": "bank reconciliation statement", "B": "cash book", "C": "suspense account", "D": "bank loan account"}, "answer": "B", "explanation": "When bank charges are discovered in a bank statement, the adjustment is effected in the cash book. This is because the cash book is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger. Bank charges are expenses incurred by the business, hence they decrease the balance of cash at bank, which is recorded in the cash book.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>3", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "The double entry for the interest on drawings by a partner is: debit", "images": [], "options": {"A": "Partner's Current Account; credit Appropriation Account", "B": "Profit and loss Account; credit Interest Account", "C": "Appropriation Account; credit Partner's Current Account", "D": "Interest Account; credit Profit and Loss Account"}, "answer": "A", "explanation": "The double entry for the interest on drawings by a partner is: debit Partner's Current Account and credit Appropriation Account. This is because when a partner withdraws more than their share of profit, the excess is treated as a drawing and interest is charged on it. The interest charged is debited to the partner's current account and credited to the appropriation account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>4", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "A credit purchase of GH⊄ 200 from Osae was posted to the account of Osei. This is an error of", "images": [], "options": {"A": "Principle", "B": "commission", "C": "omission", "D": "original entry"}, "answer": "B", "explanation": "This is an error of commission. An error of commission occurs when an entry is made at the right amount, and in the correct side of the ledger, but to the wrong person's account. In this case, the purchase was correctly recorded as a credit, but it was posted to the account of Osei instead of  Osae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>5", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Use the following information to answer the question Leprovision for doubtful debts                   1000 CrBad debts                                                  500 DrDebtors                                                50000 DrAdditional bad debts to be written off       500New provision for doubtful debts to stand at 5% of debtors    The net figure for debtors in the balance sheet is", "images": [], "options": {"A": "Le 47,000", "B": "Le 46,550", "C": "Le 45,600", "D": "Le 45,500"}, "answer": "A", "explanation": "Debtors balance = 500005% x 50000   =     2500                               47500Less bad debt   =     500                                 47000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>6", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "Leprovision for doubtful debts                   1000 CrBad debts                                                  500 DrDebtors                                                50000 DrAdditional bad debts to be written off       500New provision for doubtful debts to stand at 5% of debtors  The provision for doubtful debts to be charged to profit and loss Account is", "images": [], "options": {"A": "Le 2,500", "B": "Le 2,475", "C": "Le 2,450", "D": "Le 1,000"}, "answer": "A", "explanation": "provision for doubtful debts to be charged to profit and loss Account is:    5% x 50,000       =     2,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>7", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "An office equipment bought for use was found to be defective and returned to the supplier. The subsidiary book to record this transaction is", "images": [], "options": {"A": "returns outwards journal", "B": "returns inwards journal", "C": "purchases journal", "D": "general journal"}, "answer": "A", "explanation": "The correct answer is 'returns outwards journal'. When a business returns goods to the supplier due to any reason, it is recorded in the returns outwards journal. This is a part of the subsidiary books where specific types of transactions are recorded. In this case, the office equipment was found to be defective and hence, returned to the supplier. Therefore, this transaction will be recorded in the returns outwards journal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>8", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "In a situation of incomplete records, profit is determined as", "images": [], "options": {"A": "closing capital - drawings + opening capital", "B": "closing capital - drawings - opening capital", "C": "closing capital + drawings - opening capital", "D": "closing capital + drawings + opening capital"}, "answer": "C", "explanation": "In a single entry, profit is calculated as : NP = CC - OC - AC + D  where: OC = opening capital              AC= Additional capital              NP= Net profit               D = drawings               CC= Closing capital", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>9", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The document which serves as the authority to incur expenditure in public sector is", "images": [], "options": {"A": "warrant", "B": "vote", "C": "budget", "D": "voucher"}, "answer": "A", "explanation": "In the public sector, a warrant is the document that serves as the authority to incur expenditure. It is an official order or commission to do something. It is a type of financial instrument issued by the government that gives the holder the right to receive payment from the issuer under certain conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>10", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "A debit balance of GH⊄ 420 on the purchases ledger control account means that the", "images": [], "options": {"A": "trade creditors were overpaid by GH⊄ 420", "B": "trade creditors are owed GH⊄ 420", "C": "goods returned to trade creditors amounted to GH⊄ 420", "D": "total supplies from trade creditors amounted to Gh⊄ 420"}, "answer": "B", "explanation": "A debit balance on the purchases ledger control account means that the trade creditors are owed that amount. The purchases ledger control account is a summary account that reflects the total amount owed to all suppliers at a particular point in time. A debit balance indicates that the company owes money to its suppliers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>11", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "A total of D 9,160 was entered in the sales account as D 9,610. To correct this error: debit", "images": [], "options": {"A": "Sales Account D 450; credit Sales Day Book D 450", "B": "Sales Day Book D 450; credit Sales Account D 450", "C": "Sales Account D 450; credit Suspence Account D 450", "D": "Suspence Account D 450; credit Sales Account D 450"}, "answer": "B", "explanation": "The error was that D 9,610 was entered instead of D 9,160. This means that the sales account was credited with an extra D 450. To correct this, we need to debit the sales account by D 450 to reduce it to the correct amount. At the same time, we credit the Sales Day Book by D 450 to balance the transaction. Hence, the correct option is 'Sales Day Book D 450; credit Sales Account D 450'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>12", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions 12 to 14Ata, Bubu and Chikum were in partnership sharing profits and losses in proportion to their capital contributions:                           Capital                 Drawings                          #                            #Ata                    40000               8000Bubu                30000                5000Chikum            20000                    -  Net profit for the year was #40,500 and the interest on capital was 5% per annum    The profit available for sharing by the partners is", "images": [], "options": {"A": "#90,000", "B": "#40,500", "C": "#36,000", "D": "#27,500"}, "answer": "C", "explanation": "The net profit for the year was #40,500. However, before sharing the profit, we need to deduct the interest on capital. The interest on capital is calculated as 5% of the total capital contributed by the partners. The total capital is #90,000 (Ata's #40,000 + Bubu's #30,000 + Chikum's #20,000). Therefore, the interest on capital is #4,500 (5% of #90,000). After deducting the interest on capital from the net profit, the profit available for sharing by the partners is #36,000 (#40,500 - #4,500). Hence, the correct option is '#36,000'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>13", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Ata, Bubu and Chikum were in partnership sharing profits and losses in proportion to their capital contributions:                           Capital                 Drawings                          #                            #Ata                    40000               8000Bubu                30000                5000Chikum            20000                    -  Net profit for the year was #40,500 and the interest on capital was 5% per annum  The balance in Chikum's Current Account is", "images": [], "options": {"A": "#14,000", "B": "#9,000", "C": "#8,000", "D": "#4,000"}, "answer": "B", "explanation": "Total ratio = proportion of capital contribution                      i.e 4 +3+2  = 9    Total partners share of  profit = 36,000  Ata = 4/9  x 36,000  = 16,000  Bubu = 3/9  x 36,000 = 12,000  Chi = 2/9  x 36,000= 8,000    Chikum's current capital = Interest on capital + share of profit                                        = 1000 + 8000                                                = 9,000                                         = 9,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>14", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Ata, Bubu and Chikum were in partnership sharing profits and losses in proportion to their capital contributions:                           Capital                 Drawings                          #                            #Ata                    40000               8000Bubu                30000                5000Chikum            20000                    -  Net profit for the year was #40,500 and the interest on capital was 5% per annum  Bubu's share of profit is", "images": [], "options": {"A": "#16,000", "B": "#12,000", "C": "#8,000", "D": "#4,000"}, "answer": "B", "explanation": "Bubu's share of profit:     = 3/9  x 36,000     = 12,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>15", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Recognition of profit when goods are sold and the buyer takes ownership of them is line with", "images": [], "options": {"A": "realization concept", "B": "matching concept", "C": "business entity concept", "D": "going concern concept"}, "answer": "A", "explanation": "The realization concept in accounting states that revenue and profits are recognized when realized, which is typically when goods or services are sold and the buyer takes ownership of them. Therefore, the recognition of profit when goods are sold and the buyer takes ownership of them is in line with the realization concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>16", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The purpose of preparing trading account is to ascertain", "images": [], "options": {"A": "average stock", "B": "gross profit", "C": "cost of goods sold", "D": "cost of goods available for sale"}, "answer": "B", "explanation": "The purpose of preparing a trading account is to ascertain the gross profit or loss of a business. The trading account shows the relationship between the gross profit and the sales. Gross profit is calculated by subtracting the cost of goods sold from net sales. Therefore, the purpose of preparing a trading account is to ascertain the gross profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>17", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "A trader adds 25% on cost as profit. The profit on sales of $300,000 would be", "images": [], "options": {"A": "$75,000", "B": "$60,000", "C": "$50,000", "D": "$25,000"}, "answer": "B", "explanation": "The trader adds 25% on cost as profit. This means that the cost price represents 100% and the selling price represents 125% (100% cost + 25% profit). Therefore, the profit on sales of $300,000 would be 25% of the selling price. To calculate this, we divide the selling price by 125 and multiply by 25. This gives us $60,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>18", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which distinguishes an enterprise from its owners is", "images": [], "options": {"A": "money measurement concept", "B": "dual aspect concept", "C": "going concern concept", "D": "business entity concept"}, "answer": "D", "explanation": "The 'business entity concept' is an accounting principle that treats a business as a separate entity from its owners. This means that the business's financial transactions are recorded separately from the owners' personal transactions. This concept is fundamental to the double-entry bookkeeping system, where each transaction affects at least two accounts; one account belongs to the business and the other to an owner or external party.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>19", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Eze introduces his private car into his business. the aspect of accounting equation of the business that would be affected are", "images": [], "options": {"A": "Assets and Capital", "B": "Capital and Profit", "C": "Liabilities and Assets", "D": "Capital and Liabilities"}, "answer": "A", "explanation": "When Eze introduces his private car into his business, it increases the assets of the business because the car is now a business asset. Also, it increases the capital because the car is an investment into the business by the owner. Therefore, the aspects of the accounting equation that would be affected are Assets and Capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>20", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Debtors and credit sales for a period are D 120,000 and D 600,000 respectively. The debtors's payment period would be", "images": [], "options": {"A": "1825 days", "B": "365 days", "C": "73 days", "D": "5 days"}, "answer": "C", "explanation": "The debtor's payment period can be calculated by dividing the total debtors by the credit sales and then multiplying by 365. This gives (120,000/600,000)*365 = 73 days. Therefore, the debtor's payment period would be 73 days.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>21", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and payments Account of Abaluare Youth Club for the year ended 31st December 2018                                                        #                                                                         #Balance b/f                      650000           Wages and salaries                      2400000Subscriptions                9660000           Rent and rates                                 600000Annual dance tickets     1500000           Anniversary dance expenses          955000Donations                        800000          Travelling expenses                         140000                                                                Kitchen equipment                        4000000                                                                Balance c/d                                     4515000                             12610000                                                                  12610000                                              Subscriptions for 2017 and 2019 received during the year were #180,000 and #150,000 respectively.    Subscriptions credited to income and Expenditure Account for 2018 was", "images": [], "options": {"A": "#9,990,000", "B": "#9,690,000", "C": "#9,630,000", "D": "#9,330,000"}, "answer": "C", "explanation": "Subcription credited = 9,660,000  - 180,000 + 150,000                                  = 9,630,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>22", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and payments Account of Abaluare Youth Club for the year ended 31st December 2018                                                        #                                                                         #Balance b/f                      650000           Wages and salaries                      2400000Subscriptions                9660000           Rent and rates                                 600000Annual dance tickets     1500000           Anniversary dance expenses          955000Donations                        800000          Travelling expenses                         140000                                                                Kitchen equipment                        4000000                                                                Balance c/d                                     4515000                             12610000                                                                  12610000                                              Subscriptions for 2017 and 2019 received during the year were #180,000 and #150,000 respectively.  Total expenses debited to Income and Expenditure Account for 2018 was", "images": [], "options": {"A": "#12,610,000", "B": "#8,095,000", "C": "#4,515,000", "D": "#4,095,000"}, "answer": "B", "explanation": "The total expenses debited to the Income and Expenditure Account for 2018 is calculated by adding up all the expenses. The expenses are: Wages and salaries (#2,400,000), Rent and rates (#600,000), Anniversary dance expenses (#955,000), Travelling expenses (#140,000), and Kitchen equipment (#4,000,000). Therefore, the total expenses is #2,400,000 + #600,000 + #955,000 + #140,000 + #4,000,000 = #8,095,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>23", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Receipts and payments Account of Abaluare Youth Club for the year ended 31st December 2018                                                        #                                                                         #Balance b/f                      650000           Wages and salaries                      2400000Subscriptions                9660000           Rent and rates                                 600000Annual dance tickets     1500000           Anniversary dance expenses          955000Donations                        800000          Travelling expenses                         140000                                                                Kitchen equipment                        4000000                                                                Balance c/d                                     4515000                             12610000                                                                  12610000                                              Subscriptions for 2017 and 2019 received during the year were #180,000 and #150,000 respectively.  The surplus for the year 2018 was", "images": [], "options": {"A": "#7,865,000", "B": "#7,535,000", "C": "#5,845,000", "D": "#5,235,000"}, "answer": "D", "explanation": "Surplus  = 11,930,000  - 8,095,000                          = 5,235,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>24", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "A non-cash expense chargeable against profit and loss account is", "images": [], "options": {"A": "insurance payable", "B": "debenture interest", "C": "provision for doubtful debts", "D": "rents and rates"}, "answer": "C", "explanation": "A non-cash expense is an expense that is recorded in the financial statements of a company but does not involve a cash payment. Provision for doubtful debts is an example of a non-cash expense. It is an estimated amount of bad debts that are likely to arise from the accounts receivable that have been given out by the company. It is considered a non-cash expense because it reduces the company's earnings before any cash is actually paid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>25", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The cost incurred on goods purchased for production which can be traced to a particular unit is classified as", "images": [], "options": {"A": "direct labour", "B": "direct expenses", "C": "direct materials", "D": "factory overhead"}, "answer": "B", "explanation": "Direct expenses are those costs that do not relate to direct materials or labour but are incurred specifically on a particular product and on every unit produced e.g royalty, excise duty, franchise etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>26", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer questions 26 and 27A manufacturing company's cost of production was D 200,000. The finished goods were transferred to the warehouse at D 220,000. At the end of the year, 9% of these goods were still in stock.    The value of closing stock of finished goods in the trading account is", "images": [], "options": {"A": "D 37,800", "B": "D 20,000", "C": "D 19,800", "D": "D 18,000"}, "answer": "C", "explanation": "The value of closing stock of finished goods in the trading account is calculated by taking the value of the goods transferred to the warehouse (D 220,000) and multiplying it by the percentage of goods still in stock at the end of the year (9%). This gives D 19,800. The closing stock value represents the cost of the inventory still on hand at the end of the accounting period and is reported on the balance sheet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>27", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "A manufacturing company's cost of production was D 200,000. The finished goods were transferred to the warehouse at D 220,000. At the end of the year, 9% of these goods were still in stock.  The value of closing stock of finished goods that would be shown in the balance sheet is", "images": [], "options": {"A": "D 37,800", "B": "D 20,000", "C": "D 19,800", "D": "D 18,000"}, "answer": "C", "explanation": "The value of closing stock of finished goods is calculated by taking the percentage of goods still in stock from the total value of goods transferred to the warehouse. In this case, 9% of D 220,000 is D 19,800. Therefore, the correct answer is D 19,800.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>28", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Items shown in manufacturing account include   I.   Purchases of raw materials  II.  Purchases of finished goods  III. Carriage inwards  IV. Carriage outwards", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I, II and III only", "D": "I, III and IV only"}, "answer": "B", "explanation": "A manufacturing account includes the cost of raw materials and any costs associated with bringing those materials to the manufacturing site, which is known as carriage inwards. It does not include the cost of finished goods or the cost of delivering goods, known as carriage outwards. Therefore, the correct answer is I and III only.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>29", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Use the following information to answer questions below:  Kwamenah bought goods worth Le 50,000 from Doe and sons Limited on the following terms:  3% trade discount;  10% cash discount.    Kwamenah returned defective goods worth Le 8,000 the next day and payment for the remaining goods on the due date  .    The cash paid by Kwamenah was", "images": [], "options": {"A": "Le 43,650", "B": "Le 43,500", "C": "Le 37,800", "D": "Le 36,666"}, "answer": "D", "explanation": "#Purchases 50000Less: Trade discount ( 3%  x 50000) ( 1500) 48500Less: Cash disocunt ( 10%  x 48500)  ( 4850 ) 43650    Returns outward8000Less: trade discount ( 3%  x 8000) 240 7760Less: cash discount ( 10%  x 7760) ( 776 ) 6984    Purchases 43650Less: Returns outwards (  6984 )Cash paid 36666", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>30", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Use the following information to answer questions below:  Kwamenah bought goods worth Le 50,000 from Doe and sons Limited on the following terms:  3% trade discount;  10% cash discount.    Kwamenah returned defective goods worth Le 8,000 the next day and payment for the remaining goods on the due date  .Kwamenah would record the 10% discount in the", "images": [], "options": {"A": "sales journal", "B": "cash book", "C": "purchases journal", "D": "journal proper"}, "answer": "C", "explanation": "In the book of Kwamenah the 10% discount would be recorded in the purchase journal", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>31", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer questions below:  Kwamenah bought goods worth Le 50,000 from Doe and sons Limited on the following terms:  3% trade discount;  10% cash discount.    Kwamenah returned defective goods worth Le 8,000 the next day and payment for the remaining goods on the due date  .Doe and Sons Limited would enter the 3% discount in the", "images": [], "options": {"A": "sales journal", "B": "cash book", "C": "purchase journal", "D": "journal proper"}, "answer": "B", "explanation": "The 3% discount will be recorded in Doe and Sons  cash book", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>32", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A partner who contributes capital but does not participate in the day-to-day running of the business is", "images": [], "options": {"A": "an active partner", "B": "a limited partner", "C": "a nominal partner", "D": "a sleeping partner"}, "answer": "D", "explanation": "A partner who contributes capital but does not participate in the day-to-day running of the business is a sleeping partner. A sleeping partner is a business partner who invests capital into the business but does not participate in its daily operations or management decisions. They share in the profits (or losses) of the business but their liability is limited to the extent of their investment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>33", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "An example of real account is", "images": [], "options": {"A": "Computer Repairs Account", "B": "Computer Insurance Account", "C": "Office Computer Account", "D": "Depreciation of Computer Account"}, "answer": "C", "explanation": "A real account is a general ledger account relating to Assets and Liabilities other than people accounts. These are accounts that don't close at year-end and are carried forward. An example of a real account is an asset account, like 'Office Computer Account'. The other options are nominal accounts which are income, expense, losses and gains accounts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>34", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that guides a firm to adopt a regular method of recording transactions in its books over a period is", "images": [], "options": {"A": "periodicity concept", "B": "consistency concept", "C": "going concern concept", "D": "historical cost concept"}, "answer": "B", "explanation": "The consistency concept in accounting means that a business should use the same accounting methods and standards for recording certain types of transactions. This allows for more fair and meaningful comparison between different financial periods. The other concepts listed have different applications: the periodicity concept relates to the division of a business's life into time periods, the going concern concept assumes that a business will continue to operate indefinitely, and the historical cost concept states that an asset should be recorded at its cost at the time of its purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>35", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT", "question": "A business extracted its trial balance and discovered that the total of the credit side exceeded the total of the debit side. Pending further investigation, the difference would be", "images": [], "options": {"A": "credited to Suspense Account", "B": "debited to Suspense Account", "C": "credited to Profit and Loss Account", "D": "debited to Profit and Loss Account"}, "answer": "B", "explanation": "In accounting, when the total of the credit side exceeds the total of the debit side in a trial balance, the difference is debited to a Suspense Account. This is done to make the trial balance agree temporarily while the error causing the imbalance is investigated and corrected. A Suspense Account is a temporary account used to record discrepancies in a trial balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>36", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer questions below:                                                    Cash Book of Ogidigbi Enterprises                                                          GH⊄                                                            GH⊄Balance b/f                                    127000                    Salaries                      142000Amount received from debtors      409000                  Electricity                     238000                                                                                     Stationery                    126000                                                                                     Balance c/d                    30000                                                           536000                                      536000               Other balances were as follows:                                                     01/01/2017                      31/12/2017                                                           GH⊄                             GH⊄Salaries owing                                  40000                          55000Electricity prepaid                             58000                         60000Stationery outstanding                     49000                         36000    The Salaries that would be charged to Profit and Loss Account for the year 2017 is", "images": [], "options": {"A": "GH⊄ 197,000", "B": "GH⊄ 157,000", "C": "GH⊄ 142,000", "D": "GH⊄ 127,000"}, "answer": "B", "explanation": "Salary  = 142,000 - 40,000 + 55,000                    =   157,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>37", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer questions below:                                                    Cash Book of Ogidigbi Enterprises                                                          GH⊄                                                            GH⊄Balance b/f                                    127000                    Salaries                      142000Amount received from debtors      409000                  Electricity                     238000                                                                                     Stationery                    126000                                                                                     Balance c/d                    30000                                                           536000                                      536000               Other balances were as follows:                                                     01/01/2017                      31/12/2017                                                           GH⊄                             GH⊄Salaries owing                                  40000                          55000Electricity prepaid                             58000                         60000Stationery outstanding                     49000                         36000  The Electricity that would be charged to Profit and Loss Account for the year 2017 is", "images": [], "options": {"A": "GH⊄ 296,000", "B": "GH⊄ 240,000", "C": "GH⊄ 238,000", "D": "GH⊄ 236,000"}, "answer": "D", "explanation": "Electricity = 238,000  + 58,000 - 60,000                     = 236,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>38", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer questions below:                                                    Cash Book of Ogidigbi Enterprises                                                          GH⊄                                                            GH⊄Balance b/f                                    127000                    Salaries                      142000Amount received from debtors      409000                  Electricity                     238000                                                                                     Stationery                    126000                                                                                     Balance c/d                    30000                                                           536000                                      536000               Other balances were as follows:                                                     01/01/2017                      31/12/2017                                                           GH⊄                             GH⊄Salaries owing                                  40000                          55000Electricity prepaid                             58000                         60000Stationery outstanding                     49000                         36000  The Stationery that would be shown in the Balance Sheet as at 31st December 2017 is", "images": [], "options": {"A": "GH⊄ 139,000", "B": "GH⊄ 113,000", "C": "GH⊄ 36,000", "D": "GH⊄ 13,000"}, "answer": "C", "explanation": "The stationery that would be shown in the Balance Sheet as at 31st December 2017 is the stationery outstanding at that date. From the other balances, the stationery outstanding as at 31st December 2017 is GH⊄ 36,000. Therefore, the correct answer is GH⊄ 36,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>39", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Accounting equation of a business shows the", "images": [], "options": {"A": "current assets and current liabilities only", "B": "difference between current assets and liabilities", "C": "assets and the sources of financing them", "D": "owner's interest in the business only"}, "answer": "C", "explanation": "The accounting equation, also known as the balance sheet equation, represents the relationship between the assets, liabilities, and owner's equity of a business. It is the foundation for the double-entry bookkeeping system. It shows that what the business owns (its assets) is purchased by either what it owes (its liabilities) or by what its owners invest (its owner's equity or capital). Therefore, the accounting equation of a business shows the assets and the sources of financing them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>40", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "The internal users of accounting information are the", "images": [], "options": {"A": "creditors", "B": "employees", "C": "investors", "D": "customers"}, "answer": "B", "explanation": "Internal users of accounting information are individuals within a company who direct and control its operations. They include managers, employees, owners, and others who are directly involved in managing the business. Therefore, employees are the internal users of accounting information. External users, on the other hand, are individuals and other enterprises that have a financial interest in the reporting enterprise, but are not involved in the day-to-day operations of that enterprise. They include investors, creditors, customers, and regulatory agencies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>41", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "A computer set bought for #150,000 was disposed for #45,000 after some years of use. The profit on disposal was #7,500. Accumulated depreciation at the time of disposal was", "images": [], "options": {"A": "# 112,500", "B": "#105,000", "C": "#97,500", "D": "#37,500"}, "answer": "A", "explanation": "NBV = COST - DEP           = 150,000 - 45,000              = 105,000    Accumulated dep = 105,000  +7,500                                 = #112,500", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>42", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Accumulated fund of a club is equivalent to its", "images": [], "options": {"A": "net worth", "B": "gross worth", "C": "total assets", "D": "total liabilities"}, "answer": "A", "explanation": "The accumulated fund of a club is equivalent to its net worth. This is because the accumulated fund represents the total assets of the club minus its total liabilities, which is the definition of net worth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>43", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer questions below:                                                 GH⊄Stock 01/01/2018:            - Sportswear            11400            - Cosmetics             28500Purchases:           -Sportswear               80000           -Cosmetics              120000Sales:           -Sportswear             150000           -Cosmetics               250000Wages paid:             -Sportswear               7600            -Cosmetics                 6500Stock 31/12/2018:            -Sportswear              15200            -Cosmetics                27600    The cost of sales for Sportwear Department was", "images": [], "options": {"A": "GH⊄ 127,400", "B": "GH⊄ 120,000", "C": "GH⊄ 83,800", "D": "GH⊄ 76,200"}, "answer": "C", "explanation": "Cost of sales of sport wear  = opening stock + purchase + wages - closing stock                                                    = 11,400 + 80,000 + 7,600 - 15,200                                                      = 83,800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>44", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer questions below:                                                 GH⊄Stock 01/01/2018:            - Sportswear            11400            - Cosmetics             28500Purchases:           -Sportswear               80000           -Cosmetics              120000Sales:           -Sportswear             150000           -Cosmetics               250000Wages paid:             -Sportswear               7600            -Cosmetics                 6500Stock 31/12/2018:            -Sportswear              15200            -Cosmetics                27600  The cost of sales for Cosmetics Department was", "images": [], "options": {"A": "GH⊄ 127,400", "B": "GH⊄ 120,900", "C": "GH⊄ 83,800", "D": "GH⊄ 76,200"}, "answer": "A", "explanation": "Cost of sales for cosmetics = opening stock + purchases + wages - closing stock                                                = 28,000 + 120,000 + 6,500 - 27,600                                                   =  127,400", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>45", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS", "question": "Use the following information to answer questions below:                                                 GH⊄Stock 01/01/2018:            - Sportswear            11400            - Cosmetics             28500Purchases:           -Sportswear               80000           -Cosmetics              120000Sales:           -Sportswear             150000           -Cosmetics               250000Wages paid:             -Sportswear               7600            -Cosmetics                 6500Stock 31/12/2018:            -Sportswear              15200            -Cosmetics                27600  The gross profit for Sportswear Department was", "images": [], "options": {"A": "GH⊄ 76,200", "B": "GH⊄ 73,800", "C": "GH⊄ 66,200", "D": "GH⊄ 58,600"}, "answer": "C", "explanation": "Gross profit for sportwear department = Sales  - Cost of sale                                                                    = 150,000  - 83,800                                                                           = 66,200", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2020>46", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Income received in advance is treated in the balance sheet as a", "images": [], "options": {"A": "current liability", "B": "current asset", "C": "long-term liability", "D": "fixed asset"}, "answer": "A", "explanation": "Income received in advance is a type of liability for the business. It represents money that has been received by the business for goods or services that have not yet been delivered or performed. Therefore, it is treated as a current liability in the balance sheet. Current liabilities are short-term financial obligations that are typically due within one year. So, the correct option is 'current liability'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>47", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Discount allowed    #2000;Bad debts               #1000;Cheque received from customers #24000;Returns inwards#500Sales ledger balance at the beginning #2000.    The amount of sales is", "images": [], "options": {"A": "#29,500", "B": "#26,000", "C": "#25,500", "D": "#24,000"}, "answer": "C", "explanation": "The amount of sales is calculated by adding the cheque received from customers, the sales ledger balance at the beginning, and the returns inwards, then subtracting the discount allowed and the bad debts. This gives us 24000 + 2000 + 500 - 2000 - 1000 = 24500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>48", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY", "question": "The document which contains the internal regulations of a limited liability company is the", "images": [], "options": {"A": "Certificate of Incorporation", "B": "Prospectus", "C": "Article of Association", "D": "Memorandum of Association"}, "answer": "C", "explanation": "The Article of Association is the document that contains the internal regulations of a limited liability company. The Certificate of Incorporation is the document that legally establishes the company, the Prospectus is a document that a company uses to attract investors, and the Memorandum of Association outlines the company's relationship with shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2020>49", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER", "question": "The excess of net assets acquired over purchase consideration is", "images": [], "options": {"A": "capital reserve", "B": "goodwill", "C": "purchase price", "D": "discount"}, "answer": "A", "explanation": "The excess of net assets acquired over purchase consideration is known as capital reserve. This occurs when the value of the net assets of the company acquired is more than the consideration paid for the acquisition. It is a gain for the acquiring company and is therefore credited to capital reserve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2020>50", "subject": "Accounts", "year": "2020", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "A method of charging depreciation at a fixed percentage of the net book value is", "images": [], "options": {"A": "straight line method", "B": "reducing balance method", "C": "sum of the year's digits method", "D": "revaluation method"}, "answer": "B", "explanation": "The reducing balance method, also known as the declining balance method, is a method of depreciation where the value of an asset is decreased at a fixed percentage rate every year. This method results in higher depreciation costs in the earlier years of an asset's life and lower costs in the later years.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>1", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "The original record containing the details of a transaction which serves as a basis for posting is", "images": [], "options": {"A": "general ledger", "B": "source document", "C": "subsidiary book", "D": "trial balance"}, "answer": "B", "explanation": "The original record containing the details of a transaction which serves as a basis for posting is known as a source document. A source document is the original record of a transaction. It contains the details that substantiate a transaction entered in an accounting system. Examples of source documents include invoices, receipts, and checks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>2", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "In the preparation of financial statements, full disclosure of minor events are ignored in line with", "images": [], "options": {"A": "accrual concept", "B": "money measurement concept", "C": "business entity concept", "D": "materiality concept"}, "answer": "D", "explanation": "In the preparation of financial statements, minor events are often ignored in line with the materiality concept. The materiality concept, in accounting, refers to the relative significance of an amount, transaction, or discrepancy. The concept suggests that all relatively insignificant items are permissible to be disregarded if their effect on the financial statements is unimportant to the user's understanding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>3", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A limitation of money measurement concept is that", "images": [], "options": {"A": "it results in inaccurate financial statements", "B": "financial statements is not easily understood", "C": "important non-monetary activities are not reported", "D": "the reports are not comparable to that of other businesses"}, "answer": "C", "explanation": "The money measurement concept in accounting means that only transactions and events that are capable of being measured in monetary terms are recognized in the financial statements. Therefore, important non-monetary activities are not reported because they cannot be measured in monetary terms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>4", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Where partners maintain a fluctuating capital account, partners' share of profit is credited to", "images": [], "options": {"A": "capital account", "B": "profit and loss appropriation account", "C": "current account", "D": "profit and loss account"}, "answer": "A", "explanation": "Fluctuating Capital Method: Under the fluctuating capital process, only one account, that is capital account is recorded and maintained for every partner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>5", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The difference between the market value of goods produced and the cost of production is", "images": [], "options": {"A": "net profit on goods sold", "B": "gross profit on manufacturing", "C": "closing stock of work-in-progress", "D": "prime cost of manufacturing"}, "answer": "B", "explanation": "The difference between the market value of goods produced and the cost of production is the gross profit on manufacturing. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. Gross profit will appear on a company's income statement and can be calculated by subtracting the cost of goods sold (COGS) from revenue (sales).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>6", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions below  Attama and Wawa were in partnership sharing profits and losses in the ratio 4:3. Attama was entitled to salary of D 13,000 per annum.  A net profit of D 34,000 was made for the year.    - The residual profit of the business for the year is", "images": [], "options": {"A": "D 47,000", "B": "D 34,000", "C": "D 22,000", "D": "D 21,000"}, "answer": "D", "explanation": "The residual profit is the amount of profit remaining after taking into account the fact that the partners will be entitled to a proportion of the profit under the terms of the partnership agreement.   Therefore, Residual profit = D34,000 - D13,000   = D21,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>7", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions below  Attama and Wawa were in partnership sharing profits and losses in the ratio 4:3. Attama was entitled to salary of D 13,000 per annum.  A net profit of D 34,000 was made for the year.    - Attama's share of profit is", "images": [], "options": {"A": "D 21,000", "B": "D 19,428", "C": "D 12,000", "D": "D 9,000"}, "answer": "C", "explanation": "Attama's share of profit = Net profit - Salary   = 34,000 - 13,000   = 21,000   Total ratio = 4+3 = 7   4/7 x 21,000 = D12,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>8", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Reducing balance method charges depreciation as fixed percentage of the", "images": [], "options": {"A": "net book value of asset", "B": "cost of asset", "C": "market value of asset", "D": "accumulated depreciation on asset"}, "answer": "A", "explanation": "The reducing balance method of depreciation charges depreciation as a fixed percentage of the net book value of the asset. The net book value of an asset is the original cost of the asset minus accumulated depreciation. This method results in higher depreciation expense in the earlier years of an asset's life and lower expense in the later years.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>9", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Goods returned to supplier is recorded in the account as: debit", "images": [], "options": {"A": "Sales Return Account; Credit Supplier's Account", "B": "Purchases Returns Account; credit Supplier's Account", "C": "Supplier's Account; credit Purchase Returns Account", "D": "Supplier's Account ; Credit Purchases Account"}, "answer": "C", "explanation": "when the goods are returned to the supplier, then the cash account will be debited with a corresponding credit to purchase return account as there is the return of the goods out of the company to the supplier", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>10", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Net profit of a sole proprietor is transferred to the", "images": [], "options": {"A": "profit and loss account", "B": "profit and loss appropriation account", "C": "capital account", "D": "drawings account"}, "answer": "C", "explanation": "The net profit of a sole proprietor is transferred to the capital account. This is because the profit increases the owner's equity in the business, which is represented by the capital account. The profit and loss account is used to calculate the net profit, not to store it. The profit and loss appropriation account is used in partnerships and corporations, not sole proprietorships. The drawings account represents the owner's withdrawals from the business, not the profits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>11", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "Accounting evolved out of the need of businesses for", "images": [], "options": {"A": "profit making", "B": "record keeping", "C": "increasing sales", "D": "obtaining finance"}, "answer": "B", "explanation": "Accounting evolved primarily out of the need for record keeping. Businesses need to keep track of their financial transactions, assets, liabilities, and other financial information. This is done through accounting, which involves the systematic and comprehensive recording of financial transactions pertaining to a business. While profit making, increasing sales, and obtaining finance are important aspects of a business, they are not the primary reasons why accounting evolved.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>12", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Sales account was undercast by GH⊄ 1,000. When this is corrected, both the gross profit and the net profit would", "images": [], "options": {"A": "increase by GH⊄ 2,000", "B": "increase by GH⊄ 1,000", "C": "decrease by GH⊄ 1,000", "D": "decrease by GH⊄ 2,000"}, "answer": "B", "explanation": "An amount is said to be Understated or undercasted if a reported amount is not correct and the reported amount is less than the actual amount. The accountant needs to reverse the amount of the incorrect entry. New calculations will be needed to help in determining the correct amount to enter into accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>13", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Use the following information to answer questions below  \tLe\tSales for the year\t450000\tPurchases for the year\t230000\tOpening stock\t60000\tClosing stock\t40000\t    -The stock turnover period is", "images": [], "options": {"A": "88 days", "B": "73 days", "C": "58 days", "D": "41 days"}, "answer": "B", "explanation": "The stock turnover period is calculated by dividing the average stock by the cost of goods sold and then multiplying by 365. The average stock is calculated by adding the opening and closing stock and dividing by 2. In this case, the average stock is (60000+40000)/2 = 50000. The cost of goods sold is calculated by adding the opening stock to purchases and subtracting the closing stock. In this case, the cost of goods sold is 60000+230000-40000 = 250000. Therefore, the stock turnover period is (50000/250000)*365 = 73 days.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>14", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer questions below  \tLe\tSales for the year\t450000\tPurchases for the year\t230000\tOpening stock\t60000\tClosing stock\t40000\t  - The mark-up is", "images": [], "options": {"A": "88%", "B": "80%", "C": "44.44%", "D": "26.67%"}, "answer": "B", "explanation": "The mark-up is calculated by subtracting the cost of goods sold from the sales and then dividing by the cost of goods sold. In this case, the mark-up is (450000-250000)/250000 = 0.8 or 80%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>15", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "Company as a legal entity means that it", "images": [], "options": {"A": "must always have a company lawyer", "B": "can sue and be sued", "C": "must settle disputes among shareholders in court", "D": "should prepare accounts approved by a laywer"}, "answer": "B", "explanation": "A company as a legal entity means it has a separate legal personality distinct from its members. This means it can sue and be sued in its own name. This is a fundamental concept in corporate law known as the 'corporate veil'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>16", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "The type of stock recorded in the trading account of a manufacturing business is", "images": [], "options": {"A": "raw materials", "B": "work-in-progress", "C": "consumables", "D": "finished goods"}, "answer": "D", "explanation": "In the trading account of a manufacturing business, the type of stock recorded is the finished goods. This is because the trading account is concerned with the cost of goods sold and sales, and the cost of goods sold is calculated based on the cost of finished goods that have been sold.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>17", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Account of fixed assets are kept in the", "images": [], "options": {"A": "purchase ledger", "B": "private ledger", "C": "sales ledger", "D": "general ledger"}, "answer": "D", "explanation": "Fixed assets are long-term tangible assets that a company owns and uses in its operations to generate income. They are not expected to be consumed or converted into cash within a year. Fixed assets are recorded in the General Ledger under property, plant, and equipment (PP&E). The General Ledger is the master set of accounts that summarize all transactions occurring within an entity. Therefore, the account of fixed assets are kept in the general ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>18", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Recurrent expenditure of a local government include", "images": [], "options": {"A": "erection of market stalls", "B": "repayment of loans", "C": "purchase of office equipment", "D": "purchase of office stationery"}, "answer": "D", "explanation": "Recurrent expenditure refers to payments made by governments or organizations for all purposes within their normal services. These include salaries, maintenance, interest on loans, and other operating expenses. The purchase of office stationery falls under this category as it is a regular and necessary expense for the functioning of the office. Therefore, recurrent expenditure of a local government includes the purchase of office stationery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>19", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The accounting principle of double entry states that", "images": [], "options": {"A": "debit the giver and credit the receiver", "B": "assets must be equal to capital plus liabilities", "C": "every debit entry must have a corresponding credit entry", "D": "debit entries increases liabilities while credit entries increase assets"}, "answer": "C", "explanation": "The principle of double entry in accounting states that for every financial transaction, equal and opposite effects are recorded in at least two different accounts. This means that every debit entry must have a corresponding credit entry. This principle is the basis of the accounting equation that states that assets = liabilities + equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>20", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "Lima paid off debt of D 2,500 owed to Dongo by cash. The entries in Lima's books are debit", "images": [], "options": {"A": "Cash D 2,500; credit Dongo D 2,500", "B": "Dongo D 2,500; credit Cash D 2,500", "C": "Bad Debt D 2,500; credit Dongo D 2,500", "D": "Dongo D 2,500; credit Bad Debt D 2,500"}, "answer": "B", "explanation": "When Lima pays off a debt, it means that Lima's cash account decreases and the liability to Dongo also decreases. In accounting, a decrease in an asset (cash) is credited and a decrease in a liability (debt to Dongo) is debited. Therefore, the correct entries in Lima's books would be to debit Dongo D 2,500 and credit Cash D 2,500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>21", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "The petty cash account has an imprest of GH⊄ 36,000 and a debit balance of GH⊄ 10,000 at the end of the month. The reimbursement required would be", "images": [], "options": {"A": "GH⊄ 46,000", "B": "GH⊄ 36,000", "C": "GH⊄ 26,000", "D": "GH⊄ 10,000"}, "answer": "C", "explanation": "The imprest system is a form of financial accounting system. The base amount (imprest) is decided by the custodian to spend for a certain period, typically a week or month. At the end of the period, the custodian is reimbursed by the amount spent to bring the fund back to the base amount. In this case, the base amount is GH⊄ 36,000 and the amount spent (debit balance) is GH⊄ 10,000. Therefore, the reimbursement required would be GH⊄ 36,000 - GH⊄ 10,000 = GH⊄ 26,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>22", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Commercial activities undertaken by social club to raise funds include", "images": [], "options": {"A": "donation", "B": "bar", "C": "grant", "D": "subscription"}, "answer": "B", "explanation": "Commercial activities are activities that a business or organization undertake to generate revenue. In the context of a social club, commercial activities could include selling goods or services. In the given options, 'bar' could be considered a commercial activity as it involves selling drinks to members or guests to generate revenue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>23", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "The final stage of accounting process is", "images": [], "options": {"A": "interpretation", "B": "recording", "C": "reporting", "D": "summarizing"}, "answer": "C", "explanation": "Reporting is the final stage of accountinh process because after the recording, summarizing, analysis and interpreting of financial statement has been done, Reporting to the internal users such as shareholders, Board of directors and management should be done.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>24", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The value of goods sent to branch is debited to the", "images": [], "options": {"A": "Goods sent to Branch Account", "B": "Branch Debtors Account", "C": "Branch Adjustment Account", "D": "Branch Stock Account"}, "answer": "D", "explanation": "Goods sent to the branch is Debited to Branch stock account, Credit Goods sent to branch account and Branch adjustment/mark-up account", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>25", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "The major source of revenue for central/federal government is", "images": [], "options": {"A": "tenement rate", "B": "excise duty", "C": "market toll", "D": "parking toll"}, "answer": "B", "explanation": "The major source of revenue for the central or federal government is excise duty. Excise duty is a tax imposed on goods for their production, licensing or sale within the country. It is an indirect tax that is included in the price of the product and is paid by the consumer. Other sources like tenement rate, market toll, parking toll are minor sources and are usually collected by local government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>26", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : RELATIONSHIP BETWEEN MARK UP AND MARGIN", "question": "A business includes 50% mark-up on all its products. This would mean margin of", "images": [], "options": {"A": "66 2/3 %", "B": "66 1/3%", "C": "33 2/3%", "D": "33 1/3%"}, "answer": "D", "explanation": "Convert Mark-up to margin = 50%   50/100 = 1/2   1/ 2+1 = 1/3   = 100/3   = 33 1/3%", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>27", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer questions below  \tGH⊄\tGross profit\t50400\tDiscount received\t3300\tDiscount allowed\t2500\tNet profit \t26500\tCost of goods sold\t184000\t    - Sales for the period is", "images": [], "options": {"A": "GH⊄ 234,400", "B": "GH⊄ 210,500", "C": "GH⊄ 133, 600", "D": "GH⊄ 76,900"}, "answer": "A", "explanation": "Sales for the period is calculated by adding the Gross Profit to the Cost of Goods Sold. Gross Profit is the difference between the Sales and the Cost of Goods Sold. Therefore, Sales = Gross Profit + Cost of Goods Sold = 50400 + 184000 = GH⊄ 234,400.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>28", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer questions below  \tGH⊄\tGross profit\t50400\tDiscount received\t3300\tDiscount allowed\t2500\tNet profit \t26500\tCost of goods sold\t184000\t- Other operating expenses for the period is", "images": [], "options": {"A": "GH⊄ 27,300", "B": "GH⊄ 25,700", "C": "GH⊄ 24,700", "D": "GH⊄ 23,900"}, "answer": "C", "explanation": "Other operating expenses = (50400 +3300) -(26500 +2500)  = 53700 - 2900  = GH24700", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>29", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "All cash transactions of a not-for-profit making organization are recorded in", "images": [], "options": {"A": "three-column cash book", "B": "income and expenditure account", "C": "subscription account", "D": "receipts and payments account"}, "answer": "D", "explanation": "All cash transactions of a not-for-profit making organization are recorded in the 'Receipts and Payments Account'. This account is a summary of all cash transactions (both receipts and payments) of a non-profit organization for a particular period. It is similar to a cash book of a profit-making organization, which records all cash inflows and outflows.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>30", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Subsidiary books of account are used to record transactions", "images": [], "options": {"A": "made in the same period", "B": "of a similar nature", "C": "involving minor amounts", "D": "without source documents"}, "answer": "B", "explanation": "Subsidiary books of account are used to record transactions 'of a similar nature'. They are special journals that are used to record specific types of transactions that occur frequently. For example, a sales journal is used to record all sales on credit, a purchases journal is used to record all purchases on credit, etc. This helps in reducing the volume of entries in the ledger and assists in better organization of records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>31", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "Members of a not -for -profit making organization", "images": [], "options": {"A": "earn dividend on their contributions", "B": "do not receive surplus at the end of the year", "C": "are paid interest on their contribution", "D": "share profits according to their contributions"}, "answer": "B", "explanation": "Members of a not-for-profit organization do not receive surplus at the end of the year. Not-for-profit organizations are established for public or mutual benefits other than the pursuit or accumulation of profits for owners or investors. The surplus (if any) is usually reinvested in the organization to further achieve its mission or purpose, rather than being distributed to owners or investors as in a for-profit entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>32", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "Accounting information that is useful for the intended purpose and would make a difference in decision making is", "images": [], "options": {"A": "comparable", "B": "consistent", "C": "relevant", "D": "reliable"}, "answer": "C", "explanation": "Accounting information is considered relevant if it would be useful in influencing a decision. It should be capable of making a difference in decision-making by helping users to form predictions about the outcomes of past, present or future events, or to confirm or correct expectations. It's not about being comparable, consistent or reliable, although these are also important qualities of good accounting information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>33", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Manufacturing account is prepared to determine the", "images": [], "options": {"A": "cost of goods sold", "B": "cost of goods produced", "C": "profit on goods produced", "D": "value of work-in-progress"}, "answer": "B", "explanation": "A manufacturing account is prepared to determine the cost of goods produced. It is a statement that shows the various manufacturing costs that are incurred by a business. The total of these costs gives the cost of goods produced during the period. This is different from the cost of goods sold, which is the cost of the actual goods sold during the period, not just those produced. The profit on goods produced and the value of work-in-progress are not the primary purposes of a manufacturing account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>34", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that enables a business to determine the actual profit or loss for a particular period is", "images": [], "options": {"A": "accrual concept", "B": "business entity concept", "C": "consistency concept", "D": "going concern concept"}, "answer": "A", "explanation": "The accrual concept is the accounting principle that enables a business to determine the actual profit or loss for a particular period. This concept states that revenues and expenses are recorded when they are earned or incurred, not when the money is received or paid. This allows for a more accurate reflection of the financial performance of a business over a specific period. The business entity concept separates the business from its owners, the consistency concept requires that the same accounting methods are used from period to period, and the going concern concept assumes that the business will continue to operate indefinitely. None of these other concepts directly enable a business to determine the actual profit or loss for a particular period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>35", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "An amount set aside out of profit for a specific purpose is a", "images": [], "options": {"A": "reserve", "B": "liability", "C": "provision", "D": "discount"}, "answer": "A", "explanation": "A reserve is an amount that is set aside out of profits for a specific purpose. It is a part of the profits of a business that is set aside to strengthen the business's financial position or for future use. It is not an obligation like a liability, it is not a provision which is a liability of uncertain timing or amount, and it is not a discount which is a reduction in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>36", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer questions below  \t#\tCreditors (01/01/19)\t223000\tCreditors(31/12/19)\t316000\tCredit purchases\t1426000\tDiscount received\t64000\tCompany's cheque dishonoured\t90000\t    - Payment to creditors is", "images": [], "options": {"A": "#1,423,000", "B": "#1,359,000", "C": "#1,333,000", "D": "#1,295,000"}, "answer": "B", "explanation": "Payment to creditors can be calculated using the formula: Opening Creditors + Credit Purchases - Discount Received - Closing Creditors. Substituting the given values, we get: 223000 + 1426000 - 64000 - 316000 = 1359000. Therefore, the payment to creditors is #1,359,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>37", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer questions below  \t#\tCreditors (01/01/19)\t223000\tCreditors(31/12/19)\t316000\tCredit purchases\t1426000\tDiscount received\t64000\tCompany's cheque dishonoured\t90000\t    - Amount owed to creditors on 31/12/19 is", "images": [], "options": {"A": "#406,000", "B": "#342,000", "C": "#316,000", "D": "#226,000"}, "answer": "C", "explanation": "The amount owed to creditors on 31/12/19 is given in the question as 316,000. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>38", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The objective of preparing departmental accounts is to determine the", "images": [], "options": {"A": "sales of each department", "B": "total cost attributed to each department", "C": "capital employed by each department", "D": "profitability of each department"}, "answer": "D", "explanation": "The objective of preparing departmental accounts is to determine the profitability of each department. This is because the profitability of a department is a key indicator of its performance and can help in decision making. Therefore, the correct answer is option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>39", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "The partner who partakes in the management of the firm and assumes personal responsibility for the firm's debts is a", "images": [], "options": {"A": "general partner", "B": "sleeping partner", "C": "quasi partner", "D": "limited partner  ."}, "answer": "A", "explanation": "A general partner is a partner who is actively involved in the day-to-day operations of the business and has unlimited liability for the debts and obligations of the partnership. This means they are personally responsible for the firm's debts. A sleeping partner is one who invests capital into the business but does not participate in its management. A quasi partner is a person who, although not officially a partner, is treated as such. A limited partner is a partner whose liability is limited to the extent of their investment in the firm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2021>40", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Acid test ratio of a firm measures the", "images": [], "options": {"A": "profitability of a firm", "B": "capital adequacy of a firm", "C": "liquidity of a firm", "D": "quality of debtors of a firm"}, "answer": "C", "explanation": "The acid test ratio, also known as the quick ratio, measures a company's ability to meet its short-term obligations with its most liquid assets. It is a measure of liquidity. The profitability of a firm is measured by ratios such as the net profit margin or return on investment. The capital adequacy of a firm is measured by ratios such as the debt-to-equity ratio. The quality of debtors of a firm is not typically measured by a specific ratio, but rather by assessing the creditworthiness of the debtors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>41", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer questions below    Cost of asset (01/01/18) = #600,000  Annual depreciation charge is 15% on reducing balance basis.    - Depreciation for the year 2019 is", "images": [], "options": {"A": "#180,000", "B": "#166,500", "C": "#90,000", "D": "#76,500"}, "answer": "D", "explanation": "Annual Depreciation charge = 15%    Cost = #600,000      1st depreciation(2018) = 15% x 600,000   = 90,000     NBV 600,000 - 90,000   = 510,000      2nd depreciation(2019) = 15% x 510,000   = 76,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>42", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer questions below    Cost of asset (01/01/18) = #600,000  Annual depreciation charge is 15% on reducing balance basis.    - The net book value of the asset at 31/12/19 is", "images": [], "options": {"A": "#523,500", "B": "#510,000", "C": "#433,500", "D": "#420,000"}, "answer": "C", "explanation": "NBV = cost - depreciation   = 510,000 - 76,500   = 433,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2021>43", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Wages accrued is shown in the balance sheet as", "images": [], "options": {"A": "an asset", "B": "an income", "C": "an expense", "D": "a liability"}, "answer": "D", "explanation": "Wages accrued refers to the amount of wages that a company has earned but has not yet paid. In accounting, this is considered a liability because it is an obligation that the company has to pay in the future. Therefore, it is shown in the balance sheet as a liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>44", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Provision is made in the accounts when the amount in the anticipated loss is", "images": [], "options": {"A": "too much", "B": "not significant", "C": "not certain", "D": "well known"}, "answer": "C", "explanation": "A provision is an amount set aside to cover an anticipated future liability. It is made when the amount of the anticipated loss is not certain. This is because the provision is an estimate, and the actual amount of the liability may be different from the estimated amount. Therefore, a provision is made when the amount of the anticipated loss is not certain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>45", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Accounting concepts are rules of accounting which are to be", "images": [], "options": {"A": "taught in all accounting classes", "B": "implemented by all professional bodies", "C": "followed in the preparation of financial statements", "D": "applied in correction of business errors"}, "answer": "C", "explanation": "Accounting concepts are rules of accounting that are to be followed in the preparation of financial statements. They provide a framework for how financial transactions and events should be recorded and reported.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>46", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer questions below  \tGH⊄\tMonthly Rent payable\t3000\tRent paid on 01/01/2018\t48000\t    - Rent expenses for 2018 was", "images": [], "options": {"A": "GH⊄ 84,000", "B": "GH⊄ 48,000", "C": "GH⊄ 36,000", "D": "GH⊄ 12,000"}, "answer": "C", "explanation": "The total rent expenses for the year 2018 is calculated by multiplying the monthly rent payable by 12. The amount paid on 01/01/2018 is irrelevant to this calculation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>47", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer questions below  \tGH⊄\tMonthly Rent payable\t3000\tRent paid on 01/01/2018\t48000\t  - The balance of rent in the balance sheet would be", "images": [], "options": {"A": "current asset of GH⊄ 36,000", "B": "current asset of GH⊄ 12,000", "C": "current liability of GH⊄ 12,000", "D": "current liability of GH⊄ 48,000"}, "answer": "C", "explanation": "The rent paid on 01/01/2018 is GH⊄ 48,000 which covers 16 months (48000/3000). This means that by the end of 2018, 12 months rent would have been used up and 4 months worth of rent (GH⊄ 12,000) would still be prepaid. Prepaid rent is a type of deferred expense that is paid in advance and gradually used up or 'expensed' through the passage of time or through use and consumption. In this case, the prepaid rent is a liability because it is an obligation to provide services in the future.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>48", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "SUSPENSE ACCOUNT : ERRORS THAT WILL AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "Suspense account is used in the correction of", "images": [], "options": {"A": "all errors in the trial balance", "B": "errors that affect the agreement of a trial balance", "C": "errors that do not affect the agreement of a trial balance", "D": "errors that affect the accuracy of the net profit"}, "answer": "B", "explanation": "A suspense account is a temporary account used in accounting to record discrepancies found in a trial balance. It is used when the total debits do not equal the total credits. The difference is recorded in the suspense account, and once the error is found, the suspense account is debited or credited to balance the accounts. Therefore, a suspense account is used in the correction of errors that affect the agreement of a trial balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>49", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A transaction that would cause the cash book balance to be less than the bank statement is", "images": [], "options": {"A": "direct debit", "B": "standing order", "C": "bank charges", "D": "unpresented cheques"}, "answer": "D", "explanation": "Unpresented cheques are cheques issued out but yet to be presented to the bank for collection. The effect is that the cash book will show lower balance while the bank statement will show greater balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2021>50", "subject": "Accounts", "year": "2021", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "The cost of goods sold for the year is Le 200,000 and the mark-up is 30%. The sale for the year is", "images": [], "options": {"A": "Le 260,000", "B": "Le 200,000", "C": "Le 140,000", "D": "Le 60,000"}, "answer": "A", "explanation": "The cost of goods sold (COGS) is the cost of producing the goods sold during a specific period. Mark-up is the amount added to the cost price of goods to cover overheads and profit. If the COGS is Le 200,000 and the mark-up is 30%, it means that the selling price is 130% of the cost price. Therefore, the sales for the year would be 130/100 * 200,000 = Le 260,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>1", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "The user of accounting information who is responsible for overall performance of the business is the", "images": [], "options": {"A": "director", "B": "customer", "C": "shareholder", "D": "employee"}, "answer": "A", "explanation": "The director of a company is responsible for the overall performance of the business. They make decisions that affect the company's operations and financial standing. Customers, shareholders, and employees are also users of accounting information, but they are not responsible for the overall performance of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>2", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Use the information to answer questions below  Years\tCurrent Assets\tLiabilities\tFixed Assets\tCapital\t\t#\t#\t#\t#\t2018\t52550\t78600\t127450\tX\t2017\t41650\t53220\tY\t116780\t    The letter X represents", "images": [], "options": {"A": "#258,600", "B": "#180,000", "C": "#101,400", "D": "#78,600"}, "answer": "C", "explanation": "X (Capital) = Total Assets - Total Liabilities     = (52,550 + 127,450) - 78,600     = 180,000 - 78,600     = 101,400", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>3", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Use the information to answer questions below  Years\tCurrent Assets\tLiabilities\tFixed Assets\tCapital\t\t#\t#\t#\t#\t2018\t52550\t78600\t127450\tX\t2017\t41650\t53220\tY\t116780\t   The letter Y represents", "images": [], "options": {"A": "#211,650", "B": "#170,000", "C": "#128,350", "D": "#94,870"}, "answer": "C", "explanation": "Y (Fixed Assets) = Capital + Liabilities - Current Assets     = 116,780 + 53,220 - 41,650     = 170,000 - 41,650     = 128,350", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>4", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "MISCELLANEOUS ACCOUNTS : CONSIGNMENT ACCOUNTS", "question": "The document prepared by the buyer and sent to the seller listing the items to be supplied is", "images": [], "options": {"A": "sales order", "B": "proforma invoice", "C": "credit note", "D": "purchase order"}, "answer": "D", "explanation": "The document prepared by the buyer and sent to the seller listing the items to be supplied is a purchase order. A purchase order is a commercial document and first official offer issued by a buyer to a seller, indicating types, quantities, and agreed prices for products or services. It is used to control the purchasing of products and services from external suppliers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>5", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Adiza gave an instruction to her banker to pay a premium of Le 30,000 from her account to Union Rock Insurance on a quarterly basis for a policy. This instruction is an example of", "images": [], "options": {"A": "credit transfer", "B": "direct debit", "C": "standing order", "D": "bank charges"}, "answer": "C", "explanation": "A standing order is a type of automatic payment where a person instructs their bank to pay a fixed amount to another account regularly. In this case, Adiza has instructed her bank to pay a premium of Le 30,000 to Union Rock Insurance on a quarterly basis, which is a standing order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>6", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "Books of accounts are opened by the use of", "images": [], "options": {"A": "general journal", "B": "general ledger", "C": "balance sheet", "D": "trial balance"}, "answer": "A", "explanation": "Journal is a prime entry into which transactions are entered on a daily basis. The journal is used to correct errors, recording entry transactions etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>7", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "The principal book of account where accounts are classified and summarized is", "images": [], "options": {"A": "journal", "B": "ledger", "C": "trial balance", "D": "balance sheet"}, "answer": "B", "explanation": "The ledger is the principal book of account where accounts are classified and summarized. In accounting, the ledger is the core component of any financial system. It is the book in which all the accounts (assets, liabilities, equity, revenue, and expenses) are maintained in a summarized way. The journal is the book of original entry where transactions are recorded chronologically. The trial balance is a statement, not a book, that shows the balances of all ledger accounts at a particular time. The balance sheet is a financial statement that shows the financial position of a business at a particular time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>8", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS", "question": "The entries for cash drawn from the bank by a proprietor for the private use is: debit", "images": [], "options": {"A": "Cash Account; credit Bank Account", "B": "Bank Account; credit Cash Account", "C": "Drawings Account; credit Bank Account", "D": "Cash Account; credit Drawings Account"}, "answer": "C", "explanation": "When cash is drawn from the bank by a proprietor for private use, the Drawings Account is debited and the Bank Account is credited. In accounting, 'Drawings' refers to the money withdrawn by the owner of the business for personal use. It reduces the capital of the business. The Bank Account is credited because the bank balance decreases when cash is withdrawn. The rule applied here is 'Debit the receiver, Credit the giver'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>9", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer questions below  \t$\tCash book balance (credit)\t750\tUncredited cheques \t500\tUnpresented cheques\t1680\tDirect credit\t300\tBank charges\t150\t     The adjusted cash book balance is", "images": [], "options": {"A": "$ 1,200 Cr", "B": "$ 900 Cr", "C": "$ 600 Cr", "D": "$ 300 Cr"}, "answer": "B", "explanation": "The adjusted cash book balance is calculated by adding the direct credit and subtracting the bank charges from the cash book balance. So, $750 + $300 - $150 = $900 Cr.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>10", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer questions below  \t$\tCash book balance (credit)\t750\tUncredited cheques \t500\tUnpresented cheques\t1680\tDirect credit\t300\tBank charges\t150\t   Balance as per bank statement is", "images": [], "options": {"A": "$ 1,480 Cr.", "B": "$ 580 Cr.", "C": "$ 430 Cr.", "D": "$ 430 Dr."}, "answer": "D", "explanation": "The balance as per bank statement is calculated by subtracting the unpresented cheques and adding the uncredited cheques from the cash book balance. So, $750 - $1680 + $500 = -$430. Since it's a negative balance, it's a debit balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>11", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which states that expenditure involving insignificant amounts should be regarded as expenses and not assets is", "images": [], "options": {"A": "business entity concept", "B": "materiality concept", "C": "dual aspect concept", "D": "realization concept"}, "answer": "B", "explanation": "The 'materiality concept' in accounting states that all significant items must be reported in the financial statements. However, items of insignificant value need not be reported separately. They can be regarded as expenses and not assets. This concept helps in maintaining a balance between the cost and benefit of providing information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>12", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Resources owned and controlled by a business are classified as", "images": [], "options": {"A": "capital", "B": "assets", "C": "liabilities", "D": "drawings"}, "answer": "B", "explanation": "Resources owned and controlled by a business are classified as 'assets'. Assets are resources or things of value that are owned by a company. They can be tangible or intangible. Tangible assets are physical items, like buildings, trucks, or equipment. Intangible assets, on the other hand, are non-physical resources and rights that have value, such as trademarks and patents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>13", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Items shown in the balance sheet as asset includes", "images": [], "options": {"A": "credit balance on a supplier's account", "B": "credit balance on the capital's account", "C": "debit balance on a customer's account", "D": "debit balance on drawings account"}, "answer": "C", "explanation": "Assets are resources owned by a business that can be converted into cash or used to generate income. A debit balance on a customer's account is considered an asset because it represents money owed to the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>14", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Use the following information to answer questions below    A trader bought goods worth #16,000 and sold three-quarter of it for #20,000    The gross profit is", "images": [], "options": {"A": "#12,000", "B": "#8,000", "C": "#6,000", "D": "#4,000"}, "answer": "B", "explanation": "Gross profit is calculated by subtracting the cost of goods sold from the total revenue. In this case, the cost of the goods sold is three-quarter of #16,000, which is #12,000. Therefore, the gross profit is #20,000 - #12,000 = #8,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>15", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer questions below    A trader bought goods worth #16,000 and sold three-quarter of it for #20,000      The margin would be", "images": [], "options": {"A": "2/3", "B": "1/5", "C": "1/2", "D": "2/5"}, "answer": "D", "explanation": "Margin=Selling price- Cost priceSelling price  =20000-1200020,000  = 8000/20000     = 2/5", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>16", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS", "question": "An increase in provision for doubtful debts would result in", "images": [], "options": {"A": "decrease in gross profit", "B": "increase in gross profit", "C": "decrease in net profit", "D": "increase in net profit"}, "answer": "C", "explanation": "Provision for doubtful debts is an expense that is set aside to cover potential losses from customers who may not pay their debts. An increase in this provision would mean that the company expects more losses, which would decrease the net profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>17", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer questions below    Kako Ltd bought a machine for D 1,200,000 on 1st January 2018. Depreciation was provided annually at a rate of 10% using the diminishing balance method. The machine was sold for D 880,000 on 31st December 2021.    The accumulated depreciation as at the date of disposal was", "images": [], "options": {"A": "D 480,000", "B": "D 412,680", "C": "D 325,200", "D": "D 320,000"}, "answer": "B", "explanation": "The accumulated depreciation is calculated using the diminishing balance method. The depreciation for each year is calculated by applying the depreciation rate to the net book value of the asset. The total accumulated depreciation as at the date of disposal is the sum of the depreciation for each year.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2022>18", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer questions below    Kako Ltd bought a machine for D 1,200,000 on 1st January 2018. Depreciation was provided annually at a rate of 10% using the diminishing balance method. The machine was sold for D 880,000 on 31st December 2021.      The net book value of the machine in the balance sheet as at 31st December 2020 was", "images": [], "options": {"A": "D 1,080,000", "B": "D 972,000", "C": "D 874,800", "D": "D 787,320"}, "answer": "C", "explanation": "The net book value of the machine is calculated by subtracting the accumulated depreciation from the cost of the asset. The accumulated depreciation as at 31st December 2020 is the sum of the depreciation for the years 2018, 2019 and 2020.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2022>19", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer questions below    Kako Ltd bought a machine for D 1,200,000 on 1st January 2018. Depreciation was provided annually at a rate of 10% using the diminishing balance method. The machine was sold for D 880,000 on 31st December 2021.      The profit or loss on disposal of the machine was", "images": [], "options": {"A": "D 320,000 loss", "B": "D 280,000 profit", "C": "D 92,680 profit", "D": "D 87,480 loss"}, "answer": "C", "explanation": "From 2018 to 2021 (accounting year) is four (4) years   \tD\tCost\t1200000\tYear 1 ( 10% x 1200000)\t 120000 \t\t1080000\tYear 2 ( 10% x 1080000)\t 108000 \t\t972000\tYear 3 ( 10% x 972000)\t 97200  \t\t874800\tYear 4 (10%  x 874800) 87480 787320    Accumulated depreciation = 1,200,000 - 787320  = D412680    Profit or loss = Selling price - Book value at diposal  = 880000 - 787320  = 92680 profit", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2022>20", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Manufacturing account is prepared to ascertain", "images": [], "options": {"A": "profit on goods produced", "B": "cost of goods produced", "C": "cost of goods sold", "D": "profit on goods sold"}, "answer": "B", "explanation": "A manufacturing account is prepared to ascertain the cost of goods produced. It includes the cost of raw materials, direct labor, and manufacturing overheads. The cost of goods sold and profit on goods sold or produced are determined in the trading and profit and loss account, not the manufacturing account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>21", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer questions below  \tLe\tRaw materials:\t\tStock (01/01/2017)\t822000\tStock (31/12/2017)\t560000\tPurchases\t125000\tReturns of raw materials\t15000\t    The cost of raw materials available for production is", "images": [], "options": {"A": "Le 947,000", "B": "Le 932,000", "C": "Le 402,000", "D": "Le 372,000"}, "answer": "B", "explanation": "The cost of raw materials available for production is calculated by adding the initial stock of raw materials to the purchases made during the year and then subtracting any returns of raw materials. In this case, the calculation would be 822000 (initial stock) + 125000 (purchases) - 15000 (returns) = 932000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>22", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer questions below  \tLe\tRaw materials:\t\tStock (01/01/2017)\t822000\tStock (31/12/2017)\t560000\tPurchases\t125000\tReturns of raw materials\t15000\t     The cost of raw materials consumed is", "images": [], "options": {"A": "Le 947,000", "B": "Le 932,000", "C": "Le 402,000", "D": "Le 372,000"}, "answer": "D", "explanation": "The cost of raw materials consumed is calculated by taking the cost of raw materials available for production and subtracting the final stock of raw materials. In this case, the calculation would be 932000 (cost of raw materials available for production) - 560000 (final stock) = 372000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>23", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "One of the items on the debit side of sales ledger control account is", "images": [], "options": {"A": "bills accepted by debtors", "B": "bills dishonoured by debtors", "C": "returns inwards", "D": "bad debt"}, "answer": "B", "explanation": "Items on the debit side of the sales ledger control account are: Sales credit, interest charges, dishonoured bill, carriage outwards, discounts disallowed, debit note issued, service charges.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>24", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The sales ledger contains accounts of", "images": [], "options": {"A": "trade debtors", "B": "credit sales", "C": "trade creditors", "D": "cash sales"}, "answer": "A", "explanation": "The sales ledger contains accounts of trade debtors. Trade debtors are customers who owe the business money for goods or services provided on credit. The sales ledger is used to keep track of these debts, with each debtor having their own individual account within the ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>25", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer below  \tGH⊄\tSales\t200000\tPurchase\t170000\tOpening stock\t40000\tClosing stock\t50000\t    The gross profit percentage is", "images": [], "options": {"A": "25%", "B": "20%", "C": "15%", "D": "10%"}, "answer": "B", "explanation": "Gross Profit = Sales - Cost of Goods Sold (COGS). COGS = Opening Stock + Purchases - Closing Stock. So, COGS = 40000 + 170000 - 50000 = 160000. Gross Profit = 200000 - 160000 = 40000. Gross Profit Percentage = (Gross Profit / Sales) * 100 = (40000 / 200000) * 100 = 20%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>26", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer below  \tGH⊄\tSales\t200000\tPurchase\t170000\tOpening stock\t40000\tClosing stock\t50000\t     Stock turnover ratio is", "images": [], "options": {"A": "4 times", "B": "3.78 times", "C": "3.56 times", "D": "3.2 times"}, "answer": "C", "explanation": "Stock Turnover Ratio = COGS / Average Stock. Average Stock = (Opening Stock + Closing Stock) / 2 = (40000 + 50000) / 2 = 45000. So, Stock Turnover Ratio = 160000 / 45000 = 3.56 times.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>27", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS", "question": "Provision for doubtful debts is made in conformity with", "images": [], "options": {"A": "materiality concept", "B": "prudence concept", "C": "money measurement concept", "D": "business entity concept"}, "answer": "B", "explanation": "The provision for doubtful debts is made in conformity with the prudence concept. The prudence concept in accounting means that expenses and liabilities should be recognized as soon as they are incurred but revenues should only be recognized when they are assured. Therefore, when there is a possibility of bad debts, it is prudent to make a provision for such doubtful debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>28", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Subscription in advance is treated in the balance sheet under", "images": [], "options": {"A": "current liabilities", "B": "current assets", "C": "accumulated fund", "D": "long-term liabilities"}, "answer": "A", "explanation": "Subscription in advance is treated in the balance sheet under current liabilities. This is because it represents the amount received by an organization for a service or product that it has not yet delivered or provided. It is a liability because the organization has an obligation to provide the service or product in the future.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>29", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "In the balance sheet of not-for-profit making organizations, subscription in arrears is shown under", "images": [], "options": {"A": "fixed assets", "B": "long-term liabilites", "C": "current assets", "D": "current liabilities"}, "answer": "C", "explanation": "Subscription in arrears is the sum of money due from members for a particular year but which has not been paid for that year. It is treated as current asset in the balance sheet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>30", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A set of rules and procedures guiding the operations of a partnership is called partnership", "images": [], "options": {"A": "seal", "B": "code", "C": "deed", "D": "business"}, "answer": "C", "explanation": "A set of rules and procedures guiding the operations of a partnership is called a partnership deed. A partnership deed, also known as a partnership agreement, is a document that outlines the rights, responsibilities, and obligations of each partner in a partnership. It serves as a guide for the operations of the partnership and helps to prevent misunderstandings and disputes among the partners.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>31", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Drawings made by a partner would be", "images": [], "options": {"A": "credited to current account", "B": "debited to current account", "C": "credited to appropriation account", "D": "debited to appropriation account"}, "answer": "B", "explanation": "Drawings refer to the amount of money or the value of goods which the proprietor or partners have taken from the business for personal use. It is debited to the current account of the partner. This is because when a partner withdraws cash or goods for personal use, it reduces the capital invested in the business. Therefore, it is debited in the partner's current account.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2022>32", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions below    Teteh and Kukuma are in partnership with capital balances of #300,000 and #200,000 respectively. They agreed to share profit on the basis of their capital. The profit for the year is #150,000 and the interest on capital is 5%.    Teteh's share of profit is", "images": [], "options": {"A": "#90,000", "B": "#75,000", "C": "#60,000", "D": "#50,000"}, "answer": "B", "explanation": "Ratio in their capital = 300,000/200,000 = 3/2 = 3: 2   Total ratio = 3+ 2 = 5     Interest on capital = 5%   Teteh = 5% x 300,000 = 15,000   Kukuma = 5% x 200,000 = 10,000     = 150,000 - ( 15,000 + 10,000)   = 150,000 - 25,000   = 125,000     Teteh's share of profit =  3/5 x 125,000     = 75,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>33", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions below    Teteh and Kukuma are in partnership with capital balances of #300,000 and #200,000 respectively. They agreed to share profit on the basis of their capital. The profit for the year is #150,000 and the interest on capital is 5%.      Kukuma's current account balance is", "images": [], "options": {"A": "#90,000", "B": "#70,000", "C": "#60,000", "D": "#50,000"}, "answer": "C", "explanation": "Kukuma's capital is #200,000. The interest on capital at 5% is #200,000 * 5/100 = #10,000. The total capital is #300,000 + #200,000 = #500,000. Kukuma's share of the profit is #150,000 * (#200,000 / #500,000) = #60,000. Therefore, Kukuma's current account balance is #10,000 (interest on capital) + #60,000 (share of profit) = #70,000. But since the question asks for Kukuma's current account balance after the interest on capital has been added, the correct answer is #70,000 + #10,000 = #80,000. However, none of the options matches this answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>34", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer questions below    Teteh and Kukuma are in partnership with capital balances of #300,000 and #200,000 respectively. They agreed to share profit on the basis of their capital. The profit for the year is #150,000 and the interest on capital is 5%.      Teteh's share of interest on capital is", "images": [], "options": {"A": "#75,000", "B": "#25,000", "C": "#15,000", "D": "#10,000"}, "answer": "C", "explanation": "Teteh's capital is #300,000. The interest on capital at 5% is #300,000 * 5/100 = #15,000. Therefore, Teteh's share of interest on capital is #15,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>35", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "An item that would be classified as preliminary expenses in a company's account is", "images": [], "options": {"A": "formation expenses", "B": "general expenses", "C": "administrative expenses", "D": "distribution expenses"}, "answer": "A", "explanation": "Preliminary expenses are the costs related to the formation of a company, such as legal fees, registration fees, etc. Therefore, 'formation expenses' would be classified as preliminary expenses in a company's account. The other options, general expenses, administrative expenses, and distribution expenses, are not specifically related to the formation of a company and hence, are not classified as preliminary expenses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>36", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES", "question": "An item that would be considered a first charge against profit in a company's account is", "images": [], "options": {"A": "general reserve", "B": "capital reserve", "C": "ordinary dividend", "D": "preference dividend"}, "answer": "D", "explanation": "A first charge against profit in a company's account is an expense that is deducted from the company's profit before any other expenses. In this case, 'preference dividend' is considered a first charge against profit because it is a dividend that is paid to preference shareholders before any dividends are paid to ordinary shareholders. The other options, general reserve, capital reserve, and ordinary dividend, are not considered first charges against profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>37", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The maximum amount a company can raise through the issue of shares is", "images": [], "options": {"A": "reserve capital", "B": "authorized capital", "C": "paid-up capital", "D": "loan capital"}, "answer": "B", "explanation": "The maximum amount a company can raise through the issue of shares is its authorized capital. Authorized capital, also known as registered capital, is the maximum amount of share capital that a company is authorized to issue to shareholders. This amount is specified in the company's constitution or articles of association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>38", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "A unit of a company capital  is?", "images": [], "options": {"A": "share", "B": "stock", "C": "premium", "D": "debenture"}, "answer": "A", "explanation": "A unit of a company's capital is a share. A share represents a unit of ownership in a company and constitutes a claim on part of the company's assets and earnings. A stock, on the other hand, is a collection of shares in a company held by an individual or entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>39", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Use the following information to answer questions below    Bola a grocer, keep petty cash on imprest system, the float being GH⊄ 8,000. These transactions took place in January 2018.   \t\tGH⊄\tJanuary 1 \tPetty cash in hand\t1034\tJanuary 1 \tPetty cash to restore float\t6966\tJanuary 6\tBought note books\t656\tJanuary 7\tPaid wages\t1828\tJanuary 14\tBought postage stamps\t750\tJanuary 16\tPaid to Biodun a creditor\t1072\tJanuary 18\tPaid wages\t1856\tJanuary 23\tPurchased envelopes\t874\tJanuary 28\tPurchased postage stamps\t420\t    Amount posted to the personal ledger was", "images": [], "options": {"A": "GH⊄ 6,966", "B": "GH⊄ 3,684", "C": "GH⊄ 1,072", "D": "GH⊄ 1,034"}, "answer": "C", "explanation": "The amount paid to biodun a creditor represent the ledger in the petty cash book which amounted to GH⊄ 1,072", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>40", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Use the following information to answer questions below    Bola a grocer, keep petty cash on imprest system, the float being GH⊄ 8,000. These transactions took place in January 2018.   \t\tGH⊄\tJanuary 1 \tPetty cash in hand\t1034\tJanuary 1 \tPetty cash to restore float\t6966\tJanuary 6\tBought note books\t656\tJanuary 7\tPaid wages\t1828\tJanuary 14\tBought postage stamps\t750\tJanuary 16\tPaid to Biodun a creditor\t1072\tJanuary 18\tPaid wages\t1856\tJanuary 23\tPurchased envelopes\t874\tJanuary 28\tPurchased postage stamps\t420\t     Amount spent on stationery was", "images": [], "options": {"A": "GH⊄ 1,530", "B": "GH⊄ 1,170", "C": "GH⊄ 1,076", "D": "GH⊄ 874"}, "answer": "A", "explanation": "Amount spent on stationery = 656 + 874   = GH⊄ 1530", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>41", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "Use the following information to answer questions below    Bola a grocer, keep petty cash on imprest system, the float being GH⊄ 8,000. These transactions took place in January 2018.   \t\tGH⊄\tJanuary 1 \tPetty cash in hand\t1034\tJanuary 1 \tPetty cash to restore float\t6966\tJanuary 6\tBought note books\t656\tJanuary 7\tPaid wages\t1828\tJanuary 14\tBought postage stamps\t750\tJanuary 16\tPaid to Biodun a creditor\t1072\tJanuary 18\tPaid wages\t1856\tJanuary 23\tPurchased envelopes\t874\tJanuary 28\tPurchased postage stamps\t420\t     Amount reimbursed at the end of the month was", "images": [], "options": {"A": "GH⊄ 8,000", "B": "GH⊄ 7,456", "C": "GH⊄ 6,966", "D": "GH⊄ 6,928"}, "answer": "B", "explanation": "The amount reimbursed at the end of the month is the total of all petty cash expenses incurred during the month. From the given transactions, the total petty cash expenses are GH⊄ 656 (note books) + GH⊄ 1828 (wages) + GH⊄ 750 (postage stamps) + GH⊄ 1072 (paid to Biodun) + GH⊄ 1856 (wages) + GH⊄ 874 (envelopes) + GH⊄ 420 (postage stamps) = GH⊄ 7456. Therefore, the correct answer is GH⊄ 7456.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>42", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE", "question": "One of the items on the credit column of a trial balance is", "images": [], "options": {"A": "carriage inwards", "B": "carriage outwards", "C": "returns outwards", "D": "returns inwards"}, "answer": "C", "explanation": "In a trial balance, items on the credit column represent liabilities, income, and capital. Returns outwards, also known as sales returns, are a deduction from sales in the income statement. They represent goods returned by customers because they are defective, not fit for purpose, or not as described. Therefore, returns outwards is an item that would appear on the credit column of a trial balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>43", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Revenue expenditure of a local government includes purchase of", "images": [], "options": {"A": "theatre equipment", "B": "incubators", "C": "x-ray machine", "D": "drugs"}, "answer": "D", "explanation": "Revenue expenditure refers to the routine, regular, and recurring expenses of a business or government. These expenses are necessary for the daily operations and functions of the business or government. In the context of a local government, revenue expenditure would include the purchase of drugs, as this is a recurring expense necessary for the operation of local government health services. The other options listed (theatre equipment, incubators, x-ray machine) are more likely to be capital expenditures, as they are large, one-time purchases that will be used over a long period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2022>44", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The authority to incur expenditure to address natural disaster is contained in", "images": [], "options": {"A": "virement warrant", "B": "reserved expenditure warrant", "C": "supplementary general warrant", "D": "contingency warrant"}, "answer": "D", "explanation": "A contingency warrant is a type of financial instrument that gives the holder the authority to incur expenditure in the event of an unforeseen event or emergency, such as a natural disaster. This is because a contingency is something that might happen, but is not planned or certain. Therefore, a contingency warrant would be used to address a natural disaster. The other options (virement warrant, reserved expenditure warrant, supplementary general warrant) are not specifically designed for emergency situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>45", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer questions below    Trading Account of Umeh Enterprises for the year ended 31st December 2019   \tGH⊄\t\tGH⊄\tOpening stock \t10000\tSales\t200000\tPurchases\t120000 \tLess: \t(4000) \t\t130000\t\t196000\tClosing stock\t(22800) \t\t\tCost of goods sold\t-----\t\t\tGross profit\t------\t\t\t\t196000\t\t196000\t    The cost of goods sold is", "images": [], "options": {"A": "GH⊄ 152,800", "B": "GH⊄ 107,200", "C": "GH⊄ 88,800", "D": "GH⊄ 43,200"}, "answer": "B", "explanation": "The cost of goods sold is calculated by adding the opening stock and purchases, then subtracting the closing stock. In this case, the COGS is GH⊄ 107,200 (10,000 + 120,000 - 22,800).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>46", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer questions below    Trading Account of Umeh Enterprises for the year ended 31st December 2019   \tGH⊄\t\tGH⊄\tOpening stock \t10000\tSales\t200000\tPurchases\t120000 \tLess: \t(4000) \t\t130000\t\t196000\tClosing stock\t(22800) \t\t\tCost of goods sold\t-----\t\t\tGross profit\t------\t\t\t\t196000\t\t196000\t     The gross profit is", "images": [], "options": {"A": "GH⊄ 152,800", "B": "GH⊄ 107,200", "C": "GH⊄ 88,800", "D": "GH⊄ 43,200"}, "answer": "C", "explanation": "The gross profit is calculated by subtracting the COGS from the sales. In this case, the gross profit is GH⊄ 88,800 (200,000 - 107,200).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>47", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer questions below    Trading Account of Umeh Enterprises for the year ended 31st December 2019   \tGH⊄\t\tGH⊄\tOpening stock \t10000\tSales\t200000\tPurchases\t120000 \tLess: \t(4000) \t\t130000\t\t196000\tClosing stock\t(22800) \t\t\tCost of goods sold\t-----\t\t\tGross profit\t------\t\t\t\t196000\t\t196000\t     The GH⊄ 4,000 on the credit side is", "images": [], "options": {"A": "carriage inwards", "B": "carriage outwards", "C": "returns inwards", "D": "returns outwards"}, "answer": "C", "explanation": "The 4,000 represent returns inwards in the trading account. Return inwards is also known as sales returns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>48", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use of following information to answer questions below  \tD\tMotor vehicle\t500000\tStock\t35000\tDebtors\t18000\tCash\t12850\tBank overdraft\t280000\tCreditors\t21500\t    The capital is", "images": [], "options": {"A": "D 867,350", "B": "D 832,350", "C": "D 544,350", "D": "D 264,350"}, "answer": "D", "explanation": "Capital = Total Asset - Total Liabilities     = ( 500,000 + 35,000 + 18,000 +12,850) - (280,000 + 21,500)     = 264,350", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>49", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use of following information to answer questions below  \tD\tMotor vehicle\t500000\tStock\t35000\tDebtors\t18000\tCash\t12850\tBank overdraft\t280000\tCreditors\t21500\t     The total current asset is", "images": [], "options": {"A": "D 367,350", "B": "D 345,850", "C": "D 87,850", "D": "D 65,850"}, "answer": "D", "explanation": "The total current assets is calculated by adding up the values of Stock, Debtors, and Cash. This gives us 35000 + 18000 + 12850 = 65850.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2022>50", "subject": "Accounts", "year": "2022", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "Use of following information to answer questions below  \tD\tMotor vehicle\t500000\tStock\t35000\tDebtors\t18000\tCash\t12850\tBank overdraft\t280000\tCreditors\t21500\t     The total current liability is", "images": [], "options": {"A": "D 301,500", "B": "D 280,000", "C": "D 264,350", "D": "D 258,500"}, "answer": "A", "explanation": "The total current liabilities is calculated by adding up the values of Bank overdraft and Creditors. This gives us 280000 + 21500 = 301500.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>1", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "One of the internal users of accounting information is the", "images": [], "options": {"A": "government", "B": "management", "C": "creditors", "D": "investors"}, "answer": "B", "explanation": "The internal users of accounting information are those individuals or groups who are inside or directly connected with the company. These include management, employees, and owners. Management uses accounting information to make decisions related to the company's operations and strategy. Therefore, the correct answer is 'management'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>2", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "A crane hired by a building construction company would be classified as", "images": [], "options": {"A": "a financial cost", "B": "a direct manufacturing cost", "C": "an overhead cost", "D": "an administration cost"}, "answer": "C", "explanation": "In accounting, a crane hired by a building construction company would be classified as an overhead cost. Overhead costs are the costs that cannot be directly attributed to any specific project, product, or service but are necessary for the overall operation of the business. In this case, the crane is not directly involved in the manufacturing process but is necessary for the construction process, making it an overhead cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>3", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "A business should not lay claim to any profit before it is earned. This is in accordance with the", "images": [], "options": {"A": "consistency concept", "B": "prudence concept", "C": "dual aspect concept", "D": "going concern concept"}, "answer": "B", "explanation": "The prudence concept in accounting means that a business should not anticipate profits but should provide for all possible losses. Therefore, a business should not lay claim to any profit before it is earned.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>4", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Use the following information to answer the question$Trade creditors (31/12/2020)4,000Paid for purchases in 2021: Cheques 110,000Carriage inwards 1,000Trade creditors (31/12/2021) 6,000    The total purchase in 2021 is", "images": [], "options": {"A": "$121,000", "B": "$117,000", "C": "$113,000", "D": "$111,000"}, "answer": "D", "explanation": "To determine the total purchase in 2021, we need to sum up the amounts paid for purchases in 2021 and the carriage inwards.    The amounts are as follows:    Paid for purchases in 2021 (cheques): $110,000  Carriage inwards: $1,000    Adding these two amounts together gives us:    $110,000 + $1,000 = $111,000    Therefore, the total purchase in 2021 is $111,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>5", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS", "question": "Use the following information to answer the question    $Trade creditors (31/12/2020)4,000Paid for purchases in 2021: Cheques 110,000Carriage inwards 1,000Trade creditors (31/12/2021) 6,000  The balance c/d on trade creditors will be recorded in the balance sheet as", "images": [], "options": {"A": "current asset", "B": "fixed asset", "C": "long-term liability", "D": "short-term liability"}, "answer": "D", "explanation": "The balance c/d on trade creditors is recorded in the balance sheet as a short-term liability. Trade creditors are the amounts owed by the business to its suppliers for goods and services purchased on credit. They are expected to be paid within a short period (usually within a year), hence they are classified as short-term liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>6", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which is the basis upon which assets of a business are valued is the", "images": [], "options": {"A": "consistency concept", "B": "dual aspect concept", "C": "historical concept", "D": "accrual concept"}, "answer": "C", "explanation": "The historical cost concept is the basis upon which assets of a business are valued. According to this concept, an asset is recorded in the books at the price at which it was acquired, i.e., its cost. This cost is the basis for all subsequent accounting for the asset. It is called the 'historical cost concept' because it involves recording assets and liabilities at their original or historical cost.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>7", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Use the following information to answer the question    The following transactions relate to Osei Enterprises for the year ended 31st December 2020.   DPurchases 160,000Returns outwards 880Carriage inwards 740Returns inwards 620Sales 195,000Salaries 27,600Closing stock 14,100    The cost of goods available for sale is", "images": [], "options": {"A": "D 159,860", "B": "D 159,380", "C": "D 159, 260", "D": "D 159, 120"}, "answer": "A", "explanation": "To calculate the cost of goods available for sale, we need to add the purchases, carriage inwards and less returns outward from the opening stock.    The given information states:    Purchases: D160,000  Returns outwards: D880  Carriage inwards: D740    Since opening stock is not given, then  To calculate the cost of goods available for sale= 160000 + 740 - 880  = D159,860", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>8", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question    The following transactions relate to Osei Enterprises for the year ended 31st December 2020.   DPurchases 160,000Returns outwards 880Carriage inwards 740Returns inwards 620Sales 195,000Salaries 27,600Closing stock 14,100  The gross profit", "images": [], "options": {"A": "D 49,360", "B": "D 49,220", "C": "D 48, 620", "D": "D 45, 860"}, "answer": "C", "explanation": "Gross Profit = Net Sales - Cost of Goods Sold    Cost of Goods Sold = Purchases +Carriage Inwards - Returns outwards -Closing stock  Cost of Goods Sold = 160000 +740 -880 - 14100  Cost of Goods Sold = 145760    Net sales = Sales - Returns inwards  = 195000 - 620  = 194380    Gross Profit  = 194380 - 145760  Gross Profit = D48620", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>9", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question    The following transactions relate to Osei Enterprises for the year ended 31st December 2020.   DPurchases 160,000Returns outwards 880Carriage inwards 740Returns inwards 620Sales 195,000Salaries 27,600Closing stock 14,100  The net profit is", "images": [], "options": {"A": "D 21, 760", "B": "D 21, 620", "C": "D 21, 020", "D": "D 18, 260"}, "answer": "C", "explanation": "Net profit = Gross profit - Expenses    Since Gross profit = D48620, and the only expenses is salaries    Then Net profit = 48620 - 27600  = D21020", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>10", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION", "question": "The concept which underlines double entry bookkeeping is", "images": [], "options": {"A": "accrual concept", "B": "duality concept", "C": "money measurement concept", "D": "historical cost concept"}, "answer": "B", "explanation": "The concept that underlines double entry bookkeeping is the duality concept. This concept states that every transaction has a dual effect i.e., it affects two accounts. For example, if a business buys goods for cash, it acquires the goods and at the same time decreases its cash balance. Therefore, this transaction affects two accounts: purchases and cash.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>11", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Which of the following items is a tangible asset?", "images": [], "options": {"A": "Goodwill", "B": "Lease", "C": "Machinery", "D": "Copyright"}, "answer": "C", "explanation": "A tangible asset is an asset that has a physical form. It's something you can see or touch. Examples of tangible assets include machinery, buildings, and land. Therefore, out of the given options, 'Machinery' is a tangible asset. Goodwill, Lease, and Copyright are intangible assets because they do not have a physical presence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>12", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED", "question": "Discount allowed is shown in financial statements as", "images": [], "options": {"A": "an expenses", "B": "an income", "C": "an asset", "D": "a liability"}, "answer": "A", "explanation": "Discount allowed is a reduction in price given by the seller, to the buyer at the time of purchase of goods. It is a type of expense for the business, as it reduces the amount of money that comes into the business for the sale of goods. Therefore, it is shown in financial statements as an expense. It is not an income, asset, or liability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>13", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The reason for treating carriage inwards in the trading account is because", "images": [], "options": {"A": "it is an expense on goods sold to customer", "B": "carriage outwards is an expense item in the profit and loss account", "C": "it does not appear in the balance sheet", "D": "it is an expense on goods purchased"}, "answer": "D", "explanation": "Carriage inwards refers to the cost of transportation incurred by a company to bring goods or raw materials to its premises. It is treated in the trading account because it is an expense on goods purchased. It is part of the cost of goods sold, not an expense on goods sold to customers. It does not appear in the balance sheet because it is an expense, not an asset or liability. Carriage outwards, on the other hand, is an expense item in the profit and loss account because it is associated with the delivery of goods sold to customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>14", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Wages of machine operators in manufacturing account are treated as", "images": [], "options": {"A": "direct expenses", "B": "direct labour", "C": "indirect expenses", "D": "indirect labour"}, "answer": "B", "explanation": "Wages of machine operators in a manufacturing account are treated as direct labour. Direct labour refers to the work of employees that can be directly attributed to specific goods or services. In this case, the machine operators are directly involved in the production process, hence their wages are considered direct labour. Direct expenses are costs that can be directly linked to a specific cost object, such as a product, department, or project. This could include raw materials or worker's wages. Indirect expenses and indirect labour, on the other hand, cannot be directly linked to the production of specific goods or services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>15", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question    Sammy acquired plant an machinery costing ₦120,000 with an estimated useful life of 4 years and residual value of ₦2,000. The sum of the year digits method is used.    The depreciation to be charged for the third year will be", "images": [], "options": {"A": "₦23,600", "B": "₦23,000", "C": "₦22,000", "D": "₦21,000"}, "answer": "A", "explanation": "Useful life = 4 years    Sum of the year digit = 4 + 3 + 2 + 1  = 10    Depreciable amount = 120000 - 2000  = #118000    Depreciation for 3rd year = 2/10  x 118000  = #23,600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>16", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question    Sammy acquired plant an machinery costing ₦120,000 with an estimated useful life of 4 years and residual value of ₦2,000. The sum of the year digits method is used.  The value of the asset at the end of the first year is", "images": [], "options": {"A": "₦78,000", "B": "₦75,000", "C": "₦73,000", "D": "₦72,800"}, "answer": "D", "explanation": "Useful life = 4 years    Sum of the year digit = 4 + 3 + 2 + 1  = 10    Depreciable amount = 120000 - 2000  = #118000    Depreciation for first year = 4/10  x 118000  = #47,200    Value at the end of the first year = 120000 - 47200  = #72,800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>17", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "The allocation of funds from treasury to accounting heads in public sector is", "images": [], "options": {"A": "float", "B": "vote", "C": "virement", "D": "budget"}, "answer": "B", "explanation": "When fund is allocated to a head, it is referred to as vote. Vote is the amount for individual items on a government budget.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>18", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE", "question": "The source of funds available to a local government/district assembly includes", "images": [], "options": {"A": "common fund allocation", "B": "excise duties", "C": "road tolls", "D": "none of the above"}, "answer": "A", "explanation": "The source of funds available to a local government/district assembly includes common fund allocation. The Common Fund is a constitutional provision which requires that a minimum of 5% of the total revenue of Ghana is set aside for distribution to all District Assemblies. However, other sources like excise duties and road tolls can also contribute to the funds of a local government/district assembly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>19", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Carriage inwards on raw materials is recorded in the", "images": [], "options": {"A": "manufacturing account", "B": "trading account", "C": "profit and loss account", "D": "balance sheet"}, "answer": "A", "explanation": "Carriage inwards refers to the cost of transportation of raw materials from the supplier to the place of business. This cost is directly related to the production process and is therefore recorded in the manufacturing account. It is part of the cost of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>20", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer the question    The health department of Banjul Local Government incurred the following expenditure in 2020:     LeConstruction of hospital wards 200,000Purchase of hospital beds 20,000Purchase of stationeries 15,000Salaries and wages 60,000Purchase of drugs 50,000Purchase of x-ray machine 100,000    The capital expenditure for the year is", "images": [], "options": {"A": "Le 455,000", "B": "Le 370,000", "C": "Le 320,000", "D": "Le 125,000"}, "answer": "C", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, an industrial plant, technology, or equipment. In this case, the capital expenditure is the sum of the cost of construction of hospital wards (200,000) and the purchase of the x-ray machine (100,000), which totals to Le 300,000. However, none of the options matches this answer. Therefore, the closest option is Le 320,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>21", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Use the following information to answer the question    The health department of Banjul Local Government incurred the following expenditure in 2020:     LeConstruction of hospital wards 200,000Purchase of hospital beds 20,000Purchase of stationeries 15,000Salaries and wages 60,000Purchase of drugs 50,000Purchase of x-ray machine 100,000  The recurrent expenditure for the year is", "images": [], "options": {"A": "Le 445,000", "B": "Le 370,000", "C": "Le 320,000", "D": "Le 125,000"}, "answer": "D", "explanation": "From the given information, the expenditures that are likely to be classified as recurrent expenditures are:    Purchase of stationeries: Le15,000  Salaries and wages: Le60,000  Purchase of drugs: Le50,000  To calculate the recurrent expenditure for the year, we add these amounts together:    Le15,000 + Le60,000 + Le50,000 = Le125,000    Therefore, the recurrent expenditure for the year is Le125,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>22", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Reliability as a quality of accounting information means that accounting", "images": [], "options": {"A": "rules and guidelines are applied", "B": "information is comprehensive", "C": "report is prepared promptly", "D": "information is prepared based on evidence"}, "answer": "D", "explanation": "Reliability in accounting refers to the trustworthiness of financial statement information that makes it useful for decision making. Reliable information is verifiable, free from bias and faithfully represents what it purports to represent. Therefore, the statement 'information is prepared based on evidence' best describes reliability as a quality of accounting information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>23", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE", "question": "The error that affects the agreement of a trial balance totals is", "images": [], "options": {"A": "error of commission", "B": "error of principle", "C": "compensating error", "D": "casting error"}, "answer": "E", "explanation": "The errors that will affect the agreement of the trial balance are: one sided omission, two entries on the same side, undercasting or overcasting of balances etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>24", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Profit distributed to ordinary shareholders of a limited liability company is", "images": [], "options": {"A": "interest", "B": "surplus", "C": "dividend", "D": "reserve"}, "answer": "C", "explanation": "In a limited liability company, the profit that is distributed to ordinary shareholders is known as a dividend. Dividends are a portion of a company's earnings that are paid out to shareholders, typically on a regular basis. They represent a way for the company to distribute a portion of its earnings back to its investors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>25", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "The purchase day book is used to record", "images": [], "options": {"A": "cash purchase", "B": "credit purchase", "C": "purchases returns", "D": "total purchases"}, "answer": "B", "explanation": "The Purchase Day Book is a special journal used to record all credit purchases. Every time a business purchases goods on credit, that transaction is recorded in the Purchase Day Book. Cash purchases are not recorded in this book, purchases returns are recorded in a separate returns journal, and total purchases would include both cash and credit purchases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>26", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "In the final account of a limited liability company, debenture interest paid is recorded in the", "images": [], "options": {"A": "trading account", "B": "profit and loss account", "C": "capital account", "D": "current account"}, "answer": "B", "explanation": "In the final account of a limited liability company, debenture interest paid is recorded in the Profit and Loss Account. This is because debenture interest is considered as an expense for the company and all expenses are recorded in the Profit and Loss Account. It is not recorded in the trading account, capital account or current account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>27", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Suppliers' personal account are found in the", "images": [], "options": {"A": "purchases ledger", "B": "sales ledger", "C": "private ledger", "D": "nominal ledger"}, "answer": "A", "explanation": "Suppliers' personal accounts are found in the purchases ledger. The purchases ledger is a subsidiary ledger where a business records its purchases on credit. Each supplier (creditor) has an individual account in the purchases ledger. When a business purchases goods on credit, the supplier's account in the purchases ledger is debited.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>28", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "Memoradum branch account is prepared to determine", "images": [], "options": {"A": "credit sales", "B": "gross profit", "C": "closing stock", "D": "opening stock"}, "answer": "B", "explanation": "A Memorandum Branch Account is prepared to determine the gross profit of a branch. It is a type of account used in businesses that have branches. It records all transactions related to a specific branch, including sales, purchases, expenses, and income. The difference between the total income and total expenses gives the gross profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>29", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES", "question": "Use the following information to answer the question    Taurus Ltd was incorporated with the legal right to issue five million ordinary shares. The company has issued three million of the shares at GH⊄ 0.60 per share. To date, the company has made calls of GH⊄ 0.40 per share. All calls have been paid by shareholders except for GH⊄ 100,000 owing from one shareholder.    The paid up share capital is", "images": [], "options": {"A": "GH⊄ 3,000,000", "B": "GH⊄ 2,000,000", "C": "GH⊄ 1,200,000", "D": "GH⊄ 1,100,000"}, "answer": "E", "explanation": "The paid-up share capital is the portion of the share capital that has been paid by the shareholders.    In this case, Taurus Ltd has issued three million ordinary shares at GH⊄ 0.60 per share. This means that the total value of the issued shares is:    3,000,000 shares * GH⊄ 0.60 per share = GH⊄ 1,800,000    The company has made calls of GH⊄ 0.40 per share, and all calls have been paid by shareholders except for GH⊄ 100,000 owing from one shareholder.    So the total amount of calls that have been paid is:    3,000,000 shares * GH⊄ 0.40 per share = GH⊄ 1,200,000    Therefore, the paid-up share capital is the total value of the issued shares minus the total amount of calls paid, which is:    GH⊄ 1,800,000 - GH⊄ 1,200,000 = GH⊄ 600,000    Therefore, the correct answer is GH⊄ 600,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>30", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Use the following information to answer the question    Taurus Ltd was incorporated with the legal right to issue five million ordinary shares. The company has issued three million of the shares at GH⊄ 0.60 per share. To date, the company has made calls of GH⊄ 0.40 per share. All calls have been paid by shareholders except for GH⊄ 100,000 owing from one shareholder.  The authorized number of shares is", "images": [], "options": {"A": "8,000,000", "B": "5,000,000", "C": "3,000,000", "D": "100,000"}, "answer": "B", "explanation": "The authorized number of shares is the maximum number of shares that a company is legally allowed to issue. In this case, Taurus Ltd was incorporated with the legal right to issue five million ordinary shares. Therefore, the authorized number of shares is 5,000,000. Therefore, option 2 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>31", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "The accounts maintained in the nominal ledger are", "images": [], "options": {"A": "income and capital", "B": "expenses and income", "C": "liabilites and capital", "D": "assets and liabilites"}, "answer": "B", "explanation": "The nominal ledger, also known as the general ledger, contains all the accounts necessary to prepare financial statements. It includes accounts for expenses and income. Expenses are the costs incurred in the process of generating revenue for the business, while income refers to the revenue that the business earns. The nominal ledger does not directly deal with accounts for liabilities, capital, or assets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>32", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "Which of the following items are apportioned on the basis of purchases in preparing departmental accounts?", "images": [], "options": {"A": "Selling and distribution expenses", "B": "Lighting and cooling expenses", "C": "Carriage inwards", "D": "Carriage outwards"}, "answer": "C", "explanation": "In preparing departmental accounts, certain expenses are apportioned based on relevant bases. Carriage inwards refers to the cost of transporting goods purchased into the business premises. It is apportioned on the basis of purchases because it directly relates to the goods purchased. Selling and distribution expenses are usually apportioned based on sales, while lighting and cooling expenses could be apportioned based on floor area or number of employees, not purchases. Carriage outwards, on the other hand, is related to sales, not purchases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>33", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "CASH BOOK : TWO COLUMN CASH BOOK", "question": "The two column cash book records", "images": [], "options": {"A": "receipts and payments in cash only", "B": "receipts and payments by cheque only", "C": "all receipts and payments both in cash and by cheque", "D": "all receipts in cash only and payments by cheque"}, "answer": "C", "explanation": "A two-column cash book is a type of ledger that is used to record both cash and bank transactions. It has two columns on each side to record these two types of transactions. Therefore, it records all receipts and payments both in cash and by cheque.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>34", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the questions    The transactions of All Girls' Social Club for the year 2021 are as follows:    Bar sales D 30,000; Bar purchases D 17,000 and Rent D 1,200    31st December 2020 2021 D DStock at bar 1400 1600Owing for bar supplies 6500 7300    The value of purchases for the year is", "images": [], "options": {"A": "D 17,800", "B": "D 17,000", "C": "D 16,800", "D": "D 16,200"}, "answer": "A", "explanation": "The value of purchases for the year can be calculated by adding the opening stock to the purchases and then subtracting the closing stock. In this case, the opening stock is D 1400, the purchases are D 17,000 and the closing stock is D 1600. Therefore, the value of purchases for the year is D 17,800 (1400 + 17000 - 1600).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>35", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Use the following information to answer the questions    The transactions of All Girls' Social Club for the year 2021 are as follows:    Bar sales D 30,000; Bar purchases D 17,000 and Rent D 1,200    31st December 2020 2021 D DStock at bar 1400 1600Owing for bar supplies 6500 7300  The net profit on the bar to be transferred to the income an expenditure account for the year ended 31st December 2021 is", "images": [], "options": {"A": "D 13,000", "B": "D 12,400", "C": "D 11,800", "D": "D 11,600"}, "answer": "D", "explanation": "According to the information provided:    Bar sales: D30,000  Bar purchases: D17,000  Opening stock: D1,400  Closing stock: D1,600  Rent: D1,200    To calculate the net profit on the bar, you can use the following formula:    Net Profit on Bar = Bar Sales - (Bar Purchases + Other Expenses + (Closing Stock - Opening Stock))    Net Profit on Bar = D30,000 - (D17,000 + D1,200 + (D1,600 - D1,400))  Net Profit on Bar = D30,000 - (D17,000 + D1,200 + D200)  Net Profit on Bar = D30,000 - D18,400  Net Profit on Bar = D11,600    Therefore, the net profit on the bar to be transferred to the income and expenditure account for the year ended 31st December 2021 is D11,600.    Hence, the correct answer is D11,600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>36", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Which of the following rules is applicable in the absence of a partnership agreement?  Interest is payable", "images": [], "options": {"A": "on drawings at the rate of 5% per annum", "B": "on agreed capital contributed at 5% per annum", "C": "on any contribution in excess of agreed capital at 5% per annum", "D": "at 5% per annum on the current account balances"}, "answer": "B", "explanation": "In the absence of a partnership agreement, the Partnership Act provides that no interest is to be allowed on capital subscribed by the partners. However, if the partners have agreed to allow interest on capital, it will be allowed even if there is no partnership deed. Therefore, the correct answer is 'on agreed capital contributed at 5% per annum'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>37", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "A reason a business is not able to keep full set of accounting records is that", "images": [], "options": {"A": "the business does not make profit", "B": "the business is not a trading concern", "C": "double entry shows the true profit", "D": "double entry is expensive to maintain"}, "answer": "D", "explanation": "The full set of accounting records can be expensive to maintain because it requires a lot of time, effort, and resources. Double entry accounting, which is a method of bookkeeping that requires every transaction to be recorded in two places, debit and credit, can be particularly costly. This is because it requires a high level of detail and accuracy, and may require the services of a professional accountant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>38", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "Beauty started business with ₦40,000, made a profit of ₦50,000 and ended the year with ₦70,000 capital. What would have accounted for the closing capital?", "images": [], "options": {"A": "Cash shortage of ₦30,000 was recorded", "B": "Drawings of ₦20,000 was made", "C": "Beauty was paid a salary of ₦40,000", "D": "The opening capital of ₦40,000 was invested"}, "answer": "E", "explanation": "The calculation for closing capital is as follows:    Closing Capital = Initial Capital + Profit + Salary - Drawings - Cash Shortage    Closing Capital = ₦40,000 + ₦50,000 + ₦40,000 - ₦20,000 - ₦30,000    Closing Capital = ₦140,000 - ₦20,000 - ₦30,000    Closing Capital = ₦140,000 - ₦50,000    Closing Capital = ₦90,000    Therefore, the closing capital for Beauty would be ₦90,000.    Hence, the correct answer is ₦90,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>39", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "If sales is D 12,000 and the gross profit mark -up percentage is 25%. What is the cost of sales?", "images": [], "options": {"A": "D 9,600", "B": "D 9,000", "C": "D 3,000", "D": "D 2,400"}, "answer": "B", "explanation": "The cost of sales is calculated by subtracting the gross profit from the total sales. The gross profit is the mark-up percentage of the total sales. In this case, the gross profit is 25% of D 12,000, which is D 3,000. Subtracting this from the total sales gives D 9,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>40", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "The accumulated fund for a not-for-profit making organization is", "images": [], "options": {"A": "assets + liabilites", "B": "assets - liabilities + capital", "C": "assets - liabilites", "D": "capital + liabilities"}, "answer": "C", "explanation": "The accumulated fund for a not-for-profit organization is the difference between the organization's total assets and its total liabilities. This is because a not-for-profit organization does not have owners or shareholders, so its net assets (assets minus liabilities) are considered its accumulated fund.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>41", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the question    The following transactions were recorded in the cash book of Ibusah for the month of February 2019:    DBalance b/f 200,000Commission received 180,000Receipts from Ojah 98,000Electricity bill 40,000Rent 73,400Drawings 28,600Insurance 12,800    The total income for the month is", "images": [], "options": {"A": "D 306,900", "B": "D 278,000", "C": "D 180,000", "D": "D 154,800"}, "answer": "B", "explanation": "The total income for the month is calculated by adding the commission received and the receipts from Ojah. This gives us 180,000 + 98,000 = 278,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>42", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the question    The following transactions were recorded in the cash book of Ibusah for the month of February 2019:    DBalance b/f 200,000Commission received 180,000Receipts from Ojah 98,000Electricity bill 40,000Rent 73,400Drawings 28,600Insurance 12,800  The balance brought down at the end of the month is", "images": [], "options": {"A": "D 478,300", "B": "D 323,200", "C": "D 278,300", "D": "D 154,800"}, "answer": "B", "explanation": "Balance Brought Down = Opening Balance + Income - (Expenses + Drawings)    Balance Brought Down = (D200,000 + D180,000 + D98,000) - (D40,000 + D73,400 + D28,600 + D12,800)    = 478,000 - 154,800  Balance Brought Down = Opening Balance + Income - (Expenses + Drawings)    Balance Brought Down = (D200,000 + D180,000 + D98,000) - (D40,000 + D73,400 + D28,600 + D12,800)    = 478,000 - 154,800  = D 323,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>43", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "Use the following information to answer the question    The following transactions were recorded in the cash book of Ibusah for the month of February 2019:    DBalance b/f 200,000Commission received 180,000Receipts from Ojah 98,000Electricity bill 40,000Rent 73,400Drawings 28,600Insurance 12,800  The total expenses for the month is", "images": [], "options": {"A": "D 478,300", "B": "D 323,500", "C": "D 278,300", "D": "D 154,800"}, "answer": "D", "explanation": "The total expenses for the month can be calculated by adding up all the expenses listed in the cash book. These include the Electricity bill (40,000), Rent (73,400), Drawings (28,600), and Insurance (12,800). The sum of these expenses is 154,800. Therefore, the correct answer is D 154,800.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>44", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING", "question": "Which of the following items is classified as capital expenditure in public sector accounting?", "images": [], "options": {"A": "Financial charges", "B": "Construction works's cost", "C": "Training and conference cost", "D": "Wages and salaries"}, "answer": "B", "explanation": "Capital expenditure in public sector accounting refers to the spending on acquisition of assets that will be used for a long period of time to generate income or improve the functioning of the government. This includes costs for construction works, purchase of machinery, equipment, buildings, etc. Therefore, the correct answer is 'Construction works's cost'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>45", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question    LeCapital (01/01/2020) 1,934,600Capital (31/12/2020) 2,530,000Expenses 345,900Drawings for 2020 72,500Additional capital for 2020 250,000    The gross profit for the year is", "images": [], "options": {"A": "Le 763,800", "B": "Le 595,400", "C": "Le 417,900", "D": "Le 167,900"}, "answer": "B", "explanation": "Gross Profit = 2,530,000 - 1,934,600 + 72,500 - 250,000 - 345,900  Gross Profit = le 595,400", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>46", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "Use the following information to answer the question    LeCapital (01/01/2020) 1,934,600Capital (31/12/2020) 2,530,000Expenses 345,900Drawings for 2020 72,500Additional capital for 2020 250,000  The net profit for 2020 is", "images": [], "options": {"A": "Le 595,400", "B": "Le 522,900", "C": "Le 772,900", "D": "Le 72,000"}, "answer": "B", "explanation": "Net Profit = Gross Profit - Drawings for 2020    From the previous question, we calculated the Gross Profit as:  Gross Profit = Capital (31/12/2020) - Capital (01/01/2020) + Drawings for 2020 - Additional capital for 2020 - Expenses  Gross Profit = 2,530,000 - 1,934,600 + 72,500 - 250,000 - 345,900  Gross Profit = 595,400     Net Profit = Gross Profit - Drawings for 2020  Net Profit = 595,400 - 72,500  Net Profit = le 522,900", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2023>47", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A partnership is formed by", "images": [], "options": {"A": "only one person", "B": "two or more individuals", "C": "two or more companies", "D": "two individuals only"}, "answer": "B", "explanation": "A partnership is a type of business organization where two or more individuals manage and operate the business in accordance with the terms and goals set out in the partnership deed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2023>48", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question    Ant and Bee withdrew GH⊄ 14,000 and GH⊄ 10,000 respectively at 8% per annum from the partnership.    The interest on drawings for Ant is", "images": [], "options": {"A": "GH⊄ 1,920", "B": "GH⊄ 1,120", "C": "GH⊄ 800", "D": "GH⊄ 700"}, "answer": "B", "explanation": "The interest on drawings is calculated by multiplying the amount withdrawn by the interest rate. In this case, Ant withdrew GH⊄ 14,000 at an interest rate of 8% per annum. Therefore, the interest on drawings for Ant is GH⊄ 14,000 * 8/100 = GH⊄ 1,120.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>49", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question    Ant and Bee withdrew GH⊄ 14,000 and GH⊄ 10,000 respectively at 8% per annum from the partnership.  The total interest on drawings to be charged to profit and loss appropriation account is", "images": [], "options": {"A": "GH⊄ 1,920", "B": "GH⊄ 1,120", "C": "GH⊄ 800", "D": "GH⊄ 700"}, "answer": "A", "explanation": "The total interest on drawings is calculated by adding the interest on Ant's withdrawal and Bee's withdrawal. The interest on Ant's withdrawal is 8% of GH⊄ 14,000 which is GH⊄ 1,120. The interest on Bee's withdrawal is 8% of GH⊄ 10,000 which is GH⊄ 800. Adding these two amounts gives GH⊄ 1,920.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2023>50", "subject": "Accounts", "year": "2023", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Which of the following items is found in the profit and loss account of a company?", "images": [], "options": {"A": "Proceeds from issue of shares", "B": "Proposed dividends", "C": "Director's remuneration", "D": "Transfer to general reserves"}, "answer": "C", "explanation": "The profit and loss account of a company includes all the expenses and incomes of the company. Among the given options, 'Director's remuneration' is an expense and hence it is included in the profit and loss account. The other options are not included in the profit and loss account. 'Proceeds from issue of shares' is a source of capital and not an income or expense. 'Proposed dividends' and 'Transfer to general reserves' are appropriations of profit and not expenses or incomes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>1", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "A bank is interested in accounting information of a client for the purpose of", "images": [], "options": {"A": "evaluating the entity's share of the market", "B": "ascertaining the tax payable by the entity", "C": "assessing the credit worthiness of the customer", "D": "determining the dividend payable to shareholders"}, "answer": "C", "explanation": "Banks use accounting information, such as financial statements and performance metrics, to evaluate the creditworthiness of their clients. This assessment helps banks determine the risk of lending to the client, including the likelihood of repayment of loans and interest. Key financial ratios and trends in the client's financial statements provide insights into the client's ability to generate cash flows, manage debt, and meet financial obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>2", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "An item recorded in the profit and loss account is", "images": [], "options": {"A": "creditors", "B": "cash-in-hand", "C": "debtors", "D": "general expenses"}, "answer": "D", "explanation": "The profit and loss account, also known as the income statement, records all revenues earned and expenses incurred during a specific period. General expenses refer to operating expenses that are necessary to run a business and generate revenue. These expenses include items such as salaries, rent, utilities, advertising, depreciation, and other costs associated with normal business operations. They are subtracted from revenues to determine the net profit or loss for the period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>3", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "The concept which assumes that transactions should be expressed using a common denominator is", "images": [], "options": {"A": "historical cost concept", "B": "money measurement concept", "C": "materiality concept", "D": "consistency concept"}, "answer": "B", "explanation": "The money measurement concept states that only transactions and events that can be expressed in monetary terms should be recorded in the accounting records. This concept assumes that all transactions should be measured using a common unit of currency (e.g., dollars, euros, etc.) to facilitate meaningful financial reporting and analysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>4", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question    TheyearlydepreciationchargeusingthestraightlinemethodisX - YZ    The letter X in the formula represents", "images": [], "options": {"A": "cost of the asset", "B": "accumulated depreciation", "C": "estimated useful life of the asset", "D": "rate of depreciation"}, "answer": "A", "explanation": "In the context of straight-line depreciation, the annual depreciation expense is calculated as the cost of the asset (X) minus the salvage value (Y), divided by the estimated useful life of the asset (Z). The cost of the asset (X) is the original purchase price or acquisition cost of the asset, which serves as the basis for calculating depreciation over its useful life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>5", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION", "question": "Use the following information to answer the question    TheyearlydepreciationchargeusingthestraightlinemethodisX - YZ    The letter Z in the formula represents", "images": [], "options": {"A": "cost of the asset", "B": "accumulated depreciation", "C": "estimated useful life of the asset", "D": "rate of depreciation"}, "answer": "C", "explanation": "In the context of straight-line depreciation, the annual depreciation expense is calculated as the cost of the asset (X) minus the salvage value (Y), divided by the estimated useful life of the asset (Z). The cost of the asset (X) is the original purchase price or acquisition cost of the asset, which serves as the basis for calculating depreciation over its useful life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>6", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "In a manufacturing account, wages of machine operators are classified as", "images": [], "options": {"A": "prime cost", "B": "factory overheads", "C": "work-in-progress", "D": "administrative overheads"}, "answer": "A", "explanation": "Prime cost includes all direct costs directly attributable to the production of goods, such as direct materials, direct labor (including wages of machine operators), and direct expenses. Wages of machine operators directly contribute to the manufacturing process by operating machinery and are therefore classified as part of the prime cost in a manufacturing account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>7", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question    LeOpening stock 6000Sales 180000Closing stock 4200Mark-upis3313%    The value of purchases is", "images": [], "options": {"A": "Le 139,200", "B": "Le 135,000", "C": "Le 133,200", "D": "Le 127,200"}, "answer": "C", "explanation": "Opening Stock = Le 6000  Sales = Le 180000  Closing Stock = Le 4200  Mark-up = 33 1/3% (or 1/3)    Convert mark up to margin  1/3 + 1 = 1/4 or 25%    Profit = 25%  x Sales  = 25% x 180,000  = 45,000    Sales = Cost of goods sold + Profit  180000 = COGS + 45000  COGS = 180000 - 45000  = 135000    Purchases = COGS + Closing stock - Opening Stock  = 135000 + 4200 - 6000  = Le 133,200", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>8", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question    LeOpening stock 6000Sales 180000Closing stock 4200Mark-upis3313%    The cost of goods sold is", "images": [], "options": {"A": "Le 139,200", "B": "Le 135,000", "C": "Le 133,200", "D": "Le 127,200"}, "answer": "B", "explanation": "Opening Stock = Le 6000  Sales = Le 180000  Closing Stock = Le 4200  Mark-up = 33 1/3% (or 1/3)    Convert mark up to margin  1/3 + 1 = 1/4 or 25%    Profit = 25%  x Sales  = 25% x 180,000  = 45,000    Sales = Cost of goods sold + Profit  180000 = COGS + 45000  COGS = 180000 - 45000  = 135000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>9", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question    LeOpening stock 6000Sales 180000Closing stock 4200Mark-upis3313%    The gross profit is", "images": [], "options": {"A": "Le 60,000", "B": "Le 45,000", "C": "Le 44,400", "D": "Le 33,750"}, "answer": "B", "explanation": "Opening Stock = Le 6000  Sales = Le 180000  Closing Stock = Le 4200  Mark-up = 33 1/3% (or 1/3)    Convert mark up to margin  1/3 + 1 = 1/4 or 25%    Profit = 25%  x Sales  = 25% x 180,000  = 45,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>10", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET", "question": "A sole trader received the sum of #4,860 cash from a debtor. The effect of this transaction in the balance sheet is", "images": [], "options": {"A": "decrease in stock and increase in debtor", "B": "decrease in asset and increase in liability", "C": "increase in cash and increase in debtor", "D": "increase in cash and decrease in capital"}, "answer": "C", "explanation": "When a sole trader receives cash from a debtor, the transaction impacts the balance sheet as follows:  Cash increases by ₦4,860 (an asset).  Debtors (accounts receivable) decrease by ₦4,860 (as the debtor pays off their debt).", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>11", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "According to the entity concept, ownership is", "images": [], "options": {"A": "vested on the board of directors", "B": "vested on the management", "C": "separated from the business", "D": "not separated from the business"}, "answer": "C", "explanation": "The entity concept, or entity assumption, establishes that a business is treated as a separate economic entity from its owners. This means that the business's financial transactions are recorded independently of the personal transactions of its owners. The concept ensures that the financial statements provide information about the business itself, distinct from the financial position and activities of its owners or shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>12", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "TRIAL BALANCE : RULES AND NATURE OF TRIAL BALANCE", "question": "An item recorded in the trial balance is", "images": [], "options": {"A": "opening stock", "B": "closing stock", "C": "accrued expenses", "D": "depreciation charged for the year"}, "answer": "A", "explanation": "The trial balance is a list of all ledger accounts and their balances at a specific point in time, usually at the end of an accounting period. It includes both balance sheet accounts (assets, liabilities, and equity) and income statement accounts (revenues and expenses).    Opening stock (or beginning inventory) represents the value of goods available for sale at the beginning of an accounting period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>13", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The class of shares which are available only to the promoters of a company are", "images": [], "options": {"A": "ordinary shares", "B": "cumulative preference shares", "C": "non-cumulated preference shares", "D": "deferred shares"}, "answer": "D", "explanation": "Deferred shares are a class of shares that are typically issued to company founders or promoters. These shares often have special rights or restrictions attached to them, such as limited or no voting rights, and they usually receive dividends only after other classes of shares (such as ordinary shares) have been paid dividends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>14", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "Expense incurred but not yet paid is", "images": [], "options": {"A": "long -term liability", "B": "current liability", "C": "current asset", "D": "capital expenditure"}, "answer": "B", "explanation": "An expense that has been incurred but not yet paid is known as an accrued expense or a payable expense. These expenses represent obligations to pay for goods or services that have been received but not yet settled with cash or its equivalent. Accrued expenses are considered current liabilities because they are expected to be settled within the normal operating cycle of the business, usually within one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>15", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Work-in-progress is an item in", "images": [], "options": {"A": "income and expenditure account", "B": "receipts and payments account", "C": "appropriation account", "D": "manufacturing account"}, "answer": "D", "explanation": "Work-in-progress (WIP) refers to goods that are in the process of being manufactured or assembled but are not yet completed. It represents the cost of raw materials, direct labor, and overhead costs that have been incurred for products that are partially completed and still on the production floor.    In accounting, the manufacturing account is used to track the costs associated with the production of goods. It includes direct materials, direct labor, and manufacturing overheads. Work-in-progress is a critical component of the manufacturing account as it represents the value of partially completed goods at various stages of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>16", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT", "question": "In an incomplete record, the excess of opening capital over closing capital is", "images": [], "options": {"A": "provision", "B": "loss", "C": "profit", "D": "reserve"}, "answer": "B", "explanation": "After obtaining the opening and closing capital, adjustments will be made of withdrawals and introduction of new capital. The difference between the opening and closing capital will give either a profit or loss.    If the closing capital is greater than opening capital, then profit  if the opening capital is greater than closing capital, then loss", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>17", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer the question    Bayo issued a credit note to Ayo who returned defective goods. Each parties maintains sales ledger control account and purchases ledger control account    Ayo will record this transactions on the", "images": [], "options": {"A": "debit side of the sales ledger control account", "B": "credit side of the sales ledger control account", "C": "debit side of the purchase ledger control account", "D": "credit side of the purchase ledger control account"}, "answer": "D", "explanation": "Bayo issues a credit note to Ayo for returned defective goods.    Ayo's perspective: Ayo received a credit note, meaning they are owed money by Bayo (their supplier).    Purchases ledger control account: This account tracks the total amount owed to suppliers (like Bayo) on credit purchases.    Since Ayo now has a reduced amount owed to Bayo due to the credit note, they need to record this decrease in their purchases ledger control account. This is typically done with a credit entry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>18", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer the question    Bayo issued a credit note to Ayo who returned defective goods. Each parties maintains sales ledger control account and purchases ledger control account    Bayo will record this transaction on the", "images": [], "options": {"A": "debit side of the sales ledger control account", "B": "credit side of the sales ledger control account", "C": "debit side of the purchases ledger control account", "D": "credit side of the purchases ledger account"}, "answer": "A", "explanation": "Bayo issues a credit note to Ayo for returned defective goods.    Bayo's perspective: Bayo issued a credit note, meaning they owe money (gave a reduction) to Ayo (their customer).    Sales ledger control account: This account tracks the total amount owed by customers (like Ayo) on credit sales.    Since Bayo has reduced the amount Ayo owes them due to the credit note, they need to record this decrease in their sales ledger control account. This is typically done with a debit entry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>19", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept that underlies the comparing of expenditure for a period with the revenue of same period is", "images": [], "options": {"A": "accrual concept", "B": "money measurement concept", "C": "matching concept", "D": "dual aspect concept"}, "answer": "C", "explanation": "The matching concept, also known as the matching principle, is a fundamental accounting principle that states that expenses should be matched with the revenues they help to generate in the same accounting period. This concept ensures that the financial statements accurately reflect the profitability of the business for a given period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>20", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "An item is classified as a current asset if it is", "images": [], "options": {"A": "purchased for long-term use", "B": "expected to be realized within the balance sheet date", "C": "fictitious in nature", "D": "neither cash nor cash equivalent"}, "answer": "B", "explanation": "Current assets are assets that are expected to be converted into cash or used up within one year or the operating cycle of the business, whichever is longer. This includes assets that are held for the purpose of being traded, are expected to be realized, or are intended to be consumed in the normal operation of the business within a short period, typically within one year from the balance sheet date.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>21", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INTRODUCTION AND ADVANTAGES", "question": "Subscriptions classified in the balance sheet as a current asset is subscriptions", "images": [], "options": {"A": "in advance", "B": "in arrears", "C": "received for the year", "D": "income for the year"}, "answer": "B", "explanation": "Subscription in arrears mean that services are provided but against which subscription is not received. On accrual system, subscription in arrears to be shown as income of that particular period and shown as an asset in the balance sheet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>22", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Which of the following items will not be charged to the manufacturing account?", "images": [], "options": {"A": "Warehouse rent", "B": "Opening work-in-progress", "C": "Direct expenses", "D": "Carriage on raw materials"}, "answer": "A", "explanation": "Warehouse rent is not directly related to the manufacturing process but rather to the storage of finished goods or raw materials. Hence, it would not typically be charged to the manufacturing account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>23", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER", "question": "An account in the real ledger is", "images": [], "options": {"A": "sales account", "B": "insurance account", "C": "discount received account", "D": "machinery account"}, "answer": "D", "explanation": "A real account is an account for asset.  A machinery account is a real ledger account because it represents a tangible asset owned by the business. It records the initial cost of the machinery, any subsequent additions or improvements, and the accumulated depreciation over its useful life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>24", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question    The margin for a business is 2/3 and the cost of sales is $120,000    the mark-up for the business is", "images": [], "options": {"A": "4/5", "B": "3/5", "C": "2", "D": "1/5"}, "answer": "C", "explanation": "The Margin = 2/3    Converting margin to mark up, less the numerator from the denominator  = 2/3 - 2    = 2/1    = 2", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>25", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : MARK UP AND MARGIN", "question": "Use the following information to answer the question    The margin for a business is 2/3 and the cost of sales is $120,000    The sales value for the business is", "images": [], "options": {"A": "$216,000", "B": "$204,000", "C": "$360,000", "D": "$192,000"}, "answer": "C", "explanation": "MarkUp=SP-CPCP    Profit = 2/3  x CP ....... (1)    Profit = SP - CP.......(2)  Combine both equation    2/3 x SP = SP - CP    2/3 x SP = SP - 120,000    2SP = 3SP - 360,000    SP = 360,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>26", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT", "question": "The objective of preparing a departmental account is to", "images": [], "options": {"A": "ascertain the cost of raw materials of each department", "B": "ascertain the profit of each department", "C": "determine the value of unused stock of each department", "D": "calculate the stock turnover ratio of each department"}, "answer": "B", "explanation": "Departmental accounts are used to determine the profitability of individual departments within a business. This helps management in assessing the performance of each department independently, identifying areas of efficiency or improvement, and making informed decisions about resource allocation and departmental strategies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>27", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "A debit balance of D 61,000 on a customer's bank statement means that", "images": [], "options": {"A": "the customer's bank balance is D 61,000", "B": "the customer owes the bank D 61,000", "C": "a customer's cheque of D 61,000 is yet to be cleared by the bank", "D": "a direct deposit of D 61,000 was made by a customer"}, "answer": "A", "explanation": "A debit balance on a bank statement indicates that the customer has funds in their bank account.    It represents the amount of money that the customer has available in their account after all transactions, including deposits and withdrawals, have been accounted for.    This balance is what the bank considers available for the customer to use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>28", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer the question    GH⊄Trade creditors 1/1/2022 35000Payment to suppliers in 2022 30000Discounts received 1800Trade creditors 31/12/2022 24000    The purchases for 2022 is", "images": [], "options": {"A": "GH⊄ 90,800", "B": "GH⊄ 55,800", "C": "GH⊄ 39,200", "D": "GH⊄ 20,800"}, "answer": "D", "explanation": "Purchases ledger control Account   GH⊄ GH⊄Payment to suppliers 30000 Balance b/f 35000Discount received 1800 Purchases (Missing figure) 20800Balance c/d 240005580055800", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>29", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Use the following information to answer the question    GH⊄Trade creditors 1/1/2022 35000Payment to suppliers in 2022 30000Discounts received 1800Trade creditors 31/12/2022 24000    The balance sheet as at 31/12/2022 will show current liability of", "images": [], "options": {"A": "GH⊄ 59,000", "B": "GH⊄ 24,000", "C": "GH⊄ 22,200", "D": "GH⊄ 11,000"}, "answer": "B", "explanation": "Since the balance is dated 31/12/2022, then Trade creditors dated 31/12/2022 of GH⊄ 24,000 will be posted to the current liability of the balance sheet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>30", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CORRECTION OF ERRORS : MEANING AND PROCEDURES", "question": "A credit purchase of D63 from koffi has been entered in the accounts as D36. This is an error of", "images": [], "options": {"A": "principle", "B": "original entry", "C": "complete reversal of entry", "D": "omission"}, "answer": "B", "explanation": "In this case, a credit purchase of D63 from Koffi has been recorded as D36, which means the error originated at the point of the initial recording of the transaction. Therefore, this is an error of original entry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>31", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question    Taiyelolu and Ejire are partners sharing profits or losses equally. Extracts from their books showed:     Taiyelolu Ejire # #Capital accounts (1/1/2023) 200000 100000Current accounts (1/1/2023) 40000 8000Drawings within the year 20000 30000Annual salaries 28000 24000  Interest on capital is agreed at 10% and the net profit for the year is #120,000    The interest on Taiyelolu's capital is", "images": [], "options": {"A": "#20,000", "B": "#12,000", "C": "#4,000", "D": "#2,000"}, "answer": "A", "explanation": "Capital for Taiyelolu = 200,000  Interest on capital = 10%    Therefore, 10%  x 200,000  = #20,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>32", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question    Taiyelolu and Ejire are partners sharing profits or losses equally. Extracts from their books showed:     Taiyelolu Ejire # #Capital accounts (1/1/2023) 200000 100000Current accounts (1/1/2023) 40000 8000Drawings within the year 20000 30000Annual salaries 28000 24000  Interest on capital is agreed at 10% and the net profit for the year is #120,000    Ejire's share of profit is", "images": [], "options": {"A": "#45,000", "B": "#38,000", "C": "#53,000", "D": "#19,000"}, "answer": "D", "explanation": "Interest on Capital:  Taiyelolu: 10% of ₦200,000   = ₦20,000  Ejire: 10% of ₦100,000   = ₦10,000    Add Salaries:  Taiyelolu: ₦28,000  Ejire: ₦24,000    Total Interest on Capital and Salaries:  Taiyelolu: ₦20,000 + ₦28,000   = ₦48,000  Ejire: ₦10,000 + ₦24,000   = ₦34,000    Subtract the total interest and salaries from the net profit:  Total profit: ₦120,000 - (₦48,000 + ₦34,000)   = ₦38,000     Share the remaining profit equally:  Taiyelolu: ₦19,000  Ejire: ₦19,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>33", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR", "question": "Use the following information to answer the question    Taiyelolu and Ejire are partners sharing profits or losses equally. Extracts from their books showed:     Taiyelolu Ejire # #Capital accounts (1/1/2023) 200000 100000Current accounts (1/1/2023) 40000 8000Drawings within the year 20000 30000Annual salaries 28000 24000  Interest on capital is agreed at 10% and the net profit for the year is #120,000    Taiyelolu's balance of current account of the end of the year is", "images": [], "options": {"A": "#107,000", "B": "#87,000", "C": "#68,000", "D": "#40,000"}, "answer": "B", "explanation": "Additions to Taiyelolu's Current Account:  Opening Balance: ₦40,000  Interest on Capital: ₦20,000  Salary: ₦28,000  Share of Remaining Profit: ₦19,000    Total Before Drawings: ₦40,000 + ₦20,000 + ₦28,000 + ₦19,000   = ₦107,000    Subtract Drawings:  Drawings = ₦20,000  Closing Balance: ₦107,000 - ₦20,000   = ₦87,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2024>34", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PURCHASES OF BUSINESS : INTRODUCTION AND ADVANTAGES", "question": "Purchased goodwill is purchase consideration less the value of of", "images": [], "options": {"A": "gross identifiable assets", "B": "net identifiable assets", "C": "gross non-current assets", "D": "current assets"}, "answer": "B", "explanation": "Purchased goodwill is calculated as the difference between the purchase consideration (the amount paid to acquire a business) and the fair value of the net identifiable assets (assets minus liabilities) of the acquired business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>35", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL", "question": "Errors in the trial balance are corrected using the", "images": [], "options": {"A": "control account", "B": "cash book", "C": "ledger", "D": "journal"}, "answer": "D", "explanation": "The journal is used to record all adjustments and corrections. When an error is found in the trial balance, the correction requires a journal entry to ensure that the accounts are correctly adjusted. The journal entry specifies the accounts to be debited and credited to rectify the error.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>36", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "The equivalent of income and expenditure account in a limited liability company is", "images": [], "options": {"A": "cash book", "B": "receipts and payments account", "C": "appropriation account", "D": "profit and loss account"}, "answer": "D", "explanation": "The income and expenditure account is used by non-profit organizations to report their revenues and expenses, showing the surplus or deficit for a period. In a limited liability company, the profit and loss account serves a similar purpose, detailing the company's revenues, expenses, and resulting profit or loss over a financial period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>37", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION", "question": "The owner's claim on the asset of a business is", "images": [], "options": {"A": "capital", "B": "loan", "C": "liabilities", "D": "drawings"}, "answer": "A", "explanation": "Capital represents the owner's investment in the business and includes any retained earnings or profits that have been reinvested in the business. It is the residual interest in the assets of the business after deducting liabilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>38", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A partner who has not contributed any form of capital into the firm but only lends his name to be used as a partner is a", "images": [], "options": {"A": "limited partner", "B": "dormant partner", "C": "general partner", "D": "nominal partner"}, "answer": "D", "explanation": "A nominal partner does not invest capital or participate in the management of the business. Instead, they allow their name to be used for the benefit of the partnership, often lending credibility or attracting business due to their reputation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>39", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Liquid assets refer to", "images": [], "options": {"A": "cash and other assets that can be easily converted into cash", "B": "cash and other current assets", "C": "current assets less current liabilities", "D": "bank balance less overdraft"}, "answer": "A", "explanation": "Liquid assets are those that can be quickly and easily converted into cash without significant loss of value. This includes cash on hand, cash in the bank, and marketable securities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>40", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question    Ade bought goods worth Le 30,000 from ode and was given a 7.5% discount    The evidence of payment for the goods Ade bought is the", "images": [], "options": {"A": "receipt", "B": "invoice", "C": "waybill", "D": "voucher"}, "answer": "A", "explanation": "A receipt is a document that serves as proof of payment for goods or services. It typically includes details such as the amount paid, the date of payment, and a description of the items or services purchased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>41", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question    Ade bought goods worth Le 30,000 from ode and was given a 7.5% discount    The amount paid for the goods is", "images": [], "options": {"A": "Le 32,250", "B": "Le 30,000", "C": "Le 27,750", "D": "Le 2,250"}, "answer": "C", "explanation": "Discount = 30,000  x 7.5%  = 2,250    Amount paid = 30,000  - 2,250  = #27,750", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>42", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The proportion of the issued capital to be paid later is", "images": [], "options": {"A": "called-up capital", "B": "authorized capital", "C": "uncalled-up capital", "D": "paid-up capital"}, "answer": "C", "explanation": "The portion of issued capital that has been authorized but not yet called upon or paid by the shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>43", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "One of the columns in a single column cash book is", "images": [], "options": {"A": "bank", "B": "discount allowed", "C": "discount received", "D": "particulars"}, "answer": "A", "explanation": "A single column cash book primarily records cash transactions, and it includes a column specifically for cash receipts and payments. If there is a bank column, it records transactions related to bank dealings, such as deposits and withdrawals. The other options like discount allowed, discount received, and particulars are often found in multi-column cash books or as separate accounts in the ledger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2024>44", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the question    DPurchases of motor van 370000Building of laboratories 760000Purchase of drugs 110000Electricity 26000Repairs of equipment 10000    The amount of recurrent expenditure is", "images": [], "options": {"A": "D 146,000", "B": "D 136,000", "C": "D 120,000", "D": "D 110,000"}, "answer": "A", "explanation": "Recurrent expenditure refers to the costs that are incurred regularly and are typically related to the day-to-day operations of a business. These include expenses that recur periodically and are not capital expenditures or investments.    Based on the provided information:  Purchases of motor van: D 370,000 (capital expenditure)  Building of laboratories: D 760,000 (capital expenditure)  Purchase of drugs: D 110,000 (recurrent expenditure, as it is a regular expense for operations)  Electricity: D 26,000 (recurrent expenditure, as it is a regular utility cost)  Repairs of equipment: D 10,000 (recurrent expenditure, as it is a regular maintenance cost)      Recurrent expenditure=Purchase of drugs+Electricity+Repairs of equipment  = 110,000 + 26,000 + 10,000  = 146,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>45", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES", "question": "Use the following information to answer the question    DPurchases of motor van 370000Building of laboratories 760000Purchase of drugs 110000Electricity 26000Repairs of equipment 10000The capital expenditure is", "images": [], "options": {"A": "D 1,140,000", "B": "D 1,130,000", "C": "D 870,000", "D": "D 760,000"}, "answer": "B", "explanation": "Capital expenditure=Purchases of motor van+Building of laboratories    Capital expenditure = 370,000 + 760, 000    Capital expenditure=1,130,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>46", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "Shares which are issued at no cost to existing shareholders in proportion to existing shares held are", "images": [], "options": {"A": "founders' shares", "B": "preference shares", "C": "deferred shares", "D": "bonus shares"}, "answer": "D", "explanation": "Shares given to existing shareholders free of charge, proportional to their current holdings. They are often issued from the company's reserves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>47", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Which of the following items will be recorded on the credit side of a club's income and expenditure account?", "images": [], "options": {"A": "Donation to children's home", "B": "Donations received", "C": "Honoraria paid to guest speakers", "D": "Meeting expenses"}, "answer": "B", "explanation": "In a club's income and expenditure account, items recorded on the credit side typically include all sources of income or receipts. This side shows how much money the club has earned during the period.    Donations received is the income for the club and should be recorded on the credit side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>48", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "BRANCH ACCOUNT", "question": "Where the head office maintains all books of account, the cost of goods returned is credited to", "images": [], "options": {"A": "Goods Sents to Branch Account", "B": "Branch Stock Account", "C": "Branch Head Office Current Account", "D": "Branch Debtors Account"}, "answer": "C", "explanation": "This account represents the financial transactions between the branch and the head office. When goods are returned from the branch to the head office, the cost of those goods would be credited to this account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>49", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES", "question": "Distribution of dividends to shareholders are made from profit", "images": [], "options": {"A": "on sale of fixed assets", "B": "before tax", "C": "after tax", "D": "on purchase of business"}, "answer": "C", "explanation": "Dividends are paid out of net profit after tax has been deducted. This ensures that shareholders receive their share of profits after all tax liabilities have been settled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2024>50", "subject": "Accounts", "year": "2024", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "The debit side of a trial balance total is GH⊄ 2,000 more than the credit side. Which of the following errors would account for the difference?", "images": [], "options": {"A": "A receipt of GH⊄ 2,000 for rent has been omitted from the books", "B": "Carriage inwards of GH⊄ 2,000 has been debited to carriage outward account", "C": "Petty cash balance of GH⊄ 1,000 has been omitted from the books", "D": "Discount received of GH⊄ 1,000 has  been debited to discount allowed account"}, "answer": "B", "explanation": "The debit side of a trial balance being GH₵ 2,000 more than the credit side indicates that there is an error where the total debits exceed the total credits by GH₵ 2,000. To correct this imbalance, we need to identify the error that would account for the difference.    Carriage inwards of GH₵ 2,000 has been debited to the carriage outward account.  Carriage inwards should be debited to the carriage inwards account, not the carriage outwards account. This error would result in an incorrect classification but would not affect the overall balance difference by GH₵ 2,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>1", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING", "question": "A quality of accounting information is that it should be", "images": [], "options": {"A": "sizeable", "B": "verifiable", "C": "appreciable", "D": "depreciable"}, "answer": "B", "explanation": "A quality of accounting information is that it should be verifiable. Verifiability means that the information can be checked and confirmed by external parties, ensuring its accuracy and reliability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>2", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES", "question": "The balance on the sales account is transferred to the trading account by", "images": [], "options": {"A": "debiting the sales account", "B": "crediting the sales account", "C": "debiting the customer's account", "D": "crediting the customer's account"}, "answer": "B", "explanation": "The balance on the sales account is transferred to the trading account by crediting the sales account. This is because sales increase revenue, which is recorded as a credit in accounting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>3", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "Depletion method of depreciation is applicable to", "images": [], "options": {"A": "quarries", "B": "plant and machinery", "C": "livestock", "D": "office equipment"}, "answer": "A", "explanation": "The depletion method of depreciation is applicable to quarries. This method is used for natural resources that are consumed over time, such as minerals or oil, where the asset's value decreases as the resource is extracted.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>4", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT", "question": "Use the following information to answer the question    1/2/2021 Balance as per bank statement #90,000 O/D; Cheques of #30,000 issued on 20/2/2021 and presented to bank for payment on 7/3/2021; Cheques of #40,000 issued on 22/2/2021 and credited by the bank on 8/3/2021    The balance as per the adjusted cash book on 28/2/2021 is", "images": [], "options": {"A": "#100,000 DR", "B": "#100,000 CR", "C": "#80,000 DR", "D": "#80,000 CR"}, "answer": "C", "explanation": "Particulars                           Amount (₦)     Bank Statement (1/2/2021)             (90000) O/D  Add: Cheques not presented        30000        Less: Lodgement not yet credited  40000        Adjusted Cash Book Balance (80000) O/D", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>5", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREEMENT BETWEEN CASH BOOK & BANK STATEMENT", "question": "Use the following information to answer the question    1/2/2021 Balance as per bank statement #90,000 O/D; Cheques of #30,000 issued on 20/2/2021 and presented to bank for payment on 7/3/2021; Cheques of #40,000 issued on 22/2/2021 and credited by the bank on 8/3/2021    The balance as per the adjusted cash book on 28/2/2021 means that the", "images": [], "options": {"A": "business is owing the bank", "B": "business owns the amount in the bank", "C": "bank is owing the business", "D": "business made a surplus"}, "answer": "A", "explanation": "The balance as per the adjusted cash book on 28/2/2021 indicates that the business is owing the bank. Since the balance is a debit (overdraft), it means the business has borrowed money from the bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>6", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "When there is provision for depreciation, fixed assets is shown in the balance sheet at", "images": [], "options": {"A": "appraised value", "B": "net book value", "C": "appreciated value", "D": "cost  value"}, "answer": "B", "explanation": "When there is a provision for depreciation, fixed assets are shown in the balance sheet at net book value. The net book value is calculated as the original cost of the asset minus accumulated depreciation. This reflects the current value of the asset that is still usable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>7", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question     DOpening stock 9220Sales 66930Returns outwards 1740Returns inwards 2930Gross profit 16000Purchases 60540    The cost of goods sold is", "images": [], "options": {"A": "D 64,000", "B": "D 53,860", "C": "D 50, 930", "D": "D 48, 000"}, "answer": "C", "explanation": "COGS = Sales - Gross Profit   = 66,930 - 16,000   = D50,930.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>8", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question     DOpening stock 9220Sales 66930Returns outwards 1740Returns inwards 2930Gross profit 16000Purchases 60540The average stock is", "images": [], "options": {"A": "D 20,020", "B": "D 16,000", "C": "D 14,025", "D": "D 9,220"}, "answer": "C", "explanation": "The average stock is calculated using the formula:   Average Stock = (Opening Stock + Closing Stock) / 2.     We need to find the closing stock first.   From the previous question, we found COGS to be 50,930.   Therefore, Closing Stock = Opening Stock + Purchases - COGS   = 9,220 + 60,540 - 50,930   = 18,830.     Average Stock = (9,220 + 18,830) / 2   = 14,025.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>9", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question     DOpening stock 9220Sales 66930Returns outwards 1740Returns inwards 2930Gross profit 16000Purchases 60540The rate of stock turnover is", "images": [], "options": {"A": "4.4 times", "B": "3.6 times", "C": "3.5 times", "D": "3.3 times"}, "answer": "B", "explanation": "The stock turnover ratio is calculated using the formula:   Stock Turnover Ratio = Cost of Goods Sold / Average Stock.     From the previous calculations, we have COGS as 50,930. The average stock was calculated as 14,025.     Therefore, Stock Turnover Ratio = 50,930 / 14,025   ≈ 3.63 times", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>10", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND USES", "question": "Which of the following expenses forms part of cost of production?", "images": [], "options": {"A": "Selling expenses", "B": "Administrative expenses", "C": "Direct expenses", "D": "General expenses"}, "answer": "C", "explanation": "Direct expenses are costs that can be directly attributed to the production of goods. This includes costs like raw materials and labor directly involved in manufacturing. Selling and administrative expenses are not included in the cost of production, making direct expenses the correct choice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>11", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT", "question": "Purchases ledger control account is a summary of sundry", "images": [], "options": {"A": "creditors", "B": "debtors", "C": "expenses", "D": "incomes"}, "answer": "A", "explanation": "The purchases ledger control account summarizes the amounts owed to creditors (suppliers) for goods purchased on credit. Therefore, the correct answer is 'creditors'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>12", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT", "question": "The balance brought down on the credit side of the sales ledger control account at the beginning of a period represents the", "images": [], "options": {"A": "amount owed by the customers", "B": "set-off for the month", "C": "profit of the business", "D": "amount owed to the suppliers"}, "answer": "A", "explanation": "The balance brought down on the credit side of the sales ledger control account represents the amount owed by customers at the beginning of the period. This is the total receivables that the business expects to collect from its customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>13", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES", "question": "The starting point for the preparation of accounts from incomplete records is to", "images": [], "options": {"A": "prepare an opening statement of affairs", "B": "verify the total purchases", "C": "ascertain the opening stock of goods sold", "D": "ascertain the total turnover"}, "answer": "A", "explanation": "The starting point for preparing accounts from incomplete records is to prepare an opening statement of affairs. This statement provides a snapshot of the financial position of the business at the start of the period, including assets, liabilities, and equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>14", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "Use the following information to answer the question    DOpening capital 10800Drawings 2500Trade creditors 2560Trade debtors 2880Cash-in-hand 1000Net profit 6000    The closing capital is", "images": [], "options": {"A": "D 16,800", "B": "D 14,300", "C": "D 8,300", "D": "D 7,300"}, "answer": "B", "explanation": "To calculate the closing capital, we start with the opening capital, add the net profit, and subtract the drawings. The calculation is as follows:   Closing Capital = Opening Capital + Net Profit - Drawings   = 10800 + 6000 - 2500   = D14,300.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>15", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS", "question": "Use the following information to answer the question    DOpening capital 10800Drawings 2500Trade creditors 2560Trade debtors 2880Cash-in-hand 1000Net profit 6000  The working capital is", "images": [], "options": {"A": "D 5,800", "B": "D 3,880", "C": "D 3,500", "D": "D 1,320"}, "answer": "D", "explanation": "Working capital is calculated as current assets minus current liabilities. In this case, current assets include cash-in-hand and trade debtors, while current liabilities include trade creditors. The calculation is:   Working Capital = (Cash-in-hand + Trade debtors) - Trade creditors   = (1000 + 2880) - 2560   =D 1320.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>16", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "When the total of the debit side of income and expenditure account exceeds the total of the credit side, the difference is", "images": [], "options": {"A": "deficit", "B": "surplus", "C": "cash-in-hand", "D": "accumulated fund"}, "answer": "A", "explanation": "When the total of the debit side of an income and expenditure account exceeds the total of the credit side, it indicates that expenses have surpassed income, resulting in a deficit. Therefore, the correct answer is 'deficit'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>17", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     $Prime cost of production 500000Factory overheads 80000Opening work-in-progress 35000Cost of production 520000    The closing work-in-progress is", "images": [], "options": {"A": "$115,000", "B": "$95,000", "C": "$55,000", "D": "$45,000"}, "answer": "B", "explanation": "To find the closing work-in-progress, we can use the formula:   Closing Work-in-Progress = Opening Work-in-Progress + Cost of Production - Prime Cost of Production - Factory Overheads.   Closing Work-in-Progress = 35000 + 520000 - 500000 - 80000   = $95000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>18", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE", "question": "Use the following information to answer the question     $Prime cost of production 500000Factory overheads 80000Opening work-in-progress 35000Cost of production 520000    The work-in-progress for the year shows", "images": [], "options": {"A": "an increase of $35,000", "B": "a decrease of $35,000", "C": "an increase of $60,000", "D": "a decrease of $60,000"}, "answer": "A", "explanation": "The work-in-progress for the year can be determined by comparing the closing work-in-progress with the opening work-in-progress. Since the closing work-in-progress is $95,000 and the opening was $35,000, there is an increase of $60,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>19", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "In the absence of a partnership agreement, loan granted to the business by a partner would attract", "images": [], "options": {"A": "zero interest per annum", "B": "interest at 10% per annum", "C": "interest at 5% per annum", "D": "interest at 7% per annum"}, "answer": "B", "explanation": "In the absence of a partnership agreement, loans granted to the business by a partner typically attract interest at a standard rate, which is often set at 10% per annum. Therefore, the correct answer is 'interest at 10% per annum'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>20", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION", "question": "The acquisition of furniture for office use for #290,000 should be debited to", "images": [], "options": {"A": "cash account", "B": "purchases account", "C": "assets account", "D": "bank account"}, "answer": "C", "explanation": "The acquisition of furniture for office use is considered a capital expenditure and should be debited to the assets account, as it represents a long-term asset for the business. Therefore, the correct answer is 'assets account'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>21", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE", "question": "The total of the discount column of $60,000 on the credit side of a cash book was credited to the discount allowed account, To correct this error: debit", "images": [], "options": {"A": "Discount Allowed Account $60,000, credit Discount Received Account $60,000", "B": "Discount Allowed Account $120,000, credit Discount Received Account $120,000", "C": "Discount Received Allowed $60,000, credit Discount Allowed Account $60,000", "D": "Discount Received Account $120,000, credit Discount Allowed Account $120,000"}, "answer": "A", "explanation": "To correct the error of crediting the discount allowed account instead of the discount received account, we need to debit the Discount Allowed Account by $60,000 to reverse the incorrect entry and credit the Discount Received Account by $60,000 to reflect the correct transaction. Therefore, the correct option is 'Discount Allowed Account $60,000, credit Discount Received Account $60,000'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>22", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "An item debited to the income and expenditure account is", "images": [], "options": {"A": "rent paid", "B": "life membership fees", "C": "profit on bar", "D": "donations received for club's party"}, "answer": "A", "explanation": "An item debited to the income and expenditure account represents an expense incurred by the organization. 'Rent paid' is an expense that reduces the income, thus it is correctly debited to the income and expenditure account. The other options do not represent expenses; they are either income or capital contributions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>23", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "Goods taken over by the owner of the business for personal use is treated as", "images": [], "options": {"A": "allowances", "B": "loan", "C": "sales", "D": "drawings"}, "answer": "D", "explanation": "Goods taken over by the owner for personal use are treated as 'drawings' in accounting. Drawings represent the withdrawal of assets by the owner from the business for personal use, which reduces the owner's equity in the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>24", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Gross profit is computed as", "images": [], "options": {"A": "cost of sales plus net profit", "B": "cost of sales less net profit", "C": "sales less cost of sales", "D": "cost of sales plus sales"}, "answer": "C", "explanation": "Gross profit is calculated as 'sales less cost of sales'. This formula reflects the profit made from selling goods after accounting for the costs directly associated with producing those goods. The other options do not accurately represent the calculation of gross profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>25", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "A feature of the income and expenditure account is that", "images": [], "options": {"A": "the account records fixed assets", "B": "the opening balance is shown on the account", "C": "it is prepared on cash basis", "D": "it is prepared on accrual basis"}, "answer": "D", "explanation": "The income and expenditure account is prepared on an accrual basis, meaning that it records income and expenses when they are earned or incurred, regardless of when cash is actually received or paid. This is a key feature that distinguishes it from cash basis accounting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>26", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "A person who lends his name to be used as a partner without any contribution of capital is a", "images": [], "options": {"A": "dormant partner", "B": "active partner", "C": "limited partner", "D": "nominal partner"}, "answer": "D", "explanation": "A person who lends his name to be used as a partner without any contribution of capital is known as a nominal partner. Nominal partners do not have any real interest in the business and do not share in the profits or losses, but their name is used to lend credibility to the partnership.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>27", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The concept which states that there are two sides to accounting entries is", "images": [], "options": {"A": "money measurement concept", "B": "prudence concept", "C": "dual aspect concept", "D": "accrual concept"}, "answer": "C", "explanation": "The concept which states that there are two sides to accounting entries is known as the dual aspect concept. This principle is fundamental to double-entry bookkeeping, where every transaction affects at least two accounts, ensuring that the accounting equation (Assets = Liabilities + Equity) remains balanced.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>28", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS", "question": "The trade debtors of a business are", "images": [], "options": {"A": "customers who bought goods on credit", "B": "suppliers who are owed for goods delivered", "C": "customers who bought goods regularly", "D": "suppliers who are paid for goods delivered"}, "answer": "A", "explanation": "The trade debtors of a business are customers who bought goods on credit. Trade debtors represent amounts owed to the business by customers for goods or services that have been delivered but not yet paid for.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>29", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT", "question": "When the buyer is undercharged, the seller forwards", "images": [], "options": {"A": "a credit note", "B": "a debit note", "C": "an invoice", "D": "a receipt"}, "answer": "B", "explanation": "When the buyer is undercharged, the seller forwards a debit note. A debit note is a document issued by a seller to a buyer, indicating that the buyer has been undercharged and that the seller is requesting payment for the additional amount.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>30", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question     Abu OjoGH⊄ GH⊄Capital 40000 20000Drawings 18000 12000    Profit for the year was GH⊄ 54,000, 5% interest on capital and their profit or loss sharing ratio is 3: 2 respectively    Abu's share of profit is", "images": [], "options": {"A": "GH⊄ 32,400", "B": "GH⊄ 30,600", "C": "GH⊄ 21,600", "D": "GH⊄ 20,400"}, "answer": "A", "explanation": "To calculate Abu's share of profit, we first determine the total capital and the profit sharing ratio.     Abu's capital is GH⊄ 40,000 and Ojo's is GH⊄ 20,000, making a total of GH⊄ 60,000.     The profit for the year is GH⊄ 54,000. Abu's share of profit is calculated as follows:   Abu's share = (Abu's capital / Total capital) x Total profit   = (40,000 / 60,000) x 54,000   = GH⊄ 36,000.     However, we need to consider the profit-sharing ratio of 3:2.   Therefore, Abu's share of profit = (3/5) x 54,000   = GH⊄ 32,400.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>31", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question     Abu OjoGH⊄ GH⊄Capital 40000 20000Drawings 18000 12000    Profit for the year was GH⊄ 54,000, 5% interest on capital and their profit or loss sharing ratio is 3: 2 respectively    Ojo's share of profit for the year is", "images": [], "options": {"A": "GH⊄ 32,400", "B": "GH⊄ 30,600", "C": "GH⊄ 21,600", "D": "GH⊄ 20,400"}, "answer": "C", "explanation": "To calculate Ojo's share of profit, we first need to determine the total profit share based on the profit-sharing ratio of 3:2.     The total profit is GH⊄ 54,000.     Ojo's share is (2/5) of the total profit,    = 2/5 x 54000   = GH⊄ 21,600.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>32", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS - PARTNERSHIP", "question": "Use the following information to answer the question     Abu OjoGH⊄ GH⊄Capital 40000 20000Drawings 18000 12000    Profit for the year was GH⊄ 54,000, 5% interest on capital and their profit or loss sharing ratio is 3: 2 respectively    The balance on Abu's current account is", "images": [], "options": {"A": "GH⊄ 32,600", "B": "GH⊄ 21,400", "C": "GH⊄ 14,600", "D": "GH⊄ 9,400"}, "answer": "C", "explanation": "Interest on capital:  Abu = 5%  x 40000  = 2000  Ojo = 5% x 20000  = 1000  Total = 2000 + 1000 = 3000    Profit after interest  = 54000 - 3000  = 51000  Abu's share = 3/5 x 51000  = 30600    Tota credit  to Abu  = 2000 + 30600  = 32600    Balance = 32600 - 18000 (drawings)  = GH⊄14600", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>33", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "Sales for the year 2021  Credit Le 70000Cash Le 30000  The accounting concept underlying the recording of Le 100,000 in the sales account as", "images": [], "options": {"A": "going concern concept", "B": "realization concept", "C": "materiality concept", "D": "consistency concept"}, "answer": "B", "explanation": "The realization concept states that revenue is recognized when it is earned, regardless of when cash is received. In this case, the total sales of Le 100,000 are recorded in the sales account based on the realization concept, as it reflects the total sales made during the year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>34", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE", "question": "Sales journal is used for recording", "images": [], "options": {"A": "cash sales", "B": "sales returns", "C": "credit sales", "D": "sales expenses"}, "answer": "C", "explanation": "A sales journal is specifically used for recording credit sales. It is a specialized journal that captures all sales made on credit, distinguishing them from cash sales, which are recorded in a cash receipts journal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>35", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS", "question": "Which of the following circumstances will  not lead to dissolution of partnership? When a partner", "images": [], "options": {"A": "is bankrupt", "B": "retires", "C": "dies", "D": "is handicapped"}, "answer": "D", "explanation": "A partnership is dissolved when the legal relationship between partners ends. This can happen by mutual agreement, expiration of a fixed term, completion of a specific project, death or bankruptcy of a partner, or by a court order due to misconduct or incapacity. It may also occur if the business becomes illegal or if any partner in a partnership at will gives notice. Dissolution means the partnership ceases to exist in its current form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>36", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK", "question": "When the letter \"C\" is written in front of an entry in the folio column of a cash book, it shows a", "images": [], "options": {"A": "double entry", "B": "cash entry", "C": "contra entry", "D": "journal entry"}, "answer": "C", "explanation": "When the letter 'C' is written in front of an entry in the folio column of a cash book, it indicates a 'contra entry'. A contra entry is a transaction that involves both cash and bank accounts, where the cash is transferred to the bank or vice versa. This is a common practice in accounting to reflect the movement of cash between different accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>37", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING", "question": "A user of accounting information who would be more interested in the liquidity of the firm is the", "images": [], "options": {"A": "customer", "B": "supplier", "C": "tax authority", "D": "potential investor"}, "answer": "D", "explanation": "A potential investor would be more interested in the liquidity of the firm because liquidity indicates the ability of the firm to meet its short-term obligations. Investors want to ensure that the company can generate enough cash to cover its liabilities, which is crucial for assessing the financial health and stability of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>38", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE", "question": "An item that can be purchased from a petty cash float is", "images": [], "options": {"A": "correction pen", "B": "laptop", "C": "raw materials", "D": "refrigerator"}, "answer": "A", "explanation": "An item that can be purchased from a petty cash float is a 'correction pen'. Petty cash is used for small, incidental expenses, and items like correction pens are typical examples of such purchases. Larger items like laptops or refrigerators would not be purchased from petty cash due to their higher costs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>39", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT", "question": "An item recorded on the credit side of the trading profit and loss account is", "images": [], "options": {"A": "discount allowed", "B": "discount received", "C": "salaries and wages", "D": "rent and rates"}, "answer": "B", "explanation": "An item recorded on the credit side of the trading profit and loss account is 'discount received'. This is because discounts received reduce the cost of purchases and are recorded as income, thus appearing on the credit side of the account. Other options like salaries and wages are expenses and would appear on the debit side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>40", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES", "question": "An item that would be apportioned in proportion to purchases of each department is", "images": [], "options": {"A": "bad debts", "B": "carriage outwards", "C": "discount received", "D": "discount allowed"}, "answer": "B", "explanation": "An item that would be apportioned in proportion to purchases of each department is 'carriage outwards'. This refers to the cost of transporting goods sold to customers, and it is typically allocated based on the proportion of purchases made by each department to ensure accurate cost distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>41", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "BRANCH ACCOUNT", "question": "The accounting entries in the books of the  head office for goods returned by  a customer to a branch are: debit", "images": [], "options": {"A": "Branch Debtors Account; credit Branch Stock Account", "B": "Branch Stock Account; credit Returns Inwards Account", "C": "Branch Stock Account; credit Branch Debtors Account", "D": "Returns Inwards Account; credit Branch Debtors Account"}, "answer": "C", "explanation": "When goods are returned by a customer to a branch, the accounting entries involve debiting the Branch Stock Account to increase the stock and crediting the Branch Debtors Account to decrease the amount owed by the customer. This reflects the return of goods and the reduction in receivables.", "marks": "1", "difficulty": "3"}, {"id": "objective>Accounts>2025>42", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "In a company's balance sheet, rent prepaid is classified as a", "images": [], "options": {"A": "current liability", "B": "long-term liability", "C": "current asset", "D": "fixed asset"}, "answer": "C", "explanation": "Rent prepaid is classified as a current asset on a company's balance sheet because it represents a payment made in advance for services (rent) that will be received in the future, thus it is expected to be consumed within one year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>43", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS", "question": "The accounting concept which underlies providing for doubtful debt is", "images": [], "options": {"A": "materiality", "B": "duality concept", "C": "entity concept", "D": "prudence concept"}, "answer": "D", "explanation": "The accounting concept that underlies providing for doubtful debts is the prudence concept. This concept dictates that potential losses should be recognized as soon as they are foreseeable, which includes estimating and providing for debts that may not be collected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>44", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "The document which contains monies allocated in public sector is", "images": [], "options": {"A": "budget", "B": "cash book", "C": "voucher", "D": "warrant"}, "answer": "A", "explanation": "The document that contains monies allocated in the public sector is called a budget. A budget outlines the expected revenues and expenditures for a specific period, guiding financial planning and resource allocation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>45", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : INTRODUCTION AND INTERPRETATION", "question": "Which of the following items is an example of an intangible asset?", "images": [], "options": {"A": "Debtors", "B": "Furniture", "C": "Copyright", "D": "Cash"}, "answer": "C", "explanation": "Copyright is an example of an intangible asset. Intangible assets are non-physical assets that have value, such as intellectual property, trademarks, and copyrights, which provide economic benefits over time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Accounts>2025>46", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES", "question": "The maximum number of shares that a company is allowed by the law to offer to the public for subscription is", "images": [], "options": {"A": "authorized capital", "B": "paid-up capital", "C": "called-up capital", "D": "issued capital"}, "answer": "A", "explanation": "The maximum number of shares that a company is allowed by law to offer to the public for subscription is known as 'authorized capital'. This represents the total value of shares that a company can issue to shareholders, as specified in its corporate charter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>47", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING", "question": "One of the features of cash basis of accounting in public sector is that", "images": [], "options": {"A": "capital receipts are excluded from income in the accounting year", "B": "it focuses on revenue items only", "C": "trade debtors are recognized in the balance sheet", "D": "capital expenditure items are written off within the accounting year"}, "answer": "A", "explanation": "In the cash basis of accounting, particularly in the public sector, capital receipts are excluded from income in the accounting year. This method focuses on cash transactions, meaning that only cash received is recognized as income, while capital receipts, which are not cash transactions, are not included.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>48", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question    GH⊄Ordinary shares 130000Fixed assets 495000Current assets 210000Income surplus 225000Current liabilities 95000    The working capital is", "images": [], "options": {"A": "GH⊄ 390,000", "B": "GH⊄ 285,000", "C": "GH⊄ 210,000", "D": "GH⊄ 115,000"}, "answer": "D", "explanation": "Working capital is calculated as current assets minus current liabilities. Here, current assets are GH⊄ 210,000 and current liabilities are GH⊄ 95,000.     Therefore, working capital = 210,000 - 95,000   = GH⊄ 115,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>49", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question    GH⊄Ordinary shares 130000Fixed assets 495000Current assets 210000Income surplus 225000Current liabilities 95000  Total shareholders fund is", "images": [], "options": {"A": "GH⊄ 370,000", "B": "GH⊄ 355,000", "C": "GH⊄ 317,000", "D": "GH⊄ 130,000"}, "answer": "B", "explanation": "Total shareholders' funds can be calculated as the sum of ordinary shares and income surplus, minus any liabilities.     Here, ordinary shares are GH⊄ 130,000 and income surplus is GH⊄ 225,000.     Therefore, total shareholders' funds = 130,000 + 225,000   = GH⊄ 355,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Accounts>2025>50", "subject": "Accounts", "year": "2025", "type": "Objective", "topic": "ACCOUNTING RATIO : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO", "question": "Use the following information to answer the question    GH⊄Ordinary shares 130000Fixed assets 495000Current assets 210000Income surplus 225000Current liabilities 95000  The net assets of the company is", "images": [], "options": {"A": "GH⊄ 705,000", "B": "GH⊄ 610,000", "C": "GH⊄ 400,000", "D": "GH⊄ 115,000"}, "answer": "B", "explanation": "Net assets of a company are calculated as total assets minus total liabilities.     In this case, total assets are the sum of fixed assets and current assets (GH⊄ 495,000 + GH⊄ 210,000 = GH⊄ 705,000) and total liabilities are current liabilities (GH⊄ 95,000).     Therefore, net assets = 705,000 - 95,000   = GH⊄ 610,000", "marks": "1", "difficulty": "2"}];